            line-height: 1.7;
            color: #333;
            margin: 0 0 14px;
        }

        .sp-acknowledge-modal .sp-acknowledge-btn {
            display: block;
            width: 100%;
            margin-top: 24px;
            padding: 12px;
            background: <?php echo esc_attr( $primary ); ?>;
            color: #fff;
            border: none;
            border-radius: 6px;
            font-size: 1rem;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.2s;
        }

        .sp-acknowledge-modal .sp-acknowledge-btn:hover {
            background: <?php echo esc_attr( $primary_hover ); ?>;
        }
    </style>
    <?php
} );

/**
 * Add the pre-login privacy notice above the login form.
 *
 * WHY: The society's policy requires members to read the acceptable-use
 *      notice before logging in. This filter adds it above the form on
 *      the standard login action only (not on password reset, etc.).
 */
add_filter( 'login_message', function ( $message ) {
    // Only show on the main login form, not on password reset or registration
    $action = isset( $_GET['action'] ) ? $_GET['action'] : 'login';
    if ( $action !== 'login' ) {
        return $message;
    }

    $settings = get_option( 'societypress_settings', [] );
    $org_email = $settings['organization_email'] ?? '';

    $notice  = '<div class="sp-login-notice">';
    $notice .= '<h2>' . esc_html__( 'Important Notice', 'societypress' ) . '</h2>';
    $notice .= '<p>' . esc_html__( 'This information is for members only; please do not share your ID and password with non-members. Names and contact information are provided to assist members in collaborating on society projects and in genealogical research. The use of this information for commercial, political, personal, or religious purposes is strictly forbidden. It would show a lack of respect for the privacy of our members and would reduce their willingness to share contact data. Any violation will be considered a serious offense and will have consequences.', 'societypress' ) . '</p>';
    $notice .= '<p>' . esc_html__( 'Just as you would not share your private family conversations or your family financial matters with the general public, please do not share our financial reports, board meeting notes, etc. with non-members. In an effort to keep our members well informed, we are exceptionally open with this data within our membership. However, it is not intended for public dissemination.', 'societypress' ) . '</p>';

    if ( $org_email ) {
        $notice .= '<p>' . esc_html__( 'If you have any membership questions, please contact the Membership Chair at ', 'societypress' ) . sp_obfuscate_email( $org_email ) . '.</p>';
    } else {
        $notice .= '<p>' . esc_html__( 'If you have any membership questions, please contact the Membership Chair.', 'societypress' ) . '</p>';
    }

    $notice .= '</div>';

    return $notice . $message;
} );

/**
 * Change the "Username or Email Address" label to "Login Name".
 * Also add help text below the form.
 *
 * WHY: "Username or Email Address" is WordPress jargon. Society members
 *      know their "login name" — that's what they were given. We also add
 *      help text explaining what to do if they've forgotten their credentials.
 *      Injected via login_footer because WordPress doesn't have a filter
 *      for individual form field labels — we use JavaScript to swap it.
 */
add_action( 'login_footer', function () {
    $action = isset( $_GET['action'] ) ? $_GET['action'] : 'login';
    if ( $action !== 'login' ) {
        return;
    }
    ?>
    <div class="sp-login-help" id="sp-login-help" style="display:none;">
        <strong>Login Problem?</strong><br>
        Click the "Lost your password?" link above if you have forgotten your
        password. Enter your login name or email address and password reset
        instructions will be sent to the email address associated with your
        membership profile.
    </div>
    <script>
        (function() {
            // Move the help text inside #login so it centers with everything else
            var help = document.getElementById('sp-login-help');
            var login = document.getElementById('login');
            if (help && login) {
                login.appendChild(help);
                help.style.display = '';
            }

            // WHY: WordPress hardcodes "Username or Email Address" as the label.
            //      There's no PHP filter for it, so we swap it client-side.
            var label = document.querySelector('label[for="user_login"]');
            if (label) {
                var firstText = label.childNodes[0];
                if (firstText && firstText.nodeType === 3) {
                    firstText.textContent = 'Login Name';
                }
            }

            // WHY: WordPress blocks paste on the password field, which breaks
            //      password managers like BitWarden. Remove all paste-blocking
            //      event handlers so members can paste their passwords normally.
            var passField = document.getElementById('user_pass');
            if (passField) {
                passField.onpaste = null;
                passField.addEventListener('paste', function(e) { e.stopImmediatePropagation(); }, true);
            }
        })();
    </script>
    <?php
} );

/**
 * Point the login header link to the site home (instead of wordpress.org).
 *
 * WHY: The default login page links the logo to wordpress.org. We've hidden
 *      the logo, but if it somehow shows, it should link home — not to WP.
 */
add_filter( 'login_headerurl', function () {
    return home_url( '/' );
} );

add_filter( 'login_headertext', function () {
    $settings = get_option( 'societypress_settings', [] );
    return $settings['organization_name'] ?? get_bloginfo( 'name' );
} );


// ============================================================================
// POST-LOGIN ACKNOWLEDGMENT — Full privacy notice after successful login
// ============================================================================
//
// WHY: Society leadership requires members to see and acknowledge the full
//      acceptable-use policy after every login. This is more detailed than
//      the pre-login notice and includes specific legal consequences. A
//      transient flag is set at login time; on the first admin page load,
//      a blocking modal is shown. The member must click "I Understand" to
//      dismiss it. The flag is cleared so it won't show again until the
//      next login.

/**
 * Set a transient flag when a user successfully logs in.
 *
 * WHY: We need to know "this user just logged in and hasn't acknowledged
 *      the notice yet." A transient with a short TTL (1 hour) works well —
 *      if they close the browser and come back, they're already past the
 *      WordPress session check anyway and would need to log in again.
 */
add_action( 'wp_login', function ( $user_login, $user ) {
    set_transient( 'sp_login_ack_' . $user->ID, 1, HOUR_IN_SECONDS );
}, 10, 2 );

/**
 * AJAX handler to dismiss the acknowledgment.
 *
 * WHY: When the member clicks "I Understand," JavaScript fires an AJAX
 *      request to delete the transient. This way the modal doesn't show
 *      on subsequent page loads within the same session.
 */
add_action( 'wp_ajax_sp_dismiss_login_ack', function () {
    check_ajax_referer( 'sp_dismiss_login_ack' );
    $user_id = get_current_user_id();
    if ( $user_id ) {
        delete_transient( 'sp_login_ack_' . $user_id );
    }
    wp_send_json_success();
} );

/**
 * Show the post-login acknowledgment modal on admin pages.
 *
 * WHY: This hooks into admin_footer so the modal HTML is injected at the
 *      bottom of the page. It only renders if the transient flag exists
 *      (meaning the user just logged in and hasn't acknowledged yet).
 *      The modal is a full-screen overlay that blocks all interaction
 *      until the member clicks "I Understand."
 */
add_action( 'admin_footer', function () {
    $user_id = get_current_user_id();
    if ( ! $user_id ) return;

    // Check if this user just logged in and hasn't acknowledged yet
    $needs_ack = get_transient( 'sp_login_ack_' . $user_id );
    if ( ! $needs_ack ) return;

    $settings  = get_option( 'societypress_settings', [] );
    $primary   = $settings['design_color_primary'] ?? '#1e3a5f';
    $primary_hover = $settings['design_color_primary_hover'] ?? '#2c5282';

    // Use the canonical font map instead of a local duplicate
    $font_family = sp_get_font_family_css( $settings['design_font_body'] ?? null );
    ?>
    <div class="sp-acknowledge-overlay" id="sp-login-ack-overlay">
        <div class="sp-acknowledge-modal">
            <h2>Important Notice</h2>
            <p>This information is for members only; please do not share your ID and password with non-members or other members. Each member in good standing has been provided their own individual ID and password. Names and contact information are provided to assist members in collaborating on society projects and in genealogical research. The use of this information for commercial, political, personal, or religious purposes is strictly forbidden. It would show a lack of respect for the privacy of our dedicated members and would reduce their willingness to share contact data. Any violation will be considered a serious offense and will have legal consequences. Appropriate action will be taken immediately upon violation of this policy and will result in immediate loss of membership, in addition to legal consequences.</p>
            <p>Just as you would not share your private family conversations or your family financial matters with the general public, please do not share our financial reports, board meeting notes, etc. with non-members. In an effort to keep our members well informed, we are open with this data within our membership. However, it is not intended for public dissemination for any reason. Individuals who violate the confidential nature of this information will be dealt with by the Board of Directors and appropriate action will be taken, including immediate loss of membership.</p>
            <?php
            // WHY: The contact email was hardcoded to President@upstream-society.org. Every society
            // needs their own email here, so we pull from the org_email setting instead.
            $sp_ack_settings = get_option( 'societypress_settings', [] );
            $sp_ack_email    = $sp_ack_settings['org_email'] ?? '';
            ?>
            <p><?php echo esc_html__( 'If you have any questions, please contact us at ', 'societypress' ); ?><?php echo $sp_ack_email ? sp_obfuscate_email( $sp_ack_email ) : ''; ?>.</p>
            <button type="button" class="sp-acknowledge-btn" id="sp-login-ack-btn"><?php esc_html_e( 'I Understand', 'societypress' ); ?></button>
        </div>
    </div>
    <style>
        .sp-acknowledge-overlay {
            position: fixed;
            top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0,0,0,0.6);
            z-index: 999999;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .sp-acknowledge-modal {
            background: #fff;
            border-radius: 12px;
            max-width: 640px;
            width: 90%;
            max-height: 85vh;
            overflow-y: auto;
            padding: 32px 36px;
            box-shadow: 0 8px 40px rgba(0,0,0,0.3);
            font-family: <?php echo esc_attr( $font_family ); ?>;
        }
        .sp-acknowledge-modal h2 {
            font-size: 1.3rem;
            font-weight: 700;
            color: <?php echo esc_attr( $primary ); ?>;
            margin: 0 0 20px;
        }
        .sp-acknowledge-modal p {
            font-size: 0.9rem;
            line-height: 1.7;
            color: #333;
            margin: 0 0 14px;
        }
        .sp-acknowledge-modal a {
            color: <?php echo esc_attr( $primary ); ?>;
        }
        .sp-acknowledge-btn {
            display: block;
            width: 100%;
            margin-top: 24px;
            padding: 12px;
            background: <?php echo esc_attr( $primary ); ?>;
            color: #fff;
            border: none;
            border-radius: 6px;
            font-size: 1rem;
            font-weight: 600;
            cursor: pointer;
            transition: background 0.2s;
        }
        .sp-acknowledge-btn:hover {
            background: <?php echo esc_attr( $primary_hover ); ?>;
        }
    </style>
    <script>
        // WHY: When the member clicks "I Understand," we dismiss the modal
        //      and fire an AJAX request to clear the transient so it won't
        //      show on the next page load. The modal removal is instant —
        //      we don't wait for the AJAX response.
        document.getElementById('sp-login-ack-btn').addEventListener('click', function() {
            document.getElementById('sp-login-ack-overlay').remove();
            var xhr = new XMLHttpRequest();
            xhr.open('POST', ajaxurl, true);
            xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
            xhr.send('action=sp_dismiss_login_ack&_ajax_nonce=<?php echo wp_create_nonce( 'sp_dismiss_login_ack' ); ?>');
        });
    </script>
    <?php
} );


