    $wp_admin_bar->remove_node( 'wp-logo' );    // WordPress logo + "About WordPress"
    $wp_admin_bar->remove_node( 'comments' );    // Comments shortcut
    $wp_admin_bar->remove_node( 'new-post' );    // + New → Post
    $wp_admin_bar->remove_node( 'new-user' );    // + New → User
    $wp_admin_bar->remove_node( 'updates' );     // Updates notification badge

    // NOTE: WordPress already adds a "Log Out" link (id: 'logout') to the
    // user-actions group. A previous version of this code added a duplicate
    // 'sp-logout' node because we thought the default was removed — it wasn't.
    // No need to add anything here; the built-in logout link is sufficient.
});


// ============================================================================
// DASHBOARD WIDGET CLEANUP
// ============================================================================

/**
 * Remove default dashboard widgets that don't apply to SocietyPress.
 *
 * WHY: Even though we redirect away from the WordPress dashboard, these
 *      widgets can sometimes flash briefly during the redirect. Removing
 *      them is belt-and-suspenders — makes sure nothing confusing appears
 *      even if the redirect is slow.
 */
