                        ],
                    ];

                    // Reverse lookup: SocietyPress label → target key.
                    // WHY: The $field_map uses CSV column names as keys and SP labels
                    //      as values. We need to find the target key from the label so
                    //      we can pre-select the correct dropdown option.
                    $label_to_key = [];
                    foreach ( $target_fields as $group => $fields ) {
                        foreach ( $fields as $key => $label ) {
                            $label_to_key[ $label ] = $key;
                        }
                    }
                    ?>

                    <!-- Single form wrapping both the mapping dropdowns and the confirm button.
                         WHY: The field mapping dropdowns (<select name="sp_field_map[...]">)
                         need to be inside the same <form> as the "Run Import" submit button.
                         Otherwise the admin's mapping choices won't be sent with the POST
                         when they click import. -->
                    <form method="post" id="sp-import-confirm-form">
                        <?php wp_nonce_field( 'sp_import_members' ); ?>
                        <input type="hidden" name="sp_import_action" value="run_import">
                        <input type="hidden" name="sp_import_temp_file"
                               value="<?php echo esc_attr( basename( $preview['temp_file'] ) ); ?>">
                        <input type="hidden" id="sp-import-batch-nonce" value="<?php echo esc_attr( wp_create_nonce( 'sp_import_members_batch' ) ); ?>">

                    <!-- Field mapping table -->
                    <table class="widefat striped sp-import-map-table">
                        <thead>
                            <tr>
                                <th class="sp-import-col-csv"><?php esc_html_e( 'CSV Column', 'societypress' ); ?></th>
                                <th class="sp-import-col-maps"><?php esc_html_e( 'Maps To', 'societypress' ); ?></th>
                                <th class="sp-import-col-sample"><?php esc_html_e( 'Sample Value', 'societypress' ); ?></th>
                            </tr>
                        </thead>
                        <tbody>
                            <?php
                            $first_data_row = $preview['sample_rows'][0] ?? [];
                            foreach ( $preview['headers'] as $idx => $header ) :
                                $mapped_label = $field_map[ $header ] ?? null;
                                $mapped_key   = $mapped_label ? ( $label_to_key[ $mapped_label ] ?? '' ) : '';

                                // Decide what should be pre-selected for this column:
                                // - If auto-detection found a matching target key → use it
                                // - If the column is known (in $field_map) but doesn't map
                                //   to a specific target → store as custom field (__meta)
                                // - If the column is completely unknown → also store as
                                //   custom field so no data from the import is lost
                                if ( ! empty( $mapped_key ) ) {
                                    $selected_value = $mapped_key;
                                } else {
                                    $selected_value = '__meta';
                                }

                                $sample = isset( $first_data_row[ $idx ] ) ? trim( $first_data_row[ $idx ] ) : '';
                                if ( strlen( $sample ) > 60 ) {
                                    $sample = substr( $sample, 0, 57 ) . '...';
                                }
                            ?>
                                <tr class="sp-import-field-row">
                                    <td><code><?php echo esc_html( $header ); ?></code></td>
                                    <td>
                                        <select name="sp_field_map[<?php echo esc_attr( $header ); ?>]"
                                                class="sp-field-map-select sp-import-field-select">
                                            <option value="__skip"
                                                <?php selected( $selected_value, '__skip' ); ?>>
                                                &#10005; Skip — do not import
                                            </option>
                                            <option value="__meta"
                                                <?php selected( $selected_value, '__meta' ); ?>>
                                                &#128190; Store as custom field
                                            </option>
                                            <?php foreach ( $target_fields as $group => $fields ) : ?>
                                                <optgroup label="<?php echo esc_attr( $group ); ?>">
                                                    <?php foreach ( $fields as $key => $label ) : ?>
                                                        <option value="<?php echo esc_attr( $key ); ?>"
                                                            <?php selected( $selected_value, $key ); ?>>
                                                            <?php echo esc_html( $label ); ?>
                                                        </option>
                                                    <?php endforeach; ?>
                                                </optgroup>
                                            <?php endforeach; ?>
                                        </select>
                                    </td>
                                    <td class="sp-import-sample-cell">
                                        <?php echo esc_html( $sample ); ?>
                                    </td>
                                </tr>
                            <?php endforeach; ?>
                        </tbody>
                    </table>

                    <script>
                    // WHY: When a field is set to "Skip," dim the row so the admin
                    //      can see at a glance what's being excluded.
                    (function() {
                        var selects = document.querySelectorAll('.sp-field-map-select');
                        selects.forEach(function(sel) {
                            sel.addEventListener('change', function() {
                                var row = this.closest('tr');
                                if (this.value === '__skip') {
                                    row.style.opacity = '0.4';
                                } else {
                                    row.style.opacity = '';
                                }
                            });
                            // Apply initial state
                            if (sel.value === '__skip') {
                                sel.closest('tr').style.opacity = '0.4';
                            }
                        });
                    })();
                    </script>

                    <!-- Data preview -->
                    <h3 class="sp-import-preview-heading">Data Preview (first <?php echo count( $preview['sample_rows'] ); ?> rows)</h3>
                    <div class="sp-import-preview-scroll">
                        <table class="widefat striped sp-import-preview-table">
                            <thead>
                                <tr>
                                    <?php
                                    // Only show columns that auto-detected to a specific
                                    // target field (not meta and not skip) in the preview.
                                    // WHY: The full 86-column CSV would be unreadable.
                                    //      We show only the key columns: names, email,
                                    //      dates, address, etc. — the ones the admin most
                                    //      needs to verify are correct.
                                    $preview_cols = [];
                                    foreach ( $preview['headers'] as $idx => $header ) {
                                        $lbl = $field_map[ $header ] ?? null;
                                        $key = $lbl ? ( $label_to_key[ $lbl ] ?? '' ) : '';
                                        if ( ! empty( $key ) ) {
                                            $preview_cols[ $idx ] = $header;
                                        }
                                    }
                                    foreach ( $preview_cols as $header ) : ?>
                                        <th class="sp-import-preview-th"><?php echo esc_html( $header ); ?></th>
                                    <?php endforeach; ?>
                                </tr>
                            </thead>
                            <tbody>
                                <?php foreach ( $preview['sample_rows'] as $row ) : ?>
                                    <tr>
                                        <?php foreach ( $preview_cols as $idx => $header ) :
                                            $val = isset( $row[ $idx ] ) ? trim( $row[ $idx ] ) : '';
                                            if ( strlen( $val ) > 40 ) $val = substr( $val, 0, 37 ) . '...';
                                        ?>
                                            <td class="sp-import-preview-td"><?php echo esc_html( $val ); ?></td>
                                        <?php endforeach; ?>
                                    </tr>
                                <?php endforeach; ?>
                            </tbody>
                        </table>
                    </div>

                    <!-- Confirm import button — inside the same form as the mapping dropdowns -->
                    <div class="sp-import-confirm-box">
                            <p class="sp-import-confirm-intro">
                                <strong><?php printf( esc_html__( 'Ready to import %d members?', 'societypress' ), (int) $preview['row_count'] ); ?></strong><br>
