        ],

        // ---- Directory Visibility ----
        'dir_show_name'  => [
            'label' => __( 'Directory: Show Name', 'societypress' ),
            'value' => fn( $m ) => ( $m->dir_show_name ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_address' => [
            'label' => __( 'Directory: Show Address', 'societypress' ),
            'value' => fn( $m ) => ( $m->dir_show_address ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_phone' => [
            'label' => __( 'Directory: Show Phone', 'societypress' ),
            'value' => fn( $m ) => ( $m->dir_show_phone ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_email' => [
            'label' => __( 'Directory: Show Email', 'societypress' ),
            'value' => fn( $m ) => ( $m->dir_show_email ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_website' => [
            'label' => __( 'Directory: Show Website', 'societypress' ),
            'value' => fn( $m ) => ( $m->dir_show_website ?? 1 ) ? 'Yes' : 'No',
        ],
        'dir_show_photo' => [
            'label' => __( 'Directory: Show Photo', 'societypress' ),
            'value' => fn( $m ) => ( $m->dir_show_photo ?? 0 ) ? 'Yes' : 'No',
        ],
    ];

    // ----------------------------------------------------------------
    // Dynamic meta columns — pulled straight from the database
    //
    // WHY: Whatever a society imported or created as member meta shows
    //      up here automatically. No code changes, no config files.
    //      The meta_key becomes the column slug (prefixed with "meta:")
    //      and we generate a human-readable label from the key name.
    // ----------------------------------------------------------------
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $meta_keys = $wpdb->get_col(
        "SELECT DISTINCT meta_key FROM {$prefix}member_meta ORDER BY meta_key ASC"
    );

    // Convert meta_key slugs to human-readable labels
    // e.g. "joint_member" → "Joint Member", "skills" → "Skills"
    foreach ( $meta_keys as $mk ) {
        $label = ucwords( str_replace( [ '_', '-' ], ' ', $mk ) );
        // Prefix legacy keys for clarity
        if ( str_starts_with( $mk, 'legacy_' ) ) {
            $label = str_replace( 'Legacy ', 'Legacy: ', $label );
        }

        $columns[ 'meta:' . $mk ] = [
            'label' => $label,
            // WHY: The value getter receives the member object, but meta
            //      is stored separately. We attach all meta to the member
            //      object as ->_meta['key'] in the download handler before
            //      this closure runs. That way we query meta once in bulk
            //      instead of once per member per column.
            'value' => fn( $m ) => $m->_meta[ $mk ] ?? '',
        ];
    }

    return $columns;
}


/**
 * AJAX handler: return a filtered member count so the export page can
 * update the "X members match your filters" number in real time.
 *
 * WHY: Harold changes the Status dropdown to "Active" and immediately
 *      sees "247 members match your filters" instead of the total 356.
 *      No page reload, no guessing. He knows exactly what the CSV will
 *      contain before he clicks Download.
 */
add_action( 'wp_ajax_sp_export_count', function () {
    check_ajax_referer( 'sp_export_count' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized', 'societypress' ), 403 );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $where  = [];
    $values = [];

    $status = sanitize_text_field( $_POST['status'] ?? '' );
    if ( ! empty( $status ) && $status !== 'all' ) {
        $where[]  = 'status = %s';
        $values[] = $status;
    }

    $tier_id = absint( $_POST['tier'] ?? 0 );
    if ( $tier_id > 0 ) {
        $where[]  = 'tier_id = %d';
        $values[] = $tier_id;
    }

    $join_from = sanitize_text_field( $_POST['join_from'] ?? '' );
    $join_to   = sanitize_text_field( $_POST['join_to'] ?? '' );
    if ( ! empty( $join_from ) ) {
        $where[]  = 'join_date >= %s';
        $values[] = $join_from;
    }
    if ( ! empty( $join_to ) ) {
        $where[]  = 'join_date <= %s';
        $values[] = $join_to;
    }

    $exp_from = sanitize_text_field( $_POST['exp_from'] ?? '' );
    $exp_to   = sanitize_text_field( $_POST['exp_to'] ?? '' );
    if ( ! empty( $exp_from ) ) {
        $where[]  = 'expiration_date >= %s';
        $values[] = $exp_from;
    }
    if ( ! empty( $exp_to ) ) {
        $where[]  = 'expiration_date <= %s';
        $values[] = $exp_to;
    }

    $where_sql = '';
    if ( ! empty( $where ) ) {
        $where_sql = 'WHERE ' . implode( ' AND ', $where );
    }

    $sql = "SELECT COUNT(*) FROM {$prefix}members {$where_sql}";
    if ( ! empty( $values ) ) {
        $sql = $wpdb->prepare( $sql, $values );
    }

    $count = (int) $wpdb->get_var( $sql );
    wp_send_json_success( [ 'count' => number_format( $count ) ] );
});


/**
 * Render the Export Members admin page.
 *
 * WHY: Societies need to export their data for all kinds of reasons —
 *      mailing labels, treasurer reports, board presentations, backups,
 *      or migrating somewhere else (hopefully not). This page lets them
 *      filter by status/tier/date range and pick exactly which columns
 *      they want. Big friendly "Download CSV" button at the bottom.
 */
function sp_render_export_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Get tier list for the filter dropdown
    $tiers = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}membership_tiers ORDER BY sort_order ASC, name ASC"
    );

    // Get member count for the summary
    $total_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" );

    // All exportable columns
    $columns = sp_get_export_columns();

    // Group columns for the checkbox UI
    $groups = [
        'Identity'           => [ 'member_type', 'organization_name', 'member_number',
                                  'prefix', 'first_name', 'preferred_name',
                                  'middle_name', 'last_name', 'maiden_name', 'suffix',
                                  'date_of_birth' ],
        'Membership'         => [ 'status', 'tier_name', 'join_date', 'expiration_date' ],
        'Contact'            => [ 'email', 'phone', 'cell', 'website' ],
        'Address'            => [ 'address_1', 'address_2', 'city', 'state', 'postal_code',
                                  'country' ],
        'Seasonal Address'   => [ 'seasonal', 'seasonal_from', 'seasonal_to',
                                  'seasonal_address_1', 'seasonal_city', 'seasonal_state',
                                  'seasonal_postal_code', 'seasonal_country' ],
        'Preferences'        => [ 'receive_print', 'pref_email_notices', 'pref_email_events',
                                  'pref_email_newsletters', 'pref_email_surnames' ],
        'Directory Visibility' => [ 'dir_show_name', 'dir_show_address', 'dir_show_phone',
                                    'dir_show_email', 'dir_show_website', 'dir_show_photo' ],
    ];

    // Dynamically add any meta columns that exist in the database.
    // WHY: Whatever a society imported or created shows up automatically
    //      as checkboxes — no code changes, no config. If there are no
    //      meta keys yet, the group simply doesn't appear.
    $meta_col_keys = array_filter(
        array_keys( $columns ),
        fn( $k ) => str_starts_with( $k, 'meta:' )
    );
    if ( ! empty( $meta_col_keys ) ) {
        // Split into "useful" vs "legacy" groups so Harold isn't
        // overwhelmed by import artifacts he doesn't care about
        $custom_keys = [];
        $legacy_keys = [];
        foreach ( $meta_col_keys as $k ) {
            $raw_key = substr( $k, 5 ); // strip "meta:" prefix
            if ( str_starts_with( $raw_key, 'legacy_' ) ) {
                $legacy_keys[] = $k;
            } else {
                $custom_keys[] = $k;
            }
        }
        if ( ! empty( $custom_keys ) ) {
            $groups['Custom Fields'] = $custom_keys;
        }
        if ( ! empty( $legacy_keys ) ) {
            $groups['Legacy / Import Data'] = $legacy_keys;
        }
    }

    ?>
    <style>
    /*
     * sp_render_export_page() — admin page styles
     *
     * WHY a <style> block here instead of wp_enqueue_style():
     * These styles are small, page-specific, and only ever loaded on this
     * one admin screen. Enqueueing a separate stylesheet would add an extra
     * HTTP request for ~20 rules. A scoped <style> block keeps everything
     * self-contained, right next to the markup it styles, and easy to update.
     */

    /* Intro line: "X members match your filters…" */
    .sp-export-intro-text {
        font-size: 14px;
        color: #50575e;
        margin-bottom: 20px;
    }

    /* Outer card container — used for both Filters and Columns panels */
    .sp-export-card {
        max-width: 800px;
        background: #fff;
        border: 1px solid #c3c4c7;
        border-radius: 4px;
        margin-bottom: 20px;
    }

    /* Card title bar — grey header strip with bottom divider */
    .sp-export-card-header {
        margin: 0;
        padding: 12px 20px;
        border-bottom: 1px solid #c3c4c7;
        font-size: 14px;
        font-weight: 600;
        background: #f6f7f7;
    }

    /* Small italic note inside the Columns card header ("Leave all unchecked…") */
    .sp-export-card-header-note {
        font-weight: 400;
        color: #50575e;
        font-size: 12px;
        margin-left: 8px;
    }

    /* Inner content area padding inside each card */
    .sp-export-card-body {
        padding: 20px;
    }

    /* Reset WP's default form-table top margin so it sits flush inside the card */
    .sp-export-form-table {
        margin: 0;
    }

    /* Fixed-width date inputs so both fields in a range row line up */
    .sp-export-date-input {
        width: 160px;
    }

    /* "to" text between the two date range inputs */
    .sp-export-date-separator {
        padding: 0 8px;
        color: #50575e;
    }

    /* Row that holds the Select All / Select None links */
    .sp-export-toggle-bar {
        margin-top: 0;
        margin-bottom: 16px;
    }

    /* Select All / Select None anchor links — plain, no underline */
    .sp-export-toggle-link {
        text-decoration: none;
    }

    /* Fieldset wrapper for one column group (Identity, Membership, etc.) */
    .sp-export-col-group {
        margin-bottom: 16px;
        padding: 0;
        border: none;
    }

    /* Group legend — bold section name above its checkboxes */
    .sp-export-col-group-legend {
        font-weight: 600;
        font-size: 13px;
        margin-bottom: 6px;
