        <!-- Select All / Select None + Live Filter Count JS -->
        <script>
        (function() {
            var checkboxes = document.querySelectorAll('.sp-export-col-cb');

            document.getElementById('sp-export-select-all').addEventListener('click', function(e) {
                e.preventDefault();
                checkboxes.forEach(function(cb) { cb.checked = true; });
            });

            document.getElementById('sp-export-select-none').addEventListener('click', function(e) {
                e.preventDefault();
                checkboxes.forEach(function(cb) { cb.checked = false; });
            });

            // ============================================================
            // Live filter count — updates "X members match" when any
            // filter dropdown or date field changes.
            //
            // WHY: Immediate feedback. Harold picks "Active" from the
            //      status dropdown and instantly sees the number shrink.
            //      No guessing, no wasted exports of the wrong data set.
            // ============================================================
            var countEl   = document.getElementById('sp-export-count');
            var nonceEl   = document.getElementById('sp-export-count-nonce');
            var statusEl  = document.getElementById('sp-export-status');
            var tierEl    = document.getElementById('sp-export-tier');
            var joinFrom  = document.querySelector('input[name="sp_export_join_from"]');
            var joinTo    = document.querySelector('input[name="sp_export_join_to"]');
            var expFrom   = document.querySelector('input[name="sp_export_exp_from"]');
            var expTo     = document.querySelector('input[name="sp_export_exp_to"]');

            var debounceTimer = null;

            function updateCount() {
                // Debounce so rapid changes don't spam the server
                clearTimeout(debounceTimer);
                debounceTimer = setTimeout(function() {
                    var data = new FormData();
                    data.append('action', 'sp_export_count');
                    data.append('_ajax_nonce', nonceEl.value);
                    data.append('status', statusEl.value);
                    data.append('tier', tierEl.value);
                    data.append('join_from', joinFrom.value);
                    data.append('join_to', joinTo.value);
                    data.append('exp_from', expFrom.value);
                    data.append('exp_to', expTo.value);

                    countEl.style.opacity = '0.5';

                    fetch(ajaxurl, { method: 'POST', body: data })
                        .then(function(r) { return r.json(); })
                        .then(function(resp) {
                            if (resp.success) {
                                countEl.textContent = resp.data.count;
                            }
                            countEl.style.opacity = '1';
                        })
                        .catch(function() {
                            countEl.style.opacity = '1';
                        });
                }, 300);
            }

            // Listen on all filter inputs
            [statusEl, tierEl, joinFrom, joinTo, expFrom, expTo].forEach(function(el) {
                if (el) el.addEventListener('change', updateCount);
            });
        })();
        </script>
    </div>
    <?php
}


// ============================================================================
// SETTINGS REGISTRATION (WordPress Settings API)
// ============================================================================

/**
 * Register all settings — both SocietyPress-specific and WordPress core
 * settings that we've absorbed into our consolidated Settings page.
 *
 * WHY: Instead of scattering settings across six WordPress pages (General,
 *      Writing, Reading, Discussion, Media, Permalinks), we put everything
 *      the user needs into one clean page. WordPress core options like
 *      blogname and timezone_string are registered in our settings group
 *      so they save through the same form submission.
 *
 * HOW IT WORKS:
 *      WordPress's Settings API uses register_setting() to whitelist option
 *      names for a given settings group. When the form submits to options.php,
 *      WordPress checks that each submitted option is registered in the
 *      specified group before saving it. By registering WordPress core
 *      options (blogname, etc.) in our group, they save seamlessly alongside
 *      our custom societypress_settings option.
 */
add_action( 'admin_init', function () {

    // ====================================================================
    // SETTINGS REGISTRATION — One group per page.
    //
    // WHY separate groups: Each settings page has its own <form> that
    //      posts to options.php. WordPress only saves options that are
    //      registered under the group in the form's settings_fields().
    //      If we kept everything under one group and the Website page
    //      submitted without any societypress_settings[] fields, the
    //      sanitize callback would receive an empty array and wipe out
    //      all Organization/Membership/etc. data. Separate groups =
    //      each page only touches the options it displays.
    // ====================================================================

    // ---- WEBSITE page — WordPress core options only ----
    register_setting( 'societypress_settings_group', 'blogname',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'blogdescription',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'admin_email',
        [ 'sanitize_callback' => 'sanitize_email' ] );

    register_setting( 'societypress_settings_group', 'timezone_string',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'date_format',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'time_format',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'show_on_front',
        [ 'sanitize_callback' => 'sanitize_text_field' ] );

    register_setting( 'societypress_settings_group', 'page_on_front',
        [ 'sanitize_callback' => 'absint' ] );

    register_setting( 'societypress_settings_group', 'blog_public',
        [ 'sanitize_callback' => 'absint' ] );

    // ---- WEBSITE page also has SP settings (login requirement, admin bar) ----
    register_setting(
        'societypress_settings_group',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- ORGANIZATION page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-org',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- MEMBERSHIP page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-membership',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- DIRECTORY page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-directory',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- EVENTS page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-events',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- PRIVACY page — just the privacy policy page picker ----
    register_setting( 'sp-settings-privacy', 'wp_page_for_privacy_policy',
        [ 'sanitize_callback' => 'absint' ] );

    // ---- DESIGN page — saves to societypress_settings array ----
    register_setting(
        'sp-settings-design',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- MAILCHIMP page — saves to societypress_settings array ----
    // WHY: Follows the same pattern as every other settings page — one
    //      settings group per page, all routing through sp_sanitize_settings()
    //      so the merge logic keeps other pages' data intact.
    register_setting(
        'sp-settings-mailchimp',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- ZOOM page — saves to societypress_settings array ----
    // WHY: Same pattern as Mailchimp — separate settings group so saving
    //      Zoom credentials doesn't clobber other pages' data.
    register_setting(
        'sp-settings-zoom',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );

    // ---- AI ASSISTANT page — saves to societypress_settings array ----
    // WHY: Same pattern as Mailchimp/Zoom — separate settings group so saving
    //      AI settings doesn't clobber other pages' data.
    register_setting(
        'sp-settings-ai',
        'societypress_settings',
        [
            'type'              => 'array',
            'sanitize_callback' => 'sp_sanitize_settings',
        ]
    );


    // ====================================================================
    // SECTION: Your Website
    // ====================================================================

    add_settings_section(
        'sp_website_section',
        __( 'Your Website', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'Basic settings for your website.', 'societypress' ) . '</p>';
        },
        'sp-settings-website'
    );

    // --- Site Title ---
    add_settings_field(
        'blogname',
        __( 'Site Title', 'societypress' ),
        function () {
            printf(
                '<input type="text" name="blogname" value="%s" class="regular-text">',
                esc_attr( get_option( 'blogname', '' ) )
            );
            echo '<p class="description">' . esc_html__( 'The name of your website, shown in the browser tab and site header.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Tagline ---
    add_settings_field(
        'blogdescription',
        __( 'Tagline', 'societypress' ),
        function () {
            printf(
                '<input type="text" name="blogdescription" value="%s" class="regular-text">',
                esc_attr( get_option( 'blogdescription', '' ) )
            );
            echo '<p class="description">' . esc_html__( 'A short phrase describing your organization (appears below the site title).', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Admin Email ---
    add_settings_field(
        'admin_email',
        __( 'Admin Email', 'societypress' ),
        function () {
            printf(
                '<input type="email" name="admin_email" value="%s" class="regular-text">',
                esc_attr( get_option( 'admin_email', '' ) )
            );
            echo '<p class="description">' . esc_html__( 'Password resets and system notifications are sent to this address.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Timezone ---
    // WHY: WordPress's built-in wp_timezone_choice() dumps every city on
    //      Earth into the dropdown — hundreds of entries grouped by continent.
    //      That's overwhelming for a non-technical user who just wants to
    //      pick their timezone. We replace it with a clean list of 38 UTC
    //      offsets, each paired with one recognizable city, covering the
    //      entire world. No one needs to know the difference between
    //      America/Chicago and America/Indiana/Knox.
    add_settings_field(
        'timezone_string',
        __( 'Timezone', 'societypress' ),
        function () {
            $current_tz = get_option( 'timezone_string', '' );

            // Every UTC offset that exists, paired with one well-known city.
            // The PHP timezone identifier is what WordPress actually stores.
            $timezones = [
                'Etc/GMT+12'         => 'UTC−12:00 — Baker Island',
                'Pacific/Pago_Pago'  => 'UTC−11:00 — Pago Pago',
                'Pacific/Honolulu'   => 'UTC−10:00 — Honolulu',
                'Pacific/Marquesas'  => 'UTC−09:30 — Marquesas Islands',
                'America/Anchorage'  => 'UTC−09:00 — Anchorage',
                'America/Los_Angeles'=> 'UTC−08:00 — Los Angeles',
                'America/Denver'     => 'UTC−07:00 — Denver',
                'America/Chicago'    => 'UTC−06:00 — Chicago, ND',
                'America/New_York'   => 'UTC−05:00 — New York',
                'America/Santiago'   => 'UTC−04:00 — Santiago',
                'America/St_Johns'   => 'UTC−03:30 — St. John\'s',
                'America/Sao_Paulo'  => 'UTC−03:00 — São Paulo',
                'America/Noronha'    => 'UTC−02:00 — Fernando de Noronha',
                'Atlantic/Cape_Verde'=> 'UTC−01:00 — Praia',
                'Europe/London'      => 'UTC±00:00 — London',
                'Europe/Paris'       => 'UTC+01:00 — Paris',
                'Africa/Cairo'       => 'UTC+02:00 — Cairo',
                'Europe/Moscow'      => 'UTC+03:00 — Moscow',
                'Asia/Tehran'        => 'UTC+03:30 — Tehran',
                'Asia/Dubai'         => 'UTC+04:00 — Dubai',
                'Asia/Kabul'         => 'UTC+04:30 — Kabul',
                'Asia/Karachi'       => 'UTC+05:00 — Karachi',
                'Asia/Kolkata'       => 'UTC+05:30 — Mumbai',
                'Asia/Kathmandu'     => 'UTC+05:45 — Kathmandu',
                'Asia/Dhaka'         => 'UTC+06:00 — Dhaka',
                'Asia/Yangon'        => 'UTC+06:30 — Yangon',
                'Asia/Bangkok'       => 'UTC+07:00 — Bangkok',
                'Asia/Shanghai'      => 'UTC+08:00 — Beijing',
                'Australia/Eucla'    => 'UTC+08:45 — Eucla',
                'Asia/Tokyo'         => 'UTC+09:00 — Tokyo',
                'Australia/Adelaide' => 'UTC+09:30 — Adelaide',
                'Australia/Sydney'   => 'UTC+10:00 — Sydney',
                'Australia/Lord_Howe'=> 'UTC+10:30 — Lord Howe Island',
                'Pacific/Noumea'     => 'UTC+11:00 — Nouméa',
                'Pacific/Auckland'   => 'UTC+12:00 — Auckland',
                'Pacific/Chatham'    => 'UTC+12:45 — Chatham Islands',
                'Pacific/Apia'       => 'UTC+13:00 — Apia',
                'Pacific/Kiritimati' => 'UTC+14:00 — Kiritimati',
            ];

            echo '<select name="timezone_string">';

            // Default empty option if nothing is set yet
            if ( empty( $current_tz ) ) {
                echo '<option value="">' . esc_html__( '— Select your timezone —', 'societypress' ) . '</option>';
            }

            foreach ( $timezones as $tz_id => $label ) {
                printf(
                    '<option value="%s" %s>%s</option>',
                    esc_attr( $tz_id ),
                    selected( $current_tz, $tz_id, false ),
                    esc_html( $label )
                );
            }

            echo '</select>';
            echo '<p class="description">' . esc_html__( 'Choose the timezone where your organization is located.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Date Format ---
    // WHY: We show live examples using Harold's actual current date (in his
    //      configured timezone) so the preview matches reality. No more
    //      guessing what "F j, Y" means — he sees today's date formatted
    //      each way and picks the one that looks right.
    add_settings_field(
        'date_format',
        __( 'Date Format', 'societypress' ),
        function () {
            $current = get_option( 'date_format', 'F j, Y' );

            // Each format paired with a human-friendly description.
            // wp_date() automatically uses the site's configured timezone,
            // so Harold sees HIS current date, not the server's.
            $formats = [
                'l, F jS, Y' => 'Full day name',      // Thursday, February 12th, 2026
                'F j, Y'     => 'Month and day',       // February 12, 2026
                'M j, Y'     => 'Short month',         // Feb 12, 2026
                'm/d/Y'      => 'US numeric',          // 02/12/2026
                'd/m/Y'      => 'International numeric',// 12/02/2026
                'Y-m-d'      => 'ISO standard',        // 2026-02-12
            ];

            foreach ( $formats as $format => $hint ) {
                // wp_date() respects the site timezone — shows Harold's local date
                $example = wp_date( $format );
                printf(
                    '<label class="sp-block-mb-6">'
                    . '<input type="radio" name="date_format" value="%s" %s> '
                    . '<span>%s</span>'
                    . '</label>',
                    esc_attr( $format ),
                    checked( $current, $format, false ),
                    esc_html( $example )
                );
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Time Format ---
    // WHY: Same approach as date — live examples using Harold's current
    //      time in his timezone. The "with timezone" option (g:i A T) shows
    //      the abbreviation (CST, EST, etc.) so readers know at a glance
    //      which timezone events and dates refer to.
    add_settings_field(
        'time_format',
        __( 'Time Format', 'societypress' ),
        function () {
            $current = get_option( 'time_format', 'g:i A' );

            $formats = [
                'g:i A'   => '12-hour',               // 1:30 PM
                'g:i A T' => '12-hour with timezone',  // 1:30 PM CST
                'H:i'     => '24-hour',                // 13:30
            ];

            foreach ( $formats as $format => $hint ) {
                // wp_date() respects the site timezone — shows Harold's local time
                $example = wp_date( $format );
                printf(
                    '<label class="sp-block-mb-6">'
                    . '<input type="radio" name="time_format" value="%s" %s> '
                    . '<span>%s</span>'
                    . '</label>',
                    esc_attr( $format ),
                    checked( $current, $format, false ),
                    esc_html( $example )
                );
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Homepage ---
    add_settings_field(
        'page_on_front',
        __( 'Homepage', 'societypress' ),
        function () {
            $page_on_front = get_option( 'page_on_front', 0 );

            // We always use a static page for the homepage, not "latest posts."
            // A society website isn't a blog — the front page should be a
            // designed welcome page, not a reverse-chronological post feed.
            echo '<input type="hidden" name="show_on_front" value="page">';

            // wp_dropdown_pages() outputs nothing if there are no published
            // pages — which leaves Harold staring at a bare description with
            // no dropdown. We check for that and show a helpful message instead.
            // WHY not get_pages(['number'=>1]): The 'number' param in get_pages()
            // doesn't reliably limit results in all WP versions. A direct count
            // query is fast and always works.
            global $wpdb;
            $pages_exist = (int) $wpdb->get_var( "SELECT COUNT(*) FROM $wpdb->posts WHERE post_type = 'page' AND post_status = 'publish'" );
            if ( $pages_exist > 0 ) {
                wp_dropdown_pages( [
                    'name'              => 'page_on_front',
                    'show_option_none'  => __( '— Select a page —', 'societypress' ),
                    'option_none_value' => '0',
                    'selected'          => $page_on_front,
                ] );
                echo '<p class="description">' . esc_html__( 'Choose which page visitors see when they go to your website\'s address.', 'societypress' ) . '</p>';
            } else {
                echo '<p class="description">'
                   . sprintf(
                       /* translators: %s: URL to create a new page */
                       __( 'No pages have been created yet. <a href="%s">Create your first page</a>, then come back here to set it as your homepage.', 'societypress' ),
                       esc_url( admin_url( 'post-new.php?post_type=page' ) )
                   )
                   . '</p>';
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Search Engine Visibility ---
    add_settings_field(
        'blog_public',
        __( 'Search Engines', 'societypress' ),
        function () {
            $blog_public = get_option( 'blog_public', 1 );

            // Hidden field ensures blog_public=1 is submitted even when the
            // checkbox is unchecked. When checked, the checkbox value (0)
