    // --- Page Groups in Navigation ---
    // WHY: Page groups automatically organize the nav menu into dropdown
    //      folders. Harold creates groups on the Pages admin page and they
    //      appear as nav dropdowns without touching the WordPress menu editor.
    //      Off means Harold uses the standard WP menu editor instead.
    add_settings_field(
        'auto_group_nav',
        __( 'Page Groups in Navigation', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $enabled  = ! empty( $settings['auto_group_nav'] );

            echo '<input type="hidden" name="societypress_settings[auto_group_nav]" value="0">';
            printf(
                '<label><input type="checkbox" name="societypress_settings[auto_group_nav]" value="1" %s> %s</label>',
                checked( $enabled, true, false ),
                esc_html__( 'Automatically organize navigation using page groups', 'societypress' )
            );
            echo '<p class="description">'
               . esc_html__( 'When enabled, page groups you create on the Pages admin page will automatically appear as dropdown folders in the site navigation. Disable this if you prefer to manage menus manually.', 'societypress' )
               . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Social Media Links ---
    // WHY on the Website tab: Social links are site-wide branding, not
    // org-specific contact info. They control what shows in the header,
    // so they belong with other site display settings.
    add_settings_field(
        'social_facebook',
        __( 'Social Media', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );

            $socials = [
                'social_facebook'  => [ 'Facebook',  'https://facebook.com/yourpage' ],
                'social_youtube'   => [ 'YouTube',   'https://youtube.com/@yourchannel' ],
                'social_instagram' => [ 'Instagram', 'https://instagram.com/yourhandle' ],
                'social_tiktok'    => [ 'TikTok',    'https://tiktok.com/@yourhandle' ],
                'social_x'         => [ 'X (Twitter)', 'https://x.com/yourhandle' ],
            ];

            foreach ( $socials as $key => [ $label, $placeholder ] ) {
                $val = esc_attr( $settings[ $key ] ?? '' );
                printf(
                    '<div class="sp-mb-8">'
                    . '<label style="display:inline-block; width:100px; font-weight:500;">%s</label>'
                    . '<input type="url" name="societypress_settings[%s]" value="%s" placeholder="%s" '
                    . 'style="width:400px; max-width:100%%;">'
                    . '</div>',
                    esc_html( $label ),
                    esc_attr( $key ),
                    $val,
                    esc_attr( $placeholder )
                );
            }

            echo '<p class="description">' . esc_html__( 'Enter the full URL for each platform your society uses. Leave blank to hide. Icons appear in the site header.', 'societypress' ) . '</p>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Breadcrumbs ---
    // WHY on the Website tab: Breadcrumbs are a site-wide navigation UI
    // element, not org-specific. The admin should be able to toggle them,
    // customize the home label, and change the separator character.
    add_settings_field(
        'breadcrumbs_enabled',
        __( 'Breadcrumbs', 'societypress' ),
        function () {
            $settings  = get_option( 'societypress_settings', [] );
            $enabled   = ! empty( $settings['breadcrumbs_enabled'] );
            $home      = esc_attr( $settings['breadcrumb_home_label'] ?? 'Home' );
            $separator = esc_attr( $settings['breadcrumb_separator'] ?? '›' );

            // Hidden field ensures breadcrumbs_enabled = 0 is submitted when unchecked
            echo '<input type="hidden" name="societypress_settings[breadcrumbs_enabled]" value="0">';
            printf(
                '<label><input type="checkbox" name="societypress_settings[breadcrumbs_enabled]" value="1" %s> '
                . '%s</label>',
                checked( $enabled, true, false ),
                esc_html__( 'Automatically show breadcrumb navigation above page content', 'societypress' )
            );
            echo '<p class="description">'
               . esc_html__( 'Breadcrumbs show a trail like "Home › Events › Annual Picnic" to help visitors navigate.', 'societypress' )
               . '</p>';

            // Home label and separator — only relevant when breadcrumbs are enabled,
            // but we always render them so they're preserved on save.
            echo '<div class="sp-mt-12">';
            printf(
                '<label style="display:inline-block; width:120px; font-weight:500;">%s</label>'
                . '<input type="text" name="societypress_settings[breadcrumb_home_label]" value="%s" '
                . 'style="width:160px;" placeholder="' . esc_attr__( 'Home', 'societypress' ) . '">',
                esc_html__( 'Home label', 'societypress' ),
                $home
            );
            echo '</div>';
            echo '<div style="margin-top:6px;">';
            printf(
                '<label style="display:inline-block; width:120px; font-weight:500;">%s</label>'
                . '<input type="text" name="societypress_settings[breadcrumb_separator]" value="%s" '
                . 'style="width:60px;" placeholder="›">',
                esc_html__( 'Separator', 'societypress' ),
                $separator
            );
            echo '<span class="description" class="sp-ml-8">'
               . esc_html__( 'Character between crumbs (default: ›)', 'societypress' )
               . '</span>';
            echo '</div>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // Google Analytics — Measurement ID field.
    // WHY: Harold can paste in his GA4 measurement ID and get tracking
    //      immediately — no extra plugins needed. We also let him exclude
    //      admin traffic so his own page views don't pollute the data.
    add_settings_field(
        'analytics_google_id',
        __( 'Google Analytics', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $ga_id    = esc_attr( $settings['analytics_google_id'] ?? '' );
            $exclude  = ! empty( $settings['analytics_exclude_admins'] );

            printf(
                '<input type="text" name="societypress_settings[analytics_google_id]" '
                . 'value="%s" class="regular-text" placeholder="G-XXXXXXXXXX">',
                $ga_id
            );
            echo '<p class="description">'
               . esc_html__( 'Your Google Analytics 4 Measurement ID (starts with G-). Leave blank to disable tracking.', 'societypress' )
               . '</p>';

            echo '<div style="margin-top:8px;">';
            echo '<input type="hidden" name="societypress_settings[analytics_exclude_admins]" value="0">';
            printf(
                '<label><input type="checkbox" name="societypress_settings[analytics_exclude_admins]" value="1" %s> '
                . '%s</label>',
                checked( $exclude, true, false ),
                esc_html__( 'Exclude logged-in administrators from tracking', 'societypress' )
            );
            echo '<p class="description">'
               . esc_html__( 'When checked, page views by site admins won\'t appear in your analytics.', 'societypress' )
               . '</p>';
            echo '</div>';
        },
        'sp-settings-website',
        'sp_website_section'
    );

    // --- Progressive Web App (PWA) ---
    // WHY: PWA support lets members "install" the society website on their phone
    // home screen and use it offline. This is especially valuable for societies
    // that host events in areas with poor connectivity (rural courthouses,
    // church basements, etc.). Gated behind a toggle because service workers
    // and manifests should only be active once the site is configured.
    add_settings_field(
        'pwa_enabled',
        __( 'Progressive Web App', 'societypress' ),
        function () {
            $settings        = get_option( 'societypress_settings', [] );
            $enabled         = ! empty( $settings['pwa_enabled'] );
            $offline_message = esc_attr( $settings['pwa_offline_message'] ?? __( 'You appear to be offline. Please check your connection.', 'societypress' ) );

            echo '<input type="hidden" name="societypress_settings[pwa_enabled]" value="0">';
            printf(
                '<label><input type="checkbox" name="societypress_settings[pwa_enabled]" value="1" %s> '
                . '%s</label>',
                checked( $enabled, true, false ),
                esc_html__( 'Enable Progressive Web App features', 'societypress' )
            );
            echo '<p class="description">'
               . esc_html__( 'When enabled, members can install your site as an app on their phone or tablet. The site will also work offline with cached content.', 'societypress' )
               . '</p>';

            echo '<div class="sp-mt-12">';
            printf(
                '<label style="display:block; font-weight:500; margin-bottom:4px;">%s</label>'
                . '<input type="text" name="societypress_settings[pwa_offline_message]" value="%s" '
                . 'class="large-text" placeholder="%s">',
                esc_html__( 'Offline Message', 'societypress' ),
                $offline_message,
                esc_attr__( 'You appear to be offline. Please check your connection.', 'societypress' )
            );
            echo '<p class="description">'
               . esc_html__( 'Shown to visitors when they lose their internet connection.', 'societypress' )
               . '</p>';
            echo '</div>';

            // --- Push Notifications sub-section (only visible when PWA is enabled) ---
            // WHY: Push requires PWA (service worker) to function. Showing push settings
            // only when PWA is on prevents Harold from enabling push on a site that
            // can't actually deliver notifications. The toggle is nested under the
            // PWA field so the relationship is visually obvious.
            $push_on = ! empty( $settings['push_enabled'] );
            if ( $enabled ) {
                echo '<div class="sp-mt-12" style="border-top:1px solid #ddd; padding-top:12px; margin-top:16px;">';
                echo '<input type="hidden" name="societypress_settings[push_enabled]" value="0">';
                printf(
                    '<label><input type="checkbox" name="societypress_settings[push_enabled]" value="1" %s> '
                    . '%s</label>',
                    checked( $push_on, true, false ),
                    esc_html__( 'Enable push notifications', 'societypress' )
                );
                echo '<p class="description">'
                   . esc_html__( 'Allow members to subscribe to push notifications from their browser. Notifications can be sent for new events, announcements, and reminders.', 'societypress' )
                   . '</p>';

                // Show subscriber count if push is enabled
                if ( $push_on ) {
                    $sub_count = sp_pwa_push_subscriber_count();
                    printf(
                        '<p class="description sp-mt-8"><strong>%s</strong> %s</p>',
                        esc_html( number_format_i18n( $sub_count ) ),
                        esc_html( _n( 'subscriber', 'subscribers', $sub_count, 'societypress' ) )
                    );
                }

                echo '</div>';
            }
        },
        'sp-settings-website',
        'sp_website_section'
    );


