    );

    // --- Help Request Notifications ---
    // WHY: When a member posts a research help request, the society can
    //      optionally notify all opted-in members so they can contribute.
    //      This is off by default since it could be noisy for large societies.
    add_settings_field(
        'help_requests_notify_all',
        __( 'Research Help Notifications', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $checked  = ! empty( $settings['help_requests_notify_all'] );
            printf(
                '<label><input type="checkbox" name="societypress_settings[help_requests_notify_all]" value="1" %s> '
                . esc_html__( 'Email all opted-in members when a new research help request is posted', 'societypress' ) . '</label>',
                checked( $checked, true, false )
            );
            echo '<p class="description">' . esc_html__( 'Only members who have "General Notices" email preference enabled will receive these notifications.', 'societypress' ) . '</p>';
        },
        'sp-settings-org',
        'sp_org_section'
    );

    // --- Currency Symbol ---
    // WHY: Non-US societies need €, £, ¥, etc. This lets Harold set the
    //      currency symbol once and have it apply everywhere — finances,
    //      tiers, events, store, donations, emails.
    add_settings_field(
        'currency_symbol',
        __( 'Currency Symbol', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $value    = $settings['currency_symbol'] ?? '$';
            printf(
                '<input type="text" name="societypress_settings[currency_symbol]" value="%s" class="small-text" maxlength="5" class="sp-w-60">',
                esc_attr( $value )
            );
            echo '<p class="description">' . esc_html__( 'The symbol shown next to monetary amounts (e.g., $, €, £, ¥).', 'societypress' ) . '</p>';
        },
        'sp-settings-org',
        'sp_org_section'
    );

    // --- Currency Position ---
    // WHY: Some currencies place the symbol before the amount ($25.00) and
    //      others place it after (25,00 €). This dropdown handles both.
    add_settings_field(
        'currency_position',
        __( 'Currency Position', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $current  = $settings['currency_position'] ?? 'before';
            ?>
            <select name="societypress_settings[currency_position]">
                <option value="before" <?php selected( $current, 'before' ); ?>><?php esc_html_e( 'Before amount ($25.00)', 'societypress' ); ?></option>
                <option value="after" <?php selected( $current, 'after' ); ?>><?php esc_html_e( 'After amount (25.00€)', 'societypress' ); ?></option>
            </select>
            <p class="description"><?php esc_html_e( 'Whether the currency symbol appears before or after the number.', 'societypress' ); ?></p>
            <?php
        },
        'sp-settings-org',
        'sp_org_section'
    );


    // ---- Store Settings ----
    // WHY: The store pulls products from the library catalog. Different
    //      societies use different acq_code values (e.g., "Society Publication",
    //      "Society Books", etc.). Making this configurable removes the last
    //      hardcoded the society reference and lets any society use the store.
    add_settings_section(
        'sp_store_section',
        __( 'Store', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'Configure the publications store. Products are pulled from your library catalog — any item with a price becomes a store product.', 'societypress' ) . '</p>';
        },
        'sp-settings-org'
    );

    add_settings_field(
        'store_acq_code',
        __( 'Product Source (acq_code)', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $value    = $settings['store_acq_code'] ?? '';
            // Get distinct acq_codes from the library to help Harold pick the right one
            global $wpdb;
            $codes = $wpdb->get_col( "SELECT DISTINCT acq_code FROM {$wpdb->prefix}sp_library_items WHERE acq_code IS NOT NULL AND acq_code != '' ORDER BY acq_code" );
            printf(
                '<input type="text" name="societypress_settings[store_acq_code]" value="%s" class="regular-text" list="sp-acq-codes" placeholder="%s">',
                esc_attr( $value ),
                esc_attr__( 'Leave blank to show all priced items', 'societypress' )
            );
            if ( ! empty( $codes ) ) {
                echo '<datalist id="sp-acq-codes">';
                foreach ( $codes as $code ) {
                    echo '<option value="' . esc_attr( $code ) . '">';
                }
                echo '</datalist>';
            }
            echo '<p class="description">' . esc_html__( 'Filter store products to this acquisition code from your library catalog. Leave blank to include all items with a price.', 'societypress' ) . '</p>';
        },
        'sp-settings-org',
        'sp_store_section'
    );

    add_settings_field(
        'store_intro_text',
        __( 'Store Introduction', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $value    = $settings['store_intro_text'] ?? '';
            printf(
                '<textarea name="societypress_settings[store_intro_text]" rows="3" class="large-text" placeholder="%s">%s</textarea>',
                esc_attr__( 'A short paragraph about your publications (optional)', 'societypress' ),
                esc_textarea( $value )
            );
            echo '<p class="description">' . esc_html__( 'Shown above the product grid. Leave blank for a default message using your organization name.', 'societypress' ) . '</p>';
        },
        'sp-settings-org',
        'sp_store_section'
    );


    // ====================================================================
    // SECTION: Membership
    // WHY: Every society has different rules for how long a membership
    //      lasts and when it expires. These settings let each society
    //      configure their own bylaws so the plugin can auto-calculate
    //      expiration dates when adding new members.
    // ====================================================================

    add_settings_section(
        'sp_membership_section',
        __( 'Membership Period', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'How your organization calculates membership duration and expiration dates. These settings are used to pre-fill expiration dates when adding new members.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership'
    );

    // --- Membership Period Type ---
    // WHY: Most societies use a fixed fiscal or calendar year, but some
    //      use a rolling 12-month period from the date dues are paid.
    //      This setting drives the entire expiration calculation.
    add_settings_field(
        'sp_membership_period_type',
        __( 'Membership Period', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $current  = $settings['membership_period_type'] ?? 'annual';

            $types = [
                'annual'   => __( 'Annual — fixed period (fiscal or calendar year)', 'societypress' ),
                'rolling'  => __( 'Rolling — 12 months from the date dues are paid', 'societypress' ),
                'lifetime' => __( 'Lifetime — memberships never expire', 'societypress' ),
            ];

            foreach ( $types as $value => $label ) {
                printf(
                    '<label class="sp-block-mb-6">'
                    . '<input type="radio" name="societypress_settings[membership_period_type]" '
                    . 'value="%s" %s> %s</label>',
                    esc_attr( $value ),
                    checked( $current, $value, false ),
                    esc_html( $label )
                );
            }
        },
        'sp-settings-membership',
        'sp_membership_section'
    );

    // --- Period Start Month ---
    // WHY: A fiscal year can start in any month. July is common for
    //      genealogical societies. January = calendar year. This drives
    //      when the period ends and when renewals are due.
    add_settings_field(
        'sp_membership_start_month',
        __( 'Period Starts', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $current  = (int) ( $settings['membership_start_month'] ?? 7 );

            $months = [
                1 => 'January',   2 => 'February',  3 => 'March',
                4 => 'April',     5 => 'May',        6 => 'June',
                7 => 'July',      8 => 'August',     9 => 'September',
                10 => 'October',  11 => 'November',  12 => 'December',
            ];

            echo '<select name="societypress_settings[membership_start_month]">';
            foreach ( $months as $num => $name ) {
                printf(
                    '<option value="%d" %s>%s</option>',
                    $num,
                    selected( $current, $num, false ),
                    esc_html( $name )
                );
            }
            echo '</select>';
            echo '<p class="description">' . esc_html__( 'The month your membership year begins. For calendar-year societies, choose January. Only applies to Annual period type.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership',
        'sp_membership_section'
    );

    // --- Late-Join Credit ---
    // WHY: If someone joins near the end of the current period, they
    //      shouldn't pay full annual dues for just a few months. This
    //      setting rolls their dues into the next period automatically.
    //      Example: set to 3 = dues paid in the last 3 months of the
    //      period credit to the following period.
    add_settings_field(
        'sp_late_join_months',
        __( 'Late-Join Credit', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $current  = (int) ( $settings['late_join_months'] ?? 5 );

            printf(
                '<input type="number" name="societypress_settings[late_join_months]" '
                . 'value="%d" min="0" max="11" class="sp-w-60"> ' . esc_html__( 'months', 'societypress' ),
                $current
            );
            echo '<p class="description">' . esc_html__( 'If a new member joins within this many months of the period ending, their dues are credited to the next period. Only applies to Annual period type.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership',
        'sp_membership_section'
    );

    // --- Grace Period ---
    // WHY: Societies typically give existing members a window to renew
    //      after the new period starts before dropping them. This setting
    //      defines that window. Example: 2 = members have until 2 months
    //      after the period starts to pay before being marked lapsed.
    add_settings_field(
        'sp_grace_period_months',
        __( 'Renewal Grace Period', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $current  = (int) ( $settings['grace_period_months'] ?? 2 );

            printf(
                '<input type="number" name="societypress_settings[grace_period_months]" '
                . 'value="%d" min="0" max="11" class="sp-w-60"> ' . esc_html__( 'months', 'societypress' ),
                $current
            );
            echo '<p class="description">' . esc_html__( 'How long after the new period starts before unpaid members are considered lapsed. Only applies to Annual period type.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership',
        'sp_membership_section'
    );

    // --- Renewal Reminder Section ---
    // WHY: Automated reminders save Harold hours every renewal cycle.
    //      Instead of manually tracking who's about to expire and sending
    //      individual emails, the plugin does it automatically.
    add_settings_section(
        'sp_renewal_reminder_section',
        __( 'Renewal Reminders', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'Automatically email members before their membership expires. A daily check runs behind the scenes — each member receives each reminder only once.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership'
    );

    add_settings_field(
        'renewal_reminder_timings',
        __( 'Send Reminders', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $checks = [
                'renewal_reminder_30d' => __( '30 days before expiration', 'societypress' ),
                'renewal_reminder_15d' => __( '15 days before expiration', 'societypress' ),
                'renewal_reminder_7d'  => __( '7 days before expiration', 'societypress' ),
            ];
            foreach ( $checks as $key => $label ) {
                $checked = ! empty( $settings[ $key ] );
                printf(
                    '<label style="display:block; margin-bottom:6px;">'
                    . '<input type="checkbox" name="societypress_settings[%s]" value="1" %s> %s'
                    . '</label>',
                    esc_attr( $key ),
                    checked( $checked, true, false ),
                    esc_html( $label )
                );
            }
        },
        'sp-settings-membership',
        'sp_renewal_reminder_section'
    );

    add_settings_field(
        'renewal_reminder_subject',
        __( 'Email Subject', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $value    = $settings['renewal_reminder_subject'] ?? 'Your membership expires soon';
            printf(
                '<input type="text" name="societypress_settings[renewal_reminder_subject]" value="%s" class="regular-text">',
                esc_attr( $value )
            );
            echo '<p class="description">' . esc_html__( 'Subject line for renewal reminder emails.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership',
        'sp_renewal_reminder_section'
    );


    // ---- Expired Membership Notice ----
    // WHY: After the renewal reminders have gone out (30d, 15d, 7d before expiry),
    //      there's one more email to send: the day AFTER expiration, a notice that
    //      their membership has lapsed. This is the last automated nudge.
    add_settings_section(
        'sp_expired_notice_section',
        'Expired Membership Notice',
        function () {
            echo '<p>' . esc_html__( 'Send a one-time email the day after a member\'s membership expires. '
                . 'This is in addition to the pre-expiration renewal reminders above.', 'societypress' ) . '</p>';
        },
        'sp-settings-membership'
    );

    add_settings_field(
        'expired_notice_enabled',
        __( 'Enable', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $checked  = ! empty( $settings['expired_notice_enabled'] );
            printf(
                '<label><input type="checkbox" name="societypress_settings[expired_notice_enabled]" value="1" %s> '
                . '%s</label>',
                checked( $checked, true, false ),
                esc_html__( 'Send an email when a membership expires', 'societypress' )
            );
        },
        'sp-settings-membership',
        'sp_expired_notice_section'
    );

    add_settings_field(
        'expired_notice_subject',
        __( 'Email Subject', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $value    = $settings['expired_notice_subject'] ?? 'Your membership has expired';
            printf(
                '<input type="text" name="societypress_settings[expired_notice_subject]" value="%s" class="regular-text">',
                esc_attr( $value )
            );
            echo '<p class="description">' . esc_html__( 'Merge tags: {{first_name}}, {{last_name}}, {{organization_name}}', 'societypress' ) . '</p>';
        },
        'sp-settings-membership',
        'sp_expired_notice_section'
    );


    // ====================================================================
    // SECTION: Privacy
    // ====================================================================

    add_settings_section(
        'sp_privacy_section',
        __( 'Privacy', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'If you have a Privacy Policy page, select it here.', 'societypress' ) . '</p>';
        },
        'sp-settings-privacy'
    );

    // --- Privacy Policy Page ---
    add_settings_field(
        'wp_page_for_privacy_policy',
        __( 'Privacy Policy Page', 'societypress' ),
        function () {
            $privacy_page = get_option( 'wp_page_for_privacy_policy', 0 );

            // Same guard as Homepage — don't show an invisible empty dropdown.
            global $wpdb;
            $pages_exist = (int) $wpdb->get_var( "SELECT COUNT(*) FROM $wpdb->posts WHERE post_type = 'page' AND post_status = 'publish'" );
            if ( $pages_exist > 0 ) {
                wp_dropdown_pages( [
                    'name'              => 'wp_page_for_privacy_policy',
                    'show_option_none'  => __( '— Select a page —', 'societypress' ),
                    'option_none_value' => '0',
                    'selected'          => $privacy_page,
                ] );
                echo '<p class="description">' . esc_html__( 'This helps your site comply with privacy regulations.', 'societypress' ) . '</p>';
            } else {
                echo '<p class="description">' . esc_html__( 'No pages have been created yet. You can set a privacy policy page after you\'ve created some pages.', 'societypress' ) . '</p>';
            }
        },
        'sp-settings-privacy',
        'sp_privacy_section'
    );


    // ====================================================================
    // SECTION: Directory
    //
    // WHY: The society decides which member information appears on the
    //      public membership directory page. This is a society-level
    //      decision — "we show names and cities, not phone numbers."
    //      Individual members can further opt out of specific fields
    //      via their own Directory Visibility checkboxes on their profile.
    //
    //      Two layers of control:
    //        1) Society admin: toggles here decide which columns exist at all
    //        2) Individual member: dir_show_* checkboxes on their profile
    //           let them hide their own data within the columns the admin enabled
    // ====================================================================

    add_settings_section(
        'sp_directory_section',
        __( 'Member Directory', 'societypress' ),
        function () {
            echo '<p>' . esc_html__( 'Choose which fields appear on the public membership directory page. Individual members can opt out of showing their own information through the Directory Visibility settings on their profile.', 'societypress' ) . '</p>';
        },
        'sp-settings-directory'
    );

    // --- Directory Columns ---
    // WHY: One clean multi-checkbox field is easier to scan than eight
    //      separate settings fields. The admin sees exactly what will and
    //      won't appear on the directory page at a glance.
    add_settings_field(
        'dir_columns',
        __( 'Visible Columns', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );

            // Each column the admin can toggle on/off.
            // Name is always shown — you can't have a directory without names.
            $columns = [
                'dir_show_city_state' => [ __( 'City / State', 'societypress' ),        __( 'Show city and state', 'societypress' ) ],
                'dir_show_phone'      => [ __( 'Phone', 'societypress' ),               __( 'Show phone number', 'societypress' ) ],
                'dir_show_email'      => [ __( 'Email', 'societypress' ),               __( 'Show email address', 'societypress' ) ],
                'dir_show_website'    => [ __( 'Website', 'societypress' ),             __( 'Show personal website', 'societypress' ) ],
                'dir_show_tier'       => [ __( 'Membership Type', 'societypress' ),     __( 'Show membership tier (e.g., Single, Joint, Life)', 'societypress' ) ],
                'dir_show_join_date'  => [ __( 'Member Since', 'societypress' ),        __( 'Show the date they joined', 'societypress' ) ],
                'dir_show_surnames'   => [ __( 'Surnames Researched', 'societypress' ), __( 'Show surnames the member is researching — this is the key feature that connects researchers', 'societypress' ) ],
            ];

            echo '<fieldset>'
               . '<p style="margin-bottom: 8px; color: #666;"><em>' . esc_html__( 'Name is always displayed.', 'societypress' ) . '</em></p>';

            foreach ( $columns as $key => $info ) {
                $checked = ! empty( $settings[ $key ] );
                printf(
                    '<label class="sp-block-mb-6">'
                    . '<input type="checkbox" name="societypress_settings[%s]" value="1" %s> '
                    . '<strong>%s</strong> — %s'
                    . '</label>',
                    esc_attr( $key ),
                    checked( $checked, true, false ),
                    esc_html( $info[0] ),
                    esc_html( $info[1] )
                );
            }

            echo '</fieldset>';
        },
        'sp-settings-directory',
        'sp_directory_section'
    );

    // --- Results Per Page ---
    add_settings_field(
        'dir_per_page',
        __( 'Results Per Page', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $current  = (int) ( $settings['dir_per_page'] ?? 25 );

            $options = [ 10, 25, 50, 100, 250, 500 ];

            echo '<select name="societypress_settings[dir_per_page]">';
            foreach ( $options as $val ) {
                printf(
                    '<option value="%d" %s>%d</option>',
                    $val,
                    selected( $current, $val, false ),
                    $val
                );
            }
            echo '</select>';
            echo '<p class="description">' . esc_html__( 'How many members to show per page in the public directory.', 'societypress' ) . '</p>';
        },
        'sp-settings-directory',
        'sp_directory_section'
    );

    // --- Require Approval for Profile Changes ---
    // WHY: Some societies want to verify member-initiated changes (name,
    //      contact, address) before they go live — prevents accidental or
    //      unauthorized changes from showing up in the directory immediately.
    //      When enabled, edits to Personal Info, Contact, and Address sections
    //      go into a pending queue instead of saving directly. Preferences,
    //      privacy, interests, and genealogy changes still save immediately
    //      since those aren't identity-critical.
    add_settings_field(
        'profile_changes_require_approval',
        __( 'Profile Change Approval', 'societypress' ),
        function () {
            $settings = get_option( 'societypress_settings', [] );
            $checked  = ! empty( $settings['profile_changes_require_approval'] );
            echo '<label>';
            echo '<input type="checkbox" name="societypress_settings[profile_changes_require_approval]" value="1" '
               . checked( $checked, true, false ) . '>';
            echo ' ' . esc_html__( 'Require admin approval for member profile changes', 'societypress' );
            echo '</label>';
            echo '<p class="description">'
               . esc_html__( 'When enabled, changes to Personal Info, Contact Information, and Address sections must be approved by an admin before taking effect. Other sections (preferences, privacy, interests) save immediately.', 'societypress' )
               . '</p>';
        },
        'sp-settings-directory',
        'sp_directory_section'
    );

});


// ============================================================================
// EXPIRATION DATE CALCULATOR
// ============================================================================

/**
 * Calculate the expected membership expiration date from a join date.
 *
 * WHY: Every society has different bylaws for when memberships expire.
 *      Rather than making the volunteer do date math, we auto-calculate
 *      based on the society's configured settings. The volunteer can
 *      always override the result on the form.
 *
 * LOGIC:
 *   - Rolling: join date + 12 months.
 *   - Annual:  find the end of the membership period (last day of the
 *              month before the start month). If the join date falls
 *              within the "late-join credit" window (N months before the
 *              period ends), roll forward to the NEXT period's end.
 *
 * @param string $join_date  The join date in Y-m-d format.
 * @param array  $settings   The societypress_settings option array.
 * @return string Expiration date in Y-m-d format, or empty string on error.
 */
function sp_calculate_expiration( string $join_date, array $settings ): string {
    if ( empty( $join_date ) ) {
        return '';
    }

    $period_type  = $settings['membership_period_type'] ?? 'annual';
    $start_month  = (int) ( $settings['membership_start_month'] ?? 7 );
    $credit_months = (int) ( $settings['late_join_months'] ?? 5 );

    // --- Rolling: simply add 12 months ---
    if ( $period_type === 'rolling' ) {
        $dt = date_create( $join_date );
        if ( ! $dt ) return '';
        $dt->modify( '+12 months' );
        return $dt->format( 'Y-m-d' );
    }

    // --- Annual: calculate fiscal year end ---
    $dt = date_create( $join_date );
    if ( ! $dt ) return '';

    $join_year  = (int) $dt->format( 'Y' );
    $join_month = (int) $dt->format( 'n' );

    // The period ends on the last day of the month BEFORE the start month.
    // Example: start_month = 7 (July) → period ends June 30.
    // Example: start_month = 1 (Jan)  → period ends December 31.
    $end_month = ( $start_month === 1 ) ? 12 : $start_month - 1;

    // Determine the calendar year of the period end.
    // If the period spans two calendar years (start_month > 1), the end
    // falls in the NEXT calendar year for anyone joining on or after
    // the start month, and the SAME calendar year for earlier joiners.
    if ( $start_month === 1 ) {
        // Calendar year: Jan–Dec, ends in the same year
        $end_year = $join_year;
    } else {
        if ( $join_month >= $start_month ) {
            // Joined after the period started → ends next calendar year
            $end_year = $join_year + 1;
        } else {
            // Joined before the period starts → still in the period
            // that started last year, ends this calendar year
            $end_year = $join_year;
        }
    }

    // Last day of the end month
    $end_date = date_create( sprintf( '%04d-%02d-01', $end_year, $end_month ) );
    $end_date->modify( 'last day of this month' );

    // Check if the join date falls in the late-join credit window.
    // If there are $credit_months or fewer months remaining before the
    // period ends, roll forward to the NEXT period (add 12 months).
    $months_remaining = ( (int) $end_date->format( 'Y' ) * 12 + (int) $end_date->format( 'n' ) )
                      - ( $join_year * 12 + $join_month );

    if ( $months_remaining <= $credit_months ) {
        $end_date->modify( '+12 months' );
        // Recalculate last day in case of month-length differences
        $end_date->modify( 'last day of this month' );
    }

    return $end_date->format( 'Y-m-d' );
}


// ============================================================================
// FIELD RENDERERS
// ============================================================================

/**
 * Render a single-line text input for the Settings page.
 *
 * WHY: Each settings field needs a function that outputs the actual HTML.
 *      We keep these generic so adding new fields later is trivial — just
 *      pass a different 'key' and 'placeholder' in the args array.
 *
 * @param array $args Field arguments from add_settings_field() — contains
 *                    'key' (which setting), 'placeholder', and optional 'type'.
 */
function sp_render_text_field( array $args ): void {
    $settings = get_option( 'societypress_settings', [] );
    $value    = $settings[ $args['key'] ] ?? '';
    $type     = $args['type'] ?? 'text';
    $id_attr  = ! empty( $args['id'] ) ? sprintf( ' id="%s"', esc_attr( $args['id'] ) ) : '';

    printf(
        '<input type="%s" name="societypress_settings[%s]" value="%s" placeholder="%s" class="regular-text"%s>',
        esc_attr( $type ),
        esc_attr( $args['key'] ),
        esc_attr( $value ),
        esc_attr( $args['placeholder'] ?? '' ),
        $id_attr
    );
}

/**
 * Render a multi-line textarea for the Settings page.
 *
 * @param array $args Field arguments — contains 'key' and 'placeholder'.
 */
function sp_render_textarea_field( array $args ): void {
    $settings = get_option( 'societypress_settings', [] );
    $value    = $settings[ $args['key'] ] ?? '';

    printf(
        '<textarea name="societypress_settings[%s]" placeholder="%s" class="large-text" rows="3">%s</textarea>',
        esc_attr( $args['key'] ),
        esc_attr( $args['placeholder'] ?? '' ),
        esc_textarea( $value )
    );
}


// ============================================================================
// SANITIZE CALLBACK
// ============================================================================

/**
 * Clean all SocietyPress-specific settings before they're saved.
 *
 * WHY: Never trust user input, even from admin users. We strip HTML tags
 *      and trim whitespace to prevent XSS and keep data clean.
 *
 *      WordPress core settings (blogname, timezone_string, etc.) have their
 *      own sanitize callbacks registered individually above — they don't
 *      go through this function.
 *
 * @param array $input The raw form values.
 * @return array Sanitized values safe for storage.
 */
function sp_sanitize_settings( array $input ): array {

    // WHY belt-and-suspenders: The WP Settings API gates options.php behind
    // manage_options, but an explicit check here ensures no code path ever
    // reaches the sanitizer without the right capability.
    if ( ! current_user_can( 'manage_options' ) ) {
        add_settings_error( 'societypress_settings', 'unauthorized', __( 'Unauthorized.', 'societypress' ) );
        return get_option( 'societypress_settings', [] );
    }

    // ---- MERGE, don't replace ----
    // WHY: Each settings page now has its own form that only submits the
    //      fields on that page. If we rebuilt the entire array from scratch
    //      (the old approach), saving Organization would wipe out Design,
    //      Events, Directory, etc. — because those keys wouldn't be in
    //      $input at all and would get their defaults.
    //
    //      Instead we start from the existing saved values and only overwrite
    //      keys that are actually present in the submitted form data.
    $existing = get_option( 'societypress_settings', [] );

    // Master sanitization rules — each key maps to its sanitizer.
    // WHY a lookup table: Keeps every field's sanitization visible in one
    // place. When adding a new setting, add one line here and you're done.
    $sanitizers = [
        // Organization
        'store_acq_code'          => fn() => sanitize_text_field( $input['store_acq_code'] ?? '' ),
        'store_intro_text'        => fn() => sanitize_textarea_field( $input['store_intro_text'] ?? '' ),
        // Website
        'website_require_login'   => fn() => ! empty( $input['website_require_login'] ) ? 1 : 0,
        'website_show_admin_bar'  => fn() => ! empty( $input['website_show_admin_bar'] ) ? 1 : 0,
        'social_facebook'         => fn() => esc_url_raw( $input['social_facebook'] ?? '' ),
        'social_youtube'          => fn() => esc_url_raw( $input['social_youtube'] ?? '' ),
        'social_instagram'        => fn() => esc_url_raw( $input['social_instagram'] ?? '' ),
        'social_tiktok'           => fn() => esc_url_raw( $input['social_tiktok'] ?? '' ),
        'social_x'                => fn() => esc_url_raw( $input['social_x'] ?? '' ),
        'breadcrumbs_enabled'     => fn() => ! empty( $input['breadcrumbs_enabled'] ) ? 1 : 0,
        'breadcrumb_home_label'   => fn() => sanitize_text_field( $input['breadcrumb_home_label'] ?? 'Home' ),
        'breadcrumb_separator'    => fn() => sanitize_text_field( $input['breadcrumb_separator'] ?? '›' ),

        // Analytics — Google Analytics
        'analytics_google_id'     => fn() => preg_match( '/^(G|UA|GT)-[A-Z0-9-]+$/i', $input['analytics_google_id'] ?? '' )
                                              ? sanitize_text_field( $input['analytics_google_id'] ) : '',
        'analytics_exclude_admins'=> fn() => ! empty( $input['analytics_exclude_admins'] ) ? 1 : 0,

        // PWA — Progressive Web App
        'pwa_enabled'             => fn() => ! empty( $input['pwa_enabled'] ) ? 1 : 0,
        'pwa_offline_message'     => fn() => sanitize_text_field( $input['pwa_offline_message'] ?? __( 'You appear to be offline. Please check your connection.', 'societypress' ) ),

        // Page Groups
        'auto_group_nav'          => fn() => ! empty( $input['auto_group_nav'] ) ? 1 : 0,

        // Organization
        'organization_name'       => fn() => sanitize_text_field( $input['organization_name'] ?? '' ),
        'organization_address'    => fn() => sanitize_textarea_field( $input['organization_address'] ?? '' ),
        'organization_phone'      => fn() => sanitize_text_field( $input['organization_phone'] ?? '' ),
        'organization_email'      => fn() => sanitize_email( $input['organization_email'] ?? '' ),
        'community_forum_url'     => fn() => esc_url_raw( $input['community_forum_url'] ?? '' ),
        'help_requests_notify_all'=> fn() => ! empty( $input['help_requests_notify_all'] ) ? 1 : 0,
        // Currency — symbol and position for all monetary displays
        'currency_symbol'         => fn() => sanitize_text_field( $input['currency_symbol'] ?? '$' ),
        'currency_position'       => fn() => in_array( $input['currency_position'] ?? '', [ 'before', 'after' ], true )
                                              ? $input['currency_position'] : 'before',

        // Membership
        'membership_period_type'  => fn() => in_array( $input['membership_period_type'] ?? '', [ 'annual', 'rolling', 'lifetime' ], true )
                                              ? $input['membership_period_type'] : 'annual',
        'membership_start_month'  => fn() => max( 1, min( 12, (int) ( $input['membership_start_month'] ?? 7 ) ) ),
        'late_join_months'        => fn() => max( 0, min( 11, (int) ( $input['late_join_months'] ?? 3 ) ) ),
        'grace_period_months'     => fn() => max( 0, min( 11, (int) ( $input['grace_period_months'] ?? 2 ) ) ),
        'renewal_reminder_30d'    => fn() => ! empty( $input['renewal_reminder_30d'] ) ? 1 : 0,
        'renewal_reminder_15d'    => fn() => ! empty( $input['renewal_reminder_15d'] ) ? 1 : 0,
        'renewal_reminder_7d'     => fn() => ! empty( $input['renewal_reminder_7d'] ) ? 1 : 0,
        'renewal_reminder_subject'=> fn() => sanitize_text_field( $input['renewal_reminder_subject'] ?? 'Your membership expires soon' ),
        'expired_notice_enabled'  => fn() => ! empty( $input['expired_notice_enabled'] ) ? 1 : 0,
        'expired_notice_subject'  => fn() => sanitize_text_field( $input['expired_notice_subject'] ?? 'Your membership has expired' ),

        // Directory — checkboxes: present = 1, absent = 0
        'dir_show_city_state'     => fn() => ! empty( $input['dir_show_city_state'] ) ? 1 : 0,
        'dir_show_phone'          => fn() => ! empty( $input['dir_show_phone'] ) ? 1 : 0,
        'dir_show_email'          => fn() => ! empty( $input['dir_show_email'] ) ? 1 : 0,
        'dir_show_website'        => fn() => ! empty( $input['dir_show_website'] ) ? 1 : 0,
        'dir_show_tier'           => fn() => ! empty( $input['dir_show_tier'] ) ? 1 : 0,
        'dir_show_join_date'      => fn() => ! empty( $input['dir_show_join_date'] ) ? 1 : 0,
        'dir_show_surnames'       => fn() => ! empty( $input['dir_show_surnames'] ) ? 1 : 0,
        'dir_per_page'            => fn() => in_array( (int) ( $input['dir_per_page'] ?? 25 ), [ 10, 25, 50, 100, 250, 500 ], true )
                                              ? (int) $input['dir_per_page'] : 25,
        'profile_changes_require_approval' => fn() => ! empty( $input['profile_changes_require_approval'] ) ? 1 : 0,

        // Events
        'events_default_visibility'   => fn() => in_array( $input['events_default_visibility'] ?? '', [ 'public', 'members_only' ], true )
                                                   ? $input['events_default_visibility'] : 'public',
        'events_default_registration' => fn() => ! empty( $input['events_default_registration'] ) ? 1 : 0,
        'events_guest_registration'   => fn() => ! empty( $input['events_guest_registration'] ) ? 1 : 0,
        'events_per_page'             => fn() => in_array( (int) ( $input['events_per_page'] ?? 12 ), [ 6, 12, 24, 48 ], true )
                                                   ? (int) $input['events_per_page'] : 12,
        'events_calendar_start_day'   => fn() => in_array( (int) ( $input['events_calendar_start_day'] ?? 0 ), [ 0, 1 ], true )
                                                   ? (int) $input['events_calendar_start_day'] : 0,
        'events_ical_feed_enabled'    => fn() => ! empty( $input['events_ical_feed_enabled'] ) ? 1 : 0,
        'events_reminder_1_day'       => fn() => ! empty( $input['events_reminder_1_day'] ) ? 1 : 0,
        'events_reminder_3_days'      => fn() => ! empty( $input['events_reminder_3_days'] ) ? 1 : 0,
        'events_reminder_1_week'      => fn() => ! empty( $input['events_reminder_1_week'] ) ? 1 : 0,
        'events_confirmation_subject' => fn() => sanitize_text_field( $input['events_confirmation_subject'] ?? 'Registration Confirmed: {event_title}' ),
        'events_reminder_subject'     => fn() => sanitize_text_field( $input['events_reminder_subject'] ?? 'Reminder: {event_title} is coming up' ),

        // Stripe payment settings
        'stripe_test_mode'            => fn() => ! empty( $input['stripe_test_mode'] ) ? 1 : 0,
        'stripe_test_publishable_key' => fn() => sanitize_text_field( $input['stripe_test_publishable_key'] ?? '' ),
        // WHY: Stripe secret keys are encrypted at rest using libsodium via
        // sp_encrypt(). This prevents plaintext API keys from sitting in the
        // wp_options table where a SQL injection or database leak would expose them.
        'stripe_test_secret_key'      => function() use ( $input ) {
            $val = sanitize_text_field( $input['stripe_test_secret_key'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'stripe_live_publishable_key' => fn() => sanitize_text_field( $input['stripe_live_publishable_key'] ?? '' ),
        'stripe_live_secret_key'      => function() use ( $input ) {
            $val = sanitize_text_field( $input['stripe_live_secret_key'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'stripe_currency'             => fn() => in_array( $input['stripe_currency'] ?? '', [ 'usd', 'cad', 'gbp', 'eur', 'aud' ], true )
                                                   ? $input['stripe_currency'] : 'usd',

        // PayPal payment settings
        'paypal_test_mode'            => fn() => ! empty( $input['paypal_test_mode'] ) ? 1 : 0,
        'paypal_sandbox_client_id'    => fn() => sanitize_text_field( $input['paypal_sandbox_client_id'] ?? '' ),
        'paypal_sandbox_secret'       => function() use ( $input ) {
            $val = sanitize_text_field( $input['paypal_sandbox_secret'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'paypal_live_client_id'       => fn() => sanitize_text_field( $input['paypal_live_client_id'] ?? '' ),
        'paypal_live_secret'          => function() use ( $input ) {
            $val = sanitize_text_field( $input['paypal_live_secret'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },

        // Design — site-wide appearance customization
        // WHY sanitize_hex_color with fallbacks: We must ensure valid hex colors
        // are stored. If someone tampers with the form and sends garbage, we
        // fall back to the original theme defaults so the site never breaks.
        'design_color_primary'        => fn() => sanitize_hex_color( $input['design_color_primary'] ?? '' ) ?: '#1e3a5f',
        'design_color_primary_hover'  => fn() => sanitize_hex_color( $input['design_color_primary_hover'] ?? '' ) ?: '#2c5282',
        'design_color_accent'         => fn() => sanitize_hex_color( $input['design_color_accent'] ?? '' ) ?: '#667eea',
        'design_color_header_bg'      => fn() => sanitize_hex_color( $input['design_color_header_bg'] ?? '' ) ?: '#1e3a5f',
        'design_color_header_text'    => fn() => sanitize_hex_color( $input['design_color_header_text'] ?? '' ) ?: '#ffffff',
        'design_color_footer_bg'      => fn() => sanitize_hex_color( $input['design_color_footer_bg'] ?? '' ) ?: '#1e3a5f',
        'design_color_footer_text'    => fn() => sanitize_hex_color( $input['design_color_footer_text'] ?? '' ) ?: '#ffffff',
        'design_font_body'            => fn() => in_array( $input['design_font_body'] ?? '', [ 'system', 'georgia', 'palatino', 'garamond', 'merriweather', 'lora', 'roboto', 'open-sans', 'source-sans', 'nunito' ], true )
                                                   ? $input['design_font_body'] : 'system',
        'design_font_heading'         => fn() => in_array( $input['design_font_heading'] ?? '', [ 'inherit', 'system', 'georgia', 'palatino', 'garamond', 'merriweather', 'lora', 'roboto', 'open-sans', 'source-sans', 'nunito' ], true )
                                                   ? $input['design_font_heading'] : 'inherit',
        'design_font_size'            => fn() => in_array( $input['design_font_size'] ?? '', [ 'compact', 'comfortable', 'large' ], true )
                                                   ? $input['design_font_size'] : 'comfortable',
        'design_heading_scale'        => fn() => in_array( $input['design_heading_scale'] ?? '', [ 'small', 'normal', 'large' ], true )
                                                   ? $input['design_heading_scale'] : 'normal',
        'design_content_width'        => fn() => in_array( $input['design_content_width'] ?? '', [ 'narrow', 'standard', 'wide', 'custom' ], true )
                                                   ? $input['design_content_width'] : 'standard',

        // Logo — stores the attachment ID from the Media Library.
        // WHY absint: Attachment IDs are always positive integers. Zero = no logo.
        'design_logo_id'              => fn() => absint( $input['design_logo_id'] ?? 0 ),

        // Header title/tagline toggle — 1 = show, 0 = hide.
        // WHY: Some societies have their name baked into their logo and don't
        //      want it repeated as text next to it. Default on (1) so existing
        //      sites aren't affected.
        'design_show_header_title'    => fn() => ! empty( $input['design_show_header_title'] ) ? 1 : 0,

        // Header height in pixels. 0 = auto (no explicit height set).
        // WHY: Some societies want to match a specific header size from a
        //      reference design. Clamped to 50–500px to prevent absurd values.
        'design_header_height'        => fn() => max( 0, min( 500, (int) ( $input['design_header_height'] ?? 0 ) ) ),

        // Content width in exact pixels. Replaces the old preset dropdown.
        // WHY: Harold may need to match a specific design width (e.g., 975px).
        //      Clamped to 600–2000px to prevent unusable layouts.
        'design_content_width_px'     => fn() => max( 600, min( 2000, (int) ( $input['design_content_width_px'] ?? 1100 ) ) ),
        'design_logo_height'          => fn() => max( 0, min( 300, (int) ( $input['design_logo_height'] ?? 0 ) ) ),
        'design_header_padding'       => fn() => max( 0, min( 100, (int) ( $input['design_header_padding'] ?? 0 ) ) ),
        'design_nav_font_size'        => fn() => max( 0, min( 72, (int) ( $input['design_nav_font_size'] ?? 0 ) ) ),
        'design_nav_spacing'           => fn() => max( 0, min( 40, (int) ( $input['design_nav_spacing'] ?? 0 ) ) ),
        'design_nav_font_weight'      => fn() => in_array( $input['design_nav_font_weight'] ?? '', [ '', '300', '400', '500', '600', '700' ], true ) ? ( $input['design_nav_font_weight'] ?? '' ) : '',
        'design_color_footer_link'    => fn() => sanitize_hex_color( $input['design_color_footer_link'] ?? '' ) ?: '',
        'design_show_social_icons'    => fn() => (int) ! empty( $input['design_show_social_icons'] ),

        // Mailchimp Integration
        // WHY: The API key is encrypted at rest just like Stripe/PayPal secrets —
        // if the database leaks, the Mailchimp API key is useless without the
        // encryption key. The data center (dc) is auto-extracted from the API key
        // (the part after the dash, e.g., "us21") so Harold doesn't have to figure
        // out which Mailchimp data center he's on.
        'mailchimp_api_key'           => function() use ( $input ) {
            $val = sanitize_text_field( $input['mailchimp_api_key'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'mailchimp_audience_id'       => fn() => sanitize_text_field( $input['mailchimp_audience_id'] ?? '' ),
        'mailchimp_sync_enabled'      => fn() => ! empty( $input['mailchimp_sync_enabled'] ) ? 1 : 0,
        'mailchimp_dc'                => function() use ( $input ) {
            // Auto-extract the data center from the API key — it's the part after
            // the last dash, e.g., "abc123-us21" → "us21". Harold never needs to
            // know or type this manually.
            $key = sanitize_text_field( $input['mailchimp_api_key'] ?? '' );
            if ( $key && strpos( $key, '-' ) !== false ) {
                return substr( $key, strrpos( $key, '-' ) + 1 );
            }
            return '';
        },

        // Push Notifications
        // WHY: push_enabled is a simple toggle; VAPID keys are auto-generated
        // and should not be changed by form submission — they're set once and
        // stored encrypted. We only sanitize push_enabled here.
        'push_enabled'                => fn() => ! empty( $input['push_enabled'] ) ? 1 : 0,

        // Zoom Integration
        // WHY: API key and secret are encrypted at rest — same pattern as
        // Stripe/PayPal/Mailchimp. If the database leaks, the Zoom credentials
        // are useless without the encryption key.
        'zoom_api_key'                => function() use ( $input ) {
            $val = sanitize_text_field( $input['zoom_api_key'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'zoom_api_secret'             => function() use ( $input ) {
            $val = sanitize_text_field( $input['zoom_api_secret'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'zoom_account_email'          => fn() => sanitize_email( $input['zoom_account_email'] ?? '' ),

        // AI Assistant Integration
        // WHY: The API key is encrypted at rest — same pattern as Stripe, PayPal,
        // Mailchimp, and Zoom. If the database leaks, the Claude API key is
        // useless without the encryption key.
        'ai_enabled'                  => fn() => ! empty( $input['ai_enabled'] ) ? 1 : 0,
        'ai_api_key'                  => function() use ( $input ) {
            $val = sanitize_text_field( $input['ai_api_key'] ?? '' );
            return $val ? sp_encrypt( $val ) : '';
        },
        'ai_model'                    => fn() => in_array( $input['ai_model'] ?? '', [ 'claude-haiku-4-5-20251001', 'claude-sonnet-4-6-20250514' ], true )
                                                   ? $input['ai_model'] : 'claude-haiku-4-5-20251001',
        'ai_access'                   => fn() => in_array( $input['ai_access'] ?? '', [ 'members', 'public', 'disabled' ], true )
                                                   ? $input['ai_access'] : 'members',
        'ai_data_sources'             => function() use ( $input ) {
            // WHY: Data sources are submitted as an array of checkboxes. We
            // whitelist against the known source slugs to prevent injection.
            $allowed = [ 'events', 'library', 'resources', 'records', 'pages' ];
            $raw     = (array) ( $input['ai_data_sources'] ?? [] );
            return array_values( array_intersect( $raw, $allowed ) );
        },
        'ai_system_prompt'            => fn() => sanitize_textarea_field( $input['ai_system_prompt'] ?? '' ),
        'ai_max_monthly_queries'      => fn() => max( 10, min( 50000, (int) ( $input['ai_max_monthly_queries'] ?? 500 ) ) ),
    ];

    // Only sanitize + update keys that were actually submitted in the form.
    // Keys not in $input are left untouched from the existing saved values.
    // WHY array_key_exists instead of isset: checkbox fields that are unchecked
    // won't be in $input at all — but we still need to handle them. We detect
    // which PAGE submitted based on which known keys appear in $input, then
    // process all keys that belong to that page (including missing checkboxes).
    //
    // Page detection: look for a "signature" key unique to each page's form.
    // This tells us which group of keys to process (and zero out unchecked
    // checkboxes for), while leaving every other page's data untouched.
    $page_keys = [];

    // Website page — signature: website_require_login hidden field is always present
    if ( array_key_exists( 'website_require_login', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'website_require_login', 'website_show_admin_bar',
            'social_facebook', 'social_youtube', 'social_instagram',
            'social_tiktok', 'social_x',
            'breadcrumbs_enabled', 'breadcrumb_home_label', 'breadcrumb_separator',
            'analytics_google_id', 'analytics_exclude_admins',
            'pwa_enabled', 'pwa_offline_message', 'push_enabled', 'auto_group_nav',
        ]);
    }

    // Organization page — signature: organization_name is always in the form
    if ( array_key_exists( 'organization_name', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'organization_name', 'organization_address', 'organization_phone',
            'organization_email', 'community_forum_url', 'help_requests_notify_all',
            'currency_symbol', 'currency_position',
            'store_acq_code', 'store_intro_text',
        ]);
    }

    // Membership page — signature: membership_period_type radio is always present
    if ( array_key_exists( 'membership_period_type', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'membership_period_type', 'membership_start_month', 'late_join_months',
            'grace_period_months', 'renewal_reminder_30d', 'renewal_reminder_15d',
            'renewal_reminder_7d', 'renewal_reminder_subject',
        ]);
    }

    // Directory page — signature: dir_per_page select is always present
    if ( array_key_exists( 'dir_per_page', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'dir_show_city_state', 'dir_show_phone', 'dir_show_email',
            'dir_show_website', 'dir_show_tier', 'dir_show_join_date',
            'dir_show_surnames', 'dir_per_page', 'profile_changes_require_approval',
        ]);
    }

    // Events page — signature: events_default_visibility select is always present
    if ( array_key_exists( 'events_default_visibility', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'events_default_visibility', 'events_default_registration',
            'events_guest_registration', 'events_per_page',
            'events_calendar_start_day', 'events_ical_feed_enabled',
            'events_reminder_1_day', 'events_reminder_3_days',
            'events_reminder_1_week', 'events_confirmation_subject',
            'events_reminder_subject', 'stripe_test_mode',
            'stripe_test_publishable_key', 'stripe_test_secret_key',
            'stripe_live_publishable_key', 'stripe_live_secret_key',
            'stripe_currency',
            'paypal_test_mode', 'paypal_sandbox_client_id',
            'paypal_sandbox_secret', 'paypal_live_client_id',
            'paypal_live_secret',
        ]);
    }

    // Design page — signature: design_font_body select is always present
    if ( array_key_exists( 'design_font_body', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'design_color_primary', 'design_color_primary_hover',
            'design_color_accent', 'design_color_header_bg',
            'design_color_header_text', 'design_color_footer_bg',
            'design_color_footer_text', 'design_font_body',
            'design_font_heading', 'design_font_size',
            'design_heading_scale', 'design_content_width',
            'design_logo_id', 'design_show_header_title',
            'design_header_height', 'design_content_width_px',
            'design_logo_height', 'design_header_padding',
            'design_nav_font_size', 'design_nav_spacing', 'design_nav_font_weight',
            'design_color_footer_link', 'design_show_social_icons',
        ]);
    }

    // Mailchimp page — signature: mailchimp_audience_id is always in the form
    // WHY: We use mailchimp_audience_id as the signature key because it's a
    //      text field that will always be submitted (even if empty), unlike
    //      checkbox fields that disappear when unchecked.
    if ( array_key_exists( 'mailchimp_audience_id', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'mailchimp_api_key', 'mailchimp_audience_id',
            'mailchimp_sync_enabled', 'mailchimp_dc',
        ]);
    }

    // Zoom page — signature: zoom_account_email is always in the form
    // WHY: Same pattern as Mailchimp — zoom_account_email is a text field
    //      that will always be submitted even if empty.
    if ( array_key_exists( 'zoom_account_email', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'zoom_api_key', 'zoom_api_secret', 'zoom_account_email',
        ]);
    }

    // AI Assistant page — signature: ai_model select is always in the form
    // WHY: Same pattern as Zoom/Mailchimp — ai_model is a select field
    //      that will always be submitted even if the default is selected.
    if ( array_key_exists( 'ai_model', $input ) ) {
        $page_keys = array_merge( $page_keys, [
            'ai_enabled', 'ai_api_key', 'ai_model', 'ai_access',
            'ai_data_sources', 'ai_system_prompt', 'ai_max_monthly_queries',
        ]);
    }

    // Apply sanitizers only for the keys that belong to the submitting page
    $result = $existing;
    foreach ( $page_keys as $key ) {
        if ( isset( $sanitizers[ $key ] ) ) {
            $result[ $key ] = $sanitizers[ $key ]();
        }
    }

    // Sync logo to WordPress's custom_logo theme mod.
    // WHY: The theme reads the logo via has_custom_logo() / the_custom_logo(),
    //      which uses get_theme_mod('custom_logo'). We store the attachment ID
    //      in our own settings array (design_logo_id) so it's part of the SP
    //      settings system, but we also write it to the theme mod so the theme
    //      picks it up without any changes to header.php.
    if ( in_array( 'design_logo_id', $page_keys, true ) ) {
        $logo_id = $result['design_logo_id'] ?? 0;
        if ( $logo_id ) {
            set_theme_mod( 'custom_logo', $logo_id );
        } else {
            remove_theme_mod( 'custom_logo' );
        }
    }

    // Audit log: settings updated
    sp_audit( 'settings_updated', 'Settings saved.', 'settings' );

    return $result;
}


// ============================================================================
// INSTALLER WIZARD — First-run setup experience
// ============================================================================
//
// WHY: When a society admin installs SocietyPress for the first time, they
//      shouldn't have to hunt through settings tabs to get basic info entered.
//      The wizard walks them through organization details, membership config,
//      and key settings in a friendly step-by-step flow. Once completed, the
//      wizard never shows again (a flag is saved in options).
//
// FLOW:
//   1. Plugin activation sets default settings
//   2. First admin visit triggers redirect to wizard
//   3. Wizard collects: org info → membership → appearance → done
//   4. Wizard saves settings and marks itself complete
//   5. Admin is redirected to the SocietyPress dashboard

/**
 * Register the hidden wizard admin page.
 */
function sp_register_wizard_page(): void {
    add_submenu_page(
        null, // Hidden — no menu link
        __( 'SocietyPress Setup', 'societypress' ),
        __( 'Setup Wizard', 'societypress' ),
        'manage_options',
        'sp-setup-wizard',
        'sp_render_setup_wizard'
    );
}
add_action( 'admin_menu', 'sp_register_wizard_page', 1 );

/**
 * On first admin visit after activation, redirect to the setup wizard.
 *
 * WHY: We use a transient set during activation (sp_activation_redirect)
 *      to trigger a one-time redirect. The wizard only shows if it hasn't
 *      been completed yet (checked via sp_wizard_completed option).
 */
function sp_maybe_redirect_to_wizard(): void {
    // Only redirect if: transient exists, wizard not completed, user is admin
    if ( ! get_transient( 'sp_activation_redirect' ) ) {
        return;
    }
    delete_transient( 'sp_activation_redirect' );

    // Don't redirect if wizard already completed
    if ( get_option( 'sp_wizard_completed' ) ) {
        return;
    }

    // Don't redirect during bulk activation or AJAX
    if ( wp_doing_ajax() || isset( $_GET['activate-multi'] ) ) {
        return;
    }

    // Don't redirect if already on the wizard page
    if ( isset( $_GET['page'] ) && $_GET['page'] === 'sp-setup-wizard' ) {
        return;
    }

    wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard' ) );
    exit;
}
add_action( 'admin_init', 'sp_maybe_redirect_to_wizard' );

/**
 * Render the multi-step setup wizard.
 */
function sp_render_setup_wizard(): void {
    $settings = get_option( 'societypress_settings', [] );
    $step     = (int) ( $_GET['step'] ?? 1 );

    // Handle form submission
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_wizard_nonce'] ) ) {
        check_admin_referer( 'sp_setup_wizard', 'sp_wizard_nonce' );
        $step = (int) ( $_POST['wizard_step'] ?? 1 );

        switch ( $step ) {
            case 1: // Organization info
                $settings['organization_name']    = sanitize_text_field( $_POST['organization_name'] ?? '' );
                $settings['organization_email']   = sanitize_email( $_POST['organization_email'] ?? '' );
                $settings['organization_address'] = sanitize_textarea_field( $_POST['organization_address'] ?? '' );
                $settings['organization_phone']   = sanitize_text_field( $_POST['organization_phone'] ?? '' );
                update_option( 'societypress_settings', $settings );
                wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard&step=2' ) );
                exit;

            case 2: // Membership settings
                $settings['membership_period_type'] = sanitize_text_field( $_POST['membership_period_type'] ?? 'annual' );
                $settings['membership_start_month'] = (int) ( $_POST['membership_start_month'] ?? 7 );
                update_option( 'societypress_settings', $settings );
                wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard&step=3' ) );
                exit;

            case 3: // Feature selection
                // WHY: Collect which modules the admin wants enabled. All are
                // checked by default in the form. Unchecked modules get disabled.
                $all_module_slugs = array_keys( sp_get_modules() );
                $enabled = [];
                foreach ( $all_module_slugs as $slug ) {
                    if ( ! empty( $_POST['sp_module_' . $slug] ) ) {
                        $enabled[] = $slug;
                    }
                }
                update_option( 'sp_enabled_modules', $enabled );
                wp_safe_redirect( admin_url( 'admin.php?page=sp-setup-wizard&step=4' ) );
                exit;

            case 4: // Appearance
                $settings['design_color_primary'] = sanitize_hex_color( $_POST['design_color_primary'] ?? '#1e3a5f' );
                $settings['design_color_accent']  = sanitize_hex_color( $_POST['design_color_accent'] ?? '#667eea' );
                $settings['email_from_name']      = sanitize_text_field( $_POST['email_from_name'] ?? '' );
                $settings['email_from_email']     = sanitize_email( $_POST['email_from_email'] ?? '' );
                update_option( 'societypress_settings', $settings );

                // Mark wizard as complete
                update_option( 'sp_wizard_completed', 1 );

                // Log it
                if ( function_exists( 'sp_audit' ) ) {
                    sp_audit( 'wizard_completed', 'Setup wizard completed.', 'settings' );
                }

                wp_safe_redirect( admin_url( 'admin.php?page=societypress&wizard=done' ) );
                exit;
        }
    }

    // Prevent the default admin UI from wrapping our wizard
    ?>
    <style>
        .sp-wizard-wrap { max-width: 640px; margin: 40px auto; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }
        .sp-wizard-header { text-align: center; margin-bottom: 32px; }
        .sp-wizard-header h1 { font-size: 28px; margin: 0 0 8px; }
        .sp-wizard-header p { color: #646970; font-size: 15px; margin: 0; }
        .sp-wizard-steps { display: flex; justify-content: center; gap: 8px; margin-bottom: 32px; }
        .sp-wizard-step { width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 14px; font-weight: 600; }
        .sp-wizard-step.active { background: #2271b1; color: #fff; }
        .sp-wizard-step.done { background: #00a32a; color: #fff; }
        .sp-wizard-step.pending { background: #dcdcde; color: #646970; }
        .sp-wizard-step-line { width: 40px; height: 2px; background: #dcdcde; align-self: center; }
        .sp-wizard-card { background: #fff; border: 1px solid #c3c4c7; border-radius: 8px; padding: 32px; }
        .sp-wizard-card h2 { margin: 0 0 8px; font-size: 20px; }
        .sp-wizard-card .desc { color: #646970; margin-bottom: 24px; }
        .sp-wizard-field { margin-bottom: 20px; }
        .sp-wizard-field label { display: block; font-weight: 600; margin-bottom: 4px; font-size: 14px; }
