// ============================================================================
// MEMBER RELATIONSHIPS — Family/household connections
// ============================================================================

/**
 * Get all relationships for a member.
 *
 * @param int $user_id The member's user ID.
 * @return array Array of relationship objects with related_user_id, relationship, note,
 *               and the related user's display_name and email.
 */
function sp_get_member_relationships( int $user_id ): array {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_member_relationships';

    // Query both directions — user can be in either column
    return $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*,
                CASE WHEN r.user_id_a = %d THEN r.user_id_b ELSE r.user_id_a END AS related_user_id,
                CASE WHEN r.user_id_a = %d THEN ub.display_name ELSE ua.display_name END AS related_name,
                CASE WHEN r.user_id_a = %d THEN ub.user_email ELSE ua.user_email END AS related_email
         FROM {$table} r
         LEFT JOIN {$wpdb->users} ua ON r.user_id_a = ua.ID
         LEFT JOIN {$wpdb->users} ub ON r.user_id_b = ub.ID
         WHERE r.user_id_a = %d OR r.user_id_b = %d
         ORDER BY r.relationship ASC",
        $user_id, $user_id, $user_id, $user_id, $user_id
    ) );
}

/**
 * Add a relationship between two members.
 *
 * WHY: We always store the lower user_id as user_id_a to prevent
 *      duplicate entries (A→B and B→A would be the same relationship).
 *
 * @param int    $user_a       First member's user ID.
 * @param int    $user_b       Second member's user ID.
 * @param string $relationship Relationship type (spouse, parent, child, sibling, household).
 * @param string $note         Optional note.
 * @return int|false The relationship ID, or false on failure.
 */
function sp_add_member_relationship( int $user_a, int $user_b, string $relationship = 'spouse', string $note = '' ) {
    if ( $user_a === $user_b ) return false;

    global $wpdb;
    $table = $wpdb->prefix . 'sp_member_relationships';

    // Always store lower ID first for consistent uniqueness
    $a = min( $user_a, $user_b );
    $b = max( $user_a, $user_b );

    // Check if relationship already exists
    $exists = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE user_id_a = %d AND user_id_b = %d",
        $a, $b
    ) );
    if ( $exists ) return (int) $exists;

    $wpdb->insert( $table, [
        'user_id_a'    => $a,
        'user_id_b'    => $b,
        'relationship' => $relationship,
        'note'         => $note ?: null,
        'created_by'   => get_current_user_id() ?: null,
        'created_at'   => current_time( 'mysql' ),
    ] );

    return $wpdb->insert_id ? (int) $wpdb->insert_id : false;
}

/**
 * Remove a relationship by ID.
 */
function sp_remove_member_relationship( int $rel_id ): bool {
    global $wpdb;
    return (bool) $wpdb->delete(
        $wpdb->prefix . 'sp_member_relationships',
        [ 'id' => $rel_id ]
    );
}

/**
 * Get the spouse/partner of a member (if any).
 *
 * WHY: Quick lookup for the most common relationship type. Useful for
 *      displaying "Joint membership with [name]" on the member card.
 *
 * @param int $user_id The member's user ID.
 * @return object|null The related user object, or null if no spouse found.
 */
function sp_get_member_spouse( int $user_id ): ?object {
    $rels = sp_get_member_relationships( $user_id );
    foreach ( $rels as $r ) {
        if ( $r->relationship === 'spouse' ) {
            return $r;
        }
    }
    return null;
}

/**
 * AJAX handler: add a relationship from the member edit page.
 */
function sp_ajax_add_relationship(): void {
    check_ajax_referer( 'sp_relationship_nonce', 'nonce' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => __( 'Permission denied.', 'societypress' ) ] );
    }

    $user_a = (int) ( $_POST['user_a'] ?? 0 );
    $user_b = (int) ( $_POST['user_b'] ?? 0 );
    $type   = sanitize_text_field( $_POST['relationship'] ?? 'spouse' );
    $note   = sanitize_text_field( $_POST['note'] ?? '' );

    if ( ! $user_a || ! $user_b ) {
        wp_send_json_error( [ 'message' => __( 'Both members are required.', 'societypress' ) ] );
    }
    if ( $user_a === $user_b ) {
        wp_send_json_error( [ 'message' => __( 'Cannot create a relationship with the same person.', 'societypress' ) ] );
    }

    $id = sp_add_member_relationship( $user_a, $user_b, $type, $note );
    if ( $id ) {
        wp_send_json_success( [ 'id' => $id, 'message' => __( 'Relationship added.', 'societypress' ) ] );
    } else {
        wp_send_json_error( [ 'message' => __( 'Failed to add relationship.', 'societypress' ) ] );
    }
}
add_action( 'wp_ajax_sp_add_relationship', 'sp_ajax_add_relationship' );

/**
 * AJAX handler: remove a relationship.
 */
function sp_ajax_remove_relationship(): void {
    check_ajax_referer( 'sp_relationship_nonce', 'nonce' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => __( 'Permission denied.', 'societypress' ) ] );
    }

    $rel_id = (int) ( $_POST['rel_id'] ?? 0 );
    if ( sp_remove_member_relationship( $rel_id ) ) {
        wp_send_json_success( [ 'message' => __( 'Relationship removed.', 'societypress' ) ] );
    } else {
        wp_send_json_error( [ 'message' => __( 'Failed to remove relationship.', 'societypress' ) ] );
    }
}
add_action( 'wp_ajax_sp_remove_relationship', 'sp_ajax_remove_relationship' );

// ============================================================================
// AUDIT LOG — Activity tracking for admin actions
// ============================================================================

/**
 * Record an action in the audit log.
 *
 * WHY: This is the single entry point for all audit logging. Any part of
 *      the plugin that wants to record an action calls sp_audit(). The
 *      function is intentionally lightweight — it should never block or
 *      slow down the action it's logging.
 *
 * @param string      $action       Short action identifier (e.g., 'member_created', 'event_updated').
 * @param string|null $description  Human-readable description of what happened.
 * @param string|null $object_type  Type of object affected (e.g., 'member', 'event', 'settings').
 * @param int|null    $object_id    ID of the affected object (e.g., user_id, event_id).
 */
function sp_audit( string $action, ?string $description = null, ?string $object_type = null, ?int $object_id = null ): void {
    global $wpdb;

    // WHY sanitize: REMOTE_ADDR is generally trustworthy, but sanitizing before
    // storing defends against edge cases (malformed proxy headers, unusual server
    // configs) that could inject unexpected data into the audit log.
    $wpdb->insert( $wpdb->prefix . 'sp_audit_log', [
        'user_id'     => get_current_user_id() ?: null,
        'action'      => $action,
        'object_type' => $object_type,
        'object_id'   => $object_id,
        'description' => $description,
        'ip_address'  => isset( $_SERVER['REMOTE_ADDR'] ) ? sanitize_text_field( $_SERVER['REMOTE_ADDR'] ) : null,
        'created_at'  => current_time( 'mysql' ),
    ] );
}

/**
 * Prune old audit log entries (older than 1 year).
 *
 * WHY: The audit log grows continuously. Entries older than a year are
 *      rarely useful and just take up space. We prune on a daily cron
 *      to keep the table lean.
 */
function sp_prune_audit_log(): void {
    global $wpdb;
    $wpdb->query(
        "DELETE FROM {$wpdb->prefix}sp_audit_log
         WHERE created_at < DATE_SUB(NOW(), INTERVAL 1 YEAR)"
    );
}
add_action( 'sp_daily_maintenance', 'sp_prune_audit_log' );

// Schedule the daily maintenance cron if not already scheduled
if ( ! wp_next_scheduled( 'sp_daily_maintenance' ) ) {
    wp_schedule_event( time(), 'daily', 'sp_daily_maintenance' );
}

/**
 * Add Audit Log admin menu item under Reports.
 */
function sp_register_audit_log_menu(): void {
    add_submenu_page(
        'societypress',
        __( 'Audit Log — SocietyPress', 'societypress' ),
        __( 'Audit Log', 'societypress' ),
        'manage_options',
        'sp-audit-log',
        'sp_render_audit_log_page'
    );
}
add_action( 'admin_menu', 'sp_register_audit_log_menu', 99 );

/**
 * Render the Audit Log admin page.
 */
function sp_render_audit_log_page(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_audit_log';

    // Filters
    $filter_action = sanitize_text_field( $_GET['action_filter'] ?? '' );
    $filter_user   = (int) ( $_GET['user_filter'] ?? 0 );
    $search        = sanitize_text_field( $_GET['s'] ?? '' );
    $per_page      = 50;
    $paged         = max( 1, (int) ( $_GET['paged'] ?? 1 ) );
    $offset        = ( $paged - 1 ) * $per_page;

    $where = [ '1=1' ];
    $args  = [];

    if ( $filter_action ) {
        $where[] = 'a.action = %s';
        $args[]  = $filter_action;
    }
    if ( $filter_user ) {
        $where[] = 'a.user_id = %d';
        $args[]  = $filter_user;
    }
    if ( $search ) {
        $like    = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = '(a.description LIKE %s OR a.action LIKE %s)';
        $args[]  = $like;
        $args[]  = $like;
    }

    $where_sql = implode( ' AND ', $where );

    // Count total
    $count_sql = "SELECT COUNT(*) FROM {$table} a WHERE {$where_sql}";
    $total = $args
        ? (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$args ) )
        : (int) $wpdb->get_var( $count_sql );
    $total_pages = ceil( $total / $per_page );

    // Get rows
    $rows_sql = "SELECT a.*, u.display_name AS user_name
                 FROM {$table} a
                 LEFT JOIN {$wpdb->users} u ON a.user_id = u.ID
                 WHERE {$where_sql}
                 ORDER BY a.created_at DESC
                 LIMIT %d OFFSET %d";
    $query_args = array_merge( $args, [ $per_page, $offset ] );
    $rows = $wpdb->get_results( $wpdb->prepare( $rows_sql, ...$query_args ) );

    // Distinct actions for filter dropdown
    $actions = $wpdb->get_col( "SELECT DISTINCT action FROM {$table} ORDER BY action" );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php esc_html_e( 'Audit Log', 'societypress' ); ?></h1>

        <style>
            .sp-audit-filters { background: #fff; border: 1px solid #c3c4c7; padding: 12px; margin: 12px 0; display: flex; gap: 8px; align-items: end; flex-wrap: wrap; }
            .sp-audit-filters label { font-size: 12px; display: block; margin-bottom: 2px; color: #646970; }
            .sp-audit-filters select,
            .sp-audit-filters input { padding: 4px 8px; }
            .sp-audit-action { display: inline-block; background: #f0f0f1; padding: 2px 8px; border-radius: 3px; font-size: 12px; font-family: monospace; }
            .sp-audit-obj { color: #646970; font-size: 12px; }
        </style>

        <form method="get" class="sp-audit-filters">
            <input type="hidden" name="page" value="sp-audit-log">
            <div>
                <label for="sp-af-action"><?php esc_html_e( 'Action', 'societypress' ); ?></label>
                <select name="action_filter" id="sp-af-action">
                    <option value=""><?php esc_html_e( 'All Actions', 'societypress' ); ?></option>
                    <?php foreach ( $actions as $a ) : ?>
                        <option value="<?php echo esc_attr( $a ); ?>" <?php selected( $filter_action, $a ); ?>><?php echo esc_html( $a ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <label for="sp-af-search"><?php esc_html_e( 'Search', 'societypress' ); ?></label>
                <input type="search" name="s" id="sp-af-search" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php echo esc_attr__( 'Description...', 'societypress' ); ?>">
            </div>
            <div>
                <button type="submit" class="button"><?php esc_html_e( 'Filter', 'societypress' ); ?></button>
                <?php if ( $filter_action || $filter_user || $search ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-audit-log' ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>
            </div>
        </form>

        <table class="widefat striped">
            <thead>
                <tr>
                    <th><?php esc_html_e( 'Date/Time', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'User', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Action', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Description', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Object', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'IP', 'societypress' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $rows ) ) : ?>
                    <tr><td colspan="6" class="sp-text-center" class="sp-p-20"><?php esc_html_e( 'No log entries found.', 'societypress' ); ?></td></tr>
                <?php else : ?>
                    <?php foreach ( $rows as $row ) : ?>
                        <tr>
                            <!-- WHY: wp_date() respects the site's timezone setting; PHP date() uses server timezone. -->
                            <td style="white-space: nowrap;"><?php echo esc_html( wp_date( 'M j, Y g:i A', strtotime( $row->created_at ) ) ); ?></td>
                            <td><?php echo $row->user_name ? esc_html( $row->user_name ) : '<span class="sp-text-muted">System</span>'; ?></td>
                            <td><span class="sp-audit-action"><?php echo esc_html( $row->action ); ?></span></td>
                            <td><?php echo $row->description ? esc_html( $row->description ) : ''; ?></td>
                            <td class="sp-audit-obj">
                                <?php if ( $row->object_type ) : ?>
                                    <?php echo esc_html( $row->object_type ); ?>
                                    <?php if ( $row->object_id ) : ?>
                                        #<?php echo esc_html( $row->object_id ); ?>
                                    <?php endif; ?>
                                <?php endif; ?>
                            </td>
                            <td style="font-size: 12px; color: #787c82;"><?php echo $row->ip_address ? esc_html( $row->ip_address ) : ''; ?></td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>

        <?php if ( $total_pages > 1 ) : ?>
            <div class="tablenav bottom">
                <div class="tablenav-pages">
                    <span class="displaying-num"><?php echo number_format( $total ); ?> entries</span>
                    <?php
                    echo paginate_links( [
                        'base'    => add_query_arg( 'paged', '%#%' ),
                        'format'  => '',
                        'current' => $paged,
                        'total'   => $total_pages,
                        'prev_text' => '&laquo;',
                        'next_text' => '&raquo;',
                    ] );
                    ?>
                </div>
            </div>
        <?php endif; ?>

        <p style="margin-top: 16px; color: #646970; font-size: 12px;">
            Log entries older than 1 year are automatically pruned.
            <?php echo number_format( $total ); ?> total entries.
        </p>
    </div>
    <?php
}

// ---- WordPress hooks for audit logging ----

// Log user login
add_action( 'wp_login', function( $user_login, $user ) {
    sp_audit( 'user_login', "User logged in: {$user_login}", 'user', $user->ID );
}, 10, 2 );

// Log failed login attempts
add_action( 'wp_login_failed', function( $username ) {
    sp_audit( 'login_failed', "Failed login attempt for: {$username}", 'user' );
} );

// ============================================================================
// BREADCRUMBS NAVIGATION
// ============================================================================
//
// WHY: Breadcrumbs help visitors understand where they are in the site
//      hierarchy. For a society website with events, member pages, library,
//      etc., clear navigation context is essential. The theme calls
//      sp_breadcrumbs() to render them, or they auto-render if the
//      'breadcrumbs_enabled' setting is on.

/**
 * Generate and return breadcrumb HTML.
 *
 * WHY: We build breadcrumbs from the current page context rather than
 *      relying on URL structure. This handles WordPress pages (with
 *      parent hierarchy), posts (with categories), custom SP pages
 *      (events, member portal, etc.), and archive pages correctly.
 *
 * @param bool $echo Whether to echo (true) or return (false) the HTML.
 * @return string The breadcrumb HTML.
 */
function sp_breadcrumbs( bool $echo = true ): string {
    // Don't show breadcrumbs on the front page — it IS home
    if ( is_front_page() ) {
        return '';
    }

    $settings  = get_option( 'societypress_settings', [] );
    $home_label = $settings['breadcrumb_home_label'] ?? 'Home';
    $separator  = $settings['breadcrumb_separator'] ?? '›';

    $crumbs = [];

    // Always start with Home
    $crumbs[] = [
        'label' => $home_label,
        'url'   => home_url( '/' ),
    ];

    if ( is_page() ) {
        // For pages, walk up the parent hierarchy
        global $post;
        $ancestors = get_post_ancestors( $post );
        $ancestors = array_reverse( $ancestors );
        foreach ( $ancestors as $anc_id ) {
            $crumbs[] = [
                'label' => get_the_title( $anc_id ),
                'url'   => get_permalink( $anc_id ),
            ];
        }
        // Current page (no link)
        $crumbs[] = [
            'label' => get_the_title(),
            'url'   => '',
        ];

    } elseif ( is_single() ) {
        // For posts, show the primary category, then the post title
        $cats = get_the_category();
        if ( ! empty( $cats ) ) {
            $cat = $cats[0];
            // If category has a parent, show parent first
            if ( $cat->parent ) {
                $parent_cat = get_category( $cat->parent );
                if ( $parent_cat ) {
                    $crumbs[] = [
                        'label' => $parent_cat->name,
                        'url'   => get_category_link( $parent_cat->term_id ),
                    ];
                }
            }
            $crumbs[] = [
                'label' => $cat->name,
                'url'   => get_category_link( $cat->term_id ),
            ];
        }
        $crumbs[] = [
            'label' => get_the_title(),
            'url'   => '',
        ];

    } elseif ( is_category() ) {
        $cat = get_queried_object();
        if ( $cat->parent ) {
            $parent_cat = get_category( $cat->parent );
            if ( $parent_cat ) {
                $crumbs[] = [
                    'label' => $parent_cat->name,
                    'url'   => get_category_link( $parent_cat->term_id ),
                ];
            }
        }
        $crumbs[] = [
            'label' => $cat->name,
            'url'   => '',
        ];

    } elseif ( is_tag() ) {
        $crumbs[] = [
            'label' => sprintf( __( 'Tag: %s', 'societypress' ), single_tag_title( '', false ) ),
            'url'   => '',
        ];

    } elseif ( is_search() ) {
        $crumbs[] = [
            'label' => __( 'Search Results', 'societypress' ),
            'url'   => '',
        ];

    } elseif ( is_404() ) {
        $crumbs[] = [
            'label' => __( 'Page Not Found', 'societypress' ),
            'url'   => '',
        ];

    } elseif ( is_archive() ) {
        $crumbs[] = [
            'label' => get_the_archive_title(),
            'url'   => '',
        ];

    } elseif ( is_home() ) {
        // Blog/news page
        $crumbs[] = [
            'label' => __( 'News', 'societypress' ),
            'url'   => '',
        ];
    }

    // Build HTML
    $html = '<nav class="sp-breadcrumbs" aria-label="Breadcrumb">';
    $html .= '<ol class="sp-breadcrumb-list">';

    $last = count( $crumbs ) - 1;
    foreach ( $crumbs as $i => $crumb ) {
        $html .= '<li class="sp-breadcrumb-item">';
        if ( $crumb['url'] && $i < $last ) {
            $html .= '<a href="' . esc_url( $crumb['url'] ) . '">' . esc_html( $crumb['label'] ) . '</a>';
        } else {
            $html .= '<span aria-current="page">' . esc_html( $crumb['label'] ) . '</span>';
        }
        if ( $i < $last ) {
            $html .= ' <span class="sp-breadcrumb-sep" aria-hidden="true">' . $separator . '</span> ';
        }
        $html .= '</li>';
    }

    $html .= '</ol>';
    $html .= '</nav>';

    // Inline styles — minimal, theme can override with CSS
    $html .= '<style>'
            . '.sp-breadcrumbs { padding: 8px 0; font-size: 13px; color: var(--sp-color-text-secondary, #646970); }'
            . '.sp-breadcrumb-list { list-style: none; margin: 0; padding: 0; display: flex; flex-wrap: wrap; gap: 0; }'
            . '.sp-breadcrumb-item { display: inline; }'
            . '.sp-breadcrumb-item a { color: var(--sp-color-primary, #2271b1); text-decoration: none; }'
            . '.sp-breadcrumb-item a:hover { text-decoration: underline; }'
            . '.sp-breadcrumb-sep { margin: 0 6px; color: var(--sp-color-text-secondary, #999); }'
            . '.sp-breadcrumb-item [aria-current] { color: var(--sp-color-text, #1d2327); }'
            . '</style>';

    if ( $echo ) {
        echo $html;
    }

    return $html;
}

/**
 * Auto-render breadcrumbs if the setting is enabled.
 *
 * WHY: Some themes don't call sp_breadcrumbs() themselves. This hook
 *      lets the admin enable auto-rendering without touching theme files.
 *      Uses the 'wp' action (after the query is set up) to inject
 *      breadcrumbs via the_content filter on pages and posts.
 */
function sp_maybe_auto_breadcrumbs(): void {
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['breadcrumbs_enabled'] ) ) {
        return;
    }
    // Prepend breadcrumbs to the_content on single pages and posts
    add_filter( 'the_content', function( $content ) {
        if ( ! is_main_query() || ! in_the_loop() || is_front_page() ) {
            return $content;
        }
        static $done = false;
        if ( $done ) return $content;
        $done = true;
        return sp_breadcrumbs( false ) . $content;
    }, 5 );
}
add_action( 'wp', 'sp_maybe_auto_breadcrumbs' );

