/**
 * Render the Groups admin list page.
 */
function sp_render_groups_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete — POST-only to prevent browser prefetch / link-preview accidents
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && isset( $_POST['group_id'] ) ) {
        check_admin_referer( 'sp_delete_group_' . $_POST['group_id'] );
        $gid = (int) $_POST['group_id'];
        $wpdb->delete( $prefix . 'group_members', [ 'group_id' => $gid ] );
        $wpdb->delete( $prefix . 'groups', [ 'id' => $gid ] );
        wp_safe_redirect( admin_url( 'admin.php?page=sp-groups&deleted=1' ) );
        exit;
    }

    $groups = $wpdb->get_results(
        "SELECT g.*,
                u.display_name AS leader_name,
                (SELECT COUNT(*) FROM {$prefix}group_members gm WHERE gm.group_id = g.id) AS member_count
         FROM {$prefix}groups g
         LEFT JOIN {$wpdb->users} u ON g.leader_id = u.ID
         ORDER BY g.sort_order ASC, g.name ASC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Groups', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-group-edit' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Add New', 'societypress' ); ?></a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Group deleted.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Group saved.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <table class="widefat striped" class="sp-mt-16">
            <thead>
                <tr>
                    <th><?php esc_html_e( 'Name', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Members', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Leader', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $groups ) ) : ?>
                    <tr><td colspan="5" class="sp-text-center" class="sp-p-20"><?php esc_html_e( 'No groups yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-group-edit' ) ); ?>"><?php esc_html_e( 'Create one', 'societypress' ); ?></a>.</td></tr>
                <?php else : ?>
                    <?php foreach ( $groups as $g ) : ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-group-edit&group_id=' . $g->id ) ); ?>"><?php echo esc_html( $g->name ); ?></a></strong>
                                <?php if ( $g->description ) : ?>
                                    <br><span class="sp-text-muted sp-text-sm"><?php echo esc_html( wp_trim_words( $g->description, 15 ) ); ?></span>
                                <?php endif; ?>
                            </td>
                            <td><?php echo (int) $g->member_count; ?></td>
                            <td><?php echo $g->leader_name ? esc_html( $g->leader_name ) : '&#8212;'; ?></td>
                            <td>
                                <?php if ( $g->status === 'active' ) : ?>
                                    <span class="sp-text-success"><?php esc_html_e( 'Active', 'societypress' ); ?></span>
                                <?php else : ?>
                                    <span class="sp-text-muted"><?php esc_html_e( 'Inactive', 'societypress' ); ?></span>
                                <?php endif; ?>
                            </td>
                            <td>
                                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-group-edit&group_id=' . $g->id ) ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a>
                                |
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-groups' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this group and remove all members from it?', 'societypress' ) ); ?>">
                                    <?php wp_nonce_field( 'sp_delete_group_' . $g->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="group_id" value="<?php echo (int) $g->id; ?>">
                                    <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>
    </div>
    <?php
}

/**
 * Render the Group edit/add page.
 */
function sp_render_group_edit_page(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $group_id = (int) ( $_GET['group_id'] ?? 0 );
    $group    = null;
    $members  = [];

    if ( $group_id ) {
        $group = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}groups WHERE id = %d", $group_id
        ) );
        if ( ! $group ) {
            echo '<div class="wrap"><h1>' . esc_html__( 'Group Not Found', 'societypress' ) . '</h1><p><a href="' . esc_url( admin_url( 'admin.php?page=sp-groups' ) ) . '">&larr; ' . esc_html__( 'Back', 'societypress' ) . '</a></p></div>';
            return;
        }
        $members = $wpdb->get_results( $wpdb->prepare(
            "SELECT gm.*, u.display_name, u.user_email
             FROM {$prefix}group_members gm
             JOIN {$wpdb->users} u ON gm.user_id = u.ID
             WHERE gm.group_id = %d
             ORDER BY u.display_name ASC",
            $group_id
        ) );
    }

    // Handle save
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_group_nonce'] ) ) {
        check_admin_referer( 'sp_save_group', 'sp_group_nonce' );

        $name = sanitize_text_field( $_POST['name'] ?? '' );
        if ( ! $name ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Group name is required.', 'societypress' ) . '</p></div>';
        } else {
            $slug = sanitize_title( $name );
            $data = [
                'name'         => $name,
                'slug'         => $slug,
                'description'  => sanitize_textarea_field( $_POST['description'] ?? '' ) ?: null,
                'leader_id'    => (int) ( $_POST['leader_id'] ?? 0 ) ?: null,
                'meeting_info' => sanitize_text_field( $_POST['meeting_info'] ?? '' ) ?: null,
                'status'       => sanitize_text_field( $_POST['status'] ?? 'active' ),
                'sort_order'   => (int) ( $_POST['sort_order'] ?? 0 ),
            ];

            if ( $group_id ) {
                $wpdb->update( $prefix . 'groups', $data, [ 'id' => $group_id ] );
            } else {
                $wpdb->insert( $prefix . 'groups', $data );
                $group_id = (int) $wpdb->insert_id;
            }

            // Handle member removal
            if ( ! empty( $_POST['remove_members'] ) && is_array( $_POST['remove_members'] ) ) {
                foreach ( $_POST['remove_members'] as $uid ) {
                    $wpdb->delete( $prefix . 'group_members', [
                        'group_id' => $group_id,
                        'user_id'  => (int) $uid,
                    ] );
                }
            }

            // Handle adding a member
            $add_user = (int) ( $_POST['add_member_id'] ?? 0 );
            if ( $add_user ) {
                $exists = $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$prefix}group_members WHERE group_id = %d AND user_id = %d",
                    $group_id, $add_user
                ) );
                if ( ! $exists ) {
                    $wpdb->insert( $prefix . 'group_members', [
                        'group_id'  => $group_id,
                        'user_id'   => $add_user,
                        'joined_at' => current_time( 'mysql' ),
                    ] );
                }
            }

            wp_safe_redirect( admin_url( 'admin.php?page=sp-groups&saved=1' ) );
            exit;
        }
    }

    // All SP members for dropdowns
    $all_members = $wpdb->get_results(
        "SELECT m.user_id, u.display_name, u.user_email
         FROM {$prefix}members m
         JOIN {$wpdb->users} u ON m.user_id = u.ID
         ORDER BY u.display_name ASC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php echo $group_id ? esc_html__( 'Edit Group', 'societypress' ) : esc_html__( 'Add New Group', 'societypress' ); ?></h1>
        <p><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-groups' ) ); ?>">&larr; <?php esc_html_e( 'Back to Groups', 'societypress' ); ?></a></p>

        <form method="post" class="sp-max-w-600">
            <?php wp_nonce_field( 'sp_save_group', 'sp_group_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="sp-g-name"><?php esc_html_e( 'Group Name', 'societypress' ); ?> <span class="sp-blast-required-star">*</span></label></th>
                    <td><input type="text" name="name" id="sp-g-name" value="<?php echo esc_attr( $group->name ?? '' ); ?>" required class="sp-full-width"></td>
                </tr>
                <tr>
                    <th><label for="sp-g-desc"><?php esc_html_e( 'Description', 'societypress' ); ?></label></th>
                    <td><textarea name="description" id="sp-g-desc" rows="4" class="sp-full-width"><?php echo esc_textarea( $group->description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="sp-g-leader"><?php esc_html_e( 'Group Leader', 'societypress' ); ?></label></th>
                    <td>
                        <select name="leader_id" id="sp-g-leader" class="sp-full-width">
                            <option value="">&#8212; None &#8212;</option>
                            <?php foreach ( $all_members as $m ) : ?>
                                <option value="<?php echo esc_attr( $m->user_id ); ?>" <?php selected( (int) ( $group->leader_id ?? 0 ), (int) $m->user_id ); ?>>
                                    <?php echo esc_html( $m->display_name ); ?> (<?php echo esc_html( $m->user_email ); ?>)
                                </option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-g-meeting"><?php esc_html_e( 'Meeting Info', 'societypress' ); ?></label></th>
                    <td><input type="text" name="meeting_info" id="sp-g-meeting" value="<?php echo esc_attr( $group->meeting_info ?? '' ); ?>" class="sp-full-width" placeholder="e.g., 2nd Tuesday at 2 PM"></td>
                </tr>
                <tr>
                    <th><label for="sp-g-status"><?php esc_html_e( 'Status', 'societypress' ); ?></label></th>
                    <td>
                        <select name="status" id="sp-g-status">
                            <option value="active" <?php selected( $group->status ?? 'active', 'active' ); ?>><?php esc_html_e( 'Active', 'societypress' ); ?></option>
                            <option value="inactive" <?php selected( $group->status ?? '', 'inactive' ); ?>><?php esc_html_e( 'Inactive', 'societypress' ); ?></option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-g-order"><?php esc_html_e( 'Sort Order', 'societypress' ); ?></label></th>
                    <td><input type="number" name="sort_order" id="sp-g-order" value="<?php echo (int) ( $group->sort_order ?? 0 ); ?>" style="width: 80px;"></td>
                </tr>
            </table>

            <?php if ( $group_id && ! empty( $members ) ) : ?>
                <h2><?php echo esc_html( sprintf( __( 'Current Members (%d)', 'societypress' ), count( $members ) ) ); ?></h2>
                <table class="widefat striped" class="sp-max-w-600">
                    <thead><tr><th><?php esc_html_e( 'Name', 'societypress' ); ?></th><th><?php esc_html_e( 'Email', 'societypress' ); ?></th><th><?php esc_html_e( 'Joined', 'societypress' ); ?></th><th><?php esc_html_e( 'Remove', 'societypress' ); ?></th></tr></thead>
                    <tbody>
                        <?php foreach ( $members as $gm ) : ?>
                            <tr>
                                <td><?php echo esc_html( $gm->display_name ); ?></td>
                                <td><?php echo esc_html( $gm->user_email ); ?></td>
                                <td><?php echo esc_html( wp_date( 'M j, Y', strtotime( $gm->joined_at ) ) ); ?></td>
                                <td><label><input type="checkbox" name="remove_members[]" value="<?php echo esc_attr( $gm->user_id ); ?>"> <?php esc_html_e( 'Remove', 'societypress' ); ?></label></td>
                            </tr>
                        <?php endforeach; ?>
                    </tbody>
                </table>
            <?php endif; ?>

            <?php if ( $group_id ) : ?>
                <h2><?php esc_html_e( 'Add Member', 'societypress' ); ?></h2>
                <select name="add_member_id" style="width: 300px;">
                    <option value="">&#8212; Select Member &#8212;</option>
                    <?php
                    $current_ids = array_map( function( $m ) { return (int) $m->user_id; }, $members );
                    foreach ( $all_members as $m ) :
                        if ( in_array( (int) $m->user_id, $current_ids, true ) ) continue;
                    ?>
                        <option value="<?php echo esc_attr( $m->user_id ); ?>">
                            <?php echo esc_html( $m->display_name ); ?> (<?php echo esc_html( $m->user_email ); ?>)
                        </option>
                    <?php endforeach; ?>
                </select>
            <?php endif; ?>

            <p class="submit">
                <button type="submit" class="button button-primary"><?php echo $group_id ? esc_html__( 'Save Changes', 'societypress' ) : esc_html__( 'Create Group', 'societypress' ); ?></button>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-groups' ) ); ?>" class="button"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
            </p>
        </form>
    </div>
    <?php
}

/**
 * AJAX handler: member joins a group from the frontend.
 */
function sp_ajax_join_group(): void {
    check_ajax_referer( 'sp_groups_nonce', 'nonce' );

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => __( 'You must be logged in.', 'societypress' ) ] );
    }

    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $group_id = (int) ( $_POST['group_id'] ?? 0 );
    $user_id  = get_current_user_id();

    if ( ! $group_id ) {
        wp_send_json_error( [ 'message' => __( 'Invalid group.', 'societypress' ) ] );
    }

    $group = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}groups WHERE id = %d AND status = 'active'", $group_id
    ) );
    if ( ! $group ) {
        wp_send_json_error( [ 'message' => __( 'Group not found or inactive.', 'societypress' ) ] );
    }

    $exists = $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}group_members WHERE group_id = %d AND user_id = %d",
        $group_id, $user_id
    ) );
    if ( $exists ) {
        wp_send_json_error( [ 'message' => __( 'You are already in this group.', 'societypress' ) ] );
    }

    $wpdb->insert( $prefix . 'group_members', [
        'group_id'  => $group_id,
        'user_id'   => $user_id,
        'joined_at' => current_time( 'mysql' ),
    ] );

    wp_send_json_success( [ 'message' => sprintf( __( 'You have joined %s!', 'societypress' ), $group->name ) ] );
}
add_action( 'wp_ajax_sp_join_group', 'sp_ajax_join_group' );

/**
 * AJAX handler: member leaves a group from the frontend.
 */
function sp_ajax_leave_group(): void {
    check_ajax_referer( 'sp_groups_nonce', 'nonce' );

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => __( 'You must be logged in.', 'societypress' ) ] );
    }

    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $group_id = (int) ( $_POST['group_id'] ?? 0 );
    $user_id  = get_current_user_id();

    $wpdb->delete( $prefix . 'group_members', [
        'group_id' => $group_id,
        'user_id'  => $user_id,
    ] );

    wp_send_json_success( [ 'message' => __( 'You have left the group.', 'societypress' ) ] );
}
add_action( 'wp_ajax_sp_leave_group', 'sp_ajax_leave_group' );

// =========================================================================
// PAGES MANAGEMENT
// =========================================================================
//
// WHY: WordPress's native Pages screen (edit.php?post_type=page) drops
//      Harold into the WP admin he's not supposed to see. This section
//      builds an SP-native Pages interface that wraps wp_posts (type=page)
//      with our own list table, add/edit form, and save/delete handlers.
//
//      No new database tables — we query and write to WP's pages table
//      directly using wp_insert_post(), wp_update_post(), wp_delete_post(),
//      and get_page_template_slug().
// =========================================================================

/**
 * SP_Pages_List_Table
 *
 * Extends WP_List_Table to display WordPress pages in the SP admin UI.
 * Same pattern as SP_Members_List_Table and other SP list tables.
 */
class SP_Pages_List_Table extends WP_List_Table {

    public function __construct() {
        parent::__construct( [
            'singular' => 'page',
            'plural'   => 'pages',
            'ajax'     => false,
        ] );
    }

    /**
     * Define the columns Harold sees in the pages list.
     *
     * WHY each column:
     *   Title     — primary identifier, links to edit
     *   Page Type — which SP template is assigned (Events, Directory, etc.)
     *   Status    — Published or Draft so Harold knows what's live
     *   Date      — when the page was created/modified
     */
    public function get_columns(): array {
        return [
            'cb'        => '<input type="checkbox" />',
            'title'     => __( 'Title', 'societypress' ),
            'page_type' => __( 'Page Type', 'societypress' ),
            'status'    => __( 'Status', 'societypress' ),
            'date'      => __( 'Date', 'societypress' ),
        ];
    }

    /**
     * Which columns can be clicked to sort the list.
     */
    public function get_sortable_columns(): array {
        return [
            'title' => [ 'post_title', true ],   // Default sort: title A→Z
            'date'  => [ 'post_date', false ],
        ];
    }

    /**
     * Bulk actions dropdown — appears above the table.
     */
    protected function get_bulk_actions(): array {
        return [
            'delete' => __( 'Delete', 'societypress' ),
        ];
    }

    /**
     * Checkbox column for bulk actions.
     */
    protected function column_cb( $item ): string {
        return sprintf(
            '<input type="checkbox" name="page_id[]" value="%d" />',
            $item->ID
        );
    }

    /**
     * Title column — the primary column with row actions.
     *
     * Links to the SP page editor, not the WP editor.
     */
    protected function column_title( $item ): string {
        $title = ! empty( $item->post_title ) ? $item->post_title : __( '(no title)', 'societypress' );
        $name  = '<strong>' . esc_html( $title ) . '</strong>';

        $edit_url = admin_url( 'admin.php?page=sp-page-edit&post_id=' . $item->ID );

        $actions = [
            'edit' => sprintf( '<a href="%s">%s</a>', esc_url( $edit_url ), esc_html__( 'Edit', 'societypress' ) ),
            'quick_edit' => sprintf(
                '<a href="#" class="sp-quick-edit-trigger" data-id="%d" data-title="%s" data-status="%s" data-template="%s">%s</a>',
                $item->ID,
                esc_attr( $item->post_title ),
                esc_attr( $item->post_status ),
                esc_attr( get_page_template_slug( $item->ID ) ),
                esc_html__( 'Quick Edit', 'societypress' )
            ),
        ];

        // View link — only for published pages
        if ( $item->post_status === 'publish' ) {
            $actions['view'] = sprintf(
                '<a href="%s" target="_blank">%s</a>',
                esc_url( get_permalink( $item->ID ) ),
                esc_html__( 'View', 'societypress' )
            );
        }

        // Delete — JS-based POST to avoid nested forms inside the list table
        $actions['delete'] = '<a href="#" class="sp-text-danger" onclick="spConfirm(\'' . esc_js( __( 'Are you sure you want to delete this page?', 'societypress' ) ) . '\', function(){var f=document.createElement(\'form\');f.method=\'post\';f.action=\'' . esc_url( admin_url( 'admin.php?page=sp-pages' ) ) . '\';var d=[[\'_wpnonce\',\'' . wp_create_nonce( 'sp_delete_page_' . $item->ID ) . '\'],[\'action\',\'delete\'],[\'post_id\',\'' . (int) $item->ID . '\']];d.forEach(function(p){var i=document.createElement(\'input\');i.type=\'hidden\';i.name=p[0];i.value=p[1];f.appendChild(i);});document.body.appendChild(f);f.submit();});return false;">' . esc_html__( 'Delete', 'societypress' ) . '</a>';

        return $name . $this->row_actions( $actions );
    }

    /**
     * Page Type column — shows the friendly template label.
     *
     * WHY: Harold doesn't know what "sp-events" means. He sees "Events".
     *      If no template is set, it's just a "Standard Page" — a plain
     *      content page Harold typed up.
     */
    protected function column_page_type( $item ): string {
        $template = get_page_template_slug( $item->ID );
        $labels   = sp_get_page_type_labels();

        if ( ! empty( $template ) && isset( $labels[ $template ] ) ) {
            return '<span style="color: #0073aa; font-weight: 500;">'
                 . esc_html( $labels[ $template ] )
                 . '</span>';
        }

        return __( 'Standard Page', 'societypress' );
    }

    /**
     * Status column — color-coded so Harold can see at a glance.
     */
    protected function column_status( $item ): string {
        if ( $item->post_status === 'publish' ) {
            return '<span style="color: #00a32a; font-weight: 600;">' . esc_html__( 'Published', 'societypress' ) . '</span>';
        }
        return '<span style="color: #787c82; font-weight: 600;">' . esc_html__( 'Draft', 'societypress' ) . '</span>';
    }

    /**
     * Date column — when the page was last modified.
     */
    protected function column_date( $item ): string {
        return esc_html( date_i18n(
            get_option( 'date_format', 'F j, Y' ),
            strtotime( $item->post_modified )
        ) );
    }

    /**
     * Fetch page data from wp_posts.
     *
     * Handles searching, sorting, and pagination.
     */
    public function prepare_items(): void {
        // WHY: Most societies have a small number of pages (under 50). Showing
        //      all on one screen is often more useful than paginating. The
        //      ?show_all=1 parameter toggles between paginated and full list.
        $show_all = ! empty( $_GET['show_all'] );
        $per_page = $show_all ? 999 : 100;

        // Build query args
        $args = [
            'post_type'      => 'page',
            'post_status'    => [ 'publish', 'draft' ],
            'posts_per_page' => $per_page,
            'paged'          => $show_all ? 1 : $this->get_pagenum(),
        ];

        // Search by title
        $search = $_GET['s'] ?? '';
        if ( ! empty( $search ) ) {
            $args['s'] = sanitize_text_field( $search );
        }

        // Sorting — default to alphabetical by title so Harold can find
        // pages quickly. Column headers are clickable to re-sort by date
        // or menu order if preferred.
        $orderby = $_GET['orderby'] ?? 'post_title';
        $order   = $_GET['order'] ?? 'ASC';

        $allowed_orderby = [ 'post_title', 'post_date', 'menu_order' ];
        if ( in_array( $orderby, $allowed_orderby, true ) ) {
            $args['orderby'] = $orderby;
            $args['order']   = strtoupper( $order ) === 'DESC' ? 'DESC' : 'ASC';
        } else {
            $args['orderby'] = 'post_title';
            $args['order']   = 'ASC';
        }

        $query = new WP_Query( $args );

        $this->items = $query->posts;

        $this->set_pagination_args( [
            'total_items' => $query->found_posts,
            'per_page'    => $per_page,
            'total_pages' => $query->max_num_pages,
        ] );

        $this->_column_headers = [
            $this->get_columns(),
            [],  // hidden columns
            $this->get_sortable_columns(),
        ];
    }

    /**
     * Message shown when no pages exist yet.
     */
    public function no_items(): void {
        echo esc_html__( 'No pages found.', 'societypress' ) . ' <a href="'
           . esc_url( admin_url( 'admin.php?page=sp-page-edit' ) )
           . '">' . esc_html__( 'Create your first page', 'societypress' ) . '</a>.';
    }
}


/**
 * Returns the map of SP template slugs → friendly labels.
 *
 * WHY: This is the single source of truth for page type labels used in
 *      the list table, the add/edit dropdown, and anywhere else we need
 *      to translate a template slug into something Harold understands.
 *      Add new SP page templates here as they're built.
 */
function sp_get_page_type_labels(): array {
    return [
        'sp-events'          => __( 'Events', 'societypress' ),
        'sp-directory'       => __( 'Membership Directory', 'societypress' ),
        'sp-library-catalog' => __( 'Library Catalog', 'societypress' ),
        'sp-groups'          => __( 'Interest Groups', 'societypress' ),
        'sp-help-requests'   => __( 'Research Help Requests', 'societypress' ),
        'sp-resources'       => __( 'Resource Links Directory', 'societypress' ),
        'sp-builder'         => __( 'Page Builder', 'societypress' ),
        'sp-newsletter-archive' => __( 'Newsletter Archive', 'societypress' ),
        'sp-search'          => __( 'Site Search', 'societypress' ),
        'sp-calendar'        => __( 'Calendar', 'societypress' ),
        'sp-documents'       => __( 'Documents', 'societypress' ),
    ];
}


/**
 * Render the Pages list page.
 *
 * Shows the SP-native pages list with search, bulk actions, and pagination.
 * Pattern matches sp_render_members_page().
 */
function sp_render_pages_page(): void {

    // Handle single delete action — POST-only to prevent browser prefetch / link-preview accidents
    if ( ( $_POST['action'] ?? '' ) === 'delete'
         && isset( $_POST['post_id'] ) && ! is_array( $_POST['post_id'] ) ) {
        $post_id = (int) $_POST['post_id'];
        check_admin_referer( 'sp_delete_page_' . $post_id );
        wp_delete_post( $post_id, true ); // true = bypass trash, permanent delete
        wp_safe_redirect( admin_url( 'admin.php?page=sp-pages&deleted=1' ) );
        exit;
    }

    // Handle bulk delete action
    // WHY: WP_List_Table submits bulk actions via action (top dropdown) or
    //      action2 (bottom dropdown). We check both so either works.
    if ( ( ( $_GET['action'] ?? '' ) === 'delete' || ( $_GET['action2'] ?? '' ) === 'delete' )
         && ! empty( $_GET['page_id'] ) && is_array( $_GET['page_id'] ) ) {
        check_admin_referer( 'bulk-pages' );
        $count = 0;
        foreach ( $_GET['page_id'] as $pid ) {
            wp_delete_post( (int) $pid, true );
            $count++;
        }
        wp_safe_redirect( admin_url( 'admin.php?page=sp-pages&deleted=' . $count ) );
        exit;
    }

    $table = new SP_Pages_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Pages', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-page-edit' ) ); ?>" class="page-title-action">
            <?php esc_html_e( 'Add New', 'societypress' ); ?>
        </a>
        <hr class="wp-header-end">

        <?php
        // Success notices
        if ( isset( $_GET['deleted'] ) ) {
            $count = (int) $_GET['deleted'];
            if ( $count > 0 ) {
                printf(
                    '<div class="notice notice-success is-dismissible"><p>%s</p></div>',
                    esc_html( sprintf(
                        /* translators: %d: number of pages deleted */
                        _n( '%d page deleted.', '%d pages deleted.', $count, 'societypress' ),
                        $count
                    ) )
                );
            }
        }
        if ( isset( $_GET['saved'] ) ) {
            echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Page saved.', 'societypress' ) . '</p></div>';
        }
        ?>

        <?php
        // PAGE GROUPS UI — inserted above the page list
        $page_groups = sp_get_page_groups();
        $all_sp_pages = get_pages( [ 'post_status' => [ 'publish', 'draft' ], 'sort_column' => 'post_title', 'sort_order' => 'ASC' ] );
        $grouped_page_ids = [];
        foreach ( $page_groups as $g ) {
            foreach ( $g['page_ids'] as $pid ) {
                $grouped_page_ids[ $pid ] = true;
            }
        }
        ?>

