} );


// ============================================================================
// THEME CHOOSER — Browse and activate SocietyPress child themes
// ============================================================================
//
// WHY: WordPress has Appearance > Themes, but we've hidden all of that from
//      the admin. Society administrators shouldn't have to wade through
//      thousands of WordPress themes — they should only see themes built
//      specifically for SocietyPress. This page scans for child themes
//      that declare "Template: societypress" in their style.css header,
//      plus the parent theme itself as the "Default" option, and presents
//      them in a clean grid with screenshots and one-click activation.

/**
 * Handle theme activation via POST.
 *
 * WHY: We process the activation before any output so we can show a success
 *      message. Uses a nonce for security — only legitimate admin clicks
 *      from our page can trigger a theme switch.
 */
add_action( 'admin_init', function () {
    if ( ! isset( $_POST['sp_activate_theme'] ) ) return;
    if ( ! current_user_can( 'manage_options' ) ) return;
    if ( ! wp_verify_nonce( $_POST['_sp_theme_nonce'] ?? '', 'sp_switch_theme' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    $theme_slug = sanitize_text_field( $_POST['sp_activate_theme'] );
    $theme = wp_get_theme( $theme_slug );

    // Only allow activating the parent theme or its child themes
    if ( ! $theme->exists() ) return;
    if ( $theme_slug !== 'societypress' && $theme->get( 'Template' ) !== 'societypress' ) return;

    switch_theme( $theme_slug );

    // Redirect back to the themes page with a success flag
    wp_safe_redirect( admin_url( 'admin.php?page=sp-themes&activated=' . urlencode( $theme_slug ) ) );
    exit;
} );

/**
 * Get the SocietyPress child theme registry.
 *
 * WHY: This is the catalog of all available SocietyPress child themes. It
 *      ships with the plugin, so whenever the plugin updates, new themes
 *      automatically appear in Harold's gallery. No separate download
 *      manifest or API call needed — the registry IS the source of truth.
 *
 *      Each entry has:
 *        slug        — directory name under wp-content/themes/
 *        name        — display name
 *        version     — current version in the repo
 *        description — what Harold sees in the gallery
 *        colors      — key palette colors for the preview swatch
 *        repo_path   — path within the GitHub repo (for download)
 *
 * @return array Array of theme data arrays.
 */
