        border-radius: 8px;
        overflow: hidden;
        position: relative;
    }

    /* ---- Not-installed (available) theme card ---- */
    /* Dashed border signals "not yet installed" — visually distinct from solid installed cards */
    .sp-themes-card-available {
        background: #fff;
        border: 1px dashed #bbb;
