                                <div style="flex:1; background:<?php echo esc_attr( $color ); ?>;"></div>
                            <?php endforeach;
                        else : ?>
                            <div class="sp-themes-preview-area">
                                <span class="dashicons dashicons-art sp-themes-placeholder-icon"></span>
                            </div>
