                 class="sp-themes-card-create"
                 onmouseover="this.style.borderColor='#7C3AED'; this.style.boxShadow='0 2px 8px rgba(139,92,246,0.15)';"
                 onmouseout="this.style.borderColor='#8B5CF6'; this.style.boxShadow='none';">

