                .sp-module-card.sp-module-enabled {
                    border-color: #2271b1;
                    box-shadow: 0 0 0 1px #2271b1;
                }
                .sp-module-card-icon {
                    font-size: 24px;
                    color: #646970;
                    flex-shrink: 0;
                    width: 30px;
                    text-align: center;
                    margin-top: 2px;
                }
                .sp-module-card.sp-module-enabled .sp-module-card-icon {
                    color: #2271b1;
                }
                .sp-module-card-body {
                    flex: 1;
                    min-width: 0;
                }
                .sp-module-card-header {
                    display: flex;
                    align-items: center;
                    justify-content: space-between;
                    margin-bottom: 6px;
                }
                .sp-module-card-name {
                    font-weight: 600;
                    font-size: 14px;
                    color: #1d2327;
                }
                /* Toggle switch styling — a friendlier alternative to a plain
                   checkbox. The hidden checkbox drives the state; the visual
                   slider is purely CSS. */
                .sp-toggle {
                    position: relative;
                    width: 40px;
                    height: 22px;
                    flex-shrink: 0;
                }
                .sp-toggle input {
                    opacity: 0;
                    width: 0;
                    height: 0;
