// ============================================================================
// DESIGN TAB — ENQUEUE COLOR PICKER ON SETTINGS PAGE
// ============================================================================

/**
 * Load WordPress's built-in color picker (wp-color-picker) on our Settings page.
 *
 * WHY: The Design tab uses color picker inputs for all 7 color settings.
 * WordPress ships a jQuery-based color picker (Iris) that we just need to
 * enqueue. We only load it on our Settings page to avoid adding overhead
 * to every admin page.
 *
 * WHY we check the screen: Loading color picker CSS+JS on every admin page
 * would slow down pages that don't need it. We target only the SocietyPress
 * settings page by checking the hook suffix.
 */
add_action( "admin_enqueue_scripts", function ( $hook ) {
    // Our Design page is registered as a submenu under our custom menu.
    // The hook suffix varies by menu structure, so we check for our page slug.
    // WHY sp-settings-design specifically: Only the Design page uses color
    // pickers — no need to load these assets on the other six settings pages.
    // Load color picker and media uploader on all SocietyPress admin pages.
    // WHY no guard: The overhead is negligible and the hook suffix format
    //      varies unpredictably across WordPress versions and menu structures.
    //      Better to always load than to silently fail.
    if ( strpos( $hook ?? '', 'societypress' ) === false && strpos( $hook ?? '', 'sp-' ) === false ) {
        return;
    }

    // wp-color-picker is the WordPress wrapper around the Iris color picker.
    // It provides a nice UI with a color swatch, hex input, and visual picker.
    wp_enqueue_style( 'wp-color-picker' );
    wp_enqueue_script( 'wp-color-picker' );

    // WHY: The Logo uploader uses wp.media — WordPress's built-in media modal.
    // Must be enqueued before the page renders or wp.media will be undefined.
    wp_enqueue_media();
});

// WHY: The Leadership & Committees page needs a search/filter script so
//      admins can find specific members quickly among potentially thousands
//      of entries. Loaded as a proper enqueued script (not inline) because
//      wp_localize_script is the reliable way to pass PHP data to JS.
add_action( "admin_enqueue_scripts", function ( $hook ) {
    // Only load on the Leadership & Committees page
    if ( strpos( $hook, 'sp-governance' ) === false ) {
        return;
    }

    wp_enqueue_script(
        'sp-leadership-search',
        plugin_dir_url( SOCIETYPRESS_PLUGIN_FILE ) . 'assets/js/leadership-search.js',
        [],
        SOCIETYPRESS_VERSION,
        true // load in footer
    );

    // Build member data for the search — done here so the JS file has
    // access to the full member list via spLeadershipData.members
    global $wpdb;
    $prefix  = $wpdb->prefix . 'sp_';
    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name ASC"
    );

    // Current leadership roles — so search results can show existing assignments
    $officers = $wpdb->get_results(
        "SELECT user_id, role_title FROM {$prefix}volunteer_roles WHERE role_type = 'officer' AND status = 'active'"
    );
    $committees = $wpdb->get_results(
        "SELECT user_id, role_title, committee FROM {$prefix}volunteer_roles WHERE role_type = 'committee' AND status = 'active'"
    );

    $role_lookup = [];
    foreach ( $officers as $o ) {
        $role_lookup[ (int) $o->user_id ][] = $o->role_title . ' (' . __( 'Officer', 'societypress' ) . ')';
    }
    foreach ( $committees as $c ) {
        $label = $c->role_title;
        if ( $c->committee ) {
            $label .= ' — ' . $c->committee;
        }
        $role_lookup[ (int) $c->user_id ][] = $label . ' (' . __( 'Committee', 'societypress' ) . ')';
    }

    $members_data = [];
    $seen         = [];
    foreach ( $members as $m ) {
        $uid = (int) $m->user_id;
        if ( isset( $seen[ $uid ] ) ) continue;
        $seen[ $uid ] = true;
        $members_data[] = [
            'id'    => $uid,
            'name'  => $m->last_name . ', ' . $m->first_name,
            'roles' => $role_lookup[ $uid ] ?? [],
        ];
    }

    wp_localize_script( 'sp-leadership-search', 'spLeadershipData', [
        'members' => $members_data,
        'i18n'    => [
            'noResults'    => __( 'No members found.', 'societypress' ),
            'addOfficer'   => __( 'Add as Officer', 'societypress' ),
            'addCommittee' => __( 'Add to Committee', 'societypress' ),
        ],
    ] );
} );


// ============================================================================
// MEMBERSHIP DIRECTORY — PAGE TEMPLATE
// ============================================================================
//
// WHY: The society needs a public-facing page where members (and optionally
//      visitors) can browse and search the membership. Rather than making
//      the admin fiddle with shortcodes, we register a page template called
//      "Membership Directory" that they simply select from the Template
//      dropdown when editing a page. WordPress handles the rest.
//
// ============================================================================
// NAV MENU — HIDE MEMBERS-ONLY PAGES FROM LOGGED-OUT VISITORS
// ============================================================================
// WHY: The membership directory (and any future members-only pages) already
// show a "Members Only" gate when visited by non-members, but there's no
// reason to advertise the link in the nav if they can't use it. This filter
// removes nav menu items that point to pages using members-only templates
// (sp-directory) when the visitor isn't logged in.
// ----------------------------------------------------------------------------

add_filter( 'wp_nav_menu_objects', 'sp_hide_members_only_nav_items', 10, 2 );

function sp_hide_members_only_nav_items( $items, $args ) {
    // Don't filter if logged in — members see everything
    if ( is_user_logged_in() ) return $items;

    // Templates that require login — add more here as needed
    $members_only_templates = [ 'sp-directory' ];

    // Build a list of menu item IDs to remove (including their children)
    $remove_ids = [];
    foreach ( $items as $item ) {
        // Only check page-type menu items
        if ( $item->type !== 'post_type' || $item->object !== 'page' ) continue;

        $template = get_page_template_slug( $item->object_id );
        if ( in_array( $template, $members_only_templates, true ) ) {
            $remove_ids[] = $item->ID;
            continue;
        }

        // Also hide pages with the per-page "Members Only" checkbox
        if ( get_post_meta( $item->object_id, '_sp_members_only', true ) === '1' ) {
            $remove_ids[] = $item->ID;
        }
    }

    if ( empty( $remove_ids ) ) return $items;

    // Also remove any child items whose parent is being removed
    // WHY: If "Directory" has sub-items, they'd be orphaned in the nav
    $all_remove = $remove_ids;
    foreach ( $items as $item ) {
        if ( in_array( (int) $item->menu_item_parent, $remove_ids, true ) ) {
            $all_remove[] = $item->ID;
        }
    }

    return array_filter( $items, function( $item ) use ( $all_remove ) {
        return ! in_array( $item->ID, $all_remove, true );
    } );
}

// HOW IT WORKS:
//      1. theme_page_templates filter — adds "Membership Directory" to the
//         template dropdown in the Page editor
//      2. template_include filter — when WordPress loads that page, we
//         intercept and render our own output (with the active theme's
//         header and footer so it looks native)
//
// PRIVACY MODEL (three layers):
//      Layer 0 — Login required (always enforced, not a setting):
//        Only logged-in members can see the directory. Period. Non-members
//        have no business browsing member contact info.
//
//      Layer 1 — Society level (Settings → Directory tab):
//        The admin decides which columns appear at all. If they turn off
//        "Phone," no one sees any phone numbers, period.
//
//      Layer 2 — Individual member (member profile → Directory Visibility):
//        Each member has dir_show_name, dir_show_email, dir_show_phone,
//        dir_show_address, dir_show_website checkboxes. Even if the admin
//        enables "Email" at the society level, a member who unchecked
//        "Show email" on their profile will have their email hidden.
//
//      All layers must agree for data to appear.
// ============================================================================


/**
 * Register the "Membership Directory" page template so it shows up
 * in the Template dropdown on the Edit Page screen.
 *
 * WHY: This is a plugin-provided template (not a theme file). We use
 *      the theme_page_templates filter to inject it into the list
 *      WordPress shows. The key ('sp-directory') is an arbitrary slug —
 *      it doesn't need to correspond to a file on disk because we
 *      intercept it in template_include below.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-directory'] = __( 'Membership Directory', 'societypress' );
    return $templates;
});


/**
 * When WordPress is about to load the template for a page that uses our
 * "Membership Directory" template, hijack it and render the directory.
 *
 * WHY: Since our template isn't a physical file in the theme folder,
 *      WordPress would 404 trying to find "sp-directory.php." We catch
 *      it here and output the directory ourselves, using the active
 *      theme's header/footer so it blends in naturally.
 */
add_filter( 'template_include', function ( $template ) {

    // Only act on pages assigned to our custom template
    if ( is_page() && get_page_template_slug() === 'sp-directory' ) {

        $settings = get_option( 'societypress_settings', [] );

        // Enqueue our directory styles
        // WHY: We add the CSS via wp_head so it loads in the <head> where
        //      stylesheets belong, not inline in the body.
        add_action( 'wp_head', 'sp_directory_styles' );
        add_action( 'wp_head', 'sp_directory_detail_styles' );
        add_action( 'wp_footer', 'sp_directory_detail_script' );

        // Start output with the theme's header
        get_header();

        echo '<div class="sp-directory-wrap">';

        // WHY: The membership directory is always members-only. Non-members
        //      have no business browsing member contact info, phone numbers,
        //      and email addresses. This isn't a setting — it's a principle.
        if ( ! is_user_logged_in() ) {
            echo '<div class="sp-directory-login-required">';
            echo '<h2>' . esc_html__( 'Members Only', 'societypress' ) . '</h2>';
            echo '<p>' . sprintf(
                esc_html__( 'The membership directory is available to logged-in members. Please %s to view the directory.', 'societypress' ),
                '<a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a>'
            ) . '</p>';
            echo '</div>';
        } else {
            sp_render_directory( $settings );
        }

        echo '</div>';

        get_footer();

        // Return an empty string to prevent WordPress from loading another template.
        // WHY: We already output everything via get_header/get_footer. If we return
        //      the original $template, WordPress would load it on top of our output,
        //      causing duplicate headers/footers. An empty include file means "done."
        //
        // We use a trick: return a path to a file that outputs nothing. The simplest
        // approach is to return the path to a tiny temp file. But an even simpler
        // approach is to just exit — except that breaks wp_footer scripts. So we
        // use PHP's __DIR__ trick to find a file we know is empty-ish.
        //
        // Actually the cleanest pattern: have template_include return a custom file
        // that just does nothing. Since we can't create files from a monolithic
        // plugin, we'll use a PHP wrapper.
        return sp_get_blank_template_path();
    }

    return $template;
});


/**
 * Return the path to a blank template file for template_include.
 *
 * WHY: template_include needs to return a path to a real file, but our page
 *      templates (directory, events, etc.) output their content directly via
 *      get_header() + rendering functions + get_footer(). The included file
 *      needs to be empty so WordPress doesn't output anything extra.
 *
 *      Previously we created a blank file at runtime via file_put_contents()
 *      on every init hook — that's unexpected filesystem writes from a plugin.
 *      Instead, we use a static temp file created once in the system temp
 *      directory. If it somehow gets cleaned up, we recreate it lazily only
 *      when actually needed (not on every page load).
 */
function sp_get_blank_template_path(): string {
    // WHY: sys_get_temp_dir() is unreliable — some hosts purge /tmp on cron,
    //      some have open_basedir restrictions, and shared hosting may expose
    //      the file to other accounts. wp_upload_dir() gives us a WordPress-
    //      managed, writable, per-site directory that persists reliably.
    $upload_dir = wp_upload_dir();
    $blank_path = $upload_dir['basedir'] . '/sp-blank-template.php';
    if ( ! file_exists( $blank_path ) ) {
        @file_put_contents( $blank_path, "<?php\n// Intentionally blank — SocietyPress template shim.\n" );
    }
    return $blank_path;
}
/**
 * Render the membership directory — the main content between header and footer.
 *
 * WHY: This function builds the complete directory UI: search bar, filter
 *      dropdowns, letter filter, results table, and pagination. It queries
 *      the database respecting both society-level column toggles (settings)
 *      and individual member privacy preferences (dir_show_* fields).
 *
 * FILTERS: Text search + status + group + tier + surname all combine with
 *          AND logic. This lets members drill down precisely — e.g., find
 *          all active members in the "Cemetery Research" group who are
 *          researching the surname "Smith."
 *
 * @param array $settings The societypress_settings option array.
 */
function sp_render_directory( array $settings ): void {
    global $wpdb;

    $prefix   = $wpdb->prefix . 'sp_';
    $per_page = (int) ( $settings['dir_per_page'] ?? 25 );

    // ---- Collect filter/search parameters from the URL ----

    // Search query — sanitize and trim
    $search = isset( $_GET['sp_search'] ) ? sanitize_text_field( wp_unslash( $_GET['sp_search'] ) ) : '';

    // Letter filter — single uppercase letter or empty for "all"
    $letter = isset( $_GET['sp_letter'] ) ? strtoupper( sanitize_text_field( $_GET['sp_letter'] ) ) : '';
    if ( $letter && ! preg_match( '/^[A-Z]$/', $letter ) ) {
        $letter = ''; // Invalid letter — show all
    }

    // Status filter — default to "active" so the directory shows current members
    $status_filter = isset( $_GET['sp_status'] ) ? sanitize_text_field( $_GET['sp_status'] ) : 'active';
    $allowed_statuses = [ 'active', 'inactive', 'all' ];
    if ( ! in_array( $status_filter, $allowed_statuses, true ) ) {
        $status_filter = 'active';
    }

    // Group/committee filter — numeric group ID or empty for "all"
    $group_filter = isset( $_GET['sp_group'] ) ? (int) $_GET['sp_group'] : 0;

    // Membership tier filter — numeric tier ID or empty for "all"
    $tier_filter = isset( $_GET['sp_tier'] ) ? (int) $_GET['sp_tier'] : 0;

    // Dedicated surname search — separate from the main text search so members
    // can filter specifically by surname being researched without mixing it
    // into the general name/email search.
    $surname_search  = isset( $_GET['sp_surname'] ) ? sanitize_text_field( wp_unslash( $_GET['sp_surname'] ) ) : '';
    $surname_similar = ! empty( $_GET['sp_surname_similar'] );

    // Sort column and direction
    $allowed_sorts = [ 'last_name', 'first_name', 'city', 'state', 'join_date', 'tier_name', 'phone', 'user_email', 'website' ];
    $sort_by       = isset( $_GET['sp_sort'] ) && in_array( $_GET['sp_sort'], $allowed_sorts, true )
                     ? $_GET['sp_sort'] : 'last_name';
    $sort_dir      = isset( $_GET['sp_dir'] ) && strtolower( $_GET['sp_dir'] ) === 'desc' ? 'DESC' : 'ASC';

    // Pagination
    $current_page = max( 1, (int) ( $_GET['sp_page'] ?? 1 ) );
    $offset       = ( $current_page - 1 ) * $per_page;


    // ---- Load filter options from the database ----
    // WHY: We need these for the dropdown menus. One query each — cheap,
    //      and we cache-bust naturally since these change rarely.

    $groups = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}groups WHERE status = 'active' ORDER BY name"
    );

    $tiers = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}membership_tiers ORDER BY sort_order, name"
    );


    // ---- Build the WHERE clause ----

    $where  = [];
    $params = [];

    // Status filter — "all" shows everyone, otherwise filter by status
    if ( $status_filter !== 'all' ) {
        $where[]  = "m.status = %s";
        $params[] = $status_filter;
    }

    // Text search — look in name, city, email, member number, interests, skills, and surnames
    if ( $search !== '' ) {
        $like     = '%' . $wpdb->esc_like( $search ) . '%';
        $where[]  = "(
            m.first_name LIKE %s
            OR m.last_name LIKE %s
            OR m.preferred_name LIKE %s
            OR m.organization_name LIKE %s
            OR m.city LIKE %s
            OR m.member_number LIKE %s
            OR m.interests LIKE %s
            OR m.skills LIKE %s
            OR u.user_email LIKE %s
            OR EXISTS (
                SELECT 1 FROM {$prefix}member_surnames s
                WHERE s.user_id = m.user_id AND s.surname LIKE %s
            )
        )";
        $params[] = $like; // first_name
        $params[] = $like; // last_name
        $params[] = $like; // preferred_name
        $params[] = $like; // organization_name
        $params[] = $like; // city
        $params[] = $like; // member_number
        $params[] = $like; // interests
        $params[] = $like; // skills
        $params[] = $like; // user_email
        $params[] = $like; // surname
    }

    // Dedicated surname filter — matches against the surnames table specifically.
    // WHY: Surnames are THE killer feature for genealogical societies. Members
    //      want to find others researching the same family lines without wading
    //      through general search results. A dedicated surname filter makes
    //      this dead simple.
    if ( $surname_search !== '' ) {
        if ( $surname_similar ) {
            // WHY: Soundex and Metaphone are phonetic algorithms that group
            // surnames that "sound alike" — Smith/Smyth, Meyer/Meier/Myer,
            // Johnson/Jonson. We check both because each catches different
            // variations. This is THE feature that makes a genealogical
            // society directory worth having.
            $sdx = soundex( $surname_search );
            $mph = metaphone( $surname_search );
            $surname_like = '%' . $wpdb->esc_like( $surname_search ) . '%';
            // WHY: We check four sources in priority order:
            //   1. LIKE match on the surname itself
            //   2. Soundex phonetic match
            //   3. Metaphone phonetic match
            //   4. Explicit variant table — admin-curated mappings that say
            //      "Smythe IS a variant of Smith" with certainty, bridging
            //      gaps that phonetic algorithms miss.
            $where[]  = "EXISTS (
                SELECT 1 FROM {$prefix}member_surnames s
                WHERE s.user_id = m.user_id
                  AND (
                    s.surname LIKE %s
                    OR s.soundex_code = %s
                    OR s.metaphone_code = %s
                    OR s.surname IN (
                        SELECT sv.variant FROM {$prefix}surname_variants sv WHERE sv.canonical = %s
                        UNION
                        SELECT sv2.canonical FROM {$prefix}surname_variants sv2 WHERE sv2.variant = %s
                    )
                  )
            )";
            $params[] = $surname_like;
            $params[] = $sdx;
            $params[] = $mph;
            $params[] = $surname_search;
            $params[] = $surname_search;
        } else {
            $surname_like = '%' . $wpdb->esc_like( $surname_search ) . '%';
            $where[]  = "EXISTS (
                SELECT 1 FROM {$prefix}member_surnames s
                WHERE s.user_id = m.user_id AND s.surname LIKE %s
            )";
            $params[] = $surname_like;
        }
    }

    // Group/committee filter — find members who belong to the selected group
    if ( $group_filter > 0 ) {
        $where[]  = "m.user_id IN (
            SELECT gm.user_id FROM {$prefix}group_members gm
            WHERE gm.group_id = %d
        )";
        $params[] = $group_filter;
    }

    // Tier filter — match against the membership tier
    if ( $tier_filter > 0 ) {
        $where[]  = "m.tier_id = %d";
        $params[] = $tier_filter;
    }

    // Letter filter — match first character of last name (or org name for orgs)
    if ( $letter !== '' ) {
        $where[]  = "(m.last_name LIKE %s OR m.organization_name LIKE %s)";
        $params[] = $letter . '%';
        $params[] = $letter . '%';
    }

    // Default: if no filters at all, show all records (no WHERE restriction beyond joins)
    $where_sql = ! empty( $where ) ? implode( ' AND ', $where ) : '1=1';


    // ---- Count total matching members (for pagination) ----

    $count_sql = "SELECT COUNT(*)
        FROM {$prefix}members m
        JOIN {$wpdb->users} u ON u.ID = m.user_id
        WHERE {$where_sql}";

    if ( ! empty( $params ) ) {
        $count_sql = $wpdb->prepare( $count_sql, ...$params );
    }

    $total_members = (int) $wpdb->get_var( $count_sql );
    $total_pages   = max( 1, (int) ceil( $total_members / $per_page ) );

    // Clamp current page to valid range
    if ( $current_page > $total_pages ) {
        $current_page = $total_pages;
        $offset       = ( $current_page - 1 ) * $per_page;
    }


    // ---- Handle sort column that comes from a joined table ----

    // Map sort keys to actual SQL column references.
    // WHY: Some sortable columns live on joined tables, not on sp_members.
    $sort_col_map = [
        'tier_name'  => 't.name',
        'user_email' => 'u.user_email',
    ];
    $order_col = $sort_col_map[ $sort_by ] ?? $sort_by;


    // ---- Fetch the members for this page ----

    $query = "SELECT m.*, u.user_email, t.name AS tier_name
        FROM {$prefix}members m
        JOIN {$wpdb->users} u ON u.ID = m.user_id
        LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
        WHERE {$where_sql}
        ORDER BY {$order_col} {$sort_dir}
        LIMIT %d OFFSET %d";

    // Build params: search/letter params + limit + offset
    $query_params = array_merge( $params, [ $per_page, $offset ] );
    $members      = $wpdb->get_results( $wpdb->prepare( $query, ...$query_params ) );
    // Decrypt sensitive contact/address fields that are encrypted at rest
    $members      = sp_member_decrypt_rows( $members );


    // ---- Load surnames for all members on this page (one query, not N) ----

    $surnames_map = [];
    if ( ! empty( $settings['dir_show_surnames'] ) && ! empty( $members ) ) {
        $user_ids    = array_map( fn( $m ) => (int) $m->user_id, $members );
        $placeholders = implode( ', ', array_fill( 0, count( $user_ids ), '%d' ) );
        $surname_rows = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT user_id, surname, county, state, country, year_from, year_to
                 FROM {$prefix}member_surnames
                 WHERE user_id IN ({$placeholders})
                 ORDER BY surname",
                ...$user_ids
            )
        );
        foreach ( $surname_rows as $row ) {
            $surnames_map[ $row->user_id ][] = $row;
        }
    }


    // ---- Load group memberships for all members on this page ----
    // WHY: We show which groups each member belongs to in the results,
    //      so members can see at a glance who's in what committee.

    $groups_map = [];
    if ( ! empty( $members ) ) {
        $user_ids     = array_map( fn( $m ) => (int) $m->user_id, $members );
        $placeholders = implode( ', ', array_fill( 0, count( $user_ids ), '%d' ) );
        $group_rows   = $wpdb->get_results(
            $wpdb->prepare(
                "SELECT gm.user_id, g.name
                 FROM {$prefix}group_members gm
                 JOIN {$prefix}groups g ON g.id = gm.group_id
                 WHERE gm.user_id IN ({$placeholders}) AND g.status = 'active'
                 ORDER BY g.name",
                ...$user_ids
            )
        );
        foreach ( $group_rows as $row ) {
            $groups_map[ $row->user_id ][] = $row->name;
        }
    }


    // ---- Determine which columns to show (society-level settings) ----

    $show_city_state = ! empty( $settings['dir_show_city_state'] );
    $show_phone      = ! empty( $settings['dir_show_phone'] );
    $show_email      = ! empty( $settings['dir_show_email'] );
    $show_website    = ! empty( $settings['dir_show_website'] );
    $show_tier       = ! empty( $settings['dir_show_tier'] );
    $show_join_date  = ! empty( $settings['dir_show_join_date'] );
    $show_surnames   = ! empty( $settings['dir_show_surnames'] );

    // Count columns for the "no results" colspan
    $col_count = 1; // Name is always shown
    if ( $show_city_state ) $col_count++;
    if ( $show_phone )      $col_count++;
    if ( $show_email )      $col_count++;
    if ( $show_website )    $col_count++;
    if ( $show_tier )       $col_count++;
    if ( $show_join_date )  $col_count++;


    // ---- Build the current page URL for filters/sorting/pagination ----

    $base_url = get_permalink();


    // ---- Helper: collect all active filter args for URL building ----
    // WHY: Every link on the page (sort headers, letter filter, pagination)
    //      needs to preserve the current filter state. This array holds all
    //      non-empty filter values so we can merge them into URLs.

    $filter_args = array_filter( [
        'sp_search'  => $search ?: null,
        'sp_status'  => $status_filter !== 'active' ? $status_filter : null,
        'sp_group'   => $group_filter > 0 ? $group_filter : null,
        'sp_tier'    => $tier_filter > 0 ? $tier_filter : null,
        'sp_surname' => $surname_search ?: null,
    ] );


    // ---- Helper: build a sort URL for a column header ----

    $sort_url = function ( $col ) use ( $base_url, $filter_args, $letter, $sort_by, $sort_dir ) {
        $new_dir = ( $sort_by === $col && $sort_dir === 'ASC' ) ? 'desc' : 'asc';
        $args    = array_merge( $filter_args, [ 'sp_sort' => $col, 'sp_dir' => $new_dir ] );
        if ( $letter !== '' ) $args['sp_letter'] = $letter;
        return esc_url( add_query_arg( $args, $base_url ) );
    };

    // ---- Helper: sort indicator arrow ----

    // WHY aria-hidden on the visual arrow: screen readers would announce "up-pointing
    // triangle" which is meaningless. The aria-sort attribute on <th> already
    // communicates the sort direction in a standard way.
    $sort_arrow = function ( $col ) use ( $sort_by, $sort_dir ) {
        if ( $sort_by !== $col ) return '';
        $arrow = $sort_dir === 'ASC' ? '&#9650;' : '&#9660;';
        return ' <span aria-hidden="true">' . $arrow . '</span>';
    };

    // Helper: returns aria-sort attribute string for sortable <th> elements.
    // Screen readers use aria-sort to announce "sorted ascending/descending".
    $aria_sort = function ( $col ) use ( $sort_by, $sort_dir ) {
        if ( $sort_by !== $col ) return '';
        return ' aria-sort="' . ( $sort_dir === 'ASC' ? 'ascending' : 'descending' ) . '"';
    };


    // ---- Check if any filters are active (for the "Clear All" button) ----
    $has_filters = $search !== '' || $status_filter !== 'active' || $group_filter > 0
                   || $tier_filter > 0 || $surname_search !== '' || $letter !== '';


    // ================================================================
    // OUTPUT: Search bar + filter dropdowns
    // ================================================================

    ?>
    <div class="sp-directory-search">
        <form method="get" action="<?php echo esc_url( $base_url ); ?>">

            <!-- Text search row -->
            <div class="sp-search-row">
                <input type="text"
                       name="sp_search"
                       value="<?php echo esc_attr( $search ); ?>"
                       placeholder="<?php echo esc_attr__( 'Search by name, city, email, or surname…', 'societypress' ); ?>"
                       class="sp-search-input"
                       aria-label="<?php echo esc_attr__( 'Search the membership directory', 'societypress' ); ?>">
                <button type="submit" class="sp-search-button"><?php echo esc_html__( 'Search', 'societypress' ); ?></button>
                <?php if ( $has_filters ) : ?>
                    <a href="<?php echo esc_url( $base_url ); ?>" class="sp-search-clear"><?php echo esc_html__( 'Clear All', 'societypress' ); ?></a>
                <?php endif; ?>
            </div>

            <!-- Filter dropdowns row -->
            <div class="sp-filter-row">

                <!-- Status filter -->
                <div class="sp-filter-group">
                    <label for="sp-filter-status" class="sp-filter-label"><?php echo esc_html__( 'Status', 'societypress' ); ?></label>
                    <select name="sp_status" id="sp-filter-status" class="sp-filter-select">
                        <option value="active" <?php selected( $status_filter, 'active' ); ?>><?php echo esc_html__( 'Active', 'societypress' ); ?></option>
                        <option value="inactive" <?php selected( $status_filter, 'inactive' ); ?>><?php echo esc_html__( 'Inactive', 'societypress' ); ?></option>
                        <option value="all" <?php selected( $status_filter, 'all' ); ?>><?php echo esc_html__( 'All Members', 'societypress' ); ?></option>
                    </select>
                </div>

                <?php if ( ! empty( $groups ) ) : ?>
                <!-- Group/committee filter -->
                <div class="sp-filter-group">
                    <label for="sp-filter-group" class="sp-filter-label"><?php echo esc_html__( 'Group', 'societypress' ); ?></label>
                    <select name="sp_group" id="sp-filter-group" class="sp-filter-select">
                        <option value="0"><?php echo esc_html__( 'All Groups', 'societypress' ); ?></option>
                        <?php foreach ( $groups as $g ) : ?>
                            <option value="<?php echo (int) $g->id; ?>" <?php selected( $group_filter, (int) $g->id ); ?>>
                                <?php echo esc_html( $g->name ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                </div>
                <?php endif; ?>

                <?php if ( ! empty( $tiers ) ) : ?>
                <!-- Membership tier filter -->
                <div class="sp-filter-group">
                    <label for="sp-filter-tier" class="sp-filter-label"><?php echo esc_html__( 'Membership', 'societypress' ); ?></label>
                    <select name="sp_tier" id="sp-filter-tier" class="sp-filter-select">
                        <option value="0"><?php echo esc_html__( 'All Types', 'societypress' ); ?></option>
                        <?php foreach ( $tiers as $t ) : ?>
                            <option value="<?php echo (int) $t->id; ?>" <?php selected( $tier_filter, (int) $t->id ); ?>>
                                <?php echo esc_html( $t->name ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                </div>
                <?php endif; ?>

                <!-- Dedicated surname search -->
                <div class="sp-filter-group">
                    <label for="sp-filter-surname" class="sp-filter-label"><?php echo esc_html__( 'Surname Being Researched', 'societypress' ); ?></label>
                    <input type="text"
                           name="sp_surname"
                           id="sp-filter-surname"
                           value="<?php echo esc_attr( $surname_search ); ?>"
                           placeholder="<?php echo esc_attr__( 'e.g. Smith', 'societypress' ); ?>"
                           class="sp-filter-input">
                    <label style="display:block; margin-top:6px; font-size:12px; font-weight:400;">
                        <input type="checkbox" name="sp_surname_similar" value="1"
                               <?php checked( ! empty( $_GET['sp_surname_similar'] ) ); ?>>
                        <?php esc_html_e( 'Include similar spellings', 'societypress' ); ?>
                    </label>
                </div>

            </div>

            <!-- Preserve sort state across filter changes -->
            <?php if ( $sort_by !== 'last_name' ) : ?>
                <input type="hidden" name="sp_sort" value="<?php echo esc_attr( $sort_by ); ?>">
            <?php endif; ?>
            <?php if ( $sort_dir !== 'ASC' ) : ?>
                <input type="hidden" name="sp_dir" value="<?php echo esc_attr( strtolower( $sort_dir ) ); ?>">
            <?php endif; ?>
            <?php if ( $letter !== '' ) : ?>
                <input type="hidden" name="sp_letter" value="<?php echo esc_attr( $letter ); ?>">
            <?php endif; ?>

        </form>
    </div>
    <?php


    // ================================================================
    // OUTPUT: Alphabetical letter filter
    // ================================================================

    ?>
    <nav aria-label="<?php esc_attr_e( 'Alphabetical filter', 'societypress' ); ?>">
    <div class="sp-directory-letters">
        <a href="<?php echo esc_url( add_query_arg( $filter_args, $base_url ) ); ?>"
           class="sp-letter <?php echo $letter === '' ? 'sp-letter-active' : ''; ?>"><?php echo esc_html__( 'All', 'societypress' ); ?></a>
        <?php
        foreach ( range( 'A', 'Z' ) as $l ) :
            $l_args = array_merge( $filter_args, [ 'sp_letter' => $l ] );
        ?>
            <a href="<?php echo esc_url( add_query_arg( $l_args, $base_url ) ); ?>"
               class="sp-letter <?php echo $letter === $l ? 'sp-letter-active' : ''; ?>"><?php echo $l; ?></a>
        <?php endforeach; ?>
    </div>
    </nav>
    <?php


    // ================================================================
    // OUTPUT: Results count + active filter summary
    // ================================================================

    ?>
    <div class="sp-directory-count">
        <?php
        if ( $total_members === 0 ) {
            echo '<p>' . esc_html__( 'No members found.', 'societypress' ) . '</p>';
        } elseif ( $total_members === 1 ) {
            echo '<p>' . esc_html__( '1 member', 'societypress' ) . '</p>';
        } else {
            printf( '<p>%s ' . esc_html__( 'members', 'societypress' ) . '</p>', number_format_i18n( $total_members ) );
        }

        // Show a note when similar-spellings search is active
        if ( $surname_search !== '' && $surname_similar && $total_members > 0 ) {
            echo '<p style="font-size:13px; color:#2271b1; margin-top:4px;">'
               . esc_html__( 'Also showing members with similar surname spellings.', 'societypress' )
               . '</p>';
        }
        ?>
    </div>
    <?php


    // ================================================================
    // OUTPUT: Results table
    // ================================================================

    if ( ! empty( $members ) ) :
    ?>
    <div class="sp-directory-table-wrap">
        <table class="sp-directory-table">
            <thead>
                <tr>
                    <th class="sp-col-name"<?php echo $aria_sort( 'last_name' ); ?>>
                        <a href="<?php echo $sort_url( 'last_name' ); ?>"><?php echo esc_html__( 'Name', 'societypress' ); ?><?php echo $sort_arrow( 'last_name' ); ?></a>
                    </th>
                    <?php if ( $show_city_state ) : ?>
                        <th class="sp-col-location"<?php echo $aria_sort( 'city' ); ?>>
                            <a href="<?php echo $sort_url( 'city' ); ?>"><?php echo esc_html__( 'Location', 'societypress' ); ?><?php echo $sort_arrow( 'city' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_phone ) : ?>
                        <th class="sp-col-phone"<?php echo $aria_sort( 'phone' ); ?>>
                            <a href="<?php echo $sort_url( 'phone' ); ?>"><?php echo esc_html__( 'Phone', 'societypress' ); ?><?php echo $sort_arrow( 'phone' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_email ) : ?>
                        <th class="sp-col-email"<?php echo $aria_sort( 'user_email' ); ?>>
                            <a href="<?php echo $sort_url( 'user_email' ); ?>"><?php echo esc_html__( 'Email', 'societypress' ); ?><?php echo $sort_arrow( 'user_email' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_website ) : ?>
                        <th class="sp-col-website"<?php echo $aria_sort( 'website' ); ?>>
                            <a href="<?php echo $sort_url( 'website' ); ?>"><?php echo esc_html__( 'Website', 'societypress' ); ?><?php echo $sort_arrow( 'website' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_tier ) : ?>
                        <th class="sp-col-tier"<?php echo $aria_sort( 'tier_name' ); ?>>
                            <a href="<?php echo $sort_url( 'tier_name' ); ?>"><?php echo esc_html__( 'Type', 'societypress' ); ?><?php echo $sort_arrow( 'tier_name' ); ?></a>
                        </th>
                    <?php endif; ?>
                    <?php if ( $show_join_date ) : ?>
                        <th class="sp-col-date"<?php echo $aria_sort( 'join_date' ); ?>>
                            <a href="<?php echo $sort_url( 'join_date' ); ?>"><?php echo esc_html__( 'Member Since', 'societypress' ); ?><?php echo $sort_arrow( 'join_date' ); ?></a>
                        </th>
                    <?php endif; ?>
                </tr>
            </thead>
            <tbody>
            <?php foreach ( $members as $m ) :

                // ---- Individual member privacy checks (Layer 2) ----
                // If the member has opted out of showing their name entirely,
                // skip them from the directory. (Rare, but respected.)
                if ( empty( $m->dir_show_name ) ) {
                    continue;
                }

                // Build the display name — orgs show their org name, individuals
                // show preferred (or first) + last name as before.
                if ( ( $m->member_type ?? 'individual' ) === 'organization' && ! empty( $m->organization_name ) ) {
                    $display_name = esc_html( $m->organization_name );
                } else {
                    $display_name = esc_html( trim(
                        ( ($m->preferred_name ?? '') ?: $m->first_name ) . ' ' . $m->last_name
                    ) );
                    if ( $m->suffix ) {
                        $display_name .= ', ' . esc_html( $m->suffix );
                    }
                    // Joint member — show both names in the directory.
                    // WHY: Couples who share a membership expect to both be
                    //      visible in the directory. "John & Jane Smith" or
                    //      "John Smith & Jane Doe" if different last names.
                    if ( ! empty( $m->joint_member ) && ! empty( $m->joint_first_name ) ) {
                        $joint_display = esc_html( ($m->joint_preferred_name ?? '') ?: $m->joint_first_name );
                        if ( ! empty( $m->joint_last_name ) && $m->joint_last_name !== $m->last_name ) {
                            $joint_display .= ' ' . esc_html( $m->joint_last_name );
                        }
                        // Rebuild as "John & Jane Smith" or "John Smith & Jane Doe"
                        $primary = esc_html( ($m->preferred_name ?? '') ?: $m->first_name );
                        if ( ! empty( $m->joint_last_name ) && $m->joint_last_name !== $m->last_name ) {
                            // Different last names — show both full names
                            $display_name = $primary . ' ' . esc_html( $m->last_name )
                                          . ' &amp; ' . $joint_display;
                        } else {
                            // Same last name — "John & Jane Smith"
                            $display_name = $primary . ' &amp; ' . $joint_display
                                          . ' ' . esc_html( $m->last_name );
                        }
                        if ( $m->suffix ) {
                            $display_name .= ', ' . esc_html( $m->suffix );
                        }
                    }
                }
            ?>
                <tr>
                    <td class="sp-col-name" data-label="<?php echo esc_attr__( 'Name', 'societypress' ); ?>"><a href="#" class="sp-member-name-link" data-user-id="<?php echo (int) $m->user_id; ?>"><?php echo $display_name; ?></a></td>

                    <?php if ( $show_city_state ) : ?>
                        <td class="sp-col-location" data-label="<?php echo esc_attr__( 'Location', 'societypress' ); ?>">
                            <?php
                            // Respect the member's address privacy preference
                            if ( ! empty( $m->dir_show_address ) ) {
                                $parts = array_filter( [ $m->city, $m->state ] );
                                echo esc_html( implode( ', ', $parts ) );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_phone ) : ?>
                        <td class="sp-col-phone" data-label="<?php echo esc_attr__( 'Phone', 'societypress' ); ?>">
                            <?php
                            if ( ! empty( $m->dir_show_phone ) && $m->phone ) {
                                // Link the phone number for mobile users
                                printf(
                                    '<a href="tel:%s">%s</a>',
                                    esc_attr( preg_replace( '/[^+0-9]/', '', $m->phone ) ),
                                    esc_html( $m->phone )
                                );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_email ) : ?>
                        <td class="sp-col-email" data-label="<?php echo esc_attr__( 'Email', 'societypress' ); ?>">
                            <?php
                            if ( ! empty( $m->dir_show_email ) && $m->user_email ) {
                                // JS-based obfuscation: email is split and base64-encoded
                                // in data attributes, assembled into a real mailto: link
                                // by the spAssembleEmails() script in the footer. Bots
                                // that don't execute JS get nothing.
                                echo sp_obfuscate_email( $m->user_email );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_website ) : ?>
                        <td class="sp-col-website" data-label="<?php echo esc_attr__( 'Website', 'societypress' ); ?>">
                            <?php
                            if ( ! empty( $m->dir_show_website ) && $m->website ) {
                                // Strip protocol for display but keep it for the href
                                $display_url = preg_replace( '#^https?://#', '', rtrim( $m->website, '/' ) );
                                $full_url    = $m->website;
                                if ( ! preg_match( '#^https?://#', $full_url ) ) {
                                    $full_url = 'https://' . $full_url;
                                }
                                printf(
                                    '<a href="%s" target="_blank" rel="noopener">%s</a>',
                                    esc_url( $full_url ),
                                    esc_html( $display_url )
                                );
                            }
                            ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_tier ) : ?>
                        <td class="sp-col-tier" data-label="<?php echo esc_attr__( 'Type', 'societypress' ); ?>">
                            <?php echo esc_html( $m->tier_name ?? '' ); ?>
                        </td>
                    <?php endif; ?>

                    <?php if ( $show_join_date ) : ?>
                        <td class="sp-col-date" data-label="<?php echo esc_attr__( 'Member Since', 'societypress' ); ?>">
                            <?php
                            if ( $m->join_date && $m->join_date !== '0000-00-00' ) {
                                echo esc_html( wp_date( get_option( 'date_format', 'F j, Y' ), strtotime( $m->join_date ) ) );
                            }
                            ?>
                        </td>
                    <?php endif; ?>
                </tr>

                <?php
                // ---- Surnames row (spans full width below the member) ----
                // WHY: Surnames are the killer feature for genealogical societies.
                //      Showing them inline in a column would be too cramped — they
                //      can have location/date ranges. So we show them in an
                //      expandable row below the member's main row.
                if ( $show_surnames && ! empty( $surnames_map[ $m->user_id ] ) ) :
                ?>
                    <tr class="sp-surname-row">
                        <td colspan="<?php echo $col_count; ?>">
                            <div class="sp-surnames">
                                <span class="sp-surnames-label"><?php echo esc_html__( 'Researching:', 'societypress' ); ?></span>
                                <?php
                                $parts = [];
                                foreach ( $surnames_map[ $m->user_id ] as $s ) {
                                    $text = '<strong>' . esc_html( $s->surname ) . '</strong>';

                                    // Add location context if available
                                    $loc = array_filter( [ $s->county, $s->state, $s->country ] );
                                    if ( $loc ) {
                                        $text .= ' <span class="sp-surname-detail">(' . esc_html( implode( ', ', $loc ) );
                                        // Add year range if available
                                        if ( $s->year_from || $s->year_to ) {
                                            $text .= ', ' . esc_html( ( $s->year_from ?: '?' ) . '–' . ( $s->year_to ?: 'present' ) );
                                        }
                                        $text .= ')</span>';
                                    } elseif ( $s->year_from || $s->year_to ) {
                                        $text .= ' <span class="sp-surname-detail">(' . esc_html( ( $s->year_from ?: '?' ) . '–' . ( $s->year_to ?: 'present' ) ) . ')</span>';
                                    }

                                    $parts[] = $text;
                                }
                                echo implode( ' &middot; ', $parts );
                                ?>
                            </div>
                        </td>
                    </tr>
                <?php endif; ?>

                <?php
                // ---- Groups row (spans full width below the member/surnames) ----
                // WHY: Showing group membership helps members find others in the
                //      same committee or interest group. Displayed as tags.
                if ( ! empty( $groups_map[ $m->user_id ] ) ) :
                ?>
                    <tr class="sp-groups-row">
                        <td colspan="<?php echo $col_count; ?>">
                            <div class="sp-member-groups">
                                <span class="sp-groups-label"><?php echo esc_html__( 'Groups:', 'societypress' ); ?></span>
                                <?php
                                $group_tags = [];
                                foreach ( $groups_map[ $m->user_id ] as $gname ) {
                                    $group_tags[] = '<span class="sp-group-tag">' . esc_html( $gname ) . '</span>';
                                }
                                echo implode( ' ', $group_tags );
                                ?>
                            </div>
                        </td>
                    </tr>
                <?php endif; ?>

            <?php endforeach; ?>
            </tbody>
        </table>
    </div>
    <?php endif; // ! empty( $members ) ?>


    <?php
    // ================================================================
    // OUTPUT: Pagination
    // ================================================================

    if ( $total_pages > 1 ) :
        // Build base args that persist across page links — includes all filters
        $page_args = $filter_args;
        if ( $letter !== '' ) $page_args['sp_letter'] = $letter;
        if ( $sort_by !== 'last_name' ) $page_args['sp_sort'] = $sort_by;
        if ( $sort_dir !== 'ASC' ) $page_args['sp_dir'] = strtolower( $sort_dir );
    ?>
    <nav class="sp-directory-pagination" aria-label="<?php echo esc_attr__( 'Directory pagination', 'societypress' ); ?>">
        <?php if ( $current_page > 1 ) : ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page - 1 ] ), $base_url ) ); ?>"
               class="sp-page-link sp-page-prev">&laquo; <?php echo esc_html__( 'Previous', 'societypress' ); ?></a>
        <?php endif; ?>

        <?php
        // Show page numbers with ellipsis for large sets
        // WHY: If there are 50 pages, we don't want to show all 50 links.
        //      Show: 1 ... [current-1] [current] [current+1] ... [last]
        $range = 2; // How many pages to show on each side of current
        $start = max( 1, $current_page - $range );
        $end   = min( $total_pages, $current_page + $range );

        if ( $start > 1 ) :
        ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => 1 ] ), $base_url ) ); ?>"
               class="sp-page-link">1</a>
            <?php if ( $start > 2 ) : ?>
                <span class="sp-page-ellipsis">&hellip;</span>
            <?php endif; ?>
        <?php endif; ?>

        <?php for ( $p = $start; $p <= $end; $p++ ) : ?>
            <?php if ( $p === $current_page ) : ?>
                <span class="sp-page-link sp-page-current"><?php echo $p; ?></span>
            <?php else : ?>
                <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $p ] ), $base_url ) ); ?>"
                   class="sp-page-link"><?php echo $p; ?></a>
            <?php endif; ?>
        <?php endfor; ?>

        <?php if ( $end < $total_pages ) : ?>
            <?php if ( $end < $total_pages - 1 ) : ?>
                <span class="sp-page-ellipsis">&hellip;</span>
            <?php endif; ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $total_pages ] ), $base_url ) ); ?>"
               class="sp-page-link"><?php echo $total_pages; ?></a>
        <?php endif; ?>

        <?php if ( $current_page < $total_pages ) : ?>
            <a href="<?php echo esc_url( add_query_arg( array_merge( $page_args, [ 'sp_page' => $current_page + 1 ] ), $base_url ) ); ?>"
               class="sp-page-link sp-page-next"><?php echo esc_html__( 'Next', 'societypress' ); ?> &raquo;</a>
        <?php endif; ?>
    </nav>
    <?php endif; // $total_pages > 1 ?>

    <?php
}



// ============================================================================
// MEMBERSHIP DIRECTORY — FRONTEND CSS
// ============================================================================
function sp_directory_styles(): void {
    ?>
    <style id="sp-directory-css">
        /* ---- Wrapper ---- */
        .sp-directory-wrap {
            margin: 40px auto;
            padding: 0 20px;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, sans-serif;
        }

        /* ---- Search bar ---- */
        .sp-directory-search {
            margin-bottom: 20px;
        }
        .sp-search-row {
            display: flex;
            gap: 8px;
            align-items: center;
            flex-wrap: wrap;
        }
        .sp-search-input {
            flex: 1;
            min-width: 200px;
            padding: 10px 14px;
            font-size: 16px;
            border: 2px solid #ddd;
            border-radius: 6px;
            outline: none;
            transition: border-color 0.2s;
        }
        .sp-search-input:focus {
            border-color: var(--sp-color-primary);
        }
        .sp-search-button {
            padding: 10px 24px;
            font-size: 16px;
            font-weight: 600;
            color: #fff;
            background: var(--sp-color-primary);
            border: none;
            border-radius: 6px;
            cursor: pointer;
            transition: background-color 0.2s;
        }
        .sp-search-button:hover {
            background: var(--sp-color-primary-hover);
        }
        .sp-search-clear {
            padding: 10px 16px;
            font-size: 14px;
            color: #666;
            text-decoration: none;
        }
        .sp-search-clear:hover {
            color: #d63638;
        }

        /* ---- Filter dropdowns row ---- */
        .sp-filter-row {
            display: flex;
            flex-wrap: wrap;
            gap: 12px;
            margin-top: 12px;
            padding: 14px 16px;
            background: #f8f9fa;
            border-radius: 6px;
            border: 1px solid #e5e7eb;
            align-items: flex-end;
        }
        .sp-filter-group {
            display: flex;
            flex-direction: column;
            gap: 4px;
            min-width: 140px;
            flex: 1;
        }
        .sp-filter-label {
            font-size: 12px;
            font-weight: 600;
            color: #666;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }
        .sp-filter-select,
        .sp-filter-input {
            padding: 8px 10px;
            font-size: 14px;
            border: 1px solid #ddd;
            border-radius: 4px;
            background: #fff;
            outline: none;
            transition: border-color 0.2s;
            height: 38px;
            box-sizing: border-box;
        }
        .sp-filter-select:focus,
        .sp-filter-input:focus {
            border-color: var(--sp-color-primary);
        }

        /* ---- Alphabetical letter filter ---- */
        .sp-directory-letters {
            display: flex;
            flex-wrap: wrap;
            gap: 4px;
            margin-bottom: 16px;
            padding: 12px 0;
            border-bottom: 1px solid #eee;
        }
        .sp-letter {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            min-width: 32px;
            height: 32px;
            padding: 0 6px;
            font-size: 14px;
            font-weight: 500;
            color: #555;
            text-decoration: none;
            border-radius: 4px;
            transition: background-color 0.15s, color 0.15s;
        }
        .sp-letter:hover {
            background: #f0f0f0;
            color: var(--sp-color-primary);
        }
        .sp-letter-active {
            background: var(--sp-color-primary);
            color: #fff !important;
        }
        .sp-letter-active:hover {
            background: var(--sp-color-primary-hover);
        }

        /* ---- Results count ---- */
        .sp-directory-count {
            margin-bottom: 12px;
            font-size: 14px;
            color: #666;
        }

        /* ---- Login required message ---- */
        .sp-directory-login-required {
            text-align: center;
            padding: 60px 20px;
            background: #f9f9f9;
            border-radius: 8px;
            margin: 40px 0;
        }
        .sp-directory-login-required h2 {
            margin-bottom: 12px;
            color: #333;
        }
        .sp-directory-login-required a {
            color: var(--sp-color-primary);
            font-weight: 600;
        }

        /* ---- Results table ---- */
        .sp-directory-table-wrap {
            overflow-x: auto;
            -webkit-overflow-scrolling: touch;
        }
        .sp-directory-table {
            width: 100%;
            border-collapse: collapse;
            font-size: 15px;
        }
        .sp-directory-table thead th {
            padding: 10px 12px;
            text-align: left;
            font-weight: 600;
            font-size: 13px;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            color: #666;
            border-bottom: 2px solid #ddd;
            white-space: nowrap;
        }
        .sp-directory-table thead th a {
            color: #666;
            text-decoration: none;
        }
        .sp-directory-table thead th a:hover {
            color: var(--sp-color-primary);
        }
        .sp-directory-table tbody tr {
            border-bottom: 1px solid #eee;
        }
        .sp-directory-table tbody tr:hover {
            background: #f8f9fa;
        }
        .sp-directory-table td {
            padding: 10px 12px;
            vertical-align: top;
            color: #333;
        }
        .sp-directory-table a {
            color: var(--sp-color-primary);
            text-decoration: none;
        }
        .sp-directory-table a:hover {
            text-decoration: underline;
        }

        /* Name column — slightly bolder so it anchors the row */
        .sp-col-name {
            font-weight: 500;
        }

        /* ---- Surname sub-rows ---- */
        .sp-surname-row {
            background: #fafafa !important;
        }
        .sp-surname-row:hover {
            background: #f5f5f5 !important;
        }
        .sp-surname-row td {
            padding: 6px 12px 10px 12px;
            border-bottom: 1px solid #eee;
        }
        .sp-surnames {
            font-size: 13px;
            color: #555;
            line-height: 1.6;
        }
        .sp-surnames-label {
            font-weight: 600;
            color: #666;
            margin-right: 4px;
        }
        .sp-surname-detail {
            color: #888;
            font-size: 12px;
        }

        /* ---- Group membership sub-rows ---- */
        .sp-groups-row {
            background: #fafafa !important;
        }
        .sp-groups-row:hover {
            background: #f5f5f5 !important;
        }
        .sp-groups-row td {
            padding: 4px 12px 10px 12px;
            border-bottom: 1px solid #eee;
        }
        .sp-member-groups {
            font-size: 13px;
            color: #555;
            line-height: 1.8;
        }
        .sp-groups-label {
            font-weight: 600;
            color: #666;
            margin-right: 4px;
        }
        .sp-group-tag {
            display: inline-block;
            padding: 2px 10px;
            margin: 2px 4px 2px 0;
            font-size: 12px;
            font-weight: 500;
            color: var(--sp-color-primary, #0D1F3C);
            background: rgba(13, 31, 60, 0.08);
            border-radius: 12px;
        }

        /* ---- Pagination ---- */
        .sp-directory-pagination {
            display: flex;
            flex-wrap: wrap;
            gap: 4px;
            align-items: center;
            justify-content: center;
            margin: 24px 0;
            padding-top: 16px;
        }
        .sp-page-link {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            min-width: 36px;
            height: 36px;
            padding: 0 10px;
            font-size: 14px;
            color: var(--sp-color-primary);
            text-decoration: none;
            border: 1px solid #ddd;
            border-radius: 4px;
            transition: background-color 0.15s, border-color 0.15s;
        }
        .sp-page-link:hover {
            background: #f0f0f0;
            border-color: var(--sp-color-primary);
        }
        .sp-page-current {
            background: var(--sp-color-primary);
            color: #fff;
            border-color: var(--sp-color-primary);
        }
        .sp-page-ellipsis {
            padding: 0 6px;
            color: #999;
        }

        /* ---- Mobile responsive: table → stacked cards ---- */
        @media screen and (max-width: 768px) {
            .sp-directory-table thead {
                /* WHY: On mobile, we hide the table header and instead show
                   each cell with a data-label prefix. This turns each row
                   into a card where every field is labeled clearly. Much
                   easier to read than a tiny table on a phone. */
                display: none;
            }
            .sp-directory-table,
            .sp-directory-table tbody,
            .sp-directory-table tr,
            .sp-directory-table td {
                display: block;
            }
            .sp-directory-table tbody tr {
                padding: 12px;
                margin-bottom: 12px;
                border: 1px solid #ddd;
                border-radius: 8px;
                background: #fff;
            }
            .sp-directory-table td {
                padding: 4px 0;
                border: none;
            }
            /* Show the data-label as a bold prefix before each value */
            .sp-directory-table td::before {
                content: attr(data-label);
                font-weight: 600;
                color: #666;
                margin-right: 8px;
                font-size: 13px;
            }
            .sp-directory-table td:empty {
                display: none;
            }
            /* Name gets special treatment — bigger, no label prefix */
            .sp-col-name {
                font-size: 17px;
                font-weight: 600;
                padding-bottom: 6px !important;
                margin-bottom: 6px;
                border-bottom: 1px solid #eee;
            }
            .sp-col-name::before {
                display: none !important;
            }

            /* Surname sub-rows become part of the card */
            .sp-surname-row {
                margin-top: -12px; /* Pull up to join the previous card */
                padding-top: 0;
                border-top: none !important;
                border-top-left-radius: 0;
                border-top-right-radius: 0;
            }
            .sp-surname-row td {
                padding-top: 0;
            }

            /* Group sub-rows — same treatment */
            .sp-groups-row {
                margin-top: -12px;
                padding-top: 0;
                border-top: none !important;
                border-top-left-radius: 0;
                border-top-right-radius: 0;
            }
            .sp-groups-row td {
                padding-top: 0;
            }

            /* Filter row stacks vertically on mobile */
            .sp-filter-row {
                flex-direction: column;
                gap: 10px;
            }
            .sp-filter-group {
                min-width: 100%;
            }

            /* Search input fills the width on mobile */
            .sp-search-row {
                flex-direction: column;
            }
            .sp-search-input {
                width: 100%;
            }
            .sp-search-button {
                width: 100%;
            }
        }
    </style>
    <?php
}




// ============================================================================


// ============================================================================
// MEMBERSHIP DIRECTORY — MEMBER DETAIL MODAL (AJAX)
// ============================================================================
//
// WHY: When a member clicks a name in the directory, they want to see more
//      about that person — what they're researching, what groups they're in,
//      how to reach them. Instead of navigating to a whole new page (and
//      losing their place in the directory), we show a clean modal overlay
//      with the member's public profile. All privacy settings are respected.
//
// HOW: The directory wraps each member name in a clickable link. JavaScript
//      intercepts the click, fires an AJAX request to sp_member_detail,
//      and displays the response in a modal. Same pattern as the library
//      catalog detail view.
// ============================================================================


/**
 * AJAX handler: Return member detail data for the modal.
 *
 * WHY: This endpoint fetches a single member's public-facing profile data,
 *      respecting both society-level display settings and the individual
 *      member's privacy preferences. Only logged-in users can call this
 *      (wp_ajax_ prefix, no nopriv equivalent).
 */
add_action( 'wp_ajax_sp_member_detail', 'sp_ajax_member_detail' );
function sp_ajax_member_detail(): void {
    $user_id = absint( $_GET['user_id'] ?? 0 );
    if ( ! $user_id ) {
        wp_send_json_error( __( 'Missing member ID.', 'societypress' ) );
    }

    // Only logged-in members can view profiles
    if ( ! is_user_logged_in() ) {
        wp_send_json_error( __( 'You must be logged in to view member profiles.', 'societypress' ) );
    }

    // Verify nonce to prevent CSRF — the directory JS passes this with every request
    if ( ! check_ajax_referer( 'sp_member_detail_nonce', 'nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed. Please refresh the page.', 'societypress' ) );
    }

    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Fetch the member record with tier name and email from wp_users
    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT m.*, u.user_email, t.name AS tier_name
         FROM {$prefix}members m
         JOIN {$wpdb->users} u ON u.ID = m.user_id
         LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
         WHERE m.user_id = %d",
        $user_id
    ) );
    // Decrypt sensitive contact/address fields that are encrypted at rest
    $member = sp_member_decrypt_row( $member );

    if ( ! $member ) {
        wp_send_json_error( __( 'Member not found.', 'societypress' ) );
    }

    // If the member has opted out of the directory entirely, don't show them
    if ( empty( $member->dir_show_name ) ) {
        wp_send_json_error( __( 'This member has opted out of the directory.', 'societypress' ) );
    }

    // Build display name
    if ( ( $member->member_type ?? 'individual' ) === 'organization' && ! empty( $member->organization_name ) ) {
        $display_name = $member->organization_name;
    } else {
        $display_name = trim(
            ( ($member->preferred_name ?? '') ?: $member->first_name ) . ' ' . $member->last_name
        );
        if ( $member->suffix ) {
            $display_name .= ', ' . $member->suffix;
        }
    }

    // Build the response data, respecting both society-level and member-level privacy.
    // WHY: Two layers of privacy control. The society admin decides which columns
    //      appear at all (settings). Individual members decide whether THEIR data
    //      appears in those columns (dir_show_* fields). Both must agree.
    // WHY: Member status (active/expired/suspended) is admin-only information.
    // Regular members viewing the directory don't need to see others' statuses —
    // it could cause confusion or embarrassment if someone's lapsed status shows.
    $data = [
        'display_name' => $display_name,
        'member_type'  => $member->member_type ?? 'individual',
    ];
    if ( current_user_can( 'manage_options' ) ) {
        $data['status'] = $member->status;
    }

    // Photo — only if the member has enabled it and has one
    if ( ! empty( $member->dir_show_photo ) && ! empty( $member->photo_url ) ) {
        $data['photo_url'] = $member->photo_url;
    }

    // Location — society setting + member preference
    if ( ! empty( $settings['dir_show_city_state'] ) && ! empty( $member->dir_show_address ) ) {
        $location_parts = array_filter( [ $member->city, $member->state ] );
        $data['location'] = implode( ', ', $location_parts );
    }

    // Phone — society setting + member preference
    if ( ! empty( $settings['dir_show_phone'] ) && ! empty( $member->dir_show_phone ) && $member->phone ) {
        $data['phone'] = $member->phone;
    }

    // Email — society setting + member preference
    // WHY obfuscated: The AJAX endpoint returns JSON. Even though it requires
    // authentication, we split and base64-encode the email so it never appears
    // as a plain address in any network response. The frontend JS decodes it.
    if ( ! empty( $settings['dir_show_email'] ) && ! empty( $member->dir_show_email ) && $member->user_email ) {
        $parts = explode( '@', $member->user_email, 2 );
        $data['email_u'] = base64_encode( $parts[0] );
        $data['email_d'] = base64_encode( $parts[1] ?? '' );
    }

    // Website — society setting + member preference
    if ( ! empty( $settings['dir_show_website'] ) && ! empty( $member->dir_show_website ) && $member->website ) {
        $data['website'] = $member->website;
    }

    // Tier — society setting (no member-level toggle for this)
    if ( ! empty( $settings['dir_show_tier'] ) && $member->tier_name ) {
        $data['tier'] = $member->tier_name;
    }

    // Join date — society setting (no member-level toggle)
    if ( ! empty( $settings['dir_show_join_date'] ) && $member->join_date && $member->join_date !== '0000-00-00' ) {
        $data['join_date'] = wp_date( get_option( 'date_format', 'F j, Y' ), strtotime( $member->join_date ) );
    }

    // Interests and skills — always show if they have them (not sensitive data)
    if ( ! empty( $member->interests ) ) {
        $data['interests'] = $member->interests;
    }
    if ( ! empty( $member->skills ) ) {
        $data['skills'] = $member->skills;
    }

    // Surnames being researched
    if ( ! empty( $settings['dir_show_surnames'] ) ) {
        $surnames = $wpdb->get_results( $wpdb->prepare(
            "SELECT surname, county, state, country, year_from, year_to
             FROM {$prefix}member_surnames
             WHERE user_id = %d
             ORDER BY surname",
            $user_id
        ) );
        if ( $surnames ) {
            $data['surnames'] = array_map( function ( $s ) {
                $entry = [ 'surname' => $s->surname ];
                $loc = array_filter( [ $s->county, $s->state, $s->country ] );
                if ( $loc ) {
                    $entry['location'] = implode( ', ', $loc );
                }
                if ( $s->year_from || $s->year_to ) {
                    $entry['years'] = ( $s->year_from ?: '?' ) . '–' . ( $s->year_to ?: 'present' );
                }
                return $entry;
            }, $surnames );
        }
    }

    // Group memberships
    $groups = $wpdb->get_col( $wpdb->prepare(
        "SELECT g.name
         FROM {$prefix}group_members gm
         JOIN {$prefix}groups g ON g.id = gm.group_id
         WHERE gm.user_id = %d AND g.status = 'active'
         ORDER BY g.name",
        $user_id
    ) );
    if ( $groups ) {
        $data['groups'] = $groups;
    }

    // Genealogy service profiles — links to external platforms.
    // WHY: These are public-facing profile links that members chose to share.
    // No privacy toggle needed — if they entered a URL, they want it shown.
    $service_labels = [
        'wikitree'     => 'WikiTree',
        'familysearch' => 'FamilySearch',
        'geni'         => 'Geni',
        'werelate'     => 'WeRelate',
        'ancestry'     => 'Ancestry',
        'myheritage'   => 'MyHeritage',
        'findagrave'   => 'Find A Grave',
        '23andme'      => '23andMe',
    ];
    $gen_links = [];
    foreach ( $service_labels as $key => $label ) {
        $url = get_user_meta( $user_id, 'sp_genealogy_' . $key, true );
        if ( $url ) {
            $gen_links[] = [ 'label' => $label, 'url' => $url ];
        }
    }
    if ( $gen_links ) {
        $data['genealogy_services'] = $gen_links;
    }

    wp_send_json_success( $data );
}


/**
 * Inline JavaScript for the member detail modal.
 *
 * WHY: Handles the click-to-view interaction on directory member names.
 *      Opens a modal overlay, fetches member data via AJAX, and renders
 *      a clean profile card. Follows the same pattern as the library
 *      catalog detail modal.
 *
 * Hooked into wp_head because the directory page is rendered via
 * template_include (not a normal template file), and the directory
 * styles/scripts are output inline in the head.
 */
function sp_directory_detail_script(): void {
    ?>
    <script id="sp-directory-detail-js">
    (function() {
        'use strict';

        var ajaxUrl = '<?php echo esc_js( admin_url( 'admin-ajax.php' ) ); ?>';
        var memberDetailNonce = '<?php echo esc_js( wp_create_nonce( 'sp_member_detail_nonce' ) ); ?>';

        // ---- Create modal overlay (once) ----
        var overlay = document.createElement('div');
        overlay.className = 'sp-member-modal-overlay';
        overlay.style.display = 'none';
        overlay.innerHTML = '<div class="sp-member-modal">'
            + '<button class="sp-member-modal-close" aria-label="Close">&times;</button>'
            + '<div class="sp-member-modal-body"></div>'
            + '</div>';
        document.body.appendChild(overlay);

        var modalBody = overlay.querySelector('.sp-member-modal-body');
        var closeBtn  = overlay.querySelector('.sp-member-modal-close');

        // ---- Close handlers ----
        closeBtn.addEventListener('click', closeModal);
        overlay.addEventListener('click', function(e) {
            if (e.target === overlay) closeModal();
        });
        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape') closeModal();
        });

        function closeModal() {
            overlay.style.display = 'none';
            document.body.style.overflow = '';
        }

        function openModal() {
            overlay.style.display = 'flex';
            document.body.style.overflow = 'hidden';
        }

        // ---- Delegate clicks on member name links ----
        document.addEventListener('click', function(e) {
            var link = e.target.closest('.sp-member-name-link');
            if (!link) return;

            e.preventDefault();
            var userId = link.getAttribute('data-user-id');
            if (!userId) return;

            // Show loading state
            modalBody.innerHTML = '<div class="sp-member-modal-loading">Loading&hellip;</div>';
            openModal();

            // Fetch member detail
            fetch(ajaxUrl + '?action=sp_member_detail&user_id=' + encodeURIComponent(userId) + '&nonce=' + encodeURIComponent(memberDetailNonce), {
                credentials: 'same-origin'
            })
            .then(function(res) { return res.json(); })
            .then(function(json) {
                if (!json.success) {
                    modalBody.innerHTML = '<div class="sp-member-modal-error">'
                        + (json.data || 'Could not load member profile.') + '</div>';
                    return;
                }
                renderMemberDetail(json.data);
            })
            .catch(function() {
                modalBody.innerHTML = '<div class="sp-member-modal-error">'
                    + 'Could not load member profile. Please try again.</div>';
            });
        });


        /**
         * Render the member profile inside the modal.
         */
        function renderMemberDetail(d) {
            var html = '';

            // Header: photo + name + status badge
            html += '<div class="sp-member-detail-header">';
            if (d.photo_url) {
                html += '<img src="' + escHtml(d.photo_url) + '" alt="" class="sp-member-detail-photo">';
            }
            html += '<div class="sp-member-detail-identity">';
            html += '<h2 class="sp-member-detail-name">' + escHtml(d.display_name) + '</h2>';
            if (d.tier) {
                html += '<span class="sp-member-detail-tier">' + escHtml(d.tier) + '</span>';
            }
            if (d.status && d.status !== 'active') {
                html += ' <span class="sp-member-detail-status sp-status-' + escHtml(d.status) + '">'
                    + escHtml(d.status.charAt(0).toUpperCase() + d.status.slice(1)) + '</span>';
            }
            html += '</div></div>';

            // Contact info section
            var hasContact = d.location || d.phone || d.email_u || d.website;
            if (hasContact) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Contact</h3>';
                html += '<dl class="sp-member-detail-list">';
                if (d.location) {
                    html += '<dt>Location</dt><dd>' + escHtml(d.location) + '</dd>';
                }
                if (d.phone) {
                    html += '<dt>Phone</dt><dd><a href="tel:' + escHtml(d.phone.replace(/[^+0-9]/g, ''))
                        + '">' + escHtml(d.phone) + '</a></dd>';
                }
                if (d.email_u) {
                    // Decode the obfuscated halves and build the mailto link.
                    // Same base64 split used by sp_obfuscate_email() on the server.
                    var emlAddr = atob(d.email_u) + '@' + atob(d.email_d || '');
                    html += '<dt>Email</dt><dd><a href="mailto:' + escHtml(emlAddr)
                        + '">' + escHtml(emlAddr) + '</a></dd>';
                }
                if (d.website) {
                    var displayUrl = d.website.replace(/^https?:\/\//, '').replace(/\/$/, '');
                    var fullUrl = d.website.match(/^https?:\/\//) ? d.website : 'https://' + d.website;
                    html += '<dt>Website</dt><dd><a href="' + escHtml(fullUrl)
                        + '" target="_blank" rel="noopener">' + escHtml(displayUrl) + '</a></dd>';
                }
                html += '</dl></div>';
            }

            // Membership info
            if (d.join_date) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Membership</h3>';
                html += '<dl class="sp-member-detail-list">';
                html += '<dt>Member Since</dt><dd>' + escHtml(d.join_date) + '</dd>';
                html += '</dl></div>';
            }

            // Surnames being researched — the big one for genealogy folks
            if (d.surnames && d.surnames.length) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Surnames Being Researched</h3>';
                html += '<div class="sp-member-detail-surnames">';
                for (var i = 0; i < d.surnames.length; i++) {
                    var s = d.surnames[i];
                    html += '<div class="sp-member-detail-surname">';
                    html += '<strong>' + escHtml(s.surname) + '</strong>';
                    var meta = [];
                    if (s.location) meta.push(s.location);
                    if (s.years) meta.push(s.years);
                    if (meta.length) {
                        html += ' <span class="sp-surname-meta">(' + escHtml(meta.join(', ')) + ')</span>';
                    }
                    html += '</div>';
                }
                html += '</div></div>';
            }

            // Groups / committees
            if (d.groups && d.groups.length) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Groups</h3>';
                html += '<div class="sp-member-detail-groups">';
                for (var g = 0; g < d.groups.length; g++) {
                    html += '<span class="sp-group-tag">' + escHtml(d.groups[g]) + '</span>';
                }
                html += '</div></div>';
            }

            // Interests
            if (d.interests) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Interests</h3>';
                html += '<p class="sp-member-detail-text">' + escHtml(d.interests) + '</p>';
                html += '</div>';
            }

            // Skills
            if (d.skills) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Skills</h3>';
                html += '<p class="sp-member-detail-text">' + escHtml(d.skills) + '</p>';
                html += '</div>';
            }

            // Genealogy service profiles — external platform links
            if (d.genealogy_services && d.genealogy_services.length) {
                html += '<div class="sp-member-detail-section">';
                html += '<h3 class="sp-member-detail-section-title">Genealogy Profiles</h3>';
                html += '<div class="sp-member-detail-gen-links">';
                for (var gs = 0; gs < d.genealogy_services.length; gs++) {
                    var svc = d.genealogy_services[gs];
                    html += '<a href="' + escHtml(svc.url) + '" target="_blank" rel="noopener noreferrer" class="sp-gen-link">'
                          + escHtml(svc.label) + '</a>';
                }
                html += '</div></div>';
            }

            modalBody.innerHTML = html;
        }


        /**
         * Simple HTML escaping — prevents XSS from member-entered data.
         */
        function escHtml(str) {
            if (!str) return '';
            var div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }
    })();
    </script>
    <?php
}


/**
 * CSS for the member detail modal.
 *
 * WHY: Separate from the directory table styles for clarity. This styles
 *      the overlay, modal card, and all the profile sections inside it.
 */
function sp_directory_detail_styles(): void {
    ?>
    <style id="sp-directory-detail-css">
        /* ---- Modal overlay ---- */
        .sp-member-modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            z-index: 999999;
            background: rgba(0, 0, 0, 0.5);
            display: flex;
            align-items: center;
            justify-content: center;
            padding: 20px;
        }

        /* ---- Modal card ---- */
        .sp-member-modal {
            position: relative;
            background: #fff;
            border-radius: 12px;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
            max-width: 560px;
            width: 100%;
            max-height: 85vh;
            overflow-y: auto;
            padding: 32px;
        }

        /* ---- Close button ---- */
        .sp-member-modal-close {
            position: absolute;
            top: 12px;
            right: 16px;
            background: none;
            border: none;
            font-size: 28px;
            line-height: 1;
            color: #999;
            cursor: pointer;
            padding: 4px 8px;
            border-radius: 4px;
            transition: color 0.15s, background-color 0.15s;
        }
        .sp-member-modal-close:hover {
            color: #333;
            background: #f0f0f0;
        }

        /* ---- Loading / error states ---- */
        .sp-member-modal-loading,
        .sp-member-modal-error {
            text-align: center;
            padding: 40px 20px;
            font-size: 16px;
            color: #666;
        }
        .sp-member-modal-error {
            color: #d63638;
        }

        /* ---- Header: photo + name ---- */
        .sp-member-detail-header {
            display: flex;
            align-items: center;
            gap: 16px;
            margin-bottom: 24px;
            padding-bottom: 20px;
            border-bottom: 1px solid #eee;
        }
        .sp-member-detail-photo {
            width: 72px;
            height: 72px;
            border-radius: 50%;
            object-fit: cover;
            flex-shrink: 0;
        }
        .sp-member-detail-identity {
            flex: 1;
            min-width: 0;
        }
        .sp-member-detail-name {
            font-size: 22px;
            font-weight: 700;
            margin: 0 0 4px 0;
            color: #1a1a1a;
            line-height: 1.2;
        }
        .sp-member-detail-tier {
            display: inline-block;
            padding: 2px 10px;
            font-size: 12px;
            font-weight: 600;
            color: var(--sp-color-primary, #0D1F3C);
            background: rgba(13, 31, 60, 0.08);
            border-radius: 12px;
        }
        .sp-member-detail-status {
            display: inline-block;
            padding: 2px 10px;
            font-size: 12px;
            font-weight: 600;
            border-radius: 12px;
            margin-left: 4px;
        }
        .sp-status-inactive {
            color: #8b5e0b;
            background: #fef3cd;
        }

        /* ---- Sections ---- */
        .sp-member-detail-section {
            margin-bottom: 20px;
        }
        .sp-member-detail-section-title {
            font-size: 13px;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            color: #888;
            margin: 0 0 8px 0;
        }

        /* ---- Definition list for contact/membership info ---- */
        .sp-member-detail-list {
            margin: 0;
            display: grid;
            grid-template-columns: auto 1fr;
            gap: 6px 16px;
            font-size: 15px;
        }
        .sp-member-detail-list dt {
            font-weight: 600;
            color: #555;
            white-space: nowrap;
        }
        .sp-member-detail-list dd {
            margin: 0;
            color: #333;
            word-break: break-word;
        }
        .sp-member-detail-list a {
            color: var(--sp-color-primary, #0D1F3C);
            text-decoration: none;
        }
        .sp-member-detail-list a:hover {
            text-decoration: underline;
        }

        /* ---- Surnames ---- */
        .sp-member-detail-surnames {
            display: flex;
            flex-direction: column;
            gap: 6px;
        }
        .sp-member-detail-surname {
            font-size: 15px;
            color: #333;
            line-height: 1.5;
        }
        .sp-surname-meta {
            color: #888;
            font-size: 13px;
        }

        /* ---- Groups (reuses the tag style from the directory) ---- */
        .sp-member-detail-groups {
            display: flex;
            flex-wrap: wrap;
            gap: 6px;
        }

        /* ---- Text blocks (interests, skills) ---- */
        .sp-member-detail-text {
            font-size: 15px;
            color: #333;
            line-height: 1.6;
            margin: 0;
        }

        /* ---- Genealogy service profile links ---- */
        .sp-member-detail-gen-links {
            display: flex;
            flex-wrap: wrap;
            gap: 8px;
        }
        .sp-gen-link {
            display: inline-block;
            padding: 4px 12px;
            font-size: 13px;
            background: var(--sp-color-primary, #0D1F3C);
            color: #fff !important;
            border-radius: 4px;
            text-decoration: none;
            transition: opacity 0.15s;
        }
        .sp-gen-link:hover {
            opacity: 0.85;
            text-decoration: none !important;
        }

        /* ---- Clickable member name in the directory ---- */
        .sp-member-name-link {
            color: var(--sp-color-primary, #0D1F3C);
            text-decoration: none;
            cursor: pointer;
        }
        .sp-member-name-link:hover {
            text-decoration: underline;
        }

        /* ---- Mobile responsive ---- */
        @media screen and (max-width: 768px) {
            .sp-member-modal {
                padding: 20px;
                max-height: 90vh;
                border-radius: 8px;
            }
            .sp-member-detail-header {
                flex-direction: column;
                text-align: center;
            }
            .sp-member-detail-list {
                grid-template-columns: 1fr;
                gap: 4px;
            }
            .sp-member-detail-list dt {
                margin-top: 8px;
            }
        }
    </style>
    <?php
}


// PAGE BUILDER — ADMIN META BOX + FRONTEND RENDERING
// ============================================================================
//
// WHY: The society admin needs to build pages by arranging pre-built widgets
//      without ever touching the WordPress block editor. Gutenberg is too
//      complex for octogenarians. This gives them a dead-simple interface:
//      pick a widget, configure it, arrange with up/down arrows, hit Save.
//
// HOW IT WORKS:
//      1. theme_page_templates filter — adds "SocietyPress Builder" to the
//         template dropdown in the Page editor
//      2. add_meta_boxes — shows the builder meta box on pages using that
//         template (Gutenberg is disabled, classic editor is hidden)
//      3. save_post_page — saves widget configuration to post meta
//      4. template_include — on the frontend, renders widgets in order
//
// DATA STORAGE:
//      Widget config stored as page post_meta (_sp_page_widgets):
//      [
//          [ 'type' => 'rich_text', 'settings' => [ 'content' => '...' ] ],
//          [ 'type' => 'heading',   'settings' => [ 'text' => '...' ] ],
//      ]
//
// WIDGET TYPES:
//      Content:  rich_text, member_directory, surname_lookup, membership_tiers
//      Info:     contact_card, member_stats, heading, image
//      Actions:  button, contact_form
// ============================================================================


/**
 * Widget registry — defines all available widget types.
 *
 * WHY: Centralized so both the admin picker and the frontend renderer
 * reference the same list. Adding a new widget type means adding one
 * entry here plus a settings renderer and a frontend renderer.
 *
 * @return array Registry of widget types.
 */
function sp_get_widget_registry(): array {
    return [
        // --- Content ---
        'rich_text' => [
