// ============================================================================
// PAGE BUILDER — TEMPLATE REGISTRATION
// ============================================================================

/**
 * Register the "SocietyPress Builder" page template.
 *
 * WHY: Same approach as the Membership Directory — a plugin-provided template
 * that shows up in the Template dropdown without needing a theme file.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-builder'] = 'SocietyPress Builder';
    return $templates;
});


// ============================================================================
// PAGE BUILDER — DISABLE GUTENBERG FOR BUILDER PAGES
// ============================================================================

/**
 * Disable the Gutenberg block editor for pages using the builder template.
 *
 * WHY: The builder replaces the editor entirely. Showing both would confuse
 * Harold — two ways to edit content, neither knows about the other.
 */
add_filter( 'use_block_editor_for_post', function ( $use, $post ) {
    if ( $post && 'page' === $post->post_type ) {
        if ( get_page_template_slug( $post->ID ) === 'sp-builder' ) {
            return false;
        }
    }
    return $use;
}, 10, 2 );


// ============================================================================
// PAGE BUILDER — HIDE CLASSIC EDITOR FOR BUILDER PAGES
// ============================================================================

/**
 * Hide the classic editor content area when Gutenberg is off.
 *
 * WHY: When Gutenberg is disabled, WordPress falls back to the classic editor.
 * We don't want that either — the builder meta box IS the editor.
 */
add_action( 'admin_head', function () {
    global $post;
    if ( ! $post || 'page' !== $post->post_type ) {
        return;
    }
    if ( get_page_template_slug( $post->ID ) === 'sp-builder' ) {
        echo '<style>#postdivrich, #post-body-content > #titlediv + .inside { display: none !important; }</style>';
    }
});


// ============================================================================
// PAGE BUILDER — ADMIN META BOX
// ============================================================================

/**
 * Register the Page Builder meta box on page edit screens.
 */
add_action( 'add_meta_boxes', function () {
    $screen = get_current_screen();
    if ( ! $screen || 'page' !== $screen->post_type ) {
        return;
    }
    add_meta_box(
        'sp_page_builder',
        'SocietyPress Page Builder',
        'sp_render_builder_meta_box',
        'page',
        'normal',
        'high'
    );
});


/**
 * Render the Page Builder meta box.
 *
 * WHY: Shows a list of currently-added widgets (collapsible cards with settings),
 * and an "Add Widget" button that opens a picker overlay.
 *
 * @param WP_Post $post The page being edited.
 */
function sp_render_builder_meta_box( WP_Post $post ): void {
    $template   = get_page_template_slug( $post->ID );
    $is_builder = ( 'sp-builder' === $template );

    wp_nonce_field( 'sp_page_builder_save', 'sp_page_builder_nonce' );

    if ( ! $is_builder ) {
        echo '<div style="padding: 10px; background: #f0f6fc; border-left: 4px solid #2271b1; border-radius: 2px;">';
        echo '<p class="sp-m-0">To use the Page Builder, select the <strong>"SocietyPress Builder"</strong> template from the Page Attributes panel on the right, then update the page.</p>';
        echo '</div>';
        return;
    }

    // WHY: The builder UI is shared between the native WP meta box and the
    // custom SocietyPress page editor. Extracted into sp_render_builder_ui()
    // so both screens get identical markup without duplicating ~100 lines.
    sp_render_builder_ui( $post );
}


/**
 * Render the Page Builder widget list, picker, and templates.
 *
 * WHY: This is the shared "guts" of the builder UI. Called from the native
 * WordPress meta box (sp_render_builder_meta_box) AND from the custom
 * SocietyPress page editor (sp_render_page_edit). Keeping it in one place
 * means every builder screen stays in sync — no divergence risk.
 *
 * @param WP_Post $post The page being edited.
 */
function sp_render_builder_ui( WP_Post $post ): void {
    $widgets  = get_post_meta( $post->ID, '_sp_page_widgets', true );
    $registry = sp_get_widget_registry();
    if ( ! is_array( $widgets ) ) {
        $widgets = [];
    }

    ?>
    <div id="sp-builder-wrap">

        <!-- Current widgets -->
        <div id="sp-builder-widgets" class="sp-builder-widgets">
            <?php
            foreach ( $widgets as $index => $widget ) {
                sp_render_builder_card( $index, $widget, $registry );
            }
            ?>
        </div>

        <!-- Add Widget button -->
        <div style="margin-top: 15px; text-align: center;">
            <button type="button" id="sp-builder-add-btn" class="button button-primary button-large">
                <span class="dashicons dashicons-plus-alt2" class="sp-mt-4"></span>
                Add Widget
            </button>
        </div>

        <!-- Widget picker overlay -->
        <div id="sp-builder-picker" class="sp-builder-picker" style="display: none;">
            <div class="sp-builder-picker-inner">
                <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;">
                    <h3 style="margin:0; font-size: 18px;">Choose a Widget</h3>
                    <button type="button" class="sp-builder-picker-close" style="background:none; border:none; font-size:24px; cursor:pointer; color:#50575e;">&times;</button>
                </div>

                <?php
                $categories = [
                    'content' => 'Content',
                    'info'    => 'Information',
                    'action'  => 'Actions',
                ];
                foreach ( $categories as $cat_slug => $cat_label ) :
                    $cat_widgets = array_filter( $registry, function ( $w ) use ( $cat_slug ) {
                        return $w['category'] === $cat_slug;
                    } );
                    if ( empty( $cat_widgets ) ) continue;
                    ?>
                    <div class="sp-builder-picker-category">
                        <h4 style="font-size:13px; text-transform:uppercase; letter-spacing:0.05em; color:#646970; margin:0 0 10px; border-bottom:1px solid #dcdcde; padding-bottom:6px;"><?php echo esc_html( $cat_label ); ?></h4>
                        <div class="sp-builder-picker-grid">
                            <?php foreach ( $cat_widgets as $type => $w ) : ?>
                                <button type="button" class="sp-builder-picker-item" data-widget-type="<?php echo esc_attr( $type ); ?>">
                                    <span class="dashicons dashicons-<?php echo esc_attr( $w['icon'] ); ?>" style="color:#2271b1; margin-bottom:6px;"></span>
                                    <strong class="sp-field-label" class="sp-fw-normal"><?php echo esc_html( $w['label'] ); ?></strong>
                                    <span style="font-size:12px; color:#646970; line-height:1.4;"><?php echo esc_html( $w['description'] ); ?></span>
                                </button>
                            <?php endforeach; ?>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        </div>

        <!-- Hidden templates for JS cloning -->
        <div id="sp-builder-templates" style="display: none;">
            <?php
            foreach ( $registry as $type => $info ) {
                echo '<div class="sp-builder-template" data-widget-type="' . esc_attr( $type ) . '">';
                sp_render_builder_card( '__INDEX__', [ 'type' => $type, 'settings' => [] ], $registry );
                echo '</div>';
            }
            ?>
        </div>

    </div>
    <?php
}


/**
 * Render a single widget card in the builder.
 *
 * @param int|string $index    Position index (or '__INDEX__' for templates).
 * @param array      $widget   Widget data: [ 'type' => string, 'settings' => array ].
 * @param array      $registry The widget registry.
 */
function sp_render_builder_card( $index, array $widget, array $registry ): void {
    $type     = $widget['type'] ?? '';
    $settings = $widget['settings'] ?? [];
    $info     = $registry[ $type ] ?? null;

    if ( ! $info ) return;

    ?>
    <div class="sp-builder-card" data-widget-type="<?php echo esc_attr( $type ); ?>">
        <div class="sp-builder-card-header">
            <span class="dashicons dashicons-<?php echo esc_attr( $info['icon'] ); ?>" style="color:#2271b1; flex-shrink:0;"></span>
            <span class="sp-builder-card-title" style="font-weight:600; flex-grow:1;"><?php echo esc_html( $info['label'] ); ?></span>
            <div class="sp-builder-card-actions" style="display:flex; gap:4px; flex-shrink:0;">
                <button type="button" class="sp-builder-btn sp-builder-move-up" title="Move up">&#9650;</button>
                <button type="button" class="sp-builder-btn sp-builder-move-down" title="Move down">&#9660;</button>
                <button type="button" class="sp-builder-btn sp-builder-toggle" title="Edit">&#9998;</button>
                <button type="button" class="sp-builder-btn sp-builder-remove" title="Remove">&times;</button>
            </div>
        </div>

        <div class="sp-builder-card-body" style="display: none;">
            <input type="hidden" name="sp_widgets[<?php echo esc_attr( $index ); ?>][type]" value="<?php echo esc_attr( $type ); ?>">

            <!-- Section heading — available on every widget -->
            <div style="margin-bottom:12px; padding-bottom:12px; border-bottom:1px solid #e0e0e0;">
                <label class="sp-field-label"><?php esc_html_e( 'Section Heading (optional)', 'societypress' ); ?></label>
                <input type="text" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][section_heading]"
                       value="<?php echo esc_attr( $settings['section_heading'] ?? '' ); ?>"
                       class="widefat" placeholder="<?php esc_attr_e( 'e.g., Classes & Events', 'societypress' ); ?>">
                <p class="description" style="margin-top:4px;"><?php esc_html_e( 'Adds a centered heading with a decorative divider above this widget.', 'societypress' ); ?></p>
            </div>

            <?php
            $fn = 'sp_builder_fields_' . $type;
            if ( function_exists( $fn ) ) {
                $fn( $index, $settings );
            }
            ?>
        </div>
    </div>
    <?php
}


// ============================================================================
// PAGE BUILDER — WIDGET SETTINGS FIELD RENDERERS
// ============================================================================

/**
 * Rich Text widget settings.
 */
function sp_builder_fields_rich_text( $index, array $settings ): void {
    $content   = $settings['content'] ?? '';
    $editor_id = 'sp_widget_editor_' . $index;
    $name      = "sp_widgets[{$index}][settings][content]";

    echo '<div class="sp-builder-field">';
    echo '<label class="sp-field-label">' . esc_html__( 'Content', 'societypress' ) . '</label>';

    if ( is_numeric( $index ) ) {
        wp_editor( $content, $editor_id, [
            'textarea_name' => $name,
            'textarea_rows' => 10,
            'media_buttons' => true,
            'teeny'         => false,
            'quicktags'     => true,
        ] );
    } else {
        printf(
            '<textarea name="%s" id="%s" class="sp-builder-wysiwyg" rows="10" style="width:100%%;">%s</textarea>',
            esc_attr( $name ),
            esc_attr( $editor_id ),
            esc_textarea( $content )
        );
    }

    echo '</div>';
}

