            <option value="albums" <?php selected( $display_mode, 'albums' ); ?>><?php esc_html_e( 'All folders (grid of thumbnails)', 'societypress' ); ?></option>
            <option value="single" <?php selected( $display_mode, 'single' ); ?>><?php esc_html_e( 'Single folder (all media)', 'societypress' ); ?></option>
        </select>
    </div>
    <div class="sp-builder-field">
        <label class="sp-field-label"><?php esc_html_e( 'Folder (for single mode)', 'societypress' ); ?></label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][album_id]">
            <option value=""><?php esc_html_e( '— Select a folder —', 'societypress' ); ?></option>
            <?php foreach ( $folders as $f ) : ?>
                <option value="<?php echo esc_attr( $f->id ); ?>" <?php selected( $album_id, $f->id ); ?>><?php echo esc_html( $f->title ); ?></option>
            <?php endforeach; ?>
        </select>
    </div>
    <div class="sp-builder-field" class="sp-flex-gap-15">
        <div class="sp-flex-1">
            <label class="sp-field-label"><?php esc_html_e( 'Columns', 'societypress' ); ?></label>
            <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][columns]" class="sp-full-width">
                <?php foreach ( [ 2, 3, 4, 5 ] as $c ) : ?>
                    <option value="<?php echo $c; ?>" <?php selected( $columns, $c ); ?>><?php echo $c; ?></option>
                <?php endforeach; ?>
            </select>
        </div>
        <div class="sp-flex-1">
            <label class="sp-field-label"><?php esc_html_e( 'Max items', 'societypress' ); ?></label>
            <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][count]" class="sp-full-width">
                <?php foreach ( [ 6, 12, 24, 48 ] as $c ) : ?>
                    <option value="<?php echo $c; ?>" <?php selected( $count, $c ); ?>><?php echo $c; ?></option>
                <?php endforeach; ?>
            </select>
        </div>
    </div>
    <div class="sp-builder-field">
        <label><input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][login_required]" value="1" <?php checked( $login_required ); ?>> <?php esc_html_e( 'Require login to view', 'societypress' ); ?></label>
