function sp_builder_fields_library_catalog( $index, array $settings ): void {
    global $wpdb;
    $show_search    = $settings['show_search'] ?? true;
    $show_landing   = $settings['show_landing'] ?? true;
    $category_id    = $settings['category_id'] ?? '';
    $available_only = $settings['available_only'] ?? false;
    $count          = $settings['count'] ?? 25;
    $login_required = $settings['login_required'] ?? false;

    $categories = $wpdb->get_results(
        "SELECT id, name FROM {$wpdb->prefix}sp_library_categories WHERE active = 1 ORDER BY sort_order, name"
    );
    ?>
    <div class="sp-builder-field">
        <p class="description"><?php esc_html_e( 'Displays a searchable, browsable library catalog with collection stats, tabbed search, browse-by-type cards, popular subjects, and a paginated results table with expandable detail rows.', 'societypress' ); ?></p>
        <label class="sp-field-label"><?php esc_html_e( 'Filter by category', 'societypress' ); ?></label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][category_id]">
            <option value=""><?php esc_html_e( 'All Categories', 'societypress' ); ?></option>
            <?php foreach ( $categories as $cat ) : ?>
                <option value="<?php echo esc_attr( $cat->id ); ?>" <?php selected( $category_id, $cat->id ); ?>><?php echo esc_html( $cat->name ); ?></option>
            <?php endforeach; ?>
        </select>
    </div>
    <div class="sp-builder-field">
        <label class="sp-field-label"><?php esc_html_e( 'Items per page', 'societypress' ); ?></label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][count]">
            <?php foreach ( [ 10, 25, 50, 100 ] as $opt ) : ?>
                <option value="<?php echo $opt; ?>" <?php selected( $count, $opt ); ?>><?php echo $opt; ?></option>
            <?php endforeach; ?>
        </select>
    </div>
    <div class="sp-builder-field">
        <label><input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_landing]" value="1" <?php checked( $show_landing ); ?>> <?php esc_html_e( 'Show landing page (stats, browse by type, popular subjects)', 'societypress' ); ?></label><br>
        <label><input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][show_search]" value="1" <?php checked( $show_search ); ?>> <?php esc_html_e( 'Show search box', 'societypress' ); ?></label><br>
        <label><input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][available_only]" value="1" <?php checked( $available_only ); ?>> <?php esc_html_e( 'Show available items only', 'societypress' ); ?></label><br>
        <label><input type="checkbox" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][login_required]" value="1" <?php checked( $login_required ); ?>> <?php esc_html_e( 'Require login to view', 'societypress' ); ?></label>
    </div>
    <?php
}

/**
 * Settings fields: Hero Slider
 *
 * WHY: The admin needs to configure multiple slides — each with an image,
 *      heading, subtitle, and optional button. We use a repeater pattern
 *      (same as time slots and speaker rows) with a <template> for adding
 *      new slides via JS.
 */
function sp_builder_fields_hero_slider( $index, array $settings ): void {
    $slides    = $settings['slides'] ?? [];
    $autoplay  = $settings['autoplay'] ?? 1;
    $interval  = $settings['interval'] ?? 5;
    $height    = $settings['height'] ?? '400';
    $overlay   = $settings['overlay'] ?? 1;
    $name      = "sp_widgets[{$index}][settings]";
    ?>
    <?php
    // WHY: All layout/sizing/color rules that were previously written as
    // inline style= attributes are collected here in a single <style> block.
    // This keeps the HTML markup clean, lets browser DevTools show class names
    // instead of per-element style declarations, and makes future tweaks a
    // single-location edit rather than a hunt through every tag.
    // Classes are prefixed sp-hero-fields- to avoid collisions with any other
    // admin styles loaded on the page builder screen.
    ?>
    <style>
        /* ----------------------------------------------------------------
         * sp-hero-fields-* — admin field panel styles for the hero slider
         * widget. These rules only apply inside .sp-slider-settings panels
         * rendered by sp_builder_fields_hero_slider().
         * ---------------------------------------------------------------- */

        /* Height input */
        .sp-hero-fields-input-height     { width: 100px; }

        /* Interval (seconds) input */
        .sp-hero-fields-input-interval   { width: 60px; }

        /* "Slides" section heading */
        .sp-hero-fields-slides-heading   { margin: 16px 0 8px; }

        /* Individual slide card (used in both live rows and the <template>) */
        .sp-hero-fields-slide-card       {
            border: 1px solid #c3c4c7;
            padding: 12px;
            margin-bottom: 8px;
            border-radius: 4px;
            background: #fafafa;
        }

        /* Full-width text inputs (image URL, template image URL) */
        .sp-hero-fields-input-full       { width: 100%; }

        /* "Choose Image" button top gap */
        .sp-hero-fields-btn-media        { margin-top: 4px; }

        /* Overlay Text Lines wrapper div */
        .sp-hero-fields-lines-wrap       { margin-bottom: 12px; }

        /* Individual text-line row (flex row of inputs + selects + remove btn) */
        .sp-hero-fields-line-row         {
            display: flex;
            gap: 6px;
            align-items: center;
            margin-bottom: 6px;
            flex-wrap: wrap;
        }

        /* Line text input (flex-grow) */
        .sp-hero-fields-input-line-text  { flex: 1; min-width: 180px; }

        /* Size select */
        .sp-hero-fields-select-size      { width: 90px; }

        /* Weight select */
        .sp-hero-fields-select-weight    { width: 80px; }

        /* Color select */
        .sp-hero-fields-select-color     { width: 85px; }

        /* Danger-colored buttons (Remove Slide, Remove Line) */
        .sp-hero-fields-btn-danger       { color: #b32d2e; }

        /* "Add Line" button top gap */
        .sp-hero-fields-btn-add-line     { margin-top: 4px; }

        /* Button + URL pair inputs (half-width, inline) */
        .sp-hero-fields-input-half       { width: 48%; display: inline-block; }
    </style>

    <div class="sp-slider-settings">
        <p>
            <label><strong>Slider Height (px)</strong></label><br>
            <input type="number" name="<?php echo $name; ?>[height]" value="<?php echo esc_attr( $height ); ?>" min="200" max="800" step="50" class="sp-hero-fields-input-height">
        </p>
        <p>
            <label>
                <input type="checkbox" name="<?php echo $name; ?>[autoplay]" value="1" <?php checked( $autoplay, 1 ); ?>>
                Auto-advance slides
            </label>
            &nbsp; every
            <input type="number" name="<?php echo $name; ?>[interval]" value="<?php echo esc_attr( $interval ); ?>" min="2" max="15" class="sp-hero-fields-input-interval"> seconds
        </p>
        <p>
            <label>
                <input type="checkbox" name="<?php echo $name; ?>[overlay]" value="1" <?php checked( $overlay, 1 ); ?>>
                Dark overlay on images (improves text readability)
            </label>
        </p>

        <h4 class="sp-hero-fields-slides-heading">Slides</h4>
        <div class="sp-slider-slides" data-name="<?php echo esc_attr( $name ); ?>">
            <?php if ( ! empty( $slides ) ) : ?>
                <?php foreach ( $slides as $si => $slide ) : ?>
                    <div class="sp-slider-slide-row sp-hero-fields-slide-card">
                        <p>
                            <label><strong>Image or Video URL</strong></label><br>
                            <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][image]"
                                   value="<?php echo esc_attr( $slide['image'] ?? '' ); ?>" class="sp-hero-fields-input-full"
                                   placeholder="Paste image URL or use Media Library">
                            <button type="button" class="button sp-media-select sp-hero-fields-btn-media">Choose Image</button>
                        </p>
                        <!-- WHY: Per-line repeater replaces the old single textarea so each
                             line of overlay text can have its own size, weight, and color.
                             This lets Harold style slides differently — white text on dark
                             video, dark text on light images, accent-colored emphasis, etc. -->
                        <div class="sp-hero-fields-lines-wrap">
                            <label><strong>Overlay Text Lines</strong></label>
                            <div class="sp-slider-lines" data-name="<?php echo esc_attr( $name ); ?>[slides][<?php echo $si; ?>]">
                                <?php
                                $lines = $slide['lines'] ?? [];
                                if ( ! empty( $lines ) && is_array( $lines ) ) :
                                    foreach ( $lines as $li => $line ) :
                                ?>
                                    <div class="sp-slider-line-row sp-hero-fields-line-row">
                                        <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][text]"
                                               value="<?php echo esc_attr( $line['text'] ?? '' ); ?>" class="sp-hero-fields-input-line-text" placeholder="Line text">
                                        <select name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][size]" class="sp-hero-fields-select-size">
                                            <option value="small" <?php selected( $line['size'] ?? 'medium', 'small' ); ?>>Small</option>
                                            <option value="medium" <?php selected( $line['size'] ?? 'medium', 'medium' ); ?>><?php esc_html_e( 'Medium', 'societypress' ); ?></option>
                                            <option value="large" <?php selected( $line['size'] ?? 'medium', 'large' ); ?>><?php esc_html_e( 'Large', 'societypress' ); ?></option>
                                        </select>
                                        <select name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][weight]" class="sp-hero-fields-select-weight">
                                            <option value="light" <?php selected( $line['weight'] ?? 'light', 'light' ); ?>>Light</option>
                                            <option value="bold" <?php selected( $line['weight'] ?? 'light', 'bold' ); ?>>Bold</option>
                                        </select>
                                        <select name="<?php echo $name; ?>[slides][<?php echo $si; ?>][lines][<?php echo $li; ?>][color]" class="sp-hero-fields-select-color">
                                            <option value="white" <?php selected( $line['color'] ?? 'white', 'white' ); ?>>White</option>
                                            <option value="dark" <?php selected( $line['color'] ?? 'white', 'dark' ); ?>>Dark</option>
                                            <option value="accent" <?php selected( $line['color'] ?? 'white', 'accent' ); ?>>Accent</option>
                                        </select>
                                        <button type="button" class="button sp-slider-remove-line sp-hero-fields-btn-danger" title="Remove line">&times;</button>
                                    </div>
                                <?php
                                    endforeach;
                                endif;
                                ?>
                            </div>
                            <button type="button" class="button sp-slider-add-line sp-hero-fields-btn-add-line">+ Add Line</button>
                        </div>
                        <p>
                            <label><strong>Button Text</strong></label><br>
                            <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][btn_text]"
                                   value="<?php echo esc_attr( $slide['btn_text'] ?? '' ); ?>" class="sp-hero-fields-input-half" placeholder="e.g., Learn More">
                            <input type="text" name="<?php echo $name; ?>[slides][<?php echo $si; ?>][btn_url]"
                                   value="<?php echo esc_attr( $slide['btn_url'] ?? '' ); ?>" class="sp-hero-fields-input-half" placeholder="Button URL">
                        </p>
                        <button type="button" class="button sp-slider-remove-slide sp-hero-fields-btn-danger">Remove Slide</button>
                    </div>
                <?php endforeach; ?>
            <?php endif; ?>
        </div>
        <button type="button" class="button sp-slider-add-slide">+ Add Slide</button>

        <template class="sp-slider-slide-template">
            <div class="sp-slider-slide-row sp-hero-fields-slide-card">
                <p>
                    <label><strong>Image or Video URL</strong></label><br>
                    <input type="text" data-field="image" value="" class="sp-hero-fields-input-full" placeholder="Paste image URL or use Media Library">
                    <button type="button" class="button sp-media-select sp-hero-fields-btn-media">Choose Image</button>
                </p>
                <!-- WHY: Lines repeater in the template starts empty — Harold adds
                     lines after creating the slide. The data-field-group attribute
                     tells the JS to set name prefixes on child inputs when cloning. -->
                <div class="sp-hero-fields-lines-wrap">
                    <label><strong>Overlay Text Lines</strong></label>
                    <div class="sp-slider-lines" data-field-group="lines">
                        <!-- Lines added dynamically via Add Line button -->
                    </div>
                    <button type="button" class="button sp-slider-add-line sp-hero-fields-btn-add-line">+ Add Line</button>
                </div>
                <p>
                    <label><strong>Button Text</strong></label><br>
                    <input type="text" data-field="btn_text" value="" class="sp-hero-fields-input-half" placeholder="e.g., Learn More">
                    <input type="text" data-field="btn_url" value="" class="sp-hero-fields-input-half" placeholder="Button URL">
                </p>
                <button type="button" class="button sp-slider-remove-slide sp-hero-fields-btn-danger">Remove Slide</button>
            </div>
        </template>

        <!-- WHY: Separate template for individual text lines within a slide.
             Used by both "Add Line" inside existing slides and "Add Line"
             inside newly-added slides. Kept outside the slide template so
             the browser doesn't nest <template> tags (some browsers choke). -->
        <template class="sp-slider-line-template">
            <div class="sp-slider-line-row sp-hero-fields-line-row">
                <input type="text" data-line-field="text" value="" class="sp-hero-fields-input-line-text" placeholder="Line text">
                <select data-line-field="size" class="sp-hero-fields-select-size">
                    <option value="small">Small</option>
                    <option value="medium" selected>Medium</option>
                    <option value="large">Large</option>
                </select>
                <select data-line-field="weight" class="sp-hero-fields-select-weight">
                    <option value="light" selected>Light</option>
                    <option value="bold">Bold</option>
                </select>
                <select data-line-field="color" class="sp-hero-fields-select-color">
                    <option value="white" selected>White</option>
                    <option value="dark">Dark</option>
                    <option value="accent">Accent</option>
                </select>
                <button type="button" class="button sp-slider-remove-line sp-hero-fields-btn-danger" title="Remove line">&times;</button>
            </div>
        </template>

        <script>
        (function() {
            // WHY: All click handlers use event delegation on document so they
            // work on hero_slider widgets added dynamically via the builder's
            // "Add Widget" picker, and on lines/slides added after page load.

            // Add slide — delegated
            document.addEventListener('click', function(e) {
                if (!e.target.classList.contains('sp-slider-add-slide')) return;
                var wrapper   = e.target.closest('.sp-slider-settings');
                if (!wrapper) return;
                var container = wrapper.querySelector('.sp-slider-slides');
                var tpl       = wrapper.querySelector('.sp-slider-slide-template');
                if (!container || !tpl) return;
                var clone    = tpl.content.cloneNode(true);
                var baseName = container.getAttribute('data-name');
                var idx      = container.querySelectorAll('.sp-slider-slide-row').length;
                // WHY: Only set names on direct slide-level fields (image, btn_text, btn_url).
                // Lines inside the slide get their names set by the Add Line handler.
                clone.querySelectorAll('[data-field]').forEach(function(input) {
                    var field = input.getAttribute('data-field');
                    input.setAttribute('name', baseName + '[slides][' + idx + '][' + field + ']');
                    input.removeAttribute('data-field');
                });
                // WHY: The lines container inside a new slide needs its data-name
                // set so Add Line knows what name prefix to use for line inputs.
                var linesDiv = clone.querySelector('[data-field-group="lines"]');
                if (linesDiv) {
                    linesDiv.setAttribute('data-name', baseName + '[slides][' + idx + ']');
                    linesDiv.removeAttribute('data-field-group');
                }
                container.appendChild(clone);
            });

            // Remove slide — delegated
            document.addEventListener('click', function(e) {
                if (e.target.classList.contains('sp-slider-remove-slide')) {
                    e.target.closest('.sp-slider-slide-row').remove();
                }
            });

            // Add line — delegated
            // WHY: Finds the lines container relative to the clicked button,
            // clones the line template, and assigns name attributes based on
            // the container's data-name and the current line count.
            document.addEventListener('click', function(e) {
                if (!e.target.classList.contains('sp-slider-add-line')) return;
                var wrapper    = e.target.closest('.sp-slider-settings');
                var linesDiv   = e.target.previousElementSibling;
                if (!linesDiv || !linesDiv.classList.contains('sp-slider-lines')) {
                    // WHY: fallback — button might be a sibling of the container
                    linesDiv = e.target.parentElement.querySelector('.sp-slider-lines');
                }
                if (!wrapper || !linesDiv) return;
                var lineTpl = wrapper.querySelector('.sp-slider-line-template');
                if (!lineTpl) return;
                var clone    = lineTpl.content.cloneNode(true);
                var baseName = linesDiv.getAttribute('data-name');
                var lineIdx  = linesDiv.querySelectorAll('.sp-slider-line-row').length;
                clone.querySelectorAll('[data-line-field]').forEach(function(input) {
                    var field = input.getAttribute('data-line-field');
                    input.setAttribute('name', baseName + '[lines][' + lineIdx + '][' + field + ']');
                    input.removeAttribute('data-line-field');
                });
                linesDiv.appendChild(clone);
            });

            // Remove line — delegated
            document.addEventListener('click', function(e) {
                if (e.target.classList.contains('sp-slider-remove-line')) {
                    e.target.closest('.sp-slider-line-row').remove();
                }
            });
        })();
        </script>
    </div>
    <?php
}


/**
 * Render admin settings fields for the Feature Cards widget.
 *
 * WHY: Repeater pattern (like hero_slider slides) lets the admin build a grid
 * of image cards — each with a photo, title, description, and CTA button.
 * Used for "Library / Volunteer / Learn / Benefits" style sections.
 */
function sp_builder_fields_feature_cards( $index, array $settings ): void {
    $cards   = $settings['cards'] ?? [];
    $columns = $settings['columns'] ?? 2;
    ?>
    <div class="sp-builder-field">
        <p class="description"><?php esc_html_e( 'Add image cards with headings, descriptions, and buttons. Great for highlighting features, services, or calls to action.', 'societypress' ); ?></p>

        <label class="sp-field-label"><?php esc_html_e( 'Columns', 'societypress' ); ?></label>
        <select name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][columns]">
            <option value="2" <?php selected( $columns, 2 ); ?>>2</option>
            <option value="3" <?php selected( $columns, 3 ); ?>>3</option>
            <option value="4" <?php selected( $columns, 4 ); ?>>4</option>
        </select>

        <div class="sp-fc-cards" data-widget-index="<?php echo esc_attr( $index ); ?>" style="margin-top:16px;">
            <?php foreach ( $cards as $ci => $card ) : ?>
                <div class="sp-fc-card-row" style="border:1px solid #ddd; border-radius:6px; padding:12px; margin-bottom:12px; background:#fafafa;">
                    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">
                        <strong><?php esc_html_e( 'Card', 'societypress' ); ?> <?php echo $ci + 1; ?></strong>
                        <button type="button" class="button sp-fc-remove-card sp-text-danger">&times; <?php esc_html_e( 'Remove', 'societypress' ); ?></button>
                    </div>

                    <label class="sp-field-label"><?php esc_html_e( 'Image', 'societypress' ); ?></label>
                    <div class="sp-builder-image-field" class="sp-mb-8">
                        <input type="hidden" class="sp-builder-image-id" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][cards][<?php echo $ci; ?>][image_id]" value="<?php echo esc_attr( $card['image_id'] ?? '' ); ?>">
                        <?php
                        $img_url = '';
                        if ( ! empty( $card['image_id'] ) ) {
                            $img_url = wp_get_attachment_image_url( (int) $card['image_id'], 'medium' );
                        }
                        ?>
                        <div class="sp-builder-image-preview" style="<?php echo $img_url ? '' : 'display:none;'; ?> margin-bottom:6px;">
                            <img src="<?php echo esc_url( $img_url ); ?>" class="sp-thumb-preview">
                        </div>
                        <button type="button" class="button sp-builder-image-select"><?php echo $img_url ? esc_html__( 'Change Image', 'societypress' ) : esc_html__( 'Select Image', 'societypress' ); ?></button>
                        <button type="button" class="button sp-builder-image-remove" style="<?php echo $img_url ? '' : 'display:none;'; ?> color:#b32d2e;"><?php esc_html_e( 'Remove', 'societypress' ); ?></button>
                    </div>

                    <label class="sp-field-label"><?php esc_html_e( 'Title', 'societypress' ); ?></label>
                    <input type="text" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][cards][<?php echo $ci; ?>][title]" value="<?php echo esc_attr( $card['title'] ?? '' ); ?>" class="widefat" class="sp-mb-8">

                    <label class="sp-field-label"><?php esc_html_e( 'Description', 'societypress' ); ?></label>
                    <textarea name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][cards][<?php echo $ci; ?>][description]" class="widefat" rows="3" class="sp-mb-8"><?php echo esc_textarea( $card['description'] ?? '' ); ?></textarea>

                    <div class="sp-flex-gap-8">
                        <div class="sp-flex-1">
                            <label class="sp-field-label"><?php esc_html_e( 'Button Text', 'societypress' ); ?></label>
                            <input type="text" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][cards][<?php echo $ci; ?>][btn_text]" value="<?php echo esc_attr( $card['btn_text'] ?? '' ); ?>" class="widefat">
                        </div>
                        <div style="flex:2;">
                            <label class="sp-field-label"><?php esc_html_e( 'Button URL', 'societypress' ); ?></label>
                            <input type="text" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][cards][<?php echo $ci; ?>][btn_url]" value="<?php echo esc_attr( $card['btn_url'] ?? '' ); ?>" class="widefat" placeholder="https://">
                        </div>
                    </div>
                </div>
            <?php endforeach; ?>
        </div>

        <button type="button" class="button sp-fc-add-card" data-widget-index="<?php echo esc_attr( $index ); ?>"><?php esc_html_e( '+ Add Card', 'societypress' ); ?></button>

        <script>
        (function() {
            // WHY inline JS per widget instance: Each Feature Cards widget needs its
            // own add/remove handlers scoped to its card container. Using a data
            // attribute to target the right container avoids cross-widget conflicts.
            var idx = '<?php echo esc_js( $index ); ?>';
            var wrap = document.querySelector('.sp-fc-cards[data-widget-index="' + idx + '"]');
            var addBtn = document.querySelector('.sp-fc-add-card[data-widget-index="' + idx + '"]');

            if (addBtn && wrap) {
                addBtn.addEventListener('click', function() {
                    var ci = wrap.querySelectorAll('.sp-fc-card-row').length;
                    var html = '<div class="sp-fc-card-row" style="border:1px solid #ddd; border-radius:6px; padding:12px; margin-bottom:12px; background:#fafafa;">'
                        + '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:8px;">'
                        + '<strong><?php echo esc_js( __( 'Card', 'societypress' ) ); ?> ' + (ci + 1) + '</strong>'
                        + '<button type="button" class="button sp-fc-remove-card sp-text-danger">&times; <?php echo esc_js( __( 'Remove', 'societypress' ) ); ?></button>'
                        + '</div>'
                        + '<label class="sp-field-label"><?php echo esc_js( __( 'Image', 'societypress' ) ); ?></label>'
                        + '<div class="sp-builder-image-field" class="sp-mb-8">'
                        + '<input type="hidden" class="sp-builder-image-id" name="sp_widgets[' + idx + '][settings][cards][' + ci + '][image_id]" value="">'
                        + '<div class="sp-builder-image-preview" style="display:none; margin-bottom:6px;"><img src="" class="sp-thumb-preview"></div>'
                        + '<button type="button" class="button sp-builder-image-select"><?php echo esc_js( __( 'Select Image', 'societypress' ) ); ?></button>'
                        + '<button type="button" class="button sp-builder-image-remove" style="display:none; color:#b32d2e;"><?php echo esc_js( __( 'Remove', 'societypress' ) ); ?></button>'
                        + '</div>'
                        + '<label class="sp-field-label"><?php echo esc_js( __( 'Title', 'societypress' ) ); ?></label>'
                        + '<input type="text" name="sp_widgets[' + idx + '][settings][cards][' + ci + '][title]" value="" class="widefat" class="sp-mb-8">'
                        + '<label class="sp-field-label"><?php echo esc_js( __( 'Description', 'societypress' ) ); ?></label>'
                        + '<textarea name="sp_widgets[' + idx + '][settings][cards][' + ci + '][description]" class="widefat" rows="3" class="sp-mb-8"></textarea>'
                        + '<div class="sp-flex-gap-8">'
                        + '<div class="sp-flex-1"><label class="sp-field-label"><?php echo esc_js( __( 'Button Text', 'societypress' ) ); ?></label>'
                        + '<input type="text" name="sp_widgets[' + idx + '][settings][cards][' + ci + '][btn_text]" value="" class="widefat"></div>'
                        + '<div style="flex:2;"><label class="sp-field-label"><?php echo esc_js( __( 'Button URL', 'societypress' ) ); ?></label>'
                        + '<input type="text" name="sp_widgets[' + idx + '][settings][cards][' + ci + '][btn_url]" value="" class="widefat" placeholder="https://"></div>'
                        + '</div></div>';
                    wrap.insertAdjacentHTML('beforeend', html);
                });
            }

            // Remove card (delegated to wrap, not document)
            // WHY scoped to wrap: Attaching to document means every widget
            // instance adds another global listener. Scoping to the widget's
            // own container prevents duplicate handlers and avoids the risk
            // of one widget's listener accidentally firing on another's cards.
            if (wrap) {
                wrap.addEventListener('click', function(e) {
                    if (e.target.closest('.sp-fc-remove-card')) {
                        var row = e.target.closest('.sp-fc-card-row');
                        if (row) {
                            spConfirm('<?php echo esc_js( __( 'Remove this card?', 'societypress' ) ); ?>', function() {
                                row.remove();
                            });
                        }
                    }
                });
            }
        })();
        </script>
    </div>
    <?php
}


/**
 * Render admin settings fields for the Map Embed widget.
 *
 * WHY: Simple widget — just an address and a height. Google Maps embed doesn't
 * need an API key, so Harold can drop a map on any page without configuration.
 */
function sp_builder_fields_map_embed( $index, array $settings ): void {
    $address = $settings['address'] ?? '';
    $height  = $settings['height'] ?? 350;
    ?>
    <div class="sp-builder-field">
        <p class="description"><?php esc_html_e( 'Embeds a Google Map centered on the address you enter.', 'societypress' ); ?></p>

        <label class="sp-field-label"><?php esc_html_e( 'Address', 'societypress' ); ?></label>
        <input type="text" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][address]" value="<?php echo esc_attr( $address ); ?>" class="widefat" placeholder="<?php esc_attr_e( '123 Main St, Springfield, IL 62701', 'societypress' ); ?>" class="sp-mb-8">

        <label class="sp-field-label"><?php esc_html_e( 'Height (px)', 'societypress' ); ?></label>
        <input type="number" name="sp_widgets[<?php echo esc_attr( $index ); ?>][settings][height]" value="<?php echo esc_attr( $height ); ?>" min="200" max="600" class="sp-w-100">
    </div>
    <?php
}


function sp_sanitize_builder_widget( string $type, array $settings ): array {
    switch ( $type ) {
        case 'rich_text':
            return [ 'content' => wp_kses_post( $settings['content'] ?? '' ) ];

        case 'member_directory':
            return [
                'login_required' => ! empty( $settings['login_required'] ),
                'per_page'       => absint( $settings['per_page'] ?? 25 ),
            ];

        case 'surname_lookup':
            return [ 'login_required' => ! empty( $settings['login_required'] ) ];

        case 'membership_tiers':
            return [
                'show_prices'   => ! empty( $settings['show_prices'] ),
                'show_inactive' => ! empty( $settings['show_inactive'] ),
            ];

        case 'contact_card':
            return [
                'show_address' => ! empty( $settings['show_address'] ),
                'show_phone'   => ! empty( $settings['show_phone'] ),
                'show_email'   => ! empty( $settings['show_email'] ),
                'show_hours'   => ! empty( $settings['show_hours'] ),
            ];

        case 'member_stats':
            return [
                'show_tier_breakdown' => ! empty( $settings['show_tier_breakdown'] ),
                'show_status_counts'  => ! empty( $settings['show_status_counts'] ),
            ];

        case 'heading':
            return [
                'text'         => sanitize_text_field( $settings['text'] ?? '' ),
                'subtitle'     => sanitize_text_field( $settings['subtitle'] ?? '' ),
                'level'        => in_array( $settings['level'] ?? 'h2', [ 'h1', 'h2', 'h3', 'h4' ], true ) ? $settings['level'] : 'h2',
                'show_divider' => ! empty( $settings['show_divider'] ),
                'alignment'    => in_array( $settings['alignment'] ?? 'left', [ 'left', 'center', 'right' ], true ) ? $settings['alignment'] : 'left',
            ];

        case 'image':
            return [
                'image_id'  => absint( $settings['image_id'] ?? 0 ),
                'caption'   => sanitize_text_field( $settings['caption'] ?? '' ),
                'link_url'  => esc_url_raw( $settings['link_url'] ?? '' ),
                'size'      => in_array( $settings['size'] ?? 'large', [ 'medium', 'large', 'full' ], true ) ? $settings['size'] : 'large',
                'alignment' => in_array( $settings['alignment'] ?? 'center', [ 'left', 'center', 'right' ], true ) ? $settings['alignment'] : 'center',
            ];

        case 'button':
            return [
                'text'       => sanitize_text_field( $settings['text'] ?? '' ),
                'url'        => esc_url_raw( $settings['url'] ?? '' ),
                'style'      => in_array( $settings['style'] ?? 'primary', [ 'primary', 'secondary', 'outline' ], true ) ? $settings['style'] : 'primary',
                'alignment'  => in_array( $settings['alignment'] ?? 'left', [ 'left', 'center', 'right' ], true ) ? $settings['alignment'] : 'left',
                'new_window' => ! empty( $settings['new_window'] ),
            ];

        case 'contact_form':
            return [ 'intro_text' => sanitize_text_field( $settings['intro_text'] ?? '' ) ];

        case 'upcoming_events':
            return [
                'count'         => in_array( (int) ( $settings['count'] ?? 5 ), [ 3, 5, 10, 15, 20 ], true )
                                   ? (int) $settings['count'] : 5,
                'category_id'   => absint( $settings['category_id'] ?? 0 ),
                'layout'        => in_array( $settings['layout'] ?? 'list', [ 'list', 'cards' ], true )
                                   ? $settings['layout'] : 'list',
                'show_date'     => ! empty( $settings['show_date'] ) ? 1 : 0,
                'show_time'     => ! empty( $settings['show_time'] ) ? 1 : 0,
                'show_location' => ! empty( $settings['show_location'] ) ? 1 : 0,
            ];

        case 'event_calendar':
            return [
                'category_id' => absint( $settings['category_id'] ?? 0 ),
                'heading'     => sanitize_text_field( $settings['heading'] ?? '' ),
            ];

        case 'community_link':
            return [
                'label'       => sanitize_text_field( $settings['label'] ?? 'Join the Discussion' ),
                'description' => sanitize_text_field( $settings['description'] ?? '' ),
                'style'       => in_array( $settings['style'] ?? 'primary', [ 'primary', 'secondary', 'outline' ], true )
                                 ? $settings['style'] : 'primary',
            ];

        case 'newsletter_archive':
            return [
                'count'          => in_array( (int) ( $settings['count'] ?? 10 ), [ 5, 10, 15, 20, 50 ], true )
                                    ? (int) $settings['count'] : 10,
                'show_excerpt'   => ! empty( $settings['show_excerpt'] ),
                'show_date'      => ! empty( $settings['show_date'] ),
                'login_required' => ! empty( $settings['login_required'] ),
            ];

        case 'volunteer_stats':
            return [
                'show_count'          => ! empty( $settings['show_count'] ),
                'show_hours'          => ! empty( $settings['show_hours'] ),
                'show_top_volunteers' => ! empty( $settings['show_top_volunteers'] ),
                'time_period'         => in_array( $settings['time_period'] ?? 'year', [ 'year', 'all' ], true )
                                         ? $settings['time_period'] : 'year',
            ];

        case 'photo_gallery':
            return [
                'display_mode'   => in_array( $settings['display_mode'] ?? 'albums', [ 'albums', 'single' ], true )
                                    ? $settings['display_mode'] : 'albums',
                'album_id'       => absint( $settings['album_id'] ?? 0 ),
                'columns'        => in_array( (int) ( $settings['columns'] ?? 3 ), [ 2, 3, 4, 5 ], true )
                                    ? (int) $settings['columns'] : 3,
                'count'          => in_array( (int) ( $settings['count'] ?? 12 ), [ 6, 12, 24, 48 ], true )
                                    ? (int) $settings['count'] : 12,
                'login_required' => ! empty( $settings['login_required'] ),
            ];

        case 'resource_links':
            return [
                'category_id'       => absint( $settings['category_id'] ?? 0 ),
                'featured_only'     => ! empty( $settings['featured_only'] ),
                'count'             => in_array( (int) ( $settings['count'] ?? 20 ), [ 10, 20, 50, 100 ], true )
                                       ? (int) $settings['count'] : 20,
                'show_descriptions' => ! empty( $settings['show_descriptions'] ),
                'login_required'    => ! empty( $settings['login_required'] ),
            ];

        case 'library_catalog':
            return [
                'show_search'    => ! empty( $settings['show_search'] ),
                'category_id'    => absint( $settings['category_id'] ?? 0 ),
                'available_only' => ! empty( $settings['available_only'] ),
                'count'          => in_array( (int) ( $settings['count'] ?? 25 ), [ 10, 25, 50, 100 ], true )
                                    ? (int) $settings['count'] : 25,
                'login_required' => ! empty( $settings['login_required'] ),
            ];

        case 'hero_slider':
            // WHY: Each slide has image URL, heading, subtitle, and optional CTA
            // button. We sanitize the slides array individually to prevent XSS
            // and ensure all URLs are safe. Height and interval are clamped to
            // reasonable ranges so Harold can't accidentally break the layout.
            $slides_raw = $settings['slides'] ?? [];
            $slides     = [];
            // WHY: Valid values for per-line style dropdowns. Anything outside
            // these lists defaults to safe values, so Harold can't inject
            // arbitrary CSS through the size/weight/color fields.
            $valid_sizes   = [ 'small', 'medium', 'large' ];
            $valid_weights = [ 'light', 'bold' ];
            $valid_colors  = [ 'white', 'dark', 'accent' ];
            if ( is_array( $slides_raw ) ) {
                foreach ( $slides_raw as $slide ) {
                    if ( ! is_array( $slide ) ) continue;
                    // WHY: Per-line repeater data replaces the old overlay_text
                    // textarea. Each line has text + size/weight/color dropdowns.
                    $lines_raw = $slide['lines'] ?? [];
                    $lines     = [];
                    if ( is_array( $lines_raw ) ) {
                        foreach ( $lines_raw as $line ) {
                            if ( ! is_array( $line ) ) continue;
                            $text = sanitize_text_field( $line['text'] ?? '' );
                            if ( '' === $text ) continue; // WHY: skip blank lines
                            $lines[] = [
                                'text'   => $text,
                                'size'   => in_array( $line['size'] ?? 'medium', $valid_sizes, true ) ? $line['size'] : 'medium',
                                'weight' => in_array( $line['weight'] ?? 'light', $valid_weights, true ) ? $line['weight'] : 'light',
                                'color'  => in_array( $line['color'] ?? 'white', $valid_colors, true ) ? $line['color'] : 'white',
                            ];
                        }
                    }
                    $slides[] = [
                        'image'    => esc_url_raw( $slide['image'] ?? '' ),
                        'lines'    => $lines,
                        'btn_text' => sanitize_text_field( $slide['btn_text'] ?? '' ),
                        'btn_url'  => esc_url_raw( $slide['btn_url'] ?? '' ),
                    ];
                }
            }
            $height = absint( $settings['height'] ?? 400 );
            $height = max( 200, min( 800, $height ) );
            $interval = absint( $settings['interval'] ?? 5 );
            $interval = max( 2, min( 15, $interval ) );
            return [
                'height'   => $height,
                'autoplay' => ! empty( $settings['autoplay'] ),
                'interval' => $interval,
                'overlay'  => ! empty( $settings['overlay'] ),
                'slides'   => $slides,
            ];

        case 'feature_cards':
            $cards_raw = $settings['cards'] ?? [];
            $cards     = [];
            if ( is_array( $cards_raw ) ) {
                foreach ( $cards_raw as $card ) {
                    if ( ! is_array( $card ) ) continue;
                    $title = sanitize_text_field( $card['title'] ?? '' );
                    if ( '' === $title ) continue;
                    $cards[] = [
                        'image_id'    => absint( $card['image_id'] ?? 0 ),
                        'title'       => $title,
                        'description' => sanitize_textarea_field( $card['description'] ?? '' ),
                        'btn_text'    => sanitize_text_field( $card['btn_text'] ?? '' ),
                        'btn_url'     => esc_url_raw( $card['btn_url'] ?? '' ),
                    ];
                }
            }
            return [
                'columns' => in_array( (int) ( $settings['columns'] ?? 2 ), [ 2, 3, 4 ], true )
                             ? (int) $settings['columns'] : 2,
                'cards'   => $cards,
            ];

        case 'map_embed':
            $height = absint( $settings['height'] ?? 350 );
            $height = max( 200, min( 600, $height ) );
            return [
                'address' => sanitize_text_field( $settings['address'] ?? '' ),
                'height'  => $height,
            ];

        default:
            return [];
    }
}


// ============================================================================
// PAGE BUILDER — ADMIN ENQUEUE (SCRIPTS + STYLES + MEDIA)
// ============================================================================

/**
 * Enqueue admin assets for the page builder.
 *
 * WHY: Only loads on page edit screens. We need the media uploader for the
 * Image widget and wp_editor for the Rich Text widget.
 */
add_action( "admin_enqueue_scripts", function ( $hook ) {
    // WHY: The builder needs wp_enqueue_media() and wp_enqueue_editor() for the
    // Image widget and Rich Text widget. Originally only loaded on native WP
    // page screens; now also loads on our custom SocietyPress page editor
    // (admin_page_sp-page-edit) so the builder works there too.
    $is_native_page = in_array( $hook, [ 'post.php', 'post-new.php' ], true )
                      && ( $s = get_current_screen() ) && 'page' === $s->post_type;
    $is_sp_editor   = ( 'admin_page_sp-page-edit' === $hook );

    if ( ! $is_native_page && ! $is_sp_editor ) return;

    wp_enqueue_media();
    wp_enqueue_editor();
});


// ============================================================================
// PAGE BUILDER — ADMIN CSS (inline in admin_head)
// ============================================================================

add_action( 'admin_head', function () {
    $screen = get_current_screen();
    if ( ! $screen ) return;
    // WHY: Builder CSS needs to load on the native WP page editor AND the
    // custom SocietyPress page editor so the widget cards, picker modal,
    // and layout all render correctly in both contexts.
    if ( 'page' !== $screen->id && 'admin_page_sp-page-edit' !== $screen->id ) return;
    ?>
    <style id="sp-builder-admin-css">
        .sp-builder-card { border: 1px solid #c3c4c7; border-radius: 4px; margin-bottom: 10px; background: #fff; }
        .sp-builder-card-header { display: flex; align-items: center; padding: 10px 12px; background: #f6f7f7; border-bottom: 1px solid #c3c4c7; cursor: pointer; user-select: none; gap: 8px; }
        .sp-builder-card-header:hover { background: #f0f0f1; }
        .sp-builder-card-body { padding: 15px; }
        .sp-builder-field { margin-bottom: 12px; }
        .sp-builder-field:last-child { margin-bottom: 0; }
        .sp-builder-btn { background: none; border: 1px solid transparent; border-radius: 3px; cursor: pointer; padding: 2px 6px; font-size: 14px; line-height: 1; color: #50575e; }
        .sp-builder-btn:hover { background: #dcdcde; border-color: #c3c4c7; }
        .sp-builder-remove:hover { color: #d63638; background: #fcf0f1; border-color: #d63638; }
        .sp-builder-picker { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.6); z-index: 100100; display: flex; align-items: center; justify-content: center; }
        .sp-builder-picker-inner { background: #fff; border-radius: 8px; max-width: 650px; width: 90%; max-height: 80vh; overflow-y: auto; padding: 24px; }
        .sp-builder-picker-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 20px; }
        .sp-builder-picker-item { display: flex; flex-direction: column; align-items: flex-start; padding: 12px; border: 1px solid #c3c4c7; border-radius: 6px; background: #fff; cursor: pointer; text-align: left; transition: border-color 0.15s, box-shadow 0.15s; }
        .sp-builder-picker-item:hover { border-color: #2271b1; box-shadow: 0 0 0 1px #2271b1; }
    </style>
    <?php
});


// ============================================================================
// PAGE BUILDER — ADMIN JAVASCRIPT (inline in admin_footer)
// ============================================================================

add_action( 'admin_footer', function () {
    $screen = get_current_screen();
    if ( ! $screen ) return;
    // WHY: Builder JS (widget add/remove/reorder, picker, media library) must
    // run on both the native WP page editor and the custom SocietyPress editor.
    if ( 'page' !== $screen->id && 'admin_page_sp-page-edit' !== $screen->id ) return;
    ?>
    <script id="sp-builder-admin-js">
    document.addEventListener('DOMContentLoaded', function() {
        'use strict';
        var wrap = document.getElementById('sp-builder-wrap');
        if (!wrap) return;

        var list   = document.getElementById('sp-builder-widgets');
        var picker = document.getElementById('sp-builder-picker');
        var addBtn = document.getElementById('sp-builder-add-btn');

        // WHY: Hidden template cards contain live <input> elements with name
        // attributes. If they're not disabled, they get submitted with the form
        // on every save, creating ghost widgets (the last template type in DOM
        // order — hero_slider — would re-appear on every save even after
        // deletion). Disabling all template inputs prevents form submission
        // without affecting clone behavior, since we re-enable on clone below.
        var templates = document.getElementById('sp-builder-templates');
        if (templates) {
            templates.querySelectorAll('input, select, textarea').forEach(function(el) {
                el.disabled = true;
            });
        }

        // Open/close picker
        if (addBtn && picker) {
            addBtn.addEventListener('click', function() { picker.style.display = ''; });
        }
        if (picker) {
            // Close button inside picker
            picker.addEventListener('click', function(e) {
                var closeBtn = e.target.closest('.sp-builder-picker-close');
                if (closeBtn) { picker.style.display = 'none'; return; }
                // Click on backdrop (the picker overlay itself) closes it
                if (e.target === picker) picker.style.display = 'none';
            });
        }
        // Escape key closes picker
        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape' && picker && picker.style.display !== 'none' && picker.offsetParent !== null) {
                picker.style.display = 'none';
            }
        });

        // Add widget — delegated on picker for dynamically rendered picker items
        if (picker && list) {
            picker.addEventListener('click', function(e) {
                var item = e.target.closest('.sp-builder-picker-item');
                if (!item) return;
                var type = item.dataset.widgetType;
                var tpl = document.querySelector('#sp-builder-templates .sp-builder-template[data-widget-type="' + type + '"]');
                if (tpl) {
                    var firstChild = tpl.children[0];
                    if (firstChild) {
                        // WHY cloneNode(true): deep-clones the template card DOM.
                        // Event handlers won't copy, but we use delegation on `list`
                        // so dynamically added cards still get all their events.
                        var clone = firstChild.cloneNode(true);
                        // WHY: Template inputs were disabled to prevent form-submission
                        // pollution (see above). Re-enable them on the cloned card so
                        // the new widget's data actually gets submitted when saving.
                        clone.querySelectorAll('input, select, textarea').forEach(function(el) {
                            el.disabled = false;
                        });
                        list.appendChild(clone);
                        reindex();
                        var body = clone.querySelector('.sp-builder-card-body');
                        if (body) body.style.display = '';
                    }
                }
                picker.style.display = 'none';
            });
        }

        // All card-level events delegated on `list` so dynamically added cards work
        if (list) {
            // Remove widget
            list.addEventListener('click', function(e) {
                var removeBtn = e.target.closest('.sp-builder-remove');
                if (!removeBtn) return;
                e.stopPropagation();
                var card = removeBtn.closest('.sp-builder-card');
                spConfirm('<?php echo esc_js( __( 'Remove this widget?', 'societypress' ) ); ?>', function() {
                    if (card) card.remove();
                    reindex();
                });
            });

            // Move up
            list.addEventListener('click', function(e) {
                var upBtn = e.target.closest('.sp-builder-move-up');
                if (!upBtn) return;
                e.stopPropagation();
                var card = upBtn.closest('.sp-builder-card');
                if (!card) return;
                // Find previous sibling that is a builder card
                var prev = card.previousElementSibling;
                while (prev && !prev.classList.contains('sp-builder-card')) {
                    prev = prev.previousElementSibling;
                }
                if (prev) {
                    prev.parentNode.insertBefore(card, prev);
                    reindex();
                }
            });

            // Move down
            list.addEventListener('click', function(e) {
                var downBtn = e.target.closest('.sp-builder-move-down');
                if (!downBtn) return;
                e.stopPropagation();
                var card = downBtn.closest('.sp-builder-card');
                if (!card) return;
                // Find next sibling that is a builder card
                var next = card.nextElementSibling;
                while (next && !next.classList.contains('sp-builder-card')) {
                    next = next.nextElementSibling;
                }
                if (next) {
                    next.parentNode.insertBefore(card, next.nextSibling);
                    reindex();
                }
            });

            // Toggle expand/collapse — clicking card header
            list.addEventListener('click', function(e) {
                var header = e.target.closest('.sp-builder-card-header');
                if (!header) return;
                // Don't toggle if clicking on the action buttons inside the header
                if (e.target.closest('.sp-builder-card-actions')) return;
                var body = header.parentNode.querySelector('.sp-builder-card-body');
                if (body) body.style.display = (body.style.display === 'none') ? '' : 'none';
            });

            // Toggle expand/collapse — clicking the toggle icon
            list.addEventListener('click', function(e) {
                var toggleBtn = e.target.closest('.sp-builder-toggle');
                if (!toggleBtn) return;
                e.stopPropagation();
                var card = toggleBtn.closest('.sp-builder-card');
                if (!card) return;
                var body = card.querySelector('.sp-builder-card-body');
                if (body) body.style.display = (body.style.display === 'none') ? '' : 'none';
            });

            // Media library for Image widget — delegated on list for dynamic cards
            list.addEventListener('click', function(e) {
                var selectBtn = e.target.closest('.sp-builder-image-select');
                if (!selectBtn) return;
                e.preventDefault();
                var field = selectBtn.closest('.sp-builder-image-field');
                if (!field) return;
                var frame = wp.media({ title: 'Select Image', button: { text: 'Use This Image' }, multiple: false, library: { type: 'image' } });
                frame.on('select', function() {
                    var att = frame.state().get('selection').first().toJSON();
                    var url = att.sizes && att.sizes.medium ? att.sizes.medium.url : att.url;
                    var idInput = field.querySelector('.sp-builder-image-id');
                    if (idInput) idInput.value = att.id;
                    var previewImg = field.querySelector('.sp-builder-image-preview img');
                    if (previewImg) previewImg.setAttribute('src', url);
                    var preview = field.querySelector('.sp-builder-image-preview');
                    if (preview) preview.style.display = '';
                    var selectText = field.querySelector('.sp-builder-image-select');
                    if (selectText) selectText.textContent = 'Change Image';
                    var removeBtn = field.querySelector('.sp-builder-image-remove');
                    if (removeBtn) removeBtn.style.display = '';
                });
                frame.open();
            });

            // Remove image from Image widget
            list.addEventListener('click', function(e) {
                var removeImgBtn = e.target.closest('.sp-builder-image-remove');
                if (!removeImgBtn) return;
                e.preventDefault();
                var field = removeImgBtn.closest('.sp-builder-image-field');
                if (!field) return;
                var idInput = field.querySelector('.sp-builder-image-id');
                if (idInput) idInput.value = '';
                var preview = field.querySelector('.sp-builder-image-preview');
                if (preview) preview.style.display = 'none';
                var selectText = field.querySelector('.sp-builder-image-select');
                if (selectText) selectText.textContent = 'Select Image';
                removeImgBtn.style.display = 'none';
            });
        }

        // Media library for Hero Slider slide images
        // WHY: Slide image fields store a URL (not an attachment ID) because the
        // slider renderer uses the URL directly via esc_url(). We open the WP
        // media frame, grab the full-size URL from the selected attachment, and
        // write it into the text input that's the sibling of the clicked button.
        // Delegation on document because slider cards are cloned dynamically and
        // may exist outside the main widget list during template rendering.
        document.addEventListener('click', function(e) {
            var mediaBtn = e.target.closest('.sp-media-select');
            if (!mediaBtn) return;
            e.preventDefault();
            var inputEl = mediaBtn.closest('p');
            if (!inputEl) return;
            var textInput = inputEl.querySelector('input[type="text"]');
            if (!textInput) return;
            var frame = wp.media({
                title: 'Choose Slide Media',
                button: { text: 'Use This' },
                multiple: false,
                library: { type: ['image', 'video'] }
            });
            frame.on('select', function() {
                var att = frame.state().get('selection').first().toJSON();
                // Use the full-size URL for the slider — it renders at full width
                textInput.value = att.url;
            });
            frame.open();
        });

        // Re-index field names after add/remove/reorder
        // WHY: Widget data is submitted as sp_widgets[0][field], sp_widgets[1][field], etc.
        // After adding, removing, or reordering cards, the indices must be contiguous
        // starting at 0, or PHP will misinterpret the array structure on save.
        function reindex() {
            if (!list) return;
            var cards = list.querySelectorAll(':scope > .sp-builder-card');
            cards.forEach(function(card, i) {
                card.querySelectorAll('input, select, textarea').forEach(function(el) {
                    var name = el.getAttribute('name');
                    if (name) {
                        el.setAttribute('name', name.replace(/sp_widgets\[\d+\]/, 'sp_widgets[' + i + ']')
                                                     .replace(/sp_widgets\[__INDEX__\]/, 'sp_widgets[' + i + ']'));
                    }
                    var id = el.getAttribute('id');
                    if (id && id.indexOf('sp_widget_editor_') === 0) {
                        el.setAttribute('id', 'sp_widget_editor_' + i);
                    }
                });
            });
        }
    });
    </script>
    <?php
});


// ============================================================================
// PAGE BUILDER — FRONTEND TEMPLATE RENDERING
// ============================================================================

/**
 * When WordPress loads a page using the "SocietyPress Builder" template,
 * render the builder widgets instead of normal post content.
 *
 * WHY: Same approach as the directory — hijack template_include, render our
 * own content between get_header() and get_footer(), return blank template.
 */
add_filter( 'template_include', function ( $template ) {

    if ( ! is_page() || get_page_template_slug() !== 'sp-builder' ) {
        return $template;
    }

    // If a child theme provides front-page.php and this IS the front page,
    // let the child theme handle it — don't hijack with the Page Builder.
    // WHY: Child themes need to be able to override the homepage layout.
    //      The the society theme (and any future child theme) provides its own
    //      front-page.php with a custom hero, sections, etc. Without this
    //      check, the Page Builder always wins because it renders inline
    //      before returning a blank template.
    if ( is_front_page() && file_exists( get_stylesheet_directory() . '/front-page.php' ) && get_stylesheet() !== get_template() ) {
        return $template;
    }

    // Enqueue frontend styles
    add_action( 'wp_head', 'sp_builder_frontend_styles' );

    // Enqueue frontend JS (for contact form AJAX)
    add_action( 'wp_footer', 'sp_builder_frontend_scripts' );

    get_header();

    echo '<div class="site-content"><div class="content-area-full">';
    echo '<article class="page type-page">';

    // Page title — skip on the front page because "Home" as a big heading
    // above a hero slider looks wrong. Interior builder pages still get it.
    if ( ! is_front_page() ) {
        echo '<header class="entry-header"><h1 class="entry-title">' . esc_html( get_the_title() ) . '</h1></header>';
    }

    // Render widgets
    echo '<div class="entry-content">';
    sp_render_builder_widgets( get_the_ID() );
    echo '</div>';

    echo '</article>';
    echo '</div></div>';

    get_footer();

    return sp_get_blank_template_path();
});


/**
 * Render all builder widgets for a page.
 *
 * @param int $post_id The page ID.
 */
function sp_render_builder_widgets( int $post_id ): void {
    $widgets = get_post_meta( $post_id, '_sp_page_widgets', true );
    if ( ! is_array( $widgets ) || empty( $widgets ) ) {
        return;
    }

    echo '<div class="sp-builder-content">';

    foreach ( $widgets as $widget ) {
        $type     = $widget['type'] ?? '';
        $settings = $widget['settings'] ?? [];

        $fn = 'sp_render_builder_widget_' . $type;
        if ( function_exists( $fn ) ) {
            echo '<section class="sp-widget sp-widget--' . esc_attr( $type ) . '">';

            // Optional section heading — every widget can have one.
            // WHY no inline style: Layout rules for .sp-widget-heading-wrap
            // are defined centrally in sp_builder_frontend_styles(). This
            // keeps the HTML markup clean and overridable by child themes.
            $sec_heading = $settings['section_heading'] ?? '';
            if ( '' !== $sec_heading ) {
                echo '<div class="sp-widget-heading-wrap">';
                echo '<h2 class="sp-widget-section-heading">' . esc_html( $sec_heading ) . '</h2>';
                echo '<hr class="sp-widget-section-divider">';
                echo '</div>';
            }

            $fn( $settings );
            echo '</section>';
        }
    }

    echo '</div>';
}


// ============================================================================
// PAGE BUILDER — FRONTEND WIDGET RENDERERS
// ============================================================================

/**
 * Render: Rich Text
 */
function sp_render_builder_widget_rich_text( array $s ): void {
    $content = $s['content'] ?? '';
    if ( empty( $content ) ) return;
    echo '<div class="sp-widget-rich-text">';
    echo wp_kses_post( do_shortcode( wpautop( $content ) ) );
    echo '</div>';
}

/**
 * Render: Member Directory
 *
 * WHY: Reuses the existing sp_render_directory() function and directory styles
 * that already exist in this file. No code duplication.
 */
function sp_render_builder_widget_member_directory( array $s ): void {
    $login_required = $s['login_required'] ?? true;

    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        // WHY wp_kses: The message contains an <a> tag for the login link, so we
        // can't use esc_html. wp_kses limits allowed HTML to just the link element
        // with href — no script injection possible.
        printf(
            '<p>%s</p>',
            wp_kses(
                sprintf(
                    /* translators: %s is the login URL wrapped in an anchor tag */
                    __( 'Please <a href="%s">log in</a> to view the member directory.', 'societypress' ),
                    esc_url( wp_login_url( get_permalink() ) )
                ),
                [ 'a' => [ 'href' => [] ] ]
            )
        );
        echo '</div>';
        return;
    }

    // Load directory styles
    sp_directory_styles();

    // Render the directory using the existing function
    $settings = get_option( 'societypress_settings', [] );
    if ( ! empty( $s['per_page'] ) ) {
        $settings['dir_per_page'] = $s['per_page'];
    }
    echo '<div class="sp-directory-wrap" style="margin:0; padding:0;">';
    sp_render_directory( $settings );
    echo '</div>';
}

/**
 * Render: Surname Lookup
 */
function sp_render_builder_widget_surname_lookup( array $s ): void {
    global $wpdb;
    $login_required = $s['login_required'] ?? true;

    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        // WHY wp_kses: Same pattern as the member directory — the translatable
        // string contains an <a> link. wp_kses whitelists only the anchor tag.
        printf(
            '<p>%s</p>',
            wp_kses(
                sprintf(
                    /* translators: %s is the login URL wrapped in an anchor tag */
                    __( 'Please <a href="%s">log in</a> to search surnames.', 'societypress' ),
