                <p class="sp-event-edit-ical-notice-text">
                    <strong><?php esc_html_e( 'Imported from iCal Feed', 'societypress' ); ?></strong><br>
                    <?php
                    printf(
                        /* translators: %s: feed label */
                        esc_html__( 'This event was imported from "%s". Any manual changes will be overwritten on the next sync.', 'societypress' ),
                        esc_html( $feed_label ?: '#' . $event->feed_id )
                    );
                    ?>
                </p>
                <button type="button" class="button" id="sp-detach-from-feed"
                        data-event-id="<?php echo esc_attr( $event->id ); ?>"
                        data-nonce="<?php echo esc_attr( wp_create_nonce( 'sp_detach_event_' . $event->id ) ); ?>">
                    <?php esc_html_e( 'Detach from Feed', 'societypress' ); ?>
                </button>
            </div>
        <?php endif; ?>

        <form method="post">
            <?php wp_nonce_field( 'sp_save_event', 'sp_event_nonce' ); ?>
            <input type="hidden" name="event_id" value="<?php echo esc_attr( $event_id ); ?>">

            <table class="form-table" role="presentation">

                <!-- ============================================================ -->
                <!-- SECTION 1: Basic Info                                         -->
                <!-- ============================================================ -->

                <tr>
                    <td colspan="2" class="sp-event-edit-section-header-cell">
                        <h2 class="sp-event-edit-section-heading sp-event-edit-section-heading--first"><?php esc_html_e( 'Basic Info', 'societypress' ); ?></h2>
                    </td>
                </tr>

                <tr>
                    <th scope="row"><label for="event_title">Title <span class="sp-event-edit-required">*</span></label></th>
                    <td>
                        <input type="text" id="event_title" name="event_title"
                               value="<?php echo esc_attr( $val( 'title' ) ); ?>"
