                                <span class="sp-cat-display-color" style="background: <?php echo esc_attr( $cat->color ); ?>;"></span>
                                <input type="color" class="sp-cat-edit-color sp-cat-edit-color-input" value="<?php echo esc_attr( $cat->color ); ?>" style="display: none;">
