// ============================================================================
// EVENTS — FRONTEND JAVASCRIPT
// ============================================================================

/**
 * Output event page scripts in the footer.
 *
 * WHY: JavaScript for the calendar mobile interaction — tapping a day on
 *      mobile shows a panel with the events for that day (since the full
 *      titles are hidden and replaced with dots on small screens).
 */
function sp_events_frontend_scripts(): void {
    ?>
    <script id="sp-events-frontend-js">
    (function() {
        'use strict';

        // ---- Calendar mobile: tap day to show events panel ----
        var calDays = document.querySelectorAll('.sp-cal-has-events');
        var panel   = document.getElementById('sp-cal-mobile-panel');
        var panelDate   = document.getElementById('sp-cal-mobile-date');
        var panelEvents = document.getElementById('sp-cal-mobile-events');
        var closeBtn    = document.getElementById('sp-cal-mobile-close');

        if (calDays.length && panel) {
            calDays.forEach(function(day) {
                day.addEventListener('click', function(e) {
                    // Only on mobile (when dots are visible)
                    if (window.innerWidth > 768) return;

                    // Don't intercept link clicks inside event titles
                    if (e.target.closest('.sp-cal-event')) return;

                    var dayNum = this.querySelector('.sp-cal-day-num').textContent;
                    var monthLabel = document.querySelector('.sp-cal-month-label');
                    panelDate.textContent = monthLabel ? monthLabel.textContent + ' ' + dayNum : 'Day ' + dayNum;

                    // Build event list from the hidden .sp-cal-events links
                    var events = this.querySelectorAll('.sp-cal-event');
                    var html = '';
                    events.forEach(function(ev) {
                        var title = ev.querySelector('.sp-cal-event-title');
                        var time  = ev.querySelector('.sp-cal-event-time');
                        html += '<a class="sp-cal-mobile-event" href="' + ev.href + '">';
                        html += '<div class="sp-cal-mobile-event-title">' + (title ? title.textContent : '') + '</div>';
                        if (time) {
                            html += '<div class="sp-cal-mobile-event-time">' + time.textContent + '</div>';
                        }
                        html += '</a>';
                    });
                    panelEvents.innerHTML = html;
                    panel.style.display = 'block';
                    panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                });
            });

            if (closeBtn) {
                closeBtn.addEventListener('click', function() {
                    panel.style.display = 'none';
                });
            }
        }

        // ---- Registration AJAX (member + guest + payment) ----
        var regBtn      = document.getElementById('sp-register-btn');
        var doorBtn     = document.getElementById('sp-register-door-btn');
        var paypalBtn   = document.getElementById('sp-register-paypal-btn');
        var guestBtn    = document.getElementById('sp-guest-register-btn');
        var guestDoor   = document.getElementById('sp-guest-register-door-btn');
        var guestPaypal = document.getElementById('sp-guest-register-paypal-btn');
        var msgBox      = document.getElementById('sp-reg-message');

        // Show message in the registration message area
        function showRegMsg(text, type) {
            if (!msgBox) return;
            msgBox.textContent = text;
            msgBox.className = 'sp-reg-message sp-reg-msg-' + type;
            msgBox.style.display = 'block';
        }

        // ---- Dynamic fee calculation ----
        // WHY: When someone changes "How many attending?" we recalculate the
        //      total fee on screen so they know exactly what they'll owe before
        //      clicking Register. Nobody likes a surprise at checkout.
        //
        // Currency symbol and position from settings — so non-US societies
        // see their own currency in the dynamic fee display.
        var spCSym = <?php echo wp_json_encode( sp_get_currency_symbol() ); ?>;
        var spCPos = <?php echo wp_json_encode( sp_get_currency_position() ); ?>;
        function spFmtCurrency(amount) {
            return spCPos === 'before' ? spCSym + amount : amount + spCSym;
        }

        function updateFeeDisplay(partySizeSelect, pricePerPerson, displayEl, perPersonEl) {
            if (!partySizeSelect || !displayEl) return;
            partySizeSelect.addEventListener('change', function() {
                var qty   = parseInt(this.value, 10) || 1;
                var total = (pricePerPerson * qty).toFixed(2);
                displayEl.textContent = spFmtCurrency(total);
                if (perPersonEl) {
                    perPersonEl.textContent = qty > 1
                        ? '(' + spFmtCurrency(pricePerPerson.toFixed(2)) + '/person \u00D7 ' + qty + ')'
                        : '(' + spFmtCurrency(pricePerPerson.toFixed(2)) + '/person)';
                }
            });
        }

        // Member fee display updates
        if (typeof spRegData !== 'undefined' && spRegData.memberPrice > 0) {
            updateFeeDisplay(
                document.getElementById('sp-reg-party-size'),
                spRegData.memberPrice,
                document.getElementById('sp-fee-display'),
                document.getElementById('sp-fee-per-person')
            );
        }
        // Guest fee display updates
        if (typeof spRegData !== 'undefined' && spRegData.nonmemberPrice > 0) {
            updateFeeDisplay(
                document.getElementById('sp-guest-party-size'),
                spRegData.nonmemberPrice,
                document.getElementById('sp-guest-fee-display'),
                document.getElementById('sp-guest-fee-per-person')
            );
        }

        // ---- Shared registration handler ----
        // WHY: Both member and guest registration (and both "pay online" and
        //      "pay at door" flows) share the same backend AJAX endpoint. The
        //      pay_method parameter tells the server whether to create a Stripe
        //      Checkout Session or just register normally. If Stripe returns a
        //      checkout URL, we redirect there; otherwise we show confirmation.
        function handleRegistration(btn, extraFields) {
            var eventId   = btn.getAttribute('data-event-id');
            var payMethod = btn.getAttribute('data-pay-method') || 'none';
            var btnText   = btn.textContent;

            btn.disabled = true;
            btn.textContent = (payMethod === 'online' || payMethod === 'paypal') ? '<?php echo esc_js( __( "Redirecting to payment\u2026", "societypress" ) ); ?>' : '<?php echo esc_js( __( "Registering\u2026", "societypress" ) ); ?>';

            var formData = new FormData();
            formData.append('action', 'sp_register_for_event');
            formData.append('event_id', eventId);
            formData.append('pay_method', payMethod);
            formData.append('nonce', spRegData.nonce);

            // Add any extra fields (party_size, guest info, etc.)
            if (extraFields) {
                for (var key in extraFields) {
                    formData.append(key, extraFields[key]);
                }
            }

            fetch(spRegData.ajaxUrl, {
                method: 'POST',
                body: formData,
                credentials: 'same-origin'
            })
            .then(function(resp) { return resp.json(); })
            .then(function(data) {
                if (data.success) {
                    // If the server returned a Stripe Checkout URL, redirect there.
                    // WHY: Stripe Checkout is a hosted page — we send the user there
                    //      to enter their card. After paying (or cancelling), Stripe
                    //      redirects them back to our event page with status params.
                    if (data.data.checkout_url) {
                        window.location.href = data.data.checkout_url;
                        return;
                    }

                    // No Stripe redirect — show normal confirmation
                    var formArea = document.getElementById('sp-reg-form-area');
                    if (formArea) {
                        var icon = data.data.status === 'waitlisted' ? '\uD83D\uDCCB' : '\u2705';
                        var msg;
                        if (data.data.status === 'waitlisted') {
                            msg = '<strong>You\'re on the waitlist.</strong><br><span class="sp-reg-note">We\'ll notify you if a spot opens up.</span>';
                        } else if (payMethod === 'at_door' && data.data.fee_amount > 0) {
                            msg = '<strong>You\'re registered!</strong><br><span class="sp-reg-note">Please bring $' + parseFloat(data.data.fee_amount).toFixed(2) + ' to the event.</span>';
                        } else {
                            msg = '<strong>You\'re registered!</strong><br><span class="sp-reg-note">You\'ll receive a reminder email before the event.</span>';
                        }
                        formArea.innerHTML = '<div class="sp-reg-confirmed">'
                            + '<p>' + icon + ' ' + msg + '</p>'
                            + '<button type="button" class="sp-reg-cancel-btn" id="sp-cancel-reg-btn" '
                            + 'data-event-id="' + eventId + '" data-reg-id="' + data.data.registration_id + '">'
                            + '<?php echo esc_js( __( "Cancel My Registration", "societypress" ) ); ?></button></div>';
                        attachCancelHandler();
                        if (data.data.spots_left !== null) {
                            updateCapacityBar(data.data.spots_left, data.data.registration_limit);
                        }
                    }
                } else {
                    showRegMsg(data.data || '<?php echo esc_js( __( 'Registration failed. Please try again.', 'societypress' ) ); ?>', 'error');
                    btn.disabled = false;
                    btn.textContent = btnText;
                }
            })
            .catch(function() {
                showRegMsg('<?php echo esc_js( __( 'Something went wrong. Please try again.', 'societypress' ) ); ?>', 'error');
                btn.disabled = false;
                btn.textContent = btnText;
            });
        }

        // Member registration — main button (pay online or free)
        if (regBtn) {
            regBtn.addEventListener('click', function() {
                var extras = { party_size: document.getElementById('sp-reg-party-size').value };
                var slotEl = document.getElementById('sp-reg-slot');
                if (slotEl && slotEl.value) { extras.slot_id = slotEl.value; }
                handleRegistration(this, extras);
            });
        }

        // Member registration — "Pay at Door" alternate button
        if (doorBtn) {
            doorBtn.addEventListener('click', function() {
                var extras = { party_size: document.getElementById('sp-reg-party-size').value };
                var slotEl = document.getElementById('sp-reg-slot');
                if (slotEl && slotEl.value) { extras.slot_id = slotEl.value; }
                handleRegistration(this, extras);
            });
        }

        // Member registration — "Pay with PayPal" button
        if (paypalBtn) {
            paypalBtn.addEventListener('click', function() {
                var extras = { party_size: document.getElementById('sp-reg-party-size').value };
                var slotEl = document.getElementById('sp-reg-slot');
                if (slotEl && slotEl.value) { extras.slot_id = slotEl.value; }
                handleRegistration(this, extras);
            });
        }

        // Guest registration — main button
        if (guestBtn) {
            guestBtn.addEventListener('click', function() {
                var name  = document.getElementById('sp-guest-name').value.trim();
                var email = document.getElementById('sp-guest-email').value.trim();
                var phone = document.getElementById('sp-guest-phone').value.trim();
                if (!name) { showRegMsg('<?php echo esc_js( __( 'Please enter your name.', 'societypress' ) ); ?>', 'error'); return; }
                if (!email || email.indexOf('@') < 1) { showRegMsg('<?php echo esc_js( __( 'Please enter a valid email address.', 'societypress' ) ); ?>', 'error'); return; }

                var extras = {
                    party_size: document.getElementById('sp-guest-party-size').value,
                    guest_name: name,
                    guest_email: email,
                    guest_phone: phone
                };
                var gSlotEl = document.getElementById('sp-guest-slot');
                if (gSlotEl && gSlotEl.value) { extras.slot_id = gSlotEl.value; }
                handleRegistration(this, extras);
            });
        }

        // Guest registration — "Pay at Door" alternate button
        if (guestDoor) {
            guestDoor.addEventListener('click', function() {
                var name  = document.getElementById('sp-guest-name').value.trim();
                var email = document.getElementById('sp-guest-email').value.trim();
                var phone = document.getElementById('sp-guest-phone').value.trim();
                if (!name) { showRegMsg('<?php echo esc_js( __( 'Please enter your name.', 'societypress' ) ); ?>', 'error'); return; }
                if (!email || email.indexOf('@') < 1) { showRegMsg('<?php echo esc_js( __( 'Please enter a valid email address.', 'societypress' ) ); ?>', 'error'); return; }

                var extras = {
                    party_size: document.getElementById('sp-guest-party-size').value,
                    guest_name: name,
                    guest_email: email,
                    guest_phone: phone
                };
                var gSlotEl = document.getElementById('sp-guest-slot');
                if (gSlotEl && gSlotEl.value) { extras.slot_id = gSlotEl.value; }
                handleRegistration(this, extras);
            });
        }

        // Guest registration — "Pay with PayPal" button
        if (guestPaypal) {
            guestPaypal.addEventListener('click', function() {
                var name  = document.getElementById('sp-guest-name').value.trim();
                var email = document.getElementById('sp-guest-email').value.trim();
                var phone = document.getElementById('sp-guest-phone').value.trim();
                if (!name) { showRegMsg('<?php echo esc_js( __( 'Please enter your name.', 'societypress' ) ); ?>', 'error'); return; }
                if (!email || email.indexOf('@') < 1) { showRegMsg('<?php echo esc_js( __( 'Please enter a valid email address.', 'societypress' ) ); ?>', 'error'); return; }

                var extras = {
                    party_size: document.getElementById('sp-guest-party-size').value,
                    guest_name: name,
                    guest_email: email,
                    guest_phone: phone
                };
                var gSlotEl = document.getElementById('sp-guest-slot');
                if (gSlotEl && gSlotEl.value) { extras.slot_id = gSlotEl.value; }
                handleRegistration(this, extras);
            });
        }

        // ---- Per-slot cancel buttons ----
        // WHY: When an event has slots, each of the user's registrations has
        //      its own cancel button. These use the same cancel AJAX endpoint.
        document.querySelectorAll('.sp-slot-cancel-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var self = this;
                spConfirm('<?php echo esc_js( __( 'Cancel this registration?', 'societypress' ) ); ?>', function() {
                var regId   = self.getAttribute('data-reg-id');
                var eventId = self.getAttribute('data-event-id');
                var row     = this.closest('.sp-user-slot-reg-row');

                this.disabled = true;
                this.textContent = '<?php echo esc_js( __( "Cancelling\u2026", "societypress" ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_cancel_registration');
                fd.append('registration_id', regId);
                fd.append('event_id', eventId);
                fd.append('nonce', spRegData.nonce);

                fetch(spRegData.ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success && row) {
                            row.style.opacity = '0.4';
                            row.innerHTML = '<span style="color: #787c82; font-style: italic;"><?php echo esc_js( __( "Cancelled", "societypress" ) ); ?></span>';
                        }
                    });
            });
        });

        // ---- Stripe return handler ----
        // WHY: After paying on Stripe's checkout page, the user is redirected
        //      back here with ?sp_payment=success or ?sp_payment=cancelled in
        //      the URL. We show a friendly message and clean up the URL so a
        //      page refresh doesn't show the message again.
        (function() {
            var params = new URLSearchParams(window.location.search);
            var payStatus = params.get('sp_payment');
            if (!payStatus) return;

            var formArea = document.getElementById('sp-reg-form-area') || document.getElementById('sp-reg-status-area');
            if (formArea) {
                if (payStatus === 'success') {
                    formArea.innerHTML = '<div class="sp-reg-confirmed">'
                        + '<p>\u2705 <strong><?php echo esc_js( __( "Payment received — you\'re registered!", "societypress" ) ); ?></strong></p>'
                        + '<p class="sp-reg-note"><?php echo esc_js( __( "A confirmation email has been sent. You\'ll also get a reminder before the event.", "societypress" ) ); ?></p>'
                        + '</div>';
                } else if (payStatus === 'cancelled') {
                    formArea.innerHTML = '<div class="sp-reg-message sp-reg-msg-error" class="sp-block">'
                        + '<?php echo esc_js( __( "Payment was cancelled. Your registration is still pending — you can try again or choose to pay at the door.", "societypress" ) ); ?>'
                        + '</div>';
                }
            }

            // Clean up the URL so refreshing doesn't show the message again
            if (window.history && window.history.replaceState) {
                params.delete('sp_payment');
                params.delete('sp_session');
                var cleanUrl = window.location.pathname;
                var remaining = params.toString();
                if (remaining) cleanUrl += '?' + remaining;
                window.history.replaceState({}, '', cleanUrl);
            }
        })();

        // Cancel registration handler
        function attachCancelHandler() {
            var cancelBtn = document.getElementById('sp-cancel-reg-btn');
            if (!cancelBtn) return;
            cancelBtn.addEventListener('click', function() {
                var btn     = this;
                spConfirm('<?php echo esc_js( __( 'Are you sure you want to cancel your registration?', 'societypress' ) ); ?>', function() {
                var eventId = btn.getAttribute('data-event-id');
                var regId   = btn.getAttribute('data-reg-id');

                btn.disabled = true;
                btn.textContent = '<?php echo esc_js( __( "Cancelling\u2026", "societypress" ) ); ?>';

                var formData = new FormData();
                formData.append('action', 'sp_cancel_registration');
                formData.append('event_id', eventId);
                formData.append('registration_id', regId);
                formData.append('nonce', spRegData.nonce);

                fetch(spRegData.ajaxUrl, {
                    method: 'POST',
                    body: formData,
                    credentials: 'same-origin'
                })
                .then(function(resp) { return resp.json(); })
                .then(function(data) {
                    if (data.success) {
                        window.location.reload();
                    } else {
                        alert(data.data || '<?php echo esc_js( __( "Could not cancel registration.", "societypress" ) ); ?>');
                        btn.disabled = false;
                        btn.textContent = '<?php echo esc_js( __( "Cancel My Registration", "societypress" ) ); ?>';
                    }
                })
                .catch(function() {
                    alert('<?php echo esc_js( __( 'Something went wrong. Please try again.', 'societypress' ) ); ?>');
                    btn.disabled = false;
                    btn.textContent = '<?php echo esc_js( __( "Cancel My Registration", "societypress" ) ); ?>';
                });
            });
        }
        attachCancelHandler();

        // Update capacity bar dynamically after registration
        function updateCapacityBar(spotsLeft, limit) {
            var capText = document.querySelector('.sp-capacity-text');
            var capFill = document.querySelector('.sp-capacity-fill');
            if (!capText || !capFill || !limit) return;

            var used = limit - spotsLeft;
            var pct  = (used / limit) * 100;
            capFill.style.width = Math.min(100, pct) + '%';
            capFill.style.background = pct >= 90 ? '#d63638' : (pct >= 70 ? '#dba617' : '#00a32a');

            if (spotsLeft <= 0) {
                capText.innerHTML = '<strong><?php echo esc_js( __( 'Event is full.', 'societypress' ) ); ?></strong> <?php echo esc_js( __( 'You can join the waitlist.', 'societypress' ) ); ?>';
            } else {
                capText.textContent = spotsLeft + ' <?php echo esc_js( __( 'of', 'societypress' ) ); ?> ' + limit + ' <?php echo esc_js( __( 'spots remaining', 'societypress' ) ); ?>';
            }
        }

    })();
    </script>
    <?php
}
// END sp_events_frontend_scripts


// ============================================================================
// EVENTS — REGISTRATION AJAX HANDLERS
// ============================================================================
//
// WHY: Registration uses AJAX so the page doesn't reload — the user clicks
//      "Register Now" and gets instant feedback. We handle both logged-in
//      member registrations and guest registrations through the same endpoint.
//      Waitlisting is automatic when an event is at capacity.
// ============================================================================

/**
 * AJAX handler: Register for an event.
 *
 * WHY: Single endpoint handles both member and guest registration. We check
 *      capacity, determine confirmed vs waitlisted status, prevent duplicate
 *      registrations, and calculate the fee based on member/non-member pricing.
 *
 * Accepts: event_id, party_size, guest_name (optional), guest_email (optional),
 *          guest_phone (optional), nonce.
 *
 * Returns: JSON with registration_id, status, spots_left, registration_limit.
 */
add_action( 'wp_ajax_sp_register_for_event', 'sp_ajax_register_for_event' );
add_action( 'wp_ajax_nopriv_sp_register_for_event', 'sp_ajax_register_for_event' );

function sp_ajax_register_for_event(): void {
    // Verify nonce to prevent CSRF attacks
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_event_register' ) ) {
        wp_send_json_error( __( 'Security check failed. Please refresh and try again.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';
    $evt_table = $wpdb->prefix . 'sp_events';

    $event_id   = (int) ( $_POST['event_id'] ?? 0 );
    $party_size = max( 1, (int) ( $_POST['party_size'] ?? 1 ) );
    $slot_id    = ! empty( $_POST['slot_id'] ) ? (int) $_POST['slot_id'] : null;
    $is_guest   = ! is_user_logged_in();

    // Fetch the event to validate it exists and accepts registrations
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$evt_table} WHERE id = %d", $event_id
    ) );

    if ( ! $event ) {
        wp_send_json_error( __( 'Event not found.', 'societypress' ) );
    }

    if ( ! $event->registration_enabled ) {
        wp_send_json_error( __( 'Registration is not enabled for this event.', 'societypress' ) );
    }

    if ( $event->status !== 'scheduled' ) {
        wp_send_json_error( __( 'This event is no longer accepting registrations.', 'societypress' ) );
    }

    // Don't allow registration for events that have already happened
    if ( $event->event_date < current_time( 'Y-m-d' ) ) {
        wp_send_json_error( __( 'This event has already taken place.', 'societypress' ) );
    }

    // If a slot_id was provided, validate it belongs to this event and is active
    // WHY: Prevent tampering — someone could send a slot_id from a different
    //      event. Also verify the slot is still active (not soft-deleted).
    if ( $slot_id ) {
        $slot = sp_slot_get( $slot_id );
        if ( ! $slot || (int) $slot->event_id !== $event_id || ! $slot->is_active ) {
            wp_send_json_error( __( 'Invalid time slot selected.', 'societypress' ) );
        }
    }

    // Guest registration must be explicitly enabled per-event
    if ( $is_guest && ! $event->guest_registration ) {
        wp_send_json_error( __( 'Please log in to register for this event.', 'societypress' ) );
    }

    // Validate and sanitize guest fields
    $guest_name  = '';
    $guest_email = '';
    $guest_phone = '';
    if ( $is_guest ) {
        $guest_name  = sanitize_text_field( $_POST['guest_name'] ?? '' );
        $guest_email = sanitize_email( $_POST['guest_email'] ?? '' );
        $guest_phone = sanitize_text_field( $_POST['guest_phone'] ?? '' );

        if ( empty( $guest_name ) || empty( $guest_email ) ) {
            wp_send_json_error( __( 'Please provide your name and email address.', 'societypress' ) );
        }

        // Prevent duplicate guest registration by email for the same event+slot
        // WHY: If event has slots, a guest CAN register for multiple different
        //      slots (e.g., morning and afternoon). But they can't double-register
        //      for the same slot. If no slots, same as before — one per event.
        if ( $slot_id ) {
            $existing_guest = $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$reg_table}
                 WHERE event_id = %d AND slot_id = %d AND guest_email = %s AND status IN ('confirmed', 'waitlisted')",
                $event_id, $slot_id, $guest_email
            ) );
            if ( $existing_guest ) {
                wp_send_json_error( __( 'This email address is already registered for this time slot.', 'societypress' ) );
            }
        } else {
            $existing_guest = $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$reg_table}
                 WHERE event_id = %d AND slot_id IS NULL AND guest_email = %s AND status IN ('confirmed', 'waitlisted')",
                $event_id, $guest_email
            ) );
            if ( $existing_guest ) {
                wp_send_json_error( __( 'This email address is already registered for this event.', 'societypress' ) );
            }
        }
    } else {
        // Prevent duplicate member registration for the same event+slot
        // WHY: Same logic as guests — members can register for multiple slots
        //      of the same event, but not the same slot twice.
        if ( $slot_id ) {
            $existing_member = $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$reg_table}
                 WHERE event_id = %d AND slot_id = %d AND user_id = %d AND status IN ('confirmed', 'waitlisted')",
                $event_id, $slot_id, get_current_user_id()
            ) );
            if ( $existing_member ) {
                wp_send_json_error( __( 'You are already registered for this time slot.', 'societypress' ) );
            }
        } else {
            $existing_member = $wpdb->get_var( $wpdb->prepare(
                "SELECT COUNT(*) FROM {$reg_table}
                 WHERE event_id = %d AND slot_id IS NULL AND user_id = %d AND status IN ('confirmed', 'waitlisted')",
                $event_id, get_current_user_id()
            ) );
            if ( $existing_member ) {
                wp_send_json_error( __( 'You are already registered for this event.', 'societypress' ) );
            }
        }
    }

    // Determine status: confirmed if there's room, waitlisted if full
    // WHY: When a slot_id is provided, we check slot-level capacity instead of
    //      event-level. This lets each slot (e.g., "10-11 AM session") have its
    //      own capacity limit independent of the overall event. If no slot,
    //      we fall back to the event-wide registration_limit.
    $status = 'confirmed';
    if ( $slot_id ) {
        // Slot-level capacity check
        $slot_remaining = sp_slot_get_remaining_capacity( $slot_id );
        // NULL = unlimited, otherwise check if party fits
        if ( $slot_remaining !== null && $slot_remaining < $party_size ) {
            $status = 'waitlisted';
        }
    } else {
        // Event-level capacity check (no slots)
        $current_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COALESCE(SUM(party_size), 0) FROM {$reg_table}
             WHERE event_id = %d AND status = 'confirmed'",
            $event_id
        ) );
        if ( $event->registration_limit ) {
            $available = (int) $event->registration_limit - $current_count;
            if ( $available < $party_size ) {
                $status = 'waitlisted';
            }
        }
    }

    // Calculate fee: members get member pricing, guests get non-member pricing
    // WHY: Fee is per-person multiplied by party size. We store the total so
    //      the treasurer doesn't have to do math when reconciling payments.
    $per_person_fee = $is_guest
        ? (float) $event->nonmember_price
        : (float) $event->member_price;
    $fee_amount = $per_person_fee * $party_size;

    // Determine payment method from the frontend
    // WHY: The frontend sends 'online' (Stripe), 'paypal', 'at_door', or 'none'
    //      based on which button was clicked. If 'online' or 'paypal', we create
    //      a checkout session and send back the redirect URL. Otherwise, register.
    $pay_method = sanitize_text_field( $_POST['pay_method'] ?? 'none' );

    // Determine the correct payment_status based on method and fee
    $payment_status = 'none';
    $payment_method = null;
    if ( $fee_amount > 0 ) {
        if ( $pay_method === 'online' ) {
            $payment_status = 'pending';
            $payment_method = 'stripe';
        } elseif ( $pay_method === 'paypal' ) {
            $payment_status = 'pending';
            $payment_method = 'paypal';
        } elseif ( $pay_method === 'at_door' ) {
            $payment_status = 'pending';
            $payment_method = 'at_door';
        } else {
            $payment_status = 'pending';
        }
    }

    // Insert the registration record
    $insert_data = [
        'event_id'       => $event_id,
        'slot_id'        => $slot_id,
        'user_id'        => $is_guest ? null : get_current_user_id(),
        'guest_name'     => $is_guest ? $guest_name : null,
        'guest_email'    => $is_guest ? $guest_email : null,
        'guest_phone'    => $is_guest ? $guest_phone : null,
        'status'         => $status,
        'party_size'     => $party_size,
        'fee_amount'     => $fee_amount,
        'payment_status' => $payment_status,
        'payment_method' => $payment_method,
        'registered_at'  => current_time( 'mysql' ),
    ];
    $insert_format = [ '%d', '%d', '%d', '%s', '%s', '%s', '%s', '%d', '%f', '%s', '%s', '%s' ];

    $wpdb->insert( $reg_table, $insert_data, $insert_format );
    $registration_id = $wpdb->insert_id;

    if ( ! $registration_id ) {
        wp_send_json_error( __( 'Could not complete registration. Please try again.', 'societypress' ) );
    }

    // Audit: log the registration so Harold can see who signed up and when.
    // WHY: Event registrations are high-value actions — they affect capacity,
    //      revenue, and logistics. Logging them makes troubleshooting easy.
    $registrant_label = $is_guest
        ? ( $guest_name ?: $guest_email ?: 'Guest' )
        : wp_get_current_user()->display_name;
    sp_audit(
        'event_registration',
        sprintf( '%s registered for "%s" (party of %d, status: %s)', $registrant_label, $event->title, $party_size, $status ),
        'event_registration',
        $registration_id
    );

    // If paying online via Stripe, create a Checkout Session and send back the URL
    // WHY: Stripe Checkout is a hosted payment page — we redirect the user there,
    //      they enter their card info on Stripe's secure page, then Stripe sends
    //      them back to our event page. This means our site never touches credit
    //      card data, which eliminates PCI compliance headaches entirely.
    if ( $pay_method === 'online' && $fee_amount > 0 && $status !== 'waitlisted' ) {
        $sp_settings = get_option( 'societypress_settings', [] );

        if ( ! sp_stripe_is_configured( $sp_settings ) ) {
            // Clean up the registration since we can't complete payment
            $wpdb->delete( $reg_table, [ 'id' => $registration_id ] );
            wp_send_json_error( __( 'Online payments are not configured. Please contact the site administrator.', 'societypress' ) );
        }

        $checkout_url = sp_create_stripe_checkout_session( $event, $registration_id, $fee_amount, $sp_settings );

        if ( is_wp_error( $checkout_url ) ) {
            // Clean up the registration since payment failed to initialize
            $wpdb->delete( $reg_table, [ 'id' => $registration_id ] );
            wp_send_json_error( $checkout_url->get_error_message() );
        }

        wp_send_json_success( [
            'checkout_url'   => $checkout_url,
            'registration_id' => $registration_id,
        ] );
    }

    // If paying via PayPal, create a PayPal Order and send back the approval URL
    // WHY: Same redirect-based flow as Stripe but using PayPal's Orders API.
    //      We create an order, get an approval URL, and redirect the user to PayPal.
    //      After they approve, PayPal redirects them back and we capture the payment.
    if ( $pay_method === 'paypal' && $fee_amount > 0 && $status !== 'waitlisted' ) {
        $sp_settings = get_option( 'societypress_settings', [] );

        if ( ! sp_paypal_is_configured( $sp_settings ) ) {
            $wpdb->delete( $reg_table, [ 'id' => $registration_id ] );
            wp_send_json_error( __( 'PayPal is not configured. Please contact the site administrator.', 'societypress' ) );
        }

        $currency = $sp_settings['stripe_currency'] ?? 'usd';

        // Build return URLs — PayPal redirects back here after approval/cancel
        $event_url = get_permalink();
        if ( ! $event_url ) {
            $event_url = home_url();
        }
        $return_url = add_query_arg( [
            'sp_payment'    => 'success',
            'sp_paypal'     => '1',
            'sp_pp_reg'     => $registration_id,
        ], $event_url );
        $cancel_url = add_query_arg( [ 'sp_payment' => 'cancelled' ], $event_url );

        $description = sprintf(
            /* translators: %s: event title */
            __( 'Event Registration: %s', 'societypress' ),
            mb_substr( $event->title, 0, 100 )
        );

        $order_result = sp_paypal_create_order(
            $fee_amount,
            $currency,
            $description,
            $return_url,
            $cancel_url,
            [ 'type' => 'event', 'registration_id' => $registration_id, 'event_id' => $event_id ],
            $sp_settings
        );

        if ( is_wp_error( $order_result ) ) {
            $wpdb->delete( $reg_table, [ 'id' => $registration_id ] );
            wp_send_json_error( $order_result->get_error_message() );
        }

        // Store PayPal order ID on the registration for later verification
        $wpdb->update(
            $reg_table,
            [ 'notes' => 'paypal_order:' . $order_result['id'] ],
            [ 'id' => $registration_id ]
        );

        wp_send_json_success( [
            'checkout_url'    => $order_result['approve_url'],
            'registration_id' => $registration_id,
        ] );
    }

    // Send confirmation or waitlist email to the registrant
    // WHY: People expect instant confirmation when they register for something.
    //      Even a waitlist placement deserves acknowledgement so they're not
    //      left wondering if it went through.
    $recipient_email = $is_guest ? $guest_email : '';
    if ( ! $is_guest ) {
        $user = get_userdata( get_current_user_id() );
        $recipient_email = $user ? $user->user_email : '';
    }
    if ( $recipient_email ) {
        sp_send_registration_email( $event, $registration_id, $status, $recipient_email, $party_size, $fee_amount );
    }

    // Recalculate spots remaining to send back for UI update
    // WHY: When using slots, show slot-level capacity. Otherwise, event-level.
    $spots_left = null;
    if ( $slot_id ) {
        $spots_left = sp_slot_get_remaining_capacity( $slot_id );
    } elseif ( $event->registration_limit ) {
        $new_count  = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COALESCE(SUM(party_size), 0) FROM {$reg_table}
             WHERE event_id = %d AND status = 'confirmed'",
            $event_id
        ) );
        $spots_left = max( 0, (int) $event->registration_limit - $new_count );
    }

    wp_send_json_success( [
        'registration_id'    => $registration_id,
        'status'             => $status,
        'fee_amount'         => $fee_amount,
        'spots_left'         => $spots_left,
        'registration_limit' => $event->registration_limit ? (int) $event->registration_limit : null,
    ] );
}


/**
 * AJAX handler: Cancel a registration (frontend — user cancels their own).
 *
 * WHY: Members should be able to cancel their own registrations from the event
 *      detail page. When they cancel, we check if anyone is waitlisted and
 *      auto-promote the oldest waitlisted registrant to confirmed status.
 *      This keeps the event at capacity without Harold having to manually
 *      manage the waitlist.
 */
add_action( 'wp_ajax_sp_cancel_registration', 'sp_ajax_cancel_registration' );

function sp_ajax_cancel_registration(): void {
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_event_register' ) ) {
        wp_send_json_error( __( 'Security check failed. Please refresh and try again.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $registration_id = (int) ( $_POST['registration_id'] ?? 0 );
    $event_id        = (int) ( $_POST['event_id'] ?? 0 );

    if ( ! $registration_id || ! $event_id ) {
        wp_send_json_error( __( 'Invalid registration.', 'societypress' ) );
    }

    // Fetch the registration to verify ownership
    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d AND event_id = %d",
        $registration_id, $event_id
    ) );

    if ( ! $reg ) {
        wp_send_json_error( __( 'Registration not found.', 'societypress' ) );
    }

    // Security: only the registration owner can cancel their own
    if ( $reg->user_id && (int) $reg->user_id !== get_current_user_id() ) {
        wp_send_json_error( __( 'You can only cancel your own registration.', 'societypress' ) );
    }

    // WHY: Guest registrations have user_id = NULL. Without this check, any logged-in
    // member could cancel a guest's registration by guessing the registration ID.
    // Only admins should be able to cancel guest registrations.
    if ( ! $reg->user_id && ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( [ 'message' => __( 'You cannot cancel this registration.', 'societypress' ) ] );
    }

    // Soft-delete: set status to cancelled (keep record for reporting)
    $wpdb->update(
        $reg_table,
        [ 'status' => 'cancelled' ],
        [ 'id' => $registration_id ],
        [ '%s' ],
        [ '%d' ]
    );

    // Audit: log cancellations — they affect capacity and waitlist promotion.
    $evt_table   = $wpdb->prefix . 'sp_events';
    $event_title = $wpdb->get_var( $wpdb->prepare(
        "SELECT title FROM {$evt_table} WHERE id = %d", $event_id
    ) );
    $canceller   = wp_get_current_user()->display_name ?: 'User #' . get_current_user_id();
    sp_audit(
        'event_cancellation',
        sprintf( '%s cancelled registration #%d for "%s"', $canceller, $registration_id, $event_title ?: "Event #{$event_id}" ),
        'event_registration',
        $registration_id
    );

    // If they were confirmed, a spot just opened — try to promote from waitlist
    // WHY: Pass the slot_id so promotion happens at the slot level, not event level.
    if ( $reg->status === 'confirmed' ) {
        sp_maybe_promote_from_waitlist( $event_id, $reg->slot_id ? (int) $reg->slot_id : null );
    }

    wp_send_json_success( [ 'cancelled' => true ] );
}


/**
 * Promote the oldest waitlisted registrant to confirmed status.
 *
 * WHY: When a confirmed registration is cancelled (or admin-deleted), we check
 *      if there's anyone on the waitlist. If so, the longest-waiting person
 *      gets automatically promoted. This keeps events at capacity without
 *      manual intervention. We only promote if there's actually room — we
 *      re-check capacity to be safe against race conditions.
 *
 * NOTE: We promote one at a time in a loop to handle party_size correctly.
 *       A party of 3 can't be promoted if only 2 spots are available, but
 *       a party of 1 behind them in line could still get promoted.
 *
 * @param int $event_id The event to check waitlist for.
 */
function sp_maybe_promote_from_waitlist( int $event_id, ?int $slot_id = null ): void {
    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';
    $evt_table = $wpdb->prefix . 'sp_events';

    // Slot-aware promotion: if a slot_id is provided, only promote waitlisted
    // registrants for THAT slot using slot-level capacity.
    // WHY: When slot A has a cancellation, we should only promote people waiting
    //      for slot A — not people waiting for slot B.
    if ( $slot_id ) {
        $slot = sp_slot_get( $slot_id );
        if ( ! $slot ) {
            return;
        }

        // If slot has no capacity limit, promote all waitlisted for this slot
        if ( $slot->capacity === null ) {
            $wpdb->query( $wpdb->prepare(
                "UPDATE {$reg_table} SET status = 'confirmed'
                 WHERE event_id = %d AND slot_id = %d AND status = 'waitlisted'",
                $event_id, $slot_id
            ) );
            return;
        }

        $available = sp_slot_get_remaining_capacity( $slot_id );
        if ( $available <= 0 ) {
            return;
        }

        $waitlisted = $wpdb->get_results( $wpdb->prepare(
            "SELECT id, party_size FROM {$reg_table}
             WHERE event_id = %d AND slot_id = %d AND status = 'waitlisted'
             ORDER BY registered_at ASC",
            $event_id, $slot_id
        ) );

        $full_event = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$evt_table} WHERE id = %d", $event_id
        ) );

        foreach ( $waitlisted as $wait_reg ) {
            if ( (int) $wait_reg->party_size <= $available ) {
                $wpdb->update(
                    $reg_table,
                    [ 'status' => 'confirmed' ],
                    [ 'id' => $wait_reg->id ],
                    [ '%s' ],
                    [ '%d' ]
                );
                $available -= (int) $wait_reg->party_size;

                if ( $full_event ) {
                    sp_send_waitlist_promotion_email( $full_event, $wait_reg->id );
                }

                if ( $available <= 0 ) {
                    break;
                }
            }
        }
        return;
    }

    // Event-level promotion (no slot) — original logic
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT registration_limit FROM {$evt_table} WHERE id = %d", $event_id
    ) );

    if ( ! $event ) {
        return;
    }

    // If no capacity limit, promote all waitlisted to confirmed
    // WHY: If Harold removes a capacity limit, anyone on the waitlist should
    //      be confirmed immediately — there's no reason to keep them waiting.
    if ( ! $event->registration_limit ) {
        $wpdb->query( $wpdb->prepare(
            "UPDATE {$reg_table} SET status = 'confirmed'
             WHERE event_id = %d AND slot_id IS NULL AND status = 'waitlisted'",
            $event_id
        ) );
        return;
    }

    // Count current confirmed spots used (event-level, no slot)
    $confirmed_count = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(party_size), 0) FROM {$reg_table}
         WHERE event_id = %d AND slot_id IS NULL AND status = 'confirmed'",
        $event_id
    ) );

    $available = (int) $event->registration_limit - $confirmed_count;

    if ( $available <= 0 ) {
        return;
    }

    // Get waitlisted registrants in order (oldest first) — event-level only
    $waitlisted = $wpdb->get_results( $wpdb->prepare(
        "SELECT id, party_size FROM {$reg_table}
         WHERE event_id = %d AND slot_id IS NULL AND status = 'waitlisted'
         ORDER BY registered_at ASC",
        $event_id
    ) );

    // Fetch full event data for promotion emails
    $full_event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$evt_table} WHERE id = %d", $event_id
    ) );

    foreach ( $waitlisted as $wait_reg ) {
        if ( (int) $wait_reg->party_size <= $available ) {
            $wpdb->update(
                $reg_table,
                [ 'status' => 'confirmed' ],
                [ 'id' => $wait_reg->id ],
                [ '%s' ],
                [ '%d' ]
            );
            $available -= (int) $wait_reg->party_size;

            // Send promotion email — "You got a spot!"
            // WHY: When someone moves from waitlist to confirmed, they need
            //      to know immediately so they can plan to attend.
            if ( $full_event ) {
                sp_send_waitlist_promotion_email( $full_event, $wait_reg->id );
            }

            if ( $available <= 0 ) {
                break;
            }
        }
    }
}


// ============================================================================
// EVENTS — ADMIN REGISTRATION MANAGEMENT
// ============================================================================
//
// WHY: Harold needs to see who registered for each event, add walk-in
//      registrations the day of, mark attendance after the event, export
//      the list to CSV for treasurer reports, and manage waitlists.
//      This section adds a "Registrations" panel to the event edit page
//      (only shown when editing an existing event with registration enabled).
// ============================================================================

/**
 * Render the registrations management section on the event edit page.
 *
 * WHY: This is called from sp_render_event_edit_page() when editing an existing
 *      event that has registration enabled. It shows a table of all registrants,
 *      bulk attendance controls, walk-in add form, and export button.
 *
 * @param object $event The event database row.
 */
function sp_render_event_registrations_section( object $event ): void {
    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    // Fetch all registrations for this event, joined with WordPress users table
    // WHY: Member registrations link to wp_users for display name and email,
    //      while guest registrations store name/email directly. We need both.
    $slots_table = $wpdb->prefix . 'sp_event_slots';
    $registrations = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, u.display_name AS wp_name, u.user_email AS wp_email,
                s.start_time AS slot_start, s.end_time AS slot_end, s.description AS slot_desc
         FROM {$reg_table} r
         LEFT JOIN {$wpdb->users} u ON r.user_id = u.ID
         LEFT JOIN {$slots_table} s ON r.slot_id = s.id
         WHERE r.event_id = %d
         ORDER BY
            FIELD(r.status, 'confirmed', 'waitlisted', 'cancelled'),
            r.registered_at ASC",
        $event->id
    ) );

    // Check if this event has any slots (for showing/hiding the Slot column)
    $event_has_slots = ! empty( sp_slots_get_by_event( (int) $event->id, true ) );

    // Count by status for the summary line
    $confirmed_count  = 0;
    $waitlisted_count = 0;
    $cancelled_count  = 0;
    $total_attending  = 0;
    foreach ( $registrations as $reg ) {
        if ( $reg->status === 'confirmed' ) {
            $confirmed_count++;
            $total_attending += (int) $reg->party_size;
        } elseif ( $reg->status === 'waitlisted' ) {
            $waitlisted_count++;
        } elseif ( $reg->status === 'cancelled' ) {
            $cancelled_count++;
        }
    }

    // Has the event already happened? (for attendance tracking)
    // WHY: Attendance dropdowns only appear for past events — no point in
    //      tracking attendance for something that hasn't happened yet.
    $event_past = $event->event_date < current_time( 'Y-m-d' );

    ?>
    <style>
        /*
         * sp_render_event_registrations_section() — scoped styles
         *
         * WHY: All presentational styles for the admin registrations section are
         *      collected here rather than scattered as inline style= attributes.
         *      This makes visual changes easy to find in one place, keeps the HTML
         *      readable, and satisfies the theme's no-inline-styles rule.
         *
         *      Dynamic per-row values (status badge color, payment badge color) that
         *      depend on PHP variables at runtime remain as inline styles on those
         *      specific elements — they cannot be static CSS rules.
         *
         *      JavaScript-toggled display:none values also remain inline so JS can
         *      flip them without a class toggle dance.
         */

        /* ---- Section heading ---- */
        .sp-event-reg-heading {
            margin: 30px 0 0 0;
            padding-bottom: 8px;
            border-bottom: 1px solid #c3c4c7;
        }
        /* Subtitle: "N confirmed / M capacity, P waitlisted (Q people total)" */
        .sp-event-reg-heading-meta {
            font-size: 14px;
            font-weight: normal;
            color: #787c82;
            margin-left: 8px;
        }

        /* ---- Action-buttons row (Add Walk-in, Export CSV, Mark All Attended) ---- */
        .sp-event-reg-actions {
            margin: 12px 0;
            display: flex;
            gap: 8px;
            flex-wrap: wrap;
        }

        /* ---- Walk-in form panel ---- */
        /* WHY: Static layout styles only — display:none stays inline for JS toggle */
        .sp-event-reg-walkin-panel {
            padding: 16px;
            background: #f6f7f7;
            border: 1px solid #c3c4c7;
            border-radius: 4px;
            margin-bottom: 16px;
        }
        .sp-event-reg-walkin-panel h3 {
            margin: 0 0 12px 0;
        }
        .sp-event-reg-walkin-panel .form-table {
            margin: 0;
        }
        /* Wrapper for the Save/Cancel buttons at the bottom of the walk-in form */
        .sp-event-reg-walkin-btns {
            margin-top: 12px;
        }
        /* Inline feedback message below the walk-in form buttons */
        /* WHY: margin-top stays here; display:none stays inline for JS control */
        .sp-event-reg-walkin-msg {
            margin-top: 8px;
        }

        /* ---- Empty-state message ---- */
        .sp-event-reg-empty {
            color: #787c82;
            font-style: italic;
        }

        /* ---- Registrations table column widths ---- */
        /* WHY: Column widths defined here rather than per-th inline so they're
         *      easy to adjust when column sets change (e.g., slot/attended cols
         *      are conditional). These match the original inline values exactly. */
        #sp-registrations-table th.sp-event-reg-col-name       { width: 22%; }
        #sp-registrations-table th.sp-event-reg-col-email      { width: 18%; }
        #sp-registrations-table th.sp-event-reg-col-slot       { width: 14%; }
        #sp-registrations-table th.sp-event-reg-col-party      { width:  6%; }
        #sp-registrations-table th.sp-event-reg-col-status     { width: 10%; }
        #sp-registrations-table th.sp-event-reg-col-fee        { width: 10%; }
        #sp-registrations-table th.sp-event-reg-col-registered { width: 12%; }
        #sp-registrations-table th.sp-event-reg-col-attended   { width: 10%; }
        #sp-registrations-table th.sp-event-reg-col-actions    { width:  5%; }

        /* ---- Per-row cell content ---- */
        /* "(Member)" / "(Guest)" label beside the registrant name */
        .sp-event-reg-type-label {
            color: #787c82;
            font-size: 12px;
            margin-left: 4px;
        }
        /* Notes line shown under the registrant name */
        .sp-event-reg-notes {
            color: #787c82;
            font-size: 12px;
        }
        /* Slot time range text */
        .sp-event-reg-slot-time {
            font-size: 12px;
        }
        /* Slot description sub-line */
        .sp-event-reg-slot-desc {
            font-size: 11px;
            color: #787c82;
        }
        /* Em-dash shown in the slot cell when registrant has no slot */
        .sp-event-reg-slot-none {
            color: #787c82;
            font-size: 12px;
        }

        /* ---- Status badge ---- */
        /* WHY: Shape/size/weight are static; background-color and color are
         *      dynamic PHP values and stay as inline styles on each badge. */
        .sp-event-reg-status-badge {
            display: inline-block;
            padding: 2px 8px;
            border-radius: 3px;
            font-size: 12px;
            font-weight: 500;
        }

        /* ---- Payment badge ---- */
        /* Same reasoning as status badge — colors are dynamic PHP values. */
        .sp-event-reg-pay-badge {
            display: inline-block;
            padding: 1px 6px;
            border-radius: 3px;
            font-size: 11px;
            font-weight: 500;
        }

        /* ---- Refund button ---- */
        /* WHY: Danger-red link button that appears inline in the fee cell.
         *      Color is static here because it's always the WP admin danger red. */
        .sp-event-reg-refund-btn {
            color: #d63638;
            font-size: 11px;
            margin-left: 4px;
        }

        /* ---- "Free" label in fee column ---- */
        .sp-event-reg-free-label {
            color: #787c82;
        }

        /* ---- Attendance select ---- */
        .sp-event-reg-attendance-select {
            font-size: 12px;
        }

        /* ---- N/A placeholder in the Attended cell for non-confirmed rows ---- */
        .sp-event-reg-attended-na {
            color: #c3c4c7;
        }

        /* ---- Cancel button ---- */
        /* WHY: Danger-red link button in the Actions column. */
        .sp-event-reg-cancel-btn {
            color: #d63638;
            font-size: 12px;
        }
    </style>

    <div class="sp-admin-registrations" id="sp-admin-registrations">
        <h2 class="sp-event-reg-heading">
            <?php esc_html_e( 'Registrations', 'societypress' ); ?>
            <span class="sp-event-reg-heading-meta">
                <?php echo $confirmed_count; ?> confirmed<?php
                if ( $event->registration_limit ) {
                    echo ' / ' . (int) $event->registration_limit . ' capacity';
                }
                if ( $waitlisted_count ) {
                    echo ', ' . $waitlisted_count . ' waitlisted';
                }
                echo ' (' . $total_attending . ' people total)';
                ?>
            </span>
        </h2>

        <!-- Action buttons row -->
        <div class="sp-event-reg-actions">
            <button type="button" class="button" id="sp-add-walkin-toggle">
                + Add Walk-in
            </button>
            <?php if ( count( $registrations ) > 0 ) : ?>
                <a href="<?php echo esc_url( admin_url( 'admin-ajax.php?action=sp_export_registrations&event_id=' . $event->id . '&nonce=' . wp_create_nonce( 'sp_export_registrations' ) ) ); ?>"
                   class="button">
                    Export CSV
                </a>
            <?php endif; ?>
            <?php if ( $event_past && $confirmed_count > 0 ) : ?>
                <button type="button" class="button" id="sp-bulk-attended" title="Mark all confirmed as attended">
                    Mark All Attended
                </button>
            <?php endif; ?>
        </div>

        <!-- Walk-in add form (hidden until toggled) -->
        <!-- WHY: Day-of-event, people show up at the door. Harold needs to add     -->
        <!--      them quickly so they show up on the registration list, and the     -->
        <!--      treasurer can reconcile who paid at the door.                      -->
        <div id="sp-walkin-form" class="sp-event-reg-walkin-panel" style="display: none;">
            <h3>Add Walk-in Registration</h3>
            <table class="form-table" role="presentation">
                <tr>
                    <th scope="row"><label for="sp-walkin-name"><?php esc_html_e( 'Name', 'societypress' ); ?></label></th>
                    <td><input type="text" id="sp-walkin-name" class="regular-text" required></td>
                </tr>
                <tr>
                    <th scope="row"><label for="sp-walkin-email"><?php esc_html_e( 'Email', 'societypress' ); ?></label></th>
                    <td><input type="email" id="sp-walkin-email" class="regular-text"></td>
                </tr>
                <tr>
                    <th scope="row"><label for="sp-walkin-phone"><?php esc_html_e( 'Phone', 'societypress' ); ?></label></th>
                    <td><input type="tel" id="sp-walkin-phone" class="regular-text"></td>
                </tr>
                <?php if ( $event_has_slots ) : ?>
                <tr>
                    <th scope="row"><label for="sp-walkin-slot"><?php esc_html_e( 'Time Slot', 'societypress' ); ?></label></th>
                    <td>
                        <select id="sp-walkin-slot">
                            <option value="">— No slot —</option>
                            <?php
                            $walkin_slots = sp_slots_get_by_event( (int) $event->id, true );
                            foreach ( $walkin_slots as $ws ) :
                                $ws_time = sp_slot_format_time_range( $ws );
                            ?>
                                <option value="<?php echo esc_attr( $ws->id ); ?>">
                                    <?php echo esc_html( $ws_time ); ?>
                                    <?php if ( $ws->description ) echo ' — ' . esc_html( $ws->description ); ?>
                                </option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <?php endif; ?>
                <tr>
                    <th scope="row"><label for="sp-walkin-party"><?php esc_html_e( 'Party Size', 'societypress' ); ?></label></th>
                    <td>
                        <select id="sp-walkin-party">
                            <?php for ( $i = 1; $i <= 10; $i++ ) : ?>
                                <option value="<?php echo $i; ?>"><?php echo $i; ?></option>
                            <?php endfor; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th scope="row"><label for="sp-walkin-notes"><?php esc_html_e( 'Notes', 'societypress' ); ?></label></th>
                    <td><input type="text" id="sp-walkin-notes" class="regular-text" placeholder="e.g., Paid cash at door"></td>
                </tr>
            </table>
            <div class="sp-event-reg-walkin-btns">
                <button type="button" class="button button-primary" id="sp-walkin-save">Add Registration</button>
                <button type="button" class="button" id="sp-walkin-cancel">Cancel</button>
            </div>
            <div id="sp-walkin-message" class="sp-event-reg-walkin-msg" style="display: none;"></div>
        </div>

        <!-- Registrations table -->
        <?php if ( empty( $registrations ) ) : ?>
            <p class="sp-event-reg-empty"><?php esc_html_e( 'No registrations yet.', 'societypress' ); ?></p>
        <?php else : ?>
            <table class="wp-list-table widefat fixed striped" id="sp-registrations-table">
                <thead>
                    <tr>
                        <th class="sp-event-reg-col-name">Name</th>
                        <th class="sp-event-reg-col-email">Email</th>
                        <?php if ( $event_has_slots ) : ?>
                            <th class="sp-event-reg-col-slot">Slot</th>
                        <?php endif; ?>
                        <th class="sp-event-reg-col-party">Party</th>
                        <th class="sp-event-reg-col-status">Status</th>
                        <th class="sp-event-reg-col-fee">Fee</th>
                        <th class="sp-event-reg-col-registered">Registered</th>
                        <?php if ( $event_past ) : ?>
                            <th class="sp-event-reg-col-attended">Attended</th>
                        <?php endif; ?>
                        <th class="sp-event-reg-col-actions">Actions</th>
                    </tr>
                </thead>
                <tbody>
                    <?php foreach ( $registrations as $reg ) :
                        // Display name: WordPress user name for members, guest_name for guests
                        $display_name = $reg->user_id
                            ? esc_html( $reg->wp_name ?: 'Member #' . $reg->user_id )
                            : esc_html( $reg->guest_name ?: 'Guest' );
                        // Display email: from wp_users for members, guest_email for guests
                        $display_email = $reg->user_id
                            ? esc_html( $reg->wp_email ?? '' )
                            : esc_html( $reg->guest_email ?? '' );
                        // Status badge colors matching the rest of the plugin
                        $status_colors = [
                            'confirmed'  => '#00a32a',
                            'waitlisted' => '#dba617',
                            'cancelled'  => '#d63638',
                        ];
                        $badge_color = $status_colors[ $reg->status ] ?? '#787c82';
                        $type_label = $reg->user_id ? 'Member' : 'Guest';
                    ?>
                        <tr data-reg-id="<?php echo esc_attr( $reg->id ); ?>"
                            class="<?php echo $reg->status === 'cancelled' ? 'sp-reg-row-cancelled' : ''; ?>">
                            <td>
                                <strong><?php echo $display_name; ?></strong>
                                <span class="sp-event-reg-type-label">(<?php echo $type_label; ?>)</span>
                                <?php if ( ! empty( $reg->notes ) ) : ?>
                                    <br><em class="sp-event-reg-notes"><?php echo esc_html( $reg->notes ); ?></em>
                                <?php endif; ?>
                            </td>
                            <td><?php echo $display_email; ?></td>
                            <?php if ( $event_has_slots ) : ?>
                                <td>
                                    <?php if ( $reg->slot_start ) : ?>
                                        <span class="sp-event-reg-slot-time">
                                            <?php echo esc_html( wp_date( 'g:i A', strtotime( $reg->slot_start ) ) . ' – ' . wp_date( 'g:i A', strtotime( $reg->slot_end ) ) ); ?>
                                        </span>
                                        <?php if ( $reg->slot_desc ) : ?>
                                            <br><em class="sp-event-reg-slot-desc"><?php echo esc_html( $reg->slot_desc ); ?></em>
                                        <?php endif; ?>
                                    <?php else : ?>
                                        <span class="sp-event-reg-slot-none">—</span>
                                    <?php endif; ?>
                                </td>
                            <?php endif; ?>
                            <td><?php echo (int) $reg->party_size; ?></td>
                            <td>
                                <?php
                                /*
                                 * WHY background/color stay inline: $badge_color is a PHP variable
                                 * resolved per-row at runtime — it cannot be a static CSS rule.
                                 * The alpha-channel trick (...22) keeps the swatch readable on white.
                                 */
                                ?>
                                <?php
                                // WHY: i18n status labels — translators need static strings, not ucfirst() on DB values
                                $reg_status_labels = [
                                    'confirmed'  => __( 'Confirmed', 'societypress' ),
                                    'waitlisted' => __( 'Waitlisted', 'societypress' ),
                                    'cancelled'  => __( 'Cancelled', 'societypress' ),
                                    'pending'    => __( 'Pending', 'societypress' ),
                                ];
                                $reg_status_display = $reg_status_labels[ $reg->status ] ?? ucfirst( $reg->status );
                                ?>
                                <span class="sp-event-reg-status-badge"
                                      style="background: <?php echo $badge_color; ?>22; color: <?php echo $badge_color; ?>;">
                                    <?php echo esc_html( $reg_status_display ); ?>
                                </span>
                            </td>
                            <td>
                                <?php if ( (float) $reg->fee_amount > 0 ) : ?>
                                    <?php echo esc_html( sp_format_currency( $reg->fee_amount ) ); ?>
                                    <?php
                                    // Color-code the payment status badge for quick visual scanning
                                    $pay_colors = [
                                        'paid'     => '#00a32a',
                                        'refunded' => '#d63638',
                                        'pending'  => '#dba617',
                                        'none'     => '#787c82',
                                    ];
                                    $pay_color = $pay_colors[ $reg->payment_status ] ?? '#787c82';
                                    ?>
                                    <?php
                                    /*
                                     * WHY background/color stay inline: $pay_color is a PHP variable
                                     * resolved per-row at runtime — same reasoning as status badge.
                                     */
                                    ?>
                                    <span class="sp-event-reg-pay-badge"
                                          style="background: <?php echo $pay_color; ?>22; color: <?php echo $pay_color; ?>;">
                                        <?php echo esc_html( ucfirst( $reg->payment_status ) ); ?>
                                        <?php if ( $reg->payment_method === 'at_door' && $reg->payment_status === 'pending' ) : ?>
                                            (at door)
                                        <?php endif; ?>
                                    </span>
                                    <?php
                                    // Show refund button for Stripe and PayPal payments that are marked as paid
                                    // WHY: One-click refund right in the table. Harold shouldn't
                                    //      have to log into the payment dashboard to refund someone.
                                    if ( $reg->payment_status === 'paid' && in_array( $reg->payment_method, [ 'stripe', 'paypal' ], true ) ) : ?>
                                        <button type="button" class="button-link sp-admin-refund-btn sp-event-reg-refund-btn"
                                                data-reg-id="<?php echo esc_attr( $reg->id ); ?>"
                                                title="<?php echo esc_attr( sprintf( __( 'Issue a full refund via %s', 'societypress' ), ucfirst( $reg->payment_method ) ) ); ?>">
                                            <?php esc_html_e( 'Refund', 'societypress' ); ?>
                                        </button>
                                    <?php endif; ?>
                                <?php else : ?>
                                    <span class="sp-event-reg-free-label">Free</span>
                                <?php endif; ?>
                            </td>
                            <td><?php echo esc_html( wp_date( 'M j, g:ia', strtotime( $reg->registered_at ) ) ); ?></td>
                            <?php if ( $event_past ) : ?>
                                <td>
                                    <?php if ( $reg->status === 'confirmed' ) : ?>
                                        <select class="sp-attendance-select sp-event-reg-attendance-select"
                                                data-reg-id="<?php echo esc_attr( $reg->id ); ?>">
                                            <option value="" <?php selected( $reg->attended, null ); ?>>--</option>
                                            <option value="1" <?php selected( $reg->attended, '1' ); ?>>Yes</option>
                                            <option value="0" <?php selected( $reg->attended, '0' ); ?>>No-show</option>
                                        </select>
                                    <?php else : ?>
                                        <span class="sp-event-reg-attended-na">--</span>
                                    <?php endif; ?>
                                </td>
                            <?php endif; ?>
                            <td>
                                <?php if ( $reg->status !== 'cancelled' ) : ?>
                                    <button type="button" class="button-link sp-admin-cancel-reg sp-event-reg-cancel-btn"
                                            data-reg-id="<?php echo esc_attr( $reg->id ); ?>"
                                            title="Cancel this registration">
                                        Cancel
                                    </button>
                                <?php endif; ?>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                </tbody>
            </table>
        <?php endif; ?>
    </div>

    <!-- Registration Management JavaScript -->
    <script>
    (function() {
        'use strict';
        var eventId = <?php echo (int) $event->id; ?>;
        var ajaxUrl = '<?php echo esc_js( admin_url( "admin-ajax.php" ) ); ?>';
        var nonce   = '<?php echo wp_create_nonce( "sp_admin_registration" ); ?>';

        // ---- Walk-in form toggle ----
        var walkinToggle = document.getElementById('sp-add-walkin-toggle');
        var walkinForm   = document.getElementById('sp-walkin-form');
        var walkinCancel = document.getElementById('sp-walkin-cancel');

        if (walkinToggle && walkinForm) {
            walkinToggle.addEventListener('click', function() {
                walkinForm.style.display = walkinForm.style.display === 'none' ? '' : 'none';
            });
        }
        if (walkinCancel) {
            walkinCancel.addEventListener('click', function() {
                walkinForm.style.display = 'none';
            });
        }

        // ---- Walk-in save ----
        var walkinSave = document.getElementById('sp-walkin-save');
        var walkinMsg  = document.getElementById('sp-walkin-message');
        if (walkinSave) {
            walkinSave.addEventListener('click', function() {
                var name  = document.getElementById('sp-walkin-name').value.trim();
                var email = document.getElementById('sp-walkin-email').value.trim();
                var phone = document.getElementById('sp-walkin-phone').value.trim();
                var party = document.getElementById('sp-walkin-party').value;
                var notes = document.getElementById('sp-walkin-notes').value.trim();

                if (!name) {
                    walkinMsg.textContent = '<?php echo esc_js( __( 'Please enter a name.', 'societypress' ) ); ?>';
                    walkinMsg.style.display = 'block';
                    walkinMsg.style.color = '#d63638';
                    return;
                }

                walkinSave.disabled = true;
                walkinSave.textContent = '<?php echo esc_js( __( "Adding\u2026", "societypress" ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_admin_add_walkin');
                fd.append('event_id', eventId);
                fd.append('guest_name', name);
                fd.append('guest_email', email);
                fd.append('guest_phone', phone);
                fd.append('party_size', party);
                fd.append('notes', notes);
                fd.append('nonce', nonce);
                var wSlotEl = document.getElementById('sp-walkin-slot');
                if (wSlotEl && wSlotEl.value) { fd.append('slot_id', wSlotEl.value); }

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            location.reload();
                        } else {
                            walkinMsg.textContent = data.data || '<?php echo esc_js( __( 'Could not add registration.', 'societypress' ) ); ?>';
                            walkinMsg.style.display = 'block';
                            walkinMsg.style.color = '#d63638';
                            walkinSave.disabled = false;
                            walkinSave.textContent = '<?php echo esc_js( __( 'Add Registration', 'societypress' ) ); ?>';
                        }
                    })
                    .catch(function() {
                        walkinMsg.textContent = '<?php echo esc_js( __( 'Something went wrong.', 'societypress' ) ); ?>';
                        walkinMsg.style.display = 'block';
                        walkinMsg.style.color = '#d63638';
                        walkinSave.disabled = false;
                        walkinSave.textContent = '<?php echo esc_js( __( 'Add Registration', 'societypress' ) ); ?>';
                    });
            });
        }

        // ---- Admin cancel registration ----
        document.querySelectorAll('.sp-admin-cancel-reg').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var self = this;
                spConfirm('<?php echo esc_js( __( 'Cancel this registration?', 'societypress' ) ); ?>', function() {
                var regId = self.getAttribute('data-reg-id');

                var fd = new FormData();
                fd.append('action', 'sp_admin_cancel_registration');
                fd.append('registration_id', regId);
                fd.append('event_id', eventId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            location.reload();
                        } else {
                            alert(data.data || '<?php echo esc_js( __( 'Could not cancel.', 'societypress' ) ); ?>');
                        }
                    });
            });
        });

        // ---- Attendance tracking (individual select change) ----
        document.querySelectorAll('.sp-attendance-select').forEach(function(sel) {
            sel.addEventListener('change', function() {
                var regId = this.getAttribute('data-reg-id');
                var value = this.value;

                var fd = new FormData();
                fd.append('action', 'sp_admin_update_attendance');
                fd.append('registration_id', regId);
                fd.append('attended', value);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (!data.success) {
                            alert(data.data || '<?php echo esc_js( __( 'Could not update attendance.', 'societypress' ) ); ?>');
                        }
                    });
            });
        });

        // ---- Bulk mark all as attended ----
        var bulkAttended = document.getElementById('sp-bulk-attended');
        if (bulkAttended) {
            bulkAttended.addEventListener('click', function() {
                spConfirm('<?php echo esc_js( __( 'Mark all confirmed registrants as attended?', 'societypress' ) ); ?>', function() {
                var fd = new FormData();
                fd.append('action', 'sp_admin_bulk_attendance');
                fd.append('event_id', eventId);
                fd.append('attended', '1');
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            document.querySelectorAll('.sp-attendance-select').forEach(function(sel) {
                                sel.value = '1';
                            });
                            alert('<?php echo esc_js( __( 'All confirmed registrants marked as attended.', 'societypress' ) ); ?>');
                        } else {
                            alert(data.data || '<?php echo esc_js( __( 'Could not update attendance.', 'societypress' ) ); ?>');
                        }
                    });
            });
        }

        // ---- Stripe refund button ----
        // WHY: One-click refund for Stripe payments. Calls our AJAX handler
        //      which calls Stripe's Refund API. The admin gets confirmation
        //      and the row updates without a page reload.
        document.querySelectorAll('.sp-admin-refund-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var refundBtn = this;
                spConfirm('<?php echo esc_js( __( 'Issue a full refund for this payment? This cannot be undone.', 'societypress' ) ); ?>', function() {
                var regId = refundBtn.getAttribute('data-reg-id');

                refundBtn.disabled = true;
                refundBtn.textContent = '<?php echo esc_js( __( "Refunding\u2026", "societypress" ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_admin_refund_payment');
                fd.append('registration_id', regId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            location.reload();
                        } else {
                            alert(data.data || '<?php echo esc_js( __( "Refund failed.", "societypress" ) ); ?>');
                            refundBtn.disabled = false;
                            refundBtn.textContent = '<?php echo esc_js( __( "Refund", "societypress" ) ); ?>';
                        }
                    })
                    .catch(function() {
                        alert('<?php echo esc_js( __( 'Something went wrong. Please try again.', 'societypress' ) ); ?>');
                        refundBtn.disabled = false;
                        refundBtn.textContent = '<?php echo esc_js( __( "Refund", "societypress" ) ); ?>';
                    });
            });
        });

    })();
    </script>
    <style>
        .sp-reg-row-cancelled td { opacity: 0.5; }
        #sp-registrations-table th { font-size: 13px; }
    </style>
    <?php
}
// END sp_render_event_registrations_section
function sp_ajax_admin_add_walkin(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_admin_registration' ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $event_id   = (int) ( $_POST['event_id'] ?? 0 );
    $guest_name = sanitize_text_field( $_POST['guest_name'] ?? '' );

    if ( ! $event_id || ! $guest_name ) {
        wp_send_json_error( __( 'Event ID and name are required.', 'societypress' ) );
    }

    $slot_id = ! empty( $_POST['slot_id'] ) ? (int) $_POST['slot_id'] : null;

    $wpdb->insert( $reg_table, [
        'event_id'       => $event_id,
        'slot_id'        => $slot_id,
        'user_id'        => null,
        'guest_name'     => $guest_name,
        'guest_email'    => sanitize_email( $_POST['guest_email'] ?? '' ),
        'guest_phone'    => sanitize_text_field( $_POST['guest_phone'] ?? '' ),
        'status'         => 'confirmed',
        'party_size'     => max( 1, (int) ( $_POST['party_size'] ?? 1 ) ),
        'fee_amount'     => 0.00,
        'payment_status' => 'none',
        'notes'          => sanitize_text_field( $_POST['notes'] ?? '' ),
        'registered_at'  => current_time( 'mysql' ),
    ] );

    if ( $wpdb->insert_id ) {
        wp_send_json_success( [ 'registration_id' => $wpdb->insert_id ] );
    } else {
        wp_send_json_error( __( 'Could not add registration.', 'societypress' ) );
    }
}


/**
 * AJAX: Admin cancel a registration.
 *
 * WHY: Harold may need to cancel someone's registration (no-show pattern,
 *      refund request, duplicate, etc). This also triggers waitlist
 *      auto-promotion so the next person in line gets the spot.
 */
add_action( 'wp_ajax_sp_admin_cancel_registration', 'sp_ajax_admin_cancel_registration' );

function sp_ajax_admin_cancel_registration(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_admin_registration' ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $registration_id = (int) ( $_POST['registration_id'] ?? 0 );
    $event_id        = (int) ( $_POST['event_id'] ?? 0 );

    if ( ! $registration_id ) {
        wp_send_json_error( __( 'Invalid registration.', 'societypress' ) );
    }

    // Get current status before cancelling (needed for waitlist promotion)
    $old_status = $wpdb->get_var( $wpdb->prepare(
        "SELECT status FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    $wpdb->update(
        $reg_table,
        [ 'status' => 'cancelled' ],
        [ 'id' => $registration_id ],
        [ '%s' ],
        [ '%d' ]
    );

    // If was confirmed, try to promote someone from the waitlist
    // WHY: Pass slot_id so promotion happens at the slot level when applicable.
    if ( $old_status === 'confirmed' && $event_id ) {
        $cancelled_slot = $wpdb->get_var( $wpdb->prepare(
            "SELECT slot_id FROM {$reg_table} WHERE id = %d", $registration_id
        ) );
        sp_maybe_promote_from_waitlist( $event_id, $cancelled_slot ? (int) $cancelled_slot : null );
    }

    wp_send_json_success( [ 'cancelled' => true ] );
}


/**
 * AJAX: Update attendance for a single registration.
 *
 * WHY: After an event, Harold goes through the list and marks who showed up
 *      and who didn't. This is important for the society's annual report
 *      (average attendance per event type) and for identifying chronic
 *      no-shows who might be wasting limited spots.
 */
add_action( 'wp_ajax_sp_admin_update_attendance', 'sp_ajax_admin_update_attendance' );

function sp_ajax_admin_update_attendance(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_admin_registration' ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table       = $wpdb->prefix . 'sp_event_registrations';
    $registration_id = (int) ( $_POST['registration_id'] ?? 0 );
    $attended        = $_POST['attended'] ?? '';

    if ( ! $registration_id ) {
        wp_send_json_error( __( 'Invalid registration.', 'societypress' ) );
    }

    // attended: '' = null (not yet recorded), '1' = attended, '0' = no-show
    $attended_val = $attended === '' ? null : (int) $attended;

    $wpdb->update(
        $reg_table,
        [ 'attended' => $attended_val ],
        [ 'id' => $registration_id ],
        [ $attended_val === null ? '%s' : '%d' ],
        [ '%d' ]
    );

    wp_send_json_success();
}


/**
 * AJAX: Bulk mark all confirmed registrations as attended.
 *
 * WHY: For small events where everyone showed up, Harold doesn't want to
 *      click each row individually. One button marks them all at once.
 */
add_action( 'wp_ajax_sp_admin_bulk_attendance', 'sp_ajax_admin_bulk_attendance' );

function sp_ajax_admin_bulk_attendance(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_admin_registration' ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';
    $event_id  = (int) ( $_POST['event_id'] ?? 0 );
    $attended  = (int) ( $_POST['attended'] ?? 1 );

    if ( ! $event_id ) {
        wp_send_json_error( __( 'Invalid event.', 'societypress' ) );
    }

    // Only update rows that haven't been marked yet (attended IS NULL)
    // WHY: Don't overwrite manual no-show markings when bulk-updating.
    $wpdb->query( $wpdb->prepare(
        "UPDATE {$reg_table} SET attended = %d
         WHERE event_id = %d AND status = 'confirmed' AND attended IS NULL",
        $attended, $event_id
    ) );

    wp_send_json_success();
}


/**
 * AJAX: Export registrations to CSV file download.
 *
 * WHY: The treasurer needs a spreadsheet of who registered, how many in their
 *      party, what they owe, and whether they attended. This generates a
 *      downloadable CSV directly from the admin. Uses GET request with nonce
 *      so the browser triggers a file download instead of AJAX response.
 */
add_action( 'wp_ajax_sp_export_registrations', 'sp_ajax_export_registrations' );

function sp_ajax_export_registrations(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_export_registrations' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';
    $evt_table = $wpdb->prefix . 'sp_events';

    $event_id = (int) ( $_GET['event_id'] ?? 0 );
    if ( ! $event_id ) {
        wp_die( esc_html__( 'Invalid event.', 'societypress' ) );
    }

    // Get event title for a meaningful filename
    $event_title = $wpdb->get_var( $wpdb->prepare(
        "SELECT title FROM {$evt_table} WHERE id = %d", $event_id
    ) );
    $safe_title = sanitize_file_name( $event_title ?: 'event-' . $event_id );

    // Fetch registrations with WordPress user data
    $registrations = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, u.display_name AS wp_name, u.user_email AS wp_email
         FROM {$reg_table} r
         LEFT JOIN {$wpdb->users} u ON r.user_id = u.ID
         WHERE r.event_id = %d
         ORDER BY FIELD(r.status, 'confirmed', 'waitlisted', 'cancelled'), r.registered_at ASC",
        $event_id
    ) );

    // Send CSV headers for browser file download
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="registrations-' . $safe_title . '.csv"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $output = fopen( 'php://output', 'w' );

    // CSV header row — i18n so exported files match the admin's language
    fputcsv( $output, [
        __( 'Name', 'societypress' ), __( 'Email', 'societypress' ), __( 'Phone', 'societypress' ),
        __( 'Type', 'societypress' ), __( 'Party Size', 'societypress' ), __( 'Status', 'societypress' ),
        __( 'Fee', 'societypress' ), __( 'Payment Status', 'societypress' ), __( 'Attended', 'societypress' ),
        __( 'Notes', 'societypress' ), __( 'Registered At', 'societypress' )
    ] );

    // WHY: i18n status labels — translators need static strings, not ucfirst() on DB values
    $csv_status_labels = [
        'confirmed'  => __( 'Confirmed', 'societypress' ),
        'waitlisted' => __( 'Waitlisted', 'societypress' ),
        'cancelled'  => __( 'Cancelled', 'societypress' ),
        'pending'    => __( 'Pending', 'societypress' ),
    ];

    foreach ( $registrations as $reg ) {
        $name  = $reg->user_id ? ( $reg->wp_name ?: 'Member #' . $reg->user_id ) : ( $reg->guest_name ?: __( 'Guest', 'societypress' ) );
        $email = $reg->user_id ? ( $reg->wp_email ?? '' ) : ( $reg->guest_email ?? '' );
        $phone = $reg->guest_phone ?? '';
        $type  = $reg->user_id ? __( 'Member', 'societypress' ) : __( 'Guest', 'societypress' );

        // Translate attended column: null = blank, 1 = Yes, 0 = No-show
        $attended_label = '';
        if ( $reg->attended !== null ) {
            $attended_label = (int) $reg->attended === 1 ? __( 'Yes', 'societypress' ) : __( 'No-show', 'societypress' );
        }

        fputcsv( $output, [
            $name,
            $email,
            $phone,
            $type,
            (int) $reg->party_size,
            $csv_status_labels[ $reg->status ] ?? ucfirst( $reg->status ),
            number_format( (float) $reg->fee_amount, 2 ),
            $reg->payment_status,
            $attended_label,
            $reg->notes ?? '',
            $reg->registered_at,
        ] );
    }

    fclose( $output );
    exit;
}
// END sp_ajax_export_registrations





// ============================================================================
// PUBLIC JOIN FORM — [societypress_join] Shortcode
// ============================================================================
//
// WHY: Prospective members need to sign up directly from the website without
//      requiring an admin to manually create their account. This shortcode
//      renders a public-facing membership application form that:
//        - Shows available membership tiers with prices
//        - Collects personal and contact information
//        - Creates both a WordPress user account and sp_members record
//        - Sends a welcome email (if enabled in settings)
//        - Uses honeypot spam protection (no CAPTCHA needed)
//
//      If the selected tier has a price > 0 and a payment gateway is
//      configured (Stripe or PayPal), the form routes through the gateway
//      before completing. Free tiers submit directly.
// ============================================================================

add_shortcode( 'societypress_join', 'sp_render_join_form' );

/**
 * Process join form submission on init (before any output).
 *
 * WHY: Must run before rendering so we can set result messages and
 *      redirect on success. Runs on every init but bails immediately
 *      if our form wasn't submitted.
 */
add_action( 'init', function () {
    if ( empty( $_POST['sp_join_nonce'] ) ) {
        return;
    }

    // Verify nonce
    if ( ! wp_verify_nonce( $_POST['sp_join_nonce'], 'sp_join_form' ) ) {
        $GLOBALS['sp_join_result'] = [ 'success' => false, 'message' => __( 'Security check failed. Please try again.', 'societypress' ) ];
        return;
    }

    // Honeypot check — if the hidden field has content, it's a bot
    if ( ! empty( $_POST['sp_website_url'] ) ) {
        // Silently succeed to not tip off the bot
        $GLOBALS['sp_join_result'] = [ 'success' => true, 'message' => 'Thank you! Your application has been submitted.' ];
        return;
    }

    // Rate limiting — prevent spam submissions and Stripe API abuse
    // WHY: Without throttling, a bot or bad actor could submit hundreds of
    //      join forms per minute, creating orphaned member records and
    //      potentially racking up Stripe API calls. Three attempts per IP
    //      per hour is generous for legitimate use.
    $rate_key   = 'sp_join_rate_' . md5( $_SERVER['REMOTE_ADDR'] ?? 'unknown' );
    $attempts   = (int) get_transient( $rate_key );
    if ( $attempts >= 3 ) {
        $org_email = get_option( 'societypress_settings', [] )['org_email'] ?? get_option( 'admin_email' );
        /* translators: %s: organization email address */
        $GLOBALS['sp_join_result'] = [ 'success' => false, 'message' => sprintf( __( 'Too many attempts. Please wait one hour and try again, or contact us at %s if you need help.', 'societypress' ), $org_email ) ];
        return;
    }
    set_transient( $rate_key, $attempts + 1, HOUR_IN_SECONDS );

    // Validate required fields
    $first_name = sanitize_text_field( $_POST['first_name'] ?? '' );
    $last_name  = sanitize_text_field( $_POST['last_name'] ?? '' );
    $email      = sanitize_email( $_POST['email'] ?? '' );
    $tier_id    = absint( $_POST['tier_id'] ?? 0 );

    // WHY: Field-level errors so the form can highlight exactly which fields
    // need attention, not just a single banner at the top. Harold's prospective
    // members are often older and may not scroll up to see a generic message.
    $field_errors = [];

    if ( ! $first_name ) {
        $field_errors['first_name'] = __( 'First name is required.', 'societypress' );
    }
    if ( ! $last_name ) {
        $field_errors['last_name'] = __( 'Last name is required.', 'societypress' );
    }
    if ( ! $email ) {
        $field_errors['email'] = __( 'Email address is required.', 'societypress' );
    } elseif ( ! is_email( $email ) ) {
        $field_errors['email'] = __( 'Please enter a valid email address.', 'societypress' );
    }
    if ( ! $tier_id ) {
        $field_errors['tier_id'] = __( 'Please select a membership level.', 'societypress' );
    }

    if ( ! empty( $field_errors ) ) {
        $GLOBALS['sp_join_result'] = [
            'success'      => false,
            'message'      => __( 'Please correct the highlighted fields below.', 'societypress' ),
            'field_errors' => $field_errors,
        ];
        return;
    }

    // Check if email already exists as a member
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $existing = $wpdb->get_var( $wpdb->prepare(
        "SELECT m.user_id FROM {$prefix}members m
         INNER JOIN {$wpdb->users} u ON m.user_id = u.ID
         WHERE u.user_email = %s",
        $email
    ) );
    if ( $existing ) {
        $GLOBALS['sp_join_result'] = [
            'success'      => false,
            'message'      => __( 'A member with this email address already exists. Please contact us if you need help.', 'societypress' ),
            'field_errors' => [ 'email' => __( 'This email is already registered.', 'societypress' ) ],
        ];
        return;
    }

    // Verify tier exists and is active
    $tier = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}membership_tiers WHERE id = %d AND is_active = 1", $tier_id
    ) );
    if ( ! $tier ) {
        $GLOBALS['sp_join_result'] = [
            'success'      => false,
            'message'      => __( 'Invalid membership level selected.', 'societypress' ),
            'field_errors' => [ 'tier_id' => __( 'Please select a valid membership level.', 'societypress' ) ],
        ];
        return;
    }

    // Create WordPress user (or link existing)
    $user_id = sp_create_or_link_user( $email, $first_name, $last_name );
    if ( is_wp_error( $user_id ) ) {
        $GLOBALS['sp_join_result'] = [ 'success' => false, 'message' => 'Could not create your account: ' . $user_id->get_error_message() ];
        return;
    }

    // Calculate expiration date based on membership period settings
    $settings     = get_option( 'societypress_settings', [] );
    $period_type  = $settings['membership_period_type'] ?? 'annual';
    $start_month  = (int) ( $settings['membership_start_month'] ?? 1 );
    $today        = new DateTime();
    $join_date    = $today->format( 'Y-m-d' );

    if ( $period_type === 'rolling' ) {
        // Rolling: expires 1 year from today
        $exp_date = $today->modify( '+1 year' )->format( 'Y-m-d' );
    } else {
        // Annual: expires on the start month of the next cycle
        $current_year  = (int) $today->format( 'Y' );
        $current_month = (int) $today->format( 'n' );
        $exp_year = $current_month >= $start_month ? $current_year + 1 : $current_year;
        $exp_date = sprintf( '%04d-%02d-01', $exp_year, $start_month );
    }

    // Joint member fields — only populate if the selected tier allows it
    // WHY: Even if someone tampers with the form and submits joint fields
    //      for a non-joint tier, we ignore them. The tier controls eligibility.
    $joint_first = '';
    $joint_last  = '';
    if ( ! empty( $tier->allows_joint ) ) {
        $joint_first = sanitize_text_field( $_POST['joint_first_name'] ?? '' );
        $joint_last  = sanitize_text_field( $_POST['joint_last_name'] ?? '' );
    }
    $has_joint = ! empty( $joint_first );

    // Create the member record
    // WHY: Build the data array first so we can encrypt sensitive fields
    // before the insert. cell, address_1, address_2 are encrypted at rest.
    $join_member_data = [
        'user_id'         => $user_id,
        'member_type'     => 'individual',
        'status'          => 'pending',  // Pending until payment confirmed
        'tier_id'         => $tier_id,
        'first_name'      => $first_name,
        'last_name'       => $last_name,
        'preferred_name'  => sanitize_text_field( $_POST['preferred_name'] ?? '' ),
        'joint_member'    => $has_joint ? 1 : 0,
        'joint_first_name'     => $has_joint ? $joint_first : null,
        'joint_last_name'      => $has_joint ? $joint_last : null,
        'joint_preferred_name' => $has_joint ? sanitize_text_field( $_POST['joint_preferred_name'] ?? '' ) ?: null : null,
        'joint_email'          => $has_joint ? sanitize_email( $_POST['joint_email'] ?? '' ) ?: null : null,
        'joint_phone'          => $has_joint ? sanitize_text_field( $_POST['joint_phone'] ?? '' ) ?: null : null,
        'phone'           => sanitize_text_field( $_POST['phone'] ?? '' ),
        'cell'            => sanitize_text_field( $_POST['cell'] ?? '' ),
        'address_1'       => sanitize_text_field( $_POST['address_1'] ?? '' ),
        'address_2'       => sanitize_text_field( $_POST['address_2'] ?? '' ),
        'city'            => sanitize_text_field( $_POST['city'] ?? '' ),
        'state'           => sanitize_text_field( $_POST['state'] ?? '' ),
        'postal_code'     => sanitize_text_field( $_POST['postal_code'] ?? '' ),
        'country'         => sanitize_text_field( $_POST['country'] ?? 'US' ),
        'join_date'       => $join_date,
        'expiration_date' => $exp_date,
        'pref_email_notices'     => 1,
        'pref_email_events'      => 1,
        'pref_email_newsletters' => 1,
        'pref_email_surnames'    => 1,
        'dir_show_name'    => 1,
        'dir_show_email'   => 1,
        'dir_show_phone'   => 0,
        'dir_show_address' => 0,
        'dir_show_website' => 1,
        'dir_show_photo'   => 1,
        'created_at'       => current_time( 'mysql' ),
        'updated_at'       => current_time( 'mysql' ),
    ];
    sp_member_encrypt_fields( $join_member_data );
    $wpdb->insert( $prefix . 'members', $join_member_data );

    // ---- Payment routing for paid tiers ----
    // WHY: If the tier costs money, we need to route the user through a payment
    //      gateway before their application is complete. The member record is
    //      already created with status='pending' — we'll update it after payment
    //      is captured (or admin manually approves for free tiers).
    $tier_price  = (float) ( $tier->price ?? 0 );
    $pay_method  = sanitize_text_field( $_POST['pay_method'] ?? '' );

    if ( $tier_price > 0 && in_array( $pay_method, [ 'paypal', 'stripe' ], true ) ) {
        $sp_settings = get_option( 'societypress_settings', [] );
        $currency    = $sp_settings['stripe_currency'] ?? 'usd';
        $org_name    = $sp_settings['organization_name'] ?? get_bloginfo( 'name' );

        // Build description for the payment processor
        $pay_description = sprintf(
            /* translators: %1$s: tier name, %2$s: organization name */
            __( 'Membership Dues: %1$s — %2$s', 'societypress' ),
            mb_substr( $tier->name, 0, 80 ),
            mb_substr( $org_name, 0, 40 )
        );

        // The return URL is the page containing the [societypress_join] shortcode.
        // WHY: We look for the page using a content search for the shortcode rather
        //      than a fixed page slug, since the shortcode can live on any page.
        //      Falls back to home_url() if no shortcode page is found.
        $join_page_url = home_url();
        $join_pages    = get_posts( [
            'post_type'   => 'page',
            'post_status' => 'publish',
            's'           => '[societypress_join',
            'numberposts' => 1,
            'fields'      => 'ids',
        ] );
        if ( ! empty( $join_pages ) ) {
            $join_page_url = get_permalink( $join_pages[0] );
        }

        // --- PayPal flow ---
        if ( $pay_method === 'paypal' ) {
            if ( ! sp_paypal_is_configured( $sp_settings ) ) {
                $GLOBALS['sp_join_result'] = [
                    'success' => false,
                    'message' => __( 'PayPal is not configured. Please contact the site administrator.', 'societypress' ),
                ];
                return;
            }

            $return_url = add_query_arg( [
                'sp_join_payment' => 'success',
                'sp_paypal'       => '1',
                'sp_member_id'    => $user_id,
            ], $join_page_url );
            $cancel_url = add_query_arg( [ 'sp_join_payment' => 'cancelled' ], $join_page_url );

            $order_result = sp_paypal_create_order(
                $tier_price,
                $currency,
                $pay_description,
                $return_url,
                $cancel_url,
                [ 'type' => 'membership', 'user_id' => $user_id, 'tier_id' => $tier_id ],
                $sp_settings
            );

            if ( is_wp_error( $order_result ) ) {
                error_log( 'SocietyPress Join PayPal error: ' . $order_result->get_error_message() );
                $GLOBALS['sp_join_result'] = [
                    'success' => false,
                    'message' => __( 'Could not connect to PayPal. Please try again or choose a different payment method.', 'societypress' ),
                ];
                return;
            }

            // Store PayPal order ID on the member record via user meta so we can
            // verify on return. Using meta instead of a dedicated column because
            // sp_members doesn't have payment gateway columns — those live on
            // sp_member_payments once payment is captured.
            update_user_meta( $user_id, '_sp_join_paypal_order', $order_result['id'] );

            // Redirect to PayPal for payment approval
            wp_redirect( $order_result['approve_url'] );
            exit;
        }

        // --- Stripe flow ---
        if ( $pay_method === 'stripe' ) {
            if ( ! sp_stripe_is_configured( $sp_settings ) ) {
                $GLOBALS['sp_join_result'] = [
                    'success' => false,
                    'message' => __( 'Card payments are not configured. Please contact the site administrator.', 'societypress' ),
                ];
                return;
            }

            $secret_key   = sp_stripe_get_secret_key( $sp_settings );
            $amount_cents = (int) round( $tier_price * 100 );

            $success_url = add_query_arg( [
                'sp_join_payment' => 'success',
                'sp_stripe'       => '1',
                'sp_member_id'    => $user_id,
                'sp_session'      => '{CHECKOUT_SESSION_ID}',
            ], $join_page_url );
            $cancel_url = add_query_arg( [ 'sp_join_payment' => 'cancelled' ], $join_page_url );

            $line_item_name = $tier->name;
            if ( strlen( $line_item_name ) > 100 ) {
                $line_item_name = substr( $line_item_name, 0, 97 ) . '...';
            }

            $stripe_response = wp_remote_post( 'https://api.stripe.com/v1/checkout/sessions', [
                'timeout' => 30,
                'headers' => [
                    'Authorization' => 'Bearer ' . $secret_key,
                    'Content-Type'  => 'application/x-www-form-urlencoded',
                ],
                'body' => [
                    'payment_method_types[0]' => 'card',
                    'mode'                    => 'payment',
                    'success_url'             => $success_url,
                    'cancel_url'              => $cancel_url,
                    'client_reference_id'     => (string) $user_id,
                    'metadata[user_id]'       => (string) $user_id,
                    'metadata[tier_id]'       => (string) $tier_id,
                    'metadata[type]'          => 'membership',
                    'metadata[site_url]'      => home_url(),
                    'line_items[0][price_data][currency]'     => $currency,
                    'line_items[0][price_data][unit_amount]'   => $amount_cents,
                    'line_items[0][price_data][product_data][name]' => $line_item_name,
                    'line_items[0][price_data][product_data][description]' => $pay_description,
                    'line_items[0][quantity]' => 1,
                ],
            ] );

            if ( is_wp_error( $stripe_response ) ) {
                $GLOBALS['sp_join_result'] = [
                    'success' => false,
                    'message' => __( 'Could not connect to payment processor. Please try again.', 'societypress' ),
                ];
                return;
            }

            $stripe_body = json_decode( wp_remote_retrieve_body( $stripe_response ), true );
            $stripe_code = wp_remote_retrieve_response_code( $stripe_response );

            if ( $stripe_code !== 200 || empty( $stripe_body['url'] ) ) {
                $stripe_err = $stripe_body['error']['message'] ?? 'Payment setup failed.';
                error_log( 'SocietyPress Join Stripe error: ' . $stripe_err );
                $GLOBALS['sp_join_result'] = [
                    'success' => false,
                    'message' => __( 'Could not set up payment. Please try again or choose a different payment method.', 'societypress' ),
                ];
                return;
            }

            // Store Stripe session ID on the member for verification on return
            update_user_meta( $user_id, '_sp_join_stripe_session', $stripe_body['id'] );

            // Redirect to Stripe Checkout
            wp_redirect( $stripe_body['url'] );
            exit;
        }
    }

    // Send welcome email (for free tiers, or if no payment method was selected)
    sp_send_welcome_email( $user_id );

    $GLOBALS['sp_join_result'] = [
        'success' => true,
        'message' => __( 'Welcome! Your membership application has been submitted. You will receive a confirmation email shortly.', 'societypress' ),
    ];
} );


/**
 * Handle the return from PayPal after a join form payment.
 *
 * WHY: After the prospective member approves payment on PayPal's site, PayPal
 *      redirects them back to the join page with query parameters including the
 *      PayPal order token. We capture the payment, record it in sp_member_payments,
 *      send the welcome email, and show a success message.
 *
 *      This runs on template_redirect so the payment is captured before the page
 *      renders — same pattern as the event registration PayPal return handler.
 */
add_action( 'template_redirect', function () {
    $join_status = sanitize_text_field( $_GET['sp_join_payment'] ?? '' );
    $is_paypal   = ! empty( $_GET['sp_paypal'] );
    $member_id   = absint( $_GET['sp_member_id'] ?? 0 );

    // Only handle PayPal join returns
    if ( $join_status !== 'success' || ! $is_paypal || ! $member_id ) {
        return;
    }

    // PayPal appends a 'token' parameter (the order ID) to the return URL
    $paypal_token = sanitize_text_field( $_GET['token'] ?? '' );
    if ( empty( $paypal_token ) ) {
        return;
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Verify this member exists and is still pending
    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}members WHERE user_id = %d", $member_id
    ) );
    if ( ! $member || $member->status !== 'pending' ) {
        return;
    }

    // Verify the PayPal order ID matches what we stored during form submission
    // WHY: Prevents someone from crafting a URL with a different member_id and
    //      a valid PayPal token to mark an arbitrary member as paid.
    $stored_order = get_user_meta( $member_id, '_sp_join_paypal_order', true );
    if ( empty( $stored_order ) || $stored_order !== $paypal_token ) {
        return;
    }

    $settings = get_option( 'societypress_settings', [] );
    if ( ! sp_paypal_is_configured( $settings ) ) {
        return;
    }

    $capture = sp_paypal_capture_order( $paypal_token, $settings );

    if ( is_wp_error( $capture ) ) {
        error_log( 'SocietyPress Join PayPal capture error: ' . $capture->get_error_message() );
        // Show an error message on the join page via the global result
        $GLOBALS['sp_join_result'] = [
            'success' => false,
            'message' => __( 'Payment could not be processed. Please contact us for assistance.', 'societypress' ),
        ];
        return;
    }

    // Record the payment in the member payments ledger
    // WHY: sp_member_payments is the canonical payment history table. We store
    //      the PayPal order and capture IDs in the note field for audit trail,
    //      same pattern used in event registration PayPal capture.
    $tier = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}membership_tiers WHERE id = %d", $member->tier_id
    ) );
    $wpdb->insert( $prefix . 'member_payments', [
        'user_id'     => $member_id,
        'amount'      => $capture['capture_amount'] ?? ( $tier ? (float) $tier->price : 0 ),
        'type'        => 'dues',
        'method'      => 'paypal',
        'date'        => current_time( 'Y-m-d' ),
        'note'        => 'paypal_order:' . $paypal_token . '|paypal_capture:' . ( $capture['capture_id'] ?? '' ),
        'recorded_by' => null,
        'created_at'  => current_time( 'mysql' ),
    ] );

    // Clean up the temporary meta — no longer needed after capture
    delete_user_meta( $member_id, '_sp_join_paypal_order' );

    sp_audit(
        'join_payment_captured',
        sprintf(
            'PayPal payment captured for new member #%d ($%s)',
            $member_id,
            number_format( $capture['capture_amount'] ?? 0, 2 )
        ),
        'member',
        $member_id
    );

    // Send welcome email now that payment is confirmed
    sp_send_welcome_email( $member_id );

    // Show success to the user — the member record stays 'pending' until
    // admin approves, but the payment is captured and recorded.
    $GLOBALS['sp_join_result'] = [
        'success' => true,
        'message' => __( 'Payment received! Your membership application has been submitted. You will receive a confirmation email shortly.', 'societypress' ),
    ];
} );


/**
 * Handle the return from Stripe Checkout after a join form payment.
 *
 * WHY: After the prospective member pays on Stripe's hosted page, Stripe
 *      redirects them back to the join page with the session ID in the URL.
 *      We verify the session with Stripe's API, confirm payment was successful,
 *      record it in sp_member_payments, and send the welcome email.
 */
add_action( 'template_redirect', function () {
    $join_status = sanitize_text_field( $_GET['sp_join_payment'] ?? '' );
    $is_stripe   = ! empty( $_GET['sp_stripe'] );
    $member_id   = absint( $_GET['sp_member_id'] ?? 0 );
    $session_id  = sanitize_text_field( $_GET['sp_session'] ?? '' );

    // Only handle Stripe join returns
    if ( $join_status !== 'success' || ! $is_stripe || ! $member_id || empty( $session_id ) ) {
        return;
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Verify this member exists and is still pending
    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}members WHERE user_id = %d", $member_id
    ) );
    if ( ! $member || $member->status !== 'pending' ) {
        return;
    }

    // Verify the Stripe session ID matches what we stored during form submission
    $stored_session = get_user_meta( $member_id, '_sp_join_stripe_session', true );
    if ( empty( $stored_session ) || $stored_session !== $session_id ) {
        return;
    }

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );
    if ( empty( $secret_key ) ) {
        return;
    }

    // Retrieve the Checkout Session from Stripe to verify payment status
    $response = wp_remote_get(
        'https://api.stripe.com/v1/checkout/sessions/' . urlencode( $session_id ),
        [
            'timeout' => 30,
            'headers' => [
                'Authorization' => 'Bearer ' . $secret_key,
            ],
        ]
    );

    if ( is_wp_error( $response ) ) {
        error_log( 'SocietyPress Join Stripe session retrieve error: ' . $response->get_error_message() );
        return;
    }

    $body = json_decode( wp_remote_retrieve_body( $response ), true );
    $code = wp_remote_retrieve_response_code( $response );

    // Stripe Checkout sessions have payment_status = 'paid' when successful
    if ( $code !== 200 || empty( $body['payment_status'] ) || $body['payment_status'] !== 'paid' ) {
        $GLOBALS['sp_join_result'] = [
            'success' => false,
            'message' => __( 'Payment could not be verified. Please contact us for assistance.', 'societypress' ),
        ];
        return;
    }

    $amount_paid    = ( (float) ( $body['amount_total'] ?? 0 ) ) / 100; // Convert cents back to dollars
    $payment_intent = $body['payment_intent'] ?? '';

    // Record the payment in the member payments ledger
    $tier = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}membership_tiers WHERE id = %d", $member->tier_id
    ) );
    $wpdb->insert( $prefix . 'member_payments', [
        'user_id'     => $member_id,
        'amount'      => $amount_paid > 0 ? $amount_paid : ( $tier ? (float) $tier->price : 0 ),
        'type'        => 'dues',
        'method'      => 'stripe',
        'date'        => current_time( 'Y-m-d' ),
        'note'        => 'stripe_session:' . $session_id . '|stripe_pi:' . $payment_intent,
        'recorded_by' => null,
        'created_at'  => current_time( 'mysql' ),
    ] );

    // Clean up the temporary meta
    delete_user_meta( $member_id, '_sp_join_stripe_session' );

    sp_audit(
        'join_payment_captured',
        sprintf(
            'Stripe payment captured for new member #%d ($%s)',
            $member_id,
            number_format( $amount_paid, 2 )
        ),
        'member',
        $member_id
    );

    // Send welcome email now that payment is confirmed
    sp_send_welcome_email( $member_id );

    $GLOBALS['sp_join_result'] = [
        'success' => true,
        'message' => __( 'Payment received! Your membership application has been submitted. You will receive a confirmation email shortly.', 'societypress' ),
    ];
} );


/**
 * Handle cancelled join payment returns (both PayPal and Stripe).
 *
 * WHY: If the prospective member cancels payment on PayPal or Stripe's page,
 *      they are redirected back with sp_join_payment=cancelled. We show a
 *      helpful message letting them know they can try again. The member record
 *      already exists in 'pending' status — they can resubmit the form.
 */
add_action( 'template_redirect', function () {
    $join_status = sanitize_text_field( $_GET['sp_join_payment'] ?? '' );
    if ( $join_status !== 'cancelled' ) {
        return;
    }

    $GLOBALS['sp_join_result'] = [
        'success' => false,
        'message' => __( 'Payment was cancelled. If you would like to complete your membership, please fill out the form again.', 'societypress' ),
    ];
} );


/**
 * Render the [societypress_join] shortcode form.
 *
 * WHY: This is what the prospective member sees. Clean, simple form with
 *      tier selection, personal info, and contact fields. Styled inline
 *      to match the SocietyPress design system. No external CSS/JS needed.
 *
 * @return string Form HTML.
 */
function sp_render_join_form(): string {
    // If already logged in and already a member, show a message
    if ( is_user_logged_in() && sp_is_member() ) {
        $account_url = sp_get_my_account_url();
        return '<div style="padding: 20px; background: #f0f6fc; border: 1px solid #c3c4c7; border-radius: 4px;">'
             . '<p>' . sprintf( esc_html__( 'You are already a member. %s.', 'societypress' ), '<a href="' . esc_url( $account_url ) . '">' . esc_html__( 'Go to My Account', 'societypress' ) . '</a>' ) . '</p>'
             . '</div>';
    }

    // Get active tiers
    global $wpdb;
    $tiers = $wpdb->get_results(
        "SELECT * FROM {$wpdb->prefix}sp_membership_tiers WHERE is_active = 1 ORDER BY sort_order ASC, name ASC"
    );

    // Check for form result
    $result       = $GLOBALS['sp_join_result'] ?? null;
    $field_errors = $result['field_errors'] ?? [];

    ob_start();

    // Show summary result message
    if ( $result ) {
        $notice_class = $result['success'] ? 'sp-join-notice--success' : 'sp-join-notice--error';
        echo '<div class="sp-join-notice ' . $notice_class . '" role="alert">';
        echo '<p class="sp-m-0">' . esc_html( $result['message'] ) . '</p>';
        echo '</div>';

        if ( $result['success'] ) {
            // Don't show the form again after successful submission
            return ob_get_clean();
        }
    }

    $settings = get_option( 'societypress_settings', [] );
    $org_name = $settings['organization_name'] ?? get_bloginfo( 'name' );
    ?>

    <style>
        .sp-join-form { max-width: 640px; }
        .sp-join-form fieldset { border: 1px solid #e0e0e0; padding: 20px; margin: 0 0 20px; border-radius: 4px; }
        .sp-join-form legend { font-size: 16px; font-weight: 600; padding: 0 8px; color: #1d2327; }
        .sp-join-form .sp-field { margin-bottom: 14px; }
        .sp-join-form label { display: block; font-size: 13px; font-weight: 600; margin-bottom: 4px; color: #1d2327; }
        .sp-join-form label .required { color: #d63638; }
        .sp-join-form input[type="text"],
        .sp-join-form input[type="email"],
        .sp-join-form input[type="tel"],
        .sp-join-form select { width: 100%; padding: 8px 10px; border: 1px solid #8c8f94; border-radius: 3px; font-size: 14px; }
        .sp-join-form input:focus,
        .sp-join-form select:focus { border-color: #2271b1; box-shadow: 0 0 0 1px #2271b1; outline: none; }
        .sp-join-form .sp-field-row { display: flex; gap: 12px; }
        .sp-join-form .sp-field-row > .sp-field { flex: 1; }
        .sp-join-form .sp-tier-option { display: block; padding: 12px 16px; margin-bottom: 8px; border: 2px solid #e0e0e0; border-radius: 4px; cursor: pointer; transition: border-color 0.15s; }
        .sp-join-form .sp-tier-option:hover { border-color: #2271b1; }
        .sp-join-form .sp-tier-option input:checked + .sp-tier-label { }
        .sp-join-form .sp-tier-option:has(input:checked) { border-color: #2271b1; background: #f0f6fc; }
        .sp-join-form .sp-tier-label { display: flex; justify-content: space-between; align-items: center; }
        .sp-join-form .sp-tier-name { font-weight: 600; font-size: 15px; }
        .sp-join-form .sp-tier-price { font-size: 15px; color: #2271b1; font-weight: 600; }
        .sp-join-form .sp-tier-desc { font-size: 13px; color: #666; margin-top: 4px; }
        .sp-join-form .sp-submit { display: inline-block; padding: 12px 32px; background: #2271b1; color: #fff; border: none; border-radius: 4px; font-size: 16px; font-weight: 600; cursor: pointer; }
        .sp-join-form .sp-submit:hover { background: #135e96; }
        .sp-join-form .sp-submit-paypal { background: #0070ba; }
        .sp-join-form .sp-submit-paypal:hover { background: #005ea6; }
        .sp-join-form .sp-join-submit-area { margin-top: 4px; }
        .sp-join-form .sp-join-submit-hidden { display: none !important; }
        .sp-join-form #sp-join-paid-submit { display: flex; gap: 12px; flex-wrap: wrap; }
        .sp-join-form .sp-honeypot { position: absolute; left: -9999px; }
        .sp-join-notice { padding: 12px 16px; margin-bottom: 20px; border-radius: 4px; }
        .sp-join-notice--success { background: #edfaef; border: 1px solid #00a32a; }
        .sp-join-notice--error { background: #fcf0f1; border: 1px solid #d63638; }
        .sp-join-form .sp-field-error input,
        .sp-join-form .sp-field-error select { border-color: #d63638; }
        .sp-join-form .sp-field-error input:focus,
        .sp-join-form .sp-field-error select:focus { border-color: #d63638; box-shadow: 0 0 0 1px #d63638; }
        .sp-join-form .sp-field-error-msg { color: #d63638; font-size: 12px; margin-top: 4px; display: block; }
        @media (max-width: 480px) {
            .sp-join-form .sp-field-row { flex-direction: column; gap: 0; }
        }
    </style>

    <form method="post" class="sp-join-form">
        <?php wp_nonce_field( 'sp_join_form', 'sp_join_nonce' ); ?>

        <!-- Honeypot — hidden from humans, bots fill it in -->
        <div class="sp-honeypot" aria-hidden="true">
            <label for="sp_website_url"><?php esc_html_e( 'Website', 'societypress' ); ?></label>
            <input type="text" name="sp_website_url" id="sp_website_url" tabindex="-1" autocomplete="off">
        </div>

        <!-- Membership Level -->
        <fieldset>
            <legend><?php esc_html_e( 'Choose Your Membership Level', 'societypress' ); ?></legend>
            <?php if ( ! empty( $field_errors['tier_id'] ) ) : ?>
                <p class="sp-field-error-msg" role="alert"><?php echo esc_html( $field_errors['tier_id'] ); ?></p>
            <?php endif; ?>
            <?php foreach ( $tiers as $tier ) : ?>
                <label class="sp-tier-option">
                    <input type="radio" name="tier_id" value="<?php echo esc_attr( $tier->id ); ?>"
                           <?php checked( ( $_POST['tier_id'] ?? '' ), $tier->id ); ?>
                           <?php echo ! empty( $field_errors['tier_id'] ) ? 'aria-invalid="true"' : ''; ?>
                           required style="margin-right: 8px;">
                    <span class="sp-tier-label">
                        <span class="sp-tier-name"><?php echo esc_html( $tier->name ); ?></span>
                        <?php if ( (float) $tier->price > 0 ) : ?>
                            <span class="sp-tier-price"><?php echo esc_html( sp_format_currency( $tier->price ) ); ?>/<?php esc_html_e( 'year', 'societypress' ); ?></span>
                        <?php else : ?>
                            <span class="sp-tier-price"><?php esc_html_e( 'Free', 'societypress' ); ?></span>
                        <?php endif; ?>
                    </span>
                    <?php if ( ! empty( $tier->description ) ) : ?>
                        <span class="sp-tier-desc"><?php echo esc_html( $tier->description ); ?></span>
                    <?php endif; ?>
                </label>
            <?php endforeach; ?>
        </fieldset>

        <!-- Personal Information -->
        <fieldset>
            <legend><?php esc_html_e( 'Personal Information', 'societypress' ); ?></legend>
            <div class="sp-field-row">
                <div class="sp-field <?php echo ! empty( $field_errors['first_name'] ) ? 'sp-field-error' : ''; ?>">
                    <label for="sp-first-name"><?php esc_html_e( 'First Name', 'societypress' ); ?> <span class="required">*</span></label>
