/**
 * Output the calendar mobile-tap JavaScript.
 *
 * WHY: On mobile, the full event titles are hidden and replaced with dots.
 *      Tapping a day cell opens a panel below the calendar that lists the
 *      day's events. This JS is identical to what's in sp_events_frontend_scripts()
 *      but isolated so it can be loaded independently for the Page Builder
 *      widget and standalone calendar template.
 */
function sp_events_calendar_scripts(): void {
    ?>
    <script id="sp-calendar-widget-js">
    (function() {
        'use strict';

        // ---- Calendar mobile: tap day to show events panel ----
        var calDays = document.querySelectorAll('.sp-cal-has-events');
        var panel   = document.getElementById('sp-cal-mobile-panel');
        var panelDate   = document.getElementById('sp-cal-mobile-date');
        var panelEvents = document.getElementById('sp-cal-mobile-events');
        var closeBtn    = document.getElementById('sp-cal-mobile-close');

        if (calDays.length && panel) {
            calDays.forEach(function(day) {
                day.addEventListener('click', function(e) {
                    // Only on mobile (when dots are visible)
                    if (window.innerWidth > 768) return;

                    // Don't intercept link clicks inside event titles
                    if (e.target.closest('.sp-cal-event')) return;

                    var dayNum = this.querySelector('.sp-cal-day-num').textContent;
                    var monthLabel = document.querySelector('.sp-cal-month-label');
                    panelDate.textContent = monthLabel ? monthLabel.textContent + ' ' + dayNum : 'Day ' + dayNum;

                    // Build event list from the hidden .sp-cal-events links
                    var events = this.querySelectorAll('.sp-cal-event');
                    var html = '';
                    events.forEach(function(ev) {
                        var title = ev.querySelector('.sp-cal-event-title');
                        var time  = ev.querySelector('.sp-cal-event-time');
                        var href  = ev.href || '#';
                        html += '<a class="sp-cal-mobile-event" href="' + href + '">';
                        html += '<div class="sp-cal-mobile-event-title">' + (title ? title.textContent : '') + '</div>';
                        if (time) {
                            html += '<div class="sp-cal-mobile-event-time">' + time.textContent + '</div>';
                        }
                        html += '</a>';
                    });
                    panelEvents.innerHTML = html;
                    panel.style.display = 'block';
                    panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                });
            });

            if (closeBtn) {
                closeBtn.addEventListener('click', function() {
                    panel.style.display = 'none';
                });
            }
        }
    })();
    </script>
    <?php
}


// ============================================================================
// STRIPE PAYMENT INTEGRATION
// ============================================================================
//
// WHY: Societies that charge for workshops, seminars, or annual events need a
//      way to collect payment online. We use Stripe Checkout (hosted) — the
//      registrant clicks "Pay Now," gets redirected to Stripe's secure page,
//      enters their card, and comes back. The society's site never touches
//      credit card numbers, which means zero PCI compliance work.
//
// ARCHITECTURE:
//   1. sp_stripe_is_configured() — checks if API keys exist
//   2. sp_stripe_get_secret_key() — returns the active secret key (test/live)
//   3. sp_create_stripe_checkout_session() — calls Stripe API to create session
//   4. sp_handle_stripe_return() — processes the redirect back from Stripe
//   5. sp_test_stripe_connection AJAX — admin "Test Connection" button
//   6. sp_admin_refund_payment AJAX — admin refund button
//
// The society admin provides their own Stripe API keys in Settings > Events.
// SocietyPress never touches the money — it goes straight to the society's
// Stripe account.
// ============================================================================


/**
 * Check whether Stripe API keys are configured.
 *
 * WHY: Several places need to know if Stripe is ready — the registration form
 *      (to decide which buttons to show), the AJAX handler (to validate), and
 *      the settings page (to show connection status). One function, one truth.
 *
 * @param array $settings The societypress_settings option array.
 * @return bool True if both publishable and secret keys are set.
 */
function sp_stripe_is_configured( array $settings ): bool {
    $test_mode = ! empty( $settings['stripe_test_mode'] );
    $pub_key   = $test_mode
        ? ( $settings['stripe_test_publishable_key'] ?? '' )
        : ( $settings['stripe_live_publishable_key'] ?? '' );
    $secret    = $test_mode
        ? ( $settings['stripe_test_secret_key'] ?? '' )
        : ( $settings['stripe_live_secret_key'] ?? '' );
    return ! empty( $pub_key ) && ! empty( $secret );
}


/**
 * Get the active Stripe secret key (test or live depending on mode).
 *
 * @param array $settings The societypress_settings option array.
 * @return string The secret key, or empty string if not configured.
 */
function sp_stripe_get_secret_key( array $settings ): string {
    $test_mode = ! empty( $settings['stripe_test_mode'] );
    $key = $test_mode
        ? ( $settings['stripe_test_secret_key'] ?? '' )
        : ( $settings['stripe_live_secret_key'] ?? '' );
    // WHY: Secret keys are now stored encrypted via sp_encrypt(). We must
    // decrypt them before passing to the Stripe API. sp_decrypt() returns
    // false on failure (e.g. corrupted data), so we fall back to empty string.
    return $key ? ( sp_decrypt( $key ) ?: '' ) : '';
}


// ============================================================================
// PAYPAL — Helper Functions
//
// WHY: PayPal REST API v2 (Orders API) for online payments. Same pattern as
//      Stripe — direct REST calls via wp_remote_post(), no SDK. PayPal uses
//      OAuth2 bearer tokens instead of API key auth, so we need an extra step
//      to get an access token before making API calls.
// ============================================================================


/**
 * Check if PayPal is configured (has client ID and secret for the active mode).
 *
 * @param array $settings The societypress_settings option array.
 * @return bool
 */
function sp_paypal_is_configured( array $settings ): bool {
    $test_mode = ! empty( $settings['paypal_test_mode'] );
    $client_id = $test_mode
        ? ( $settings['paypal_sandbox_client_id'] ?? '' )
        : ( $settings['paypal_live_client_id'] ?? '' );
    $secret = $test_mode
        ? ( $settings['paypal_sandbox_secret'] ?? '' )
        : ( $settings['paypal_live_secret'] ?? '' );
    return ! empty( $client_id ) && ! empty( $secret );
}


/**
 * Get the PayPal API base URL for the active mode.
 *
 * @param array $settings The societypress_settings option array.
 * @return string
 */
function sp_paypal_api_base( array $settings ): string {
    return ! empty( $settings['paypal_test_mode'] )
        ? 'https://api-m.sandbox.paypal.com'
        : 'https://api-m.paypal.com';
}


/**
 * Get the active PayPal client ID.
 *
 * @param array $settings The societypress_settings option array.
 * @return string
 */
function sp_paypal_get_client_id( array $settings ): string {
    return ! empty( $settings['paypal_test_mode'] )
        ? ( $settings['paypal_sandbox_client_id'] ?? '' )
        : ( $settings['paypal_live_client_id'] ?? '' );
}


/**
 * Get the active PayPal secret (decrypted).
 *
 * @param array $settings The societypress_settings option array.
 * @return string
 */
function sp_paypal_get_secret( array $settings ): string {
    $key = ! empty( $settings['paypal_test_mode'] )
        ? ( $settings['paypal_sandbox_secret'] ?? '' )
        : ( $settings['paypal_live_secret'] ?? '' );
    return $key ? ( sp_decrypt( $key ) ?: '' ) : '';
}


/**
 * Get a PayPal OAuth2 access token.
 *
 * WHY: Unlike Stripe (which uses API key auth), PayPal requires an OAuth2
 *      access token for every API call. We cache it in a transient to avoid
 *      re-authenticating on every request. Tokens last ~9 hours; we cache
 *      for the token's lifetime minus a 60-second safety buffer.
 *
 * @param array $settings The societypress_settings option array.
 * @return string|WP_Error The access token, or WP_Error on failure.
 */
function sp_paypal_get_access_token( array $settings ) {
    $mode          = ! empty( $settings['paypal_test_mode'] ) ? 'sandbox' : 'live';
    $transient_key = 'sp_paypal_token_' . $mode;

    // Check cache first
    $cached = get_transient( $transient_key );
    if ( $cached ) {
        return $cached;
    }

    $client_id = sp_paypal_get_client_id( $settings );
    $secret    = sp_paypal_get_secret( $settings );

    if ( empty( $client_id ) || empty( $secret ) ) {
        return new WP_Error( 'paypal_not_configured', __( 'PayPal API credentials are not configured.', 'societypress' ) );
    }

    $response = wp_remote_post( sp_paypal_api_base( $settings ) . '/v1/oauth2/token', [
        'headers' => [
            'Authorization' => 'Basic ' . base64_encode( $client_id . ':' . $secret ),
            'Content-Type'  => 'application/x-www-form-urlencoded',
        ],
        'body'    => 'grant_type=client_credentials',
        'timeout' => 30,
    ] );

    if ( is_wp_error( $response ) ) {
        return $response;
    }

    $code = wp_remote_retrieve_response_code( $response );
    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( $code !== 200 || empty( $body['access_token'] ) ) {
        $error_msg = $body['error_description'] ?? $body['error'] ?? __( 'Unknown PayPal authentication error.', 'societypress' );
        error_log( 'SocietyPress PayPal auth error: ' . $error_msg );
        return new WP_Error( 'paypal_auth_failed', $error_msg );
    }

    // Cache the token — expires_in is in seconds, subtract 60s safety buffer
    $expires_in = max( 0, ( $body['expires_in'] ?? 3600 ) - 60 );
    set_transient( $transient_key, $body['access_token'], $expires_in );

    return $body['access_token'];
}


/**
 * Create a PayPal order (checkout session equivalent).
 *
 * WHY: This is the PayPal equivalent of creating a Stripe Checkout Session.
 *      We create an order with the amount and description, PayPal returns an
 *      approval URL, and we redirect the buyer there. After they approve, they
 *      come back to our return URL and we capture the payment.
 *
 * @param float  $amount      Payment amount.
 * @param string $currency    ISO 4217 currency code (e.g. 'usd').
 * @param string $description Line item description.
 * @param string $return_url  URL to redirect to after approval.
 * @param string $cancel_url  URL to redirect to if buyer cancels.
 * @param array  $metadata    Custom metadata (stored in custom_id as JSON).
 * @param array  $settings    The societypress_settings option array.
 * @return array|WP_Error     ['id' => order_id, 'approve_url' => url] or WP_Error.
 */
function sp_paypal_create_order( float $amount, string $currency, string $description, string $return_url, string $cancel_url, array $metadata, array $settings ) {
    $token = sp_paypal_get_access_token( $settings );
    if ( is_wp_error( $token ) ) {
        return $token;
    }

    $org_name = $settings['organization_name'] ?? get_bloginfo( 'name' );

    $order_data = [
        'intent'         => 'CAPTURE',
        'purchase_units' => [
            [
                'amount'      => [
                    'currency_code' => strtoupper( $currency ),
                    'value'         => number_format( $amount, 2, '.', '' ),
                ],
                'description' => mb_substr( $description, 0, 127 ), // PayPal limit
                'custom_id'   => wp_json_encode( $metadata ),
            ],
        ],
        'application_context' => [
            'brand_name'  => mb_substr( $org_name, 0, 127 ),
            'return_url'  => $return_url,
            'cancel_url'  => $cancel_url,
            'user_action' => 'PAY_NOW',
        ],
    ];

    $response = wp_remote_post( sp_paypal_api_base( $settings ) . '/v2/checkout/orders', [
        'headers' => [
            'Authorization' => 'Bearer ' . $token,
            'Content-Type'  => 'application/json',
        ],
        'body'    => wp_json_encode( $order_data ),
        'timeout' => 30,
    ] );

    if ( is_wp_error( $response ) ) {
        return $response;
    }

    $code = wp_remote_retrieve_response_code( $response );
    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( $code !== 201 || empty( $body['id'] ) ) {
        $error_msg = $body['message'] ?? $body['error'] ?? __( 'Failed to create PayPal order.', 'societypress' );
        error_log( 'SocietyPress PayPal create order error: ' . $error_msg );
        return new WP_Error( 'paypal_order_failed', $error_msg );
    }

    // Find the approval URL from the HATEOAS links
    $approve_url = '';
    foreach ( $body['links'] ?? [] as $link ) {
        if ( $link['rel'] === 'approve' ) {
            $approve_url = $link['href'];
            break;
        }
    }

    if ( empty( $approve_url ) ) {
        return new WP_Error( 'paypal_no_approve_url', __( 'PayPal order created but no approval URL returned.', 'societypress' ) );
    }

    return [
        'id'          => $body['id'],
        'approve_url' => $approve_url,
    ];
}


/**
 * Capture a PayPal order after the buyer has approved it.
 *
 * WHY: PayPal's two-phase flow: create → approve → capture. The buyer approves
 *      on PayPal's site, then returns to ours. We capture the payment to
 *      actually charge them. This is the capture step.
 *
 * @param string $paypal_order_id The PayPal order ID to capture.
 * @param array  $settings        The societypress_settings option array.
 * @return array|WP_Error         Capture details or WP_Error.
 */
function sp_paypal_capture_order( string $paypal_order_id, array $settings ) {
    $token = sp_paypal_get_access_token( $settings );
    if ( is_wp_error( $token ) ) {
        return $token;
    }

    $response = wp_remote_post(
        sp_paypal_api_base( $settings ) . '/v2/checkout/orders/' . urlencode( $paypal_order_id ) . '/capture',
        [
            'headers' => [
                'Authorization' => 'Bearer ' . $token,
                'Content-Type'  => 'application/json',
            ],
            'body'    => '{}', // Empty JSON body required by PayPal
            'timeout' => 30,
        ]
    );

    if ( is_wp_error( $response ) ) {
        return $response;
    }

    $code = wp_remote_retrieve_response_code( $response );
    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( $code !== 201 || empty( $body['status'] ) || $body['status'] !== 'COMPLETED' ) {
        $error_msg = $body['message'] ?? __( 'PayPal capture failed.', 'societypress' );
        error_log( 'SocietyPress PayPal capture error: ' . wp_json_encode( $body ) );
        return new WP_Error( 'paypal_capture_failed', $error_msg );
    }

    // Extract the capture ID from the first purchase unit's first capture
    $capture_id = '';
    $capture_amount = 0.0;
    if ( ! empty( $body['purchase_units'][0]['payments']['captures'][0] ) ) {
        $capture = $body['purchase_units'][0]['payments']['captures'][0];
        $capture_id     = $capture['id'] ?? '';
        $capture_amount = (float) ( $capture['amount']['value'] ?? 0 );
    }

    return [
        'status'         => $body['status'],
        'capture_id'     => $capture_id,
        'capture_amount' => $capture_amount,
        'payer_email'    => $body['payer']['email_address'] ?? '',
        'payer_name'     => trim( ( $body['payer']['name']['given_name'] ?? '' ) . ' ' . ( $body['payer']['name']['surname'] ?? '' ) ),
        'raw'            => $body,
    ];
}


/**
 * AJAX: Test PayPal connection by attempting to get an access token.
 *
 * WHY: The settings page has a "Test Connection" button. If the admin can
 *      get an access token, the credentials are valid. Same pattern as the
 *      Stripe test connection handler.
 */
add_action( 'wp_ajax_sp_test_paypal_connection', function(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized.', 'societypress' ) );
    }
    check_ajax_referer( 'sp_test_paypal' );

    $settings = get_option( 'societypress_settings', [] );
    $token    = sp_paypal_get_access_token( $settings );

    if ( is_wp_error( $token ) ) {
        wp_send_json_error( $token->get_error_message() );
    }

    $mode = ! empty( $settings['paypal_test_mode'] ) ? __( 'Sandbox', 'societypress' ) : __( 'Live', 'societypress' );
    wp_send_json_success( sprintf(
        /* translators: %s: PayPal mode (Sandbox or Live) */
        __( 'Connected to PayPal (%s) successfully.', 'societypress' ),
        $mode
    ) );
} );


// ============================================================================
// BACKUPS — Automated & Manual Backup System
//
// WHY: A society's data is irreplaceable — decades of membership records,
//      library catalogs, genealogical transcriptions, event history. If the
//      server dies, the database corrupts, or someone accidentally deletes
//      everything, the society needs to recover. This backup system creates
//      downloadable ZIP archives of the database tables, uploaded files, and
//      settings — on a schedule or on demand.
// ============================================================================


/**
 * Get (and create if needed) the backup storage directory.
 *
 * WHY: Backups live inside wp-content/uploads/sp-backups so they're in a
 *      predictable location that works on any host. The .htaccess and index.php
 *      files prevent direct HTTP access — backup ZIPs contain full database
 *      dumps with member names, emails, addresses, and payment history. Nobody
 *      should be able to download them by guessing the URL.
 *
 * @return string Absolute path to the backup directory.
 */
function sp_get_backup_dir(): string {
    $upload_dir = wp_upload_dir();
    $backup_dir = $upload_dir['basedir'] . '/sp-backups';

    if ( ! is_dir( $backup_dir ) ) {
        wp_mkdir_p( $backup_dir );
    }

    // Prevent direct HTTP access — backup ZIPs contain sensitive member data
    if ( ! file_exists( $backup_dir . '/.htaccess' ) ) {
        file_put_contents( $backup_dir . '/.htaccess', "Order Deny,Allow\nDeny from all" );
    }
    if ( ! file_exists( $backup_dir . '/index.php' ) ) {
        file_put_contents( $backup_dir . '/index.php', '<?php // Silence is golden.' );
    }

    return $backup_dir;
}


/**
 * Get all database tables that should be included in a backup.
 *
 * WHY: We back up every sp_* table (all SocietyPress data) plus the core
 *      WordPress user tables (wp_users and wp_usermeta). SP members ARE WP
 *      users — the sp_members table references user_id — so restoring member
 *      data without the user accounts would leave orphaned references.
 *      We intentionally do NOT back up wp_posts, wp_options, etc. — those
 *      are WordPress core data, not society data, and the host's own backups
 *      cover those.
 *
 * @return array List of full table names (e.g., 'wp_sp_events', 'wp_users').
 */
function sp_backup_get_tables(): array {
    global $wpdb;
    $sp_tables = $wpdb->get_col(
        $wpdb->prepare( "SHOW TABLES LIKE %s", $wpdb->esc_like( $wpdb->prefix . 'sp_' ) . '%' )
    );
    // Also include WP user tables since SP members are WP users
    $wp_tables = [ $wpdb->users, $wpdb->usermeta ];
    return array_merge( $sp_tables, $wp_tables );
}


/**
 * Export a single database table to a SQL file using paginated SELECTs.
 *
 * WHY: We can't use mysqldump on shared hosting (no shell access). Instead
 *      we SELECT in batches of 1000 rows and write INSERT statements to a
 *      .sql file. The batch approach keeps memory usage flat even for tables
 *      with tens of thousands of rows (e.g., library_items with 19,000+).
 *      Each INSERT groups up to 100 rows in a single VALUES clause — this is
 *      dramatically faster to import than one INSERT per row.
 *
 * @param string $table     Full table name (e.g., 'wp_sp_members').
 * @param string $output_dir Directory to write the .sql file into.
 * @return int Number of rows exported.
 */
function sp_backup_export_table( string $table, string $output_dir ): int {
    global $wpdb;

    $file   = $output_dir . '/' . $table . '.sql';
    $handle = fopen( $file, 'w' );
    if ( ! $handle ) return 0;

    // WHY no $wpdb->prepare() for table names: MySQL prepared statements cannot
    // parameterize identifiers (table/column names), only values. The table names
    // come from sp_backup_get_tables() which returns only hardcoded SP table names
    // and WP core table names — never user input. This is architecturally correct.
    $row_count = (int) $wpdb->get_var( "SELECT COUNT(*) FROM `{$table}`" );
    fwrite( $handle, "-- SocietyPress Backup: {$table}\n" );
    fwrite( $handle, "-- Generated: " . current_time( 'mysql' ) . "\n" );
    fwrite( $handle, "-- Rows: {$row_count}\n\n" );

    // CREATE TABLE statement — needed for restore to recreate the schema
    $create = $wpdb->get_row( "SHOW CREATE TABLE `{$table}`", ARRAY_N );
    if ( $create ) {
        fwrite( $handle, "DROP TABLE IF EXISTS `{$table}`;\n" );
        fwrite( $handle, $create[1] . ";\n\n" );
    }

    // Export data in batches of 1000 rows to keep memory flat.
    // WHY 1000: Large enough to minimize query overhead, small enough that
    // even a 50-column table with TEXT fields won't blow PHP's memory limit.
    $batch_size = 1000;
    $offset     = 0;
    $exported   = 0;

    while ( true ) {
        $rows = $wpdb->get_results(
            "SELECT * FROM `{$table}` LIMIT {$batch_size} OFFSET {$offset}",
            ARRAY_A
        );
        if ( empty( $rows ) ) break;

        // Build batched INSERTs — 100 rows per statement is a good balance
        // between import speed (fewer statements) and readability/debuggability.
        $chunks = array_chunk( $rows, 100 );
        foreach ( $chunks as $chunk ) {
            $columns  = array_keys( $chunk[0] );
            $col_list = '`' . implode( '`, `', $columns ) . '`';
            fwrite( $handle, "INSERT INTO `{$table}` ({$col_list}) VALUES\n" );

            $value_rows = [];
            foreach ( $chunk as $row ) {
                $vals = [];
                foreach ( $row as $val ) {
                    if ( $val === null ) {
                        $vals[] = 'NULL';
                    } else {
                        $vals[] = "'" . $wpdb->_real_escape( $val ) . "'";
                    }
                }
                $value_rows[] = '(' . implode( ', ', $vals ) . ')';
            }
            fwrite( $handle, implode( ",\n", $value_rows ) . ";\n\n" );
        }

        $exported += count( $rows );
        $offset   += $batch_size;

        // Memory safety — nudge PHP to free the previous batch's memory
        if ( function_exists( 'gc_collect_cycles' ) ) {
            gc_collect_cycles();
        }
    }

    fclose( $handle );
    return $exported;
}


/**
 * Export SocietyPress settings to a JSON file.
 *
 * WHY: Settings are stored in wp_options as a serialized array. If the site
 *      is rebuilt from scratch, Harold would have to re-enter every setting
 *      by hand — colors, email templates, module toggles, payment config.
 *      This exports them as human-readable JSON that the restore process can
 *      re-import. We intentionally EXCLUDE encrypted API secrets because
 *      they're tied to this site's AUTH_KEY — they'd be garbage on a
 *      different installation.
 *
 * @param string $output_dir Directory to write settings.json into.
 */
function sp_backup_export_settings( string $output_dir ): void {
    $settings = get_option( 'societypress_settings', [] );
    $modules  = get_option( 'sp_enabled_modules', [] );

    // Exclude encrypted secrets — they're tied to this site's AUTH_KEY and
    // would be undecryptable on a restored/migrated site.
    $exclude = [
        'stripe_test_secret_key', 'stripe_live_secret_key',
        'paypal_sandbox_secret',  'paypal_live_secret',
    ];
    foreach ( $exclude as $key ) {
        unset( $settings[ $key ] );
    }

    $data = [
        'societypress_settings' => $settings,
        'sp_enabled_modules'    => $modules,
        'exported_at'           => current_time( 'mysql' ),
    ];

    file_put_contents(
        $output_dir . '/settings.json',
        wp_json_encode( $data, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE )
    );
}


/**
 * Create a manifest.json describing the contents of a backup archive.
 *
 * WHY: When someone opens a backup ZIP months later — or tries to restore
 *      on a different server — they need to know what's inside without
 *      reading every SQL file. The manifest records the plugin version,
 *      PHP/WP versions, which components were included, and table/file
 *      counts. The restore process will also use this to validate
 *      compatibility before importing.
 *
 * @param string $output_dir Directory to write manifest.json into.
 * @param array  $options    What was included: 'db', 'uploads', 'settings',
 *                           'tables' (array), 'file_count' (int).
 */
function sp_backup_create_manifest( string $output_dir, array $options ): void {
    $manifest = [
        'version'        => '1.0',
        'plugin_version' => SOCIETYPRESS_VERSION,
        'wp_version'     => get_bloginfo( 'version' ),
        'php_version'    => PHP_VERSION,
        'site_url'       => home_url(),
        'created_at'     => current_time( 'c' ),
        'includes'       => [
            'database' => (bool) $options['db'],
            'uploads'  => (bool) $options['uploads'],
            'settings' => (bool) $options['settings'],
        ],
    ];

    if ( $options['db'] && isset( $options['tables'] ) ) {
        $manifest['database'] = [
            'tables'      => $options['tables'],
            'table_count' => count( $options['tables'] ),
            'prefix'      => $GLOBALS['wpdb']->prefix . 'sp_',
        ];
    }

    if ( $options['uploads'] && isset( $options['file_count'] ) ) {
        $manifest['uploads'] = [
            'file_count' => $options['file_count'],
        ];
    }

    file_put_contents(
        $output_dir . '/manifest.json',
        wp_json_encode( $manifest, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE )
    );
}


/**
 * Create a ZIP archive from a directory of backup files.
 *
 * WHY: A single ZIP is easier for Harold to download, store, and move than
 *      a folder of SQL and JSON files. We try PHP's ZipArchive first (faster,
 *      better compression) and fall back to PclZip which WordPress bundles
 *      for hosts that don't have the zip extension.
 *
 * @param string $source_dir Directory containing the backup files.
 * @param string $zip_path   Full path for the output ZIP file.
 * @return bool True if the ZIP was created successfully.
 */
function sp_backup_create_zip( string $source_dir, string $zip_path ): bool {
    // Try ZipArchive first (preferred — faster, better compression)
    if ( class_exists( 'ZipArchive' ) ) {
        $zip = new ZipArchive();
        if ( $zip->open( $zip_path, ZipArchive::CREATE | ZipArchive::OVERWRITE ) !== true ) {
            return false;
        }

        $files = new RecursiveIteratorIterator(
            new RecursiveDirectoryIterator( $source_dir, RecursiveDirectoryIterator::SKIP_DOTS ),
            RecursiveIteratorIterator::LEAVES_ONLY
        );

        foreach ( $files as $file ) {
            if ( $file->isFile() ) {
                // Store relative paths inside the ZIP so it extracts cleanly
                $relative = substr( $file->getPathname(), strlen( $source_dir ) + 1 );
                $zip->addFile( $file->getPathname(), $relative );
            }
        }

        $zip->close();
        return file_exists( $zip_path );
    }

    // Fallback: PclZip (bundled with WordPress for plugin/theme uploads)
    require_once ABSPATH . 'wp-admin/includes/class-pclzip.php';
    $zip    = new PclZip( $zip_path );
    $result = $zip->create( $source_dir, PCLZIP_OPT_REMOVE_PATH, $source_dir );
    return $result !== 0;
}


/**
 * Delete old backups beyond the retention limit.
 *
 * WHY: Without pruning, backups would accumulate forever and eventually fill
 *      the disk. The retention setting (default 5) keeps the most recent N
 *      completed backups and deletes the rest — both the ZIP file on disk
 *      and the metadata row in sp_backups.
 */
function sp_prune_old_backups(): void {
    global $wpdb;
    $settings  = get_option( 'societypress_settings', [] );
    $retention = max( 1, (int) ( $settings['backup_retention'] ?? 5 ) );
    $prefix    = $wpdb->prefix . 'sp_';

    // Get all completed backups ordered newest-first
    $backups = $wpdb->get_results(
        "SELECT id, filename FROM {$prefix}backups WHERE status = 'complete' ORDER BY created_at DESC"
    );

    // Keep the newest $retention, delete the rest
    if ( count( $backups ) <= $retention ) return;

    $to_delete  = array_slice( $backups, $retention );
    $backup_dir = sp_get_backup_dir();

    foreach ( $to_delete as $old ) {
        $path = $backup_dir . '/' . $old->filename;
        if ( file_exists( $path ) ) {
            wp_delete_file( $path );
        }
        $wpdb->delete( $prefix . 'backups', [ 'id' => $old->id ] );
    }
}


/**
 * Clean up stale/orphaned backup records and temp directories.
 *
 * WHY: If a backup crashes mid-run (PHP timeout, memory limit, server restart),
 *      it leaves behind a 'running' or 'pending' database row and a temp
 *      directory full of partial SQL files. This function marks those records
 *      as failed (so they show an error in the UI instead of "running" forever)
 *      and deletes orphaned temp directories older than 1 hour.
 */
function sp_cleanup_stale_backups(): void {
    global $wpdb;
    $prefix     = $wpdb->prefix . 'sp_';
    $backup_dir = sp_get_backup_dir();

    // Mark stale running/pending backups as failed (older than 1 hour)
    $wpdb->query( $wpdb->prepare(
        "UPDATE {$prefix}backups SET status = 'failed', note = %s
         WHERE status IN ('pending', 'running')
         AND created_at < DATE_SUB(NOW(), INTERVAL 1 HOUR)",
        __( 'Backup timed out.', 'societypress' )
    ) );

    // Clean up orphaned temp directories
    $dirs = glob( $backup_dir . '/tmp-*', GLOB_ONLYDIR );
    if ( $dirs ) {
        foreach ( $dirs as $dir ) {
            // Only delete if older than 1 hour — don't nuke a backup in progress
            if ( filemtime( $dir ) < time() - 3600 ) {
                sp_backup_rmdir( $dir );
            }
        }
    }
}


/**
 * Recursively delete a directory and all its contents.
 *
 * WHY: PHP has no built-in "rm -rf". After a backup ZIP is created, we need
 *      to clean up the temp directory that held the raw SQL and JSON files.
 *      We use wp_delete_file() for files (respects security filters) and
 *      iterate children-first so directories are empty before we rmdir() them.
 *
 * @param string $dir Absolute path to the directory to remove.
 */
function sp_backup_rmdir( string $dir ): void {
    if ( ! is_dir( $dir ) ) return;
    $items = new RecursiveIteratorIterator(
        new RecursiveDirectoryIterator( $dir, RecursiveDirectoryIterator::SKIP_DOTS ),
        RecursiveIteratorIterator::CHILD_FIRST
    );
    foreach ( $items as $item ) {
        if ( $item->isDir() ) {
            rmdir( $item->getPathname() );
        } else {
            wp_delete_file( $item->getPathname() );
        }
    }
    rmdir( $dir );
}


// ============================================================================
// BACKUPS — Cron Schedule & Scheduled Backup Runner
// ============================================================================

// Register a weekly cron interval.
// WHY: WordPress only ships with 'hourly', 'twicedaily', and 'daily'.
// Genealogical societies don't change data fast enough to need daily backups
// by default, so we add a weekly option.
add_filter( 'cron_schedules', function( array $schedules ): array {
    $schedules['sp_weekly'] = [
        'interval' => WEEK_IN_SECONDS,
        'display'  => __( 'Once Weekly (SocietyPress)', 'societypress' ),
    ];
    return $schedules;
} );

// Schedule (or deschedule) the backup cron on every request.
// WHY: We check on 'init' so that if Harold changes the frequency from
// "weekly" to "daily" (or "off"), the cron updates on the next page load
// without requiring a deactivate/reactivate cycle. If frequency is 'off',
// we clear the hook entirely.
add_action( 'init', function(): void {
    $settings  = get_option( 'societypress_settings', [] );
    $frequency = $settings['backup_frequency'] ?? 'weekly';

    if ( $frequency === 'off' ) {
        wp_clear_scheduled_hook( 'sp_backup_cron' );
        return;
    }

    if ( ! wp_next_scheduled( 'sp_backup_cron' ) ) {
        $schedule = ( $frequency === 'daily' ) ? 'daily' : 'sp_weekly';
        // Schedule for the configured hour (default 3 AM).
        // WHY: 3 AM is a safe default — almost no society admin is using
        // the site at that hour, so the backup won't compete for resources.
        $hour = (int) ( $settings['backup_hour'] ?? 3 );
        $next = strtotime( "today {$hour}:00" );
        if ( $next < time() ) $next = strtotime( "tomorrow {$hour}:00" );
        wp_schedule_event( $next, $schedule, 'sp_backup_cron' );
    }
} );

// The cron handler itself.
add_action( 'sp_backup_cron', 'sp_run_scheduled_backup' );

/**
 * Execute a scheduled backup.
 *
 * WHY: This is the workhorse — called by wp_cron on the configured schedule.
 *      It creates a metadata row in sp_backups, exports the database tables
 *      to SQL files, exports settings to JSON, optionally copies uploads,
 *      wraps everything in a ZIP, updates the metadata with the final size
 *      and status, and prunes old backups beyond the retention limit.
 *
 *      If another backup is already running (started < 30 min ago), we bail
 *      to prevent overlapping runs on sites with aggressive wp_cron triggers.
 *      The 10-minute time limit gives large databases room to export without
 *      hitting PHP's default 30-second limit.
 */
function sp_run_scheduled_backup(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Don't run if another backup is already in progress
    $running = $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}backups WHERE status = 'running' AND created_at > DATE_SUB(NOW(), INTERVAL 30 MINUTE)"
    );
    if ( $running > 0 ) return;

    // Clean up stale/orphaned backups before starting a new one
    sp_cleanup_stale_backups();

    // Give the backup up to 10 minutes — large databases with TEXT columns
    // (library items, genealogical records) can take a while to export.
    set_time_limit( 600 );

    $include_db       = ! empty( $settings['backup_include_db'] );
    $include_uploads  = ! empty( $settings['backup_include_uploads'] );
    $include_settings = ! empty( $settings['backup_include_settings'] );

    // Nothing to back up — all three components are disabled
    if ( ! $include_db && ! $include_uploads && ! $include_settings ) return;

    $backup_dir = sp_get_backup_dir();
    $token      = wp_generate_password( 8, false );
    $date_str   = current_time( 'Y-m-d' );
    $filename   = "sp-backup-{$date_str}-{$token}.zip";

    // Determine backup type label for the UI
    $type = 'full';
    if ( $include_db && ! $include_uploads ) $type = 'db_only';
    if ( ! $include_db && $include_uploads )  $type = 'uploads_only';

    // Create the metadata row first — this lets us track the backup even
    // if it crashes partway through (sp_cleanup_stale_backups will mark
    // it as failed after 1 hour).
    $wpdb->insert( $prefix . 'backups', [
        'filename'          => $filename,
        'backup_type'       => $type,
        'includes_db'       => $include_db ? 1 : 0,
        'includes_uploads'  => $include_uploads ? 1 : 0,
        'includes_settings' => $include_settings ? 1 : 0,
        'status'            => 'running',
        'trigger_type'      => 'scheduled',
        'started_at'        => current_time( 'mysql' ),
    ] );
    $backup_id = (int) $wpdb->insert_id;

    if ( ! $backup_id ) {
        error_log( 'SocietyPress Backup: Could not create backup record.' );
        return;
    }

    $temp_dir = $backup_dir . '/tmp-' . $backup_id;
    wp_mkdir_p( $temp_dir );

    $tables_count = 0;
    $files_count  = 0;

    try {
        // ---- Export database tables ----
        if ( $include_db ) {
            $db_dir = $temp_dir . '/database';
            wp_mkdir_p( $db_dir );
            $tables = sp_backup_get_tables();
            foreach ( $tables as $table ) {
                sp_backup_export_table( $table, $db_dir );
                $tables_count++;
            }
        }

        // ---- Export settings ----
        if ( $include_settings ) {
            $settings_dir = $temp_dir . '/settings';
            wp_mkdir_p( $settings_dir );
            sp_backup_export_settings( $settings_dir );
        }

        // ---- Copy uploads (media library) ----
        if ( $include_uploads ) {
            $upload_dir   = wp_upload_dir();
            $uploads_src  = $upload_dir['basedir'];
            $uploads_dest = $temp_dir . '/uploads';
            wp_mkdir_p( $uploads_dest );

            $iterator = new RecursiveIteratorIterator(
                new RecursiveDirectoryIterator( $uploads_src, RecursiveDirectoryIterator::SKIP_DOTS ),
                RecursiveIteratorIterator::SELF_FIRST
            );

            foreach ( $iterator as $item ) {
                $relative = substr( $item->getPathname(), strlen( $uploads_src ) + 1 );
                // Skip the backups directory itself — don't back up backups
                if ( strpos( $relative, 'sp-backups' ) === 0 ) continue;

                $dest_path = $uploads_dest . '/' . $relative;
                if ( $item->isDir() ) {
                    wp_mkdir_p( $dest_path );
                } else {
                    copy( $item->getPathname(), $dest_path );
                    $files_count++;
                }
            }
        }

        // ---- Create manifest ----
        sp_backup_create_manifest( $temp_dir, [
            'db'         => $include_db,
            'uploads'    => $include_uploads,
            'settings'   => $include_settings,
            'tables'     => $include_db ? sp_backup_get_tables() : [],
            'file_count' => $files_count,
        ] );

        // ---- Create ZIP archive ----
        $zip_path = $backup_dir . '/' . $filename;
        $success  = sp_backup_create_zip( $temp_dir, $zip_path );

        if ( $success && file_exists( $zip_path ) ) {
            // Success — update the metadata row with final stats
            $wpdb->update( $prefix . 'backups', [
                'status'       => 'complete',
                'file_size'    => filesize( $zip_path ),
                'tables_count' => $tables_count,
                'files_count'  => $files_count,
                'completed_at' => current_time( 'mysql' ),
            ], [ 'id' => $backup_id ] );

            // Log it in the audit trail so there's a record of what ran
            sp_audit( 'backup_created', sprintf( 'Scheduled backup created: %d tables, %d files, %s',
                $tables_count, $files_count, size_format( filesize( $zip_path ) ) ), 'backup', $backup_id );

            // Enforce retention limit — delete oldest backups beyond the limit
            sp_prune_old_backups();
        } else {
            $wpdb->update( $prefix . 'backups', [
                'status' => 'failed',
                'note'   => __( 'ZIP creation failed.', 'societypress' ),
            ], [ 'id' => $backup_id ] );
        }

    } catch ( \Throwable $e ) {
        // Catch any unexpected error so the backup row doesn't stay 'running'
        // forever — mark it failed and log the error for debugging.
        $wpdb->update( $prefix . 'backups', [
            'status' => 'failed',
            'note'   => $e->getMessage(),
        ], [ 'id' => $backup_id ] );
        error_log( 'SocietyPress Backup error: ' . $e->getMessage() );
    }

    // Always clean up the temp directory — even on failure, the partial
    // files are useless and just waste disk space.
    sp_backup_rmdir( $temp_dir );
}


// ============================================================================
// BACKUPS — Admin Page, AJAX Handlers, Cron Wiring
//
// WHY: The backup infrastructure (table creation, directory management, table
//      export, ZIP creation, scheduling, pruning) is all built above. This
//      section adds the user-facing admin page where Harold can trigger manual
//      backups, view/download/delete existing archives, and configure the
//      automated backup schedule. Without this, the backup system is invisible.
// ============================================================================


/**
 * Render the Backups admin page.
 *
 * WHY: Harold needs a single page where he can:
 *      1. Create an immediate backup with one click
 *      2. See all existing backups with date, size, type, and status
 *      3. Download or delete any backup
 *      4. Configure automated backup schedule and retention
 *      All in one place, no digging through multiple screens.
 */
function sp_render_backup_page(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Fetch all backups, newest first
    $backups = $wpdb->get_results(
        "SELECT * FROM {$prefix}backups ORDER BY created_at DESC"
    );

    // Current settings with defaults
    $auto_enabled     = ! empty( $settings['backup_auto_enabled'] );
    $day_of_month     = (int) ( $settings['backup_day_of_month'] ?? 1 );
    $retention        = (int) ( $settings['backup_retention'] ?? 3 );
    $email_notify     = ! empty( $settings['backup_email_notify'] );
    $email_attach     = ! empty( $settings['backup_email_attach'] );
    $include_db       = isset( $settings['backup_include_db'] ) ? (int) $settings['backup_include_db'] : 1;
    $include_uploads  = ! empty( $settings['backup_include_uploads'] );
    $include_settings = isset( $settings['backup_include_settings'] ) ? (int) $settings['backup_include_settings'] : 1;

    // Nonces for AJAX operations
    $backup_nonce   = wp_create_nonce( 'sp_create_manual_backup' );
    $delete_nonce   = wp_create_nonce( 'sp_delete_backup' );
    $download_nonce = wp_create_nonce( 'sp_download_backup' );
    $settings_nonce = wp_create_nonce( 'sp_save_backup_settings' );
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Backups', 'societypress' ); ?></h1>
        <hr class="wp-header-end">

        <?php if ( isset( $_GET['settings-saved'] ) && $_GET['settings-saved'] === '1' ) : ?>
            <div class="notice notice-success is-dismissible">
                <p><?php esc_html_e( 'Backup settings saved.', 'societypress' ); ?></p>
            </div>
        <?php endif; ?>

        <!-- Status messages inserted by JS -->
        <div id="sp-backup-notices"></div>

        <!-- ============================================================ -->
        <!-- Back Up Now — Primary Action                                 -->
        <!-- ============================================================ -->
        <div class="sp-backup-action-card">
            <h2><?php esc_html_e( 'Create Backup', 'societypress' ); ?></h2>
            <p class="sp-backup-action-description">
                <?php esc_html_e( 'Create an immediate backup of your society\'s database and settings. This may take a few minutes for large databases.', 'societypress' ); ?>
            </p>
            <button type="button" id="sp-backup-now-btn" class="button button-primary button-hero">
                <?php esc_html_e( 'Back Up Now', 'societypress' ); ?>
            </button>
        </div>

        <!-- ============================================================ -->
        <!-- Existing Backups Table                                       -->
        <!-- ============================================================ -->
        <h2><?php esc_html_e( 'Existing Backups', 'societypress' ); ?></h2>

        <?php if ( empty( $backups ) ) : ?>
            <p class="sp-backup-empty-message">
                <?php esc_html_e( 'No backups yet. Click "Back Up Now" to create your first backup.', 'societypress' ); ?>
            </p>
        <?php else : ?>
            <table class="widefat striped sp-backup-table" id="sp-backup-table">
                <thead>
                    <tr>
                        <th><?php esc_html_e( 'Date', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Size', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Type', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Contents', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                    </tr>
                </thead>
                <tbody>
                    <?php foreach ( $backups as $backup ) : ?>
                        <tr data-backup-id="<?php echo esc_attr( $backup->id ); ?>">
                            <td>
                                <?php
                                // WHY: Show both date and time so Harold can distinguish
                                // between a morning manual backup and an afternoon one.
                                echo esc_html( wp_date( 'M j, Y \a\t g:i A', strtotime( $backup->created_at ) ) );
                                ?>
                            </td>
                            <td>
                                <?php
                                if ( $backup->status === 'complete' && $backup->file_size > 0 ) {
                                    echo esc_html( size_format( $backup->file_size, 1 ) );
                                } else {
                                    echo '&mdash;';
                                }
                                ?>
                            </td>
                            <td>
                                <?php
                                // WHY: Distinguish manual from scheduled so Harold knows
                                // which backups he triggered vs. which ran automatically.
                                if ( $backup->trigger_type === 'manual' ) {
                                    esc_html_e( 'Manual', 'societypress' );
                                } else {
                                    esc_html_e( 'Scheduled', 'societypress' );
                                }
                                ?>
                            </td>
                            <td>
                                <?php
                                // WHY: Show what's included so Harold knows whether an
                                // older backup has his uploads or just the database.
                                $parts = [];
                                if ( $backup->includes_db )       $parts[] = __( 'Database', 'societypress' );
                                if ( $backup->includes_settings ) $parts[] = __( 'Settings', 'societypress' );
                                if ( $backup->includes_uploads )  $parts[] = __( 'Uploads', 'societypress' );
                                echo esc_html( implode( ', ', $parts ) ?: '—' );
                                ?>
                            </td>
                            <td>
                                <?php
                                $status_labels = [
                                    'complete' => __( 'Complete', 'societypress' ),
                                    'running'  => __( 'Running', 'societypress' ),
                                    'pending'  => __( 'Pending', 'societypress' ),
                                    'failed'   => __( 'Failed', 'societypress' ),
                                ];
                                $status_classes = [
                                    'complete' => 'sp-backup-status-complete',
                                    'running'  => 'sp-backup-status-running',
                                    'pending'  => 'sp-backup-status-pending',
                                    'failed'   => 'sp-backup-status-failed',
                                ];
                                $status_label = $status_labels[ $backup->status ] ?? $backup->status;
                                $status_class = $status_classes[ $backup->status ] ?? '';
                                ?>
                                <span class="sp-backup-status <?php echo esc_attr( $status_class ); ?>">
                                    <?php echo esc_html( $status_label ); ?>
                                </span>
                                <?php if ( $backup->status === 'failed' && ! empty( $backup->note ) ) : ?>
                                    <span class="sp-backup-note"><?php echo esc_html( $backup->note ); ?></span>
