            max-width: 960px;
        }
        .sp-backup-empty-message {
            color: #646970;
            font-style: italic;
        }
        .sp-backup-status {
            display: inline-block;
            padding: 2px 10px;
            border-radius: 12px;
            font-size: 12px;
            font-weight: 500;
            line-height: 1.6;
        }
        .sp-backup-status-complete {
            background: #d4edda;
            color: #155724;
        }
        .sp-backup-status-running {
            background: #fff3cd;
            color: #856404;
        }
        .sp-backup-status-pending {
            background: #e2e3e5;
            color: #383d41;
        }
        .sp-backup-status-failed {
            background: #f8d7da;
            color: #721c24;
        }
        .sp-backup-note {
            display: block;
            font-size: 12px;
            color: #721c24;
            margin-top: 4px;
        }

        /* sp-backup-settings: Settings form section spacing. */
