            transition: opacity 0.2s;
        }
        .sp-backup-auto-row.sp-hidden {
            display: none;
        }

        /* Button states during AJAX operations */
        .sp-backup-btn-working {
            opacity: 0.7;
            pointer-events: none;
        }
