    <!-- ================================================================ -->
    <!-- Backup Page JavaScript                                           -->
    <!-- WHY: All AJAX interactions for the backup page — creating,       -->
    <!--      deleting, and saving settings. Vanilla JS, no jQuery.       -->
    <!-- ================================================================ -->
    <script>
    (function() {
        'use strict';

        var backupNonce   = <?php echo wp_json_encode( $backup_nonce ); ?>;
        var deleteNonce   = <?php echo wp_json_encode( $delete_nonce ); ?>;
        var settingsNonce = <?php echo wp_json_encode( $settings_nonce ); ?>;

        // ---- Toggle day-of-month row visibility based on auto toggle ----
        var autoToggle = document.getElementById('sp-backup-auto-toggle');
        var autoRows   = document.querySelectorAll('.sp-backup-auto-row');

        function updateAutoRowVisibility() {
            autoRows.forEach(function(row) {
                if (autoToggle && autoToggle.checked) {
                    row.classList.remove('sp-hidden');
                } else {
                    row.classList.add('sp-hidden');
                }
            });
        }

        if (autoToggle) {
            autoToggle.addEventListener('change', updateAutoRowVisibility);
            updateAutoRowVisibility();
        }

        // ---- Helper: Show a notice at the top of the page ----
        function showNotice(message, type) {
            var container = document.getElementById('sp-backup-notices');
            if (!container) return;
            var div = document.createElement('div');
            div.className = 'notice notice-' + (type || 'success') + ' is-dismissible';
            div.innerHTML = '<p>' + message + '</p>' +
                '<button type="button" class="notice-dismiss"><span class="screen-reader-text">' +
                <?php echo wp_json_encode( __( 'Dismiss this notice.', 'societypress' ) ); ?> +
                '</span></button>';
            container.appendChild(div);
            // Wire up the dismiss button
            div.querySelector('.notice-dismiss').addEventListener('click', function() {
                div.remove();
            });
        }

        // ---- "Back Up Now" handler ----
        var backupBtn = document.getElementById('sp-backup-now-btn');
        if (backupBtn) {
            backupBtn.addEventListener('click', function() {
                backupBtn.disabled = true;
                backupBtn.classList.add('sp-backup-btn-working');
                backupBtn.innerHTML = '<span class="sp-spinner sp-spinner--light"></span> ' +
                    <?php echo wp_json_encode( __( 'Creating backup...', 'societypress' ) ); ?>;

                var formData = new FormData();
                formData.append('action', 'sp_create_manual_backup');
                formData.append('nonce', backupNonce);

                fetch(ajaxurl, { method: 'POST', body: formData })
                    .then(function(response) { return response.json(); })
                    .then(function(data) {
                        backupBtn.disabled = false;
                        backupBtn.classList.remove('sp-backup-btn-working');
                        backupBtn.textContent = <?php echo wp_json_encode( __( 'Back Up Now', 'societypress' ) ); ?>;

                        if (data.success) {
                            showNotice(data.data.message, 'success');
                            // Reload the page to show the new backup in the table
                            window.location.reload();
                        } else {
                            showNotice(data.data || <?php echo wp_json_encode( __( 'Backup failed. Please try again.', 'societypress' ) ); ?>, 'error');
                        }
                    })
                    .catch(function() {
                        backupBtn.disabled = false;
                        backupBtn.classList.remove('sp-backup-btn-working');
                        backupBtn.textContent = <?php echo wp_json_encode( __( 'Back Up Now', 'societypress' ) ); ?>;
                        showNotice(<?php echo wp_json_encode( __( 'An unexpected error occurred. Please try again.', 'societypress' ) ); ?>, 'error');
                    });
            });
        }

        // ---- Delete backup handler ----
        document.querySelectorAll('.sp-backup-delete-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var backupId = btn.getAttribute('data-id');
                spConfirm(<?php echo wp_json_encode( __( 'Delete this backup? This cannot be undone.', 'societypress' ) ); ?>, function() {
                    btn.disabled = true;
                    btn.classList.add('sp-backup-btn-working');

                    var formData = new FormData();
                    formData.append('action', 'sp_delete_backup');
                    formData.append('nonce', deleteNonce);
                    formData.append('id', backupId);

                    fetch(ajaxurl, { method: 'POST', body: formData })
                        .then(function(response) { return response.json(); })
                        .then(function(data) {
                            if (data.success) {
                                // Remove the row from the table
                                var row = document.querySelector('tr[data-backup-id="' + backupId + '"]');
                                if (row) row.remove();
                                showNotice(data.data.message, 'success');
                                // If no rows left, show the empty message
                                var tbody = document.querySelector('#sp-backup-table tbody');
                                if (tbody && tbody.children.length === 0) {
                                    window.location.reload();
                                }
                            } else {
                                btn.disabled = false;
                                btn.classList.remove('sp-backup-btn-working');
                                showNotice(data.data || <?php echo wp_json_encode( __( 'Could not delete backup.', 'societypress' ) ); ?>, 'error');
                            }
                        })
                        .catch(function() {
                            btn.disabled = false;
                            btn.classList.remove('sp-backup-btn-working');
                            showNotice(<?php echo wp_json_encode( __( 'An unexpected error occurred.', 'societypress' ) ); ?>, 'error');
                        });
                });
            });
        });

        // ---- Save settings handler ----
        var settingsForm = document.getElementById('sp-backup-settings-form');
        if (settingsForm) {
            settingsForm.addEventListener('submit', function(e) {
                e.preventDefault();
                var saveBtn = document.getElementById('sp-backup-save-settings-btn');
                if (saveBtn) {
                    saveBtn.disabled = true;
                    saveBtn.classList.add('sp-backup-btn-working');
                }

                var formData = new FormData(settingsForm);
                formData.append('action', 'sp_save_backup_settings');
                formData.append('nonce', settingsNonce);

                fetch(ajaxurl, { method: 'POST', body: formData })
                    .then(function(response) { return response.json(); })
                    .then(function(data) {
                        if (saveBtn) {
                            saveBtn.disabled = false;
                            saveBtn.classList.remove('sp-backup-btn-working');
                        }
                        if (data.success) {
                            showNotice(data.data.message, 'success');
                        } else {
                            showNotice(data.data || <?php echo wp_json_encode( __( 'Could not save settings.', 'societypress' ) ); ?>, 'error');
                        }
                    })
                    .catch(function() {
                        if (saveBtn) {
                            saveBtn.disabled = false;
                            saveBtn.classList.remove('sp-backup-btn-working');
                        }
                        showNotice(<?php echo wp_json_encode( __( 'An unexpected error occurred.', 'societypress' ) ); ?>, 'error');
                    });
            });
        }
    })();
    </script>
    <?php
}


// ============================================================================
// BACKUPS — AJAX: Create Manual Backup
//
// WHY: The "Back Up Now" button triggers this. It reuses the same export
//      pipeline as sp_run_scheduled_backup() but sets trigger_type to 'manual'
//      and returns JSON instead of running silently via cron.
// ============================================================================
add_action( 'wp_ajax_sp_create_manual_backup', function() {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'You do not have permission to create backups.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_create_manual_backup' ) ) {
        wp_send_json_error( __( 'Security check failed. Please reload the page and try again.', 'societypress' ) );
    }

    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Don't allow overlapping backups
    $running = $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}backups WHERE status = 'running' AND created_at > DATE_SUB(NOW(), INTERVAL 30 MINUTE)"
    );
    if ( $running > 0 ) {
        wp_send_json_error( __( 'A backup is already in progress. Please wait for it to complete.', 'societypress' ) );
    }

    // Clean up any stale records first
    sp_cleanup_stale_backups();

    // Give the backup room to run — shared hosting often has 30s default
    set_time_limit( 600 );

    $include_db       = ! empty( $settings['backup_include_db'] );
    $include_uploads  = ! empty( $settings['backup_include_uploads'] );
    $include_settings = isset( $settings['backup_include_settings'] ) ? (int) $settings['backup_include_settings'] : 1;

    // At least one component must be included
    if ( ! $include_db && ! $include_uploads && ! $include_settings ) {
        wp_send_json_error( __( 'Nothing to back up — all backup components are disabled in settings.', 'societypress' ) );
    }

    $backup_dir = sp_get_backup_dir();
    $token      = wp_generate_password( 8, false );
    $date_str   = current_time( 'Y-m-d-His' );
    $filename   = "sp-backup-{$date_str}-{$token}.zip";

    // Determine backup type label
    $type = 'full';
    if ( $include_db && ! $include_uploads ) $type = 'db_only';
    if ( ! $include_db && $include_uploads )  $type = 'uploads_only';

    // Create metadata row
    $wpdb->insert( $prefix . 'backups', [
        'filename'          => $filename,
        'backup_type'       => $type,
        'includes_db'       => $include_db ? 1 : 0,
        'includes_uploads'  => $include_uploads ? 1 : 0,
        'includes_settings' => $include_settings ? 1 : 0,
        'status'            => 'running',
        'trigger_type'      => 'manual',
        'created_by'        => get_current_user_id(),
        'started_at'        => current_time( 'mysql' ),
    ] );
    $backup_id = (int) $wpdb->insert_id;

    if ( ! $backup_id ) {
        wp_send_json_error( __( 'Could not create backup record in the database.', 'societypress' ) );
    }

    $temp_dir     = $backup_dir . '/tmp-' . $backup_id;
    wp_mkdir_p( $temp_dir );
    $tables_count = 0;
    $files_count  = 0;

    try {
        // ---- Export database tables ----
        if ( $include_db ) {
            $db_dir = $temp_dir . '/database';
            wp_mkdir_p( $db_dir );
            $tables = sp_backup_get_tables();
            foreach ( $tables as $table ) {
                sp_backup_export_table( $table, $db_dir );
                $tables_count++;
            }
        }

        // ---- Export settings ----
        if ( $include_settings ) {
            $settings_dir = $temp_dir . '/settings';
            wp_mkdir_p( $settings_dir );
            sp_backup_export_settings( $settings_dir );
        }

        // ---- Copy uploads ----
        if ( $include_uploads ) {
            $upload_dir   = wp_upload_dir();
            $uploads_src  = $upload_dir['basedir'];
            $uploads_dest = $temp_dir . '/uploads';
            wp_mkdir_p( $uploads_dest );

            $iterator = new RecursiveIteratorIterator(
                new RecursiveDirectoryIterator( $uploads_src, RecursiveDirectoryIterator::SKIP_DOTS ),
                RecursiveIteratorIterator::SELF_FIRST
            );

            foreach ( $iterator as $item ) {
                $relative = substr( $item->getPathname(), strlen( $uploads_src ) + 1 );
                // Skip the backups directory itself
                if ( strpos( $relative, 'sp-backups' ) === 0 ) continue;

                $dest_path = $uploads_dest . '/' . $relative;
                if ( $item->isDir() ) {
                    wp_mkdir_p( $dest_path );
                } else {
                    copy( $item->getPathname(), $dest_path );
                    $files_count++;
                }
            }
        }

        // ---- Create manifest ----
        sp_backup_create_manifest( $temp_dir, [
            'db'         => $include_db,
            'uploads'    => $include_uploads,
            'settings'   => $include_settings,
            'tables'     => $include_db ? sp_backup_get_tables() : [],
            'file_count' => $files_count,
        ] );

        // ---- Create ZIP ----
        $zip_path = $backup_dir . '/' . $filename;
        $success  = sp_backup_create_zip( $temp_dir, $zip_path );

        if ( $success && file_exists( $zip_path ) ) {
            $file_size = filesize( $zip_path );
            $wpdb->update( $prefix . 'backups', [
                'status'       => 'complete',
                'file_size'    => $file_size,
                'tables_count' => $tables_count,
                'files_count'  => $files_count,
                'completed_at' => current_time( 'mysql' ),
            ], [ 'id' => $backup_id ] );

            sp_audit( 'backup_created', sprintf(
                'Manual backup created: %d tables, %d files, %s',
                $tables_count, $files_count, size_format( $file_size )
            ), 'backup', $backup_id );

            // Enforce retention
            sp_prune_old_backups();

            // Clean up temp
            sp_backup_rmdir( $temp_dir );

            wp_send_json_success( [
                'message' => sprintf(
                    /* translators: %s: human-readable file size like "2.4 MB" */
                    __( 'Backup created successfully (%s).', 'societypress' ),
                    size_format( $file_size, 1 )
                ),
                'id' => $backup_id,
            ] );
        } else {
            $wpdb->update( $prefix . 'backups', [
                'status' => 'failed',
                'note'   => __( 'ZIP creation failed.', 'societypress' ),
            ], [ 'id' => $backup_id ] );

            sp_backup_rmdir( $temp_dir );
            wp_send_json_error( __( 'Backup failed — could not create ZIP archive.', 'societypress' ) );
        }
    } catch ( \Throwable $e ) {
        $wpdb->update( $prefix . 'backups', [
            'status' => 'failed',
            'note'   => $e->getMessage(),
        ], [ 'id' => $backup_id ] );
        error_log( 'SocietyPress Manual Backup error: ' . $e->getMessage() );
        sp_backup_rmdir( $temp_dir );
        wp_send_json_error( __( 'Backup failed due to an unexpected error. Check the server error log for details.', 'societypress' ) );
    }
} );


// ============================================================================
// BACKUPS — AJAX: Download Backup
//
// WHY: Backup ZIPs live in a .htaccess-protected directory — they can't be
//      downloaded via direct URL (by design, since they contain sensitive data).
//      This handler verifies the user is an admin, looks up the backup record,
//      and streams the file with proper Content-Disposition headers.
// ============================================================================
add_action( 'wp_ajax_sp_download_backup', function() {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'You do not have permission to download backups.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_download_backup' ) ) {
        wp_die( esc_html__( 'Security check failed. Please reload the page and try again.', 'societypress' ) );
    }

    $id = (int) ( $_GET['id'] ?? 0 );
    if ( ! $id ) {
        wp_die( esc_html__( 'Invalid backup ID.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $backup = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}backups WHERE id = %d AND status = 'complete'",
        $id
    ) );

    if ( ! $backup ) {
        wp_die( esc_html__( 'Backup not found or not yet complete.', 'societypress' ) );
    }

    $file_path = sp_get_backup_dir() . '/' . $backup->filename;
    if ( ! file_exists( $file_path ) ) {
        wp_die( esc_html__( 'Backup file not found on disk. It may have been manually deleted.', 'societypress' ) );
    }

    // Stream the file to the browser
    header( 'Content-Type: application/zip' );
    header( 'Content-Disposition: attachment; filename="' . basename( $backup->filename ) . '"' );
    header( 'Content-Length: ' . filesize( $file_path ) );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    // WHY readfile() instead of file_get_contents(): readfile() streams the
    // file directly to output without loading it all into memory. A 200MB
    // backup ZIP would crash PHP with file_get_contents().
    readfile( $file_path );
    exit;
} );


// ============================================================================
// BACKUPS — AJAX: Delete Backup
//
// WHY: Harold needs to free disk space or remove old backups he no longer
//      needs. This deletes both the ZIP file on disk and the metadata row
//      in sp_backups.
// ============================================================================
add_action( 'wp_ajax_sp_delete_backup', function() {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'You do not have permission to delete backups.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_delete_backup' ) ) {
        wp_send_json_error( __( 'Security check failed. Please reload the page and try again.', 'societypress' ) );
    }

    $id = (int) ( $_POST['id'] ?? 0 );
    if ( ! $id ) {
        wp_send_json_error( __( 'Invalid backup ID.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $backup = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}backups WHERE id = %d",
        $id
    ) );

    if ( ! $backup ) {
        wp_send_json_error( __( 'Backup not found.', 'societypress' ) );
    }

    // Delete the file from disk
    $file_path = sp_get_backup_dir() . '/' . $backup->filename;
    if ( file_exists( $file_path ) ) {
        wp_delete_file( $file_path );
    }

    // Delete the database row
    $wpdb->delete( $prefix . 'backups', [ 'id' => $id ] );

    sp_audit( 'backup_deleted', sprintf(
        'Backup deleted: %s (%s)',
        $backup->filename,
        size_format( $backup->file_size )
    ), 'backup', $id );

    wp_send_json_success( [
        'message' => __( 'Backup deleted.', 'societypress' ),
    ] );
} );


// ============================================================================
// BACKUPS — AJAX: Save Backup Settings
//
// WHY: The settings form on the Backups page saves via AJAX so Harold doesn't
//      have to leave the page or lose his scroll position. All backup-related
//      settings are stored in the main societypress_settings option array.
// ============================================================================
add_action( 'wp_ajax_sp_save_backup_settings', function() {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'You do not have permission to change backup settings.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_POST['nonce'] ?? '', 'sp_save_backup_settings' ) ) {
        wp_send_json_error( __( 'Security check failed. Please reload the page and try again.', 'societypress' ) );
    }

    $settings = get_option( 'societypress_settings', [] );

    // What to include
    $settings['backup_include_db']       = ! empty( $_POST['backup_include_db'] ) ? 1 : 0;
    $settings['backup_include_settings'] = ! empty( $_POST['backup_include_settings'] ) ? 1 : 0;
    $settings['backup_include_uploads']  = ! empty( $_POST['backup_include_uploads'] ) ? 1 : 0;

    // Automated backup toggle
    $settings['backup_auto_enabled'] = ! empty( $_POST['backup_auto_enabled'] ) ? 1 : 0;

    // Day of month — clamp to 1–28
    $day = (int) ( $_POST['backup_day_of_month'] ?? 1 );
    $settings['backup_day_of_month'] = max( 1, min( 28, $day ) );

    // Retention — at least 1, sane maximum of 50
    $retention = (int) ( $_POST['backup_retention'] ?? 3 );
    $settings['backup_retention'] = max( 1, min( 50, $retention ) );

    // Email notification
    $settings['backup_email_notify'] = ! empty( $_POST['backup_email_notify'] ) ? 1 : 0;
    $settings['backup_email_attach'] = ! empty( $_POST['backup_email_attach'] ) ? 1 : 0;

    // WHY: When the auto toggle changes, we need to reschedule or clear the
    // cron. The existing 'init' handler reads backup_frequency, so we sync
    // that setting here. When auto is enabled, we set frequency to 'daily'
    // (the cron fires daily and the handler checks if today matches the
    // configured day_of_month). When disabled, we set 'off' to clear cron.
    if ( ! empty( $settings['backup_auto_enabled'] ) ) {
        $settings['backup_frequency'] = 'daily';
    } else {
        $settings['backup_frequency'] = 'off';
    }

    update_option( 'societypress_settings', $settings );

    // If auto was just turned off, clear any scheduled cron immediately
    if ( empty( $settings['backup_auto_enabled'] ) ) {
        wp_clear_scheduled_hook( 'sp_backup_cron' );
    }

    sp_audit( 'backup_settings_changed', __( 'Backup settings updated.', 'societypress' ), 'settings' );

    wp_send_json_success( [
        'message' => __( 'Backup settings saved.', 'societypress' ),
    ] );
} );


// ============================================================================
// BACKUPS — Cron: Monthly Day-of-Month Check + Email Notification
//
// WHY: The existing cron fires daily (when auto-enabled). This filter wraps
//      the cron handler to check whether today matches the configured
//      day_of_month before running. After a successful backup, it sends an
//      email notification if that setting is on, optionally attaching the ZIP
//      if it's under 10 MB.
// ============================================================================
add_action( 'sp_backup_cron', 'sp_backup_cron_monthly_gate', 5 );

/**
 * Gate the scheduled backup to only run on the configured day of the month.
 *
 * WHY: The cron fires daily so we can do the day-of-month check in PHP rather
 *      than trying to schedule a "monthly" WordPress cron (which WP doesn't
 *      natively support). If today isn't the right day, we bail before the
 *      actual backup runs — sp_run_scheduled_backup is hooked at default
 *      priority 10, so this priority-5 hook can remove it to prevent execution.
 */
function sp_backup_cron_monthly_gate(): void {
    $settings = get_option( 'societypress_settings', [] );

    // If auto backups are disabled, don't run
    if ( empty( $settings['backup_auto_enabled'] ) ) {
        remove_action( 'sp_backup_cron', 'sp_run_scheduled_backup' );
        return;
    }

    // Check if today matches the configured day of month
    $target_day = (int) ( $settings['backup_day_of_month'] ?? 1 );
    $today      = (int) current_time( 'j' ); // Day of the month without leading zeros

    if ( $today !== $target_day ) {
        // Not the right day — prevent sp_run_scheduled_backup from running
        remove_action( 'sp_backup_cron', 'sp_run_scheduled_backup' );
        return;
    }

    // It IS the right day — sp_run_scheduled_backup will fire at priority 10.
    // After it runs, we send the notification email (priority 15).
}


add_action( 'sp_backup_cron', 'sp_backup_cron_email_notification', 15 );

/**
 * Send email notification after a scheduled backup completes.
 *
 * WHY: Harold may not log in every day. An email confirms the backup ran
 *      successfully (or warns him if it failed) without him having to check.
 *      If the "attach ZIP" option is on and the file is under 10 MB, we
 *      include it — so Harold has an off-site copy in his email archive.
 *      The 10 MB limit prevents bounced emails from hosts with attachment
 *      size restrictions.
 */
function sp_backup_cron_email_notification(): void {
    $settings = get_option( 'societypress_settings', [] );

    // Only send if notification is enabled
    if ( empty( $settings['backup_email_notify'] ) ) {
        return;
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Find the most recent backup (the one we just created)
    $backup = $wpdb->get_row(
        "SELECT * FROM {$prefix}backups WHERE trigger_type = 'scheduled' ORDER BY created_at DESC LIMIT 1"
    );

    if ( ! $backup ) {
        return;
    }

    // Only notify for backups created in the last 10 minutes (i.e., the one
    // that just ran, not an old one from last month)
    $backup_time = strtotime( $backup->created_at );
    if ( $backup_time < time() - 600 ) {
        return;
    }

    $admin_email = get_option( 'admin_email' );
    $site_name   = get_bloginfo( 'name' );

    if ( $backup->status === 'complete' ) {
        $subject = sprintf(
            /* translators: %s: site name */
            __( '[%s] Backup completed successfully', 'societypress' ),
            $site_name
        );
        $message = sprintf(
            /* translators: 1: site name, 2: date/time, 3: file size */
            __( "A scheduled backup of %1\$s completed successfully.\n\nDate: %2\$s\nSize: %3\$s\nTables: %4\$d\n\nYou can download this backup from the Backups page in your admin panel.", 'societypress' ),
            $site_name,
            wp_date( 'F j, Y \a\t g:i A', strtotime( $backup->completed_at ) ),
            size_format( $backup->file_size, 1 ),
            $backup->tables_count
        );
    } else {
        $subject = sprintf(
            /* translators: %s: site name */
            __( '[%s] Backup failed', 'societypress' ),
            $site_name
        );
        $message = sprintf(
            /* translators: 1: site name, 2: error note */
            __( "A scheduled backup of %1\$s failed.\n\nError: %2\$s\n\nPlease check the Backups page in your admin panel.", 'societypress' ),
            $site_name,
            $backup->note ?: __( 'Unknown error', 'societypress' )
        );
    }

    $attachments = [];

    // Attach the ZIP if enabled, the backup succeeded, and it's under 10 MB
    // WHY 10 MB: Most email providers and shared hosting SMTP relays reject
    // attachments larger than 10-25 MB. 10 MB is the safe floor that works
    // everywhere — Gmail, Outlook, Fastmail, and budget SMTP services.
    if ( $backup->status === 'complete'
         && ! empty( $settings['backup_email_attach'] )
         && $backup->file_size > 0
         && $backup->file_size <= 10 * 1024 * 1024 ) {

        $file_path = sp_get_backup_dir() . '/' . $backup->filename;
        if ( file_exists( $file_path ) ) {
            $attachments[] = $file_path;
        }
    }

    // If attachment was requested but file is too large, note that in the email
    if ( $backup->status === 'complete'
         && ! empty( $settings['backup_email_attach'] )
         && $backup->file_size > 10 * 1024 * 1024 ) {

        $message .= "\n\n" . sprintf(
            /* translators: %s: file size */
            __( 'Note: The backup file (%s) exceeds the 10 MB email attachment limit. Please download it from the admin panel.', 'societypress' ),
            size_format( $backup->file_size, 1 )
        );
    }

    wp_mail( $admin_email, $subject, $message, '', $attachments );
}


/**
 * Create a Stripe Checkout Session for an event registration payment.
 *
 * WHY: Stripe Checkout is a hosted payment page. We tell Stripe "charge $X for
 *      event Y" and it gives us a URL. The registrant goes there, enters their
 *      card on Stripe's secure page, and Stripe redirects them back to our site
 *      when done. This eliminates PCI compliance entirely — our server never
 *      sees a credit card number.
 *
 * We use the Stripe REST API directly via wp_remote_post() instead of the PHP
 * SDK to avoid adding a Composer dependency. The API is simple enough for our
 * use case — we only need Checkout Sessions and Refunds.
 *
 * @param object $event            The event row from sp_events.
 * @param int    $registration_id  The new registration ID.
 * @param float  $fee_amount       Total fee to charge.
 * @param array  $settings         The societypress_settings option array.
 * @return string|WP_Error         The checkout URL on success, WP_Error on failure.
 */
function sp_create_stripe_checkout_session( object $event, int $registration_id, float $fee_amount, array $settings ) {
    $secret_key = sp_stripe_get_secret_key( $settings );
    if ( empty( $secret_key ) ) {
        return new WP_Error( 'stripe_not_configured', __( 'Stripe is not configured.', 'societypress' ) );
    }

    $currency = $settings['stripe_currency'] ?? 'usd';

    // Stripe expects amounts in the smallest currency unit (cents for USD)
    // WHY: $25.00 becomes 2500. This is a Stripe convention to avoid
    //      floating-point rounding issues.
    $amount_cents = (int) round( $fee_amount * 100 );

    // Build the return URLs
    // WHY: After the customer pays (or cancels), Stripe redirects them back to
    //      our event detail page with query parameters so we know what happened.
    //      We include the registration_id so we can look up and update the record.
    $events_page_id = 0;
    $pages = get_pages( [ 'meta_key' => '_wp_page_template', 'meta_value' => 'sp-events' ] );
    if ( ! empty( $pages ) ) {
        $events_page_id = $pages[0]->ID;
    }

    $base_url = $events_page_id
        ? add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) )
        : home_url();

    $success_url = add_query_arg( [
        'sp_payment' => 'success',
        'sp_session' => '{CHECKOUT_SESSION_ID}',
    ], $base_url );

    $cancel_url = add_query_arg( [
        'sp_payment' => 'cancelled',
    ], $base_url );

    // Build the line item description
    $site_name = get_bloginfo( 'name' );
    $line_item_name = $event->title;
    if ( strlen( $line_item_name ) > 100 ) {
        $line_item_name = substr( $line_item_name, 0, 97 ) . '...';
    }

    // Call the Stripe API to create a Checkout Session
    $response = wp_remote_post( 'https://api.stripe.com/v1/checkout/sessions', [
        'timeout' => 30,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
            'Content-Type'  => 'application/x-www-form-urlencoded',
        ],
        'body' => [
            'payment_method_types[0]' => 'card',
            'mode'                    => 'payment',
            'success_url'             => $success_url,
            'cancel_url'              => $cancel_url,
            'client_reference_id'     => (string) $registration_id,
            'metadata[registration_id]' => (string) $registration_id,
            'metadata[event_id]'        => (string) $event->id,
            'metadata[site_url]'        => home_url(),
            'line_items[0][price_data][currency]'     => $currency,
            'line_items[0][price_data][unit_amount]'   => $amount_cents,
            'line_items[0][price_data][product_data][name]' => $line_item_name,
            'line_items[0][price_data][product_data][description]' =>
                sprintf( __( 'Registration for %1$s — %2$s', 'societypress' ), $event->title, $site_name ),
            'line_items[0][quantity]' => 1,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        return new WP_Error( 'stripe_api_error', __( 'Could not connect to payment processor. Please try again.', 'societypress' ) );
    }

    $body = json_decode( wp_remote_retrieve_body( $response ), true );
    $code = wp_remote_retrieve_response_code( $response );

    if ( $code !== 200 || empty( $body['url'] ) ) {
        $error_msg = $body['error']['message'] ?? 'Payment setup failed. Please try again.';
        error_log( 'SocietyPress Stripe error: ' . $error_msg );
        return new WP_Error( 'stripe_session_error', __( 'Could not set up payment. Please try again or choose to pay at the door.', 'societypress' ) );
    }

    // Store the Stripe session ID on the registration for later verification
    global $wpdb;
    $wpdb->update(
        $wpdb->prefix . 'sp_event_registrations',
        [ 'notes' => 'stripe_session:' . $body['id'] ],
        [ 'id' => $registration_id ]
    );

    return $body['url'];
}


/**
 * Handle the return from Stripe Checkout.
 *
 * WHY: After paying on Stripe's page, the customer is redirected back to the
 *      event detail page with ?sp_payment=success&sp_session=cs_xxx in the URL.
 *      We verify the session with Stripe's API, confirm the payment actually
 *      went through, and update the registration record accordingly.
 *
 *      This runs early (on template_redirect) so the registration is already
 *      updated by the time the page renders — the frontend JS just shows a
 *      "Payment received" message based on the URL parameter.
 */
add_action( 'template_redirect', function () {
    // Only process Stripe returns on the events page
    if ( ! is_page() || get_page_template_slug() !== 'sp-events' ) return;

    $payment_status = sanitize_text_field( $_GET['sp_payment'] ?? '' );
    $session_id     = sanitize_text_field( $_GET['sp_session'] ?? '' );

    // Only handle successful returns with a session ID
    if ( $payment_status !== 'success' || empty( $session_id ) ) return;

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) return;

    // Verify the Checkout Session with Stripe
    // WHY: We never trust the URL parameters alone — an attacker could craft a
    //      fake success URL. We call Stripe's API to confirm the session exists
    //      and payment actually succeeded before marking anything as paid.
    $response = wp_remote_get( 'https://api.stripe.com/v1/checkout/sessions/' . $session_id, [
        'timeout' => 15,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
        ],
    ] );

    if ( is_wp_error( $response ) ) return;

    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( empty( $body['payment_status'] ) || $body['payment_status'] !== 'paid' ) return;

    // Find the registration from the session metadata
    $registration_id = (int) ( $body['client_reference_id'] ?? 0 );
    if ( ! $registration_id ) return;

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    // Only update if still in pending payment status
    // WHY: Prevents double-processing if the user refreshes the success page
    //      or if a webhook fires at the same time (future enhancement).
    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    if ( ! $reg || $reg->payment_status === 'paid' ) return;

    // WHY: Prevent a logged-in user from confirming payment for another user's
    // registration by visiting the success URL with someone else's session ID.
    if ( is_user_logged_in() && $reg->user_id && (int) $reg->user_id !== get_current_user_id() ) {
        return;
    }

    $wpdb->update(
        $reg_table,
        [
            'payment_status' => 'paid',
            'payment_method' => 'stripe',
            'payment_date'   => current_time( 'mysql' ),
            'notes'          => 'stripe_session:' . $session_id . '|stripe_pi:' . ( $body['payment_intent'] ?? '' ),
        ],
        [ 'id' => $registration_id ]
    );

    // Send confirmation email now that payment is confirmed
    // WHY: For Stripe payments, we hold the confirmation email until payment
    //      actually goes through. Nobody wants a "you're registered!" email
    //      followed by "just kidding, your card was declined."
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d", $reg->event_id
    ) );

    if ( $event ) {
        $recipient_email = '';
        if ( $reg->user_id ) {
            $user = get_userdata( $reg->user_id );
            $recipient_email = $user ? $user->user_email : '';
        } elseif ( $reg->guest_email ) {
            $recipient_email = $reg->guest_email;
        }
        if ( $recipient_email ) {
            sp_send_registration_email(
                $event, $registration_id, 'confirmed',
                $recipient_email, (int) $reg->party_size, (float) $reg->fee_amount
            );
        }
    }
} );


/**
 * Handle the return from PayPal Checkout for event registration.
 *
 * WHY: After approving payment on PayPal's site, the buyer is redirected back
 *      to the event page with ?sp_payment=success&sp_paypal=1&sp_pp_reg=N
 *      and a PayPal-appended token parameter. We capture the payment via the
 *      PayPal API, verify it succeeded, and update the registration record.
 *
 *      This runs on template_redirect (same as Stripe) so the registration is
 *      already updated by the time the page renders.
 */
add_action( 'template_redirect', function () {
    if ( ! is_page() || get_page_template_slug() !== 'sp-events' ) return;

    $payment_status = sanitize_text_field( $_GET['sp_payment'] ?? '' );
    $is_paypal      = ! empty( $_GET['sp_paypal'] );
    $reg_id         = absint( $_GET['sp_pp_reg'] ?? 0 );

    // Only handle PayPal returns — Stripe returns are handled by the hook above
    if ( $payment_status !== 'success' || ! $is_paypal || ! $reg_id ) return;

    // PayPal appends a 'token' parameter (the order ID) to the return URL
    $paypal_token = sanitize_text_field( $_GET['token'] ?? '' );
    if ( empty( $paypal_token ) ) return;

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $reg_id
    ) );

    if ( ! $reg || $reg->payment_status === 'paid' ) return;

    if ( is_user_logged_in() && $reg->user_id && (int) $reg->user_id !== get_current_user_id() ) {
        return;
    }

    // Verify the PayPal order ID matches what we stored on this registration
    if ( strpos( $reg->notes ?? '', 'paypal_order:' . $paypal_token ) === false ) {
        return;
    }

    $settings = get_option( 'societypress_settings', [] );
    if ( ! sp_paypal_is_configured( $settings ) ) return;

    $capture = sp_paypal_capture_order( $paypal_token, $settings );

    if ( is_wp_error( $capture ) ) {
        error_log( 'SocietyPress PayPal event capture error: ' . $capture->get_error_message() );
        return;
    }

    $wpdb->update(
        $reg_table,
        [
            'payment_status' => 'paid',
            'payment_method' => 'paypal',
            'payment_date'   => current_time( 'mysql' ),
            'notes'          => 'paypal_order:' . $paypal_token . '|paypal_capture:' . ( $capture['capture_id'] ?? '' ),
        ],
        [ 'id' => $reg_id ]
    );

    sp_audit(
        'event_payment_captured',
        sprintf( 'PayPal payment captured for registration #%d ($%s)', $reg_id, number_format( $capture['capture_amount'] ?? 0, 2 ) ),
        'event_registration',
        $reg_id
    );

    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d", $reg->event_id
    ) );

    if ( $event ) {
        $recipient_email = '';
        if ( $reg->user_id ) {
            $user = get_userdata( $reg->user_id );
            $recipient_email = $user ? $user->user_email : '';
        } elseif ( $reg->guest_email ) {
            $recipient_email = $reg->guest_email;
        }
        if ( $recipient_email ) {
            sp_send_registration_email(
                $event, $reg_id, 'confirmed',
                $recipient_email, (int) $reg->party_size, (float) $reg->fee_amount
            );
        }
    }
} );


// ============================================================================
// EVENTS — iCAL HELPERS (shared between .ics download + subscription feed)
// ============================================================================
//
// WHY: Both the single-event .ics download and the calendar subscription feed
//      need to produce identical, RFC 5545-compliant output. Extracting these
//      helpers into standalone functions avoids duplication and ensures any
//      future fix to iCal formatting applies everywhere at once.
// ============================================================================

/**
 * RFC 5545 line folding — lines must not exceed 75 octets.
 *
 * WHY: Some calendar apps (notably Outlook) strictly enforce this limit.
 *      We fold long lines by inserting CRLF + space at the 75-byte boundary.
 *      mb_strlen/mb_substr with UTF-8 encoding prevent splitting multibyte
 *      characters (e.g., accented names, CJK) mid-byte, which would produce
 *      invalid UTF-8 and corrupt text in calendar apps.
 *
 * @param string $line A single iCal content line (property + value).
 * @return string The line folded to comply with the 75-octet rule.
 */
function sp_ical_fold_line( string $line ): string {
    if ( mb_strlen( $line, 'UTF-8' ) <= 75 ) return $line;
    $folded = '';
    while ( mb_strlen( $line, 'UTF-8' ) > 75 ) {
        if ( $folded === '' ) {
            $folded .= mb_substr( $line, 0, 75, 'UTF-8' );
            $line    = mb_substr( $line, 75, null, 'UTF-8' );
        } else {
            // Continuation lines start with a space (counts toward the 75)
            $folded .= "\r\n " . mb_substr( $line, 0, 74, 'UTF-8' );
            $line    = mb_substr( $line, 74, null, 'UTF-8' );
        }
    }
    if ( $line !== '' ) {
        $folded .= "\r\n " . $line;
    }
    return $folded;
}

/**
 * Escape iCal text values per RFC 5545 §3.3.11.
 *
 * WHY: Semicolons, commas, and backslashes have special meaning in iCal
 *      property values. Without escaping, an event titled "Meet & Greet,
 *      January 5" would break parsing in strict calendar clients.
 *
 * @param string $text Raw text to escape.
 * @return string Text safe for use in iCal property values.
 */
function sp_ical_escape_text( string $text ): string {
    $text = str_replace( '\\', '\\\\', $text );
    $text = str_replace( ';', '\\;', $text );
    $text = str_replace( ',', '\\,', $text );
    return $text;
}

/**
 * Build DTSTART and DTEND lines for an event.
 *
 * WHY: If the event has a start_time, we create a timed event in UTC.
 *      If no time is set, it's treated as an all-day event (DATE format).
 *      All-day DTEND is the day AFTER the event (exclusive end per RFC 5545).
 *
 * @param object $event Event row from the database.
 * @return array Associative array with 'dtstart' and 'dtend' iCal lines.
 */
function sp_ical_build_dt_lines( object $event ): array {
    $event_date = $event->event_date; // YYYY-MM-DD
    $tz         = wp_timezone();

    if ( ! empty( $event->start_time ) ) {
        // Timed event — convert site-local time to UTC for the .ics
        $start_dt = new DateTime( $event_date . ' ' . $event->start_time, $tz );
        $start_dt->setTimezone( new DateTimeZone( 'UTC' ) );

        if ( ! empty( $event->end_time ) ) {
            $end_dt = new DateTime( $event_date . ' ' . $event->end_time, $tz );
            $end_dt->setTimezone( new DateTimeZone( 'UTC' ) );
        } else {
            // No end time — default to 1 hour after start
            $end_dt = clone $start_dt;
            $end_dt->modify( '+1 hour' );
        }

        return [
            'dtstart' => 'DTSTART:' . $start_dt->format( 'Ymd\THis\Z' ),
            'dtend'   => 'DTEND:' . $end_dt->format( 'Ymd\THis\Z' ),
        ];
    }

    // All-day event — use DATE format (no time component)
    $date_val = str_replace( '-', '', $event_date );
    $next_day = wp_date( 'Ymd', strtotime( $event_date . ' +1 day' ) );

    return [
        'dtstart' => 'DTSTART;VALUE=DATE:' . $date_val,
        'dtend'   => 'DTEND;VALUE=DATE:' . $next_day,
    ];
}

/**
 * Build a combined LOCATION string for an event.
 *
 * WHY: Calendar apps display a single location field. Combining venue name,
 *      address, and virtual URL into one comma-separated string gives users
 *      maximum context in their calendar app without needing to open the event.
 *
 * @param object $event Event row from the database.
 * @return string Combined location string (may be empty).
 */
function sp_ical_build_location( object $event ): string {
    $parts = [];
    if ( ! empty( $event->location_name ) ) {
        $parts[] = $event->location_name;
    }
    if ( ! empty( $event->location_address ) ) {
        $parts[] = $event->location_address;
    }
    if ( $event->is_virtual && ! empty( $event->virtual_url ) ) {
        $parts[] = $event->virtual_url;
    }
    return implode( ', ', $parts );
}

/**
 * Build a plain-text DESCRIPTION for an event's iCal entry.
 *
 * WHY: iCal DESCRIPTION is plain text — HTML tags would render as literal
 *      text in calendar apps. We strip tags, normalize line breaks, and
 *      append the virtual meeting URL so members can join directly from
 *      their calendar without navigating back to the website.
 *
 * @param object $event Event row from the database.
 * @return string Plain-text description with iCal-escaped newlines.
 */
function sp_ical_build_description( object $event ): string {
    $description = '';
    if ( ! empty( $event->description ) ) {
        $description = wp_strip_all_tags( $event->description );
        // Normalize line breaks to \n, then escape for iCal
        $description = str_replace( [ "\r\n", "\r" ], "\n", $description );
        $description = str_replace( "\n", "\\n", $description );
    }

    // Add virtual meeting URL to description if available
    if ( $event->is_virtual && ! empty( $event->virtual_url ) ) {
        if ( $description ) {
            $description .= "\\n\\n";
        }
        $description .= __( 'Join online:', 'societypress' ) . ' ' . $event->virtual_url;
    }

    return $description;
}


// ============================================================================
// EVENTS — ADD TO CALENDAR (.ICS DOWNLOAD)
// ============================================================================

/**
 * Serve an .ics file for a single event when ?sp_ics=EVENT_ID is in the URL.
 *
 * WHY: Members want to add society events to their personal calendars (Google,
 *      Apple, Outlook). The simplest, most universal way to do this is an .ics
 *      file — every major calendar app supports it. We intercept early on
 *      template_redirect, generate RFC 5545 compliant VCALENDAR/VEVENT data,
 *      and send it as a file download. No AJAX, no JS dependency — just a link.
 *
 * RFC 5545 compliance notes:
 * - DTSTART/DTEND use YYYYMMDD for all-day events, YYYYMMDDTHHmmssZ for timed
 * - UID is globally unique per event (site URL + event ID)
 * - DESCRIPTION is plain text (HTML stripped), CRLF line breaks per spec
 * - LOCATION combines venue name + address for maximum calendar app compatibility
 * - Lines longer than 75 octets are folded per RFC 5545 §3.1
 *
 * Now uses the shared sp_ical_* helper functions defined above, so formatting
 * stays in sync with the calendar subscription feed.
 */
add_action( 'template_redirect', function () {
    if ( ! isset( $_GET['sp_ics'] ) ) return;

    $event_id = (int) $_GET['sp_ics'];
    if ( $event_id < 1 ) return;

    global $wpdb;
    $event = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_events WHERE id = %d",
        $event_id
    ) );

    if ( ! $event ) {
        wp_die( __( 'Event not found.', 'societypress' ), 404 );
    }

    // Visibility check — members_only events require login
    if ( $event->visibility === 'members_only' && ! is_user_logged_in() ) {
        wp_die( __( 'You must be logged in to download this event.', 'societypress' ), 403 );
    }

    // Build date/time, location, and description using shared helpers
    $dt          = sp_ical_build_dt_lines( $event );
    $location    = sp_ical_build_location( $event );
    $description = sp_ical_build_description( $event );

    // Unique ID per event — required by RFC 5545
    // WHY: Calendar apps use UID to detect updates vs new events. Using the
    //      site URL + event ID guarantees uniqueness across installations.
    $uid     = 'sp-event-' . $event->id . '@' . wp_parse_url( home_url(), PHP_URL_HOST );
    $dtstamp = gmdate( 'Ymd\THis\Z' );

    // Build the iCal content using shared helpers
    $lines = [
        'BEGIN:VCALENDAR',
        'VERSION:2.0',
        'PRODID:-//SocietyPress//Events//EN',
        'CALSCALE:GREGORIAN',
        'METHOD:PUBLISH',
        'BEGIN:VEVENT',
        sp_ical_fold_line( 'UID:' . $uid ),
        'DTSTAMP:' . $dtstamp,
        sp_ical_fold_line( $dt['dtstart'] ),
        sp_ical_fold_line( $dt['dtend'] ),
        sp_ical_fold_line( 'SUMMARY:' . sp_ical_escape_text( $event->title ) ),
    ];

    if ( $location ) {
        $lines[] = sp_ical_fold_line( 'LOCATION:' . sp_ical_escape_text( $location ) );
    }
    if ( $description ) {
        $lines[] = sp_ical_fold_line( 'DESCRIPTION:' . sp_ical_escape_text( $description ) );
    }

    // Add URL — use external_url if set (the event lives on another site),
    // otherwise link to the SocietyPress event detail page.
    // WHY: Some calendar apps (Google Calendar, Apple Calendar) show a clickable
    //      "More Info" link when URL is present — drives people back to the site.
    if ( ! empty( $event->external_url ) ) {
        $lines[] = sp_ical_fold_line( 'URL:' . $event->external_url );
    } else {
        $events_page_id = $wpdb->get_var(
            "SELECT p.ID FROM {$wpdb->posts} p
             INNER JOIN {$wpdb->postmeta} pm ON p.ID = pm.post_id
             WHERE pm.meta_key = '_wp_page_template' AND pm.meta_value = 'sp-events'
             AND p.post_status = 'publish' LIMIT 1"
        );
        if ( $events_page_id ) {
            $event_url = add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) );
            $lines[]   = sp_ical_fold_line( 'URL:' . $event_url );
        }
    }

    $lines[] = 'END:VEVENT';
    $lines[] = 'END:VCALENDAR';

    // Use CRLF line endings per RFC 5545
    $ics_content = implode( "\r\n", $lines ) . "\r\n";

    // Sanitize filename — strip non-alphanumeric characters for safety
    $safe_title = sanitize_file_name( $event->title );
    $filename   = $safe_title . '.ics';

    // Send headers and content
    header( 'Content-Type: text/calendar; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Content-Length: ' . strlen( $ics_content ) );
    header( 'Cache-Control: no-cache, no-store, must-revalidate' );
    echo $ics_content;
    exit;
} );


// ============================================================================
// EVENTS — iCAL CALENDAR SUBSCRIPTION FEED
// ============================================================================

/**
 * Serve an iCal feed that calendar apps (Google Calendar, Apple Calendar,
 * Outlook) can subscribe to for automatic event updates.
 *
 * Two modes:
 *   - Public: ?sp_ical_feed=public — only public-visibility events
 *   - Members-only: ?sp_ical_feed=TOKEN — includes members-only events
 *
 * WHY: Unlike the single-event .ics download (which adds one event), a
 *      subscription feed lets calendar apps poll this URL periodically and
 *      automatically show new/changed/removed events. This is the standard
 *      way calendar apps stay synced — Google Calendar, Apple Calendar, and
 *      Outlook all support it natively.
 *
 * We cache the output as a transient for 1 hour and invalidate whenever
 * events are created, updated, or deleted (see cache invalidation calls
 * in the save/delete handlers).
 *
 * Priority 5 so this runs early on template_redirect, before template loading.
 */
add_action( 'template_redirect', function () {
    if ( ! isset( $_GET['sp_ical_feed'] ) ) return;

    $feed_param = sanitize_text_field( $_GET['sp_ical_feed'] );
    if ( ! $feed_param ) return;

    // Bail if the events module is disabled
    if ( ! sp_module_enabled( 'events' ) ) return;

    // Bail with 404 if the admin has turned off the iCal feed
    // WHY: We default to enabled (1) so the feed works out of the box on new
    //      installations before the admin has visited the Events settings page.
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['events_ical_feed_enabled'] ?? 1 ) ) {
        status_header( 404 );
        exit;
    }

    global $wpdb;
    $prefix             = $wpdb->prefix . 'sp_';
    $include_members_only = false;
    $transient_key      = 'sp_ical_feed_public';

    if ( $feed_param !== 'public' ) {
        // Authenticated feed — look up the token in user_meta.
        // WHY: Calendar apps can't send WordPress auth cookies, so each member
        //      gets an opaque token in their feed URL. We validate it here by
        //      checking if any user has this token stored as sp_ical_token.
        $users = get_users( [
            'meta_key'   => 'sp_ical_token',
            'meta_value' => $feed_param,
            'number'     => 1,
            'fields'     => 'ID',
        ] );
        if ( empty( $users ) ) {
            status_header( 403 );
            wp_die( esc_html__( 'Invalid calendar feed URL.', 'societypress' ) );
        }
        $include_members_only = true;
        $transient_key        = 'sp_ical_feed_members';
    }

    // Check transient cache — avoid regenerating the feed on every poll
    $cached = get_transient( $transient_key );
    if ( $cached !== false ) {
        header( 'Content-Type: text/calendar; charset=utf-8' );
        header( 'Cache-Control: public, max-age=3600' );
        echo $cached;
        exit;
    }

    // Query events: next 12 months + past 30 days
    // WHY: Past 30 days ensures recently-passed events still show in the
    //      calendar (some members check "what was that event last week?").
    //      12 months forward covers the typical planning horizon.
    $date_start = wp_date( 'Y-m-d', strtotime( '-30 days' ) );
    $date_end   = wp_date( 'Y-m-d', strtotime( '+12 months' ) );

    $visibility_sql = $include_members_only
        ? ""
        : " AND e.visibility = 'public'";

    // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- $visibility_sql is static
    $events = $wpdb->get_results( $wpdb->prepare(
        "SELECT e.* FROM {$prefix}events e
         WHERE e.status != 'cancelled'
         AND (e.notice_only = 0 OR e.notice_only IS NULL)
         AND e.event_date >= %s
         AND e.event_date <= %s
         {$visibility_sql}
         ORDER BY e.event_date ASC",
        $date_start,
        $date_end
    ) );

    // Build the VCALENDAR wrapper
    $site_name = get_bloginfo( 'name' );
    $cal_name  = $include_members_only
        ? $site_name . ' ' . __( 'Events (Members)', 'societypress' )
        : $site_name . ' ' . __( 'Events', 'societypress' );

    $output  = "BEGIN:VCALENDAR\r\n";
    $output .= "VERSION:2.0\r\n";
    $output .= "PRODID:-//SocietyPress//Events//EN\r\n";
    $output .= "CALSCALE:GREGORIAN\r\n";
    $output .= "METHOD:PUBLISH\r\n";
    $output .= sp_ical_fold_line( "X-WR-CALNAME:" . sp_ical_escape_text( $cal_name ) ) . "\r\n";
    // REFRESH-INTERVAL tells compliant calendar apps to re-fetch every hour
    $output .= "REFRESH-INTERVAL;VALUE=DURATION:PT1H\r\n";
    // X-PUBLISHED-TTL is the legacy equivalent for older apps (Outlook, etc.)
    $output .= "X-PUBLISHED-TTL:PT1H\r\n";

    $host = wp_parse_url( home_url(), PHP_URL_HOST );

    // Look up the events page once for building event URLs
    $events_page_id = $wpdb->get_var(
        "SELECT p.ID FROM {$wpdb->posts} p
         INNER JOIN {$wpdb->postmeta} pm ON p.ID = pm.post_id
         WHERE pm.meta_key = '_wp_page_template' AND pm.meta_value = 'sp-events'
         AND p.post_status = 'publish' LIMIT 1"
    );

    foreach ( $events as $event ) {
        $dt          = sp_ical_build_dt_lines( $event );
        $location    = sp_ical_build_location( $event );
        $description = sp_ical_build_description( $event );

        $output .= "BEGIN:VEVENT\r\n";
        $output .= sp_ical_fold_line( "UID:sp-event-{$event->id}@{$host}" ) . "\r\n";
        $output .= "DTSTAMP:" . gmdate( 'Ymd\THis\Z' ) . "\r\n";
        $output .= sp_ical_fold_line( $dt['dtstart'] ) . "\r\n";
        $output .= sp_ical_fold_line( $dt['dtend'] ) . "\r\n";
        $output .= sp_ical_fold_line( "SUMMARY:" . sp_ical_escape_text( $event->title ) ) . "\r\n";

        if ( $location ) {
            $output .= sp_ical_fold_line( "LOCATION:" . sp_ical_escape_text( $location ) ) . "\r\n";
        }
        if ( $description ) {
            $output .= sp_ical_fold_line( "DESCRIPTION:" . sp_ical_escape_text( $description ) ) . "\r\n";
        }

        // Link — use external_url if set (manual or imported events that live on
        // another site), otherwise link to the SocietyPress event detail page.
        if ( ! empty( $event->external_url ) ) {
            $output .= sp_ical_fold_line( "URL:" . $event->external_url ) . "\r\n";
        } elseif ( $events_page_id && ! empty( $event->slug ) ) {
            $event_url = add_query_arg( 'sp_event', $event->slug, get_permalink( $events_page_id ) );
            $output .= sp_ical_fold_line( "URL:" . $event_url ) . "\r\n";
        }

        $output .= "END:VEVENT\r\n";
    }

    $output .= "END:VCALENDAR\r\n";

    // Cache for 1 hour — calendar apps will get stale data at most 1 hour
    set_transient( $transient_key, $output, HOUR_IN_SECONDS );

    // Serve the feed
    header( 'Content-Type: text/calendar; charset=utf-8' );
    header( 'Cache-Control: public, max-age=3600' );
    echo $output;
    exit;
}, 5 );


// ============================================================================
// EVENTS — iCAL TOKEN MANAGEMENT
// ============================================================================
//
// WHY: Calendar apps can't send WordPress cookies, so members need a unique,
//      opaque token in their feed URL. These functions handle creating, reading,
//      and regenerating that token. Regeneration is exposed via AJAX so members
//      can revoke old URLs if they're compromised or shared accidentally.
// ============================================================================

/**
 * Get or create a per-user iCal feed token.
 *
 * WHY: We lazily create the token the first time a member views their feed URL.
 *      This avoids creating tokens for members who never use the feature.
 *
 * @param int $user_id WordPress user ID.
 * @return string The 32-character alphanumeric token.
 */
function sp_get_or_create_ical_token( int $user_id ): string {
    $token = get_user_meta( $user_id, 'sp_ical_token', true );
    if ( ! $token ) {
        // wp_generate_password with $special_chars=false, $extra_special_chars=true
        // gives us a URL-safe alphanumeric string that's unpredictable enough
        // to serve as a bearer token for a calendar feed.
        $token = wp_generate_password( 32, false, false );
        update_user_meta( $user_id, 'sp_ical_token', $token );
    }
    return $token;
}

/**
 * Regenerate a user's iCal feed token, invalidating the old URL.
 *
 * WHY: If a member accidentally shares their feed URL (which contains their
 *      token), they can regenerate it. The old URL stops working immediately,
 *      and they get a fresh one to paste into their calendar app.
 *
 * @param int $user_id WordPress user ID.
 * @return string The new 32-character token.
 */
function sp_regenerate_ical_token( int $user_id ): string {
    $token = wp_generate_password( 32, false, false );
    update_user_meta( $user_id, 'sp_ical_token', $token );
    return $token;
}

/**
 * AJAX: Regenerate the current user's iCal feed token.
 *
 * WHY: Called from the subscribe dropdown when a member clicks "Regenerate URL."
 *      Returns the new URL so JS can update the display without a page reload.
 */
add_action( 'wp_ajax_sp_regenerate_ical_token', function () {
    check_ajax_referer( 'sp_ical_token', 'nonce' );

    if ( ! is_user_logged_in() ) {
        wp_send_json_error( [ 'message' => __( 'You must be logged in.', 'societypress' ) ] );
    }

    $token = sp_regenerate_ical_token( get_current_user_id() );
    $url   = home_url( '?sp_ical_feed=' . $token );

    wp_send_json_success( [
        'url'     => $url,
        'message' => __( 'Feed URL regenerated. Update your calendar app with the new URL.', 'societypress' ),
    ] );
} );


// ============================================================================
// STRIPE — TEST CONNECTION AJAX HANDLER
// ============================================================================

/**
 * AJAX: Test that the saved Stripe API keys are valid.
 *
 * WHY: Harold just pasted two cryptic strings and has no idea if they work.
 *      This makes a tiny API call to Stripe (retrieve account balance) that
 *      will succeed with valid keys and fail with invalid ones. The admin gets
 *      an instant green checkmark or red X — no guessing.
 */
add_action( 'wp_ajax_sp_test_stripe_connection', function () {
    if ( ! check_ajax_referer( 'sp_stripe_test', 'nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Permission denied.', 'societypress' ) );
    }

    $settings   = get_option( 'societypress_settings', [] );
    $secret_key = sp_stripe_get_secret_key( $settings );

    if ( empty( $secret_key ) ) {
        wp_send_json_error( __( 'No API keys found. Please enter your keys and save settings first.', 'societypress' ) );
    }

    // Call Stripe's /v1/balance endpoint — the simplest authenticated call
    // WHY: If we can retrieve the account balance, the key is valid. This
    //      endpoint is cheap, fast, and doesn't create or modify anything.
    $response = wp_remote_get( 'https://api.stripe.com/v1/balance', [
        'timeout' => 15,
        'headers' => [
            'Authorization' => 'Bearer ' . $secret_key,
        ],
    ] );

    if ( is_wp_error( $response ) ) {
        wp_send_json_error( __( 'Could not reach Stripe. Please check your internet connection.', 'societypress' ) );
    }

    $code = wp_remote_retrieve_response_code( $response );
    $body = json_decode( wp_remote_retrieve_body( $response ), true );

    if ( $code === 200 ) {
        wp_send_json_success();
    } elseif ( $code === 401 ) {
        wp_send_json_error( __( 'Invalid API key. Please double-check your keys in Stripe dashboard.', 'societypress' ) );
    } else {
        /* translators: %d: HTTP status code from Stripe API */
        $msg = $body['error']['message'] ?? sprintf( __( 'Unexpected error (HTTP %d)', 'societypress' ), $code );
        wp_send_json_error( $msg );
    }
} );


// ============================================================================
// STRIPE — ADMIN REFUND HANDLER
// ============================================================================

/**
 * AJAX: Issue a full refund for a Stripe payment.
 *
 * WHY: Sometimes an event gets cancelled, someone can't make it after paying,
 *      or there's a billing dispute. The admin needs a one-click refund button
 *      right in the registrations table — they shouldn't have to log into
 *      Stripe's dashboard to find the payment and refund it manually.
 */
add_action( 'wp_ajax_sp_admin_refund_payment', function () {
    if ( ! check_ajax_referer( 'sp_admin_registration', 'nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed.', 'societypress' ) );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Permission denied.', 'societypress' ) );
    }

    global $wpdb;
    $reg_table = $wpdb->prefix . 'sp_event_registrations';

    $registration_id = (int) ( $_POST['registration_id'] ?? 0 );
    if ( ! $registration_id ) {
        wp_send_json_error( __( 'Invalid registration.', 'societypress' ) );
    }

    $reg = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$reg_table} WHERE id = %d", $registration_id
    ) );

    if ( ! $reg ) {
        wp_send_json_error( __( 'Registration not found.', 'societypress' ) );
    }

    if ( $reg->payment_status !== 'paid' || ! in_array( $reg->payment_method, [ 'stripe', 'paypal' ], true ) ) {
        wp_send_json_error( __( 'This registration was not paid via an online payment method.', 'societypress' ) );
    }

    $settings = get_option( 'societypress_settings', [] );

    // ---- Stripe refund path ----
    if ( $reg->payment_method === 'stripe' ) {
        // Extract the Stripe PaymentIntent ID from the notes field
        // WHY: We stored it as "stripe_session:cs_xxx|stripe_pi:pi_xxx" when the
        //      payment was confirmed. The PaymentIntent ID is what Stripe needs to
        //      process a refund.
        $payment_intent = '';
        if ( preg_match( '/stripe_pi:(\S+)/', $reg->notes ?? '', $matches ) ) {
            $payment_intent = $matches[1];
        }

        if ( empty( $payment_intent ) ) {
            wp_send_json_error( __( 'Could not find payment reference. Please refund manually in Stripe dashboard.', 'societypress' ) );
        }

        $secret_key = sp_stripe_get_secret_key( $settings );
        if ( empty( $secret_key ) ) {
            wp_send_json_error( __( 'Stripe is not configured.', 'societypress' ) );
        }

        $response = wp_remote_post( 'https://api.stripe.com/v1/refunds', [
            'timeout' => 30,
            'headers' => [
                'Authorization' => 'Bearer ' . $secret_key,
                'Content-Type'  => 'application/x-www-form-urlencoded',
            ],
            'body' => [ 'payment_intent' => $payment_intent ],
        ] );

        if ( is_wp_error( $response ) ) {
            wp_send_json_error( __( 'Could not connect to Stripe. Please try again.', 'societypress' ) );
        }

        $body = json_decode( wp_remote_retrieve_body( $response ), true );
        $code = wp_remote_retrieve_response_code( $response );

        $status = $body['status'] ?? '';
        if ( $code === 200 && in_array( $status, [ 'succeeded', 'pending' ], true ) ) {
            $wpdb->update( $reg_table, [
                'payment_status' => 'refunded',
                'notes'          => $reg->notes . '|refund:' . ( $body['id'] ?? 'unknown' ),
            ], [ 'id' => $registration_id ] );
            $message = ( $status === 'pending' )
                ? __( 'Refund initiated — processing with Stripe.', 'societypress' )
                : __( 'Refund processed successfully via Stripe.', 'societypress' );
            wp_send_json_success( [ 'message' => $message ] );
        } else {
            $error_msg = $body['error']['message'] ?? 'Refund failed (HTTP ' . $code . ')';
            wp_send_json_error( $error_msg );
        }
    }

    // ---- PayPal refund path ----
    // WHY: PayPal refunds go through the Captures API — we refund the capture, not
    //      the order. The capture ID was stored in the notes when payment was confirmed.
    if ( $reg->payment_method === 'paypal' ) {
        $capture_id = '';
        if ( preg_match( '/paypal_capture:(\S+)/', $reg->notes ?? '', $matches ) ) {
            $capture_id = $matches[1];
        }

        if ( empty( $capture_id ) ) {
            wp_send_json_error( __( 'Could not find PayPal capture reference. Please refund manually in PayPal dashboard.', 'societypress' ) );
        }

        if ( ! sp_paypal_is_configured( $settings ) ) {
            wp_send_json_error( __( 'PayPal is not configured.', 'societypress' ) );
        }

        $token = sp_paypal_get_access_token( $settings );
        if ( is_wp_error( $token ) ) {
            wp_send_json_error( __( 'Could not authenticate with PayPal. Please try again.', 'societypress' ) );
        }

        $response = wp_remote_post(
            sp_paypal_api_base( $settings ) . '/v2/payments/captures/' . urlencode( $capture_id ) . '/refund',
            [
                'headers' => [
                    'Authorization' => 'Bearer ' . $token,
                    'Content-Type'  => 'application/json',
                ],
                'body'    => '{}', // Full refund — no amount needed
                'timeout' => 30,
            ]
        );

        if ( is_wp_error( $response ) ) {
            wp_send_json_error( __( 'Could not connect to PayPal. Please try again.', 'societypress' ) );
        }

        $body = json_decode( wp_remote_retrieve_body( $response ), true );
        $code = wp_remote_retrieve_response_code( $response );
        $pp_status = $body['status'] ?? '';

        if ( in_array( $code, [ 200, 201 ], true ) && in_array( $pp_status, [ 'COMPLETED', 'PENDING' ], true ) ) {
            $wpdb->update( $reg_table, [
                'payment_status' => 'refunded',
                'notes'          => $reg->notes . '|paypal_refund:' . ( $body['id'] ?? 'unknown' ),
            ], [ 'id' => $registration_id ] );
            $message = ( $pp_status === 'PENDING' )
                ? __( 'Refund initiated — processing with PayPal.', 'societypress' )
                : __( 'Refund processed successfully via PayPal.', 'societypress' );
            wp_send_json_success( [ 'message' => $message ] );
        } else {
            $error_msg = $body['message'] ?? $body['error'] ?? 'PayPal refund failed (HTTP ' . $code . ')';
            error_log( 'SocietyPress PayPal refund error: ' . wp_json_encode( $body ) );
            wp_send_json_error( $error_msg );
        }
    }
} );


// ============================================================================
// PAGE BUILDER — FRONTEND WIDGET RENDERERS (NEW FEATURES)
// ============================================================================

/**
 * Render: Community Link
 *
 * WHY: Feature 1 — a simple styled card/button that links to an external
 *      community forum (Facebook group, Discord, etc.). If no URL is configured
 *      in Settings > Organization, visitors see nothing and admins see a notice.
 */
function sp_render_builder_widget_community_link( array $s ): void {
    $settings = get_option( 'societypress_settings', [] );
    $url      = $settings['community_forum_url'] ?? '';
    $label    = $s['label'] ?? __( 'Join Our Community', 'societypress' );
    $desc     = $s['description'] ?? __( 'Connect with fellow members in our online community.', 'societypress' );
    $style    = $s['button_style'] ?? 'primary';

    if ( empty( $url ) ) {
        // Only show a notice to admins — visitors see nothing
        if ( current_user_can( 'manage_options' ) ) {
            echo '<div class="sp-widget-community-link" style="padding:20px; background:#fef9e7; border:1px dashed #d4a017; border-radius:8px; text-align:center;">';
            echo '<p style="margin:0; color:#8a6d00;">' . esc_html__( 'Community Forum URL not configured.', 'societypress' ) . ' <a href="' . esc_url( admin_url( 'admin.php?page=sp-settings-organization' ) ) . '">' . esc_html__( 'Set it in Settings &rarr; Organization', 'societypress' ) . '</a>.</p>';
            echo '</div>';
        }
        return;
    }

    echo '<div class="sp-widget-community-link" style="text-align:center; padding:32px; background:linear-gradient(135deg, #f0f7ff 0%, #e8f4f8 100%); border-radius:12px;">';
    echo '<h3 style="margin:0 0 8px; font-size:22px; color:#1d2327;">' . esc_html( $label ) . '</h3>';
    if ( $desc ) {
        echo '<p style="margin:0 0 20px; color:#555; font-size:16px;">' . esc_html( $desc ) . '</p>';
    }
    echo '<a href="' . esc_url( $url ) . '" target="_blank" rel="noopener noreferrer" class="sp-btn sp-btn-' . esc_attr( $style ) . '" style="font-size:16px;">';
    echo esc_html( $label ) . ' &rarr;</a>';
    echo '</div>';
}

/**
 * Render: Newsletter Archive
 *
 * WHY: Feature 8 — shows recent posts from the "Newsletter" category so
 *      Harold can publish newsletter summaries as regular blog posts and
 *      have them appear on any page via the Page Builder.
 */
function sp_render_builder_widget_newsletter_archive( array $s ): void {
    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to view newsletters.', 'societypress' ) . '</p>';
        echo '</div>';
        return;
    }

    $count        = max( 1, (int) ( $s['count'] ?? 5 ) );
    $show_excerpt = $s['show_excerpt'] ?? true;
    $show_date    = $s['show_date'] ?? true;

    // Get the Newsletter category — created on activation
    $cat = get_category_by_slug( 'newsletter' );
    if ( ! $cat ) {
        if ( current_user_can( 'manage_options' ) ) {
            echo '<p style="color:#8a6d00; padding:12px; background:#fef9e7; border-radius:6px;">' . esc_html__( 'Newsletter category not found. Try deactivating and reactivating the plugin.', 'societypress' ) . '</p>';
        }
        return;
    }

    $posts = get_posts( [
        'category'       => $cat->term_id,
        'posts_per_page' => $count,
        'post_status'    => 'publish',
        'orderby'        => 'date',
        'order'          => 'DESC',
    ] );

    echo '<div class="sp-widget-newsletter-archive">';
    if ( empty( $posts ) ) {
        echo '<p class="sp-text-secondary" class="sp-italic">' . esc_html__( 'No newsletters published yet.', 'societypress' ) . '</p>';
    } else {
        echo '<ul class="sp-list-reset">';
        foreach ( $posts as $post ) {
            echo '<li style="padding:16px 0; border-bottom:1px solid #eee;">';
            echo '<a href="' . esc_url( get_permalink( $post ) ) . '" style="font-size:17px; font-weight:600; color:var(--sp-color-primary); text-decoration:none;">';
            echo esc_html( $post->post_title ) . '</a>';
            if ( $show_date ) {
                echo '<span style="display:block; color:#999; font-size:13px; margin-top:2px;">'
                   . esc_html( get_the_date( '', $post ) ) . '</span>';
            }
            if ( $show_excerpt && $post->post_excerpt ) {
                echo '<p style="margin:6px 0 0; color:#555; font-size:14px;">' . esc_html( $post->post_excerpt ) . '</p>';
            }
            echo '</li>';
        }
        echo '</ul>';
    }
    echo '</div>';
}

/**
 * Render: Volunteer Stats
 *
 * WHY: Feature 4 — a public-facing widget showing volunteer activity.
 *      Highlights the community's collective effort with total hours,
 *      active volunteer count, and optionally top contributors.
 */
function sp_render_builder_widget_volunteer_stats( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $show_count = $s['show_count'] ?? true;
    $show_hours = $s['show_hours'] ?? true;
    $show_top   = $s['show_top_volunteers'] ?? false;
    $period     = $s['time_period'] ?? 'year';

    // Build date constraint based on time period
    $date_clause = '';
    if ( $period === 'year' ) {
        $date_clause = $wpdb->prepare( ' AND vh.activity_date >= %s', wp_date( 'Y-01-01' ) );
    } elseif ( $period === 'month' ) {
        $date_clause = $wpdb->prepare( ' AND vh.activity_date >= %s', wp_date( 'Y-m-01' ) );
    }
    // 'all' = no date constraint

    $stats_html = [];

    if ( $show_count ) {
        $active_count = (int) $wpdb->get_var(
            "SELECT COUNT(DISTINCT vr.user_id) FROM {$prefix}volunteer_roles vr WHERE vr.status = 'active'"
        );
        $stats_html[] = '<div class="sp-stat-card">'
                      . '<div style="font-size:36px; font-weight:700; color:var(--sp-color-primary);">' . number_format( $active_count ) . '</div>'
                      . '<div style="font-size:14px; color:#666; margin-top:4px;">' . esc_html__( 'Active Volunteers', 'societypress' ) . '</div></div>';
    }

    if ( $show_hours ) {
        $total_hours = (float) $wpdb->get_var(
            "SELECT COALESCE(SUM(vh.hours), 0) FROM {$prefix}volunteer_hours vh WHERE 1=1{$date_clause}"
        );
        $period_label = $period === 'year' ? __( 'This Year', 'societypress' ) : ( $period === 'month' ? __( 'This Month', 'societypress' ) : __( 'All Time', 'societypress' ) );
        $stats_html[] = '<div class="sp-stat-card">'
                      . '<div style="font-size:36px; font-weight:700; color:var(--sp-color-primary);">' . number_format( $total_hours, 1 ) . '</div>'
                      . '<div style="font-size:14px; color:#666; margin-top:4px;">' . esc_html__( 'Hours', 'societypress' ) . ' ' . esc_html( $period_label ) . '</div></div>';
    }

    echo '<div class="sp-widget-volunteer-stats">';
    if ( ! empty( $stats_html ) ) {
        echo '<div style="display:flex; flex-wrap:wrap; gap:24px; justify-content:center; margin-bottom:' . ( $show_top ? '24px' : '0' ) . ';">';
        echo implode( '', $stats_html );
        echo '</div>';
    }

    if ( $show_top ) {
        $top = $wpdb->get_results(
            "SELECT vh.user_id, m.first_name, m.last_name, SUM(vh.hours) as total_hours
             FROM {$prefix}volunteer_hours vh
             INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
             WHERE 1=1{$date_clause}
             GROUP BY vh.user_id, m.first_name, m.last_name
             ORDER BY total_hours DESC
             LIMIT 5"
        );
        if ( ! empty( $top ) ) {
            echo '<h4 style="margin:0 0 12px; font-size:16px; color:#1d2327;">' . esc_html__( 'Top Contributors', 'societypress' ) . '</h4>';
            echo '<ol style="margin:0; padding:0 0 0 20px;">';
            foreach ( $top as $v ) {
                echo '<li style="padding:4px 0; font-size:15px;">';
                echo esc_html( $v->first_name . ' ' . $v->last_name );
                echo ' <span class="sp-text-secondary">(' . number_format( (float) $v->total_hours, 1 ) . ' hrs)</span>';
                echo '</li>';
            }
            echo '</ol>';
        }
    }
    echo '</div>';
}


/**
 * Render: Photos & Videos
 *
 * WHY: Displays media folders or a single folder's items on the frontend.
 *      Supports both images (WP media library) and YouTube videos.
 *      Images use a pure CSS :target lightbox. Videos open in a responsive
 *      iframe lightbox. Both work without JavaScript for basic functionality.
 */
function sp_render_builder_widget_photo_gallery( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to view media.', 'societypress' ) . '</p>';
        echo '</div>';
        return;
    }

    $display_mode = $s['display_mode'] ?? 'albums';
    $album_id     = absint( $s['album_id'] ?? 0 );
    $columns      = max( 2, min( 6, (int) ( $s['columns'] ?? 3 ) ) );
    $count        = max( 1, (int) ( $s['count'] ?? 12 ) );

    /*
     * WHY a <style> block here: All static presentational rules for this widget
     * are gathered in one place so they are easy to audit and override via a
     * child theme. Dynamic values (column width, which depends on a PHP
     * variable) cannot be expressed as static CSS and are kept as inline styles
     * below. display:none on the lightbox is also kept inline because the
     * :target CSS rule flips it to flex — removing the inline attribute would
     * break that toggle without JavaScript.
     */
    echo '<style>
/* Photos & Videos widget — static layout & presentational rules */
.sp-gallery-not-found          { color: #666; }
.sp-gallery-album-title        { margin: 0 0 16px; }
.sp-gallery-album-desc         { color: #555; margin: 0 0 16px; }
.sp-gallery-empty              { color: #666; font-style: italic; }
.sp-gallery-photo-grid         { display: flex; flex-wrap: wrap; gap: 8px; }
.sp-gallery-thumb-img          { width: 100%; height: 100%; object-fit: cover; }
/* Video play overlay — indicates clickable YouTube thumbnails */
.sp-gallery-video-overlay      { position: absolute; inset: 0; display: flex;
                                  align-items: center; justify-content: center;
                                  background: rgba(0,0,0,0.2); }
.sp-gallery-play-icon          { width: 48px; height: 48px; background: rgba(0,0,0,0.7);
                                  border-radius: 50%; display: flex; align-items: center;
                                  justify-content: center; color: #fff; font-size: 20px; }
/* Lightbox overlay — display:none kept inline; :target rule overrides it */
.sp-gallery-lightbox           { position: fixed; inset: 0; z-index: 100000;
                                  background: rgba(0,0,0,0.9);
                                  align-items: center; justify-content: center; }
.sp-gallery-lightbox-backdrop  { position: absolute; inset: 0; z-index: 1; }
.sp-gallery-lightbox-img       { max-width: 90vw; max-height: 90vh;
                                  object-fit: contain; position: relative;
                                  z-index: 2; border-radius: 4px; }
.sp-gallery-lightbox-video     { position: relative; z-index: 2; width: 80vw;
                                  max-width: 960px; aspect-ratio: 16/9; }
.sp-gallery-lightbox-video iframe { width: 100%; height: 100%; border: none;
                                  border-radius: 4px; }
.sp-gallery-lightbox-caption   { position: absolute; bottom: 20px; left: 50%;
                                  transform: translateX(-50%); color: #fff;
                                  font-size: 14px; z-index: 2;
                                  background: rgba(0,0,0,0.6);
                                  padding: 6px 16px; border-radius: 4px; }
/* Folder grid */
.sp-gallery-albums-grid        { display: flex; flex-wrap: wrap; gap: 16px; }
.sp-gallery-cover-wrap         { aspect-ratio: 4/3; overflow: hidden;
                                  border-radius: 8px; margin-bottom: 8px; }
.sp-gallery-cover-img          { width: 100%; height: 100%; object-fit: cover; }
.sp-gallery-no-cover           { aspect-ratio: 4/3; background: #f0f0f0;
                                  border-radius: 8px; margin-bottom: 8px;
                                  display: flex; align-items: center;
                                  justify-content: center; color: #999; }
.sp-gallery-no-cover-icon      { font-size: 48px; width: 48px; height: 48px; }
.sp-gallery-album-name         { margin: 0 0 4px; font-size: 16px; }
.sp-gallery-photo-count        { color: #666; font-size: 13px; }
/* :target lightbox trigger — flips display:none to flex when hash matches */
.sp-gallery-lightbox:target    { display: flex !important; }
</style>';

    echo '<div class="sp-widget-photo-gallery">';

    if ( $display_mode === 'single' && $album_id ) {
        // Single folder view — show all media items in a grid
        $folder = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_albums WHERE id = %d", $album_id
        ) );
        if ( ! $folder ) {
            echo '<p class="sp-gallery-not-found">' . esc_html__( 'Folder not found.', 'societypress' ) . '</p></div>';
            return;
        }

        // Visibility check
        if ( $folder->visibility === 'members_only' && ! is_user_logged_in() ) {
            echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to view this folder.', 'societypress' ) . '</p></div>';
            return;
        }

        if ( $folder->title ) {
            echo '<h3 class="sp-gallery-album-title">' . esc_html( $folder->title ) . '</h3>';
        }
        if ( $folder->description ) {
            echo '<p class="sp-gallery-album-desc">' . esc_html( $folder->description ) . '</p>';
        }

        $items = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_album_items WHERE album_id = %d ORDER BY sort_order ASC LIMIT %d",
            $album_id, $count
        ) );

        if ( empty( $items ) ) {
            echo '<p class="sp-gallery-empty">' . esc_html__( 'No media in this folder yet.', 'societypress' ) . '</p>';
        } else {
            $col_width = round( 100 / $columns, 2 );

            echo '<style>
.sp-gallery-thumb-link { aspect-ratio: 1; overflow: hidden; border-radius: 6px; display: block; position: relative; }
</style>';

            echo '<div class="sp-gallery-photo-grid">';
            foreach ( $items as $i => $item ) {
                $item_type = $item->type ?? 'image';
                $target_id = 'sp-media-' . $album_id . '-' . $item->id;

                if ( $item_type === 'video' && ! empty( $item->video_url ) ) {
                    // WHY: Extract YouTube video ID to build thumbnail URL and
                    // embed URL. Supports youtube.com/watch?v=, youtu.be/, and
                    // youtube.com/embed/ formats.
                    $video_id = sp_extract_youtube_id( $item->video_url );
                    if ( ! $video_id ) continue;

                    $thumb_url = 'https://img.youtube.com/vi/' . $video_id . '/mqdefault.jpg';
                    $embed_url = 'https://www.youtube-nocookie.com/embed/' . $video_id . '?autoplay=1';

                    // Video thumbnail with play overlay
                    echo '<a href="#' . esc_attr( $target_id ) . '" class="sp-gallery-thumb-link" style="width:calc(' . $col_width . '% - 8px);">';
                    echo '<img src="' . esc_url( $thumb_url ) . '" alt="' . esc_attr( $item->caption ?: __( 'Video', 'societypress' ) . ' ' . ( $i + 1 ) ) . '" class="sp-gallery-thumb-img" loading="lazy">';
                    echo '<div class="sp-gallery-video-overlay"><div class="sp-gallery-play-icon">&#9654;</div></div>';
                    echo '</a>';

                    // Video lightbox with responsive iframe
                    echo '<div id="' . esc_attr( $target_id ) . '" class="sp-gallery-lightbox" style="display:none;">';
                    echo '<a href="#" class="sp-gallery-lightbox-backdrop"></a>';
                    echo '<div class="sp-gallery-lightbox-video"><iframe src="' . esc_url( $embed_url ) . '" allowfullscreen></iframe></div>';
                    if ( $item->caption ) {
                        echo '<p class="sp-gallery-lightbox-caption">' . esc_html( $item->caption ) . '</p>';
                    }
                    echo '</div>';
                } else {
                    // Image from WP media library
                    $img_url  = wp_get_attachment_image_url( $item->attachment_id, 'medium' );
                    $full_url = wp_get_attachment_image_url( $item->attachment_id, 'full' );
                    if ( ! $img_url ) continue;

                    echo '<a href="#' . esc_attr( $target_id ) . '" class="sp-gallery-thumb-link" style="width:calc(' . $col_width . '% - 8px);">';
                    echo '<img src="' . esc_url( $img_url ) . '" alt="' . esc_attr( $item->caption ?: __( 'Photo', 'societypress' ) . ' ' . ( $i + 1 ) ) . '" class="sp-gallery-thumb-img" loading="lazy">';
                    echo '</a>';

                    /*
                     * WHY display:none is kept inline on the lightbox <div>: the
                     * CSS :target rule (.sp-gallery-lightbox:target) flips it to
                     * flex. Keeping it inline preserves the no-JS fallback.
                     */
                    echo '<div id="' . esc_attr( $target_id ) . '" class="sp-gallery-lightbox" style="display:none;">';
                    echo '<a href="#" class="sp-gallery-lightbox-backdrop"></a>';
                    echo '<img src="' . esc_url( $full_url ?: $img_url ) . '" alt="' . esc_attr( $item->caption ) . '" class="sp-gallery-lightbox-img">';
                    if ( $item->caption ) {
                        echo '<p class="sp-gallery-lightbox-caption">' . esc_html( $item->caption ) . '</p>';
                    }
                    echo '</div>';
                }
            }
            echo '</div>';
        }
    } else {
        // Folders grid view — show top-level folder covers
        $visibility_clause = is_user_logged_in() ? '' : " AND visibility = 'public'";
        $folders = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_albums WHERE (parent_id IS NULL OR parent_id = 0){$visibility_clause} ORDER BY sort_order ASC, created_at DESC LIMIT %d",
            $count
        ) );

        if ( empty( $folders ) ) {
            echo '<p class="sp-gallery-empty">' . esc_html__( 'No media folders yet.', 'societypress' ) . '</p>';
        } else {
            $col_width = round( 100 / $columns, 2 );

            echo '<style>
.sp-gallery-album-card { min-width: 200px; }
</style>';

            echo '<div class="sp-gallery-albums-grid">';
            foreach ( $folders as $folder ) {
                $cover_url = $folder->cover_image_id
                    ? wp_get_attachment_image_url( $folder->cover_image_id, 'medium' )
                    : '';
                $item_count = (int) $wpdb->get_var( $wpdb->prepare(
                    "SELECT COUNT(*) FROM {$prefix}photo_album_items WHERE album_id = %d", $folder->id
                ) );

                echo '<div class="sp-gallery-album-card" style="width:calc(' . $col_width . '% - 16px);">';
                if ( $cover_url ) {
                    echo '<div class="sp-gallery-cover-wrap">';
                    echo '<img src="' . esc_url( $cover_url ) . '" alt="' . esc_attr( $folder->title ) . '" class="sp-gallery-cover-img" loading="lazy">';
                    echo '</div>';
                } else {
                    echo '<div class="sp-gallery-no-cover">';
                    echo '<span class="dashicons dashicons-format-gallery sp-gallery-no-cover-icon"></span>';
                    echo '</div>';
                }
                echo '<h4 class="sp-gallery-album-name">' . esc_html( $folder->title ) . '</h4>';
                echo '<span class="sp-gallery-photo-count">' . sprintf( _n( '%d item', '%d items', $item_count, 'societypress' ), $item_count ) . '</span>';
                echo '</div>';
            }
            echo '</div>';
        }
    }
    echo '</div>';
}

/**
 * Extract YouTube video ID from a URL.
 *
 * WHY: Supports multiple YouTube URL formats (watch, short link, embed) so
 *      volunteers can paste any YouTube link format and it just works.
 *
 * @param string $url The YouTube URL.
 * @return string|false The video ID, or false if not a valid YouTube URL.
 */
function sp_extract_youtube_id( string $url ) {
    // youtube.com/watch?v=ID
    if ( preg_match( '/[?&]v=([a-zA-Z0-9_-]{11})/', $url, $m ) ) {
        return $m[1];
    }
    // youtu.be/ID
    if ( preg_match( '#youtu\.be/([a-zA-Z0-9_-]{11})#', $url, $m ) ) {
        return $m[1];
    }
    // youtube.com/embed/ID
    if ( preg_match( '#youtube\.com/embed/([a-zA-Z0-9_-]{11})#', $url, $m ) ) {
        return $m[1];
    }
    return false;
}

/**
 * Render: Resource Links
 *
 * WHY: Feature 6 — displays useful genealogy links grouped by category.
 *      Helps members discover external research databases, archives, and
 *      tools that the society recommends.
 */
function sp_render_builder_widget_resource_links( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . sprintf( __( 'Please <a href="%s">log in</a> to view resources.', 'societypress' ), esc_url( wp_login_url( get_permalink() ) ) ) . '</p>';
        echo '</div>';
        return;
    }

    $category_id    = absint( $s['category_id'] ?? 0 );
    $featured_only  = $s['featured_only'] ?? false;
    $count          = max( 1, (int) ( $s['count'] ?? 50 ) );
    $show_desc      = $s['show_descriptions'] ?? true;

    $where = [ 'r.active = 1' ];
    if ( $category_id ) {
        $where[] = $wpdb->prepare( 'r.category_id = %d', $category_id );
    }
    if ( $featured_only ) {
        $where[] = 'r.featured = 1';
    }
    $where_sql = implode( ' AND ', $where );

    $resources = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, rc.name as category_name
         FROM {$prefix}resources r
         LEFT JOIN {$prefix}resource_categories rc ON r.category_id = rc.id
         WHERE {$where_sql}
         ORDER BY rc.sort_order ASC, rc.name ASC, r.sort_order ASC, r.title ASC
         LIMIT %d",
        $count
    ) );

    echo '<div class="sp-widget-resource-links">';
    if ( empty( $resources ) ) {
        echo '<p class="sp-text-secondary" class="sp-italic">' . esc_html__( 'No resources available yet.', 'societypress' ) . '</p>';
    } else {
        // Group by category for display
        $grouped = [];
        foreach ( $resources as $r ) {
            $cat_name = $r->category_name ?: __( 'Uncategorized', 'societypress' );
            $grouped[ $cat_name ][] = $r;
        }

        foreach ( $grouped as $cat_name => $items ) {
            echo '<div class="sp-mb-24">';
            echo '<h4 style="margin:0 0 12px; font-size:16px; color:#1d2327; border-bottom:2px solid #eee; padding-bottom:8px;">' . esc_html( $cat_name ) . '</h4>';
            echo '<ul class="sp-list-reset">';
            foreach ( $items as $item ) {
                echo '<li style="padding:8px 0; border-bottom:1px solid #f0f0f0;">';
                echo '<a href="' . esc_url( $item->url ) . '" target="_blank" rel="noopener noreferrer" style="font-weight:600; color:var(--sp-color-primary); text-decoration:none; font-size:15px;">';
                echo esc_html( $item->title );
                if ( $item->featured ) {
                    echo ' <span style="background:#fef0c7; color:#92400e; font-size:11px; padding:2px 6px; border-radius:4px; font-weight:500; margin-left:4px;">' . esc_html__( 'Featured', 'societypress' ) . '</span>';
                }
                echo '</a>';
                if ( $show_desc && $item->description ) {
                    echo '<p style="margin:4px 0 0; color:#555; font-size:13px;">' . esc_html( $item->description ) . '</p>';
                }
                echo '</li>';
            }
            echo '</ul></div>';
        }
    }
    echo '</div>';
}

/**
 * Render: Library Catalog (Enhanced Landing Page)
 *
 * WHY: The catalog is the crown jewel of any genealogical society's website.
 *      19,000+ items need a proper landing experience — not just a raw table dump.
 *      Inspired by NEHGS (tabbed search, researcher-focused) and NGS (visual
 *      browsing, cover images, editorial feel). The page has three zones:
 *
 *      1. Collection overview — stats that convey the depth of the collection
 *      2. Tabbed search — keyword/title/author/subject/call# (like an OPAC)
 *      3. Browse sections — media type cards + popular subject tags
 *      4. Results table — the existing paginated, sortable, expandable catalog
 *
 *      Browse sections auto-hide when a search/filter is active so the results
 *      get top billing. They reappear when filters are cleared.
 */
function sp_render_builder_widget_library_catalog( array $s ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ---- Access control ----
    $login_required = $s['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . esc_html__( 'Please', 'societypress' ) . ' <a href="' . esc_url( wp_login_url( get_permalink() ) ) . '">' . esc_html__( 'log in', 'societypress' ) . '</a> ' . esc_html__( 'to browse the catalog.', 'societypress' ) . '</p>';
        echo '</div>';
        return;
    }

    // ---- Widget settings ----
    $show_search    = $s['show_search'] ?? true;
    $show_landing   = $s['show_landing'] ?? true;
    $category_id    = absint( $s['category_id'] ?? 0 );
    $available_only = $s['available_only'] ?? false;
    $per_page       = max( 1, (int) ( $s['count'] ?? 25 ) );

    // ---- Read URL parameters ----
    $search       = isset( $_GET['sp_lib_search'] ) ? sanitize_text_field( $_GET['sp_lib_search'] ) : '';
    $search_field = isset( $_GET['sp_lib_field'] ) ? sanitize_text_field( $_GET['sp_lib_field'] ) : 'keyword';
    $media_filter = isset( $_GET['sp_lib_media'] ) ? sanitize_text_field( $_GET['sp_lib_media'] ) : '';
    $subj_filter  = isset( $_GET['sp_lib_subject'] ) ? sanitize_text_field( $_GET['sp_lib_subject'] ) : '';
    $acq_filter   = isset( $_GET['sp_lib_acq'] ) ? sanitize_text_field( $_GET['sp_lib_acq'] ) : '';
    $sort_by      = isset( $_GET['sp_lib_sort'] ) ? sanitize_text_field( $_GET['sp_lib_sort'] ) : 'title';
    $page_num     = max( 1, absint( $_GET['sp_lib_pg'] ?? 1 ) );

    // Validate search field tab
    $allowed_fields = [ 'keyword', 'title', 'author', 'subject', 'call_number' ];
    if ( ! in_array( $search_field, $allowed_fields, true ) ) {
        $search_field = 'keyword';
    }

    // Validate sort column
    $allowed_sorts = [ 'title', 'author', 'pub_year', 'call_number', 'media_type' ];
    if ( ! in_array( $sort_by, $allowed_sorts, true ) ) {
        $sort_by = 'title';
    }
    $order_sql = 'li.' . $sort_by . ' ASC';
    // For pub_year, newest first is more useful
    if ( $sort_by === 'pub_year' ) {
        $order_sql = 'li.pub_year DESC';
    }

    // ---- Build WHERE clause ----
    $where = [ '1=1' ];
    if ( $category_id ) {
        $where[] = $wpdb->prepare( 'li.category_id = %d', $category_id );
    }
    if ( $available_only ) {
        $where[] = 'li.available = 1';
    }

    // WHY: Tabbed search — instead of one generic search box, let the researcher
    //      target a specific field (title, author, subject, call number) or search
    //      everything (keyword). This mirrors how real library OPACs work and helps
    //      researchers who know exactly what they're looking for.
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        switch ( $search_field ) {
            case 'title':
                $where[] = $wpdb->prepare( 'li.title LIKE %s', $like );
                break;
            case 'author':
                $where[] = $wpdb->prepare( 'li.author LIKE %s', $like );
                break;
            case 'subject':
                $where[] = $wpdb->prepare( 'li.subject LIKE %s', $like );
                break;
            case 'call_number':
                $where[] = $wpdb->prepare( 'li.call_number LIKE %s', $like );
                break;
            default: // keyword — all fields
                $where[] = $wpdb->prepare(
                    '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s OR li.subject LIKE %s OR li.surname LIKE %s OR li.description LIKE %s)',
                    $like, $like, $like, $like, $like, $like
                );
                break;
        }
    }
    if ( $media_filter ) {
        $where[] = $wpdb->prepare( 'li.media_type = %s', $media_filter );
    }
    if ( $subj_filter ) {
        // Subject is comma-separated — match as substring
        $like = '%' . $wpdb->esc_like( $subj_filter ) . '%';
        $where[] = $wpdb->prepare( 'li.subject LIKE %s', $like );
    }
    if ( $acq_filter ) {
        $where[] = $wpdb->prepare( 'li.acq_code = %s', $acq_filter );
    }
    $where_sql = implode( ' AND ', $where );

    // ---- Detect whether any search/filter is active ----
    // WHY: When the user hasn't searched or filtered yet, we show the full landing
    //      page experience (stats, browse cards, subjects). Once they've drilled in,
    //      those sections collapse so results get the spotlight.
    $has_active_filter = ( $search || $media_filter || $subj_filter || $acq_filter );

    // ---- Get dropdown values (always from full catalog, not filtered) ----
    $media_types = $wpdb->get_col( "SELECT DISTINCT media_type FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' ORDER BY media_type ASC" );
    $acq_codes   = $wpdb->get_col( "SELECT DISTINCT acq_code FROM {$prefix}library_items WHERE acq_code IS NOT NULL AND acq_code != '' ORDER BY acq_code ASC" );

    // ---- Count + fetch results ----
    $offset = ( $page_num - 1 ) * $per_page;
    $total  = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items li WHERE {$where_sql}" );
    $items  = $wpdb->get_results( $wpdb->prepare(
        "SELECT li.*, lc.name as category_name
         FROM {$prefix}library_items li
         LEFT JOIN {$prefix}library_categories lc ON li.category_id = lc.id
         WHERE {$where_sql}
         ORDER BY {$order_sql}
         LIMIT %d OFFSET %d",
        $per_page,
        $offset
    ) );
    $total_pages = (int) ceil( $total / $per_page );

    // ---- Collection-wide stats (for the landing header) ----
    // WHY: Showing the breadth of the collection upfront — "19,418 items across
    //      6 formats" — immediately tells a researcher this is a serious library,
    //      not a shelf of pamphlets. Cached via transient so we don't re-count
    //      on every page load.
    $stats = get_transient( 'sp_library_catalog_stats' );
    if ( false === $stats ) {
        $total_items = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items" );
        $type_counts = $wpdb->get_results(
            "SELECT media_type, COUNT(*) as cnt FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' GROUP BY media_type ORDER BY cnt DESC"
        );
        // Top subjects for the tag cloud
        $subject_rows = $wpdb->get_col(
            "SELECT subject FROM {$prefix}library_items WHERE subject IS NOT NULL AND subject != ''"
        );
        $subject_counts = [];
        foreach ( $subject_rows as $subj_raw ) {
            foreach ( explode( ',', $subj_raw ) as $part ) {
                $part = trim( $part );
                if ( $part ) {
                    $subject_counts[ $part ] = ( $subject_counts[ $part ] ?? 0 ) + 1;
                }
            }
        }
        arsort( $subject_counts );

        $stats = [
            'total'          => $total_items,
            'type_counts'    => $type_counts,
            'subject_counts' => array_slice( $subject_counts, 0, 24, true ),
        ];
        // Cache for 1 hour — stats don't change often and the query is expensive
        set_transient( 'sp_library_catalog_stats', $stats, HOUR_IN_SECONDS );
    }

    // Unique ID so multiple catalog widgets on one page don't collide
    $uid = 'sp-catalog-' . wp_rand( 1000, 9999 );

    echo '<div class="sp-widget-library-catalog" id="' . esc_attr( $uid ) . '">';

    // ---- Inline styles ----
    // WHY: Scoped inside the widget so they don't leak into the rest of the page.
    //      Uses CSS custom properties from the design system where available.
    ?>
    <style>
        .sp-widget-library-catalog { font-family: var(--sp-font-body, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif); }

        /* ================================================================
           COLLECTION HEADER — stats bar at the top of the landing page
           ================================================================ */
        .sp-catalog-header { margin-bottom: 32px; }
        .sp-catalog-header h2 {
            font-size: 28px; font-weight: 700; margin: 0 0 8px 0;
            color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-header .sp-catalog-subtitle {
            font-size: 16px; color: #555; margin: 0 0 20px 0; line-height: 1.5;
        }
        .sp-catalog-stats-bar {
            display: flex; flex-wrap: wrap; gap: 12px;
        }
        .sp-catalog-stat {
            background: #f8f9fa; border: 1px solid #e9ecef; border-radius: 8px;
            padding: 14px 20px; text-align: center; min-width: 100px;
        }
        .sp-catalog-stat-number {
            font-size: 24px; font-weight: 700;
            color: var(--sp-color-primary, #1a1a2e);
            display: block; line-height: 1.2;
        }
        .sp-catalog-stat-label {
            font-size: 12px; color: #666; text-transform: uppercase;
            letter-spacing: 0.04em; font-weight: 500; margin-top: 2px; display: block;
        }

        /* ================================================================
           TABBED SEARCH — OPAC-style search with field targeting
           ================================================================ */
        .sp-catalog-search { margin-bottom: 28px; }
        .sp-catalog-tabs {
            display: flex; gap: 0; border-bottom: 2px solid #d0d5dd; margin-bottom: 0;
        }
        .sp-catalog-tab {
            padding: 10px 18px; font-size: 14px; font-weight: 500; color: #555;
            background: none; border: none; border-bottom: 2px solid transparent;
            margin-bottom: -2px; cursor: pointer; transition: all 0.15s ease;
        }
        .sp-catalog-tab:hover { color: var(--sp-color-primary, #1a1a2e); background: #f8f9fa; }
        .sp-catalog-tab.active {
            color: var(--sp-color-primary, #1a1a2e); font-weight: 600;
            border-bottom-color: var(--sp-color-accent, #667eea);
            background: #f8f9fa;
        }
        .sp-catalog-search-form {
            display: flex; gap: 0; background: #f8f9fa;
            border: 1px solid #d0d5dd; border-top: none;
            border-radius: 0 0 8px 8px; padding: 16px;
        }
        .sp-catalog-search-form input[type="text"] {
            flex: 1; padding: 12px 16px; border: 1px solid #d0d5dd;
            border-radius: 6px 0 0 6px; font-size: 15px;
            border-right: none; background: #fff;
        }
        .sp-catalog-search-form input[type="text"]:focus {
            outline: none; border-color: var(--sp-color-accent, #667eea);
            box-shadow: 0 0 0 2px rgba(102, 126, 234, 0.15);
        }
        .sp-catalog-search-form button[type="submit"] {
            padding: 12px 24px; border: 1px solid var(--sp-color-primary, #1a1a2e);
            background: var(--sp-color-primary, #1a1a2e); color: #fff;
            font-size: 15px; font-weight: 600; cursor: pointer;
            border-radius: 0 6px 6px 0; white-space: nowrap;
            transition: background 0.15s ease;
        }
        .sp-catalog-search-form button[type="submit"]:hover {
            background: var(--sp-color-accent, #667eea);
            border-color: var(--sp-color-accent, #667eea);
        }

        /* Additional filter row below the search bar */
        .sp-catalog-filter-row {
            display: flex; flex-wrap: wrap; gap: 10px; padding: 12px 16px;
            background: #f8f9fa; border: 1px solid #d0d5dd; border-top: none;
            border-radius: 0 0 8px 8px; margin-top: -8px; padding-top: 0;
        }
        .sp-catalog-filter-row select {
            padding: 8px 10px; border: 1px solid #d0d5dd; border-radius: 6px;
            font-size: 13px; background: #fff; min-width: 130px;
        }

        /* ================================================================
           BROWSE SECTIONS — media type cards + subject tag cloud
           ================================================================ */
        .sp-catalog-browse { margin-bottom: 32px; }
        .sp-catalog-browse h3 {
            font-size: 16px; font-weight: 700; margin: 0 0 14px 0;
            color: var(--sp-color-primary, #1a1a2e);
            text-transform: uppercase; letter-spacing: 0.03em;
        }
        .sp-catalog-type-grid {
            display: grid; grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
            gap: 12px; margin-bottom: 28px;
        }
        .sp-catalog-type-card {
            display: block; background: #fff; border: 1px solid #e0e0e0;
            border-radius: 8px; padding: 18px 14px; text-align: center;
            text-decoration: none; color: inherit;
            transition: all 0.15s ease; cursor: pointer;
        }
        .sp-catalog-type-card:hover {
            border-color: var(--sp-color-accent, #667eea);
            box-shadow: 0 2px 8px rgba(0,0,0,0.08);
            transform: translateY(-1px);
        }
        .sp-catalog-type-card.active {
            border-color: var(--sp-color-accent, #667eea);
            background: #f0f4ff;
        }
        .sp-catalog-type-icon {
            font-size: 28px; display: block; margin-bottom: 8px; line-height: 1;
            color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-type-name {
            font-size: 14px; font-weight: 600; display: block; margin-bottom: 4px;
            color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-type-count {
            font-size: 13px; color: #888; display: block;
        }

        /* Subject tag cloud */
        .sp-catalog-subject-cloud { display: flex; flex-wrap: wrap; gap: 8px; }
        .sp-catalog-subject-tag {
            display: inline-block; padding: 6px 14px;
            background: #f0f0f0; border: 1px solid #e0e0e0; border-radius: 20px;
            font-size: 13px; color: #444; text-decoration: none;
            transition: all 0.15s ease;
        }
        .sp-catalog-subject-tag:hover {
            background: var(--sp-color-primary, #1a1a2e); color: #fff;
            border-color: var(--sp-color-primary, #1a1a2e);
        }
        .sp-catalog-subject-tag .sp-tag-count {
            font-size: 11px; color: #999; margin-left: 4px;
        }
        .sp-catalog-subject-tag:hover .sp-tag-count { color: rgba(255,255,255,0.7); }

        /* Divider between landing and results */
        .sp-catalog-divider {
            border: none; border-top: 1px solid #e5e7eb; margin: 28px 0;
        }

        /* ================================================================
           RESULTS — status bar, table, detail rows, pagination
           ================================================================ */

        /* Results count + active filters */
        .sp-catalog-status { display: flex; flex-wrap: wrap; align-items: center; gap: 8px; margin-bottom: 14px; color: #555; font-size: 14px; }
        .sp-catalog-active-filter { display: inline-flex; align-items: center; gap: 4px; background: var(--sp-color-accent, #667eea); color: #fff; padding: 3px 10px; border-radius: 12px; font-size: 12px; font-weight: 500; }
        .sp-catalog-active-filter a { color: #fff; text-decoration: none; font-weight: 700; margin-left: 2px; }
        .sp-catalog-active-filter a:hover { opacity: 0.8; }

        /* Table */
        .sp-catalog-table { width: 100%; border-collapse: collapse; }
        .sp-catalog-table thead th { padding: 10px 14px; text-align: left; border-bottom: 2px solid #d0d5dd; background: #f8f9fa; font-size: 13px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.03em; color: #555; cursor: pointer; user-select: none; }
        .sp-catalog-table thead th:hover { color: var(--sp-color-primary, #1a1a2e); }
        .sp-catalog-table thead th.sorted { color: var(--sp-color-primary, #1a1a2e); }
        .sp-catalog-table thead th .sp-sort-arrow { font-size: 11px; margin-left: 4px; opacity: 0.4; }
        .sp-catalog-table thead th.sorted .sp-sort-arrow { opacity: 1; }
        .sp-catalog-table tbody td { padding: 10px 14px; border-bottom: 1px solid #eee; font-size: 14px; vertical-align: top; }
        .sp-catalog-table tbody tr:hover { background: #f8f9fa; }
        .sp-catalog-table .sp-item-title { color: var(--sp-color-primary, #2271b1); cursor: pointer; font-weight: 600; text-decoration: none; }
        .sp-catalog-table .sp-item-title:hover { text-decoration: underline; }
        .sp-catalog-table .sp-item-condition { font-size: 11px; font-weight: 500; }
        .sp-catalog-table .sp-item-media-type { font-size: 12px; color: #666; background: #f0f0f0; padding: 2px 8px; border-radius: 10px; display: inline-block; }

        /* Expandable detail row */
        .sp-catalog-detail-row td { padding: 0 !important; border-bottom: 2px solid var(--sp-color-accent, #667eea) !important; }
        .sp-catalog-detail { padding: 20px 24px; background: #fafbfc; animation: spDetailSlide 0.25s ease-out; }
        @keyframes spDetailSlide { from { opacity: 0; max-height: 0; } to { opacity: 1; max-height: 600px; } }
        .sp-catalog-detail-layout { display: flex; gap: 24px; }
        .sp-catalog-detail-cover { flex: 0 0 auto; }
        .sp-catalog-detail-cover img { max-width: 140px; max-height: 200px; border: 1px solid #ddd; border-radius: 4px; box-shadow: 0 2px 6px rgba(0,0,0,0.1); }
        .sp-catalog-detail-body { flex: 1; min-width: 0; }
        .sp-catalog-detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px 32px; }
        .sp-catalog-detail-field { }
        .sp-catalog-detail-field dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 2px; font-weight: 600; }
        .sp-catalog-detail-field dd { margin: 0; font-size: 14px; color: #333; }
        .sp-catalog-detail-desc { grid-column: 1 / -1; margin-top: 8px; }
        .sp-catalog-detail-desc dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 4px; font-weight: 600; }
        .sp-catalog-detail-desc dd { margin: 0; font-size: 14px; color: #333; line-height: 1.6; }

        /* Subject / surname tags (in detail rows) */
        .sp-catalog-tag { display: inline-block; background: var(--sp-color-primary, #2271b1); color: #fff; padding: 2px 10px; border-radius: 12px; font-size: 12px; margin: 2px 3px 2px 0; text-decoration: none; cursor: pointer; }
        .sp-catalog-tag:hover { opacity: 0.85; color: #fff; }
        .sp-catalog-tag.sp-tag-surname { background: #6b7280; }

        /* Pagination */
        .sp-catalog-pagination { display: flex; justify-content: center; align-items: center; gap: 4px; margin-top: 20px; flex-wrap: wrap; }
        .sp-catalog-pagination a, .sp-catalog-pagination span { display: inline-block; padding: 6px 12px; border: 1px solid #d0d5dd; border-radius: 4px; font-size: 14px; text-decoration: none; color: #333; }
        .sp-catalog-pagination a:hover { background: #f0f0f0; }
        .sp-catalog-pagination .current { background: var(--sp-color-primary, #2271b1); color: #fff; border-color: var(--sp-color-primary, #2271b1); }
        .sp-catalog-pagination .dots { border: none; color: #999; }

        /* ================================================================
           RESPONSIVE — mobile-first adjustments
           ================================================================ */
        @media (max-width: 768px) {
            .sp-catalog-header h2 { font-size: 22px; }
            .sp-catalog-stats-bar { gap: 8px; }
            .sp-catalog-stat { padding: 10px 14px; min-width: 80px; }
            .sp-catalog-stat-number { font-size: 20px; }

            .sp-catalog-tabs { overflow-x: auto; -webkit-overflow-scrolling: touch; }
            .sp-catalog-tab { padding: 8px 12px; font-size: 13px; white-space: nowrap; }
            .sp-catalog-search-form { flex-direction: column; gap: 8px; }
            .sp-catalog-search-form input[type="text"] { border-radius: 6px; border-right: 1px solid #d0d5dd; }
            .sp-catalog-search-form button[type="submit"] { border-radius: 6px; }

            .sp-catalog-filter-row { flex-direction: column; }
            .sp-catalog-type-grid { grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); }

            .sp-catalog-table thead { display: none; }
            .sp-catalog-table tbody tr { display: block; padding: 12px 0; border-bottom: 1px solid #eee; }
            .sp-catalog-table tbody td { display: block; padding: 3px 0 !important; border-bottom: none !important; }
            .sp-catalog-table tbody td:before { content: attr(data-label); font-weight: 600; font-size: 11px; text-transform: uppercase; color: #888; display: block; }
            .sp-catalog-detail-grid { grid-template-columns: 1fr; }
            .sp-catalog-detail-layout { flex-direction: column; }
            .sp-catalog-detail-cover { text-align: center; }
            .sp-catalog-detail-cover img { max-width: 120px; }
        }
    </style>
