        echo '</tbody></table>';

        // ---- Pagination ----
        if ( $total_pages > 1 ) {
            echo '<div class="sp-catalog-pagination">';
            $base_url = remove_query_arg( 'sp_lib_pg' );

            // Previous
            if ( $page_num > 1 ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $page_num - 1, $base_url ) ) . '">&laquo; ' . esc_html__( 'Prev', 'societypress' ) . '</a>';
            }

            // Page numbers with smart truncation for large catalogs
            $range = 2;
            for ( $i = 1; $i <= $total_pages; $i++ ) {
                if ( $i === 1 || $i === $total_pages || abs( $i - $page_num ) <= $range ) {
                    if ( $i === $page_num ) {
                        echo '<span class="current">' . $i . '</span>';
                    } else {
                        echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $i, $base_url ) ) . '">' . $i . '</a>';
                    }
                } elseif ( $i === 2 && $page_num > $range + 2 ) {
                    echo '<span class="dots">&hellip;</span>';
                } elseif ( $i === $total_pages - 1 && $page_num < $total_pages - $range - 1 ) {
                    echo '<span class="dots">&hellip;</span>';
                }
            }

            // Next
            if ( $page_num < $total_pages ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_lib_pg', $page_num + 1, $base_url ) ) . '">' . esc_html__( 'Next', 'societypress' ) . ' &raquo;</a>';
            }
            echo '</div>';
        }
    }

    // ================================================================
    // JAVASCRIPT — tab switching, AJAX detail expansion
    // ================================================================
    ?>
    <script>
    (function() {
        var container = document.getElementById('<?php echo esc_js( $uid ); ?>');
        if ( ! container ) return;

        var ajaxUrl = '<?php echo esc_js( admin_url( "admin-ajax.php" ) ); ?>';
        var openRow = null;

        // ---- Tab switching ----
        // WHY: Clicking a tab doesn't submit the form — it just changes which
        //      field the search targets. The hidden input and placeholder update
        //      instantly so the researcher knows what they're searching.
        var tabs = container.querySelectorAll('.sp-catalog-tab');
        var fieldInput = document.getElementById('<?php echo esc_js( $uid ); ?>-field');
        var searchInput = document.getElementById('<?php echo esc_js( $uid ); ?>-input');
        var placeholders = <?php echo wp_json_encode( $tab_placeholders ); ?>;

        tabs.forEach(function(tab) {
            tab.addEventListener('click', function() {
                var field = this.getAttribute('data-field');

                // Update active tab styling
                tabs.forEach(function(t) { t.classList.remove('active'); });
                this.classList.add('active');

                // Update hidden field value and placeholder
                if ( fieldInput ) fieldInput.value = field;
                if ( searchInput ) searchInput.placeholder = placeholders[field] || '';
                if ( searchInput ) searchInput.focus();
            });
        });

        // ---- AJAX expand/collapse ----
        // WHY: Clicking a title row fetches full item details via AJAX and injects
        //      a detail panel below the row. Clicking again collapses it. No page
        //      reload — the researcher stays in context of their results.
        container.addEventListener('click', function(e) {
            var titleLink = e.target.closest('.sp-item-title');
            if ( ! titleLink ) return;
            e.preventDefault();

            var itemId = titleLink.getAttribute('data-item-id');
            var parentRow = titleLink.closest('tr');
            if ( ! parentRow ) return;

            // If this row's detail is already open, close it
            var existingDetail = parentRow.nextElementSibling;
            if ( existingDetail && existingDetail.classList.contains('sp-catalog-detail-row') ) {
                existingDetail.remove();
                openRow = null;
                return;
            }

            // Close any other open detail row
            if ( openRow ) {
                openRow.remove();
                openRow = null;
            }

            // Create placeholder row
            var detailRow = document.createElement('tr');
            detailRow.className = 'sp-catalog-detail-row';
            var detailCell = document.createElement('td');
            detailCell.setAttribute('colspan', '6');
            detailCell.innerHTML = '<div class="sp-catalog-detail" style="text-align:center; padding:30px;"><?php echo esc_js( __( 'Loading...', 'societypress' ) ); ?></div>';
            detailRow.appendChild(detailCell);
            parentRow.after(detailRow);
            openRow = detailRow;

            // Fetch item details
            fetch(ajaxUrl + '?action=sp_library_item_detail&item_id=' + itemId, { credentials: 'same-origin' })
                .then(function(r) { return r.json(); })
                .then(function(resp) {
                    if ( ! resp.success || ! resp.data ) {
                        detailCell.innerHTML = '<div class="sp-catalog-detail"><p><?php echo esc_js( __( 'Unable to load details.', 'societypress' ) ); ?></p></div>';
                        return;
                    }
                    var d = resp.data;

                    var html = '<div class="sp-catalog-detail">';
                    html += '<div class="sp-catalog-detail-layout">';

                    // Cover image — shown on the left if available
                    if ( d.cover_url ) {
                        html += '<div class="sp-catalog-detail-cover">';
                        html += '<img src="' + escAttr(d.cover_url) + '" alt="' + escAttr(d.title) + ' cover" loading="lazy">';
                        html += '</div>';
                    }

                    html += '<div class="sp-catalog-detail-body">';
                    html += '<div class="sp-catalog-detail-grid">';

                    function field(label, value) {
                        if ( ! value ) return '';
                        return '<dl class="sp-catalog-detail-field"><dt>' + label + '</dt><dd>' + escHtml(value) + '</dd></dl>';
                    }

                    html += field('<?php echo esc_js( __( 'Title', 'societypress' ) ); ?>', d.title);
                    html += field('<?php echo esc_js( __( 'Author', 'societypress' ) ); ?>', d.author);
                    html += field('<?php echo esc_js( __( 'Publisher', 'societypress' ) ); ?>', d.publisher);
                    html += field('<?php echo esc_js( __( 'Publisher Location', 'societypress' ) ); ?>', d.publisher_location);
                    html += field('<?php echo esc_js( __( 'Published', 'societypress' ) ); ?>', d.pub_date);
                    html += field('<?php echo esc_js( __( 'Media Type', 'societypress' ) ); ?>', d.media_type);
                    html += field('<?php echo esc_js( __( 'Category', 'societypress' ) ); ?>', d.category_name);
                    html += field('<?php echo esc_js( __( 'Call Number', 'societypress' ) ); ?>', d.call_number);
                    html += field('<?php echo esc_js( __( 'ISBN', 'societypress' ) ); ?>', d.isbn);
                    html += field('<?php echo esc_js( __( 'LCCN', 'societypress' ) ); ?>', d.lccn);
                    html += field('<?php echo esc_js( __( 'Shelf Location', 'societypress' ) ); ?>', d.shelf_location);
                    html += field('<?php echo esc_js( __( 'Geographic Coverage', 'societypress' ) ); ?>', d.geographic_location);
                    html += field('<?php echo esc_js( __( 'County', 'societypress' ) ); ?>', d.county);
                    html += field('<?php echo esc_js( __( 'State', 'societypress' ) ); ?>', d.state);
                    html += field('<?php echo esc_js( __( 'Condition', 'societypress' ) ); ?>', d.item_condition ? d.item_condition.charAt(0).toUpperCase() + d.item_condition.slice(1) : '');
                    html += field('<?php echo esc_js( __( 'Status', 'societypress' ) ); ?>', d.available ? '<?php echo esc_js( __( 'Available', 'societypress' ) ); ?>' : '<?php echo esc_js( __( 'Checked Out', 'societypress' ) ); ?>');
                    html += field('<?php echo esc_js( __( 'Acquisition', 'societypress' ) ); ?>', [d.acq_code, d.acq_date].filter(Boolean).join(' — '));
                    html += field('<?php echo esc_js( __( 'Donor', 'societypress' ) ); ?>', d.donor);
                    html += field('<?php echo esc_js( __( 'Value', 'societypress' ) ); ?>', d.item_value);
                    html += field('<?php echo esc_js( __( 'Acquisition #', 'societypress' ) ); ?>', d.acquisition_number);
                    html += field('<?php echo esc_js( __( 'System ID', 'societypress' ) ); ?>', d.system_id);

                    // Subject tags — clickable to filter
                    if ( d.subjects && d.subjects.length > 0 ) {
                        html += '<dl class="sp-catalog-detail-field"><dt><?php echo esc_js( __( 'Subjects', 'societypress' ) ); ?></dt><dd>';
                        d.subjects.forEach(function(s) {
                            var filterUrl = addOrReplaceParam(window.location.href, 'sp_lib_subject', s);
                            filterUrl = removeParam(filterUrl, 'sp_lib_pg');
                            html += '<a href="' + escAttr(filterUrl) + '" class="sp-catalog-tag">' + escHtml(s) + '</a>';
                        });
                        html += '</dd></dl>';
                    }

                    // Surname tags
                    if ( d.surnames && d.surnames.length > 0 ) {
                        html += '<dl class="sp-catalog-detail-field"><dt><?php echo esc_js( __( 'Surnames', 'societypress' ) ); ?></dt><dd>';
                        d.surnames.forEach(function(s) {
                            var filterUrl = addOrReplaceParam(window.location.href, 'sp_lib_search', s);
                            filterUrl = removeParam(filterUrl, 'sp_lib_pg');
                            html += '<a href="' + escAttr(filterUrl) + '" class="sp-catalog-tag sp-tag-surname">' + escHtml(s) + '</a>';
                        });
                        html += '</dd></dl>';
                    }

                    // Description — full width
                    if ( d.description ) {
                        html += '<div class="sp-catalog-detail-desc"><dt><?php echo esc_js( __( 'Description', 'societypress' ) ); ?></dt><dd>' + escHtml(d.description) + '</dd></div>';
                    }

                    html += '</div>'; // close grid
                    html += '</div>'; // close body
                    html += '</div>'; // close layout
                    html += '</div>'; // close detail

                    detailCell.innerHTML = html;
                })
                .catch(function() {
                    detailCell.innerHTML = '<div class="sp-catalog-detail"><p><?php echo esc_js( __( 'Unable to load details.', 'societypress' ) ); ?></p></div>';
                });
        });

        // Utility: escape HTML
        function escHtml(str) {
            var div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }
        function escAttr(str) {
            return str.replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        }
        function addOrReplaceParam(url, key, value) {
            var u = new URL(url);
            u.searchParams.set(key, value);
            return u.toString();
        }
        function removeParam(url, key) {
            var u = new URL(url);
            u.searchParams.delete(key);
            return u.toString();
        }
    })();
    </script>
    <?php
    echo '</div>'; // close .sp-widget-library-catalog
}

/**
 * Render: Hero Slider
 *
 * WHY: A full-width image slider is the centerpiece of many society homepages.
 *      This uses lightweight CSS transitions + vanilla JS for auto-advancing.
 *      No jQuery, no external libraries.
 */
function sp_render_builder_widget_hero_slider( array $s ): void {
    $slides   = $s['slides'] ?? [];
    $height   = (int) ( $s['height'] ?? 400 );
    $autoplay = (int) ( $s['autoplay'] ?? 1 );
    $interval = max( 2, (int) ( $s['interval'] ?? 5 ) ) * 1000;
    $overlay  = (int) ( $s['overlay'] ?? 1 );
    $uid      = 'sp-slider-' . wp_rand( 1000, 9999 );

    if ( empty( $slides ) ) {
        echo '<p class="sp-empty-state">' . esc_html__( 'No slides configured.', 'societypress' ) . '</p>';
        return;
    }

    ?>
    <?php
    // WHY no inline <style> block: All static hero slider CSS is now centralized
    // in sp_builder_frontend_styles(). Only the dynamic height value (which varies
    // per widget instance) remains as an inline style on the container div.
    ?>
    <div class="sp-hero-slider" id="<?php echo esc_attr( $uid ); ?>" style="height: <?php echo absint( $height ); ?>px;">
        <?php foreach ( $slides as $i => $slide ) :
            $media_url = esc_url( $slide['image'] ?? '' );
            // WHY: Detect video files so we can render a <video> element instead
            // of a CSS background-image. Videos need autoplay + muted + loop to
            // behave like a background — muted is required by browsers for
            // autoplay to work without user interaction.
            $is_video  = (bool) preg_match( '/\.(mp4|webm|ogg)(\?|$)/i', $media_url );
        ?>
            <div class="sp-slide <?php echo $i === 0 ? 'active' : ''; ?>"
                 <?php if ( ! $is_video && $media_url ) : ?>
                     style="background-image: url('<?php echo $media_url; ?>');"
                 <?php endif; ?>>
                <?php if ( $is_video && $media_url ) : ?>
                    <video class="sp-slide-video" autoplay muted loop playsinline>
                        <source src="<?php echo $media_url; ?>" type="video/<?php echo esc_attr( pathinfo( parse_url( $media_url, PHP_URL_PATH ), PATHINFO_EXTENSION ) ); ?>">
                    </video>
                <?php endif; ?>
                <?php if ( $overlay ) : ?>
                    <div class="sp-slide-overlay" style="background: rgba(0,0,0,0.35);"></div>
                <?php endif; ?>
                <div class="sp-slide-content">
                    <?php
                    // WHY: Per-line repeater data provides independent styling
                    // for each text line (size, weight, color). Falls back to
                    // legacy overlay_text format for slides saved before this
                    // change — auto-migrates on next save.
                    $slide_lines = $slide['lines'] ?? [];

                    // WHY: Legacy migration — if old overlay_text exists but no
                    // lines array, convert it. Line 1 → large/bold, line 2+ →
                    // medium/light, line 3+ → small/light. All white by default.
                    if ( empty( $slide_lines ) && ! empty( $slide['overlay_text'] ) ) {
                        $raw = array_filter( array_map( 'trim', explode( "\n", $slide['overlay_text'] ) ), 'strlen' );
                        $slide_lines = [];
                        foreach ( array_values( $raw ) as $li => $text ) {
                            if ( $li === 0 ) {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'large',  'weight' => 'bold',  'color' => 'white' ];
                            } elseif ( $li === 1 ) {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'medium', 'weight' => 'light', 'color' => 'white' ];
                            } else {
                                $slide_lines[] = [ 'text' => $text, 'size' => 'small',  'weight' => 'light', 'color' => 'white' ];
                            }
                        }
                    }

                    // WHY: Size/weight/color maps translate dropdown values to
                    // actual CSS values. Using a class for size so the media
                    // query can override it on mobile (inline styles beat MQs).
                    $size_map   = [ 'small' => '22px', 'medium' => '30px', 'large' => '44px' ];
                    $weight_map = [ 'light' => '300', 'bold' => '700' ];
                    $color_map  = [ 'white' => '#fff', 'dark' => '#1a1a1a', 'accent' => 'var(--sp-color-accent)' ];

                    foreach ( $slide_lines as $line ) {
                        $text   = esc_html( $line['text'] ?? '' );
                        if ( '' === $text ) continue;
                        $sz     = $size_map[ $line['size'] ?? 'medium' ] ?? '30px';
                        $wt     = $weight_map[ $line['weight'] ?? 'light' ] ?? '300';
                        $cl     = $color_map[ $line['color'] ?? 'white' ] ?? '#fff';
                        $szClass = 'sp-line-' . ( $line['size'] ?? 'medium' );
                        printf(
                            '<p class="sp-slide-line %s" style="font-size:%s; font-weight:%s; color:%s;">%s</p>',
                            esc_attr( $szClass ),
                            esc_attr( $sz ),
                            esc_attr( $wt ),
                            esc_attr( $cl ),
                            $text
                        );
                    }
                    ?>
                    <?php if ( ! empty( $slide['btn_text'] ) && ! empty( $slide['btn_url'] ) ) : ?>
                        <a href="<?php echo esc_url( $slide['btn_url'] ); ?>" class="sp-slide-btn"><?php echo esc_html( $slide['btn_text'] ); ?></a>
                    <?php endif; ?>
                </div>
            </div>
        <?php endforeach; ?>

        <?php if ( count( $slides ) > 1 ) : ?>
            <div class="sp-slider-arrows">
                <button type="button" class="sp-slider-arrow sp-slider-prev">&lsaquo;</button>
                <button type="button" class="sp-slider-arrow sp-slider-next">&rsaquo;</button>
            </div>
        <?php endif; ?>
    </div>

    <?php if ( count( $slides ) > 1 ) : ?>
        <div class="sp-slider-dots" data-slider="<?php echo esc_attr( $uid ); ?>">
            <?php for ( $i = 0; $i < count( $slides ); $i++ ) : ?>
                <button type="button" class="sp-slider-dot <?php echo $i === 0 ? 'active' : ''; ?>" data-index="<?php echo $i; ?>"></button>
            <?php endfor; ?>
        </div>

        <script>
        (function() {
            var slider   = document.getElementById('<?php echo esc_js( $uid ); ?>');
            var slides   = slider.querySelectorAll('.sp-slide');
            var dots     = document.querySelectorAll('[data-slider="<?php echo esc_js( $uid ); ?>"] .sp-slider-dot');
            var current  = 0;
            var total    = slides.length;
            var auto     = <?php echo $autoplay ? 'true' : 'false'; ?>;
            var interval = <?php echo $interval; ?>;
            var timer    = null;

            function goTo(idx) {
                slides[current].classList.remove('active');
                dots[current].classList.remove('active');
                current = (idx + total) % total;
                slides[current].classList.add('active');
                dots[current].classList.add('active');
            }

            function next() { goTo(current + 1); }
            function prev() { goTo(current - 1); }

            function startAuto() {
                if (auto && total > 1) {
                    timer = setInterval(next, interval);
                }
            }
            function stopAuto() {
                if (timer) { clearInterval(timer); timer = null; }
            }

            // Arrow buttons
            var prevBtn = slider.querySelector('.sp-slider-prev');
            var nextBtn = slider.querySelector('.sp-slider-next');
            if (prevBtn) prevBtn.addEventListener('click', function() { stopAuto(); prev(); startAuto(); });
            if (nextBtn) nextBtn.addEventListener('click', function() { stopAuto(); next(); startAuto(); });

            // Dot buttons
            dots.forEach(function(dot) {
                dot.addEventListener('click', function() {
                    stopAuto();
                    goTo(parseInt(this.getAttribute('data-index'), 10));
                    startAuto();
                });
            });

            // Pause on hover
            slider.addEventListener('mouseenter', stopAuto);
            slider.addEventListener('mouseleave', startAuto);

            startAuto();
        })();
        </script>
    <?php endif; ?>
    <?php
}


/**
 * Render: Feature Cards
 *
 * WHY: Grid of image cards with titles, descriptions, and buttons. Used for
 * "Library / Volunteer / Learn / Benefits" style sections. Replaces the
 * hardcoded feature cards that were previously in the society front-page.php.
 */
function sp_render_builder_widget_feature_cards( array $s ): void {
    $cards   = $s['cards'] ?? [];
    $columns = (int) ( $s['columns'] ?? 2 );

    if ( empty( $cards ) ) {
        echo '<p class="sp-empty-state">' . esc_html__( 'No cards configured.', 'societypress' ) . '</p>';
        return;
    }

    ?>
    <?php
    // WHY: Static feature card CSS is centralized in sp_builder_frontend_styles().
    // Only the dynamic grid-template-columns (which depends on $columns) stays
    // inline on the grid container. This avoids duplicate <style> blocks when
    // multiple feature_cards widgets appear on the same page.
    ?>
    <div class="sp-feature-cards-grid" style="grid-template-columns: repeat(<?php echo absint( $columns ); ?>, 1fr);">
        <?php foreach ( $cards as $card ) :
            $img_url = '';
            if ( ! empty( $card['image_id'] ) ) {
                $img_url = wp_get_attachment_image_url( (int) $card['image_id'], 'medium_large' );
            }
        ?>
            <div class="sp-feature-card">
                <?php if ( $img_url ) : ?>
                    <img class="sp-feature-card-img" src="<?php echo esc_url( $img_url ); ?>" alt="<?php echo esc_attr( $card['title'] ?? '' ); ?>">
                <?php endif; ?>
                <h3><?php echo esc_html( $card['title'] ?? '' ); ?></h3>
                <?php if ( ! empty( $card['description'] ) ) : ?>
                    <p><?php echo esc_html( $card['description'] ); ?></p>
                <?php endif; ?>
                <?php if ( ! empty( $card['btn_text'] ) && ! empty( $card['btn_url'] ) ) : ?>
                    <a href="<?php echo esc_url( $card['btn_url'] ); ?>" class="sp-feature-card-btn"><?php echo esc_html( $card['btn_text'] ); ?></a>
                <?php endif; ?>
            </div>
        <?php endforeach; ?>
    </div>
    <?php
}


/**
 * Render: Map Embed
 *
 * WHY: Embeds a Google Map using the free iframe embed (no API key). The
 * address is URL-encoded and passed to Google Maps' embed endpoint.
 */
function sp_render_builder_widget_map_embed( array $s ): void {
    $address = $s['address'] ?? '';
    $height  = (int) ( $s['height'] ?? 350 );

    if ( empty( $address ) ) {
        echo '<p class="sp-empty-state">' . esc_html__( 'No address configured.', 'societypress' ) . '</p>';
        return;
    }

    // WHY this URL format: Google's free embed endpoint requires the query
    // string parameters in this specific order. The 't' param is map type,
    // 'z' is zoom level, 'output=embed' tells Google to serve the iframe
    // version. esc_url() will encode the & signs for HTML but browsers
    // decode them correctly in src attributes.
    //
    // NOTE: The maps.google.com/maps?output=embed endpoint is unofficial
    // and could change or break without notice from Google. If that happens,
    // the proper replacement is the Maps Embed API (requires an API key):
    // https://developers.google.com/maps/documentation/embed/get-started
    $embed_url = 'https://maps.google.com/maps?q=' . rawurlencode( $address ) . '&t=&z=15&ie=UTF8&iwloc=&output=embed';
    ?>
    <div class="sp-map-embed-wrap">
        <iframe
            src="<?php echo esc_url( $embed_url ); ?>"
            width="100%"
            height="<?php echo absint( $height ); ?>"
            allowfullscreen=""
            loading="lazy"
            referrerpolicy="no-referrer-when-downgrade"
            title="<?php echo esc_attr( $address ); ?>">
        </iframe>
    </div>
    <?php
}


// ============================================================================
// SURNAME CONTACT — AJAX HANDLER
// ============================================================================
//
// WHY: Feature 2 — lets logged-in members contact a surname researcher without
//      exposing the researcher's email address. The sender's email goes in
//      Reply-To so the researcher can respond directly if they choose.

add_action( 'wp_ajax_sp_surname_contact', 'sp_handle_surname_contact' );

function sp_handle_surname_contact(): void {
    if ( ! check_ajax_referer( 'sp_surname_contact', 'sp_surname_contact_nonce', false ) ) {
        wp_send_json_error( __( 'Security check failed. Please refresh and try again.', 'societypress' ) );
    }
    if ( ! is_user_logged_in() ) {
        wp_send_json_error( __( 'You must be logged in to contact a researcher.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $researcher_id = absint( $_POST['researcher_id'] ?? 0 );
    $sender_name   = sanitize_text_field( $_POST['sender_name'] ?? '' );
    $sender_email  = sanitize_email( $_POST['sender_email'] ?? '' );
    $message       = sanitize_textarea_field( $_POST['message'] ?? '' );

    if ( ! $researcher_id || ! $sender_name || ! $sender_email || ! $message ) {
        wp_send_json_error( __( 'Please fill in all fields.', 'societypress' ) );
    }
    if ( ! is_email( $sender_email ) ) {
        wp_send_json_error( __( 'Please enter a valid email address.', 'societypress' ) );
    }

    // Look up the researcher's email from the contact table
    $researcher_email = $wpdb->get_var( $wpdb->prepare(
        "SELECT email FROM {$prefix}member_contact WHERE user_id = %d",
        $researcher_id
    ) );

    if ( ! $researcher_email || ! is_email( $researcher_email ) ) {
        wp_send_json_error( __( 'Unable to contact this researcher at this time.', 'societypress' ) );
    }

    // Check opt-out preference
    $opted_out = $wpdb->get_var( $wpdb->prepare(
        "SELECT meta_value FROM {$prefix}member_meta
         WHERE user_id = %d AND meta_key = 'pref_email_surnames'",
        $researcher_id
    ) );
    if ( $opted_out === '0' ) {
        wp_send_json_error( __( 'This researcher has opted out of contact messages.', 'societypress' ) );
    }

    // Build and send the email
    $site_name = get_bloginfo( 'name' );
    $body_html = '<p>' . esc_html( $sender_name ) . ' is researching a surname you have listed '
               . 'and would like to connect with you.</p>'
               . '<div style="background:#f6f7f7; border:1px solid #e0e0e0; border-radius:6px; padding:16px; margin:16px 0;">'
               . '<p class="sp-m-0 sp-pre-wrap">' . esc_html( $message ) . '</p>'
               . '</div>'
               . '<p class="sp-text-secondary" style="font-size:13px;">To reply, simply respond to this email. '
               . 'Your email address has not been shared with the sender.</p>';

    $html = sp_build_email_html( __( 'Surname Research Inquiry', 'societypress' ), $body_html );

    // Strip \r and \n from sender name before use in email headers to prevent
    // header injection attacks (an attacker could inject BCC: or other headers)
    $safe_sender_name = str_replace( [ "\r", "\n" ], '', $sender_name );

    $headers = [
        'Content-Type: text/html; charset=UTF-8',
        sprintf( 'Reply-To: %s <%s>', $safe_sender_name, $sender_email ),
    ];

    $sent = wp_mail(
        $researcher_email,
        sprintf( '[%s] Surname research inquiry from %s', $site_name, $safe_sender_name ),
        $html,
        $headers
    );

    if ( $sent ) {
        wp_send_json_success( [ 'message' => __( 'Your message has been sent! The researcher can reply directly to your email.', 'societypress' ) ] );
    } else {
        wp_send_json_error( __( 'There was a problem sending your message. Please try again later.', 'societypress' ) );
    }
}


// ============================================================================
// PHOTOS & VIDEOS — ADMIN PAGES
// ============================================================================
//
// WHY: Admin interface for managing media in a hierarchical folder structure.
//      Folders can be nested up to 5 levels deep. Each folder holds images
//      (from WP media library) and videos (YouTube links). All folder
//      operations (create, rename, move, delete) happen via AJAX so the
//      admin stays on the same page.

/**
 * Build breadcrumb trail for a folder.
 *
 * WHY: Breadcrumbs show the user exactly where they are in the folder tree
 *      and let them navigate back up to any parent with one click.
 *
 * @param int    $folder_id  Current folder ID (0 = root).
 * @param string $base_url   Base admin URL for the gallery page.
 * @return array Array of [ 'id' => int, 'title' => string, 'url' => string ].
 */
function sp_build_folder_breadcrumbs( int $folder_id, string $base_url ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $crumbs = [];

    $current = $folder_id;
    while ( $current ) {
        $row = $wpdb->get_row( $wpdb->prepare(
            "SELECT id, title, parent_id FROM {$prefix}photo_albums WHERE id = %d",
            $current
        ) );
        if ( ! $row ) break;

        array_unshift( $crumbs, [
            'id'    => (int) $row->id,
            'title' => $row->title,
            'url'   => add_query_arg( 'folder', $row->id, $base_url ),
        ] );
        $current = (int) $row->parent_id;
    }

    // Prepend root
    array_unshift( $crumbs, [
        'id'    => 0,
        'title' => __( 'All Media', 'societypress' ),
        'url'   => $base_url,
    ] );

    return $crumbs;
}

/**
 * Render: Photos & Videos — Folder Browser
 *
 * WHY: Single-page folder browser that shows the current folder's contents
 *      (subfolders + media items). Breadcrumb navigation for moving through
 *      the hierarchy. Folder CRUD happens via AJAX. Images are added from
 *      the WP media library picker. Videos are added by pasting YouTube URLs.
 */
function sp_render_gallery_page(): void {
    global $wpdb;
    $prefix    = $wpdb->prefix . 'sp_';
    $folder_id = absint( $_GET['folder'] ?? 0 );
    $base_url  = admin_url( 'admin.php?page=sp-gallery' );

    // Load current folder info (null if at root)
    $current_folder = $folder_id ? $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}photo_albums WHERE id = %d", $folder_id
    ) ) : null;

    // If folder ID was provided but doesn't exist, redirect to root
    if ( $folder_id && ! $current_folder ) {
        echo '<div class="notice notice-error"><p>' . esc_html__( 'Folder not found.', 'societypress' ) . '</p></div>';
        $folder_id      = 0;
        $current_folder = null;
    }

    // Build breadcrumbs
    $breadcrumbs = sp_build_folder_breadcrumbs( $folder_id, $base_url );

    // Load subfolders of current folder
    if ( $folder_id ) {
        $subfolders = $wpdb->get_results( $wpdb->prepare(
            "SELECT a.*, (SELECT COUNT(*) FROM {$prefix}photo_album_items WHERE album_id = a.id) as item_count
             FROM {$prefix}photo_albums a
             WHERE a.parent_id = %d
             ORDER BY a.sort_order ASC, a.title ASC",
            $folder_id
        ) );
    } else {
        $subfolders = $wpdb->get_results(
            "SELECT a.*, (SELECT COUNT(*) FROM {$prefix}photo_album_items WHERE album_id = a.id) as item_count
             FROM {$prefix}photo_albums a
             WHERE a.parent_id IS NULL OR a.parent_id = 0
             ORDER BY a.sort_order ASC, a.title ASC"
        );
    }

    // Load media items in current folder (only if viewing a specific folder)
    $items = [];
    if ( $folder_id ) {
        $items = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}photo_album_items WHERE album_id = %d ORDER BY sort_order ASC",
            $folder_id
        ) );
    }

    // Load all folders for the "Move to" dropdown (used by AJAX)
    $all_folders = $wpdb->get_results(
        "SELECT id, title, parent_id FROM {$prefix}photo_albums ORDER BY title ASC"
    );

    // Generate the AJAX nonce
    $nonce = wp_create_nonce( 'sp_media_folder_nonce' );

    // WordPress media uploader needs this when viewing a folder
    if ( $folder_id ) {
        wp_enqueue_media();
    }
    ?>
    <style>
    /* sp_render_gallery_page styles — folder browser layout */
    .sp-media-breadcrumbs          { display: flex; align-items: center; gap: 4px;
                                     padding: 8px 0; margin-bottom: 16px; font-size: 13px; }
    .sp-media-breadcrumbs a        { color: #2271b1; text-decoration: none; }
    .sp-media-breadcrumbs a:hover  { text-decoration: underline; }
    .sp-media-breadcrumbs .sep     { color: #999; }
    .sp-media-breadcrumbs .current { font-weight: 600; color: #1d2327; }
    .sp-media-toolbar              { display: flex; gap: 8px; margin-bottom: 20px; flex-wrap: wrap; }
    .sp-media-folders-grid         { display: flex; flex-wrap: wrap; gap: 16px; margin-bottom: 24px; }
    .sp-media-folder-card          { width: 180px; background: #fff; border: 1px solid #ccd0d4;
                                     border-radius: 8px; overflow: hidden; transition: box-shadow 0.2s; }
    .sp-media-folder-card:hover    { box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    .sp-media-folder-icon          { width: 100%; height: 100px; background: #f0f6fc;
                                     display: flex; align-items: center; justify-content: center; }
    .sp-media-folder-icon .dashicons { font-size: 48px; width: 48px; height: 48px; color: #2271b1; }
    .sp-media-folder-info          { padding: 10px 12px; }
    .sp-media-folder-title         { margin: 0 0 4px; font-size: 14px; font-weight: 600; }
    .sp-media-folder-title a       { text-decoration: none; color: #1d2327; }
    .sp-media-folder-title a:hover { color: #2271b1; }
    .sp-media-folder-meta          { font-size: 12px; color: #666; }
