}


/**
 * Render: Annual Report Page
 *
 * WHY: Generates a comprehensive report with membership trends, event
 *      attendance, volunteer hours, and other metrics. Uses CSS bar charts
 *      (no JS libraries) and has a print-friendly layout.
 */
function sp_render_annual_report_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $year       = absint( $_GET['year'] ?? wp_date( 'Y' ) );
    $start_date = $year . '-01-01';
    $end_date   = $year . '-12-31';
    $prev_year  = $year - 1;

    // MEMBERSHIP STATS
    $total_members    = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" );
    $active_members   = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'active'" );
    $new_this_year    = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}members WHERE join_date BETWEEN %s AND %s", $start_date, $end_date
    ) );
    $expired_this_year = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}members WHERE expiration_date BETWEEN %s AND %s AND status != 'active'", $start_date, $end_date
    ) );

    // Members by status
    $status_counts = $wpdb->get_results(
        "SELECT status, COUNT(*) as cnt FROM {$prefix}members GROUP BY status ORDER BY cnt DESC"
    );

    // EVENTS STATS
    $events_count = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}events WHERE event_date BETWEEN %s AND %s", $start_date, $end_date
    ) );
    $total_registrations = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}event_registrations er
         INNER JOIN {$prefix}events e ON er.event_id = e.id
         WHERE e.event_date BETWEEN %s AND %s AND er.status = 'confirmed'", $start_date, $end_date
    ) );

    // Actual attendance: count registrations explicitly marked as attended
    // WHY: The 'attended' column is nullable — NULL means not yet marked,
    //      1 means attended, 0 means no-show. We only count rows where
    //      attended = 1 so the report reflects who actually showed up,
    //      not who registered. This is the number Harold puts in the
    //      annual report to the board.
    $total_attendance = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}event_registrations er
         INNER JOIN {$prefix}events e ON er.event_id = e.id
         WHERE e.event_date BETWEEN %s AND %s AND er.attended = 1", $start_date, $end_date
    ) );

    // Monthly event breakdown
    $monthly_events = $wpdb->get_results( $wpdb->prepare(
        "SELECT MONTH(event_date) as mo, COUNT(*) as cnt
         FROM {$prefix}events WHERE event_date BETWEEN %s AND %s
         GROUP BY mo ORDER BY mo", $start_date, $end_date
    ) );
    $monthly_map = [];
    foreach ( $monthly_events as $me ) $monthly_map[ (int) $me->mo ] = (int) $me->cnt;
    $max_monthly_events = max( 1, max( $monthly_map ?: [ 1 ] ) );

    // VOLUNTEER STATS
    $vol_hours = (float) $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(hours), 0) FROM {$prefix}volunteer_hours WHERE activity_date BETWEEN %s AND %s", $start_date, $end_date
    ) );
    $vol_count = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(DISTINCT user_id) FROM {$prefix}volunteer_hours WHERE activity_date BETWEEN %s AND %s", $start_date, $end_date
    ) );
    ?>
    <div class="wrap" id="sp-annual-report">
        <style>
            @media print {
                #wpadminbar, #adminmenumain, #wpfooter, .sp-no-print { display: none !important; }
                #wpcontent { margin-left: 0 !important; }
                .sp-report-section { page-break-inside: avoid; }
                .sp-bar-chart { page-break-inside: avoid; }
            }
            .sp-bar-chart .sp-bar { background: var(--sp-color-primary); border-radius: 3px; min-width: 4px; transition: width 0.3s; }
            .sp-stat-card { background: #fff; border: 1px solid #ccd0d4; border-radius: 8px; padding: 20px; text-align: center; }
            .sp-stat-value { font-size: 32px; font-weight: 700; color: var(--sp-color-primary); }
            .sp-stat-label { color: #666; font-size: 13px; margin-top: 4px; }

            /* Annual report layout classes — extracted from inline styles to keep templates clean */
            .sp-annual-header         { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
            .sp-annual-title          { margin: 0; }
            .sp-annual-print-btn      { margin-left: 8px; }
            .sp-annual-copy-btn       { margin-left: 4px; }
            .sp-annual-stat-grid      { display: grid; grid-template-columns: repeat(auto-fill, minmax(160px, 1fr)); gap: 12px; margin-bottom: 32px; }
            .sp-annual-section        { background: #fff; border: 1px solid #ccd0d4; border-radius: 8px; padding: 24px; margin-bottom: 24px; }
            .sp-annual-section-title  { margin-top: 0; }
            .sp-annual-table          { width: 100%; border-collapse: collapse; }
            .sp-annual-th-left        { text-align: left; padding: 8px 12px; border-bottom: 2px solid #ddd; }
            .sp-annual-th-right       { text-align: right; padding: 8px 12px; border-bottom: 2px solid #ddd; }
            .sp-annual-th-chart       { text-align: left; padding: 8px 12px; border-bottom: 2px solid #ddd; width: 60%; }
            .sp-annual-td-status      { padding: 8px 12px; border-bottom: 1px solid #eee; font-weight: 600; }
            .sp-annual-td-count       { padding: 8px 12px; border-bottom: 1px solid #eee; text-align: right; }
            .sp-annual-td-chart       { padding: 8px 12px; border-bottom: 1px solid #eee; }
            .sp-annual-month-bar-row  { height: 20px; } /* fixed height for membership status bars */
            .sp-annual-events-chart   { display: flex; align-items: flex-end; gap: 8px; height: 200px; padding: 0 12px; }
            .sp-annual-month-col      { flex: 1; text-align: center; }
            .sp-annual-month-count    { font-size: 12px; font-weight: 600; margin-bottom: 4px; }
            .sp-annual-month-label    { font-size: 11px; color: #666; margin-top: 4px; }
            .sp-annual-vol-name       { padding: 6px 12px; width: 200px; }
            .sp-annual-vol-hours      { padding: 6px 12px; width: 80px; text-align: right; }
            .sp-annual-vol-chart      { padding: 6px 12px; }
        </style>

        <div class="sp-no-print sp-annual-header">
            <h1 class="sp-annual-title"><?php echo esc_html( sprintf( __( 'Annual Report — %s', 'societypress' ), $year ) ); ?></h1>
            <div>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-annual-report&year=' . $prev_year ) ); ?>" class="button">&larr; <?php echo $prev_year; ?></a>
                <?php if ( $year < (int) wp_date( 'Y' ) ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-annual-report&year=' . ( $year + 1 ) ) ); ?>" class="button"><?php echo $year + 1; ?> &rarr;</a>
                <?php endif; ?>
                <button type="button" onclick="window.print();" class="button button-primary sp-annual-print-btn"><?php esc_html_e( 'Print Report', 'societypress' ); ?></button>
                <button type="button" id="sp-copy-report-btn" class="button sp-annual-copy-btn"><?php esc_html_e( 'Copy as Text', 'societypress' ); ?></button>
            </div>
        </div>

        <!-- Summary Cards -->
        <div class="sp-annual-stat-grid">
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo absint( $active_members ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'Active Members', 'societypress' ); ?></div></div>
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo absint( $new_this_year ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'New Members', 'societypress' ); ?></div></div>
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo absint( $expired_this_year ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'Expired/Lapsed', 'societypress' ); ?></div></div>
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo absint( $events_count ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'Events', 'societypress' ); ?></div></div>
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo absint( $total_registrations ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'Registrations', 'societypress' ); ?></div></div>
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo absint( $total_attendance ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'Attended', 'societypress' ); ?></div></div>
            <div class="sp-stat-card"><div class="sp-stat-value"><?php echo esc_html( number_format( $vol_hours, 0 ) ); ?></div><div class="sp-stat-label"><?php esc_html_e( 'Volunteer Hours', 'societypress' ); ?></div></div>
        </div>

        <!-- Membership Breakdown -->
        <div class="sp-report-section sp-annual-section">
            <h2 class="sp-annual-section-title"><?php esc_html_e( 'Membership', 'societypress' ); ?></h2>
            <table class="sp-annual-table">
                <thead><tr>
                    <th class="sp-annual-th-left"><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                    <th class="sp-annual-th-right"><?php esc_html_e( 'Count', 'societypress' ); ?></th>
                    <th class="sp-annual-th-chart"><?php esc_html_e( 'Chart', 'societypress' ); ?></th>
                </tr></thead>
                <tbody>
                    <?php
                    $max_status = max( array_column( $status_counts ?: [ (object) [ 'cnt' => 1 ] ], 'cnt' ) );
                    foreach ( $status_counts as $sc ) :
                        $pct = round( ( (int) $sc->cnt / max( 1, $max_status ) ) * 100 );
                    ?>
                        <tr>
                            <td class="sp-annual-td-status"><?php echo esc_html( ucfirst( $sc->status ) ); ?></td>
                            <td class="sp-annual-td-count"><?php echo (int) $sc->cnt; ?></td>
                            <td class="sp-annual-td-chart">
                                <div class="sp-bar-chart"><div class="sp-bar sp-annual-month-bar-row" style="width:<?php echo $pct; ?>%;"></div></div>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                </tbody>
            </table>
        </div>

        <!-- Events by Month -->
        <div class="sp-report-section sp-annual-section">
            <h2 class="sp-annual-section-title"><?php esc_html_e( 'Events by Month', 'societypress' ); ?></h2>
            <div class="sp-annual-events-chart">
                <?php
                $months = [ '', 'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec' ];
                for ( $m = 1; $m <= 12; $m++ ) :
                    $cnt = $monthly_map[ $m ] ?? 0;
                    $height = $max_monthly_events > 0 ? round( ( $cnt / $max_monthly_events ) * 160 ) : 0;
                ?>
                    <div class="sp-annual-month-col">
                        <div class="sp-annual-month-count"><?php echo $cnt; ?></div>
                        <div class="sp-bar" style="width:100%; height:<?php echo max( 4, $height ); ?>px;"></div>
                        <div class="sp-annual-month-label"><?php echo $months[ $m ]; ?></div>
                    </div>
                <?php endfor; ?>
            </div>
        </div>

        <!-- Volunteer Summary -->
        <div class="sp-report-section sp-annual-section">
            <h2 class="sp-annual-section-title"><?php esc_html_e( 'Volunteers', 'societypress' ); ?></h2>
            <p><strong><?php echo $vol_count; ?></strong> volunteers contributed <strong><?php echo number_format( $vol_hours, 1 ); ?></strong> hours in <?php echo $year; ?>.</p>

            <?php
            $top_volunteers = $wpdb->get_results( $wpdb->prepare(
                "SELECT m.first_name, m.last_name, SUM(vh.hours) as total_hours
                 FROM {$prefix}volunteer_hours vh
                 INNER JOIN {$prefix}members m ON vh.user_id = m.user_id
                 WHERE vh.activity_date BETWEEN %s AND %s
                 GROUP BY vh.user_id, m.first_name, m.last_name
                 ORDER BY total_hours DESC LIMIT 10", $start_date, $end_date
            ) );
            if ( ! empty( $top_volunteers ) ) :
                $max_vol_hrs = (float) $top_volunteers[0]->total_hours;
            ?>
                <h3><?php esc_html_e( 'Top Contributors', 'societypress' ); ?></h3>
                <table class="sp-annual-table">
                    <?php foreach ( $top_volunteers as $tv ) :
                        $pct = round( ( (float) $tv->total_hours / max( 1, $max_vol_hrs ) ) * 100 );
                    ?>
                        <tr>
                            <td class="sp-annual-vol-name"><?php echo esc_html( $tv->first_name . ' ' . $tv->last_name ); ?></td>
                            <td class="sp-annual-vol-hours"><?php echo number_format( (float) $tv->total_hours, 1 ); ?> <?php esc_html_e( 'hrs', 'societypress' ); ?></td>
                            <td class="sp-annual-vol-chart"><div class="sp-bar-chart"><div class="sp-bar" style="height:16px; width:<?php echo $pct; ?>%;"></div></div></td>
                        </tr>
                    <?php endforeach; ?>
                </table>
            <?php endif; ?>
        </div>
    </div>

    <script>
    // "Copy as Text" button — copies a plain text summary for pasting into emails
    document.getElementById('sp-copy-report-btn')?.addEventListener('click', function() {
        var text = '<?php echo esc_js( __( 'Annual Report', 'societypress' ) ); ?> — <?php echo esc_js( (string) $year ); ?>\n\n'
            + '<?php echo esc_js( __( 'MEMBERSHIP', 'societypress' ) ); ?>\n'
            + '  <?php echo esc_js( __( 'Active Members', 'societypress' ) ); ?>: <?php echo esc_js( (string) $active_members ); ?>\n'
            + '  <?php echo esc_js( __( 'New This Year', 'societypress' ) ); ?>: <?php echo esc_js( (string) $new_this_year ); ?>\n'
            + '  <?php echo esc_js( __( 'Expired/Lapsed', 'societypress' ) ); ?>: <?php echo esc_js( (string) $expired_this_year ); ?>\n'
            + '  <?php echo esc_js( __( 'Total', 'societypress' ) ); ?>: <?php echo esc_js( (string) $total_members ); ?>\n\n'
            + '<?php echo esc_js( __( 'EVENTS', 'societypress' ) ); ?>\n'
            + '  <?php echo esc_js( __( 'Events Held', 'societypress' ) ); ?>: <?php echo esc_js( (string) $events_count ); ?>\n'
            + '  <?php echo esc_js( __( 'Total Registrations', 'societypress' ) ); ?>: <?php echo esc_js( (string) $total_registrations ); ?>\n'
            + '  <?php echo esc_js( __( 'Actual Attendance', 'societypress' ) ); ?>: <?php echo esc_js( (string) $total_attendance ); ?>\n\n'
            + '<?php echo esc_js( __( 'VOLUNTEERS', 'societypress' ) ); ?>\n'
            + '  <?php echo esc_js( __( 'Active Volunteers', 'societypress' ) ); ?>: <?php echo esc_js( (string) $vol_count ); ?>\n'
            + '  <?php echo esc_js( __( 'Total Hours', 'societypress' ) ); ?>: <?php echo esc_js( number_format( $vol_hours, 1 ) ); ?>\n';

        navigator.clipboard.writeText(text).then(function() {
            var btn = document.getElementById('sp-copy-report-btn');
            btn.textContent = '<?php echo esc_js( __( 'Copied!', 'societypress' ) ); ?>';
            setTimeout(function() { btn.textContent = '<?php echo esc_js( __( 'Copy as Text', 'societypress' ) ); ?>'; }, 2000);
        });
    });
    </script>
    <?php
}


// ============================================================================
// MEMBERSHIP REPORTS — DEDICATED ANALYTICS DASHBOARD
// ============================================================================
//
// WHY: Every board meeting, someone asks "how many members do we have?" and
//      "how are renewals going?" Harold shouldn't have to count rows in a
//      spreadsheet. This page answers the questions boards actually ask:
//      totals by tier, renewal pipeline, retention rate, revenue, trends.

/**
 * AJAX handler: Export membership report as CSV.
 *
 * WHY: Harold needs to attach reports to board meeting minutes or share them
 *      with the treasurer. A one-click CSV download gives him a clean file
 *      he can open in Excel or attach to an email.
 */
add_action( 'wp_ajax_sp_export_membership_report', 'sp_ajax_export_membership_report' );
function sp_ajax_export_membership_report(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'You do not have permission to export reports.', 'societypress' ) );
    }

    // Verify nonce to prevent CSRF on the export endpoint
    if ( ! check_ajax_referer( 'sp_export_membership_report', '_wpnonce', false ) ) {
        wp_die( esc_html__( 'Security check failed. Please refresh the page.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $today  = current_time( 'Y-m-d' );

    // Period filter — same logic as the render function
    $period = sanitize_text_field( $_GET['period'] ?? 'this_year' );
    $valid  = [ '30days', '90days', 'this_year', 'last_year', 'all_time' ];
    if ( ! in_array( $period, $valid, true ) ) $period = 'this_year';

    switch ( $period ) {
        case '30days':    $period_start = wp_date( 'Y-m-d', strtotime( '-30 days' ) ); $period_end = $today; break;
        case '90days':    $period_start = wp_date( 'Y-m-d', strtotime( '-90 days' ) ); $period_end = $today; break;
        case 'last_year': $period_start = ( (int) wp_date( 'Y' ) - 1 ) . '-01-01'; $period_end = ( (int) wp_date( 'Y' ) - 1 ) . '-12-31'; break;
        case 'all_time':  $period_start = '2000-01-01'; $period_end = $today; break;
        default:          $period_start = wp_date( 'Y' ) . '-01-01'; $period_end = $today; break;
    }

    $filename = 'membership-report-' . $today . '.csv';
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename=' . $filename );
    $out = fopen( 'php://output', 'w' );

    // Section 1: Summary Stats
    fputcsv( $out, [ 'Membership Summary' ] );
    fputcsv( $out, [ 'Metric', 'Count' ] );
    fputcsv( $out, [ 'Total Members',    $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" ) ] );
    fputcsv( $out, [ 'Active',           $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'active'" ) ] );
    fputcsv( $out, [ 'Expired/Lapsed',   $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status IN ('expired','lapsed','grace')" ) ] );
    fputcsv( $out, [ 'Pending',          $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'pending'" ) ] );
    fputcsv( $out, [ 'Deceased',         $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE deceased = 1" ) ] );
    fputcsv( $out, [ 'Lifetime',         $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE lifetime = 1" ) ] );
    fputcsv( $out, [ 'New This Month',   $wpdb->get_var( $wpdb->prepare( "SELECT COUNT(*) FROM {$prefix}members WHERE join_date >= %s", wp_date( 'Y-m-01' ) ) ) ] );
    fputcsv( $out, [ 'New This Year',    $wpdb->get_var( $wpdb->prepare( "SELECT COUNT(*) FROM {$prefix}members WHERE join_date >= %s", wp_date( 'Y' ) . '-01-01' ) ) ] );
    fputcsv( $out, [] );

    // Section 2: By Tier
    fputcsv( $out, [ 'Membership by Tier' ] );
    fputcsv( $out, [ 'Tier', 'Active', 'Expired', 'Total', '% of Total' ] );
    $grand_total = max( 1, (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" ) );
    $tiers = $wpdb->get_results(
        "SELECT t.name AS tier_name,
                SUM(CASE WHEN m.status = 'active' THEN 1 ELSE 0 END) AS active_count,
                SUM(CASE WHEN m.status IN ('expired','lapsed','grace') THEN 1 ELSE 0 END) AS expired_count,
                COUNT(m.user_id) AS total_count
         FROM {$prefix}membership_tiers t
         LEFT JOIN {$prefix}members m ON m.tier_id = t.id
         GROUP BY t.id, t.name ORDER BY total_count DESC"
    );
    foreach ( $tiers as $t ) {
        fputcsv( $out, [ $t->tier_name, $t->active_count, $t->expired_count, $t->total_count, round( ( $t->total_count / $grand_total ) * 100, 1 ) . '%' ] );
    }
    $unassigned = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE tier_id IS NULL OR tier_id = 0" );
    if ( $unassigned > 0 ) {
        fputcsv( $out, [ 'Unassigned', '', '', $unassigned, round( ( $unassigned / $grand_total ) * 100, 1 ) . '%' ] );
    }
    fputcsv( $out, [] );

    // Section 3: Renewal Pipeline
    fputcsv( $out, [ 'Renewal Pipeline' ] );
    fputcsv( $out, [ 'Window', 'Count' ] );
    $pipe_base = "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'active' AND lifetime = 0 AND expiration_date IS NOT NULL AND expiration_date BETWEEN %s AND %s";
    $p30 = (int) $wpdb->get_var( $wpdb->prepare( $pipe_base, $today, wp_date( 'Y-m-d', strtotime( '+30 days' ) ) ) );
    $p60 = (int) $wpdb->get_var( $wpdb->prepare( $pipe_base, wp_date( 'Y-m-d', strtotime( '+31 days' ) ), wp_date( 'Y-m-d', strtotime( '+60 days' ) ) ) );
    $p90 = (int) $wpdb->get_var( $wpdb->prepare( $pipe_base, wp_date( 'Y-m-d', strtotime( '+61 days' ) ), wp_date( 'Y-m-d', strtotime( '+90 days' ) ) ) );
    fputcsv( $out, [ 'Within 30 days', $p30 ] );
    fputcsv( $out, [ '31-60 days', $p60 ] );
    fputcsv( $out, [ '61-90 days', $p90 ] );
    fputcsv( $out, [] );

    // Section 4: Members Added by Month
    fputcsv( $out, [ 'Members Added by Month (' . $period . ')' ] );
    fputcsv( $out, [ 'Month', 'Count' ] );
    $monthly = $wpdb->get_results( $wpdb->prepare(
        "SELECT DATE_FORMAT(join_date, '%%Y-%%m') AS month_key,
                DATE_FORMAT(join_date, '%%b %%Y') AS month_label,
                COUNT(*) AS cnt
         FROM {$prefix}members WHERE join_date BETWEEN %s AND %s
         GROUP BY month_key ORDER BY month_key ASC",
        $period_start, $period_end
    ) );
    foreach ( $monthly as $mo ) fputcsv( $out, [ $mo->month_label, $mo->cnt ] );
    fputcsv( $out, [] );

    // Section 5: Revenue by Tier
    fputcsv( $out, [ 'Revenue by Tier (' . $period . ')' ] );
    fputcsv( $out, [ 'Tier', 'Payments', 'Revenue' ] );
    $rev_tiers = $wpdb->get_results( $wpdb->prepare(
        "SELECT COALESCE(t.name, 'Unassigned') AS tier_name,
                COUNT(p.id) AS payment_count,
                COALESCE(SUM(p.amount), 0) AS tier_revenue
         FROM {$prefix}member_payments p
         INNER JOIN {$prefix}members m ON m.user_id = p.user_id
         LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
         WHERE p.date BETWEEN %s AND %s
         GROUP BY t.id, t.name ORDER BY tier_revenue DESC",
        $period_start, $period_end
    ) );
    foreach ( $rev_tiers as $rt ) fputcsv( $out, [ $rt->tier_name, $rt->payment_count, number_format( $rt->tier_revenue, 2 ) ] );
    fputcsv( $out, [] );

    // Section 6: Revenue by Month
    fputcsv( $out, [ 'Revenue by Month (' . $period . ')' ] );
    fputcsv( $out, [ 'Month', 'Revenue' ] );
    $rev_monthly = $wpdb->get_results( $wpdb->prepare(
        "SELECT DATE_FORMAT(p.date, '%%Y-%%m') AS month_key,
                DATE_FORMAT(p.date, '%%b %%Y') AS month_label,
                COALESCE(SUM(p.amount), 0) AS monthly_revenue
         FROM {$prefix}member_payments p
         WHERE p.date BETWEEN %s AND %s
         GROUP BY month_key ORDER BY month_key ASC",
        $period_start, $period_end
    ) );
    foreach ( $rev_monthly as $rm ) fputcsv( $out, [ $rm->month_label, number_format( $rm->monthly_revenue, 2 ) ] );

    fclose( $out );
    exit;
}


/**
 * Render: Membership Reports Page
 *
 * WHY: A dedicated analytics dashboard for membership data. The existing
 *      Reports page has high-level stats; the Annual Report is a yearly
 *      snapshot. This page gives Harold the real-time, filterable membership
 *      intelligence he needs for board meetings and planning.
 */
function sp_render_membership_reports_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $today  = current_time( 'Y-m-d' );

    // ---- Period filter ----
    $period = sanitize_text_field( $_GET['period'] ?? 'this_year' );
    $valid  = [ '30days', '90days', 'this_year', 'last_year', 'all_time' ];
    if ( ! in_array( $period, $valid, true ) ) $period = 'this_year';

    switch ( $period ) {
        case '30days':    $period_start = wp_date( 'Y-m-d', strtotime( '-30 days' ) ); $period_end = $today; break;
        case '90days':    $period_start = wp_date( 'Y-m-d', strtotime( '-90 days' ) ); $period_end = $today; break;
        case 'last_year': $period_start = ( (int) wp_date( 'Y' ) - 1 ) . '-01-01'; $period_end = ( (int) wp_date( 'Y' ) - 1 ) . '-12-31'; break;
        case 'all_time':  $period_start = '2000-01-01'; $period_end = $today; break;
        default:          $period_start = wp_date( 'Y' ) . '-01-01'; $period_end = $today; break;
    }

    // ---- Stat card queries (always live, not date-filtered) ----
    $total_members  = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members" );
    $active_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'active'" );
    $expired_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status IN ('expired','lapsed','grace')" );
    $pending_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'pending'" );
    $deceased_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE deceased = 1" );
    $lifetime_members = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}members WHERE lifetime = 1" );
    $new_this_month  = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}members WHERE join_date >= %s", wp_date( 'Y-m-01' )
    ) );
    $new_this_year   = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}members WHERE join_date >= %s", wp_date( 'Y' ) . '-01-01'
    ) );

    // ---- Tier breakdown (always live) ----
    $grand_total = max( 1, $total_members );
    $tier_rows = $wpdb->get_results(
        "SELECT t.id, t.name AS tier_name,
                SUM(CASE WHEN m.status = 'active' THEN 1 ELSE 0 END) AS active_count,
                SUM(CASE WHEN m.status IN ('expired','lapsed','grace') THEN 1 ELSE 0 END) AS expired_count,
                COUNT(m.user_id) AS total_count
         FROM {$prefix}membership_tiers t
         LEFT JOIN {$prefix}members m ON m.tier_id = t.id
         GROUP BY t.id, t.name ORDER BY total_count DESC"
    );
    $unassigned_count = (int) $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}members WHERE tier_id IS NULL OR tier_id = 0"
    );

    // ---- Renewal pipeline (always live, relative to today) ----
    $pipe_sql = "SELECT COUNT(*) FROM {$prefix}members WHERE status = 'active' AND lifetime = 0 AND expiration_date IS NOT NULL AND expiration_date BETWEEN %s AND %s";
    $pipe_30 = (int) $wpdb->get_var( $wpdb->prepare( $pipe_sql, $today, wp_date( 'Y-m-d', strtotime( '+30 days' ) ) ) );
    $pipe_60 = (int) $wpdb->get_var( $wpdb->prepare( $pipe_sql, wp_date( 'Y-m-d', strtotime( '+31 days' ) ), wp_date( 'Y-m-d', strtotime( '+60 days' ) ) ) );
    $pipe_90 = (int) $wpdb->get_var( $wpdb->prepare( $pipe_sql, wp_date( 'Y-m-d', strtotime( '+61 days' ) ), wp_date( 'Y-m-d', strtotime( '+90 days' ) ) ) );

    // Pipeline detail lists (for expandable sections)
    $pipe_detail_sql = "SELECT m.first_name, m.last_name, m.organization_name, m.member_type,
                               m.expiration_date, t.name AS tier_name
                        FROM {$prefix}members m
                        LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
                        WHERE m.status = 'active' AND m.lifetime = 0
                          AND m.expiration_date IS NOT NULL
                          AND m.expiration_date BETWEEN %s AND %s
                        ORDER BY m.expiration_date ASC";
    $pipe_30_list = $wpdb->get_results( $wpdb->prepare( $pipe_detail_sql, $today, wp_date( 'Y-m-d', strtotime( '+30 days' ) ) ) );
    $pipe_60_list = $wpdb->get_results( $wpdb->prepare( $pipe_detail_sql, wp_date( 'Y-m-d', strtotime( '+31 days' ) ), wp_date( 'Y-m-d', strtotime( '+60 days' ) ) ) );
    $pipe_90_list = $wpdb->get_results( $wpdb->prepare( $pipe_detail_sql, wp_date( 'Y-m-d', strtotime( '+61 days' ) ), wp_date( 'Y-m-d', strtotime( '+90 days' ) ) ) );

    // ---- Members added by month (date-filtered) ----
    $monthly_added = $wpdb->get_results( $wpdb->prepare(
        "SELECT DATE_FORMAT(join_date, '%%Y-%%m') AS month_key,
                DATE_FORMAT(join_date, '%%b %%Y') AS month_label,
                COUNT(*) AS cnt
         FROM {$prefix}members WHERE join_date BETWEEN %s AND %s
         GROUP BY month_key ORDER BY month_key ASC",
        $period_start, $period_end
    ) );
    $max_monthly_added = max( 1, max( array_column( $monthly_added ?: [ (object) [ 'cnt' => 1 ] ], 'cnt' ) ) );

    // ---- Retention rate (date-filtered) ----
    $renewed = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}members
         WHERE expiration_date BETWEEN %s AND %s AND status = 'active'",
        $period_start, $period_end
    ) );
    $lapsed = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM {$prefix}members
         WHERE expiration_date BETWEEN %s AND %s AND status IN ('expired','lapsed','grace')",
        $period_start, $period_end
    ) );
    $retention_total = max( 1, $renewed + $lapsed );
    $retention_pct   = round( ( $renewed / $retention_total ) * 100, 1 );

    // ---- Revenue (date-filtered) ----
    $total_revenue = (float) $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(amount), 0) FROM {$prefix}member_payments WHERE date BETWEEN %s AND %s",
        $period_start, $period_end
    ) );
    $rev_by_tier = $wpdb->get_results( $wpdb->prepare(
        "SELECT COALESCE(t.name, 'Unassigned') AS tier_name,
                COUNT(p.id) AS payment_count,
                COALESCE(SUM(p.amount), 0) AS tier_revenue
         FROM {$prefix}member_payments p
         INNER JOIN {$prefix}members m ON m.user_id = p.user_id
         LEFT JOIN {$prefix}membership_tiers t ON t.id = m.tier_id
         WHERE p.date BETWEEN %s AND %s
         GROUP BY t.id, t.name ORDER BY tier_revenue DESC",
        $period_start, $period_end
    ) );
    $rev_by_month = $wpdb->get_results( $wpdb->prepare(
        "SELECT DATE_FORMAT(p.date, '%%Y-%%m') AS month_key,
                DATE_FORMAT(p.date, '%%b %%Y') AS month_label,
                COALESCE(SUM(p.amount), 0) AS monthly_revenue
         FROM {$prefix}member_payments p
         WHERE p.date BETWEEN %s AND %s
         GROUP BY month_key ORDER BY month_key ASC",
        $period_start, $period_end
    ) );
    $max_monthly_rev = max( 1, max( array_column( $rev_by_month ?: [ (object) [ 'monthly_revenue' => 1 ] ], 'monthly_revenue' ) ) );

    // ---- Export URL ----
    $export_url = wp_nonce_url( add_query_arg( [
        'action' => 'sp_export_membership_report',
        'period' => $period,
    ], admin_url( 'admin-ajax.php' ) ), 'sp_export_membership_report' );

    // ---- Period labels for display ----
    $period_labels = [
        '30days'    => __( 'Last 30 Days', 'societypress' ),
        '90days'    => __( 'Last 90 Days', 'societypress' ),
        'this_year' => __( 'This Year', 'societypress' ),
        'last_year' => __( 'Last Year', 'societypress' ),
        'all_time'  => __( 'All Time', 'societypress' ),
    ];

    ?>
    <style>
        /* Membership Reports — all CSS classes for the sp-membership-reports page.
           WHY: No inline styles. Single-point edits. Override-friendly. */

        /* Header row: title + filter + actions */
        .sp-mr-header {
            display: flex;
            align-items: center;
            gap: 16px;
            flex-wrap: wrap;
            margin-bottom: 20px;
        }
        .sp-mr-header h1 { margin: 0; }
        .sp-mr-filter-form {
            display: flex;
