            </button>
        </div>

        <!-- Stat Cards -->
        <div class="sp-mr-stat-grid">
            <div class="sp-mr-stat-card">
                <div class="sp-mr-stat-number"><?php echo absint( $total_members ); ?></div>
                <div class="sp-mr-stat-label"><?php esc_html_e( 'Total Members', 'societypress' ); ?></div>
            </div>
