// RESEARCH HELP REQUESTS — ADMIN & FRONTEND
// ============================================================================
//
// WHY: Feature 10 — lightweight Q&A where members submit genealogy research
//      questions and other members can reply. Admin has moderation controls.
//      Deliberately simple: no threading, no voting, no complexity.

/**
 * Render: Help Requests Admin Page
 *
 * WHY: Moderation interface for admins to view, close/reopen, and delete
 *      research help requests submitted by members.
 */
function sp_render_help_requests_admin_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle actions — delete is POST-only to prevent browser prefetch accidents
    $action = $_GET['action'] ?? '';
    $req_id = absint( $_GET['request_id'] ?? 0 );

    // Delete uses POST
    $post_action = $_POST['action'] ?? '';
    $post_req_id = absint( $_POST['request_id'] ?? 0 );
    if ( $post_action === 'delete' && $post_req_id ) {
        check_admin_referer( 'sp_delete_help_request_' . $post_req_id );
        $wpdb->delete( $prefix . 'help_responses', [ 'request_id' => $post_req_id ] );
        $wpdb->delete( $prefix . 'help_requests', [ 'id' => $post_req_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Request deleted.', 'societypress' ) . '</p></div>';
    }
    if ( $action === 'close' && $req_id ) {
        check_admin_referer( 'sp_close_help_request_' . $req_id );
        $wpdb->update( $prefix . 'help_requests', [ 'status' => 'closed' ], [ 'id' => $req_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Request closed.', 'societypress' ) . '</p></div>';
    }
    if ( $action === 'reopen' && $req_id ) {
        check_admin_referer( 'sp_reopen_help_request_' . $req_id );
        $wpdb->update( $prefix . 'help_requests', [ 'status' => 'open' ], [ 'id' => $req_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Request reopened.', 'societypress' ) . '</p></div>';
    }

    // View single request with responses
    if ( $action === 'view' && $req_id ) {
        $request = $wpdb->get_row( $wpdb->prepare(
            "SELECT hr.*, m.first_name, m.last_name
             FROM {$prefix}help_requests hr
             INNER JOIN {$prefix}members m ON hr.user_id = m.user_id
             WHERE hr.id = %d", $req_id
        ) );
        if ( ! $request ) {
            echo '<div class="wrap"><p>Request not found.</p></div>';
            return;
        }

        $responses = $wpdb->get_results( $wpdb->prepare(
            "SELECT hresp.*, m.first_name, m.last_name
             FROM {$prefix}help_responses hresp
             INNER JOIN {$prefix}members m ON hresp.user_id = m.user_id
             WHERE hresp.request_id = %d
             ORDER BY hresp.created_at ASC", $req_id
        ) );

        $close_url  = wp_nonce_url( admin_url( 'admin.php?page=sp-help-requests&action=close&request_id=' . $req_id ), 'sp_close_help_request_' . $req_id );
        $reopen_url = wp_nonce_url( admin_url( 'admin.php?page=sp-help-requests&action=reopen&request_id=' . $req_id ), 'sp_reopen_help_request_' . $req_id );
        // Delete uses POST form below
        ?>
        <div class="wrap">
            <h1><?php echo esc_html( $request->title ); ?></h1>
            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-help-requests' ) ); ?>">&larr; Back to Requests</a>

            <div class="sp-card">
                <p style="color:#666; font-size:13px; margin:0 0 12px;">
                    Asked by <?php echo esc_html( $request->first_name . ' ' . $request->last_name ); ?>
                    on <?php echo esc_html( wp_date( 'M j, Y g:i A', strtotime( $request->created_at ) ) ); ?>
                    — Status: <strong><?php echo esc_html( ucfirst( $request->status ) ); ?></strong>
                </p>
                <div style="font-size:15px; line-height:1.6;"><?php echo wpautop( esc_html( $request->description ) ); ?></div>
                <div style="margin-top:16px;">
                    <?php if ( $request->status === 'open' ) : ?>
                        <a href="<?php echo esc_url( $close_url ); ?>" class="button"><?php esc_html_e( 'Close Request', 'societypress' ); ?></a>
                    <?php else : ?>
                        <a href="<?php echo esc_url( $reopen_url ); ?>" class="button"><?php esc_html_e( 'Reopen Request', 'societypress' ); ?></a>
                    <?php endif; ?>
                    <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-help-requests' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this request and all responses?', 'societypress' ) ); ?>">
                        <?php wp_nonce_field( 'sp_delete_help_request_' . $req_id ); ?>
                        <input type="hidden" name="action" value="delete">
                        <input type="hidden" name="request_id" value="<?php echo (int) $req_id; ?>">
                        <button type="submit" class="button" style="color:#b32d2e; border-color:#b32d2e; cursor:pointer;"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                    </form>
                </div>
            </div>

            <h3><?php echo sprintf( _n( '%d Response', '%d Responses', count( $responses ), 'societypress' ), count( $responses ) ); ?></h3>
            <?php foreach ( $responses as $resp ) : ?>
                <div style="background:#f9f9f9; border:1px solid #e0e0e0; border-radius:4px; padding:16px; margin-bottom:12px;">
                    <p style="color:#666; font-size:13px; margin:0 0 8px;">
                        <strong><?php echo esc_html( $resp->first_name . ' ' . $resp->last_name ); ?></strong>
                        — <?php echo esc_html( wp_date( 'M j, Y g:i A', strtotime( $resp->created_at ) ) ); ?>
                    </p>
                    <div style="font-size:14px; line-height:1.5;"><?php echo wpautop( esc_html( $resp->content ) ); ?></div>
                </div>
            <?php endforeach; ?>
        </div>
        <?php
        return;
    }

    // List all requests
    $status_filter = sanitize_text_field( $_GET['status'] ?? '' );
    $where = '1=1';
    if ( $status_filter ) {
        $where = $wpdb->prepare( 'hr.status = %s', $status_filter );
    }

    $requests = $wpdb->get_results(
        "SELECT hr.*, m.first_name, m.last_name
         FROM {$prefix}help_requests hr
         INNER JOIN {$prefix}members m ON hr.user_id = m.user_id
         WHERE {$where}
         ORDER BY hr.created_at DESC
         LIMIT 100"
    );
    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Research Help Requests', 'societypress' ); ?></h1>

        <ul class="subsubsub" style="margin-bottom:16px;">
            <li><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-help-requests' ) ); ?>" <?php if ( ! $status_filter ) echo 'class="current"'; ?>><?php esc_html_e( 'All', 'societypress' ); ?></a> |</li>
            <li><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-help-requests&status=open' ) ); ?>" <?php if ( $status_filter === 'open' ) echo 'class="current"'; ?>><?php esc_html_e( 'Open', 'societypress' ); ?></a> |</li>
            <li><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-help-requests&status=closed' ) ); ?>" <?php if ( $status_filter === 'closed' ) echo 'class="current"'; ?>><?php esc_html_e( 'Closed', 'societypress' ); ?></a></li>
        </ul>

        <table class="wp-list-table widefat striped">
            <thead><tr><th><?php esc_html_e( 'Title', 'societypress' ); ?></th><th><?php esc_html_e( 'Asked By', 'societypress' ); ?></th><th><?php esc_html_e( 'Responses', 'societypress' ); ?></th><th><?php esc_html_e( 'Status', 'societypress' ); ?></th><th><?php esc_html_e( 'Date', 'societypress' ); ?></th></tr></thead>
            <tbody>
                <?php if ( empty( $requests ) ) : ?>
                    <tr><td colspan="5"><?php esc_html_e( 'No requests found.', 'societypress' ); ?></td></tr>
                <?php else : ?>
                    <?php foreach ( $requests as $req ) :
                        $view_url   = admin_url( 'admin.php?page=sp-help-requests&action=view&request_id=' . $req->id );
                        // delete_url removed — using POST form in row actions
                    ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo esc_url( $view_url ); ?>"><?php echo esc_html( $req->title ); ?></a></strong>
                                <div class="row-actions">
                                    <span><a href="<?php echo esc_url( $view_url ); ?>"><?php esc_html_e( 'View', 'societypress' ); ?></a> | </span>
                                    <span><form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-help-requests' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete?', 'societypress' ) ); ?>"><?php wp_nonce_field( 'sp_delete_help_request_' . $req->id ); ?><input type="hidden" name="action" value="delete"><input type="hidden" name="request_id" value="<?php echo (int) $req->id; ?>"><button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button></form></span>
                                </div>
                            </td>
                            <td><?php echo esc_html( $req->first_name . ' ' . $req->last_name ); ?></td>
                            <td><?php echo (int) $req->responses_count; ?></td>
                            <td>
                                <?php $sc = $req->status === 'open' ? '#0a6b2e' : '#666'; ?>
                                <span style="color:<?php echo $sc; ?>; font-weight:600;"><?php echo esc_html( ucfirst( $req->status ) ); ?></span>
                            </td>
                            <td><?php echo esc_html( wp_date( 'M j, Y', strtotime( $req->created_at ) ) ); ?></td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>
    </div>
    <?php
}

/**
 * Frontend Page Template: Research Help Requests
 *
 * WHY: Members interact with help requests on the frontend via a page that
 *      uses the sp-help-requests template. Three sub-views: list, submit, detail.
 *      Registered via theme_page_templates and rendered via template_include.
 */
add_filter( 'theme_page_templates', function( $templates ) {
    $templates['sp-help-requests']   = 'Research Help Requests';
    $templates['sp-resources']       = 'Resource Links Directory';
    $templates['sp-library-catalog'] = 'Library Catalog';
    $templates['sp-records']         = 'Genealogical Records Search';
    $templates['sp-store']           = 'Store';
    $templates['sp-cart']            = 'Shopping Cart';
    $templates['sp-documents']       = 'Documents';
    return $templates;
} );

add_filter( 'template_include', function( $template ) {
    if ( ! is_page() ) return $template;

    $page_template = get_page_template_slug();
    if ( ! in_array( $page_template, [ 'sp-help-requests', 'sp-resources', 'sp-library-catalog', 'sp-records', 'sp-store', 'sp-cart', 'sp-documents' ], true ) ) {
        return $template;
    }

    // Most templates require login. Records, Store, and Documents handle their
    // own access (records: per-collection, store: public storefront, documents:
    // per-document access_level). Cart requires login to purchase.
    if ( ! in_array( $page_template, [ 'sp-records', 'sp-store', 'sp-cart', 'sp-documents' ], true ) && ! is_user_logged_in() ) {
        wp_safe_redirect( wp_login_url( get_permalink() ) );
        exit;
    }

    // Output the header, run the appropriate template function, output footer
    get_header();
    echo '<div class="entry-content" style="max-width:960px; margin:40px auto; padding:0 20px;">';

    switch ( $page_template ) {
        case 'sp-help-requests':
            sp_frontend_help_requests();
            break;
        case 'sp-resources':
            sp_frontend_resources_directory();
            break;
        case 'sp-library-catalog':
            // WHY: Previously called the basic 85-line sp_frontend_library_catalog(),
            // which was a simple table with minimal search. Now unified to use the
            // full OPAC-style builder widget version (sp_render_builder_widget_library_catalog)
            // which supports faceted search, browse-by sections, expandable detail
            // rows, sort options, and media type filtering. Empty array = use defaults.
            sp_render_builder_widget_library_catalog( [] );
            break;
        case 'sp-records':
            sp_render_records_frontend();
            break;
        case 'sp-store':
            sp_render_store_frontend();
            break;
        case 'sp-cart':
            sp_render_cart_page();
            break;
        case 'sp-documents':
            sp_frontend_documents();
            break;
    }

    echo '</div>';
    get_footer();
    return ''; // Return empty to prevent WordPress from loading another template
}, 99 );

/**
 * Frontend: Help Requests sub-views
 */
function sp_frontend_help_requests(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $view   = sanitize_text_field( $_GET['sp_help'] ?? 'list' );
    $current_user_id = get_current_user_id();

    // Handle new response submission
    if ( isset( $_POST['sp_submit_response'] ) && check_admin_referer( 'sp_help_response' ) ) {
        $request_id = absint( $_POST['request_id'] ?? 0 );
        $content    = sanitize_textarea_field( $_POST['response_content'] ?? '' );

        if ( $request_id && $content ) {
            $wpdb->insert( $prefix . 'help_responses', [
                'request_id' => $request_id,
                'user_id'    => $current_user_id,
                'content'    => $content,
            ] );
            // Update response count
            $wpdb->query( $wpdb->prepare(
                "UPDATE {$prefix}help_requests SET responses_count = responses_count + 1 WHERE id = %d",
                $request_id
            ) );

            // Notify the question author
            $request = $wpdb->get_row( $wpdb->prepare(
                "SELECT hr.*, mc.email, m.first_name
                 FROM {$prefix}help_requests hr
                 INNER JOIN {$prefix}members m ON hr.user_id = m.user_id
                 INNER JOIN {$prefix}member_contact mc ON hr.user_id = mc.user_id
                 WHERE hr.id = %d", $request_id
            ) );
            if ( $request && $request->email && $request->user_id !== $current_user_id ) {
                $responder = $wpdb->get_row( $wpdb->prepare(
                    "SELECT first_name, last_name FROM {$prefix}members WHERE user_id = %d", $current_user_id
                ) );
                $resp_name = $responder ? $responder->first_name . ' ' . $responder->last_name : 'A member';

                // WHY: Email body uses inline styles intentionally — email clients
                //      do not load external stylesheets, so inline is the only reliable
                //      way to style HTML email across Gmail, Outlook, Apple Mail, etc.
                $body = '<p>Dear ' . esc_html( $request->first_name ) . ',</p>'
                      . '<p>' . esc_html( $resp_name ) . ' replied to your question: <strong>' . esc_html( $request->title ) . '</strong></p>'
                      . '<div style="background:#f6f7f7; border:1px solid #e0e0e0; border-radius:6px; padding:16px; margin:16px 0;">'
                      . '<p class="sp-m-0" class="sp-pre-wrap">' . esc_html( $content ) . '</p></div>'
                      . '<p><a href="' . esc_url( get_permalink() . '?sp_help=view&id=' . $request_id ) . '" style="display:inline-block; padding:10px 20px; background:#2271b1; color:#fff; text-decoration:none; border-radius:6px;">View Full Discussion</a></p>';

                wp_mail(
                    $request->email,
                    sprintf( '[%s] New response to your question', get_bloginfo( 'name' ) ),
                    sp_build_email_html( 'New Response', $body ),
                    [ 'Content-Type: text/html; charset=UTF-8' ]
                );
            }

            echo '<div class="sp-help-notice sp-help-notice--success">Your response has been posted.</div>';
        }
    }

    // Handle new question submission
    if ( isset( $_POST['sp_submit_question'] ) && check_admin_referer( 'sp_help_question' ) ) {
        $title = sanitize_text_field( $_POST['question_title'] ?? '' );
        $desc  = sanitize_textarea_field( $_POST['question_description'] ?? '' );

        if ( $title && $desc ) {
            $wpdb->insert( $prefix . 'help_requests', [
                'user_id'     => $current_user_id,
                'title'       => $title,
                'description' => $desc,
                'status'      => 'open',
            ] );
            $new_id = $wpdb->insert_id;

            // Notify site administrators when a new help request is posted
            // WHY: Previously this emailed ALL active members with no opt-out,
            //      which was noisy and borderline spam for large societies. Now
            //      it notifies only administrators (manage_options capability)
            //      who are the ones most likely to triage and route the question.
            $settings = get_option( 'societypress_settings', [] );
            if ( ! empty( $settings['help_requests_notify_all'] ) ) {
                $admin_users = get_users( [ 'capability' => 'manage_options' ] );
                $asker = $wpdb->get_row( $wpdb->prepare(
                    "SELECT first_name, last_name FROM {$prefix}members WHERE user_id = %d", $current_user_id
                ) );
                $asker_name = $asker ? $asker->first_name . ' ' . $asker->last_name : 'A member';

                foreach ( $admin_users as $admin ) {
                    if ( (int) $admin->ID === $current_user_id ) continue;
                    if ( ! is_email( $admin->user_email ) ) continue;
                    $admin_first = $admin->first_name ?: $admin->display_name;
                    // WHY: Email body uses inline styles intentionally — see note above.
                    $body = '<p>Dear ' . esc_html( $admin_first ) . ',</p>'
                          . '<p>' . esc_html( $asker_name ) . ' posted a research question:</p>'
                          . '<h3 style="margin:16px 0 8px;">' . esc_html( $title ) . '</h3>'
                          . '<p style="color:#555;">' . esc_html( wp_trim_words( $desc, 50 ) ) . '</p>'
                          . '<p><a href="' . esc_url( get_permalink() . '?sp_help=view&id=' . $new_id ) . '" style="display:inline-block; padding:10px 20px; background:#2271b1; color:#fff; text-decoration:none; border-radius:6px;">View &amp; Respond</a></p>';
                    wp_mail(
                        $admin->user_email,
                        sprintf( '[%s] New research question: %s', get_bloginfo( 'name' ), $title ),
                        sp_build_email_html( 'New Research Question', $body ),
                        [ 'Content-Type: text/html; charset=UTF-8' ]
                    );
                }
            }

            echo '<div class="sp-help-notice sp-help-notice--success">Your question has been posted!</div>';
            $view = 'list'; // Show list after submission
        }
    }

    // Sub-view routing
    if ( $view === 'submit' ) {
        // Submit question form
        echo '<h2>' . esc_html__( 'Ask a Research Question', 'societypress' ) . '</h2>';
        echo '<p class="sp-help-intro-text">' . esc_html__( 'Describe your genealogy research challenge. Other members may be able to help!', 'societypress' ) . '</p>';
        ?>
        <style>
            /*
             * WHY: These styles are scoped to the Help Requests feature and kept
             * here rather than in style.css so the feature remains self-contained.
             * Every rule uses the sp-help- prefix to avoid collisions with other
             * SocietyPress components or the active child theme.
             *
             * KEPT INLINE (not extracted):
             *   - All styles inside $body strings for wp_mail() — email clients
             *     require inline styles; external stylesheets are ignored.
             *   - The status color span in the single-question view — the color
             *     is determined at runtime by a PHP conditional (open vs. closed).
             */

            /* === Notices === */
            .sp-help-notice {
                padding: 12px 16px;
                border-radius: 6px;
                margin-bottom: 16px;
            }
            .sp-help-notice--success {
                background: #edfaef;
                color: #0a6b2e;
            }

            /* === Submit form === */
            .sp-help-intro-text {
                color: #555;
            }
            .sp-help-form {
                max-width: 600px;
            }
            .sp-help-form-group {
                margin-bottom: 16px;
            }
            .sp-help-form-label {
                display: block;
                font-weight: 600;
                margin-bottom: 4px;
            }
            .sp-help-form-input {
                width: 100%;
                padding: 10px;
                border: 1px solid #ccc;
                border-radius: 6px;
                font-size: 16px;
            }
            .sp-help-form-textarea {
                width: 100%;
                padding: 10px;
                border: 1px solid #ccc;
                border-radius: 6px;
                font-size: 16px;
                font-family: inherit;
            }
            .sp-help-cancel-btn {
                margin-left: 8px;
            }

            /* === Single question view === */
            .sp-help-question-meta {
                color: #666;
                font-size: 13px;
            }
            .sp-help-question-body {
                font-size: 15px;
                line-height: 1.7;
                margin-bottom: 32px;
            }

            /* === Response cards === */
            .sp-help-response-card {
                background: #f9f9f9;
                border: 1px solid #eee;
                border-radius: 8px;
                padding: 16px;
                margin-bottom: 12px;
            }
            .sp-help-response-byline {
                margin: 0 0 8px;
                font-size: 13px;
                color: #666;
            }
            .sp-help-response-body {
                font-size: 14px;
                line-height: 1.6;
            }

            /* === Reply form === */
            .sp-help-reply-section {
                margin-top: 24px;
                padding-top: 24px;
                border-top: 2px solid #eee;
            }
            .sp-help-reply-textarea {
                width: 100%;
                padding: 10px;
                border: 1px solid #ccc;
                border-radius: 6px;
                font-size: 15px;
                font-family: inherit;
                margin-bottom: 12px;
            }
            .sp-help-closed-notice {
                color: #666;
                font-style: italic;
            }

            /* === List view === */
            .sp-help-list-header {
                display: flex;
                justify-content: space-between;
                align-items: center;
                margin-bottom: 20px;
            }
            .sp-help-list-header h2 {
                margin: 0;
            }
            .sp-help-empty-notice {
                color: #666;
                font-style: italic;
            }
            .sp-help-question-card {
                background: #fff;
                border: 1px solid #eee;
                border-radius: 8px;
                padding: 20px;
                margin-bottom: 12px;
            }
            .sp-help-question-card h3 {
                margin: 0 0 6px;
            }
            .sp-help-question-card h3 a {
                color: #1d2327;
                text-decoration: none;
            }
            .sp-help-question-card-meta {
                margin: 0;
                color: #666;
                font-size: 13px;
            }
            .sp-help-question-card-excerpt {
                margin: 8px 0 0;
                color: #555;
                font-size: 14px;
            }
        </style>
        <form method="post" class="sp-help-form">
            <?php wp_nonce_field( 'sp_help_question' ); ?>
            <div class="sp-help-form-group">
                <label class="sp-help-form-label"><?php esc_html_e( 'Question Title', 'societypress' ); ?></label>
                <input type="text" name="question_title" required class="sp-help-form-input" placeholder="e.g., Looking for Smith family records in Sample County">
            </div>
            <div class="sp-help-form-group">
                <label class="sp-help-form-label"><?php esc_html_e( 'Details', 'societypress' ); ?></label>
                <textarea name="question_description" rows="6" required class="sp-help-form-textarea" placeholder="Provide details about what you're looking for, what you've already tried, and any specific time periods or locations..."></textarea>
            </div>
            <button type="submit" name="sp_submit_question" class="sp-btn sp-btn-primary"><?php esc_html_e( 'Submit Question', 'societypress' ); ?></button>
            <a href="<?php echo esc_url( get_permalink() ); ?>" class="sp-btn sp-btn-secondary sp-help-cancel-btn"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
        </form>
        <?php

    } elseif ( $view === 'view' && ! empty( $_GET['id'] ) ) {
        // View single request with responses
        $req_id  = absint( $_GET['id'] );
        $request = $wpdb->get_row( $wpdb->prepare(
            "SELECT hr.*, m.first_name, m.last_name
             FROM {$prefix}help_requests hr
             INNER JOIN {$prefix}members m ON hr.user_id = m.user_id
             WHERE hr.id = %d", $req_id
        ) );

        if ( ! $request ) {
            echo '<p>' . esc_html__( 'Question not found.', 'societypress' ) . '</p>';
            return;
        }

        $responses = $wpdb->get_results( $wpdb->prepare(
            "SELECT hresp.*, m.first_name, m.last_name
             FROM {$prefix}help_responses hresp
             INNER JOIN {$prefix}members m ON hresp.user_id = m.user_id
             WHERE hresp.request_id = %d
             ORDER BY hresp.created_at ASC", $req_id
        ) );

        echo '<p><a href="' . esc_url( get_permalink() ) . '">&larr; ' . esc_html__( 'Back to Questions', 'societypress' ) . '</a></p>';
        echo '<h2>' . esc_html( $request->title ) . '</h2>';
        // WHY: The status color span keeps its inline style because the color value
        //      is determined at runtime by PHP — 'open' maps to green, anything else
        //      to grey. A static CSS class cannot express this conditional.
        $help_status_labels = [
            'open'   => __( 'Open', 'societypress' ),
            'closed' => __( 'Closed', 'societypress' ),
        ];
        echo '<p class="sp-help-question-meta">'
           . sprintf(
                /* translators: %1$s = author name, %2$s = date */
                esc_html__( 'Asked by %1$s on %2$s', 'societypress' ),
                esc_html( $request->first_name . ' ' . $request->last_name ),
                esc_html( wp_date( 'F j, Y', strtotime( $request->created_at ) ) )
             )
           . ' — <span style="color:' . ( $request->status === 'open' ? '#0a6b2e' : '#666' ) . ';">' . esc_html( $help_status_labels[ $request->status ] ?? ucfirst( $request->status ) ) . '</span></p>';
        echo '<div class="sp-help-question-body">' . wpautop( esc_html( $request->description ) ) . '</div>';

        // Responses
        echo '<h3>' . sprintf( _n( '%d Response', '%d Responses', count( $responses ), 'societypress' ), count( $responses ) ) . '</h3>';
        foreach ( $responses as $resp ) {
            echo '<div class="sp-help-response-card">';
            echo '<p class="sp-help-response-byline">'
               . '<strong>' . esc_html( $resp->first_name . ' ' . $resp->last_name ) . '</strong>'
               . ' — ' . esc_html( wp_date( 'M j, Y g:i A', strtotime( $resp->created_at ) ) ) . '</p>';
            echo '<div class="sp-help-response-body">' . wpautop( esc_html( $resp->content ) ) . '</div>';
            echo '</div>';
        }

        // Reply form (only if open)
        if ( $request->status === 'open' ) {
            ?>
            <div class="sp-help-reply-section">
                <h4><?php esc_html_e( 'Add a Response', 'societypress' ); ?></h4>
                <form method="post">
                    <?php wp_nonce_field( 'sp_help_response' ); ?>
                    <input type="hidden" name="request_id" value="<?php echo $req_id; ?>">
                    <textarea name="response_content" rows="4" required class="sp-help-reply-textarea" placeholder="<?php echo esc_attr__( 'Share what you know...', 'societypress' ); ?>"></textarea>
                    <button type="submit" name="sp_submit_response" class="sp-btn sp-btn-primary"><?php esc_html_e( 'Post Response', 'societypress' ); ?></button>
                </form>
            </div>
            <?php
        } else {
            echo '<p class="sp-help-closed-notice">' . esc_html__( 'This question has been closed and is no longer accepting responses.', 'societypress' ) . '</p>';
        }

    } else {
        // List view
        echo '<div class="sp-help-list-header">';
        echo '<h2>' . esc_html__( 'Research Help', 'societypress' ) . '</h2>';
        echo '<a href="' . esc_url( add_query_arg( 'sp_help', 'submit' ) ) . '" class="sp-btn sp-btn-primary">Ask a Question</a>';
        echo '</div>';

        $requests = $wpdb->get_results(
            "SELECT hr.*, m.first_name, m.last_name
             FROM {$prefix}help_requests hr
             INNER JOIN {$prefix}members m ON hr.user_id = m.user_id
             WHERE hr.status = 'open'
             ORDER BY hr.created_at DESC
             LIMIT 50"
        );

        if ( empty( $requests ) ) {
            echo '<p class="sp-help-empty-notice">' . esc_html__( 'No questions yet. Be the first to ask!', 'societypress' ) . '</p>';
        } else {
            foreach ( $requests as $req ) {
                $view_url = add_query_arg( [ 'sp_help' => 'view', 'id' => $req->id ] );
                echo '<div class="sp-help-question-card">';
                echo '<h3><a href="' . esc_url( $view_url ) . '">' . esc_html( $req->title ) . '</a></h3>';
                echo '<p class="sp-help-question-card-meta">'
                   . esc_html( $req->first_name . ' ' . $req->last_name )
                   . ' &middot; ' . esc_html( wp_date( 'M j, Y', strtotime( $req->created_at ) ) )
                   . ' &middot; ' . sprintf( _n( '%d response', '%d responses', (int) $req->responses_count, 'societypress' ), (int) $req->responses_count )
                   . '</p>';
                if ( $req->description ) {
                    echo '<p class="sp-help-question-card-excerpt">' . esc_html( wp_trim_words( $req->description, 30 ) ) . '</p>';
                }
                echo '</div>';
            }
        }
    }
}
function sp_frontend_resources_directory(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $search     = isset( $_GET['sp_resource'] ) ? sanitize_text_field( $_GET['sp_resource'] ) : '';
    $cat_filter = absint( $_GET['sp_rcat'] ?? 0 );

    // Fetch categories sorted alphabetically for the dropdown
    $categories = $wpdb->get_results(
        "SELECT rc.id, rc.name, COUNT(r.id) as link_count
         FROM {$prefix}resource_categories rc
         LEFT JOIN {$prefix}resources r ON r.category_id = rc.id AND r.active = 1
         WHERE rc.active = 1
         GROUP BY rc.id
         ORDER BY rc.name ASC"
    );

    // WHY OR not AND: Search and category filter are independent controls.
    //     If someone searches "Sample" they get everything matching "Sample"
    //     across all categories. If they pick a category they get everything
    //     in that category. They don't combine — whichever one is active wins.
    $where = 'r.active = 1';
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        $where .= $wpdb->prepare(
            ' AND (r.title LIKE %s OR r.description LIKE %s OR rc.name LIKE %s)',
            $like, $like, $like
        );
    } elseif ( $cat_filter ) {
        $where .= $wpdb->prepare( ' AND r.category_id = %d', $cat_filter );
    }

    $resources = $wpdb->get_results(
        "SELECT r.*, rc.name as category_name
         FROM {$prefix}resources r
         LEFT JOIN {$prefix}resource_categories rc ON r.category_id = rc.id
         WHERE {$where}
         ORDER BY r.title ASC"
    );

    echo '<h2>' . esc_html__( 'Resource Links', 'societypress' ) . '</h2>';

    // Two independent controls: a search box and a category dropdown.
    // WHY independent: They don't combine — search searches everything,
    //     the dropdown filters by category. Using one clears the other.
    //     This keeps it simple for Harold: type to find something specific,
    //     or browse by category. No confusing AND logic.
    echo '<div style="display:flex; flex-wrap:wrap; gap:12px; margin-bottom:24px; align-items:center;">';

    // Search form — searches title, description, and category name
    echo '<form method="get" style="display:flex; gap:8px; flex:1; min-width:220px;">';
    echo '<input type="text" name="sp_resource" value="' . esc_attr( $search ) . '" placeholder="' . esc_attr__( 'Search resources…', 'societypress' ) . '" style="flex:1; padding:10px; border:1px solid #ccc; border-radius:6px; font-size:16px;">';
    echo '<button type="submit" class="sp-btn sp-btn-primary">' . esc_html__( 'Search', 'societypress' ) . '</button>';
    echo '</form>';

    // Category dropdown — auto-submits, clears any active search
    echo '<form method="get">';
    echo '<select name="sp_rcat" onchange="this.form.submit()" style="padding:10px; border:1px solid #ccc; border-radius:6px; font-size:16px; min-width:240px;">';
    echo '<option value="0">' . esc_html__( 'All Categories', 'societypress' ) . '</option>';
    foreach ( $categories as $cat ) {
        if ( $cat->link_count < 1 ) continue;
        $sel = selected( $cat_filter, (int) $cat->id, false );
        echo '<option value="' . esc_attr( $cat->id ) . '"' . $sel . '>'
             . esc_html( $cat->name )
             . '</option>';
    }
    echo '</select>';
    echo '</form>';

    // Clear link — shows when any filter is active
    if ( $search || $cat_filter ) {
        echo '<a href="' . esc_url( get_permalink() ) . '" style="font-size:14px; color:var(--sp-color-text-secondary, #6b7280);">' . esc_html__( 'Clear', 'societypress' ) . '</a>';
    }

    echo '</div>';

    if ( empty( $resources ) ) {
        echo '<p class="sp-text-secondary">' . esc_html__( 'No resources found.', 'societypress' ) . '</p>';
        return;
    }

    // Alphabetical list within the selected category (or all)
    foreach ( $resources as $item ) {
        echo '<div style="padding:12px 0; border-bottom:1px solid #f0f0f0;">';
        echo '<a href="' . esc_url( $item->url ) . '" target="_blank" rel="noopener noreferrer" style="font-weight:600; font-size:16px; color:var(--sp-color-primary);">' . esc_html( $item->title ) . '</a>';
        if ( $item->featured ) {
            echo ' <span style="background:#fef0c7; color:#92400e; font-size:11px; padding:2px 6px; border-radius:4px;">' . esc_html__( 'Featured', 'societypress' ) . '</span>';
        }
        // Show category tag when viewing all categories so links have context
        if ( ! $cat_filter && ! empty( $item->category_name ) ) {
            echo ' <span style="background:#f0f0f0; color:#555; font-size:11px; padding:2px 6px; border-radius:4px;">' . esc_html( $item->category_name ) . '</span>';
        }
        if ( $item->description ) {
            echo '<p style="margin:4px 0 0; color:#555; font-size:14px;">' . esc_html( $item->description ) . '</p>';
        }
        echo '</div>';
    }
}

/**
 * Frontend: Library Catalog (DEPRECATED)
 *
 * WHY THIS IS DEPRECATED: This was the original basic 85-line catalog — a simple
 *      table with keyword search and category filter. It has been superseded by
 *      sp_render_builder_widget_library_catalog(), which provides the full OPAC-style
 *      experience: faceted search, browse-by sections, expandable detail rows, sort
 *      options, and media type filtering. The sp-library-catalog page template now
 *      calls the OPAC version directly. This function is retained for backward
 *      compatibility in case any custom code references it, but new code should
 *      use sp_render_builder_widget_library_catalog( [] ) instead.
 *
 * @deprecated Use sp_render_builder_widget_library_catalog( [] ) instead.
 */
function sp_frontend_library_catalog(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $search = isset( $_GET['sp_lib_search'] ) ? sanitize_text_field( $_GET['sp_lib_search'] ) : '';
    $cat_filter = absint( $_GET['category'] ?? 0 );
    $categories = $wpdb->get_results( "SELECT * FROM {$prefix}library_categories WHERE active = 1 ORDER BY sort_order ASC, name ASC" );

    $where = [ '1=1' ];
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = $wpdb->prepare( '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s)', $like, $like, $like );
    }
    if ( $cat_filter ) {
        $where[] = $wpdb->prepare( 'li.category_id = %d', $cat_filter );
    }
    $where_sql = implode( ' AND ', $where );

    $per_page = 25;
    $page_num = max( 1, absint( $_GET['pg'] ?? 1 ) );
    $offset   = ( $page_num - 1 ) * $per_page;
    $total    = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items li WHERE {$where_sql}" );
    $items    = $wpdb->get_results( $wpdb->prepare(
        "SELECT li.*, lc.name as category_name
         FROM {$prefix}library_items li
         LEFT JOIN {$prefix}library_categories lc ON li.category_id = lc.id
         WHERE {$where_sql}
         ORDER BY li.title ASC
         LIMIT %d OFFSET %d",
        $per_page,
        $offset
    ) );

    // WHY: All layout/typography styles live here rather than inline so they
    // can be overridden by child themes and the design stays centralised.
    // Class prefix: sp-fe-catalog- isolates these rules from any other
    // SocietyPress or theme styles.
    echo '<style>
        /* ── Library Catalog front-end styles ─────────────────────── */

        /* Search / filter bar */
        .sp-fe-catalog-form          { display:flex; gap:8px; margin-bottom:20px; flex-wrap:wrap; }
        .sp-fe-catalog-search        { flex:1; min-width:200px; padding:10px; border:1px solid #ccc; border-radius:6px; font-size:16px; }
        .sp-fe-catalog-cat-select    { padding:10px; border:1px solid #ccc; border-radius:6px; }

        /* Result count line */
        .sp-fe-catalog-count         { color:#666; font-size:13px; }

        /* Results table */
        .sp-fe-catalog-table         { width:100%; border-collapse:collapse; }
        .sp-fe-catalog-th            { padding:10px 12px; text-align:left; border-bottom:2px solid #ddd; background:#f8f8f8; }
        .sp-fe-catalog-th--center    { text-align:center; }   /* modifier: Available column header */
        .sp-fe-catalog-td            { padding:10px 12px; border-bottom:1px solid #eee; }
        .sp-fe-catalog-td--center    { text-align:center; }   /* modifier: Available column cell */

        /* Item condition badge (e.g. "Good", "Fair") shown after the title */
        .sp-fe-catalog-condition     { color:#666; font-size:12px; }

        /* Availability indicators */
        .sp-fe-catalog-avail-yes     { color:#0a6b2e; font-weight:600; }
        .sp-fe-catalog-avail-no      { color:#b32d2e; }

        /* Pagination bar */
        .sp-fe-catalog-pagination    { margin-top:20px; text-align:center; }
        /* Current page — filled pill */
        .sp-fe-catalog-page-current  { display:inline-block; padding:6px 12px; margin:0 2px; background:var(--sp-color-primary); color:#fff; border-radius:4px; }
        /* Other pages — outlined pill */
        .sp-fe-catalog-page-link     { display:inline-block; padding:6px 12px; margin:0 2px; border:1px solid #ccc; border-radius:4px; text-decoration:none; color:var(--sp-color-primary); }

        /* Empty-state message */
        .sp-fe-catalog-empty         { color:#666; font-style:italic; }
    </style>';

    echo '<h2>' . esc_html__( 'Library Catalog', 'societypress' ) . '</h2>';
    echo '<form method="get" class="sp-fe-catalog-form">';
    echo '<input type="text" name="sp_lib_search" value="' . esc_attr( $search ) . '" placeholder="Search title, author, or call number..." class="sp-fe-catalog-search">';
    echo '<select name="category" class="sp-fe-catalog-cat-select">';
    echo '<option value="0">' . esc_html__( 'All Categories', 'societypress' ) . '</option>';
    foreach ( $categories as $cat ) {
        echo '<option value="' . $cat->id . '"' . selected( $cat_filter, $cat->id, false ) . '>' . esc_html( $cat->name ) . '</option>';
    }
    echo '</select>';
    echo '<button type="submit" class="sp-btn sp-btn-primary">' . esc_html__( 'Search', 'societypress' ) . '</button>';
    echo '</form>';
    echo '<p class="sp-fe-catalog-count">' . sprintf( _n( '%d item', '%d items', $total, 'societypress' ), $total ) . '</p>';

    if ( ! empty( $items ) ) {
        echo '<table class="sp-fe-catalog-table">';
        echo '<thead><tr>';
        echo '<th class="sp-fe-catalog-th">' . esc_html__( 'Title', 'societypress' ) . '</th>';
        echo '<th class="sp-fe-catalog-th">' . esc_html__( 'Author', 'societypress' ) . '</th>';
        echo '<th class="sp-fe-catalog-th">' . esc_html__( 'Category', 'societypress' ) . '</th>';
        echo '<th class="sp-fe-catalog-th">' . esc_html__( 'Call #', 'societypress' ) . '</th>';
        echo '<th class="sp-fe-catalog-th sp-fe-catalog-th--center">' . esc_html__( 'Available', 'societypress' ) . '</th>';
        echo '</tr></thead><tbody>';
        foreach ( $items as $item ) {
            echo '<tr>';
            echo '<td class="sp-fe-catalog-td"><strong>' . esc_html( $item->title ) . '</strong>';
            if ( $item->item_condition ) echo ' <span class="sp-fe-catalog-condition">(' . esc_html( ucfirst( $item->item_condition ) ) . ')</span>';
            echo '</td>';
            echo '<td class="sp-fe-catalog-td">' . esc_html( $item->author ?: '—' ) . '</td>';
            echo '<td class="sp-fe-catalog-td">' . esc_html( $item->category_name ?: '—' ) . '</td>';
            echo '<td class="sp-fe-catalog-td">' . esc_html( $item->call_number ?: '—' ) . '</td>';
            echo '<td class="sp-fe-catalog-td sp-fe-catalog-td--center">';
            echo $item->available ? '<span class="sp-fe-catalog-avail-yes">' . esc_html__( 'Yes', 'societypress' ) . '</span>' : '<span class="sp-fe-catalog-avail-no">' . esc_html__( 'No', 'societypress' ) . '</span>';
            echo '</td></tr>';
        }
        echo '</tbody></table>';

        // Pagination
        $total_pages = ceil( $total / $per_page );
        if ( $total_pages > 1 ) {
            echo '<div class="sp-fe-catalog-pagination">';
            for ( $p = 1; $p <= $total_pages; $p++ ) {
                $url = add_query_arg( 'pg', $p );
                if ( $p === $page_num ) {
                    echo '<span class="sp-fe-catalog-page-current">' . $p . '</span>';
                } else {
                    echo '<a href="' . esc_url( $url ) . '" class="sp-fe-catalog-page-link">' . $p . '</a>';
                }
            }
            echo '</div>';
        }
    } else {
        echo '<p class="sp-fe-catalog-empty">' . esc_html__( 'No items found.', 'societypress' ) . '</p>';
    }
}


// ============================================================================
// LIBRARY CATALOG — ADMIN PAGES
// ============================================================================
//
// WHY: Feature 7 — admin interface for managing the society's physical
//      library collection (books, periodicals, maps, microfilm, etc.).

/**
 * Render: Library Catalog Admin Page
 *
 * WHY: WP_List_Table-style list showing all library items with search,
 *      category filtering, and links to the item edit page.
 */
function sp_render_library_catalog_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( ( $_POST['action'] ?? '' ) === 'delete' && ! empty( $_POST['item_id'] ) ) {
        $item_id = absint( $_POST['item_id'] );
        check_admin_referer( 'sp_delete_library_item_' . $item_id );
        $wpdb->delete( $prefix . 'library_items', [ 'id' => $item_id ] );
        // WHY: The catalog stats widget caches item counts and subject breakdowns.
        //      Any add/edit/delete/import must bust that cache or the frontend shows stale numbers.
        delete_transient( 'sp_library_catalog_stats' );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Item deleted.', 'societypress' ) . '</p></div>';
    }

    // Filters
    $search       = isset( $_GET['s'] ) ? sanitize_text_field( $_GET['s'] ) : '';
    $media_filter = isset( $_GET['media_type'] ) ? sanitize_text_field( $_GET['media_type'] ) : '';
    $shelf_filter = isset( $_GET['shelf'] ) ? sanitize_text_field( $_GET['shelf'] ) : '';
    $acq_filter   = isset( $_GET['acq_code'] ) ? sanitize_text_field( $_GET['acq_code'] ) : '';

    // Get distinct values for filter dropdowns
    $media_types     = $wpdb->get_col( "SELECT DISTINCT media_type FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' ORDER BY media_type ASC" );
    $shelf_locations = $wpdb->get_col( "SELECT DISTINCT shelf_location FROM {$prefix}library_items WHERE shelf_location IS NOT NULL AND shelf_location != '' ORDER BY shelf_location ASC" );
    $acq_codes       = $wpdb->get_col( "SELECT DISTINCT acq_code FROM {$prefix}library_items WHERE acq_code IS NOT NULL AND acq_code != '' ORDER BY acq_code ASC" );

    // Build WHERE clause
    $where = [ '1=1' ];
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = $wpdb->prepare(
            '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s OR li.subject LIKE %s OR li.surname LIKE %s)',
            $like, $like, $like, $like, $like
        );
    }
    if ( $media_filter ) {
        $where[] = $wpdb->prepare( 'li.media_type = %s', $media_filter );
    }
    if ( $shelf_filter ) {
        $where[] = $wpdb->prepare( 'li.shelf_location = %s', $shelf_filter );
    }
    if ( $acq_filter ) {
        $where[] = $wpdb->prepare( 'li.acq_code = %s', $acq_filter );
    }
    $where_sql = implode( ' AND ', $where );

    // Sorting
    $allowed_orderby = [ 'title', 'author', 'media_type', 'shelf_location', 'call_number', 'pub_year', 'acq_code' ];
    $orderby = isset( $_GET['orderby'] ) && in_array( $_GET['orderby'], $allowed_orderby, true )
             ? 'li.' . $_GET['orderby']
             : 'li.title';
    $order = isset( $_GET['order'] ) && strtoupper( $_GET['order'] ) === 'DESC' ? 'DESC' : 'ASC';

    // Read per-page from settings (same setting the directory uses)
    $settings = get_option( 'societypress_settings', [] );
    $per_page = absint( $settings['directory_per_page'] ?? 50 );
    if ( $per_page < 1 ) $per_page = 50;

    $page_num = max( 1, absint( $_GET['paged'] ?? 1 ) );
    $offset   = ( $page_num - 1 ) * $per_page;
    $total    = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items li WHERE {$where_sql}" );
    $items    = $wpdb->get_results( $wpdb->prepare(
        "SELECT li.*
         FROM {$prefix}library_items li
         WHERE {$where_sql}
         ORDER BY {$orderby} {$order}
         LIMIT %d OFFSET %d",
        $per_page,
        $offset
    ) );
    $total_pages = (int) ceil( $total / $per_page );

    // Helper to build sortable column header links
    $sort_link = function( string $col, string $label ) use ( $orderby, $order ) {
        $current   = ( $orderby === 'li.' . $col );
        $next_order = ( $current && $order === 'ASC' ) ? 'desc' : 'asc';
        $url = add_query_arg( [ 'orderby' => $col, 'order' => $next_order ] );
        $arrow = $current ? ( $order === 'ASC' ? ' &#9650;' : ' &#9660;' ) : '';
        return '<a href="' . esc_url( $url ) . '">' . esc_html( $label ) . $arrow . '</a>';
    };
    ?>
    <?php
    // WHY: All layout and color styles for the library catalog admin page live here,
    //      not as inline style= attributes scattered through the markup. This makes
    //      it far easier to adjust spacing, colors, or breakpoints in one place rather
    //      than hunting through dozens of HTML tags. Classes are prefixed sp-catalog-
    //      to avoid collisions with WP core or other plugin styles.
    //      display:none on JS-toggled elements and element.style.* in JS are untouched.
    //      Dynamic PHP values (e.g. per-item colors from DB) would also stay inline,
    //      but none exist in this function.
    ?>
    <style>
    /* ---- Library Catalog: stats dashboard ---- */
    .sp-catalog-stats-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 16px;
        margin: 16px 0 24px;
    }
    .sp-catalog-stat-card {
        background: #fff;
        border: 1px solid #c3c4c7;
        border-radius: 4px;
        padding: 16px;
    }
    .sp-catalog-stat-number {
        font-size: 32px;
        font-weight: 700;
    }
    /* Individual accent colors for each KPI tile */
    .sp-catalog-stat-number--total     { color: #2271b1; } /* WP admin blue  — total items   */
    .sp-catalog-stat-number--available { color: #0a6b2e; } /* green          — available      */
    .sp-catalog-stat-number--value     { color: #dba617; } /* amber          — collection $   */
    .sp-catalog-stat-number--types     { color: #8c5bbd; } /* purple         — media type cnt */
    .sp-catalog-stat-label {
        color: #666;
        font-size: 13px;
    }

    /* ---- Library Catalog: secondary breakdown panels ---- */
    .sp-catalog-breakdown-grid {
        display: grid;
        grid-template-columns: 1fr 1fr 1fr;
        gap: 16px;
        margin-bottom: 24px;
    }
    .sp-catalog-breakdown-card {
        background: #fff;
        border: 1px solid #c3c4c7;
        border-radius: 4px;
        padding: 16px;
    }
    .sp-catalog-breakdown-card h3 {
        margin: 0 0 10px;
        font-size: 14px;
        color: #1d2327;
    }
    .sp-catalog-breakdown-row {
        display: flex;
        justify-content: space-between;
        padding: 3px 0;
        font-size: 13px;
    }
    .sp-catalog-recent-item {
        padding: 3px 0;
        font-size: 13px;
    }
    .sp-catalog-recent-author {
        color: #666;
    }

    /* ---- Library Catalog: search / filter bar ---- */
    .sp-catalog-filter-form {
        display: flex;
        flex-wrap: wrap;
        gap: 8px;
        align-items: flex-end;
        margin: 16px 0;
    }
    .sp-catalog-search-input {
        width: 320px;
    }

    /* ---- Library Catalog: row-action delete button ---- */
    /* WHY: The delete trigger must look like a text link (matching WP row-action
    //      convention) but is a <button> so it can live inside a <form> for POST-
    //      based deletion without JavaScript. background:none + border:none strips
    //      the default button chrome; the rest restores link appearance. */
    .sp-catalog-delete-form {
        display: inline;
    }
    .sp-catalog-delete-btn {
        background: none;
        border: none;
        color: #b32d2e;
        cursor: pointer;
        padding: 0;
        font: inherit;
        text-decoration: underline;
    }
    </style>

    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Library Catalog', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-library-item-edit' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Add New Item', 'societypress' ); ?></a>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-import-library' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Import CSV', 'societypress' ); ?></a>
        <?php
        // Export CSV button — passes current filters so admins export what they see
        $export_args = [ 'action' => 'sp_export_library' ];
        if ( $search )       $export_args['s']          = $search;
        if ( $media_filter ) $export_args['media_type']  = $media_filter;
        if ( $shelf_filter ) $export_args['shelf']       = $shelf_filter;
        if ( $acq_filter )   $export_args['acq_code']    = $acq_filter;
        $export_url = wp_nonce_url( add_query_arg( $export_args, admin_url( 'admin-ajax.php' ) ), 'sp_export_library' );
        ?>
        <a href="<?php echo esc_url( $export_url ); ?>" class="page-title-action"><?php esc_html_e( 'Export CSV', 'societypress' ); ?></a>
        <hr class="wp-header-end">

        <?php
        // ---- Library Stats Dashboard ----
        // WHY: At a glance, the librarian sees collection size, breakdown by
        //      media type and acquisition method, total estimated value, and
        //      most recent additions — no need to run reports or export.
        $stats_total     = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items" );
        $stats_available = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}library_items WHERE available = 1" );
        $stats_value     = (float) $wpdb->get_var( "SELECT COALESCE(SUM(item_value), 0) FROM {$prefix}library_items" );
        $stats_by_media  = $wpdb->get_results( "SELECT media_type, COUNT(*) as cnt FROM {$prefix}library_items WHERE media_type IS NOT NULL AND media_type != '' GROUP BY media_type ORDER BY cnt DESC LIMIT 10" );
        $stats_by_acq    = $wpdb->get_results( "SELECT acq_code, COUNT(*) as cnt FROM {$prefix}library_items WHERE acq_code IS NOT NULL AND acq_code != '' GROUP BY acq_code ORDER BY cnt DESC LIMIT 10" );
        $stats_recent    = $wpdb->get_results( "SELECT title, author, media_type, created_at FROM {$prefix}library_items ORDER BY created_at DESC LIMIT 5" );
        ?>
        <div class="sp-library-stats sp-catalog-stats-grid">
            <div class="sp-catalog-stat-card">
                <div class="sp-catalog-stat-number sp-catalog-stat-number--total"><?php echo number_format( $stats_total ); ?></div>
                <div class="sp-catalog-stat-label"><?php esc_html_e( 'Total Items', 'societypress' ); ?></div>
            </div>
            <div class="sp-catalog-stat-card">
                <div class="sp-catalog-stat-number sp-catalog-stat-number--available"><?php echo number_format( $stats_available ); ?></div>
                <div class="sp-catalog-stat-label"><?php esc_html_e( 'Available', 'societypress' ); ?></div>
            </div>
            <div class="sp-catalog-stat-card">
                <div class="sp-catalog-stat-number sp-catalog-stat-number--value"><?php echo esc_html( sp_format_currency( $stats_value ) ); ?></div>
                <div class="sp-catalog-stat-label"><?php esc_html_e( 'Collection Value', 'societypress' ); ?></div>
            </div>
            <div class="sp-catalog-stat-card">
                <div class="sp-catalog-stat-number sp-catalog-stat-number--types"><?php echo count( $media_types ); ?></div>
                <div class="sp-catalog-stat-label"><?php esc_html_e( 'Media Types', 'societypress' ); ?></div>
            </div>
        </div>

        <?php if ( ! $search && ! $media_filter && ! $shelf_filter && ! $acq_filter ) : ?>
        <div class="sp-catalog-breakdown-grid">
            <div class="sp-catalog-breakdown-card">
                <h3><?php esc_html_e( 'By Media Type', 'societypress' ); ?></h3>
                <?php foreach ( $stats_by_media as $row ) : ?>
                    <div class="sp-catalog-breakdown-row">
                        <span><?php echo esc_html( $row->media_type ); ?></span>
                        <strong><?php echo number_format( $row->cnt ); ?></strong>
                    </div>
                <?php endforeach; ?>
            </div>
            <div class="sp-catalog-breakdown-card">
                <h3><?php esc_html_e( 'By Acquisition', 'societypress' ); ?></h3>
                <?php foreach ( $stats_by_acq as $row ) : ?>
                    <div class="sp-catalog-breakdown-row">
                        <span><?php echo esc_html( $row->acq_code ); ?></span>
                        <strong><?php echo number_format( $row->cnt ); ?></strong>
                    </div>
                <?php endforeach; ?>
            </div>
            <div class="sp-catalog-breakdown-card">
                <h3><?php esc_html_e( 'Recently Added', 'societypress' ); ?></h3>
                <?php foreach ( $stats_recent as $row ) : ?>
                    <div class="sp-catalog-recent-item">
                        <strong><?php echo esc_html( wp_trim_words( $row->title, 8 ) ); ?></strong>
                        <?php if ( $row->author ) : ?>
                            <br><span class="sp-catalog-recent-author"><?php echo esc_html( $row->author ); ?></span>
                        <?php endif; ?>
                    </div>
                <?php endforeach; ?>
            </div>
        </div>
        <?php endif; ?>

        <!-- Search and filter bar -->
        <form method="get" class="sp-catalog-filter-form">
            <input type="hidden" name="page" value="sp-library-catalog">
            <div>
                <input type="text" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="Search title, author, call #, subject, surname..." class="sp-catalog-search-input">
            </div>
            <div>
                <select name="media_type">
                    <option value=""><?php esc_html_e( 'All Media Types', 'societypress' ); ?></option>
                    <?php foreach ( $media_types as $mt ) : ?>
                        <option value="<?php echo esc_attr( $mt ); ?>" <?php selected( $media_filter, $mt ); ?>><?php echo esc_html( $mt ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <select name="shelf">
                    <option value=""><?php esc_html_e( 'All Locations', 'societypress' ); ?></option>
                    <?php foreach ( $shelf_locations as $sl ) : ?>
                        <option value="<?php echo esc_attr( $sl ); ?>" <?php selected( $shelf_filter, $sl ); ?>><?php echo esc_html( $sl ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <select name="acq_code">
                    <option value=""><?php esc_html_e( 'All Acquisition Types', 'societypress' ); ?></option>
                    <?php foreach ( $acq_codes as $ac ) : ?>
                        <option value="<?php echo esc_attr( $ac ); ?>" <?php selected( $acq_filter, $ac ); ?>><?php echo esc_html( $ac ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <input type="submit" class="button" value="<?php echo esc_attr__( 'Filter', 'societypress' ); ?>">
            <?php if ( $search || $media_filter || $shelf_filter || $acq_filter ) : ?>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-library-catalog' ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
            <?php endif; ?>
        </form>

        <p class="description"><?php echo sprintf( _n( '%d item found.', '%d items found.', $total, 'societypress' ), $total ); ?></p>

        <table class="wp-list-table widefat striped">
            <thead>
                <tr>
                    <th><?php echo $sort_link( 'title', 'Title' ); ?></th>
                    <th><?php echo $sort_link( 'author', 'Author' ); ?></th>
                    <th><?php echo $sort_link( 'media_type', 'Type' ); ?></th>
                    <th><?php echo $sort_link( 'call_number', 'Call #' ); ?></th>
                    <th><?php echo $sort_link( 'shelf_location', 'Location' ); ?></th>
                    <th><?php echo $sort_link( 'pub_year', 'Year' ); ?></th>
                    <th><?php echo $sort_link( 'acq_code', 'Acquired' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $items ) ) : ?>
                    <tr><td colspan="7"><?php esc_html_e( 'No items found.', 'societypress' ); ?></td></tr>
                <?php else : ?>
                    <?php foreach ( $items as $item ) :
                        $edit_url   = admin_url( 'admin.php?page=sp-library-item-edit&item_id=' . $item->id );
                        // delete handled via POST form in row actions
                    ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo esc_url( $edit_url ); ?>"><?php echo esc_html( $item->title ); ?></a></strong>
                                <div class="row-actions">
                                    <span><a href="<?php echo esc_url( $edit_url ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a> | </span>
                                    <span><form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-library-catalog' ) ); ?>" class="sp-catalog-delete-form" data-sp-confirm="<?php echo esc_attr( __( 'Delete this item?', 'societypress' ) ); ?>"><?php wp_nonce_field( 'sp_delete_library_item_' . $item->id ); ?><input type="hidden" name="action" value="delete"><input type="hidden" name="item_id" value="<?php echo (int) $item->id; ?>"><button type="submit" class="sp-link-btn sp-catalog-delete-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button></form></span>
                                </div>
                            </td>
                            <td><?php echo esc_html( $item->author ?: '—' ); ?></td>
                            <td><?php echo esc_html( $item->media_type ?: '—' ); ?></td>
                            <td><?php echo esc_html( $item->call_number ?: '—' ); ?></td>
                            <td><?php echo esc_html( $item->shelf_location ?: '—' ); ?></td>
                            <td><?php echo esc_html( $item->pub_year ?: '—' ); ?></td>
                            <td><?php echo esc_html( $item->acq_code ?: '—' ); ?></td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>

        <?php if ( $total_pages > 1 ) : ?>
            <div class="tablenav bottom"><div class="tablenav-pages">
                <?php
                // Show smarter pagination for large catalogs — first, prev, current, next, last
                $base_url = remove_query_arg( 'paged' );
                if ( $page_num > 1 ) : ?>
                    <a class="button" href="<?php echo esc_url( add_query_arg( 'paged', 1, $base_url ) ); ?>">&laquo; First</a>
                    <a class="button" href="<?php echo esc_url( add_query_arg( 'paged', $page_num - 1, $base_url ) ); ?>">&lsaquo; Prev</a>
                <?php endif; ?>

                <span class="tablenav-pages-navspan button disabled">
                    Page <?php echo $page_num; ?> of <?php echo number_format( $total_pages ); ?>
                </span>

                <?php if ( $page_num < $total_pages ) : ?>
                    <a class="button" href="<?php echo esc_url( add_query_arg( 'paged', $page_num + 1, $base_url ) ); ?>">Next &rsaquo;</a>
                    <a class="button" href="<?php echo esc_url( add_query_arg( 'paged', $total_pages, $base_url ) ); ?>">Last &raquo;</a>
                <?php endif; ?>
            </div></div>
        <?php endif; ?>
    </div>
    <?php
}

/**
 * Render: Library Item Edit Page
 *
 * WHY: Add/edit a single library item with all metadata fields.
 */
function sp_render_library_item_edit_page(): void {
    global $wpdb;
    $prefix  = $wpdb->prefix . 'sp_';
    $item_id = absint( $_GET['item_id'] ?? 0 );

    // Handle save
    if ( isset( $_POST['sp_save_library_item'] ) && check_admin_referer( 'sp_library_item_save' ) ) {

        // Parse numeric fields safely — empty strings become null, not 0
        $parse_int = function( $val ) {
            $val = trim( $val ?? '' );
            return ( $val !== '' && is_numeric( $val ) ) ? (int) $val : null;
        };
        $parse_decimal = function( $val ) {
            $val = trim( $val ?? '' );
            return ( $val !== '' && is_numeric( $val ) ) ? (float) $val : null;
        };

        $data = [
            'system_id'           => $parse_int( $_POST['system_id'] ?? '' ),
            'title'               => sanitize_text_field( $_POST['title'] ?? '' ),
            'author'              => sanitize_text_field( $_POST['author'] ?? '' ) ?: null,
            'description'         => sanitize_textarea_field( $_POST['description'] ?? '' ) ?: null,
            'publisher'           => sanitize_text_field( $_POST['publisher'] ?? '' ) ?: null,
            'publisher_location'  => sanitize_text_field( $_POST['publisher_location'] ?? '' ) ?: null,
            'pub_year'            => $parse_int( $_POST['pub_year'] ?? '' ),
            'pub_month'           => $parse_int( $_POST['pub_month'] ?? '' ),
            'pub_day'             => $parse_int( $_POST['pub_day'] ?? '' ),
            'media_type'          => sanitize_text_field( $_POST['media_type'] ?? '' ) ?: null,
            'use_serials'         => ! empty( $_POST['use_serials'] ) ? 1 : 0,
            'isbn'                => sanitize_text_field( $_POST['isbn'] ?? '' ) ?: null,
            'call_number'         => sanitize_text_field( $_POST['call_number'] ?? '' ) ?: null,
            'lccn'                => sanitize_text_field( $_POST['lccn'] ?? '' ) ?: null,
            'category_id'         => absint( $_POST['category_id'] ?? 0 ) ?: null,
            'shelf_location'      => sanitize_text_field( $_POST['shelf_location'] ?? '' ) ?: null,
            'geographic_location' => sanitize_text_field( $_POST['geographic_location'] ?? '' ) ?: null,
            'acquisition_number'  => $parse_int( $_POST['acquisition_number'] ?? '' ),
            'acq_year'            => $parse_int( $_POST['acq_year'] ?? '' ),
            'acq_month'           => $parse_int( $_POST['acq_month'] ?? '' ),
            'acq_day'             => $parse_int( $_POST['acq_day'] ?? '' ),
            'acq_code'            => sanitize_text_field( $_POST['acq_code'] ?? '' ) ?: null,
            'donor'               => sanitize_text_field( $_POST['donor'] ?? '' ) ?: null,
            'item_value'          => $parse_decimal( $_POST['item_value'] ?? '' ),
            'county'              => sanitize_text_field( $_POST['county'] ?? '' ) ?: null,
            'state'               => sanitize_text_field( $_POST['state'] ?? '' ) ?: null,
            'surname'             => sanitize_text_field( $_POST['surname'] ?? '' ) ?: null,
            'subject'             => sanitize_text_field( $_POST['subject'] ?? '' ) ?: null,
            'librarian_notes'     => sanitize_textarea_field( $_POST['librarian_notes'] ?? '' ) ?: null,
            'store_description'   => sanitize_textarea_field( $_POST['store_description'] ?? '' ) ?: null,
            'item_condition'      => sanitize_text_field( $_POST['item_condition'] ?? 'good' ),
            'available'           => ! empty( $_POST['available'] ) ? 1 : 0,
            'cover_url'           => esc_url_raw( $_POST['cover_url'] ?? '' ) ?: null,
        ];

        if ( ! empty( $data['title'] ) ) {
            if ( $item_id ) {
                $wpdb->update( $prefix . 'library_items', $data, [ 'id' => $item_id ] );
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Item updated.', 'societypress' ) . '</p></div>';
            } else {
                $wpdb->insert( $prefix . 'library_items', $data );
                $item_id = $wpdb->insert_id;
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Item added.', 'societypress' ) . '</p></div>';
            }
            delete_transient( 'sp_library_catalog_stats' );
        }
    }

    $item = $item_id ? $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}library_items WHERE id = %d", $item_id
    ) ) : null;
    $categories = $wpdb->get_results( "SELECT * FROM {$prefix}library_categories WHERE active = 1 ORDER BY sort_order ASC, name ASC" );
