    <!-- Volunteer Opportunities JS -->
    <script>
    (function() {
        'use strict';
        var nonce = '<?php echo esc_js( $nonce ); ?>';
        var ajaxUrl = '<?php echo esc_js( admin_url( "admin-ajax.php" ) ); ?>';

        // Signup buttons
        document.querySelectorAll('.sp-vol-signup-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var oppId = this.getAttribute('data-opp-id');
                var origText = this.textContent;
                this.disabled = true;
                this.textContent = '<?php echo esc_js( __( "Signing up\u2026", "societypress" ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_volunteer_signup');
                fd.append('opportunity_id', oppId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            var icon = data.data.status === 'waitlisted' ? '\uD83D\uDCCB <?php echo esc_js( __( "Waitlisted", "societypress" ) ); ?>' : '\u2705 <?php echo esc_js( __( "Signed Up", "societypress" ) ); ?>';
                            btn.parentNode.innerHTML = '<span style="font-weight:600;color:' +
                                (data.data.status === 'confirmed' ? '#00a32a' : '#dba617') + ';">' + icon + '</span>' +
                                ' <em style="font-size:0.85em;color:#787c82;"><?php echo esc_js( __( "(reload to update)", "societypress" ) ); ?></em>';
                        } else {
                            alert(data.data || '<?php echo esc_js( __( "Could not sign up.", "societypress" ) ); ?>');
                            btn.disabled = false;
                            btn.textContent = origText;
                        }
                    })
                    .catch(function() {
                        alert('<?php echo esc_js( __( 'Something went wrong.', 'societypress' ) ); ?>');
                        btn.disabled = false;
                        btn.textContent = origText;
                    });
            });
        });

        // Cancel buttons
        document.querySelectorAll('.sp-vol-cancel-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var self = this;
                spConfirm('<?php echo esc_js( __( 'Cancel your volunteer signup?', 'societypress' ) ); ?>', function() {
                var signupId = self.getAttribute('data-signup-id');
                self.disabled = true;
                self.textContent = '<?php echo esc_js( __( "Cancelling\u2026", "societypress" ) ); ?>';

                var fd = new FormData();
                fd.append('action', 'sp_volunteer_cancel');
                fd.append('signup_id', signupId);
                fd.append('nonce', nonce);

                fetch(ajaxUrl, { method: 'POST', body: fd, credentials: 'same-origin' })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            btn.parentNode.innerHTML = '<em class="sp-text-muted"><?php echo esc_js( __( "Cancelled (reload to update)", "societypress" ) ); ?></em>';
                        } else {
                            alert(data.data || '<?php echo esc_js( __( "Could not cancel.", "societypress" ) ); ?>');
                            btn.disabled = false;
                            btn.textContent = '<?php echo esc_js( __( "Cancel", "societypress" ) ); ?>';
                        }
                    });
            });
        });

        // Client-side filters
        var filterCommittee = document.getElementById('sp-vol-filter-committee');
        var filterType      = document.getElementById('sp-vol-filter-type');
        function applyFilters() {
            var cVal = filterCommittee ? filterCommittee.value : '';
            var tVal = filterType ? filterType.value : '';
            document.querySelectorAll('.sp-vol-card').forEach(function(card) {
                var matchC = !cVal || card.getAttribute('data-committee') === cVal;
                var matchT = !tVal || card.getAttribute('data-type') === tVal;
                card.style.display = (matchC && matchT) ? '' : 'none';
            });
        }
        if (filterCommittee) filterCommittee.addEventListener('change', applyFilters);
        if (filterType) filterType.addEventListener('change', applyFilters);
    })();
    </script>
    <?php
    return ob_get_clean();
}


// ============================================================================
// VOLUNTEER OPPORTUNITIES — ADMIN LIST PAGE
// ============================================================================

function sp_render_volunteer_opportunities_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && ! empty( $_POST['opp_id'] ) ) {
        if ( check_admin_referer( 'sp_delete_opp_' . $_POST['opp_id'] ) ) {
            $opp_id = absint( $_POST['opp_id'] );
            $wpdb->delete( $prefix . 'volunteer_signups', [ 'opportunity_id' => $opp_id ] );
            $wpdb->delete( $prefix . 'volunteer_opportunities', [ 'id' => $opp_id ] );
            echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Opportunity deleted.', 'societypress' ) . '</p></div>';
        }
    }

    // WHY: The committee_id column references committees by ID, but there is
    //      no sp_committees table — committee names are stored as free-text on
    //      sp_volunteer_roles.committee. Until a dedicated committees table is
    //      added, we skip the JOIN and show committee_id as-is.
    $opportunities = $wpdb->get_results(
        "SELECT o.*,
                (SELECT COUNT(*) FROM {$prefix}volunteer_signups s WHERE s.opportunity_id = o.id AND s.status = 'confirmed') AS signup_count,
                (SELECT COUNT(*) FROM {$prefix}volunteer_signups s WHERE s.opportunity_id = o.id AND s.status = 'waitlisted') AS waitlist_count
         FROM {$prefix}volunteer_opportunities o
         ORDER BY o.status ASC, o.event_date ASC, o.sort_order ASC"
    );

    $status_colors = [ 'open' => '#00a32a', 'filled' => '#dba617', 'closed' => '#787c82', 'cancelled' => '#d63638' ];
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Volunteer Opportunities', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Add New', 'societypress' ); ?></a>
        <hr class="wp-header-end">

        <p class="description"><?php esc_html_e( 'Post volunteer needs for your members to browse and sign up for.', 'societypress' ); ?></p>

        <?php if ( empty( $opportunities ) ) : ?>
            <p style="color: #787c82; font-style: italic; margin-top: 20px;">
                <?php esc_html_e( 'No opportunities yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit' ) ); ?>"><?php esc_html_e( 'Create your first one.', 'societypress' ); ?></a>
            </p>
        <?php else : ?>
            <table class="wp-list-table widefat fixed striped" class="sp-mt-16">
                <thead>
                    <tr>
                        <th style="width:25%;"><?php esc_html_e( 'Title', 'societypress' ); ?></th>
                        <th style="width:12%;"><?php esc_html_e( 'Type', 'societypress' ); ?></th>
                        <th style="width:15%;"><?php esc_html_e( 'Committee', 'societypress' ); ?></th>
                        <th style="width:12%;"><?php esc_html_e( 'Date', 'societypress' ); ?></th>
                        <th style="width:10%;"><?php esc_html_e( 'Signups', 'societypress' ); ?></th>
                        <th style="width:10%;"><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                        <th style="width:16%;"><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                    </tr>
                </thead>
                <tbody>
                    <?php foreach ( $opportunities as $opp ) :
                        $badge_color = $status_colors[ $opp->status ] ?? '#787c82';
                        $type_labels = [ 'one_time' => __( 'One-Time', 'societypress' ), 'recurring' => __( 'Recurring', 'societypress' ), 'ongoing' => __( 'Ongoing', 'societypress' ) ];
                    ?>
                    <tr>
                        <td><strong><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit&opp_id=' . $opp->id ) ); ?>"><?php echo esc_html( $opp->title ); ?></a></strong></td>
                        <td><?php echo esc_html( $type_labels[ $opp->opportunity_type ] ?? $opp->opportunity_type ); ?></td>
                        <td><?php echo esc_html( ! empty( $opp->committee_id ) ? sprintf( __( 'Committee #%d', 'societypress' ), $opp->committee_id ) : __( 'Society-Wide', 'societypress' ) ); ?></td>
                        <td><?php echo $opp->event_date ? esc_html( date_i18n( 'M j, Y', strtotime( $opp->event_date ) ) ) : '—'; ?></td>
                        <td>
                            <?php echo (int) $opp->signup_count; ?>
                            <?php if ( $opp->capacity ) echo ' / ' . (int) $opp->capacity; ?>
                            <?php if ( (int) $opp->waitlist_count > 0 ) : ?>
                                <span style="color: #dba617; font-size: 12px;">(+<?php echo (int) $opp->waitlist_count; ?> waitlisted)</span>
                            <?php endif; ?>
                        </td>
                        <td>
                            <span style="display:inline-block;padding:2px 8px;border-radius:3px;background:<?php echo $badge_color; ?>22;color:<?php echo $badge_color; ?>;font-size:12px;font-weight:500;">
                                <?php echo esc_html( ucfirst( $opp->status ) ); ?>
                            </span>
                        </td>
                        <td>
                            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunity-edit&opp_id=' . $opp->id ) ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a>
                            |
                            <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-opportunities' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this opportunity and all signups?', 'societypress' ) ); ?>">
                                <?php wp_nonce_field( 'sp_delete_opp_' . $opp->id ); ?>
                                <input type="hidden" name="action" value="delete">
                                <input type="hidden" name="opp_id" value="<?php echo (int) $opp->id; ?>">
                                <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                            </form>
                        </td>
                    </tr>
                    <?php endforeach; ?>
                </tbody>
            </table>
        <?php endif; ?>
    </div>
    <?php
}


// ============================================================================
// VOLUNTEER OPPORTUNITIES — ADD/EDIT PAGE
// ============================================================================

function sp_render_volunteer_opportunity_edit_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $opp_id = (int) ( $_GET['opp_id'] ?? 0 );
    $opp    = null;

    // Handle save
    if ( isset( $_POST['sp_save_opp_nonce'] ) && wp_verify_nonce( $_POST['sp_save_opp_nonce'], 'sp_save_opportunity' ) ) {
        $data = [
            'title'            => sanitize_text_field( $_POST['opp_title'] ?? '' ),
            'description'      => wp_kses_post( $_POST['opp_description'] ?? '' ),
            'committee_id'     => ! empty( $_POST['opp_committee_id'] ) ? (int) $_POST['opp_committee_id'] : null,
            'opportunity_type' => in_array( $_POST['opp_type'] ?? '', [ 'one_time', 'recurring', 'ongoing' ], true )
                                  ? $_POST['opp_type'] : 'one_time',
            'event_date'       => ! empty( $_POST['opp_date'] ) ? sanitize_text_field( $_POST['opp_date'] ) : null,
            'start_time'       => ! empty( $_POST['opp_start_time'] ) ? sanitize_text_field( $_POST['opp_start_time'] ) : null,
            'end_time'         => ! empty( $_POST['opp_end_time'] ) ? sanitize_text_field( $_POST['opp_end_time'] ) : null,
            'location'         => sanitize_text_field( $_POST['opp_location'] ?? '' ),
            'capacity'         => ( $_POST['opp_capacity'] ?? '' ) !== '' ? absint( $_POST['opp_capacity'] ) : null,
            'skills_needed'    => sanitize_textarea_field( $_POST['opp_skills'] ?? '' ),
            'contact_user_id'  => ! empty( $_POST['opp_contact'] ) ? (int) $_POST['opp_contact'] : null,
            'status'           => in_array( $_POST['opp_status'] ?? '', [ 'open', 'filled', 'closed', 'cancelled' ], true )
                                  ? $_POST['opp_status'] : 'open',
        ];

        if ( $opp_id > 0 ) {
            $wpdb->update( $prefix . 'volunteer_opportunities', $data, [ 'id' => $opp_id ] );
            echo '<div class="notice notice-success"><p>' . esc_html__( 'Opportunity updated.', 'societypress' ) . '</p></div>';
        } else {
            $data['created_by'] = get_current_user_id();
            $wpdb->insert( $prefix . 'volunteer_opportunities', $data );
            $opp_id = $wpdb->insert_id;
            echo '<div class="notice notice-success"><p>' . esc_html__( 'Opportunity created.', 'societypress' ) . '</p></div>';
        }
    }

    // Load existing
    if ( $opp_id > 0 ) {
        $opp = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}volunteer_opportunities WHERE id = %d", $opp_id
        ) );
    }

    $val = function ( string $field, $default = '' ) use ( $opp ) {
        if ( $opp && isset( $opp->$field ) ) return $opp->$field;
        return $default;
    };

    $committees = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}committees WHERE active = 1 ORDER BY name"
    );
    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name"
    );

    $page_title = $opp ? __( 'Edit Opportunity', 'societypress' ) : __( 'Add Volunteer Opportunity', 'societypress' );
    ?>
    <div class="wrap">
        <h1><?php echo esc_html( $page_title ); ?></h1>

        <form method="post">
            <?php wp_nonce_field( 'sp_save_opportunity', 'sp_save_opp_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="opp_title"><?php esc_html_e( 'Title', 'societypress' ); ?> <span class="sp-text-error">*</span></label></th>
                    <td><input type="text" id="opp_title" name="opp_title" value="<?php echo esc_attr( $val('title') ); ?>" class="large-text" required></td>
                </tr>
                <tr>
                    <th><label for="opp_type"><?php esc_html_e( 'Type', 'societypress' ); ?></label></th>
                    <td>
                        <select id="opp_type" name="opp_type">
                            <option value="one_time" <?php selected( $val('opportunity_type', 'one_time'), 'one_time' ); ?>><?php esc_html_e( 'One-Time', 'societypress' ); ?></option>
                            <option value="recurring" <?php selected( $val('opportunity_type'), 'recurring' ); ?>><?php esc_html_e( 'Recurring', 'societypress' ); ?></option>
                            <option value="ongoing" <?php selected( $val('opportunity_type'), 'ongoing' ); ?>><?php esc_html_e( 'Ongoing', 'societypress' ); ?></option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_committee_id"><?php esc_html_e( 'Committee', 'societypress' ); ?></label></th>
                    <td>
                        <select id="opp_committee_id" name="opp_committee_id">
                            <option value=""><?php esc_html_e( 'Society-Wide (no committee)', 'societypress' ); ?></option>
                            <?php foreach ( $committees as $c ) : ?>
                                <option value="<?php echo esc_attr( $c->id ); ?>" <?php selected( $val('committee_id'), $c->id ); ?>><?php echo esc_html( $c->name ); ?></option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_description"><?php esc_html_e( 'Description', 'societypress' ); ?></label></th>
                    <td><textarea id="opp_description" name="opp_description" rows="5" class="large-text"><?php echo esc_textarea( $val('description') ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="opp_date"><?php esc_html_e( 'Date', 'societypress' ); ?></label></th>
                    <td><input type="date" id="opp_date" name="opp_date" value="<?php echo esc_attr( $val('event_date') ); ?>">
                        <p class="description"><?php esc_html_e( 'For one-time opportunities. Leave blank for ongoing.', 'societypress' ); ?></p></td>
                </tr>
                <tr>
                    <th><label for="opp_start_time"><?php esc_html_e( 'Time', 'societypress' ); ?></label></th>
                    <td>
                        <input type="time" id="opp_start_time" name="opp_start_time" value="<?php echo esc_attr( $val('start_time') ); ?>">
                        to
                        <input type="time" id="opp_end_time" name="opp_end_time" value="<?php echo esc_attr( $val('end_time') ); ?>">
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_location"><?php esc_html_e( 'Location', 'societypress' ); ?></label></th>
                    <td><input type="text" id="opp_location" name="opp_location" value="<?php echo esc_attr( $val('location') ); ?>" class="regular-text"></td>
                </tr>
                <tr>
                    <th><label for="opp_capacity"><?php esc_html_e( 'Capacity', 'societypress' ); ?></label></th>
                    <td><input type="number" id="opp_capacity" name="opp_capacity" value="<?php echo $val('capacity') !== null ? esc_attr( $val('capacity') ) : ''; ?>" min="0" class="small-text">
                        <p class="description"><?php esc_html_e( 'Leave blank for unlimited.', 'societypress' ); ?></p></td>
                </tr>
                <tr>
                    <th><label for="opp_skills"><?php esc_html_e( 'Skills/Requirements', 'societypress' ); ?></label></th>
                    <td><textarea id="opp_skills" name="opp_skills" rows="2" class="large-text"><?php echo esc_textarea( $val('skills_needed') ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="opp_contact"><?php esc_html_e( 'Contact Person', 'societypress' ); ?></label></th>
                    <td>
                        <select id="opp_contact" name="opp_contact">
                            <option value=""><?php esc_html_e( '— None —', 'societypress' ); ?></option>
                            <?php foreach ( $members as $m ) : ?>
                                <option value="<?php echo esc_attr( $m->user_id ); ?>" <?php selected( $val('contact_user_id'), $m->user_id ); ?>>
                                    <?php echo esc_html( $m->last_name . ', ' . $m->first_name ); ?>
                                </option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="opp_status"><?php esc_html_e( 'Status', 'societypress' ); ?></label></th>
                    <td>
                        <select id="opp_status" name="opp_status">
                            <option value="open" <?php selected( $val('status', 'open'), 'open' ); ?>><?php esc_html_e( 'Open', 'societypress' ); ?></option>
                            <option value="filled" <?php selected( $val('status'), 'filled' ); ?>><?php esc_html_e( 'Filled', 'societypress' ); ?></option>
                            <option value="closed" <?php selected( $val('status'), 'closed' ); ?>><?php esc_html_e( 'Closed', 'societypress' ); ?></option>
                            <option value="cancelled" <?php selected( $val('status'), 'cancelled' ); ?>><?php esc_html_e( 'Cancelled', 'societypress' ); ?></option>
                        </select>
                    </td>
                </tr>
            </table>

            <?php submit_button( $opp ? __( 'Update Opportunity', 'societypress' ) : __( 'Create Opportunity', 'societypress' ) ); ?>
        </form>

        <?php
        // Show signups for existing opportunity
        if ( $opp ) {
            $signups = $wpdb->get_results( $wpdb->prepare(
                "SELECT s.*, u.display_name, m.first_name, m.last_name
                 FROM {$prefix}volunteer_signups s
                 LEFT JOIN {$wpdb->users} u ON s.user_id = u.ID
                 LEFT JOIN {$prefix}members m ON s.user_id = m.user_id
                 WHERE s.opportunity_id = %d
                 ORDER BY FIELD(s.status, 'confirmed', 'waitlisted', 'cancelled'), s.signed_up_at ASC",
                $opp->id
            ) );
            if ( ! empty( $signups ) ) : ?>
                <h2 style="margin-top: 30px; border-bottom: 1px solid #c3c4c7; padding-bottom: 8px;"><?php echo esc_html( sprintf( __( 'Signups (%d)', 'societypress' ), count( $signups ) ) ); ?></h2>
                <table class="wp-list-table widefat fixed striped">
                    <thead><tr><th><?php esc_html_e( 'Name', 'societypress' ); ?></th><th><?php esc_html_e( 'Status', 'societypress' ); ?></th><th><?php esc_html_e( 'Signed Up', 'societypress' ); ?></th></tr></thead>
                    <tbody>
                    <?php foreach ( $signups as $s ) :
                        $name = $s->first_name ? $s->first_name . ' ' . $s->last_name : $s->display_name;
                        $badge = [ 'confirmed' => '#00a32a', 'waitlisted' => '#dba617', 'cancelled' => '#d63638' ];
                    ?>
                        <tr>
                            <td><?php echo esc_html( $name ); ?></td>
                            <td><span style="display:inline-block;padding:2px 8px;border-radius:3px;background:<?php echo ($badge[$s->status] ?? '#787c82') . '22'; ?>;color:<?php echo $badge[$s->status] ?? '#787c82'; ?>;font-size:12px;"><?php echo esc_html( ucfirst( $s->status ) ); ?></span></td>
                            <td><?php echo esc_html( date_i18n( 'M j, Y g:i A', strtotime( $s->signed_up_at ) ) ); ?></td>
                        </tr>
                    <?php endforeach; ?>
                    </tbody>
                </table>
            <?php endif;
        }
        ?>
    </div>
    <?php
}


// ============================================================================
// LEADERSHIP & COMMITTEES — ADMIN PAGE
//
// WHY: Officers (president, treasurer, etc.) and committee assignments are
//      governance-level roles, distinct from day-to-day volunteer work. This
//      page gives the admin a clear, card-based view of who holds officer
//      positions and which members serve on which committees. Data lives in
//      sp_volunteer_roles with role_type = 'officer' or 'committee'.
//      Volunteer roster assignments (role_type = 'volunteer') are on a
//      separate page.
// ============================================================================

function sp_render_leadership_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ------------------------------------------------------------------
    // FORM HANDLING: Save / Update officer or committee assignment
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_save_leadership'] ) && check_admin_referer( 'sp_leadership_save' ) ) {
        $role_id    = absint( $_POST['role_id'] ?? 0 );
        $user_id    = absint( $_POST['user_id'] ?? 0 );
        $role_title = sanitize_text_field( $_POST['role_title'] ?? '' );
        $committee  = sanitize_text_field( $_POST['committee'] ?? '' );
        $role_type  = sanitize_text_field( $_POST['role_type'] ?? 'officer' );
        $start_date = sanitize_text_field( $_POST['start_date'] ?? '' );
        $end_date   = sanitize_text_field( $_POST['end_date'] ?? '' );
        $status     = sanitize_text_field( $_POST['status'] ?? 'active' );

        // Validate role_type — only allow officer or committee on this page
        if ( ! in_array( $role_type, [ 'officer', 'committee' ], true ) ) {
            $role_type = 'officer';
        }

        if ( $user_id && $role_title ) {
            $data = [
                'user_id'    => $user_id,
                'role_title' => $role_title,
                'committee'  => $committee,
                'role_type'  => $role_type,
                'start_date' => $start_date ?: null,
                'end_date'   => $end_date ?: null,
                'status'     => $status,
            ];

            if ( $role_id ) {
                $wpdb->update( $prefix . 'volunteer_roles', $data, [ 'id' => $role_id ] );
                sp_audit( 'leadership_role_updated', sprintf( 'Leadership role "%s" updated for user #%d', $role_title, $user_id ), 'volunteer_role', $role_id );
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Role updated.', 'societypress' ) . '</p></div>';
            } else {
                $wpdb->insert( $prefix . 'volunteer_roles', $data );
                $new_id = (int) $wpdb->insert_id;
                sp_audit( 'leadership_role_created', sprintf( 'Leadership role "%s" created for user #%d', $role_title, $user_id ), 'volunteer_role', $new_id );
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Role added.', 'societypress' ) . '</p></div>';
            }
        } else {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a member and enter a position/role title.', 'societypress' ) . '</p></div>';
        }
    }

    // ------------------------------------------------------------------
    // DELETE HANDLING: Remove an officer or committee assignment
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_delete_leadership'] ) && ! empty( $_POST['delete_role_id'] ) ) {
        $del_id = absint( $_POST['delete_role_id'] );
        check_admin_referer( 'sp_delete_leadership_role_' . $del_id );
        $wpdb->delete( $prefix . 'volunteer_roles', [ 'id' => $del_id ] );
        sp_audit( 'leadership_role_deleted', sprintf( 'Leadership role #%d deleted', $del_id ), 'volunteer_role', $del_id );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Role deleted.', 'societypress' ) . '</p></div>';
    }

    // ------------------------------------------------------------------
    // LOAD DATA: Active members for dropdowns, officers, committee roles
    // ------------------------------------------------------------------

    // WHY: Server-side member search — when the admin types a name and
    // clicks "Filter", the page reloads with only matching members in
    // the dropdown. This avoids any dependency on JavaScript for search.
    $member_search = sanitize_text_field( $_GET['member_search'] ?? '' );

    // WHY: Each form (officer / committee) has its own member search.
    // Dropdowns start empty — the admin searches within the form they're
    // using, and only matching members appear in that dropdown.
    $officer_search   = sanitize_text_field( $_GET['officer_search'] ?? '' );
    $committee_search = sanitize_text_field( $_GET['committee_search'] ?? '' );

    // Build filtered member lists per form
    $officer_members   = [];
    $committee_members = [];

    if ( $officer_search ) {
        $like = '%' . $wpdb->esc_like( $officer_search ) . '%';
        $officer_members = $wpdb->get_results( $wpdb->prepare(
            "SELECT user_id, first_name, last_name FROM {$prefix}members
             WHERE status = 'active'
               AND (first_name LIKE %s OR last_name LIKE %s OR CONCAT(last_name, ', ', first_name) LIKE %s)
             ORDER BY last_name ASC",
            $like, $like, $like
        ) );
    }

    if ( $committee_search ) {
        $like = '%' . $wpdb->esc_like( $committee_search ) . '%';
        $committee_members = $wpdb->get_results( $wpdb->prepare(
            "SELECT user_id, first_name, last_name FROM {$prefix}members
             WHERE status = 'active'
               AND (first_name LIKE %s OR last_name LIKE %s OR CONCAT(last_name, ', ', first_name) LIKE %s)
             ORDER BY last_name ASC",
            $like, $like, $like
        ) );
    }

    // WHY: When editing an existing role, we need the assigned member in
    // the dropdown even without a search.
    $editing = null;
    $editing_section = '';
    if ( ( $_GET['action'] ?? '' ) === 'edit' && ! empty( $_GET['role_id'] ) ) {
        $editing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}volunteer_roles WHERE id = %d", absint( $_GET['role_id'] )
        ) );
        if ( $editing ) {
            $editing_section = $editing->role_type === 'committee' ? 'committee' : 'officer';
            $edit_member = $wpdb->get_results( $wpdb->prepare(
                "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE user_id = %d",
                $editing->user_id
            ) );
            if ( $editing_section === 'officer' && empty( $officer_members ) ) {
                $officer_members = $edit_member;
            } elseif ( $editing_section === 'committee' && empty( $committee_members ) ) {
                $committee_members = $edit_member;
            }
        }
    }

    // Officers: role_type = 'officer', ordered by status (active first) then start_date
    $officers = $wpdb->get_results(
        "SELECT vr.*, m.first_name, m.last_name
         FROM {$prefix}volunteer_roles vr
         INNER JOIN {$prefix}members m ON vr.user_id = m.user_id
         WHERE vr.role_type = 'officer'
         ORDER BY FIELD(vr.status, 'active', 'inactive'), vr.start_date DESC"
    );

    // Committee assignments: role_type = 'committee', grouped by committee name
    $committee_rows = $wpdb->get_results(
        "SELECT vr.*, m.first_name, m.last_name
         FROM {$prefix}volunteer_roles vr
         INNER JOIN {$prefix}members m ON vr.user_id = m.user_id
         WHERE vr.role_type = 'committee'
         ORDER BY vr.committee ASC, FIELD(vr.status, 'active', 'inactive'), m.last_name ASC"
    );

    // Group committee rows by the committee field for display
    $committees = [];
    foreach ( $committee_rows as $row ) {
        $key = $row->committee ?: __( '(Unassigned)', 'societypress' );
        $committees[ $key ][] = $row;
    }

    // Badge color helper — used in both sections
    // WHY: Background and text color are dynamic (driven by status value),
    // so these two properties must stay inline. The structural shape of the
    // badge (display, padding, border-radius, font-size, font-weight) is
    // extracted to sp-leadership-status-badge in the <style> block above.
    $status_badge = function ( string $status ): string {
        $colors = [
            'active'   => [ 'bg' => '#00a32a22', 'text' => '#00a32a' ],
            'inactive' => [ 'bg' => '#b32d2e22', 'text' => '#b32d2e' ],
        ];
        $c = $colors[ $status ] ?? [ 'bg' => '#78788222', 'text' => '#787882' ];
        return '<span class="sp-leadership-status-badge" style="background:' . $c['bg'] . ';color:' . $c['text'] . ';">' . esc_html( ucfirst( $status ) ) . '</span>';
    };

