// ============================================================================
// Render: Committees — Dedicated Admin Page
//
// WHY: Committees are important enough to warrant their own menu entry. This
//      page shows only the committee management portion of the Leadership page
//      — committee definitions, member assignments, chair/co-chair roles.
//      Officers and board positions remain on the Leadership & Committees page.
// ============================================================================

function sp_render_committees_page(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'You do not have permission to access this page.', 'societypress' ) );
    }
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ------------------------------------------------------------------
    // FORM HANDLING: Save / Delete committee
    // ------------------------------------------------------------------
    if ( isset( $_POST['sp_save_committee'] ) && check_admin_referer( 'sp_committee_save' ) ) {
        $committee_id = absint( $_POST['committee_id'] ?? 0 );
        $data = [
            'committee'   => sanitize_text_field( $_POST['committee_name'] ?? '' ),
            'description' => sanitize_textarea_field( $_POST['committee_description'] ?? '' ) ?: null,
            'status'      => sanitize_text_field( $_POST['committee_status'] ?? 'active' ),
        ];

        if ( ! empty( $data['committee'] ) ) {
            if ( $committee_id ) {
                // Update existing committee assignments' committee name
                $old_name = $wpdb->get_var( $wpdb->prepare(
                    "SELECT committee FROM {$prefix}volunteer_roles WHERE id = %d", $committee_id
                ) );
                if ( $old_name && $old_name !== $data['committee'] ) {
                    $wpdb->update(
                        $prefix . 'volunteer_roles',
                        [ 'committee' => $data['committee'] ],
                        [ 'committee' => $old_name, 'role_type' => 'committee' ]
                    );
                }
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Committee updated.', 'societypress' ) . '</p></div>';
            } else {
                // Create a placeholder committee role so the committee name exists
                $wpdb->insert( $prefix . 'volunteer_roles', [
                    'user_id'    => 0,
                    'role_title' => __( 'Member', 'societypress' ),
                    'committee'  => $data['committee'],
                    'role_type'  => 'committee',
                    'status'     => $data['status'],
                ] );
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Committee created.', 'societypress' ) . '</p></div>';
            }
        }
    }

    // Delete committee
    if ( isset( $_POST['sp_delete_committee'] ) && check_admin_referer( 'sp_committee_delete' ) ) {
        $committee_name = sanitize_text_field( $_POST['committee_name_delete'] ?? '' );
        if ( $committee_name ) {
            $wpdb->delete( $prefix . 'volunteer_roles', [
                'committee' => $committee_name,
                'role_type' => 'committee',
            ] );
            echo '<div class="notice notice-success"><p>' . esc_html__( 'Committee deleted.', 'societypress' ) . '</p></div>';
        }
    }

    // ------------------------------------------------------------------
    // DATA: Fetch committees grouped by name
    // ------------------------------------------------------------------
    $committees = $wpdb->get_results(
        "SELECT DISTINCT committee
         FROM {$prefix}volunteer_roles
         WHERE role_type = 'committee' AND committee IS NOT NULL AND committee != ''
         ORDER BY committee ASC"
    );

    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Committees', 'societypress' ); ?></h1>
        <hr class="wp-header-end">

        <p class="description">
            <?php esc_html_e( 'Manage your society\'s committees. Assign members as chairs, co-chairs, or committee members. Committee chairs with auto-permissions enabled will automatically get access to their area.', 'societypress' ); ?>
        </p>

        <?php if ( empty( $committees ) ) : ?>
            <div class="notice notice-info">
                <p><?php esc_html_e( 'No committees have been created yet. You can create committees on the Leadership & Committees page, or use the form below.', 'societypress' ); ?></p>
            </div>
        <?php else : ?>
            <?php foreach ( $committees as $c ) :
                $members = $wpdb->get_results( $wpdb->prepare(
                    "SELECT vr.*, u.display_name
                     FROM {$prefix}volunteer_roles vr
                     LEFT JOIN {$wpdb->users} u ON vr.user_id = u.ID
                     WHERE vr.committee = %s AND vr.role_type = 'committee' AND vr.user_id > 0
                     ORDER BY FIELD(vr.role_title, 'Chair', 'Co-Chair', 'Member'), u.display_name ASC",
                    $c->committee
                ) );
            ?>
                <div class="sp-committee-card" style="background:#fff; border:1px solid #ccd0d4; border-radius:4px; padding:16px 20px; margin:16px 0;">
                    <h3 style="margin:0 0 8px;"><?php echo esc_html( $c->committee ); ?></h3>
                    <?php if ( $members ) : ?>
                        <table class="widefat striped" style="margin-top:8px;">
                            <thead>
                                <tr>
                                    <th><?php esc_html_e( 'Member', 'societypress' ); ?></th>
                                    <th><?php esc_html_e( 'Role', 'societypress' ); ?></th>
                                    <th><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                                </tr>
                            </thead>
                            <tbody>
                                <?php foreach ( $members as $m ) : ?>
                                    <tr>
                                        <td><?php echo esc_html( $m->display_name ?: __( '(unassigned)', 'societypress' ) ); ?></td>
                                        <td><?php echo esc_html( $m->role_title ); ?></td>
                                        <td><?php echo esc_html( ucfirst( $m->status ) ); ?></td>
                                    </tr>
                                <?php endforeach; ?>
                            </tbody>
                        </table>
                    <?php else : ?>
                        <p class="description"><?php esc_html_e( 'No members assigned yet.', 'societypress' ); ?></p>
                    <?php endif; ?>
                    <p style="margin:8px 0 0;">
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-governance' ) ); ?>" class="button button-small">
                            <?php esc_html_e( 'Manage Members', 'societypress' ); ?>
                        </a>
                    </p>
                </div>
            <?php endforeach; ?>
        <?php endif; ?>

        <p>
            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-governance' ) ); ?>" class="button button-primary">
                <?php esc_html_e( 'Go to Leadership & Committees', 'societypress' ); ?>
            </a>
        </p>
    </div>
    <?php
}

function sp_render_volunteers_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle form submission for add/edit
    if ( isset( $_POST['sp_save_volunteer_role'] ) && check_admin_referer( 'sp_volunteer_role_save' ) ) {
        $role_id    = absint( $_POST['role_id'] ?? 0 );
        $user_id    = absint( $_POST['user_id'] ?? 0 );
        $role_title = sanitize_text_field( $_POST['role_title'] ?? '' );
        $committee  = sanitize_text_field( $_POST['committee'] ?? '' );
        $role_type  = sanitize_text_field( $_POST['role_type'] ?? 'volunteer' );
        $start_date = sanitize_text_field( $_POST['start_date'] ?? '' );
        $end_date   = sanitize_text_field( $_POST['end_date'] ?? '' );
        $status     = sanitize_text_field( $_POST['status'] ?? 'active' );

        if ( $user_id && $role_title ) {
            $data = [
                'user_id'    => $user_id,
                'role_title' => $role_title,
                'committee'  => $committee,
                'role_type'  => $role_type,
                'start_date' => $start_date ?: null,
                'end_date'   => $end_date ?: null,
                'status'     => $status,
            ];

            if ( $role_id ) {
                $wpdb->update( $prefix . 'volunteer_roles', $data, [ 'id' => $role_id ] );
                sp_audit( 'volunteer_role_updated', sprintf( 'Volunteer role "%s" updated for user #%d', $role_title, $user_id ), 'volunteer_role', $role_id );
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Volunteer role updated.', 'societypress' ) . '</p></div>';
            } else {
                $wpdb->insert( $prefix . 'volunteer_roles', $data );
                $new_role_id = (int) $wpdb->insert_id;
                sp_audit( 'volunteer_role_created', sprintf( 'Volunteer role "%s" created for user #%d', $role_title, $user_id ), 'volunteer_role', $new_role_id );
                echo '<div class="notice notice-success"><p>' . esc_html__( 'Volunteer role added.', 'societypress' ) . '</p></div>';
            }
        } else {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a member and enter a role title.', 'societypress' ) . '</p></div>';
        }
    }

    // Load edit data if editing
    $editing = null;
    if ( ( $_GET['action'] ?? '' ) === 'edit' && ! empty( $_GET['role_id'] ) ) {
        $editing = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}volunteer_roles WHERE id = %d", absint( $_GET['role_id'] )
        ) );
    }

    // Get members for the dropdown
    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name ASC"
    );

    $table = new SP_Volunteers_List_Table();
    $table->prepare_items();
    ?>
    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Volunteer Roster', 'societypress' ); ?></h1>
        <hr class="wp-header-end">

        <!-- Add/Edit form -->
        <div class="sp-card">
            <h3 class="sp-mt-0"><?php echo $editing ? esc_html__( 'Edit Role Assignment', 'societypress' ) : esc_html__( 'Add Volunteer Role', 'societypress' ); ?></h3>
            <form method="post">
                <?php wp_nonce_field( 'sp_volunteer_role_save' ); ?>
                <input type="hidden" name="role_id" value="<?php echo $editing ? $editing->id : 0; ?>">
                <input type="hidden" name="role_type" value="volunteer">

                <table class="form-table">
                    <tr>
                        <th><label for="user_id"><?php esc_html_e( 'Member', 'societypress' ); ?></label></th>
                        <td>
                            <select name="user_id" id="user_id" required style="min-width:250px;">
                                <option value=""><?php echo '— ' . esc_html__( 'Select Member', 'societypress' ) . ' —'; ?></option>
                                <?php foreach ( $members as $m ) : ?>
                                    <option value="<?php echo $m->user_id; ?>" <?php selected( $editing->user_id ?? 0, $m->user_id ); ?>>
                                        <?php echo esc_html( $m->last_name . ', ' . $m->first_name ); ?>
                                    </option>
                                <?php endforeach; ?>
                            </select>
                        </td>
                    </tr>
                    <tr>
                        <th><label for="role_title"><?php esc_html_e( 'Role Title', 'societypress' ); ?></label></th>
                        <td><input type="text" name="role_title" id="role_title" value="<?php echo esc_attr( $editing->role_title ?? '' ); ?>" class="regular-text" required placeholder="e.g., Event Coordinator"></td>
                    </tr>
                    <tr>
                        <th><label for="committee"><?php esc_html_e( 'Committee', 'societypress' ); ?></label></th>
                        <td><input type="text" name="committee" id="committee" value="<?php echo esc_attr( $editing->committee ?? '' ); ?>" class="regular-text" placeholder="e.g., Programs Committee"></td>
                    </tr>
                    <tr>
                        <th><label for="start_date"><?php esc_html_e( 'Start Date', 'societypress' ); ?></label></th>
                        <td><input type="date" name="start_date" id="start_date" value="<?php echo esc_attr( $editing->start_date ?? '' ); ?>"></td>
                    </tr>
                    <tr>
                        <th><label for="end_date"><?php esc_html_e( 'End Date', 'societypress' ); ?></label></th>
                        <td><input type="date" name="end_date" id="end_date" value="<?php echo esc_attr( $editing->end_date ?? '' ); ?>"> <span class="description"><?php esc_html_e( 'Leave blank for ongoing roles.', 'societypress' ); ?></span></td>
                    </tr>
                    <tr>
                        <th><label for="vstatus"><?php esc_html_e( 'Status', 'societypress' ); ?></label></th>
                        <td>
                            <select name="status" id="vstatus">
                                <option value="active" <?php selected( $editing->status ?? 'active', 'active' ); ?>><?php esc_html_e( 'Active', 'societypress' ); ?></option>
                                <option value="inactive" <?php selected( $editing->status ?? '', 'inactive' ); ?>><?php esc_html_e( 'Inactive', 'societypress' ); ?></option>
                            </select>
                        </td>
                    </tr>
                </table>
                <p class="submit">
                    <input type="submit" name="sp_save_volunteer_role" class="button button-primary" value="<?php echo $editing ? esc_attr__( 'Update Role', 'societypress' ) : esc_attr__( 'Add Role', 'societypress' ); ?>">
                    <?php if ( $editing ) : ?>
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-volunteer-roster' ) ); ?>" class="button"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
                    <?php endif; ?>
                </p>
            </form>
        </div>

        <!-- Volunteer roster table -->
        <form method="get">
            <input type="hidden" name="page" value="sp-volunteer-roster">
            <?php
            $table->search_box( __( 'Search Volunteers', 'societypress' ), 'volunteer_search' );
            $table->display();
            ?>
        </form>
    </div>
    <?php
}

/**
 * Render: Volunteer Hours Page
 *
 * WHY: Admin page for logging and viewing volunteer hours. Has an inline
 *      add form and a summary stats bar at the top showing totals.
 */
function sp_render_volunteer_hours_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle form submission
    if ( isset( $_POST['sp_log_volunteer_hours'] ) && check_admin_referer( 'sp_volunteer_hours_save' ) ) {
        $user_id       = absint( $_POST['user_id'] ?? 0 );
        $activity      = sanitize_text_field( $_POST['activity'] ?? '' );
        $committee     = sanitize_text_field( $_POST['committee'] ?? '' );
        $hours         = floatval( $_POST['hours'] ?? 0 );
        $activity_date = sanitize_text_field( $_POST['activity_date'] ?? '' );

        if ( $user_id && $hours > 0 ) {
            $wpdb->insert( $prefix . 'volunteer_hours', [
                'user_id'       => $user_id,
                'activity'      => $activity,
                'committee'     => $committee,
                'hours'         => $hours,
                'activity_date' => $activity_date ?: current_time( 'Y-m-d' ),
                'recorded_by'   => get_current_user_id(),
            ] );
            echo '<div class="notice notice-success"><p>' . esc_html__( 'Hours logged successfully.', 'societypress' ) . '</p></div>';
        } else {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a member and enter hours greater than 0.', 'societypress' ) . '</p></div>';
        }
    }

    // Summary stats
    $year_start   = wp_date( 'Y-01-01' );
    $total_hours  = (float) $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(hours), 0) FROM {$prefix}volunteer_hours WHERE activity_date >= %s", $year_start
    ) );
    $total_volunteers = (int) $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(DISTINCT user_id) FROM {$prefix}volunteer_hours WHERE activity_date >= %s", $year_start
    ) );

    $members = $wpdb->get_results(
        "SELECT user_id, first_name, last_name FROM {$prefix}members WHERE status = 'active' ORDER BY last_name ASC"
    );

    $table = new SP_VolunteerHours_List_Table();
    $table->prepare_items();
    ?>
    <style>
        /* ----------------------------------------------------------------
         * sp_render_volunteer_hours_page() — scoped admin page styles
         *
         * WHY: Moved from inline style= attributes to named classes so
         * future devs can find and adjust layout in one place rather than
         * hunting through HTML. All classes are prefixed sp-vol-hours- to
         * avoid collisions with WP core or other admin styles.
         * ---------------------------------------------------------------- */

        /* Stats row: flexbox strip holding the two summary cards */
        .sp-vol-hours-stats-row {
            display: flex;
            gap: 16px;
            margin: 16px 0;
        }

        /* Individual summary stat card (Hours This Year / Active Volunteers) */
        .sp-vol-hours-stat-card {
            background: #fff;
            border: 1px solid #ccd0d4;
            border-radius: 4px;
            padding: 16px 24px;
            flex: 1;
            text-align: center;
        }

        /* Large number displayed inside a stat card */
        .sp-vol-hours-stat-number {
            font-size: 28px;
            font-weight: 700;
            color: var(--sp-color-primary);
        }

        /* Descriptive label below the stat number */
        .sp-vol-hours-stat-label {
            color: #666;
            font-size: 13px;
        }

        /* Log Hours panel container */
        .sp-vol-hours-log-panel {
            background: #fff;
            border: 1px solid #ccd0d4;
            border-radius: 4px;
            padding: 20px;
            margin: 16px 0;
        }

        /* Section heading inside the log panel — reset default top margin */
        .sp-vol-hours-log-heading {
            margin-top: 0;
        }

        /* The inline log-hours form — flex row that wraps on narrow screens */
        .sp-vol-hours-log-form {
            display: flex;
            flex-wrap: wrap;
            gap: 12px;
            align-items: flex-end;
        }

        /* Labels for every field in the log-hours form */
        .sp-vol-hours-field-label {
            display: block;
            font-weight: 600;
            margin-bottom: 4px;
        }

        /* Member dropdown — slightly wider than a default select */
        .sp-vol-hours-select-member {
            min-width: 200px;
        }

        /* Activity text input */
        .sp-vol-hours-input-activity {
            width: 200px;
        }

        /* Committee text input — narrower than Activity */
        .sp-vol-hours-input-committee {
            width: 150px;
        }

        /* Hours number input — tight width for a numeric value */
        .sp-vol-hours-input-hours {
            width: 80px;
        }
    </style>

    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Volunteer Hours', 'societypress' ); ?></h1>

        <!-- Export CSV link -->
        <a href="<?php echo esc_url( wp_nonce_url( admin_url( 'admin.php?page=sp-volunteer-hours&action=export_csv' ), 'sp_export_volunteer_hours' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Export CSV', 'societypress' ); ?></a>
        <hr class="wp-header-end">

        <!-- Summary stats -->
        <div class="sp-vol-hours-stats-row">
            <div class="sp-vol-hours-stat-card">
                <div class="sp-vol-hours-stat-number"><?php echo number_format( $total_hours, 1 ); ?></div>
                <div class="sp-vol-hours-stat-label"><?php esc_html_e( 'Hours This Year', 'societypress' ); ?></div>
            </div>
            <div class="sp-vol-hours-stat-card">
                <div class="sp-vol-hours-stat-number"><?php echo $total_volunteers; ?></div>
                <div class="sp-vol-hours-stat-label"><?php esc_html_e( 'Active Volunteers', 'societypress' ); ?></div>
            </div>
        </div>

        <!-- Log hours form -->
        <div class="sp-vol-hours-log-panel">
            <h3 class="sp-vol-hours-log-heading"><?php esc_html_e( 'Log Hours', 'societypress' ); ?></h3>
            <form method="post" class="sp-vol-hours-log-form">
                <?php wp_nonce_field( 'sp_volunteer_hours_save' ); ?>
                <div>
                    <label class="sp-vol-hours-field-label"><?php esc_html_e( 'Member', 'societypress' ); ?></label>
                    <select name="user_id" required class="sp-vol-hours-select-member">
                        <option value=""><?php esc_html_e( '— Select —', 'societypress' ); ?></option>
                        <?php foreach ( $members as $m ) : ?>
                            <option value="<?php echo $m->user_id; ?>"><?php echo esc_html( $m->last_name . ', ' . $m->first_name ); ?></option>
                        <?php endforeach; ?>
                    </select>
                </div>
