                // so the admin knows what's available.
                if ( $active_tab === 'donation_acknowledgment' ) {
                    // Donation-specific merge tags — donors aren't always members,
                    // so we use a separate set tailored to donation data.
                    $merge_tags = [
                        '{{donor_name}}'        => __( 'Donor name', 'societypress' ),
                        '{{donor_email}}'       => __( 'Donor email', 'societypress' ),
                        '{{amount}}'            => __( 'Donation amount (formatted)', 'societypress' ),
                        '{{campaign}}'          => __( 'Campaign name', 'societypress' ),
                        '{{donation_date}}'     => __( 'Date of donation', 'societypress' ),
                        '{{donation_type}}'     => __( 'Donation type (cash, check, etc.)', 'societypress' ),
                        '{{in_kind_description}}' => __( 'In-kind item description', 'societypress' ),
                        '{{organization_name}}' => __( 'Organization name', 'societypress' ),
                        '{{site_url}}'          => __( 'Website URL', 'societypress' ),
                        '{{admin_email}}'       => __( 'Admin email address', 'societypress' ),
                    ];
                } else {
                    $merge_tags = [
                        '{{first_name}}'            => __( 'First name', 'societypress' ),
                        '{{last_name}}'             => __( 'Last name', 'societypress' ),
                        '{{full_name}}'             => __( 'Full name', 'societypress' ),
                        '{{preferred_name}}'        => __( 'Preferred name (or first name)', 'societypress' ),
                        '{{email}}'                 => __( 'Member email', 'societypress' ),
                        '{{tier}}'                  => __( 'Membership tier name', 'societypress' ),
                        '{{status}}'                => __( 'Membership status', 'societypress' ),
                        '{{join_date}}'             => __( 'Join date', 'societypress' ),
                        '{{expiration_date}}'       => __( 'Expiration date', 'societypress' ),
                        '{{days_until_expiration}}' => __( 'Days until expiration', 'societypress' ),
                        '{{days}}'                  => __( 'Days (shorthand)', 'societypress' ),
                        '{{organization_name}}'     => __( 'Organization name', 'societypress' ),
                        '{{site_url}}'              => __( 'Website URL', 'societypress' ),
                        '{{admin_email}}'           => __( 'Admin email address', 'societypress' ),
                    ];
                }
                foreach ( $merge_tags as $tag => $desc ) :
                ?>
                    <div style="margin-bottom: 6px; cursor: pointer;" class="sp-merge-tag-item"
                         data-tag="<?php echo esc_attr( $tag ); ?>"
                         title="<?php echo esc_attr( $desc ); ?>">
                        <code style="background: #fff; border: 1px solid #ddd; padding: 2px 6px; border-radius: 3px; font-size: 12px; display: inline-block;">
                            <?php echo esc_html( $tag ); ?>
                        </code>
                        <span style="font-size: 12px; color: #646970; margin-left: 4px;">
                            <?php echo esc_html( $desc ); ?>
                        </span>
                    </div>
                <?php endforeach; ?>
            </div>

        </div><!-- .flex wrapper -->
    </div><!-- .wrap -->

    <script>
    // WHY vanilla JS: Project policy — no jQuery. Two behaviors:
    // 1. Click-to-copy on merge tags so the admin can paste them into the editor.
    // 2. Reset button loads the default template via a hidden data attribute.
    (function() {
        // --- Click-to-copy merge tags ---
        document.querySelectorAll('.sp-merge-tag-item').forEach(function(el) {
            el.addEventListener('click', function() {
                var tag = this.getAttribute('data-tag');
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(tag).then(function() {
                        // Brief visual feedback
                        var code = el.querySelector('code');
                        var orig = code.style.background;
                        code.style.background = '#e0f0e0';
                        setTimeout(function() { code.style.background = orig; }, 600);
                    });
                } else {
                    // Fallback for older browsers
                    var ta = document.createElement('textarea');
                    ta.value = tag;
                    ta.style.position = 'fixed';
                    ta.style.left = '-9999px';
                    document.body.appendChild(ta);
                    ta.select();
                    document.execCommand('copy');
                    document.body.removeChild(ta);
                }
            });
        });

        // --- Reset to default ---
        var resetBtn = document.getElementById('sp-reset-template');
        if (resetBtn) {
            resetBtn.addEventListener('click', function() {
                spConfirm(<?php echo wp_json_encode( __( 'Reset this template to the default? Your customizations will be lost.', 'societypress' ) ); ?>, function() {
                // Fetch the default template via AJAX
                var formData = new FormData();
                formData.append('action', 'sp_get_default_template');
                formData.append('type', <?php echo wp_json_encode( $active_tab ); ?>);
                formData.append('_wpnonce', <?php echo wp_json_encode( wp_create_nonce( 'sp_default_template' ) ); ?>);

                fetch(ajaxurl, { method: 'POST', body: formData })
                    .then(function(r) { return r.json(); })
                    .then(function(data) {
                        if (data.success) {
                            // Update subject
                            var subjField = document.getElementById(<?php echo wp_json_encode( $subj_key ); ?>);
                            if (subjField) subjField.value = data.data.subject;

                            // Update TinyMCE editor or textarea
                            var editorId = <?php echo wp_json_encode( $body_key ); ?>;
                            if (typeof tinymce !== 'undefined' && tinymce.get(editorId)) {
                                tinymce.get(editorId).setContent(data.data.body);
                            } else {
                                var ta = document.getElementById(editorId);
                                if (ta) ta.value = data.data.body;
                            }
                        }
                    });
            });
        }
    })();
    </script>
    <?php
}

/**
 * AJAX handler: return default email template content for the reset button.
 *
 * WHY: The reset button needs to restore the factory default without a page
 *      reload. This endpoint returns the default subject and body for a
 *      given template type so JavaScript can inject them into the editor.
 */
add_action( 'wp_ajax_sp_get_default_template', function() {
    check_ajax_referer( 'sp_default_template' );

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_send_json_error( __( 'Unauthorized', 'societypress' ), 403 );
    }

    $type = sanitize_key( $_POST['type'] ?? '' );

    $default_subjects = [
        'welcome'                 => __( 'Welcome to {{organization_name}}!', 'societypress' ),
        'renewal_reminder'        => __( 'Your membership expires soon', 'societypress' ),
        'expired'                 => __( 'Your membership has expired', 'societypress' ),
        'donation_acknowledgment' => __( 'Thank You for Your Donation — {{organization_name}}', 'societypress' ),
    ];

    if ( ! isset( $default_subjects[ $type ] ) ) {
        wp_send_json_error( __( 'Invalid type', 'societypress' ), 400 );
    }

    wp_send_json_success( [
        'subject' => $default_subjects[ $type ],
        'body'    => sp_get_default_email_template( $type ),
    ] );
} );


// ============================================================================
// EMAIL LOG — ADMIN PAGE
// ============================================================================
//
// WHY: Admins need to see what emails went out, whether they were delivered,
//      and what they contained. This page provides a searchable, filterable
//      list of all emails with status indicators and a detail view.
// ============================================================================

/**
 * Render the Email Log admin page.
 *
 * WHY: Provides the admin interface for reviewing all outgoing emails.
 *      Shows status (sent/blocked/failed), recipient, subject, date, and
 *      type. Supports filtering by status and type, search by recipient
 *      or subject, and pagination. Clicking a row shows the full email body.
 */
function sp_render_email_log_page(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_email_log';

    // Check if viewing a single email detail
    $view_id = isset( $_GET['view'] ) ? absint( $_GET['view'] ) : 0;

    if ( $view_id ) {
        sp_render_email_log_detail( $view_id );
        return;
    }

    // Gather filter parameters
    $current_status = sanitize_text_field( $_GET['status'] ?? '' );
    $current_type   = sanitize_text_field( $_GET['email_type'] ?? '' );
    $search         = sanitize_text_field( $_GET['s'] ?? '' );
    $paged          = max( 1, absint( $_GET['paged'] ?? 1 ) );
    $per_page       = 20;

    // Fetch results
    $result = sp_email_log_get_list( [
        'status'     => $current_status,
        'email_type' => $current_type,
        'search'     => $search,
        'per_page'   => $per_page,
        'page'       => $paged,
    ] );

    $items      = $result['items'];
    $total      = $result['total'];
    $total_pages = ceil( $total / $per_page );

    // Get stats for the summary cards
    $stats = sp_email_log_get_stats( 30 );

    // Get email types for the filter dropdown
    $email_types = sp_email_log_get_types();

    $base_url = admin_url( 'admin.php?page=sp-email-log' );

    ?>
    <style>
        /*
         * WHY: All static presentational styles for the Email Log admin page
         * are collected here rather than scattered as inline style= attributes.
         * This makes them easier to override, maintain, and audit. Dynamic
         * per-row values (badge colors driven by PHP variables) remain inline
         * because they cannot be expressed as static CSS.
         */

        /* Stats row — flex container for the four summary cards */
        .sp-email-log-stats-row {
            display: flex;
            gap: 16px;
            margin: 20px 0;
        }

        /* Base card shared by all four stat cards */
        .sp-email-log-stat-card {
            background: #fff;
            border: 1px solid #c3c4c7;
            padding: 12px 20px;
            min-width: 120px;
        }

        /* Accent left-border per status — mirrors WP admin notice palette */
        .sp-email-log-stat-sent    { border-left: 4px solid #00a32a; }
        .sp-email-log-stat-blocked { border-left: 4px solid #dba617; }
        .sp-email-log-stat-failed  { border-left: 4px solid #d63638; }
        .sp-email-log-stat-total   { border-left: 4px solid #2271b1; }

        /* Large count number inside each stat card */
        .sp-email-log-stat-number {
            font-size: 24px;
            font-weight: 600;
        }

        /* Color per status for the count number */
        .sp-email-log-stat-sent-num    { color: #00a32a; }
        .sp-email-log-stat-blocked-num { color: #dba617; }
        .sp-email-log-stat-failed-num  { color: #d63638; }
        .sp-email-log-stat-total-num   { color: #2271b1; }

        /* "Sent (30d)" label beneath the number */
        .sp-email-log-stat-label {
            color: #50575e;
            font-size: 13px;
        }

        /* Dev-mode warning notice — tighten WP default margin */
        .sp-email-log-notice {
            margin: 10px 0;
        }

        /* Filter bar — lays out selects, search box, and button in a row */
        .sp-email-log-filters {
            display: flex;
            align-items: center;
            gap: 8px;
        }

        /* Search input width — wide enough for a typical email address + subject */
        .sp-email-log-search {
            width: 250px;
        }

        /* Item count ("123 items") pushed to the far right of the filter bar */
        .sp-email-log-count {
            margin-left: auto;
        }

        /* Fixed-width table columns — prevents layout shift as data changes */
        .sp-email-log-col-id     { width: 50px; }
        .sp-email-log-col-status { width: 80px; }
        .sp-email-log-col-type   { width: 100px; }
        .sp-email-log-col-date   { width: 160px; }

        /* Empty-state message when no log entries exist */
        .sp-email-log-empty {
            text-align: center;
            padding: 20px;
            color: #50575e;
        }

        /* Type column — de-emphasised smaller text */
        .sp-email-log-type-cell {
            color: #50575e;
            font-size: 12px;
        }

        /* Recipient link — slightly heavier weight to act as the row's primary anchor */
        .sp-email-log-recipient-link {
            font-weight: 500;
        }

        /* Date column — slightly smaller, de-emphasised */
        .sp-email-log-date-cell {
            color: #50575e;
            font-size: 13px;
        }

        /*
         * Status badge — structural/shape styles only.
         * WHY: Background, text color, and border color are driven by PHP
         * variables ($bc[]) resolved at row render time and must stay inline.
         * The structural styles here are static and safe to centralise.
         */
        .sp-email-log-badge {
            display: inline-block;
            padding: 2px 8px;
            border-radius: 3px;
            font-size: 12px;
            font-weight: 500;
        }
    </style>

    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Email Log', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin-ajax.php?action=sp_export_email_log&nonce=' . wp_create_nonce( 'sp_export_email_log' ) ) ); ?>" class="page-title-action"><?php esc_html_e( 'Export CSV', 'societypress' ); ?></a>
        <hr class="wp-header-end">

        <!-- Stats cards -->
        <div class="sp-email-log-stats-row">
            <div class="sp-email-log-stat-card sp-email-log-stat-sent">
                <div class="sp-email-log-stat-number sp-email-log-stat-sent-num"><?php echo esc_html( $stats['sent'] ); ?></div>
                <div class="sp-email-log-stat-label">Sent (30d)</div>
            </div>
            <div class="sp-email-log-stat-card sp-email-log-stat-blocked">
                <div class="sp-email-log-stat-number sp-email-log-stat-blocked-num"><?php echo esc_html( $stats['blocked'] ); ?></div>
                <div class="sp-email-log-stat-label">Blocked (30d)</div>
            </div>
            <div class="sp-email-log-stat-card sp-email-log-stat-failed">
                <div class="sp-email-log-stat-number sp-email-log-stat-failed-num"><?php echo esc_html( $stats['failed'] ); ?></div>
                <div class="sp-email-log-stat-label">Failed (30d)</div>
            </div>
            <div class="sp-email-log-stat-card sp-email-log-stat-total">
                <div class="sp-email-log-stat-number sp-email-log-stat-total-num"><?php echo esc_html( $stats['total'] ); ?></div>
                <div class="sp-email-log-stat-label">Total (30d)</div>
            </div>
        </div>

        <?php if ( sp_email_should_block() ) : ?>
            <div class="notice notice-warning sp-email-log-notice">
                <p><strong>Dev Mode Active:</strong> Emails are being logged but <strong>not sent</strong>. Define <code>SOCIETYPRESS_ALLOW_EMAILS</code> as <code>true</code> to override.</p>
            </div>
        <?php endif; ?>

        <!-- Filters -->
        <form method="get" action="<?php echo esc_url( $base_url ); ?>">
            <input type="hidden" name="page" value="sp-email-log">
            <div class="tablenav top sp-email-log-filters">
                <select name="status">
                    <option value=""><?php esc_html_e( 'All Statuses', 'societypress' ); ?></option>
                    <?php foreach ( [ 'sent', 'blocked', 'failed', 'pending' ] as $s ) : ?>
                        <option value="<?php echo esc_attr( $s ); ?>" <?php selected( $current_status, $s ); ?>>
                            <?php echo esc_html( ucfirst( $s ) ); ?>
                        </option>
                    <?php endforeach; ?>
                </select>

                <?php if ( ! empty( $email_types ) ) : ?>
                    <select name="email_type">
                        <option value=""><?php esc_html_e( 'All Types', 'societypress' ); ?></option>
                        <?php foreach ( $email_types as $type ) : ?>
                            <option value="<?php echo esc_attr( $type ); ?>" <?php selected( $current_type, $type ); ?>>
                                <?php echo esc_html( ucfirst( str_replace( '_', ' ', $type ) ) ); ?>
                            </option>
                        <?php endforeach; ?>
                    </select>
                <?php endif; ?>

                <input type="search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php echo esc_attr__( 'Search recipient or subject...', 'societypress' ); ?>" class="sp-email-log-search">
                <button type="submit" class="button"><?php esc_html_e( 'Filter', 'societypress' ); ?></button>

                <?php if ( $current_status || $current_type || $search ) : ?>
                    <a href="<?php echo esc_url( $base_url ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>

                <span class="displaying-num sp-email-log-count">
                    <?php echo sprintf( _n( '%d item', '%d items', $total, 'societypress' ), $total ); ?>
                </span>
            </div>
        </form>

        <!-- Table -->
        <table class="wp-list-table widefat fixed striped">
            <thead>
                <tr>
                    <th class="sp-email-log-col-id"><?php esc_html_e( 'ID', 'societypress' ); ?></th>
                    <th class="sp-email-log-col-status"><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                    <th class="sp-email-log-col-type"><?php esc_html_e( 'Type', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Recipient', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Subject', 'societypress' ); ?></th>
                    <th class="sp-email-log-col-date"><?php esc_html_e( 'Date', 'societypress' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $items ) ) : ?>
                    <tr>
                        <td colspan="6" class="sp-email-log-empty">
                            No emails logged yet.
                        </td>
                    </tr>
                <?php else : ?>
                    <?php foreach ( $items as $item ) : ?>
                        <?php
                        // Status badge colors
                        // WHY: Each status has its own background/text/border combination that
                        // mirrors WordPress admin's own traffic-light palette. These values are
                        // resolved from a PHP array keyed on $item->status, so they cannot be
                        // expressed as static CSS — they must stay as inline style attributes.
                        $badge_colors = [
                            'sent'    => [ 'bg' => '#edfaef', 'text' => '#00a32a', 'border' => '#00a32a' ],
                            'blocked' => [ 'bg' => '#fef8ee', 'text' => '#996800', 'border' => '#dba617' ],
                            'failed'  => [ 'bg' => '#fcf0f1', 'text' => '#d63638', 'border' => '#d63638' ],
                            'pending' => [ 'bg' => '#f0f0f1', 'text' => '#50575e', 'border' => '#8c8f94' ],
                        ];
                        $bc = $badge_colors[ $item->status ] ?? $badge_colors['pending'];
                        $detail_url = add_query_arg( [ 'page' => 'sp-email-log', 'view' => $item->id ], admin_url( 'admin.php' ) );
                        ?>
                        <tr>
                            <td><?php echo esc_html( $item->id ); ?></td>
                            <td>
                                <span class="sp-email-log-badge" style="background: <?php echo esc_attr( $bc['bg'] ); ?>; color: <?php echo esc_attr( $bc['text'] ); ?>; border: 1px solid <?php echo esc_attr( $bc['border'] ); ?>;">
                                    <?php echo esc_html( ucfirst( $item->status ) ); ?>
                                </span>
                            </td>
                            <td class="sp-email-log-type-cell">
                                <?php echo $item->email_type ? esc_html( ucfirst( str_replace( '_', ' ', $item->email_type ) ) ) : '—'; ?>
