                            </td>
                            <td><?php echo esc_html( $item->subject ); ?></td>
                            <td class="sp-email-log-date-cell">
                                <?php echo esc_html( date_i18n( 'M j, Y g:i a', strtotime( $item->created_at ) ) ); ?>
