                <?php if ( $entry->error_message ) : ?>
                    <tr>
                        <th class="sp-email-detail-th">Error</th>
                        <td class="sp-email-detail-error-text"><?php echo esc_html( $entry->error_message ); ?></td>
                    </tr>
                <?php endif; ?>
                <?php if ( $entry->headers ) : ?>
                    <tr>
                        <th class="sp-email-detail-th">Headers</th>
