}

// ============================================================================
// BLAST EMAIL — ADMIN PAGES + SENDING ENGINE
// ============================================================================
//
// WHY: the society sends weekly blast emails to members — meeting reminders,
//      research tips, event announcements, volunteer requests. This was their
//      most-used ENS feature (972 archived messages). The blast email system
//      lets admins compose rich HTML emails, target them by group or tier,
//      and batch-send via WP cron to avoid server timeouts.
// ============================================================================

/**
 * Render the Blast Email list page.
 *
 * WHY: Shows all blast emails — drafts, sent, failed — with filtering by
 *      status. Each row shows subject, sender, date, recipient count, and
 *      delivery stats. Clicking a sent email shows a read-only preview.
 */
function sp_render_blast_email_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete action
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && isset( $_POST['blast_id'] ) ) {
        check_admin_referer( 'sp_delete_blast_' . $_POST['blast_id'] );
        $wpdb->delete( $prefix . 'blast_emails', [ 'id' => (int) $_POST['blast_id'] ] );
        wp_safe_redirect( admin_url( 'admin.php?page=sp-blast-email&deleted=1' ) );
        exit;
    }

    // View a single blast email (read-only)
    $view_id = isset( $_GET['view'] ) ? absint( $_GET['view'] ) : 0;
    if ( $view_id ) {
        sp_render_blast_email_detail( $view_id );
        return;
    }

    // Filters
    $filter_status = sanitize_text_field( $_GET['status'] ?? '' );
    $per_page      = 20;
    $paged         = max( 1, (int) ( $_GET['paged'] ?? 1 ) );
    $offset        = ( $paged - 1 ) * $per_page;

    $where = [ '1=1' ];
    $args  = [];

    if ( $filter_status ) {
        $where[] = 'b.status = %s';
        $args[]  = $filter_status;
    }

    $where_sql = implode( ' AND ', $where );

    // Count total
    $count_sql = "SELECT COUNT(*) FROM {$prefix}blast_emails b WHERE {$where_sql}";
    $total = $args
        ? (int) $wpdb->get_var( $wpdb->prepare( $count_sql, ...$args ) )
        : (int) $wpdb->get_var( $count_sql );

    $total_pages = ceil( $total / $per_page );

    // Fetch rows
    $rows_sql = "SELECT b.*, u.display_name AS sender_name
                 FROM {$prefix}blast_emails b
                 LEFT JOIN {$wpdb->users} u ON b.sender_id = u.ID
                 WHERE {$where_sql}
                 ORDER BY b.created_at DESC
                 LIMIT %d OFFSET %d";

    $query_args = array_merge( $args, [ $per_page, $offset ] );
    $rows = $wpdb->get_results( $wpdb->prepare( $rows_sql, ...$query_args ) );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Blast Email', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email-compose' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Compose New', 'societypress' ); ?></a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Blast email deleted.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['sent'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Blast email is being sent.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Draft saved.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <!-- Status filter tabs -->
        <ul class="subsubsub" style="margin: 12px 0;">
            <?php
            $statuses = [ '' => 'All', 'draft' => 'Drafts', 'sending' => 'Sending', 'sent' => 'Sent', 'failed' => 'Failed' ];
            $links = [];
            foreach ( $statuses as $key => $label ) {
                $url = add_query_arg( [ 'page' => 'sp-blast-email', 'status' => $key ], admin_url( 'admin.php' ) );
                $class = ( $filter_status === $key ) ? ' class="current"' : '';
                $links[] = sprintf( '<li><a href="%s"%s>%s</a></li>', esc_url( $url ), $class, esc_html( $label ) );
            }
            echo implode( ' | ', $links );
            ?>
        </ul>

        <table class="widefat striped" style="margin-top: 16px; clear: both;">
            <thead>
                <tr>
                    <th><?php esc_html_e( 'Subject', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Sender', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Recipients', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Date', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $rows ) ) : ?>
                    <tr><td colspan="6" class="sp-text-center" class="sp-p-20"><?php esc_html_e( 'No blast emails yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email-compose' ) ); ?>"><?php esc_html_e( 'Compose one', 'societypress' ); ?></a>.</td></tr>
                <?php else : ?>
                    <?php foreach ( $rows as $row ) : ?>
                        <tr>
                            <td>
                                <strong>
                                    <?php if ( $row->status === 'draft' ) : ?>
                                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email-compose&blast_id=' . $row->id ) ); ?>"><?php echo esc_html( $row->subject ); ?></a>
                                    <?php else : ?>
                                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email&view=' . $row->id ) ); ?>"><?php echo esc_html( $row->subject ); ?></a>
                                    <?php endif; ?>
                                </strong>
                            </td>
                            <td><?php echo esc_html( $row->sender_name ?: '—' ); ?></td>
                            <td>
                                <?php
                                if ( $row->status === 'sent' || $row->status === 'sending' ) {
                                    echo (int) $row->total_sent . ' / ' . (int) $row->total_recipients;
                                    if ( (int) $row->total_failed > 0 ) {
                                        echo ' <span class="sp-text-error">(' . (int) $row->total_failed . ' failed)</span>';
                                    }
                                } else {
                                    echo (int) $row->total_recipients ?: '—';
                                }
                                ?>
                            </td>
                            <td>
                                <?php
                                $status_colors = [
                                    'draft'   => '#787c82',
                                    'sending' => '#dba617',
                                    'sent'    => '#00a32a',
                                    'failed'  => '#d63638',
                                ];
                                $color = $status_colors[ $row->status ] ?? '#787c82';
                                printf( '<span style="color: %s; font-weight: 600;">%s</span>', esc_attr( $color ), esc_html( ucfirst( $row->status ) ) );
                                ?>
                            </td>
                            <td>
                                <?php
                                $date = $row->sent_at ?: $row->created_at;
                                echo esc_html( date_i18n( 'M j, Y g:i a', strtotime( $date ) ) );
                                ?>
                            </td>
                            <td>
                                <?php if ( $row->status === 'draft' ) : ?>
                                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email-compose&blast_id=' . $row->id ) ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a> |
                                <?php else : ?>
                                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email&view=' . $row->id ) ); ?>"><?php esc_html_e( 'View', 'societypress' ); ?></a> |
                                <?php endif; ?>
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this blast email?', 'societypress' ) ); ?>">
                                    <?php wp_nonce_field( 'sp_delete_blast_' . $row->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="blast_id" value="<?php echo (int) $row->id; ?>">
                                    <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>

        <?php if ( $total_pages > 1 ) : ?>
            <div class="tablenav bottom">
                <div class="tablenav-pages">
                    <?php
                    echo paginate_links( [
                        'base'      => add_query_arg( 'paged', '%#%' ),
                        'format'    => '',
                        'current'   => $paged,
                        'total'     => $total_pages,
                        'prev_text' => '&laquo;',
                        'next_text' => '&raquo;',
                    ] );
                    ?>
                </div>
            </div>
        <?php endif; ?>
    </div>
    <?php
}

/**
 * Render a single blast email in read-only detail view.
 *
 * WHY: After a blast is sent, admins need to review what went out —
 *      the subject, body, targeting, and delivery stats. This is the
 *      audit trail for email communications.
 *
 * @param int $blast_id The blast email ID.
 */
function sp_render_blast_email_detail( int $blast_id ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $blast = $wpdb->get_row( $wpdb->prepare(
        "SELECT b.*, u.display_name AS sender_name
         FROM {$prefix}blast_emails b
         LEFT JOIN {$wpdb->users} u ON b.sender_id = u.ID
         WHERE b.id = %d", $blast_id
    ) );

    if ( ! $blast ) {
        echo '<div class="wrap"><h1>' . esc_html__( 'Blast Email Not Found', 'societypress' ) . '</h1>';
        echo '<p><a href="' . esc_url( admin_url( 'admin.php?page=sp-blast-email' ) ) . '">&larr; ' . esc_html__( 'Back', 'societypress' ) . '</a></p></div>';
        return;
    }

    // Decode recipient filter for display
    $filter_display = __( 'All Active Members', 'societypress' );
    if ( $blast->recipient_type === 'group' && $blast->recipient_filter ) {
        $filter_data = json_decode( $blast->recipient_filter, true );
        if ( ! empty( $filter_data['group_ids'] ) ) {
            $group_names = $wpdb->get_col( sprintf(
                "SELECT name FROM {$prefix}groups WHERE id IN (%s)",
                implode( ',', array_map( 'intval', $filter_data['group_ids'] ) )
            ) );
            /* translators: %s: comma-separated list of group names */
            $filter_display = sprintf( __( 'Groups: %s', 'societypress' ), implode( ', ', $group_names ) );
        }
    } elseif ( $blast->recipient_type === 'tier' && $blast->recipient_filter ) {
        $filter_data = json_decode( $blast->recipient_filter, true );
        if ( ! empty( $filter_data['tier_ids'] ) ) {
            $tier_names = $wpdb->get_col( sprintf(
                "SELECT name FROM {$prefix}membership_tiers WHERE id IN (%s)",
                implode( ',', array_map( 'intval', $filter_data['tier_ids'] ) )
            ) );
            /* translators: %s: comma-separated list of tier names */
            $filter_display = sprintf( __( 'Tiers: %s', 'societypress' ), implode( ', ', $tier_names ) );
        }
    }

    ?>
    <div class="wrap">
        <h1><?php echo esc_html( sprintf( __( 'Blast Email — %s', 'societypress' ), $blast->subject ) ); ?></h1>
        <p><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-blast-email' ) ); ?>">&larr; <?php esc_html_e( 'Back to Blast Email', 'societypress' ); ?></a></p>

        <table class="widefat" style="max-width: 800px; margin-bottom: 24px;">
            <tbody>
                <tr><th class="sp-bg-subtle sp-w-140"><?php esc_html_e( 'Subject', 'societypress' ); ?></th><td><?php echo esc_html( $blast->subject ); ?></td></tr>
                <tr><th class="sp-bg-subtle"><?php esc_html_e( 'Sender', 'societypress' ); ?></th><td><?php echo esc_html( $blast->sender_name ?: '—' ); ?></td></tr>
                <tr><th class="sp-bg-subtle"><?php esc_html_e( 'Recipients', 'societypress' ); ?></th><td><?php echo esc_html( $filter_display ); ?></td></tr>
                <tr><th class="sp-bg-subtle"><?php esc_html_e( 'Delivery', 'societypress' ); ?></th><td><?php
                    /* translators: %1$d: sent count, %2$d: failed count, %3$d: total count */
                    printf( esc_html__( '%1$d sent, %2$d failed, %3$d total', 'societypress' ), (int) $blast->total_sent, (int) $blast->total_failed, (int) $blast->total_recipients );
                ?></td></tr>
                <tr><th class="sp-bg-subtle"><?php esc_html_e( 'Status', 'societypress' ); ?></th><td><strong><?php echo esc_html( ucfirst( $blast->status ) ); ?></strong></td></tr>
                <tr><th class="sp-bg-subtle"><?php esc_html_e( 'Sent', 'societypress' ); ?></th><td><?php echo $blast->sent_at ? esc_html( date_i18n( 'F j, Y g:i a', strtotime( $blast->sent_at ) ) ) : '—'; ?></td></tr>
            </tbody>
        </table>

        <h3>Email Body</h3>
        <div style="background: #fff; border: 1px solid #c3c4c7; padding: 20px; max-width: 800px;">
            <?php
            $rendered = sp_build_email_html( $blast->subject, $blast->body );
            echo '<iframe srcdoc="' . esc_attr( $rendered ) . '" style="width: 100%; min-height: 500px; border: none;" sandbox></iframe>';
            ?>
        </div>
    </div>
    <?php
}

/**
 * Render the Blast Email compose/edit page.
 *
 * WHY: The compose page is where Harold crafts his weekly email. It uses
 *      wp_editor() for rich text editing (media insertion, formatting),
 *      radio buttons for recipient targeting, and AJAX to show the estimated
 *      recipient count as targeting changes. Preview shows the rendered
 *      email exactly as recipients will see it.
 */
function sp_render_blast_email_compose_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $blast_id = (int) ( $_GET['blast_id'] ?? 0 );
    $blast    = null;

    if ( $blast_id ) {
        $blast = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}blast_emails WHERE id = %d", $blast_id
        ) );
        // Only allow editing drafts
        if ( $blast && $blast->status !== 'draft' ) {
            echo '<div class="wrap"><h1>' . esc_html__( 'Cannot Edit', 'societypress' ) . '</h1>';
            echo '<p>' . esc_html__( 'This blast email has already been sent and cannot be edited.', 'societypress' ) . '</p>';
            echo '<p><a href="' . esc_url( admin_url( 'admin.php?page=sp-blast-email' ) ) . '">&larr; ' . esc_html__( 'Back', 'societypress' ) . '</a></p></div>';
            return;
        }
    }

    // Handle save/send
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_blast_nonce'] ) ) {
        check_admin_referer( 'sp_save_blast', 'sp_blast_nonce' );

        $subject        = sanitize_text_field( $_POST['blast_subject'] ?? '' );
        $body           = wp_kses_post( $_POST['blast_body'] ?? '' );
        $recipient_type = sanitize_text_field( $_POST['recipient_type'] ?? 'all_members' );
        $action         = sanitize_text_field( $_POST['sp_blast_action'] ?? 'save_draft' );

        // Build recipient filter JSON
        $recipient_filter = null;
        if ( $recipient_type === 'group' && ! empty( $_POST['group_ids'] ) ) {
            $recipient_filter = wp_json_encode( [
                'group_ids' => array_map( 'intval', (array) $_POST['group_ids'] ),
            ] );
        } elseif ( $recipient_type === 'tier' && ! empty( $_POST['tier_ids'] ) ) {
            $recipient_filter = wp_json_encode( [
                'tier_ids' => array_map( 'intval', (array) $_POST['tier_ids'] ),
            ] );
        }

        // Count recipients
        $total_recipients = sp_blast_count_recipients( $recipient_type, $recipient_filter );

        $data = [
            'subject'          => $subject,
            'body'             => $body,
            'sender_id'        => get_current_user_id(),
            'recipient_type'   => $recipient_type,
            'recipient_filter' => $recipient_filter,
            'total_recipients' => $total_recipients,
            'status'           => 'draft',
            'updated_at'       => current_time( 'mysql' ),
        ];

        if ( $blast_id ) {
            $wpdb->update( $prefix . 'blast_emails', $data, [ 'id' => $blast_id ] );
        } else {
            $data['created_at'] = current_time( 'mysql' );
            $wpdb->insert( $prefix . 'blast_emails', $data );
            $blast_id = (int) $wpdb->insert_id;
        }

        // If "Send Now" was clicked, trigger the send
        if ( $action === 'send_now' && $blast_id && $total_recipients > 0 ) {
            $wpdb->update( $prefix . 'blast_emails', [
                'status' => 'sending',
            ], [ 'id' => $blast_id ] );

            // Audit: blast emails go to many people — always log who sent what and to how many.
            sp_audit(
                'blast_email_sent',
                sprintf( 'Blast email "%s" sent to %d recipients (%s)', $subject, $total_recipients, $recipient_type ),
                'blast_email',
                $blast_id
            );

            // Schedule the first batch via WP cron (runs immediately on next page load)
            wp_schedule_single_event( time(), 'sp_blast_email_send_batch', [ $blast_id, 0 ] );

            wp_safe_redirect( admin_url( 'admin.php?page=sp-blast-email&sent=1' ) );
            exit;
        }

        wp_safe_redirect( admin_url( 'admin.php?page=sp-blast-email&saved=1' ) );
        exit;
    }

    // Load groups and tiers for targeting
    $groups = $wpdb->get_results(
        "SELECT g.id, g.name,
                (SELECT COUNT(*) FROM {$prefix}group_members gm WHERE gm.group_id = g.id) AS member_count
         FROM {$prefix}groups g
         WHERE g.status = 'active'
         ORDER BY g.sort_order, g.name"
    );

    $tiers = $wpdb->get_results(
        "SELECT t.id, t.name,
                (SELECT COUNT(*) FROM {$prefix}members m WHERE m.tier_id = t.id AND m.status = 'active') AS member_count
         FROM {$prefix}membership_tiers t
         WHERE t.active = 1
         ORDER BY t.sort_order"
    );

    // Parse existing filter for pre-selecting checkboxes
    $selected_groups = [];
    $selected_tiers  = [];
    $recipient_type  = $blast->recipient_type ?? 'all_members';

    if ( $blast && $blast->recipient_filter ) {
        $filter_data = json_decode( $blast->recipient_filter, true );
        $selected_groups = $filter_data['group_ids'] ?? [];
        $selected_tiers  = $filter_data['tier_ids'] ?? [];
    }

