                            data-method="stripe" id="<?php echo esc_attr( $form_id ); ?>-btn-stripe">
                        <?php esc_html_e( 'Donate with Card', 'societypress' ); ?>
                    </button>
                <?php endif; ?>
                <?php if ( $paypal_ready ) : ?>
                    <button type="button" class="sp-donate-pay-btn sp-donate-pay-btn-paypal"
                            data-method="paypal" id="<?php echo esc_attr( $form_id ); ?>-btn-paypal">
                        <?php esc_html_e( 'Donate with PayPal', 'societypress' ); ?>
                    </button>
                <?php endif; ?>
            </div>

            <input type="hidden" name="nonce" value="<?php echo esc_attr( $nonce ); ?>">
            <input type="hidden" name="action" value="sp_donate_online">
        </form>
    </div>

    <script>
    /**
     * Donation form handler — vanilla JS, no jQuery.
     *
     * WHY: Manages campaign card selection, amount preset buttons, custom amount
     * toggling, form validation, and AJAX submission to the sp_donate_online
     * endpoint. On success, redirects to the checkout URL returned by the server.
     *
     * Uses an IIFE scoped to the form ID so multiple donation widgets on one
     * page don't conflict with each other.
     */
    (function() {
        var formId   = <?php echo wp_json_encode( $form_id ); ?>;
        var form     = document.getElementById(formId + '-inner');
        var errorBox = document.getElementById(formId + '-error');
        var spinner  = document.getElementById(formId + '-spinner');
        var customWrap   = document.getElementById(formId + '-custom-wrap');
        var customInput  = document.getElementById(formId + '-custom-amount');
        var amountHidden = document.getElementById(formId + '-amount');

        if (!form) return;

        // --- Campaign card selection ---
        var campaignCards = form.querySelectorAll('.sp-donate-campaign-card');
        var campaignInput = form.querySelector('input[name="campaign_id"]');

        campaignCards.forEach(function(card) {
            card.addEventListener('click', function() {
                campaignCards.forEach(function(c) { c.classList.remove('sp-selected'); });
                card.classList.add('sp-selected');
                if (campaignInput) {
                    campaignInput.value = card.getAttribute('data-campaign-id') || '0';
                }
            });
        });

        // --- Amount preset buttons ---
        var amountBtns = form.querySelectorAll('.sp-donate-amount-btn');
        var selectedPreset = null;

        amountBtns.forEach(function(btn) {
            btn.addEventListener('click', function() {
                amountBtns.forEach(function(b) { b.classList.remove('sp-selected'); });
                btn.classList.add('sp-selected');

                var val = btn.getAttribute('data-amount');
                if (val === 'other') {
                    // Show custom amount input, clear preset value
                    customWrap.style.display = '';
                    customInput.focus();
                    amountHidden.value = '';
                    selectedPreset = 'other';
                } else {
                    customWrap.style.display = 'none';
                    customInput.value = '';
                    amountHidden.value = val;
                    selectedPreset = val;
                }
            });
        });

        // Sync custom amount input to hidden field
        if (customInput) {
            customInput.addEventListener('input', function() {
                amountHidden.value = this.value;
            });
        }

        // --- Payment button handlers ---
        var payBtns = form.querySelectorAll('.sp-donate-pay-btn');
        var submitting = false;

        payBtns.forEach(function(btn) {
            btn.addEventListener('click', function() {
                if (submitting) return;

                errorBox.style.display = 'none';
                errorBox.textContent = '';

                // Resolve the final amount
                var amount = parseFloat(amountHidden.value);
                if (!amount || amount <= 0) {
                    showError(<?php echo wp_json_encode( __( 'Please select or enter a donation amount.', 'societypress' ) ); ?>);
                    return;
                }

                var nameField  = form.querySelector('input[name="donor_name"]');
                var emailField = form.querySelector('input[name="donor_email"]');

                if (!nameField.value.trim()) {
                    showError(<?php echo wp_json_encode( __( 'Please enter your name.', 'societypress' ) ); ?>);
                    nameField.focus();
                    return;
                }
                if (!emailField.value.trim() || emailField.value.indexOf('@') === -1) {
                    showError(<?php echo wp_json_encode( __( 'Please enter a valid email address.', 'societypress' ) ); ?>);
                    emailField.focus();
                    return;
                }

                var method = btn.getAttribute('data-method');

                // Build form data
                var fd = new FormData();
                fd.append('action', 'sp_donate_online');
                fd.append('nonce', form.querySelector('input[name="nonce"]').value);
                fd.append('donor_name', nameField.value.trim());
                fd.append('donor_email', emailField.value.trim());
                fd.append('amount', amount.toString());
                fd.append('pay_method', method);
                fd.append('campaign_id', (campaignInput ? campaignInput.value : '0'));
                fd.append('is_anonymous', form.querySelector('input[name="is_anonymous"]').checked ? '1' : '0');

                var noteField = form.querySelector('textarea[name="note"]');
                if (noteField) {
                    fd.append('note', noteField.value);
                }

                // Disable buttons and show spinner
                submitting = true;
                payBtns.forEach(function(b) { b.disabled = true; });
                spinner.style.display = '';

                fetch(<?php echo wp_json_encode( admin_url( 'admin-ajax.php' ) ); ?>, {
                    method: 'POST',
                    credentials: 'same-origin',
                    body: fd,
                })
                .then(function(resp) { return resp.json(); })
                .then(function(data) {
                    if (data.success && data.data && data.data.checkout_url) {
                        // Redirect to the payment gateway
                        window.location.href = data.data.checkout_url;
                    } else {
                        showError(data.data && data.data.message
                            ? data.data.message
                            : <?php echo wp_json_encode( __( 'Something went wrong. Please try again.', 'societypress' ) ); ?>);
                        submitting = false;
                        payBtns.forEach(function(b) { b.disabled = false; });
                        spinner.style.display = 'none';
                    }
                })
                .catch(function() {
                    showError(<?php echo wp_json_encode( __( 'Network error. Please check your connection and try again.', 'societypress' ) ); ?>);
                    submitting = false;
                    payBtns.forEach(function(b) { b.disabled = false; });
                    spinner.style.display = 'none';
                });
            });
        });

        function showError(msg) {
            errorBox.textContent = msg;
            errorBox.style.display = '';
            errorBox.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }
    })();
    </script>
    <?php
}


/**
 * Render the Donation Form page builder widget.
 *
 * WHY: Societies may want to embed a donation form on any builder page — not
 *      just the dedicated Donate page. This widget wraps the shared form
 *      rendering function with an optional campaign_id setting to lock the
 *      form to a specific campaign.
 *
 * @param array $s Widget settings array. Keys:
 *                  - campaign_id (int): Lock to a specific campaign (0 = show dropdown).
 */
function sp_render_builder_widget_donations_form( array $s ): void {
    $campaign_id = absint( $s['campaign_id'] ?? 0 );
    sp_render_donation_form_frontend( $campaign_id );
}


// ============================================================================

/**
 * Render the Donations list page.
 *
 * WHY: Shows all donations with summary stats, filtering by campaign/type/
 *      date range, and search. Each row has edit/delete actions and an
 *      acknowledgment status indicator. Summary cards show total giving
 *      at a glance.
 */
function sp_render_donations_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && isset( $_POST['donation_id'] ) ) {
        check_admin_referer( 'sp_delete_donation_' . $_POST['donation_id'] );
        $wpdb->delete( $prefix . 'donations', [ 'id' => (int) $_POST['donation_id'] ] );
        wp_safe_redirect( admin_url( 'admin.php?page=sp-donations&deleted=1' ) );
        exit;
    }

    // Handle bulk acknowledgment
    if ( isset( $_POST['sp_bulk_acknowledge'] ) && ! empty( $_POST['donation_ids'] ) ) {
        check_admin_referer( 'sp_bulk_acknowledge' );
        sp_send_donation_acknowledgments( array_map( 'intval', (array) $_POST['donation_ids'] ) );
        wp_safe_redirect( admin_url( 'admin.php?page=sp-donations&acknowledged=1' ) );
        exit;
    }

    // Filters
    $filter_campaign = (int) ( $_GET['campaign'] ?? 0 );
    $filter_type     = sanitize_text_field( $_GET['type'] ?? '' );
    $filter_from     = sanitize_text_field( $_GET['from'] ?? '' );
    $filter_to       = sanitize_text_field( $_GET['to'] ?? '' );
    $search          = sanitize_text_field( $_GET['s'] ?? '' );
    $per_page        = 50;
    $paged           = max( 1, (int) ( $_GET['paged'] ?? 1 ) );
    $offset          = ( $paged - 1 ) * $per_page;

    $where = [ '1=1' ];
    $args  = [];

    if ( $filter_campaign ) {
        $where[] = 'd.campaign_id = %d';
        $args[]  = $filter_campaign;
    }
    if ( $filter_type ) {
        $where[] = 'd.type = %s';
        $args[]  = $filter_type;
    }
    if ( $filter_from ) {
        $where[] = 'd.date >= %s';
        $args[]  = $filter_from;
    }
    if ( $filter_to ) {
        $where[] = 'd.date <= %s';
        $args[]  = $filter_to;
    }
    if ( $search ) {
        $like    = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = '(d.donor_name LIKE %s OR d.donor_email LIKE %s OR d.note LIKE %s)';
        $args[]  = $like;
        $args[]  = $like;
        $args[]  = $like;
    }

    $where_sql = implode( ' AND ', $where );

    // Summary stats
    $stats_sql = "SELECT
        COUNT(*) AS total_count,
        COALESCE(SUM(d.amount), 0) AS total_amount
        FROM {$prefix}donations d
        WHERE {$where_sql}";

    $stats = $args
        ? $wpdb->get_row( $wpdb->prepare( $stats_sql, ...$args ) )
        : $wpdb->get_row( $stats_sql );

    // This year's total (always unfiltered)
    $year_start = wp_date( 'Y-01-01' );
    $year_total = (float) $wpdb->get_var( $wpdb->prepare(
        "SELECT COALESCE(SUM(amount), 0) FROM {$prefix}donations WHERE date >= %s",
        $year_start
    ) );

    // Paginated results
    $rows_sql = "SELECT d.*, c.name AS campaign_name,
                        r.display_name AS recorded_by_name
                 FROM {$prefix}donations d
                 LEFT JOIN {$prefix}campaigns c ON d.campaign_id = c.id
                 LEFT JOIN {$wpdb->users} r ON d.recorded_by = r.ID
                 WHERE {$where_sql}
                 ORDER BY d.date DESC, d.created_at DESC
                 LIMIT %d OFFSET %d";

    $query_args = array_merge( $args, [ $per_page, $offset ] );
    $rows = $wpdb->get_results( $wpdb->prepare( $rows_sql, ...$query_args ) );

    $total_rows  = (int) ( $stats->total_count ?? 0 );
    $total_pages = ceil( $total_rows / $per_page );

    // Dropdowns
    $campaigns = $wpdb->get_results( "SELECT id, name FROM {$prefix}campaigns ORDER BY name" );
    $types     = $wpdb->get_col( "SELECT DISTINCT type FROM {$prefix}donations ORDER BY type" );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Donations', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-donation-edit' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Record Donation', 'societypress' ); ?></a>
        <a href="<?php echo esc_url( admin_url( 'admin-ajax.php?action=sp_export_donations&nonce=' . wp_create_nonce( 'sp_export_donations' ) ) ); ?>" class="page-title-action"><?php esc_html_e( 'Export CSV', 'societypress' ); ?></a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Donation deleted.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Donation saved.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['acknowledged'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Acknowledgment emails sent.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <style>
            /* sp_render_donations_page() — summary stat cards (pre-existing block,
             * kept here; migrated inline styles added below).
             * WHY: Stat card styles were already centralised; inline styles on the
             * filter bar and table rows are now extracted to match the same pattern. */
            .sp-donation-stats { display: flex; gap: 16px; margin: 16px 0; flex-wrap: wrap; }
            .sp-donation-stat { background: #fff; border: 1px solid #c3c4c7; border-radius: 4px; padding: 12px 20px; min-width: 140px; }
            .sp-donation-stat .stat-label { font-size: 12px; color: #646970; text-transform: uppercase; letter-spacing: 0.5px; }
            .sp-donation-stat .stat-value { font-size: 24px; font-weight: 600; margin-top: 4px; }
            .sp-donation-stat .stat-value.money { color: #00a32a; }

            /* Filter bar: white card with flex layout */
            .sp-donations-filter-form {
                background: #fff;
                border: 1px solid #c3c4c7;
                padding: 12px;
                margin-bottom: 12px;
                display: flex;
                gap: 8px;
                align-items: end;
                flex-wrap: wrap;
            }

            /* Small uppercase-style labels inside the filter bar */
            .sp-donations-filter-label {
                font-size: 12px;
                display: block;
                margin-bottom: 2px;
                color: #646970;
            }

            /* Checkbox select-all column: just wide enough */
            .sp-donations-col-check {
                width: 30px;
            }

            /* Empty-state cell: centred with breathing room */
            .sp-donations-empty-cell {
                text-align: center;
                padding: 20px;
            }

            /* Anonymous donor label — muted grey */
            .sp-donations-anonymous {
                color: #787c82;
            }

            /* Donor email sub-line — smaller, muted */
            .sp-donations-email {
                color: #787c82;
                font-size: 12px;
            }

            /* Amount cell — bold to make numbers scannable */
            .sp-donations-amount-cell {
                font-weight: 600;
            }

            /* Acknowledged checkmark — green */
            .sp-donations-ack-yes {
                color: #00a32a;
            }

            /* Not-acknowledged dash — muted */
            .sp-donations-ack-no {
                color: #787c82;
            }

            /* Delete form sits inline alongside the Edit link */
            .sp-donations-delete-form {
                display: inline;
            }

            /* Delete button: unstyled link appearance with red text */
            .sp-donations-delete-btn {
                background: none;
                border: none;
                color: #b32d2e;
                cursor: pointer;
                padding: 0;
                font: inherit;
                text-decoration: underline;
            }

            /* Bulk-action bar below the table */
            .sp-donations-bulk-bar {
                margin-top: 12px;
            }
        </style>

        <!-- Summary Stats -->
        <div class="sp-donation-stats">
            <div class="sp-donation-stat">
                <div class="stat-label"><?php esc_html_e( 'Shown', 'societypress' ); ?></div>
                <div class="stat-value"><?php echo number_format( $total_rows ); ?></div>
            </div>
            <div class="sp-donation-stat">
                <div class="stat-label"><?php esc_html_e( 'Shown Total', 'societypress' ); ?></div>
                <div class="stat-value money"><?php echo esc_html( sp_format_currency( $stats->total_amount ?? 0 ) ); ?></div>
            </div>
            <div class="sp-donation-stat">
                <div class="stat-label"><?php esc_html_e( 'This Year', 'societypress' ); ?></div>
                <div class="stat-value money"><?php echo esc_html( sp_format_currency( $year_total ) ); ?></div>
            </div>
        </div>

        <!-- Filters -->
        <form method="get" class="sp-donations-filter-form">
            <input type="hidden" name="page" value="sp-donations">
            <div>
                <label class="sp-donations-filter-label"><?php esc_html_e( 'Campaign', 'societypress' ); ?></label>
                <select name="campaign">
                    <option value=""><?php esc_html_e( 'All Campaigns', 'societypress' ); ?></option>
                    <?php foreach ( $campaigns as $c ) : ?>
                        <option value="<?php echo esc_attr( $c->id ); ?>" <?php selected( $filter_campaign, $c->id ); ?>><?php echo esc_html( $c->name ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <label class="sp-donations-filter-label"><?php esc_html_e( 'Type', 'societypress' ); ?></label>
                <select name="type">
                    <option value=""><?php esc_html_e( 'All Types', 'societypress' ); ?></option>
                    <?php foreach ( $types as $t ) : ?>
                        <option value="<?php echo esc_attr( $t ); ?>" <?php selected( $filter_type, $t ); ?>><?php echo esc_html( ucfirst( str_replace( '_', ' ', $t ) ) ); ?></option>
                    <?php endforeach; ?>
                </select>
            </div>
            <div>
                <label class="sp-donations-filter-label"><?php esc_html_e( 'From', 'societypress' ); ?></label>
                <input type="date" name="from" value="<?php echo esc_attr( $filter_from ); ?>">
            </div>
            <div>
                <label class="sp-donations-filter-label"><?php esc_html_e( 'To', 'societypress' ); ?></label>
                <input type="date" name="to" value="<?php echo esc_attr( $filter_to ); ?>">
