            <div>
                <label class="sp-donations-filter-label"><?php esc_html_e( 'Search', 'societypress' ); ?></label>
                <input type="search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php echo esc_attr__( 'Donor name or note...', 'societypress' ); ?>">
            </div>
            <div>
                <button type="submit" class="button"><?php esc_html_e( 'Filter', 'societypress' ); ?></button>
                <?php if ( $filter_campaign || $filter_type || $filter_from || $filter_to || $search ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-donations' ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>
            </div>
        </form>

        <!-- Donations Table -->
        <form method="post">
            <?php wp_nonce_field( 'sp_bulk_acknowledge' ); ?>
            <table class="widefat striped">
                <thead>
                    <tr>
                        <th class="sp-donations-col-check"><input type="checkbox" id="sp-don-check-all"></th>
                        <th><?php esc_html_e( 'Date', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Donor', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Amount', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Type', 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Campaign', 'societypress' ); ?></th>
                        <th><?php esc_html_e( "Ack'd", 'societypress' ); ?></th>
                        <th><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                    </tr>
                </thead>
                <tbody>
                    <?php if ( empty( $rows ) ) : ?>
                        <tr><td colspan="8" class="sp-donations-empty-cell"><?php esc_html_e( 'No donations found.', 'societypress' ); ?></td></tr>
                    <?php else : ?>
                        <?php foreach ( $rows as $row ) : ?>
                            <tr>
                                <td><input type="checkbox" name="donation_ids[]" value="<?php echo esc_attr( $row->id ); ?>"></td>
