function sp_render_donation_edit_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $donation_id = (int) ( $_GET['donation_id'] ?? 0 );
    $donation    = null;

    if ( $donation_id ) {
        $donation = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}donations WHERE id = %d", $donation_id
        ) );
    }

    // Handle save
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_donation_nonce'] ) ) {
        check_admin_referer( 'sp_save_donation', 'sp_donation_nonce' );

        $member_id   = (int) ( $_POST['member_id'] ?? 0 );
        $donor_name  = sanitize_text_field( $_POST['donor_name'] ?? '' );
        $donor_email = sanitize_email( $_POST['donor_email'] ?? '' );

        // If a member was selected, pull their name/email
        if ( $member_id ) {
            $member = $wpdb->get_row( $wpdb->prepare(
                "SELECT m.first_name, m.last_name, u.user_email
                 FROM {$prefix}members m
                 JOIN {$wpdb->users} u ON m.user_id = u.ID
                 WHERE m.user_id = %d", $member_id
            ) );
            if ( $member ) {
                $donor_name  = trim( $member->first_name . ' ' . $member->last_name );
                $donor_email = $member->user_email;
            }
        }

        $data = [
            'campaign_id'         => (int) ( $_POST['campaign_id'] ?? 0 ) ?: null,
            'user_id'             => $member_id ?: null,
            'donor_name'          => $donor_name,
            'donor_email'         => $donor_email,
            'amount'              => (float) ( $_POST['amount'] ?? 0 ),
            'type'                => sanitize_text_field( $_POST['donation_type'] ?? 'cash' ),
            'in_kind_description' => sanitize_textarea_field( $_POST['in_kind_description'] ?? '' ) ?: null,
            'date'                => sanitize_text_field( $_POST['donation_date'] ?? wp_date( 'Y-m-d' ) ),
            'note'                => sanitize_textarea_field( $_POST['note'] ?? '' ) ?: null,
            'is_anonymous'        => isset( $_POST['is_anonymous'] ) ? 1 : 0,
            'recorded_by'         => get_current_user_id(),
        ];

        if ( $donation_id ) {
            $wpdb->update( $prefix . 'donations', $data, [ 'id' => $donation_id ] );
        } else {
            $data['created_at'] = current_time( 'mysql' );
            $wpdb->insert( $prefix . 'donations', $data );
        }

        wp_safe_redirect( admin_url( 'admin.php?page=sp-donations&saved=1' ) );
        exit;
    }

    // Members for dropdown
    $members = $wpdb->get_results(
        "SELECT m.user_id, m.first_name, m.last_name, u.user_email
         FROM {$prefix}members m
         JOIN {$wpdb->users} u ON m.user_id = u.ID
         ORDER BY m.last_name, m.first_name"
    );

    // Campaigns for dropdown
    $campaigns = $wpdb->get_results(
        "SELECT id, name FROM {$prefix}campaigns WHERE status = 'active' ORDER BY name"
    );

    $types = [ 'cash', 'check', 'credit_card', 'paypal', 'stripe', 'in_kind', 'other' ];

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php echo $donation_id ? esc_html__( 'Edit Donation', 'societypress' ) : esc_html__( 'Record Donation', 'societypress' ); ?></h1>
        <p><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-donations' ) ); ?>">&larr; Back to Donations</a></p>

        <form method="post" class="sp-max-w-600">
            <?php wp_nonce_field( 'sp_save_donation', 'sp_donation_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="sp-d-campaign"><?php esc_html_e( 'Campaign', 'societypress' ); ?></label></th>
                    <td>
                        <select name="campaign_id" id="sp-d-campaign" class="sp-full-width">
                            <option value="">— General / No Campaign —</option>
                            <?php foreach ( $campaigns as $c ) : ?>
                                <option value="<?php echo esc_attr( $c->id ); ?>" <?php selected( $donation->campaign_id ?? 0, $c->id ); ?>><?php echo esc_html( $c->name ); ?></option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-d-member"><?php esc_html_e( 'Member', 'societypress' ); ?></label></th>
                    <td>
                        <select name="member_id" id="sp-d-member" class="sp-full-width">
                            <option value="">— Non-member / Manual Entry —</option>
                            <?php foreach ( $members as $m ) : ?>
                                <option value="<?php echo esc_attr( $m->user_id ); ?>"
                                        data-name="<?php echo esc_attr( trim( $m->first_name . ' ' . $m->last_name ) ); ?>"
                                        data-email="<?php echo esc_attr( $m->user_email ); ?>"
                                        <?php selected( $donation->user_id ?? 0, $m->user_id ); ?>>
                                    <?php echo esc_html( $m->last_name . ', ' . $m->first_name . ' (' . $m->user_email . ')' ); ?>
                                </option>
                            <?php endforeach; ?>
                        </select>
                        <p class="description">Select a member to auto-fill name and email, or leave blank for manual entry.</p>
                    </td>
                </tr>
                <tr>
                    <th><label for="sp-d-name">Donor Name <span class="sp-text-error">*</span></label></th>
                    <td><input type="text" name="donor_name" id="sp-d-name" value="<?php echo esc_attr( $donation->donor_name ?? '' ); ?>" required class="sp-full-width"></td>
                </tr>
                <tr>
                    <th><label for="sp-d-email"><?php esc_html_e( 'Donor Email', 'societypress' ); ?></label></th>
                    <td><input type="email" name="donor_email" id="sp-d-email" value="<?php echo esc_attr( $donation->donor_email ?? '' ); ?>" class="sp-full-width"></td>
                </tr>
                <tr>
                    <th><label for="sp-d-amount"><?php esc_html_e( 'Amount', 'societypress' ); ?></label></th>
                    <td><input type="number" name="amount" id="sp-d-amount" value="<?php echo esc_attr( number_format( (float) ( $donation->amount ?? 0 ), 2, '.', '' ) ); ?>" step="0.01" min="0" class="sp-w-150"></td>
                </tr>
                <tr>
                    <th><label for="sp-d-type"><?php esc_html_e( 'Type', 'societypress' ); ?></label></th>
                    <td>
                        <select name="donation_type" id="sp-d-type" style="width: 200px;">
                            <?php foreach ( $types as $t ) : ?>
                                <option value="<?php echo esc_attr( $t ); ?>" <?php selected( $donation->type ?? 'cash', $t ); ?>><?php echo esc_html( ucfirst( str_replace( '_', ' ', $t ) ) ); ?></option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr id="sp-d-inkind-row" style="<?php echo ( $donation->type ?? '' ) !== 'in_kind' ? 'display:none;' : ''; ?>">
                    <th><label for="sp-d-inkind"><?php esc_html_e( 'In-Kind Description', 'societypress' ); ?></label></th>
                    <td><textarea name="in_kind_description" id="sp-d-inkind" rows="3" class="sp-full-width"><?php echo esc_textarea( $donation->in_kind_description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="sp-d-date"><?php esc_html_e( 'Date', 'societypress' ); ?> <span class="sp-text-error">*</span></label></th>
                    <td><input type="date" name="donation_date" id="sp-d-date" value="<?php echo esc_attr( $donation->date ?? wp_date( 'Y-m-d' ) ); ?>" required></td>
                </tr>
                <tr>
                    <th><label for="sp-d-note"><?php esc_html_e( 'Note', 'societypress' ); ?></label></th>
                    <td><textarea name="note" id="sp-d-note" rows="3" class="sp-full-width"><?php echo esc_textarea( $donation->note ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><?php esc_html_e( 'Options', 'societypress' ); ?></th>
                    <td>
                        <label><input type="checkbox" name="is_anonymous" value="1" <?php checked( $donation->is_anonymous ?? 0, 1 ); ?>> <?php esc_html_e( 'Anonymous donation', 'societypress' ); ?></label>
                    </td>
                </tr>
            </table>

            <p class="submit">
                <button type="submit" class="button button-primary"><?php echo $donation_id ? esc_html__( 'Save Changes', 'societypress' ) : esc_html__( 'Record Donation', 'societypress' ); ?></button>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-donations' ) ); ?>" class="button"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
            </p>
        </form>

        <script>
        // Auto-fill donor name/email when a member is selected
        document.getElementById('sp-d-member').addEventListener('change', function() {
            var opt = this.options[this.selectedIndex];
            if (this.value) {
                document.getElementById('sp-d-name').value = opt.getAttribute('data-name') || '';
                document.getElementById('sp-d-email').value = opt.getAttribute('data-email') || '';
            }
        });

        // Show/hide in-kind description based on type
        document.getElementById('sp-d-type').addEventListener('change', function() {
