        });
        </script>
    </div>
    <?php
}

/**
 * Replace donation-specific merge tags in a template string.
 *
 * WHY: Donation acknowledgment emails use a different set of merge tags than
 *      the member-based emails (which use sp_replace_merge_tags). Donors may
 *      not be members, so the tags map to donation fields: donor_name, amount,
 *      campaign, date, etc. This follows the same pattern as sp_replace_merge_tags
 *      but for donation context.
 *
 * @param string $content Template string containing {{merge_tags}}.
 * @param object $donation Donation row from sp_donations (with campaign_name joined).
 * @return string Content with tags replaced.
 */
function sp_replace_donation_merge_tags( string $content, object $donation ): string {
    $settings = get_option( 'societypress_settings', [] );
    $org_name = $settings['organization_name'] ?? get_bloginfo( 'name' );

    // Format the amount — skip for in-kind donations where amount may be 0
    $amount_display = ( $donation->type !== 'in_kind' && $donation->amount )
        ? sp_format_currency( $donation->amount )
        : '';

    // Campaign line — show "Campaign: Name" if there's a campaign, empty otherwise.
    // WHY: The template might wrap this in a <p> tag, so returning an empty string
    // lets the admin remove the whole paragraph if they don't use campaigns.
    $campaign_display = ! empty( $donation->campaign_name )
        ? sprintf( __( 'Campaign: %s', 'societypress' ), $donation->campaign_name )
        : '';

    $tags = [
        '{{donor_name}}'          => $donation->donor_name ?? '',
        '{{donor_email}}'         => $donation->donor_email ?? '',
        '{{amount}}'              => $amount_display,
        '{{campaign}}'            => $campaign_display,
        '{{donation_date}}'       => ! empty( $donation->date ) ? wp_date( 'F j, Y', strtotime( $donation->date ) ) : '',
        '{{donation_type}}'       => ucfirst( str_replace( '_', ' ', $donation->type ?? '' ) ),
        '{{in_kind_description}}' => $donation->in_kind_description ?? '',
        '{{organization_name}}'   => $org_name,
        '{{site_url}}'            => home_url(),
        '{{admin_email}}'         => $settings['organization_email'] ?? get_option( 'admin_email' ),
    ];

    return str_replace( array_keys( $tags ), array_values( $tags ), $content );
}

/**
 * Send donation acknowledgment emails for selected donation IDs.
 *
 * WHY: The treasurer needs to send thank-you emails for tax-deductible
 *      donations. This function handles the batch: loads the email template
 *      from settings (or falls back to the default), replaces merge tags,
 *      sends via wp_mail, logs to sp_email_log, and marks the donation as
 *      acknowledged. Uses the same template system as the other email types
 *      so the admin can customize wording from Settings > Email Templates.
 *
 * @param array $donation_ids Array of donation row IDs.
 */
function sp_send_donation_acknowledgments( array $donation_ids ): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );
    $headers  = sp_get_email_headers();

    // Load the customized template, or fall back to the default.
    // WHY: Same pattern as welcome/renewal/expired emails — the admin can
    // customize subject and body from the Email Templates page, but if they
    // haven't touched it, the sensible default kicks in.
    $subject_template = $settings['donation_acknowledgment_subject']
        ?? __( 'Thank You for Your Donation — {{organization_name}}', 'societypress' );
    $body_template    = $settings['email_template_donation_acknowledgment']
        ?? sp_get_default_email_template( 'donation_acknowledgment' );

    foreach ( $donation_ids as $did ) {
        $donation = $wpdb->get_row( $wpdb->prepare(
            "SELECT d.*, c.name AS campaign_name
             FROM {$prefix}donations d
             LEFT JOIN {$prefix}campaigns c ON d.campaign_id = c.id
             WHERE d.id = %d", $did
        ) );

        if ( ! $donation || ! $donation->donor_email || $donation->acknowledgment_sent ) {
            continue; // Skip if no email or already acknowledged
        }

        // Replace merge tags in both subject and body
        $subject   = sp_replace_donation_merge_tags( $subject_template, $donation );
        $body_html = sp_replace_donation_merge_tags( $body_template, $donation );

        $full_html = sp_build_email_html(
            __( 'Donation Acknowledgment', 'societypress' ),
            $body_html
        );

        $sent = wp_mail( $donation->donor_email, $subject, $full_html, $headers );

        // Log to email log
        sp_email_log_insert(
            $donation->donor_email,
            $subject,
            $full_html,
            implode( "\n", $headers ),
            $sent ? 'sent' : 'failed',
            $sent ? null : 'wp_mail() returned false',
            $donation->user_id ? (int) $donation->user_id : null,
            'donation_acknowledgment'
        );

        // Mark as acknowledged
        if ( $sent ) {
            $wpdb->update( $prefix . 'donations', [
                'acknowledgment_sent' => 1,
                'acknowledgment_date' => current_time( 'mysql' ),
            ], [ 'id' => $did ] );
        }
    }
}


/**
 * Render the Campaigns list page.
 *
 * WHY: Campaigns organize donations around specific fundraising goals.
 *      The list shows each campaign's name, goal, amount raised, status,
 *      and date range. The raised amount is a live sum from sp_donations.
 */
function sp_render_campaigns_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Handle delete
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && isset( $_POST['campaign_id'] ) ) {
        check_admin_referer( 'sp_delete_campaign_' . $_POST['campaign_id'] );
        // Don't delete donations — just unlink them
        $wpdb->update( $prefix . 'donations', [ 'campaign_id' => null ], [ 'campaign_id' => (int) $_POST['campaign_id'] ] );
        $wpdb->delete( $prefix . 'campaigns', [ 'id' => (int) $_POST['campaign_id'] ] );
        wp_safe_redirect( admin_url( 'admin.php?page=sp-campaigns&deleted=1' ) );
        exit;
    }

    $campaigns = $wpdb->get_results(
        "SELECT c.*,
                u.display_name AS created_by_name,
                COALESCE((SELECT SUM(d.amount) FROM {$prefix}donations d WHERE d.campaign_id = c.id), 0) AS raised,
                (SELECT COUNT(*) FROM {$prefix}donations d WHERE d.campaign_id = c.id) AS donation_count
         FROM {$prefix}campaigns c
         LEFT JOIN {$wpdb->users} u ON c.created_by = u.ID
         ORDER BY c.status ASC, c.created_at DESC"
    );

    ?>
    <div class="wrap sp-admin-wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Campaigns', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaign-edit' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Add New', 'societypress' ); ?></a>

        <?php if ( isset( $_GET['deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Campaign deleted. Donations have been unlinked.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( isset( $_GET['saved'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Campaign saved.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <table class="widefat striped" class="sp-mt-16">
            <thead>
                <tr>
                    <th><?php esc_html_e( 'Campaign', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Goal', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Raised', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Progress', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Status', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Date Range', 'societypress' ); ?></th>
                    <th><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                </tr>
            </thead>
            <tbody>
                <?php if ( empty( $campaigns ) ) : ?>
                    <tr><td colspan="7" class="sp-text-center" class="sp-p-20"><?php esc_html_e( 'No campaigns yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaign-edit' ) ); ?>"><?php esc_html_e( 'Create one', 'societypress' ); ?></a>.</td></tr>
                <?php else : ?>
                    <?php foreach ( $campaigns as $c ) : ?>
                        <?php
                        $raised    = (float) $c->raised;
                        $goal      = (float) ( $c->goal_amount ?? 0 );
                        $pct       = $goal > 0 ? min( 100, round( ( $raised / $goal ) * 100 ) ) : 0;
                        $bar_color = $pct >= 100 ? '#00a32a' : '#2271b1';
                        ?>
                        <tr>
                            <td>
                                <strong><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaign-edit&campaign_id=' . $c->id ) ); ?>"><?php echo esc_html( $c->name ); ?></a></strong>
                                <?php if ( $c->description ) : ?>
                                    <br><span class="sp-text-muted sp-text-sm"><?php echo esc_html( wp_trim_words( $c->description, 15 ) ); ?></span>
                                <?php endif; ?>
                            </td>
                            <td><?php echo $goal > 0 ? esc_html( sp_format_currency( $goal ) ) : '—'; ?></td>
                            <td class="sp-fw-600 sp-text-success"><?php echo esc_html( sp_format_currency( $raised ) ); ?> <span style="font-weight: normal; color: #787c82;">(<?php echo (int) $c->donation_count; ?>)</span></td>
                            <td class="sp-w-120">
                                <?php if ( $goal > 0 ) : ?>
                                    <div style="background: #e5e7eb; border-radius: 4px; height: 16px; overflow: hidden;">
                                        <div style="background: <?php echo $bar_color; ?>; height: 100%; width: <?php echo $pct; ?>%; border-radius: 4px;"></div>
                                    </div>
                                    <span style="font-size: 11px; color: #787c82;"><?php echo $pct; ?>%</span>
                                <?php else : ?>
                                    —
                                <?php endif; ?>
                            </td>
                            <td>
                                <?php
                                $status_colors = [ 'active' => '#00a32a', 'closed' => '#787c82', 'draft' => '#dba617' ];
                                $color = $status_colors[ $c->status ] ?? '#787c82';
                                printf( '<span style="color: %s; font-weight: 600;">%s</span>', esc_attr( $color ), esc_html( ucfirst( $c->status ) ) );
                                ?>
                            </td>
                            <td>
                                <?php
                                $dates = [];
                                if ( $c->start_date ) $dates[] = date_i18n( 'M j, Y', strtotime( $c->start_date ) );
                                if ( $c->end_date )   $dates[] = date_i18n( 'M j, Y', strtotime( $c->end_date ) );
                                echo $dates ? implode( ' — ', $dates ) : '—';
                                ?>
                            </td>
                            <td>
                                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaign-edit&campaign_id=' . $c->id ) ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a>
                                |
                                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-donations&campaign=' . $c->id ) ); ?>"><?php esc_html_e( 'Donations', 'societypress' ); ?></a>
                                |
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaigns' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this campaign? Donations will be unlinked, not deleted.', 'societypress' ) ); ?>">
                                    <?php wp_nonce_field( 'sp_delete_campaign_' . $c->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="campaign_id" value="<?php echo (int) $c->id; ?>">
                                    <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>
    </div>
    <?php
}

/**
 * Render the Campaign edit/add page.
 *
 * WHY: Simple form for creating or editing a fundraising campaign.
 *      Name and status are required; goal, description, and dates are optional.
 */
function sp_render_campaign_edit_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $campaign_id = (int) ( $_GET['campaign_id'] ?? 0 );
    $campaign    = null;

    if ( $campaign_id ) {
        $campaign = $wpdb->get_row( $wpdb->prepare(
            "SELECT * FROM {$prefix}campaigns WHERE id = %d", $campaign_id
        ) );
        if ( ! $campaign ) {
            echo '<div class="wrap"><h1>' . esc_html__( 'Campaign Not Found', 'societypress' ) . '</h1><p><a href="' . esc_url( admin_url( 'admin.php?page=sp-campaigns' ) ) . '">&larr; ' . esc_html__( 'Back', 'societypress' ) . '</a></p></div>';
            return;
        }
    }

    // Handle save
    if ( $_SERVER['REQUEST_METHOD'] === 'POST' && isset( $_POST['sp_campaign_nonce'] ) ) {
        check_admin_referer( 'sp_save_campaign', 'sp_campaign_nonce' );

        $name = sanitize_text_field( $_POST['name'] ?? '' );
        if ( ! $name ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Campaign name is required.', 'societypress' ) . '</p></div>';
        } else {
            $data = [
                'name'        => $name,
                'slug'        => sanitize_title( $name ),
                'description' => sanitize_textarea_field( $_POST['description'] ?? '' ) ?: null,
                'goal_amount' => (float) ( $_POST['goal_amount'] ?? 0 ) ?: null,
                'start_date'  => sanitize_text_field( $_POST['start_date'] ?? '' ) ?: null,
                'end_date'    => sanitize_text_field( $_POST['end_date'] ?? '' ) ?: null,
                'status'      => sanitize_text_field( $_POST['campaign_status'] ?? 'active' ),
                'updated_at'  => current_time( 'mysql' ),
            ];

            if ( $campaign_id ) {
                $wpdb->update( $prefix . 'campaigns', $data, [ 'id' => $campaign_id ] );
            } else {
                $data['created_by']  = get_current_user_id();
                $data['created_at']  = current_time( 'mysql' );
                $wpdb->insert( $prefix . 'campaigns', $data );
            }

            wp_safe_redirect( admin_url( 'admin.php?page=sp-campaigns&saved=1' ) );
            exit;
        }
    }

    ?>
    <div class="wrap sp-admin-wrap">
        <h1><?php echo $campaign_id ? esc_html__( 'Edit Campaign', 'societypress' ) : esc_html__( 'Add New Campaign', 'societypress' ); ?></h1>
        <p><a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaigns' ) ); ?>">&larr; Back to Campaigns</a></p>

        <form method="post" class="sp-max-w-600">
            <?php wp_nonce_field( 'sp_save_campaign', 'sp_campaign_nonce' ); ?>

            <table class="form-table">
                <tr>
                    <th><label for="sp-c-name">Campaign Name <span class="sp-text-error">*</span></label></th>
                    <td><input type="text" name="name" id="sp-c-name" value="<?php echo esc_attr( $campaign->name ?? '' ); ?>" required class="sp-full-width"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-desc"><?php esc_html_e( 'Description', 'societypress' ); ?></label></th>
                    <td><textarea name="description" id="sp-c-desc" rows="4" class="sp-full-width"><?php echo esc_textarea( $campaign->description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="sp-c-goal"><?php esc_html_e( 'Goal Amount', 'societypress' ); ?></label></th>
                    <td><input type="number" name="goal_amount" id="sp-c-goal" value="<?php echo esc_attr( $campaign->goal_amount ?? '' ); ?>" step="0.01" min="0" class="sp-w-150" placeholder="0.00"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-start"><?php esc_html_e( 'Start Date', 'societypress' ); ?></label></th>
                    <td><input type="date" name="start_date" id="sp-c-start" value="<?php echo esc_attr( $campaign->start_date ?? '' ); ?>"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-end"><?php esc_html_e( 'End Date', 'societypress' ); ?></label></th>
                    <td><input type="date" name="end_date" id="sp-c-end" value="<?php echo esc_attr( $campaign->end_date ?? '' ); ?>"></td>
                </tr>
                <tr>
                    <th><label for="sp-c-status"><?php esc_html_e( 'Status', 'societypress' ); ?></label></th>
                    <td>
                        <select name="campaign_status" id="sp-c-status">
                            <option value="active" <?php selected( $campaign->status ?? 'active', 'active' ); ?>>Active</option>
                            <option value="draft" <?php selected( $campaign->status ?? '', 'draft' ); ?>>Draft</option>
                            <option value="closed" <?php selected( $campaign->status ?? '', 'closed' ); ?>>Closed</option>
                        </select>
                    </td>
                </tr>
            </table>

            <p class="submit">
                <button type="submit" class="button button-primary"><?php echo $campaign_id ? esc_html__( 'Save Changes', 'societypress' ) : esc_html__( 'Create Campaign', 'societypress' ); ?></button>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-campaigns' ) ); ?>" class="button"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
            </p>
        </form>
    </div>
    <?php
}


// ============================================================================
// GDPR COMPLIANCE — PRIVACY POLICY, DATA EXPORT, DATA ERASURE
// ============================================================================
//
// WHY: SocietyPress stores personal data in custom database tables that
//      WordPress doesn't know about. Without these hooks:
//        - The Privacy Policy page has no idea we collect member data
//        - "Export Personal Data" finds nothing in our tables
//        - "Erase Personal Data" leaves our records untouched
//
//      This is a legal problem under GDPR, CCPA, and similar regulations.
//      These three hooks make SocietyPress a good citizen of the WordPress
//      privacy framework.
// ============================================================================


// --------------------------------------------------------------------------
// 1. SUGGESTED PRIVACY POLICY CONTENT
// --------------------------------------------------------------------------
//
// WHY: WordPress's Privacy page has a "Policy Guide" tab where plugins can
//      contribute suggested text. Harold can copy it into his Privacy Policy
//      page — or adapt it. This saves him from having to figure out what
//      data we collect and how to describe it. We register it once; WordPress
//      shows it on wp-admin/privacy-policy-guide.php.
// --------------------------------------------------------------------------

add_action( 'admin_init', function () {
    wp_add_privacy_policy_content(
        'SocietyPress',
        '<p>' . __( 'SocietyPress automatically generates a complete privacy policy for your Privacy Policy page using the <strong>Privacy Policy</strong> page template. No manual configuration is needed — the policy adapts to your current site settings.', 'societypress' ) . '</p>'
    );
} );

/**
 * Register the Privacy Policy page template.
 *
 * WHY: Page templates appear in the "Template" dropdown on the Edit Page screen.
 *      Harold doesn't need to know this exists — the Privacy Policy page is
 *      auto-created with this template on activation. But if he ever needs to
 *      assign it to a different page, it's available.
 */
add_filter( 'theme_page_templates', function ( $templates ) {
    $templates['sp-privacy-policy'] = __( 'Privacy Policy', 'societypress' );
    return $templates;
} );

/**
 * Render the Privacy Policy page template.
 *
 * WHY: When WordPress loads a page assigned to the sp-privacy-policy template,
 *      we intercept it and render the complete privacy policy inside the active
 *      theme's header/footer. The policy is generated dynamically based on the
 *      site's actual configuration — no manual maintenance needed.
 */
add_filter( 'template_include', function ( $template ) {
    if ( ! is_page() || get_page_template_slug() !== 'sp-privacy-policy' ) {
        return $template;
    }

    get_header();
    echo '<div class="entry-content" style="max-width:var(--sp-content-width,800px); margin:40px auto; padding:0 20px;">';
    echo '<h1 class="entry-title">' . esc_html( get_the_title() ) . '</h1>';
    sp_render_privacy_policy_content();
    echo '</div>';
    get_footer();

    return sp_get_blank_template_path();
}, 50 );

/**
 * Render the privacy policy content.
 *
 * WHY: Harold should never have to write or maintain a privacy policy by hand.
 *      This function renders a complete, legally comprehensive privacy policy
 *      that adapts dynamically to the site's actual configuration:
 *
 *      - Google Analytics enabled? The cookie disclosure appears automatically.
 *      - Stripe keys configured? The payment section appears.
 *      - Donations module enabled? The donation data section appears.
 *      - Store module enabled? Store purchase data is disclosed.
 *
 *      Using a template means the content can't be accidentally deleted by
 *      editing the page. The page content is ignored — the template controls
 *      everything.
 */
function sp_render_privacy_policy_content(): void {

    $settings    = get_option( 'societypress_settings', [] );
    $org_name    = esc_html( $settings['organization_name'] ?? get_bloginfo( 'name' ) );
    $org_email   = esc_html( $settings['organization_email'] ?? get_option( 'admin_email' ) );
    $site_url    = esc_url( home_url( '/' ) );
    $ga_enabled  = ! empty( $settings['analytics_google_id'] );
    $has_stripe  = ! empty( $settings['stripe_test_publishable_key'] ) || ! empty( $settings['stripe_live_publishable_key'] );
    $has_donations = sp_module_enabled( 'donations' );
    $has_store     = sp_module_enabled( 'store' );
    $has_events    = sp_module_enabled( 'events' );
    $has_library   = sp_module_enabled( 'library' );
    $has_volunteers = sp_module_enabled( 'governance' );
    $has_records   = sp_module_enabled( 'records' );
    $has_blast     = sp_module_enabled( 'blast_email' );
    $has_newsletters = sp_module_enabled( 'newsletters' );
    $has_documents = sp_module_enabled( 'documents' );
    $last_updated  = current_time( 'F j, Y' );
    ?>
    <div class="sp-privacy-policy">

        <p><em><?php printf( esc_html__( 'Last updated: %s', 'societypress' ), $last_updated ); ?></em></p>

        <!-- ============================================================ -->
        <!-- WHO WE ARE                                                   -->
        <!-- ============================================================ -->
        <h2><?php esc_html_e( 'Who We Are', 'societypress' ); ?></h2>
        <p><?php printf(
            esc_html__( 'This website is operated by %s. Our website address is: %s', 'societypress' ),
            '<strong>' . $org_name . '</strong>',
            '<a href="' . $site_url . '">' . $site_url . '</a>'
        ); ?></p>
        <?php if ( $org_email ) : ?>
            <p><?php printf( esc_html__( 'For privacy-related inquiries, contact us at %s.', 'societypress' ), '<a href="mailto:' . $org_email . '">' . $org_email . '</a>' ); ?></p>
        <?php endif; ?>

        <!-- ============================================================ -->
        <!-- WHAT DATA WE COLLECT                                         -->
        <!-- ============================================================ -->
        <h2><?php esc_html_e( 'What Personal Data We Collect and Why', 'societypress' ); ?></h2>

        <h3><?php esc_html_e( 'Membership Information', 'societypress' ); ?></h3>
        <p><?php esc_html_e( 'When you join as a member, we collect:', 'societypress' ); ?></p>
        <ul>
            <li><?php esc_html_e( 'Your name (first, last, and optionally preferred name, middle name, maiden name, prefix, and suffix)', 'societypress' ); ?></li>
            <li><?php esc_html_e( 'Email address', 'societypress' ); ?></li>
            <li><?php esc_html_e( 'Mailing address (and optionally a seasonal address)', 'societypress' ); ?></li>
            <li><?php esc_html_e( 'Phone number(s) (home, cell, work)', 'societypress' ); ?></li>
            <li><?php esc_html_e( 'Optional: date of birth, profile photo, personal website', 'societypress' ); ?></li>
            <li><?php esc_html_e( 'If you have a joint (couple/household) membership: your partner\'s name, email, and phone number', 'societypress' ); ?></li>
        </ul>
        <p><?php esc_html_e( 'We use this information to manage your membership, communicate with you about society activities, process renewals, and (if you opt in) display your information in the member directory.', 'societypress' ); ?></p>
        <p><?php esc_html_e( 'Sensitive contact information — including phone numbers and street addresses — is encrypted at rest using modern cryptographic methods. Even in the unlikely event of a database breach, these fields cannot be read without the encryption key.', 'societypress' ); ?></p>
        <p><?php esc_html_e( 'You control which of your personal details are visible to other members through the directory privacy settings on your account page.', 'societypress' ); ?></p>

        <h3><?php esc_html_e( 'Genealogical Research Information', 'societypress' ); ?></h3>
        <p><?php esc_html_e( 'Members may optionally provide:', 'societypress' ); ?></p>
        <ul>
            <li><?php esc_html_e( 'Surnames being researched, including geographic location and date ranges', 'societypress' ); ?></li>
            <li><?php esc_html_e( 'Geographic research areas of interest', 'societypress' ); ?></li>
