            <?php endif; ?>
        </ul>

    </div>
    <?php
}


// --------------------------------------------------------------------------
// 2. PERSONAL DATA EXPORTER
// --------------------------------------------------------------------------
//
// WHY: Under Tools > Export Personal Data, WordPress lets an admin fulfill
//      "give me all my data" requests. But it only knows about wp_users and
//      wp_comments. We need to register exporters that find personal data in
//      our custom tables (sp_members, sp_event_registrations, sp_event_speakers)
//      and include it in the export ZIP.
//
//      The exporter receives an email address and returns structured data.
//      WordPress handles the rest — packaging it into a nice HTML/JSON export.
// --------------------------------------------------------------------------

add_filter( 'wp_privacy_personal_data_exporters', function ( $exporters ) {

    // Membership data exporter
    $exporters['societypress-members'] = [
        'exporter_friendly_name' => 'SocietyPress Membership Data',
        'callback'               => 'sp_privacy_export_member_data',
    ];

    // Event registration exporter
    $exporters['societypress-registrations'] = [
        'exporter_friendly_name' => 'SocietyPress Event Registrations',
        'callback'               => 'sp_privacy_export_registration_data',
    ];

    // Speaker data exporter (in case a speaker requests their data)
    $exporters['societypress-speakers'] = [
        'exporter_friendly_name' => 'SocietyPress Speaker Profile',
        'callback'               => 'sp_privacy_export_speaker_data',
    ];

    // Volunteer data exporter
    $exporters['societypress-volunteers'] = [
        'exporter_friendly_name' => 'SocietyPress Volunteer Data',
        'callback'               => 'sp_privacy_export_volunteer_data',
    ];

    // Help requests exporter
    $exporters['societypress-help-requests'] = [
        'exporter_friendly_name' => 'SocietyPress Help Requests',
        'callback'               => 'sp_privacy_export_help_data',
    ];

    // Donation data exporter
    $exporters['societypress-donations'] = [
        'exporter_friendly_name' => 'SocietyPress Donations',
        'callback'               => 'sp_privacy_export_donation_data',
    ];

    return $exporters;
} );


/**
 * Export membership data for a given email address.
 *
 * WHY: The sp_members table is keyed by user_id, not email. So we look up
 *      the WordPress user by email first, then find their member record.
 */
function sp_privacy_export_member_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $export_items = [];

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) {
        return [ 'data' => $export_items, 'done' => true ];
    }

    $member = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_members WHERE user_id = %d",
        $user->ID
    ) );
    // Decrypt sensitive contact/address fields for GDPR plaintext export
    $member = sp_member_decrypt_row( $member );

    if ( ! $member ) {
        return [ 'data' => $export_items, 'done' => true ];
    }

    // Build the export data array — every personal field we store
    // WHY: i18n — member type/status need static labels for translators
    $member_type_labels = [
        'individual'   => __( 'Individual', 'societypress' ),
        'organization' => __( 'Organization', 'societypress' ),
    ];
    $member_status_labels = [
        'active'   => __( 'Active', 'societypress' ),
        'expired'  => __( 'Expired', 'societypress' ),
        'lapsed'   => __( 'Lapsed', 'societypress' ),
        'deceased' => __( 'Deceased', 'societypress' ),
        'inactive' => __( 'Inactive', 'societypress' ),
    ];
    $none_label = __( '(none)', 'societypress' );

    $data = [
        [ 'name' => __( 'Member Type', 'societypress' ),      'value' => $member_type_labels[ $member->member_type ?? 'individual' ] ?? ucfirst( $member->member_type ?? 'individual' ) ],
        [ 'name' => __( 'Organization Name', 'societypress' ),'value' => $member->organization_name ?: $none_label ],
        [ 'name' => __( 'Member Number', 'societypress' ),    'value' => $member->member_number ?: $none_label ],
        [ 'name' => __( 'Status', 'societypress' ),           'value' => $member_status_labels[ $member->status ] ?? ucfirst( $member->status ) ],
        [ 'name' => __( 'Name', 'societypress' ),             'value' => trim( $member->prefix . ' ' . $member->first_name . ' ' . $member->middle_name . ' ' . $member->last_name . ' ' . $member->suffix ) ],
        [ 'name' => __( 'Preferred Name', 'societypress' ),   'value' => $member->preferred_name ?: $none_label ],
        [ 'name' => __( 'Maiden Name', 'societypress' ),      'value' => $member->maiden_name ?: $none_label ],
        [ 'name' => __( 'Date of Birth', 'societypress' ),    'value' => $member->date_of_birth ?: __( '(not provided)', 'societypress' ) ],
        [ 'name' => __( 'Join Date', 'societypress' ),        'value' => $member->join_date ],
        [ 'name' => __( 'Expiration Date', 'societypress' ),  'value' => $member->expiration_date ?: $none_label ],
        [ 'name' => __( 'Address', 'societypress' ),          'value' => implode( ', ', array_filter( [
            $member->address_1, $member->address_2, $member->city,
            $member->state, $member->postal_code, $member->country,
        ] ) ) ?: $none_label ],
        [ 'name' => __( 'Phone', 'societypress' ),            'value' => $member->phone ?: $none_label ],
        [ 'name' => __( 'Cell', 'societypress' ),             'value' => $member->cell ?: $none_label ],
        [ 'name' => __( 'Website', 'societypress' ),          'value' => $member->website ?: $none_label ],
    ];

    // Include seasonal address if they have one
    if ( $member->seasonal ) {
        $data[] = [ 'name' => __( 'Seasonal Address', 'societypress' ), 'value' => implode( ', ', array_filter( [
            $member->seasonal_address_1, $member->seasonal_city,
            $member->seasonal_state, $member->seasonal_postal_code, $member->seasonal_country,
        ] ) ) ];
        $data[] = [ 'name' => __( 'Seasonal Period', 'societypress' ), 'value' => ( $member->seasonal_from ?: '?' ) . ' ' . __( 'to', 'societypress' ) . ' ' . ( $member->seasonal_to ?: '?' ) ];
    }

    // Communication preferences
    $prefs = [];
    if ( $member->pref_email_notices )      $prefs[] = __( 'General Notices', 'societypress' );
    if ( $member->pref_email_events )       $prefs[] = __( 'Events', 'societypress' );
    if ( $member->pref_email_newsletters )  $prefs[] = __( 'Newsletters', 'societypress' );
    if ( $member->pref_email_surnames )     $prefs[] = __( 'Surname Alerts', 'societypress' );
    $data[] = [ 'name' => __( 'Email Preferences', 'societypress' ), 'value' => $prefs ? implode( ', ', $prefs ) : __( '(all disabled)', 'societypress' ) ];

    // Directory visibility settings
    $dir = [];
    if ( $member->dir_show_name )    $dir[] = __( 'Name', 'societypress' );
    if ( $member->dir_show_address ) $dir[] = __( 'Address', 'societypress' );
    if ( $member->dir_show_phone )   $dir[] = __( 'Phone', 'societypress' );
    if ( $member->dir_show_email )   $dir[] = __( 'Email', 'societypress' );
    if ( $member->dir_show_website ) $dir[] = __( 'Website', 'societypress' );
    if ( $member->dir_show_photo )   $dir[] = __( 'Photo', 'societypress' );
    $data[] = [ 'name' => __( 'Directory Visibility', 'societypress' ), 'value' => $dir ? implode( ', ', $dir ) : __( '(all hidden)', 'societypress' ) ];

    $export_items[] = [
        'group_id'          => 'societypress-member',
        'group_label'       => __( 'Membership Profile', 'societypress' ),
        'group_description' => __( 'Your membership information stored by this site.', 'societypress' ),
        'item_id'           => 'member-' . $member->user_id,
        'data'              => $data,
    ];

    return [ 'data' => $export_items, 'done' => true ];
}


/**
 * Export event registration data for a given email address.
 *
 * WHY: Registrations can be tied to a user_id (members) or a guest_email
 *      (non-members). We check both — the same email might appear in both
 *      contexts if someone registered as a guest before becoming a member.
 */
function sp_privacy_export_registration_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $export_items = [];
    $reg_table    = $wpdb->prefix . 'sp_event_registrations';
    $evt_table    = $wpdb->prefix . 'sp_events';

    // Find registrations by user email (member) OR guest email
    $user = get_user_by( 'email', $email_address );
    $user_id = $user ? $user->ID : 0;

    $registrations = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, e.title AS event_title, e.event_date
         FROM {$reg_table} r
         LEFT JOIN {$evt_table} e ON r.event_id = e.id
         WHERE r.user_id = %d OR r.guest_email = %s
         ORDER BY r.registered_at DESC",
        $user_id, $email_address
    ) );

    // WHY: i18n status labels — translators need static strings, not ucfirst() on DB values
    $export_status_labels = [
        'confirmed'  => __( 'Confirmed', 'societypress' ),
        'waitlisted' => __( 'Waitlisted', 'societypress' ),
        'cancelled'  => __( 'Cancelled', 'societypress' ),
        'pending'    => __( 'Pending', 'societypress' ),
    ];
    $export_pay_labels = [
        'paid'     => __( 'Paid', 'societypress' ),
        'refunded' => __( 'Refunded', 'societypress' ),
        'pending'  => __( 'Pending', 'societypress' ),
        'none'     => __( 'None', 'societypress' ),
    ];

    foreach ( $registrations as $reg ) {
        $data = [
            [ 'name' => __( 'Event', 'societypress' ),            'value' => $reg->event_title ?: __( '(deleted event)', 'societypress' ) ],
            [ 'name' => __( 'Event Date', 'societypress' ),       'value' => $reg->event_date ?: __( '(unknown)', 'societypress' ) ],
            [ 'name' => __( 'Registration Type', 'societypress' ), 'value' => $reg->user_id ? __( 'Member', 'societypress' ) : __( 'Guest', 'societypress' ) ],
            [ 'name' => __( 'Status', 'societypress' ),           'value' => $export_status_labels[ $reg->status ] ?? ucfirst( $reg->status ) ],
            [ 'name' => __( 'Party Size', 'societypress' ),       'value' => (string) $reg->party_size ],
            [ 'name' => __( 'Fee', 'societypress' ),              'value' => $reg->fee_amount > 0 ? sp_format_currency( $reg->fee_amount ) : __( 'Free', 'societypress' ) ],
            [ 'name' => __( 'Payment Status', 'societypress' ),   'value' => $export_pay_labels[ $reg->payment_status ] ?? ucfirst( $reg->payment_status ) ],
            [ 'name' => __( 'Registered At', 'societypress' ),    'value' => $reg->registered_at ],
        ];

        // Include guest fields if this was a guest registration
        if ( ! $reg->user_id ) {
            $data[] = [ 'name' => __( 'Guest Name', 'societypress' ),  'value' => $reg->guest_name ?: '' ];
            $data[] = [ 'name' => __( 'Guest Email', 'societypress' ), 'value' => $reg->guest_email ?: '' ];
            $data[] = [ 'name' => __( 'Guest Phone', 'societypress' ), 'value' => $reg->guest_phone ?: '' ];
        }

        $export_items[] = [
            'group_id'          => 'societypress-registrations',
            'group_label'       => __( 'Event Registrations', 'societypress' ),
            'group_description' => __( 'Your event registration history on this site.', 'societypress' ),
            'item_id'           => 'registration-' . $reg->id,
            'data'              => $data,
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}


/**
 * Export speaker profile data for a given email address.
 *
 * WHY: If someone is listed as a speaker and requests their data, we need to
 *      include their speaker profile (name, bio, email, phone, website).
 */
function sp_privacy_export_speaker_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $export_items = [];

    $speaker = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_event_speakers WHERE email = %s",
        $email_address
    ) );

    if ( ! $speaker ) {
        return [ 'data' => $export_items, 'done' => true ];
    }

    $data = [
        [ 'name' => 'Name',    'value' => $speaker->name ],
        [ 'name' => 'Title',   'value' => $speaker->title ?: '(none)' ],
        [ 'name' => 'Bio',     'value' => $speaker->bio ?: '(none)' ],
        [ 'name' => 'Email',   'value' => $speaker->email ?: '(none)' ],
        [ 'name' => 'Phone',   'value' => $speaker->phone ?: '(none)' ],
        [ 'name' => 'Website', 'value' => $speaker->website ?: '(none)' ],
    ];

    $export_items[] = [
        'group_id'          => 'societypress-speakers',
        'group_label'       => 'Speaker Profile',
        'group_description' => 'Your speaker profile stored by this site.',
        'item_id'           => 'speaker-' . $speaker->id,
        'data'              => $data,
    ];

    return [ 'data' => $export_items, 'done' => true ];
}


// --------------------------------------------------------------------------
// 3. PERSONAL DATA ERASER
// --------------------------------------------------------------------------
//
// WHY: Under Tools > Erase Personal Data, WordPress lets an admin fulfill
//      "delete my data" requests (right to be forgotten). We register erasers
//      that remove or anonymize personal data in our custom tables.
//
//      For members: We remove the member record entirely (they can re-join).
//      For registrations: We anonymize guest fields but keep the record for
//        event capacity/financial reporting (replace name with "Deleted User",
//        clear email, phone, and notes).
//      For speakers: We anonymize the speaker record but keep the link to
//        events for historical accuracy.
// --------------------------------------------------------------------------

add_filter( 'wp_privacy_personal_data_erasers', function ( $erasers ) {

    $erasers['societypress-members'] = [
        'eraser_friendly_name' => 'SocietyPress Membership Data',
        'callback'             => 'sp_privacy_erase_member_data',
    ];

    $erasers['societypress-registrations'] = [
        'eraser_friendly_name' => 'SocietyPress Event Registrations',
        'callback'             => 'sp_privacy_erase_registration_data',
    ];

    $erasers['societypress-speakers'] = [
        'eraser_friendly_name' => 'SocietyPress Speaker Profile',
        'callback'             => 'sp_privacy_erase_speaker_data',
    ];

    // Volunteer data eraser
    $erasers['societypress-volunteers'] = [
        'eraser_friendly_name' => 'SocietyPress Volunteer Data',
        'callback'             => 'sp_privacy_erase_volunteer_data',
    ];

    // Help requests eraser
    $erasers['societypress-help-requests'] = [
        'eraser_friendly_name' => 'SocietyPress Help Requests',
        'callback'             => 'sp_privacy_erase_help_data',
    ];

    // Donation data eraser
    $erasers['societypress-donations'] = [
        'eraser_friendly_name' => 'SocietyPress Donations',
        'callback'             => 'sp_privacy_erase_donation_data',
    ];

    return $erasers;
} );


/**
 * Erase membership data for a given email address.
 *
 * WHY: When someone exercises their right to be forgotten, we delete their
 *      member record entirely. The WordPress user account is handled by core;
 *      we just clean up our custom table.
 */
function sp_privacy_erase_member_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $items_removed = 0;

    $user = get_user_by( 'email', $email_address );
    if ( $user ) {
        $deleted = $wpdb->delete(
            $wpdb->prefix . 'sp_members',
            [ 'user_id' => $user->ID ],
            [ '%d' ]
        );
        if ( $deleted ) {
            $items_removed = 1;
        }
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => 0,
        'messages'       => $items_removed ? [ 'Membership profile deleted.' ] : [],
        'done'           => true,
    ];
}


/**
 * Erase (anonymize) event registration data for a given email address.
 *
 * WHY: We can't just delete registration rows because the society needs them
 *      for financial reporting (who paid what) and capacity history. Instead,
 *      we anonymize: replace the name with "Deleted User," clear the email,
 *      phone, and notes. The registration record stays but is no longer tied
 *      to an identifiable person.
 */
function sp_privacy_erase_registration_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $reg_table      = $wpdb->prefix . 'sp_event_registrations';
    $items_removed  = 0;
    $items_retained = 0;

    // Anonymize guest registrations (matched by guest_email)
    $guest_regs = $wpdb->get_results( $wpdb->prepare(
        "SELECT id FROM {$reg_table} WHERE guest_email = %s",
        $email_address
    ) );

    foreach ( $guest_regs as $reg ) {
        $wpdb->update(
            $reg_table,
            [
                'guest_name'  => 'Deleted User',
                'guest_email' => '',
                'guest_phone' => '',
                'notes'       => '',
            ],
            [ 'id' => $reg->id ]
        );
        $items_removed++;
    }

    // Anonymize member registrations (matched by user_id via email lookup)
    $user = get_user_by( 'email', $email_address );
    if ( $user ) {
        $member_regs = $wpdb->get_results( $wpdb->prepare(
            "SELECT id FROM {$reg_table} WHERE user_id = %d",
            $user->ID
        ) );

        foreach ( $member_regs as $reg ) {
            $wpdb->update(
                $reg_table,
                [
                    'user_id' => null,
                    'notes'   => '',
                ],
                [ 'id' => $reg->id ]
            );
            $items_removed++;
        }
    }

    // The registration rows themselves are retained for financial records
    if ( $items_removed > 0 ) {
        $items_retained = $items_removed;
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => $items_retained,
        'messages'       => $items_removed
            ? [ sprintf( '%d registration(s) anonymized. Records retained for financial reporting.', $items_removed ) ]
            : [],
        'done'           => true,
    ];
}


/**
 * Erase (anonymize) speaker data for a given email address.
 *
 * WHY: A speaker might request deletion. We anonymize their profile (clear
 *      bio, email, phone, website) but keep the name and event assignments
 *      so the society's event history still makes sense. If they want the
 *      name removed too, the admin can manually edit the speaker record.
 */
function sp_privacy_erase_speaker_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $items_removed = 0;

    $speaker = $wpdb->get_row( $wpdb->prepare(
        "SELECT id FROM {$wpdb->prefix}sp_event_speakers WHERE email = %s",
        $email_address
    ) );

    if ( $speaker ) {
        $wpdb->update(
            $wpdb->prefix . 'sp_event_speakers',
            [
                'bio'     => '',
                'email'   => '',
                'phone'   => '',
                'website' => '',
            ],
            [ 'id' => $speaker->id ]
        );
        $items_removed = 1;
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => $items_removed ? 1 : 0,
        'messages'       => $items_removed
            ? [ 'Speaker profile anonymized. Name and event assignments retained for historical records.' ]
            : [],
        'done'           => true,
    ];
}


/**
 * Export volunteer data for GDPR requests.
 *
 * WHY: Volunteer hours and role assignments are personal data — they show
 *      what someone did, when, and for how long. Must be exportable.
 */
function sp_privacy_export_volunteer_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $export_items = [];

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'data' => $export_items, 'done' => true ];

    // Volunteer roles
    $roles = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}volunteer_roles WHERE user_id = %d", $user->ID
    ) );
    foreach ( $roles as $role ) {
        $export_items[] = [
            'group_id'    => 'sp-volunteer-roles',
            'group_label' => __( 'Volunteer Roles', 'societypress' ),
            'item_id'     => 'sp-volunteer-role-' . $role->id,
            'data'        => [
                [ 'name' => __( 'Role', 'societypress' ), 'value' => $role->role_title ],
                [ 'name' => __( 'Committee', 'societypress' ), 'value' => $role->committee ?: __( '(none)', 'societypress' ) ],
                [ 'name' => __( 'Start Date', 'societypress' ), 'value' => $role->start_date ?: __( '(none)', 'societypress' ) ],
                [ 'name' => __( 'End Date', 'societypress' ), 'value' => $role->end_date ?: __( 'Ongoing', 'societypress' ) ],
                [ 'name' => __( 'Status', 'societypress' ), 'value' => ucfirst( $role->status ) ],
            ],
        ];
    }

    // Volunteer hours
    $hours = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}volunteer_hours WHERE user_id = %d ORDER BY activity_date DESC", $user->ID
    ) );
    foreach ( $hours as $entry ) {
        $export_items[] = [
            'group_id'    => 'sp-volunteer-hours',
            'group_label' => 'Volunteer Hours',
            'item_id'     => 'sp-volunteer-hour-' . $entry->id,
            'data'        => [
                [ 'name' => 'Activity', 'value' => $entry->activity ?: '(none)' ],
                [ 'name' => 'Committee', 'value' => $entry->committee ?: '(none)' ],
                [ 'name' => 'Hours', 'value' => $entry->hours ],
                [ 'name' => 'Date', 'value' => $entry->activity_date ],
            ],
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}

/**
 * Export help request data for GDPR requests.
 */
function sp_privacy_export_help_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $export_items = [];

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'data' => $export_items, 'done' => true ];

    // Questions asked
    $requests = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}help_requests WHERE user_id = %d", $user->ID
    ) );
    foreach ( $requests as $req ) {
        $export_items[] = [
            'group_id'    => 'sp-help-requests',
            'group_label' => 'Research Help Requests',
            'item_id'     => 'sp-help-request-' . $req->id,
            'data'        => [
                [ 'name' => 'Title', 'value' => $req->title ],
                [ 'name' => 'Description', 'value' => $req->description ],
                [ 'name' => 'Status', 'value' => ucfirst( $req->status ) ],
                [ 'name' => 'Date', 'value' => $req->created_at ],
            ],
        ];
    }

    // Responses given
    $responses = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}help_responses WHERE user_id = %d", $user->ID
    ) );
    foreach ( $responses as $resp ) {
        $export_items[] = [
            'group_id'    => 'sp-help-responses',
            'group_label' => 'Research Help Responses',
            'item_id'     => 'sp-help-response-' . $resp->id,
            'data'        => [
                [ 'name' => 'Content', 'value' => $resp->content ],
                [ 'name' => 'Date', 'value' => $resp->created_at ],
            ],
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}

/**
 * Erase volunteer data for GDPR requests.
 */
function sp_privacy_erase_volunteer_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $items_removed = 0;

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'items_removed' => 0, 'items_retained' => 0, 'messages' => [], 'done' => true ];

    $items_removed += (int) $wpdb->delete( $prefix . 'volunteer_roles', [ 'user_id' => $user->ID ] );
    $items_removed += (int) $wpdb->delete( $prefix . 'volunteer_hours', [ 'user_id' => $user->ID ] );

    return [
        'items_removed'  => $items_removed,
        'items_retained' => 0,
        'messages'       => $items_removed > 0 ? [ 'Volunteer roles and hours deleted.' ] : [],
        'done'           => true,
    ];
}

/**
 * Erase help request data for GDPR requests.
 */
function sp_privacy_erase_help_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $items_removed = 0;

    $user = get_user_by( 'email', $email_address );
    if ( ! $user ) return [ 'items_removed' => 0, 'items_retained' => 0, 'messages' => [], 'done' => true ];

    // Delete responses first (FK integrity)
    $request_ids = $wpdb->get_col( $wpdb->prepare(
        "SELECT id FROM {$prefix}help_requests WHERE user_id = %d", $user->ID
    ) );
    if ( ! empty( $request_ids ) ) {
        $placeholders = implode( ',', array_fill( 0, count( $request_ids ), '%d' ) );
        $wpdb->query( $wpdb->prepare(
            "DELETE FROM {$prefix}help_responses WHERE request_id IN ({$placeholders})", ...$request_ids
        ) );
    }
    $items_removed += (int) $wpdb->delete( $prefix . 'help_requests', [ 'user_id' => $user->ID ] );
    $items_removed += (int) $wpdb->delete( $prefix . 'help_responses', [ 'user_id' => $user->ID ] );

    return [
        'items_removed'  => $items_removed,
        'items_retained' => 0,
        'messages'       => $items_removed > 0 ? [ 'Research help requests and responses deleted.' ] : [],
        'done'           => true,
    ];
}


/**
 * Export donation data for GDPR requests.
 *
 * WHY: The sp_donations table stores donor name, email, and donation details.
 *      Donations can be tied to a user_id (members) or matched by donor_email
 *      (non-member donors). Both paths need to be covered.
 */
function sp_privacy_export_donation_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix       = $wpdb->prefix . 'sp_';
    $export_items = [];

    // Find donations by user_id (member) or donor_email (non-member)
    $user    = get_user_by( 'email', $email_address );
    $user_id = $user ? $user->ID : 0;

    $donations = $wpdb->get_results( $wpdb->prepare(
        "SELECT d.*, c.name AS campaign_name
         FROM {$prefix}donations d
         LEFT JOIN {$prefix}donation_campaigns c ON d.campaign_id = c.id
         WHERE d.user_id = %d OR d.donor_email = %s
         ORDER BY d.date DESC",
        $user_id, $email_address
    ) );

    foreach ( $donations as $don ) {
        $data = [
            [ 'name' => 'Donor Name',   'value' => $don->donor_name ],
            [ 'name' => 'Donor Email',  'value' => $don->donor_email ?: '(none)' ],
            [ 'name' => 'Amount',       'value' => sp_format_currency( $don->amount ) ],
            [ 'name' => 'Type',         'value' => ucfirst( $don->type ) ],
            [ 'name' => 'Campaign',     'value' => $don->campaign_name ?: 'General/Unrestricted' ],
            [ 'name' => 'Date',         'value' => $don->date ],
            [ 'name' => 'Anonymous',    'value' => $don->is_anonymous ? 'Yes' : 'No' ],
            [ 'name' => 'Note',         'value' => $don->note ?: '(none)' ],
        ];

        if ( $don->type === 'in_kind' && $don->in_kind_description ) {
            $data[] = [ 'name' => 'In-Kind Description', 'value' => $don->in_kind_description ];
        }

        $export_items[] = [
            'group_id'          => 'societypress-donations',
            'group_label'       => 'Donations',
            'group_description' => 'Your donation history on this site.',
            'item_id'           => 'donation-' . $don->id,
            'data'              => $data,
        ];
    }

    return [ 'data' => $export_items, 'done' => true ];
}


/**
 * Erase (anonymize) donation data for GDPR requests.
 *
 * WHY: We can't delete donation records outright because the society needs them
 *      for tax and financial reporting. Instead we anonymize: clear donor name,
 *      email, notes, and unlink the user_id. The donation amount, date, and
 *      campaign linkage are retained for accounting purposes.
 */
function sp_privacy_erase_donation_data( string $email_address, int $page = 1 ): array {
    global $wpdb;
    $prefix         = $wpdb->prefix . 'sp_';
    $items_removed  = 0;
    $items_retained = 0;

    $user    = get_user_by( 'email', $email_address );
    $user_id = $user ? $user->ID : 0;

    // Find all donations linked to this person
    $donations = $wpdb->get_results( $wpdb->prepare(
        "SELECT id FROM {$prefix}donations WHERE user_id = %d OR donor_email = %s",
        $user_id, $email_address
    ) );

    foreach ( $donations as $don ) {
        $wpdb->update(
            $prefix . 'donations',
            [
                'donor_name'  => 'Deleted User',
                'donor_email' => '',
                'user_id'     => null,
                'note'        => '',
            ],
            [ 'id' => $don->id ]
        );
        $items_removed++;
    }

    // Records retained for financial reporting
    if ( $items_removed > 0 ) {
        $items_retained = $items_removed;
    }

    return [
        'items_removed'  => $items_removed,
        'items_retained' => $items_retained,
        'messages'       => $items_removed
            ? [ sprintf( '%d donation(s) anonymized. Financial records retained for tax reporting.', $items_removed ) ]
            : [],
        'done'           => true,
    ];
}

// ============================================================================
// AJAX: Library Item Detail (frontend expandable row)
//
// WHY: When a member clicks an item in the catalog, we fetch the full record
//      via AJAX and slide open a detail panel below the row — no page reload,
//      no separate URL. Keeps the user in context of their search results.
//      Accessible to logged-in users (wp_ajax_) only, matching catalog access.
// ============================================================================
add_action( 'wp_ajax_sp_library_item_detail', 'sp_ajax_library_item_detail' );
// Also register for non-logged-in users so the catalog expand works when
// the library widget is configured as public (login_required = false).
// WHY no nonce: Same as unified search — public endpoint for anonymous visitors.
// The data returned is read-only catalog info, not sensitive.
add_action( 'wp_ajax_nopriv_sp_library_item_detail', 'sp_ajax_library_item_detail' );
function sp_ajax_library_item_detail(): void {
    $item_id = absint( $_GET['item_id'] ?? 0 );
    if ( ! $item_id ) {
        wp_send_json_error( __( 'Missing item ID.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';
    $item = $wpdb->get_row( $wpdb->prepare(
        "SELECT li.*, lc.name as category_name
         FROM {$prefix}library_items li
         LEFT JOIN {$prefix}library_categories lc ON li.category_id = lc.id
         WHERE li.id = %d",
        $item_id
    ) );

    if ( ! $item ) {
        wp_send_json_error( __( 'Item not found.', 'societypress' ) );
    }

    // Build a clean publication date string from year/month/day parts
    $pub_date = '';
    if ( $item->pub_year ) {
        $pub_date = (string) $item->pub_year;
        if ( $item->pub_month ) {
            $pub_date = $item->pub_month . '/' . $pub_date;
            if ( $item->pub_day ) {
                $pub_date = $item->pub_day . '/' . $pub_date;
            }
        }
    }

    // Build acquisition date
    $acq_date = '';
    if ( $item->acq_year ) {
        $acq_date = (string) $item->acq_year;
        if ( $item->acq_month ) {
            $acq_date = $item->acq_month . '/' . $acq_date;
            if ( $item->acq_day ) {
                $acq_date = $item->acq_day . '/' . $acq_date;
            }
        }
    }

    // Parse subject field into array of individual tags
    $subjects = [];
    if ( $item->subject ) {
        $subjects = array_map( 'trim', explode( ',', $item->subject ) );
        $subjects = array_filter( $subjects );
        $subjects = array_values( $subjects );
    }

    // Parse surnames similarly
    $surnames = [];
    if ( $item->surname ) {
        $surnames = array_map( 'trim', explode( ',', $item->surname ) );
        $surnames = array_filter( $surnames );
        $surnames = array_values( $surnames );
    }

    $response = [
        'id'                  => $item->id,
        'system_id'           => $item->system_id,
        'title'               => $item->title,
        'author'              => $item->author ?: '',
        'description'         => $item->description ?: '',
        'publisher'           => $item->publisher ?: '',
        'publisher_location'  => $item->publisher_location ?: '',
        'pub_date'            => $pub_date,
        'pub_year'            => $item->pub_year ?: '',
        'media_type'          => $item->media_type ?: '',
        'isbn'                => $item->isbn ?: '',
        'call_number'         => $item->call_number ?: '',
        'lccn'                => $item->lccn ?: '',
        'category_name'       => $item->category_name ?: '',
        'shelf_location'      => $item->shelf_location ?: '',
        'geographic_location' => $item->geographic_location ?: '',
        'county'              => $item->county ?: '',
        'state'               => $item->state ?: '',
        'subjects'            => $subjects,
        'surnames'            => $surnames,
        'acq_code'            => $item->acq_code ?: '',
        'acq_date'            => $acq_date,
        'item_condition'      => $item->item_condition ?: '',
        'available'           => (bool) $item->available,
        'cover_url'           => $item->cover_url ?: '',
    ];

    // WHY: item_value, librarian_notes, donor, and acquisition_number are internal
    // administrative data that regular members should not see. Only admins need
    // these for catalog management. Leaking item_value could cause awkward
    // conversations; librarian_notes may contain internal commentary.
    if ( current_user_can( 'manage_options' ) ) {
        $response['donor']              = $item->donor ?: '';
        $response['item_value']         = $item->item_value ? sp_format_currency( $item->item_value ) : '';
        $response['librarian_notes']    = $item->librarian_notes ?: '';
        $response['acquisition_number'] = $item->acquisition_number ?: '';
    }

    wp_send_json_success( $response );
}

// ============================================================================
// AJAX: CSV Export of Library Catalog (admin)
//
// WHY: Admins need to export their catalog for backup, sharing with other
//      societies, or migration. This mirrors the import field mapping so
//      a CSV exported here can be re-imported cleanly.
// ============================================================================
add_action( 'wp_ajax_sp_export_library', 'sp_ajax_export_library' );
function sp_ajax_export_library(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }

    // Verify nonce to prevent CSRF on the export endpoint
    if ( ! check_ajax_referer( 'sp_export_library', '_wpnonce', false ) ) {
        wp_die( esc_html__( 'Security check failed. Please refresh the page.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Apply same filters the admin catalog page uses, so "export what you see"
    $where = [ '1=1' ];
    $search = isset( $_GET['s'] ) ? sanitize_text_field( $_GET['s'] ) : '';
    if ( $search ) {
        $like = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = $wpdb->prepare(
            '(li.title LIKE %s OR li.author LIKE %s OR li.call_number LIKE %s OR li.subject LIKE %s OR li.surname LIKE %s)',
            $like, $like, $like, $like, $like
        );
    }
    $media_filter = isset( $_GET['media_type'] ) ? sanitize_text_field( $_GET['media_type'] ) : '';
    if ( $media_filter ) {
        $where[] = $wpdb->prepare( 'li.media_type = %s', $media_filter );
    }
    $shelf_filter = isset( $_GET['shelf'] ) ? sanitize_text_field( $_GET['shelf'] ) : '';
    if ( $shelf_filter ) {
        $where[] = $wpdb->prepare( 'li.shelf_location = %s', $shelf_filter );
    }
    $acq_filter = isset( $_GET['acq_code'] ) ? sanitize_text_field( $_GET['acq_code'] ) : '';
    if ( $acq_filter ) {
        $where[] = $wpdb->prepare( 'li.acq_code = %s', $acq_filter );
    }
    $where_sql = implode( ' AND ', $where );

    $items = $wpdb->get_results(
        "SELECT li.* FROM {$prefix}library_items li WHERE {$where_sql} ORDER BY li.title ASC"
    );

    // CSV headers match the import target fields
    $headers = [
        'System ID', 'Title', 'Author', 'Description', 'Publisher',
        'Publisher Location', 'Pub. Year', 'Pub. Month', 'Pub. Day',
        'Media Type', 'Use Serials', 'ISBN', 'Call Number', 'LCCN',
        'Shelf Location', 'Geographic Location', 'Acquisition Number',
        'Acq. Year', 'Acq. Month', 'Acq. Day', 'Acq. Code', 'Donor',
        'Value', 'County', 'State', 'Surname', 'Subject',
        'Librarian Notes', 'Updated By', 'Last Updated Date',
        'Condition', 'Available', 'Cover URL',
    ];

    $filename = 'library-catalog-' . gmdate( 'Y-m-d' ) . '.csv';

    // Stream CSV output directly — no buffering the whole result set
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $out = fopen( 'php://output', 'w' );
    // BOM for Excel UTF-8 compatibility
    fwrite( $out, "\xEF\xBB\xBF" );
    fputcsv( $out, $headers );

    foreach ( $items as $item ) {
        fputcsv( $out, [
            $item->system_id,
            $item->title,
            $item->author,
            $item->description,
            $item->publisher,
            $item->publisher_location,
            $item->pub_year,
            $item->pub_month,
            $item->pub_day,
            $item->media_type,
            $item->use_serials,
            $item->isbn,
            $item->call_number,
            $item->lccn,
            $item->shelf_location,
            $item->geographic_location,
            $item->acquisition_number,
            $item->acq_year,
            $item->acq_month,
            $item->acq_day,
            $item->acq_code,
            $item->donor,
            $item->item_value,
            $item->county,
            $item->state,
            $item->surname,
            $item->subject,
            $item->librarian_notes,
            $item->updated_by,
            $item->last_updated_date,
            $item->item_condition,
            $item->available,
            $item->cover_url,
        ] );
    }

    fclose( $out );
    exit;
}


// ============================================================================
// DATA PORTABILITY — Per-Module CSV Exports
// WHY: Every piece of data a society puts into SocietyPress can come back
//      out in a standard format. No export fees, no "contact us," no degraded
//      exports. Your data is yours. Always.
// ============================================================================


/**
 * Export events as CSV.
 *
 * WHY: Events are a society's history. Treasurers need them for annual reports,
 *      archivists need them for records, and societies switching platforms need
 *      them for migration.
 */
add_action( 'wp_ajax_sp_export_events', function () {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_export_events' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $items = $wpdb->get_results(
        "SELECT e.*, c.name AS category_name
         FROM {$prefix}events e
         LEFT JOIN {$prefix}event_categories c ON e.category_id = c.id
         ORDER BY e.event_date DESC"
    );

    $headers = [
        'ID', 'Title', 'Category', 'Status', 'Event Date', 'Start Time',
        'End Time', 'Location Name', 'Location Address', 'Is Virtual',
        'Virtual URL', 'Capacity', 'Price Per Ticket', 'Contact Name',
        'Contact Email', 'Contact Phone', 'External URL', 'Description',
        'Created At', 'Updated At',
    ];

    $filename = 'events-' . wp_date( 'Y-m-d' ) . '.csv';
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $out = fopen( 'php://output', 'w' );
    fwrite( $out, "\xEF\xBB\xBF" );
    fputcsv( $out, $headers );

    foreach ( $items as $e ) {
        fputcsv( $out, [
            $e->id, $e->title, $e->category_name ?? '', $e->status ?? '',
            $e->event_date, $e->start_time, $e->end_time,
            $e->location_name, $e->location_address,
            $e->is_virtual, $e->virtual_url, $e->capacity,
            $e->price_per_ticket, $e->contact_name, $e->contact_email,
            $e->contact_phone, $e->external_url ?? '', $e->description,
            $e->created_at, $e->updated_at,
        ] );
    }

    fclose( $out );
    exit;
} );


/**
 * Export donations as CSV.
 *
 * WHY: Treasurers need donation records for tax reports and acknowledgment
 *      tracking. Societies switching platforms need their full giving history.
 */
add_action( 'wp_ajax_sp_export_donations', function () {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_export_donations' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $items = $wpdb->get_results(
        "SELECT d.*, c.name AS campaign_name, u.display_name AS recorded_by_name
         FROM {$prefix}donations d
         LEFT JOIN {$prefix}campaigns c ON d.campaign_id = c.id
         LEFT JOIN {$wpdb->users} u ON d.recorded_by = u.ID
         ORDER BY d.date DESC"
    );

    $headers = [
        'ID', 'Donor Name', 'Donor Email', 'Amount', 'Type', 'Date',
        'Campaign', 'In-Kind Description', 'Anonymous', 'Acknowledgment Sent',
        'Acknowledgment Date', 'Note', 'Recorded By', 'Created At',
    ];

    $filename = 'donations-' . wp_date( 'Y-m-d' ) . '.csv';
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $out = fopen( 'php://output', 'w' );
    fwrite( $out, "\xEF\xBB\xBF" );
    fputcsv( $out, $headers );

    foreach ( $items as $d ) {
        fputcsv( $out, [
            $d->id, $d->donor_name, $d->donor_email, $d->amount,
            $d->type, $d->date, $d->campaign_name ?? '',
            $d->in_kind_description, $d->is_anonymous ? 'Yes' : 'No',
            $d->acknowledgment_sent ? 'Yes' : 'No', $d->acknowledgment_date,
            $d->note, $d->recorded_by_name ?? '', $d->created_at,
        ] );
    }

    fclose( $out );
    exit;
} );


