/**
 * Render: Newsletter Archive Admin Page (Card Grid)
 *
 * WHY: Card grid matches the Gallery pattern — newsletters are visual items
 *      (cover thumbnails) so a card layout is more intuitive than a table.
 *      Shows cover image, title, date, volume/issue, visibility badge, and
 *      Edit/Delete action links. Sorted newest-first by publication date.
 */
function sp_render_newsletter_archive_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // ========== HANDLE DELETE ==========
    if ( ( $_POST['action'] ?? '' ) === 'delete' && ! empty( $_POST['newsletter_id'] ) ) {
        $newsletter_id = absint( $_POST['newsletter_id'] );
        check_admin_referer( 'sp_delete_newsletter_' . $newsletter_id );
        $wpdb->delete( $prefix . 'newsletters', [ 'id' => $newsletter_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Newsletter deleted.', 'societypress' ) . '</p></div>';
    }

    // ========== SEARCH FILTER ==========
    $search = sanitize_text_field( $_GET['s'] ?? '' );

    // ========== FETCH NEWSLETTERS ==========
    $sql = "SELECT * FROM {$prefix}newsletters";
    if ( $search ) {
        $sql .= $wpdb->prepare( " WHERE title LIKE %s", '%' . $wpdb->esc_like( $search ) . '%' );
    }
    $sql .= " ORDER BY pub_date DESC, created_at DESC";

    $newsletters = $wpdb->get_results( $sql );
    ?>

    <?php
    /*
     * WHY: All presentational styles for this admin page live here in a single
     * <style> block rather than as inline style= attributes on individual elements.
     * This keeps the HTML templates readable, makes it easy to adjust the card
     * layout in one place, and follows the project rule of no inline styles in
     * PHP templates. Classes are prefixed sp-newsletter-archive- to avoid any
     * collision with WordPress core or other plugin styles.
     */
    ?>
    <style>
        /* ---- Outer layout ---- */
        .sp-newsletter-archive-search-form   { margin: 16px 0; }
        .sp-newsletter-archive-grid          { display: flex; flex-wrap: wrap; gap: 20px; margin-top: 20px; }

        /* ---- Individual newsletter card ---- */
        .sp-newsletter-archive-card          { width: 220px; background: #fff; border: 1px solid #ccd0d4; border-radius: 8px; overflow: hidden; }

        /* ---- Card cover-image link wrapper ---- */
        .sp-newsletter-archive-cover-link    { display: block; }

        /* ---- Cover image (when a real image exists) ---- */
        .sp-newsletter-archive-cover-img     { width: 100%; height: 280px; object-fit: cover; }

        /* ---- Cover placeholder (no image uploaded) ---- */
        .sp-newsletter-archive-cover-placeholder          { width: 100%; height: 280px; background: #f0f0f0; display: flex; align-items: center; justify-content: center; }
        .sp-newsletter-archive-cover-placeholder-icon     { font-size: 48px; width: 48px; height: 48px; color: #ccc; }

        /* ---- Card body ---- */
        .sp-newsletter-archive-card-body     { padding: 12px; }

        /* ---- Card title ---- */
        .sp-newsletter-archive-title         { margin: 0 0 4px; }
        .sp-newsletter-archive-title-link    { text-decoration: none; color: #1d2327; }

        /* ---- Meta lines (date, vol/issue) ---- */
        .sp-newsletter-archive-meta          { color: #666; font-size: 12px; }

        /* ---- Visibility badge: members-only ---- */
        .sp-newsletter-archive-badge-members { background: #fef0c7; color: #92400e; font-size: 10px; padding: 2px 6px; border-radius: 3px; margin-left: 4px; }

        /* ---- Visibility badge: public ---- */
        .sp-newsletter-archive-badge-public  { background: #d1fae5; color: #065f46; font-size: 10px; padding: 2px 6px; border-radius: 3px; margin-left: 4px; }

        /* ---- Card action row (Edit | Delete) ---- */
        .sp-newsletter-archive-actions       { margin-top: 8px; font-size: 12px; }

        /* ---- Inline delete form (must stay inline beside the | separator) ---- */
        .sp-newsletter-archive-delete-form   { display: inline; }

        /* ---- Delete button styled as a plain text link ---- */
        .sp-newsletter-archive-delete-btn    { background: none; border: none; color: #b32d2e; cursor: pointer; padding: 0; font: inherit; text-decoration: underline; }
    </style>

    <div class="wrap">
        <h1 class="wp-heading-inline"><?php esc_html_e( 'Newsletter Archive', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-edit' ) ); ?>" class="page-title-action"><?php esc_html_e( 'Add New', 'societypress' ); ?></a>
        <a href="<?php echo esc_url( admin_url( 'admin-ajax.php?action=sp_export_newsletters_zip&nonce=' . wp_create_nonce( 'sp_export_newsletters_zip' ) ) ); ?>" class="page-title-action"><?php esc_html_e( 'Export All (ZIP)', 'societypress' ); ?></a>
        <hr class="wp-header-end">

        <!-- Search bar -->
        <form method="get" class="sp-newsletter-archive-search-form">
            <input type="hidden" name="page" value="sp-newsletter-archive">
            <p class="search-box">
                <input type="search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="Search newsletters…">
                <input type="submit" class="button" value="<?php echo esc_attr__( 'Search', 'societypress' ); ?>">
                <?php if ( $search ) : ?>
                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-archive' ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
                <?php endif; ?>
            </p>
        </form>

        <?php if ( empty( $newsletters ) ) : ?>
            <p><?php esc_html_e( 'No newsletters yet.', 'societypress' ); ?> <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-edit' ) ); ?>"><?php esc_html_e( 'Upload your first newsletter', 'societypress' ); ?></a>.</p>
        <?php else : ?>
            <div class="sp-newsletter-archive-grid">
                <?php foreach ( $newsletters as $nl ) :
                    // Cover thumbnail — use auto-generated cover, fall back to placeholder
                    $cover_url = $nl->cover_image_id
                        ? wp_get_attachment_image_url( $nl->cover_image_id, 'medium' )
                        : '';

                    $edit_url   = admin_url( 'admin.php?page=sp-newsletter-edit&newsletter_id=' . $nl->id );
                    // delete via POST form below

                    // Format the volume/issue line (e.g. "Vol. 3, No. 2")
                    $vol_issue = '';
                    if ( $nl->volume )       $vol_issue .= 'Vol.&nbsp;' . esc_html( $nl->volume );
                    if ( $nl->issue_number ) $vol_issue .= ( $vol_issue ? ', ' : '' ) . 'No.&nbsp;' . esc_html( $nl->issue_number );

                    // Format the publication date
                    $date_display = $nl->pub_date ? wp_date( 'M j, Y', strtotime( $nl->pub_date ) ) : '';
                ?>
                    <div class="sp-newsletter-archive-card">
                        <!-- Cover image area -->
                        <a href="<?php echo esc_url( $edit_url ); ?>" class="sp-newsletter-archive-cover-link">
                            <?php if ( $cover_url ) : ?>
                                <img src="<?php echo esc_url( $cover_url ); ?>" alt="" class="sp-newsletter-archive-cover-img">
                            <?php else : ?>
                                <div class="sp-newsletter-archive-cover-placeholder">
                                    <span class="dashicons dashicons-media-document sp-newsletter-archive-cover-placeholder-icon"></span>
                                </div>
                            <?php endif; ?>
                        </a>
                        <!-- Card body -->
                        <div class="sp-newsletter-archive-card-body">
                            <h4 class="sp-newsletter-archive-title">
                                <a href="<?php echo esc_url( $edit_url ); ?>" class="sp-newsletter-archive-title-link">
                                    <?php echo esc_html( $nl->title ); ?>
                                </a>
                            </h4>
                            <?php if ( $date_display ) : ?>
                                <span class="sp-newsletter-archive-meta"><?php echo $date_display; ?></span><br>
                            <?php endif; ?>
                            <?php if ( $vol_issue ) : ?>
                                <span class="sp-newsletter-archive-meta"><?php echo $vol_issue; ?></span>
                            <?php endif; ?>
                            <?php if ( $nl->visibility === 'members_only' ) : ?>
                                <span class="sp-newsletter-archive-badge-members"><?php esc_html_e( 'Members Only', 'societypress' ); ?></span>
                            <?php endif; ?>
                            <?php if ( $nl->visibility === 'public' ) : ?>
                                <span class="sp-newsletter-archive-badge-public">Public</span>
                            <?php endif; ?>
                            <div class="sp-newsletter-archive-actions">
                                <a href="<?php echo esc_url( $edit_url ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a> |
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-newsletter-archive' ) ); ?>" class="sp-newsletter-archive-delete-form" data-sp-confirm="<?php echo esc_attr( __( 'Delete this newsletter?', 'societypress' ) ); ?>">
                                    <?php wp_nonce_field( 'sp_delete_newsletter_' . $nl->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="newsletter_id" value="<?php echo (int) $nl->id; ?>">
                                    <button type="submit" class="sp-link-btn sp-newsletter-archive-delete-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </div>
                        </div>
                    </div>
                <?php endforeach; ?>
            </div>
        <?php endif; ?>
    </div>
    <?php
}


/**
 * Export all newsletters as a ZIP archive containing the actual PDF files plus
 * a metadata CSV.
 *
 * WHY: Societies that switch platforms or need an offline backup of their entire
 *      newsletter archive should be able to grab everything in one click — the
 *      actual PDFs and the structured metadata (title, dates, volume/issue) —
 *      without downloading files one-by-one. The CSV lets them reimport the
 *      metadata into another system, and the PDFs are the irreplaceable originals.
 */
add_action( 'wp_ajax_sp_export_newsletters_zip', function () {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_export_newsletters_zip' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    if ( ! class_exists( 'ZipArchive' ) ) {
        wp_die( esc_html__( 'The ZipArchive PHP extension is required but not available on this server.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $newsletters = $wpdb->get_results(
        "SELECT * FROM {$prefix}newsletters ORDER BY pub_date DESC, created_at DESC"
    );

    if ( empty( $newsletters ) ) {
        wp_die( esc_html__( 'No newsletters to export.', 'societypress' ) );
    }

    // Build temp directory inside the WP uploads folder
    $upload_dir = wp_upload_dir();
    $temp_base  = trailingslashit( $upload_dir['basedir'] ) . 'sp-export-temp/';
    $temp_dir   = $temp_base . 'newsletters-' . wp_generate_password( 8, false ) . '/';

    if ( ! wp_mkdir_p( $temp_dir ) ) {
        wp_die( esc_html__( 'Could not create temporary directory for export.', 'societypress' ) );
    }

    // Clean up temp files when we are done no matter what
    $cleanup = function () use ( $temp_dir, $temp_base ) {
        // Recursively remove the temp directory
        if ( is_dir( $temp_dir ) ) {
            $files = new RecursiveIteratorIterator(
                new RecursiveDirectoryIterator( $temp_dir, RecursiveDirectoryIterator::SKIP_DOTS ),
                RecursiveIteratorIterator::CHILD_FIRST
            );
            foreach ( $files as $file_info ) {
                if ( $file_info->isDir() ) {
                    @rmdir( $file_info->getRealPath() );
                } else {
                    @unlink( $file_info->getRealPath() );
                }
            }
            @rmdir( $temp_dir );
        }
        // Remove any leftover ZIP files in the temp base
        foreach ( glob( $temp_base . 'newsletters-*.zip' ) as $stale_zip ) {
            @unlink( $stale_zip );
        }
    };
    register_shutdown_function( $cleanup );

    // ---- Build the metadata CSV ----
    $csv_path = $temp_dir . 'newsletters.csv';
    $csv_out  = fopen( $csv_path, 'w' );
    // UTF-8 BOM so Excel handles accented characters correctly
    fwrite( $csv_out, "\xEF\xBB\xBF" );
    fputcsv( $csv_out, [
        'ID', 'Title', 'Pub Date', 'Volume', 'Issue Number', 'Visibility', 'Filename',
    ] );

    // Track filenames to avoid collisions when multiple newsletters share a title
    $used_filenames = [];

    foreach ( $newsletters as $nl ) {
        $safe_filename = '';

        // Copy the actual PDF into the temp directory if the attachment exists
        if ( ! empty( $nl->file_id ) ) {
            $source_path = get_attached_file( (int) $nl->file_id );
            if ( $source_path && file_exists( $source_path ) ) {
                $ext = pathinfo( $source_path, PATHINFO_EXTENSION );
                if ( ! $ext ) {
                    $ext = 'pdf';
                }
                // Build a human-readable filename from the newsletter title
                $base_name = sanitize_file_name( $nl->title );
                // Strip any extension sanitize_file_name may have kept
                $base_name = preg_replace( '/\.' . preg_quote( $ext, '/' ) . '$/i', '', $base_name );
                $candidate = $base_name . '.' . $ext;

                // Deduplicate: append a numeric suffix if the name is already used
                $counter = 1;
                while ( in_array( strtolower( $candidate ), $used_filenames, true ) ) {
                    $candidate = $base_name . '-' . $counter . '.' . $ext;
                    $counter++;
                }
                $used_filenames[] = strtolower( $candidate );
                $safe_filename    = $candidate;

                copy( $source_path, $temp_dir . $safe_filename );
            }
        }

        fputcsv( $csv_out, [
            $nl->id,
            $nl->title,
            $nl->pub_date ?? '',
            $nl->volume ?? '',
            $nl->issue_number ?? '',
            $nl->visibility,
            $safe_filename,
        ] );
    }

    fclose( $csv_out );

    // ---- Create the ZIP ----
    $zip_filename = 'newsletters-' . wp_date( 'Y-m-d' ) . '.zip';
    $zip_path     = $temp_base . $zip_filename;

    $zip = new ZipArchive();
    if ( $zip->open( $zip_path, ZipArchive::CREATE | ZipArchive::OVERWRITE ) !== true ) {
        wp_die( esc_html__( 'Could not create ZIP file.', 'societypress' ) );
    }

    // Add every file in the temp directory to the ZIP (flat — no subfolders needed)
    $dir_iterator  = new RecursiveDirectoryIterator( $temp_dir, RecursiveDirectoryIterator::SKIP_DOTS );
    $file_iterator = new RecursiveIteratorIterator( $dir_iterator );
    foreach ( $file_iterator as $file_info ) {
        if ( $file_info->isFile() ) {
            $zip->addFile( $file_info->getRealPath(), $file_info->getFilename() );
        }
    }

    $zip->close();

    // ---- Stream the ZIP to the browser ----
    $zip_size = filesize( $zip_path );
    header( 'Content-Type: application/zip' );
    header( 'Content-Disposition: attachment; filename="' . $zip_filename . '"' );
    header( 'Content-Length: ' . $zip_size );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    readfile( $zip_path );

    // Clean up the ZIP file immediately (temp dir handled by shutdown function)
    @unlink( $zip_path );

    exit;
} );


// WHY: Newsletter save must happen on admin_init (before any output) because
// wp_safe_redirect() requires headers not yet sent. The page render callback fires
// after admin_head has already output CSS, so redirect would silently fail.
add_action( 'admin_init', function () {
    // Only run on the newsletter edit page when the save button was clicked.
    if ( ! isset( $_POST['sp_save_newsletter'] ) ) return;
    if ( ( $_GET['page'] ?? '' ) !== 'sp-newsletter-edit' ) return;
    if ( ! current_user_can( 'manage_options' ) ) return;

    check_admin_referer( 'sp_newsletter_save' );

    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $newsletter_id = absint( $_GET['newsletter_id'] ?? 0 );

    $data = [
        'title'          => sanitize_text_field( $_POST['title'] ?? '' ),
        'slug'           => sanitize_title( $_POST['title'] ?? '' ),
        'description'    => sanitize_textarea_field( $_POST['description'] ?? '' ),
        'pub_date'       => sanitize_text_field( $_POST['pub_date'] ?? '' ) ?: null,
        'volume'         => absint( $_POST['volume'] ?? 0 ) ?: null,
        'issue_number'   => absint( $_POST['issue_number'] ?? 0 ) ?: null,
        'file_id'        => absint( $_POST['file_id'] ?? 0 ) ?: null,
        'cover_image_id' => absint( $_POST['cover_image_id'] ?? 0 ) ?: null,
        'visibility'     => sanitize_text_field( $_POST['visibility'] ?? 'members_only' ),
    ];

    if ( $newsletter_id ) {
        $wpdb->update( $prefix . 'newsletters', $data, [ 'id' => $newsletter_id ] );
    } else {
        $data['created_by'] = get_current_user_id();
        $wpdb->insert( $prefix . 'newsletters', $data );
    }

    wp_safe_redirect( admin_url( 'admin.php?page=sp-newsletter-archive&sp_notice=newsletter_saved' ) );
    exit;
} );



/**
 * Render: Newsletter Edit Page (Add / Edit)
 *
 * WHY: Single form handles both creation and editing. Uses the WordPress
 *      media library picker for PDF upload. On PDF selection, fires an AJAX
 *      request to auto-generate a cover thumbnail from the first page using
 *      Imagick. If Imagick isn't available or fails, admin can manually pick
 *      a cover image. The wp.media picker is deferred to window.load to
 *      avoid conflicts with other media-related scripts.
 */
function sp_render_newsletter_edit_page(): void {
    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $newsletter_id = absint( $_GET['newsletter_id'] ?? 0 );

    // ========== LOAD DATA ==========
    $nl = $newsletter_id ? $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}newsletters WHERE id = %d", $newsletter_id
    ) ) : null;

    // Get existing attachment URLs for display
    $pdf_url   = ( $nl && $nl->file_id )        ? wp_get_attachment_url( $nl->file_id )                        : '';
    $pdf_name  = ( $nl && $nl->file_id )        ? basename( get_attached_file( $nl->file_id ) )               : '';
    $cover_url = ( $nl && $nl->cover_image_id ) ? wp_get_attachment_image_url( $nl->cover_image_id, 'medium' ) : '';

    // WordPress media uploader needs this
    wp_enqueue_media();
    ?>
    <style>
        /* sp_render_newsletter_edit_page() — migrated from inline styles.
         * WHY: Keeps the form's structural and cosmetic rules in one auditable
         * place instead of scattered through the markup. */

        /* Extra top margin between the back-link and the form */
        .sp-newsletter-edit-form {
            margin-top: 20px;
        }

        /* Vol./No. inline labels — a small gap before the input */
        .sp-newsletter-edit-vol-label {
            margin-right: 8px;
        }

        /* Volume number input: compact width, gap before the No. field */
        .sp-newsletter-edit-vol-input {
            width: 80px;
            margin-right: 16px;
        }

        /* Issue-number input: compact width */
        .sp-newsletter-edit-issue-input {
            width: 80px;
        }

        /* PDF and cover preview containers: breathing room below */
        .sp-newsletter-edit-preview {
            margin-bottom: 8px;
        }

        /* Dashicon shown next to the selected PDF filename */
        .sp-newsletter-edit-pdf-icon {
            color: #0073aa;
            vertical-align: middle;
        }

        /* Cover-generating progress indicator: layout and text colour.
         * display:none is kept inline because JS toggles it via element.style. */
        .sp-newsletter-edit-generating {
            margin-left: 12px;
            color: #666;
        }

        /* Spinner inside the generating indicator: override WP default float */
        .sp-newsletter-edit-spinner {
            float: none;
            margin: 0 4px 0 0;
        }

        /* Cover image thumbnail: constrained width with subtle border */
        .sp-newsletter-edit-cover-img {
            max-width: 200px;
            border: 1px solid #ddd;
            border-radius: 4px;
        }
    </style>
    <div class="wrap">
