        }

        /* Fixed-width column: record type */
        .sp-records-col-type {
            width: 140px;
        }

        /* Fixed-width, centred column: record count */
        .sp-records-col-count {
            width: 100px;
            text-align: center;
        }

        /* Fixed-width column: access level */
        .sp-records-col-access {
            width: 100px;
        }

        /* Fixed-width column: status */
        .sp-records-col-status {
