                <tr>
                    <th><label for="record_type"><?php esc_html_e( 'Record Type', 'societypress' ); ?></label></th>
                    <td>
                        <select name="record_type" id="record_type">
                            <?php foreach ( $type_labels as $val => $label ) : ?>
