                        </tr>
                    <?php
                        endforeach;
                    endif;
                    ?>
                </tbody>
            </table>
            <button type="button" id="sp-add-field" class="button"><?php esc_html_e( '+ Add Field', 'societypress' ); ?></button>

            <p class="submit sp-record-edit-submit">
                <input type="submit" name="sp_save_collection" class="button button-primary" value="<?php echo $collection ? esc_attr__( 'Update Collection', 'societypress' ) : esc_attr__( 'Create Collection', 'societypress' ); ?>">
            </p>
        </form>
    </div>

    <script>
    (function() {
        var tbody      = document.getElementById('sp-field-rows');
        var addBtn     = document.getElementById('sp-add-field');
        var typeSelect = document.getElementById('record_type');
        var fieldIdx   = <?php echo max( count( $fields ), 0 ); ?>;

        // Default field templates per record type (from PHP)
        var defaults = <?php echo wp_json_encode( array_map( function( $type ) {
            return sp_record_type_default_fields( $type );
        }, array_combine( array_keys( sp_record_type_labels() ), array_keys( sp_record_type_labels() ) ) ) ); ?>;

        var fieldTypeOptions = <?php echo wp_json_encode( $field_types ); ?>;

        // Add a single field row — inline styles kept here because these strings are
        // built dynamically in JS via innerHTML; extracting them to a class would
        // require JS to also add class attributes, adding complexity for no real gain.
        function addFieldRow(name, type, searchable, isPublic) {
            var tr = document.createElement('tr');
            tr.className = 'sp-field-row';
            tr.draggable = true;
            var typeOpts = '';
            for (var k in fieldTypeOptions) {
                typeOpts += '<option value="' + k + '"' + (k === type ? ' selected' : '') + '>' + fieldTypeOptions[k] + '</option>';
            }
            tr.innerHTML =
                '<td style="cursor:grab; text-align:center; color:#999;">&#9776;</td>' +
                '<td><input type="hidden" name="field_id[' + fieldIdx + ']" value="0">' +
                '<input type="text" name="field_name[' + fieldIdx + ']" value="' + (name || '') + '" class="regular-text" required></td>' +
                '<td><select name="field_type[' + fieldIdx + ']">' + typeOpts + '</select></td>' +
                '<td class="sp-text-center"><input type="checkbox" name="field_searchable[' + fieldIdx + ']" value="1"' + (searchable ? ' checked' : '') + '></td>' +
                '<td class="sp-text-center"><input type="checkbox" name="field_public[' + fieldIdx + ']" value="1"' + (isPublic ? ' checked' : '') + '></td>' +
                '<td><button type="button" class="button sp-remove-field sp-text-danger">&times;</button></td>';
            tbody.appendChild(tr);
            fieldIdx++;
        }

        // Add field button
        addBtn.addEventListener('click', function() {
            addFieldRow('', 'text', true, true);
        });

        // Remove field button (delegated)
        tbody.addEventListener('click', function(e) {
            if (e.target.classList.contains('sp-remove-field')) {
                e.target.closest('tr').remove();
            }
        });

        // When record type changes on a NEW collection, populate default fields
        <?php if ( ! $collection ) : ?>
        typeSelect.addEventListener('change', function() {
            var type = this.value;
            var tmpl = defaults[type] || defaults['general'];
            tbody.innerHTML = '';
            fieldIdx = 0;
            tmpl.forEach(function(f) {
                addFieldRow(f.field_name, f.field_type, !!f.searchable, !!f.is_public);
            });
        });
        // Trigger on load for new collections
        typeSelect.dispatchEvent(new Event('change'));
        <?php endif; ?>

        // Drag-and-drop reorder
        var dragRow = null;
        tbody.addEventListener('dragstart', function(e) {
            dragRow = e.target.closest('tr');
            if (dragRow) dragRow.style.opacity = '0.5';
        });
        tbody.addEventListener('dragend', function(e) {
            if (dragRow) dragRow.style.opacity = '';
            dragRow = null;
        });
        tbody.addEventListener('dragover', function(e) {
            e.preventDefault();
            var target = e.target.closest('tr');
            if (target && target !== dragRow && target.parentNode === tbody) {
                var rect = target.getBoundingClientRect();
                var after = (e.clientY - rect.top) > (rect.height / 2);
                tbody.insertBefore(dragRow, after ? target.nextSibling : target);
            }
        });

        // Re-index field names before submit so sort_order is correct
        document.querySelector('form').addEventListener('submit', function() {
            var rows = tbody.querySelectorAll('.sp-field-row');
            rows.forEach(function(row, idx) {
                row.querySelectorAll('input, select').forEach(function(el) {
                    if (el.name) {
                        el.name = el.name.replace(/\[\d+\]/, '[' + idx + ']');
                    }
                });
            });
        });
    })();
    </script>
    <?php
}

function sp_render_record_browse_page(): void {
    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $collection_id = absint( $_GET['collection_id'] ?? 0 );

    if ( ! $collection_id ) {
        echo '<div class="wrap"><h1>' . esc_html__( 'Browse Records', 'societypress' ) . '</h1>';
        echo '<p>' . esc_html__( 'No collection specified.', 'societypress' ) . ' <a href="' . esc_url( admin_url( 'admin.php?page=sp-record-collections' ) ) . '">' . esc_html__( 'View Collections', 'societypress' ) . '</a></p></div>';
        return;
    }

    $collection = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collections WHERE id = %d", $collection_id
    ) );
    if ( ! $collection ) {
        echo '<div class="wrap"><p>' . esc_html__( 'Collection not found.', 'societypress' ) . '</p></div>';
        return;
    }

    // Handle delete
    if ( isset( $_POST['action'] ) && $_POST['action'] === 'delete' && isset( $_POST['record_id'] ) ) {
        $del_id = absint( $_POST['record_id'] );
        check_admin_referer( 'sp_delete_record_' . $del_id );
        $wpdb->delete( $prefix . 'record_values', [ 'record_id' => $del_id ] );
        $wpdb->delete( $prefix . 'records', [ 'id' => $del_id ] );
        // Update count
        $new_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$prefix}records WHERE collection_id = %d", $collection_id
        ) );
        $wpdb->update( $prefix . 'record_collections', [ 'record_count' => $new_count ], [ 'id' => $collection_id ] );
        echo '<div class="notice notice-success"><p>' . esc_html__( 'Record deleted.', 'societypress' ) . '</p></div>';
    }

    $fields = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collection_fields WHERE collection_id = %d ORDER BY sort_order ASC",
        $collection_id
    ) );

    // Search + pagination
    $search   = isset( $_GET['s'] ) ? sanitize_text_field( $_GET['s'] ) : '';
    $per_page = 50;
    $page_num = max( 1, absint( $_GET['paged'] ?? 1 ) );
    $offset   = ( $page_num - 1 ) * $per_page;

    $where = $wpdb->prepare( 'r.collection_id = %d', $collection_id );
    if ( $search ) {
        $like   = '%' . $wpdb->esc_like( $search ) . '%';
        $where .= $wpdb->prepare( ' AND r.search_text LIKE %s', $like );
    }

    $total = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}records r WHERE {$where}" );
    $records = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.* FROM {$prefix}records r WHERE {$where} ORDER BY r.id DESC LIMIT %d OFFSET %d",
        $per_page,
        $offset
    ) );
    $total_pages = (int) ceil( $total / $per_page );

    // Load all values for these records in one query (avoid N+1)
    $record_ids = array_map( 'absint', wp_list_pluck( $records, 'id' ) );
    $values_map = []; // record_id => [ field_id => value ]
    if ( $record_ids ) {
        $placeholders = implode( ',', array_fill( 0, count( $record_ids ), '%d' ) );
        $all_vals = $wpdb->get_results( $wpdb->prepare(
            "SELECT record_id, field_id, field_value FROM {$prefix}record_values WHERE record_id IN ({$placeholders})",
            ...$record_ids
        ) );
        foreach ( $all_vals as $v ) {
            $values_map[ $v->record_id ][ $v->field_id ] = $v->field_value;
        }
    }

    // Limit display columns to first 5 fields (to fit the table)
    $display_fields = array_slice( $fields, 0, 5 );
    ?>
    <div class="wrap">
        <h1>
            <?php echo esc_html( $collection->name ); ?>
            <span style="font-size:14px; font-weight:400; color:#666;">(<?php echo number_format( $total ); ?> <?php esc_html_e( 'records', 'societypress' ); ?>)</span>
            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-record-edit&collection_id=' . $collection_id ) ); ?>" class="page-title-action"><?php esc_html_e( 'Add Record', 'societypress' ); ?></a>
        </h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-record-collections' ) ); ?>">&larr; <?php esc_html_e( 'Back to Collections', 'societypress' ); ?></a>

        <!-- Search -->
        <form method="get" class="sp-my-16">
            <input type="hidden" name="page" value="sp-record-browse">
            <input type="hidden" name="collection_id" value="<?php echo esc_attr( $collection_id ); ?>">
            <input type="text" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php esc_attr_e( 'Search records...', 'societypress' ); ?>" style="width:300px; padding:6px 10px;">
            <input type="submit" class="button" value="<?php esc_attr_e( 'Search', 'societypress' ); ?>">
            <?php if ( $search ) : ?>
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-record-browse&collection_id=' . $collection_id ) ); ?>" class="button"><?php esc_html_e( 'Clear', 'societypress' ); ?></a>
            <?php endif; ?>
        </form>

        <?php if ( empty( $records ) ) : ?>
            <p class="sp-text-secondary" class="sp-italic"><?php esc_html_e( 'No records found.', 'societypress' ); ?></p>
        <?php else : ?>
            <table class="wp-list-table widefat fixed striped">
                <thead>
                    <tr>
                        <th class="sp-w-60">ID</th>
                        <?php foreach ( $display_fields as $f ) : ?>
                            <th><?php echo esc_html( $f->field_name ); ?></th>
                        <?php endforeach; ?>
                        <th style="width:120px;"><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                    </tr>
                </thead>
                <tbody>
                    <?php foreach ( $records as $rec ) :
                        $edit_url   = admin_url( 'admin.php?page=sp-record-edit&collection_id=' . $collection_id . '&record_id=' . $rec->id );
                        // delete via POST form
                    ?>
                        <tr>
                            <td><?php echo esc_html( $rec->id ); ?></td>
                            <?php foreach ( $display_fields as $f ) : ?>
                                <td><?php echo esc_html( wp_trim_words( $values_map[ $rec->id ][ $f->id ] ?? '', 10 ) ); ?></td>
                            <?php endforeach; ?>
                            <td>
                                <a href="<?php echo esc_url( $edit_url ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a> |
                                <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-record-browse&collection_id=' . $collection_id ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this record?', 'societypress' ) ); ?>">
                                    <?php wp_nonce_field( 'sp_delete_record_' . $rec->id ); ?>
                                    <input type="hidden" name="action" value="delete">
                                    <input type="hidden" name="record_id" value="<?php echo (int) $rec->id; ?>">
                                    <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                </form>
                            </td>
                        </tr>
                    <?php endforeach; ?>
                </tbody>
            </table>

            <?php if ( $total_pages > 1 ) : ?>
                <div class="tablenav" class="sp-mt-12">
                    <div class="tablenav-pages">
                        <span class="displaying-num"><?php echo number_format( $total ) . ' ' . esc_html__( 'items', 'societypress' ); ?></span>
                        <?php
                        echo paginate_links( [
                            'base'    => add_query_arg( 'paged', '%#%' ),
                            'format'  => '',
                            'current' => $page_num,
                            'total'   => $total_pages,
                        ] );
                        ?>
                    </div>
                </div>
            <?php endif; ?>
        <?php endif; ?>
    </div>
    <?php
}


/**
 * Render: Record Edit Page (Add / Edit Single Record)
 *
 * WHY: Lets admins manually add or edit a single record. The form is
 *      dynamically built from the collection's field definitions. Each field
 *      is rendered as the appropriate input type (text, textarea, number, date).
 */
function sp_render_record_edit_page(): void {
    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $collection_id = absint( $_GET['collection_id'] ?? 0 );
    $record_id     = absint( $_GET['record_id'] ?? 0 );

    if ( ! $collection_id ) {
        echo '<div class="wrap"><p>' . esc_html__( 'No collection specified.', 'societypress' ) . '</p></div>';
        return;
    }

    $collection = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collections WHERE id = %d", $collection_id
    ) );
    if ( ! $collection ) {
        echo '<div class="wrap"><p>' . esc_html__( 'Collection not found.', 'societypress' ) . '</p></div>';
        return;
    }

    $fields = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collection_fields WHERE collection_id = %d ORDER BY sort_order ASC",
        $collection_id
    ) );

    // Handle save
    if ( isset( $_POST['sp_save_record'] ) && check_admin_referer( 'sp_record_save' ) ) {

        if ( $record_id ) {
            // Update existing — delete old values and re-insert
            $wpdb->delete( $prefix . 'record_values', [ 'record_id' => $record_id ] );
        } else {
            // Insert new record shell
            $wpdb->insert( $prefix . 'records', [
                'collection_id' => $collection_id,
                'search_text'   => '',
            ] );
            $record_id = $wpdb->insert_id;
        }

        // Insert field values + build search text
        $search_parts = [];
        foreach ( $fields as $f ) {
            $val = sanitize_textarea_field( $_POST[ 'field_' . $f->id ] ?? '' );
            if ( $val !== '' ) {
                $wpdb->insert( $prefix . 'record_values', [
                    'record_id'   => $record_id,
                    'field_id'    => $f->id,
                    'field_value' => $val,
                ] );
                if ( $f->searchable ) {
                    $search_parts[] = $val;
                }
            }
        }

        // Update search_text
        $wpdb->update( $prefix . 'records', [
            'search_text' => implode( ' ', $search_parts ),
        ], [ 'id' => $record_id ] );

        // Update collection record count
        $new_count = (int) $wpdb->get_var( $wpdb->prepare(
            "SELECT COUNT(*) FROM {$prefix}records WHERE collection_id = %d", $collection_id
        ) );
        $wpdb->update( $prefix . 'record_collections', [ 'record_count' => $new_count ], [ 'id' => $collection_id ] );

        echo '<div class="notice notice-success"><p>' . esc_html__( 'Record saved.', 'societypress' ) . '</p></div>';
    }

    // Load existing values
    $values = [];
    if ( $record_id ) {
        $rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT field_id, field_value FROM {$prefix}record_values WHERE record_id = %d", $record_id
        ) );
        foreach ( $rows as $r ) {
            $values[ $r->field_id ] = $r->field_value;
        }
    }
    ?>
    <div class="wrap">
        <h1><?php echo $record_id ? esc_html__( 'Edit Record', 'societypress' ) : esc_html__( 'Add Record', 'societypress' ); ?></h1>
        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-record-browse&collection_id=' . $collection_id ) ); ?>">&larr; <?php echo esc_html( $collection->name ); ?></a>

        <form method="post" style="margin-top:16px; max-width:700px;">
            <?php wp_nonce_field( 'sp_record_save' ); ?>
            <table class="form-table">
                <?php foreach ( $fields as $f ) :
                    $val = $values[ $f->id ] ?? '';
                ?>
                    <tr>
                        <th><label for="field_<?php echo esc_attr( $f->id ); ?>"><?php echo esc_html( $f->field_name ); ?></label></th>
                        <td>
                            <?php if ( $f->field_type === 'textarea' ) : ?>
                                <textarea name="field_<?php echo esc_attr( $f->id ); ?>" id="field_<?php echo esc_attr( $f->id ); ?>" rows="3" class="large-text"><?php echo esc_textarea( $val ); ?></textarea>
                            <?php elseif ( $f->field_type === 'number' ) : ?>
                                <input type="number" name="field_<?php echo esc_attr( $f->id ); ?>" id="field_<?php echo esc_attr( $f->id ); ?>" value="<?php echo esc_attr( $val ); ?>" class="regular-text">
                            <?php elseif ( $f->field_type === 'date' ) : ?>
                                <input type="date" name="field_<?php echo esc_attr( $f->id ); ?>" id="field_<?php echo esc_attr( $f->id ); ?>" value="<?php echo esc_attr( $val ); ?>">
                            <?php else : ?>
                                <input type="text" name="field_<?php echo esc_attr( $f->id ); ?>" id="field_<?php echo esc_attr( $f->id ); ?>" value="<?php echo esc_attr( $val ); ?>" class="regular-text">
                            <?php endif; ?>
                        </td>
                    </tr>
                <?php endforeach; ?>
            </table>
            <p class="submit">
                <input type="submit" name="sp_save_record" class="button button-primary" value="<?php echo $record_id ? esc_attr__( 'Update Record', 'societypress' ) : esc_attr__( 'Add Record', 'societypress' ); ?>">
            </p>
        </form>
    </div>
    <?php
}


/**
 * Render: Record Import Page
 *
 * WHY: Societies typically have genealogical records in spreadsheets — sometimes
 *      thousands or tens of thousands of rows. This two-step import (upload +
 *      map columns → process) follows the same pattern as the library and member
 *      imports. The admin maps CSV columns to collection fields, then we batch-
 *      insert records and build search_text for each.
 */
function sp_render_record_import_page(): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Get all active collections for the selector
    $collections = $wpdb->get_results(
        "SELECT id, name, record_type FROM {$prefix}record_collections ORDER BY name ASC"
    );

    $collection_id = absint( $_GET['collection_id'] ?? $_POST['collection_id'] ?? 0 );

    // ----------------------------------------------------------------
    // GENRECORD IMPORT: Parse .genrecord file header + data, create
    // collection from metadata, and import all records automatically.
    //
    // WHY: A .genrecord file is self-describing — the header block carries
    //      the collection title, type, location, date range, and license.
    //      The data block is CSV with column headers that become fields.
    //      One upload does everything: no naming, no type selection, no
    //      field mapping. The file IS the schema.
    // ----------------------------------------------------------------
    if ( isset( $_POST['sp_import_genrecord'] ) && check_admin_referer( 'sp_record_import' ) ) {
        $access_level = in_array( $_POST['access_level'] ?? '', [ 'public', 'members' ], true )
            ? $_POST['access_level']
            : 'public';

        if ( empty( $_FILES['genrecord_file']['tmp_name'] ) ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a .genrecord file.', 'societypress' ) . '</p></div>';
        } else {
            // Parse the .genrecord file
            $parsed = sp_parse_genrecord_file( $_FILES['genrecord_file']['tmp_name'] );

            if ( is_wp_error( $parsed ) ) {
                echo '<div class="notice notice-error"><p>' . esc_html( $parsed->get_error_message() ) . '</p></div>';
            } else {
                $header  = $parsed['header'];
                $columns = $parsed['columns'];
                $rows    = $parsed['rows'];

                // Map GENRECORD type to SP record type
                $gr_type     = strtoupper( $header['type'] ?? 'BIO' );
                $type_map    = sp_genrecord_type_to_sp();
                $sp_type     = $type_map[ $gr_type ] ?? 'general';

                // Build collection metadata from header
                $col_name    = sanitize_text_field( $header['title'] ?? __( 'Imported GENRECORD Collection', 'societypress' ) );
                $slug        = sp_unique_collection_slug( sanitize_title( $col_name ) );
                $description = sanitize_textarea_field( $header['notes'] ?? '' );
                $location    = sanitize_text_field( $header['coverage.place'] ?? $header['coverage_place'] ?? '' );
                $date_range  = sanitize_text_field( $header['coverage.dates'] ?? $header['coverage_dates'] ?? '' );
                $source_info = '';

                // Build source attribution from header metadata
                $source_parts = [];
                if ( ! empty( $header['society'] ) ) {
                    $source_parts[] = sanitize_text_field( $header['society'] );
                }
                if ( ! empty( $header['society_url'] ) ) {
                    $source_parts[] = esc_url_raw( $header['society_url'] );
                }
                if ( ! empty( $header['license'] ) ) {
                    $source_parts[] = sprintf(
                        /* translators: %s: license name */
                        __( 'License: %s', 'societypress' ),
                        sanitize_text_field( $header['license'] )
                    );
                }
                if ( $source_parts ) {
                    $source_info = implode( ' | ', $source_parts );
                }

                // Create collection
                $wpdb->insert( $prefix . 'record_collections', [
                    'name'         => $col_name,
                    'slug'         => $slug,
                    'description'  => $description,
                    'record_type'  => $sp_type,
                    'source_info'  => $source_info,
                    'date_range'   => $date_range,
                    'location'     => $location,
                    'access_level' => $access_level,
                    'status'       => 'active',
                    'record_count' => 0,
                ] );
                $new_collection_id = (int) $wpdb->insert_id;

                if ( ! $new_collection_id ) {
                    echo '<div class="notice notice-error"><p>' . esc_html__( 'Failed to create collection.', 'societypress' ) . ' ' . esc_html( $wpdb->last_error ) . '</p></div>';
                } else {
                    // Create fields from column headers, skipping record_id
                    // WHY: record_id is a GENRECORD structural field, not a data
                    //      field. SP generates its own IDs. We skip it in import
                    //      and re-generate it on export.
                    $import_map = []; // col_index => field_id
                    $sort_order = 0;
                    foreach ( $columns as $idx => $col_name_raw ) {
                        // Skip record_id — it's structural, not data
                        if ( strtolower( trim( $col_name_raw ) ) === 'record_id' ) {
                            continue;
                        }
                        if ( empty( trim( $col_name_raw ) ) ) {
                            continue;
                        }

                        // Convert GENRECORD snake_case to readable field names
                        // e.g. "birth_date" → "Birth Date", "cemetery_place" → "Cemetery Place"
                        $field_name = ucwords( str_replace( '_', ' ', trim( $col_name_raw ) ) );
                        $field_slug = sanitize_title( $col_name_raw );

                        $wpdb->insert( $prefix . 'record_collection_fields', [
                            'collection_id' => $new_collection_id,
                            'field_name'    => $field_name,
                            'field_slug'    => $field_slug,
                            'field_type'    => 'text',
                            'sort_order'    => $sort_order++,
                            'required'      => 0,
                            'searchable'    => 1,
                            'is_public'     => 1,
                        ] );
                        $field_id = (int) $wpdb->insert_id;
                        if ( $field_id ) {
                            $import_map[ $idx ] = $field_id;
                        }
                    }

                    // Write rows to a temp CSV (header + data) so we can reuse
                    // the existing sp_process_record_import() function.
                    // WHY: The existing import processor handles record insertion,
                    //      search_text building, and record_count updates. No
                    //      reason to duplicate that logic.
                    $upload_dir = wp_upload_dir();
                    $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
                    if ( ! is_dir( $temp_dir ) ) {
                        wp_mkdir_p( $temp_dir );
                    }
                    // Ensure .htaccess exists even if directory was created by
                    // a different code path without it
                    if ( ! file_exists( $temp_dir . '/.htaccess' ) ) {
                        file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
                    }
                    $temp_file = $temp_dir . '/genrecord-import-' . wp_generate_password( 12, false ) . '.csv';
                    $temp_handle = fopen( $temp_file, 'w' );

                    if ( ! $temp_handle ) {
                        // Clean up the collection we just created — no records will follow
                        $wpdb->delete( $prefix . 'record_collection_fields', [ 'collection_id' => $new_collection_id ] );
                        $wpdb->delete( $prefix . 'record_collections', [ 'id' => $new_collection_id ] );
                        echo '<div class="notice notice-error"><p>' . esc_html__( 'Could not create temp file for import. Check that the uploads directory is writable.', 'societypress' ) . '</p></div>';
                    } else {
                    // Write column headers
                    fputcsv( $temp_handle, $columns );

                    // Write data rows
                    foreach ( $rows as $row ) {
                        fputcsv( $temp_handle, $row );
                    }
                    fclose( $temp_handle );

                    // Import using existing processor
                    $results = sp_process_record_import( $temp_file, $new_collection_id, $import_map );

                    // Show results — look up the human-readable label for the GENRECORD type code
                    $gr_type_label = $gr_type;
                    foreach ( sp_genrecord_type_labels() as $group_labels ) {
                        if ( isset( $group_labels[ $gr_type ] ) ) {
                            $gr_type_label = $group_labels[ $gr_type ];
                            break;
                        }
                    }
                    echo '<div class="notice notice-success"><p>';
                    printf(
                        /* translators: 1: collection name, 2: GENRECORD type, 3: field count, 4: imported count, 5: duplicate count */
                        esc_html__( 'GENRECORD import complete. Created collection "%1$s" (type: %2$s) with %3$d fields. Imported %4$d records, %5$d duplicates skipped.', 'societypress' ),
                        esc_html( $col_name ),
                        esc_html( $gr_type_label ),
                        count( $import_map ),
                        $results['imported'],
                        $results['duplicates'] ?? 0
                    );
                    echo '</p></div>';

                    if ( ! empty( $header['society'] ) ) {
                        echo '<div class="notice notice-info"><p>';
                        printf(
                            /* translators: %s: source society name */
                            esc_html__( 'Source: %s', 'societypress' ),
                            esc_html( $source_info )
                        );
                        echo '</p></div>';
                    }

                    if ( $results['skipped'] > 0 ) {
                        echo '<div class="notice notice-warning"><p>';
                        printf( esc_html__( '%d rows skipped (empty).', 'societypress' ), $results['skipped'] );
                        echo '</p></div>';
                    }

                    if ( $results['errors'] ) {
                        echo '<div class="notice notice-warning"><p><strong>' . esc_html__( 'Errors:', 'societypress' ) . '</strong><br>';
                        foreach ( array_slice( $results['errors'], 0, 10 ) as $err ) {
                            echo esc_html( $err ) . '<br>';
                        }
                        if ( count( $results['errors'] ) > 10 ) {
                            printf( '<br>' . esc_html__( '...and %d more.', 'societypress' ), count( $results['errors'] ) - 10 );
                        }
                        echo '</p></div>';
                    }

                    wp_delete_file( $temp_file );
                    } // end temp_handle success
                }
            }
        }
    }

    // ----------------------------------------------------------------
    // ONE-STEP: Create collection from CSV headers and import all rows.
    //
    // WHY: Annie uploads a CSV, names the collection, and clicks one button.
    //      The system creates the collection, creates a field for each column
    //      header, and imports every row — no manual field definitions, no
    //      separate mapping step. The CSV headers ARE the schema.
    // ----------------------------------------------------------------
    if ( isset( $_POST['sp_create_and_import'] ) && check_admin_referer( 'sp_record_import' ) ) {
        $col_name     = sanitize_text_field( $_POST['collection_name'] ?? '' );
        $record_type  = sanitize_text_field( $_POST['record_type'] ?? 'general' );
        $access_level = sanitize_text_field( $_POST['access_level'] ?? 'public' );
        $description  = sanitize_textarea_field( $_POST['description'] ?? '' );

        if ( empty( $col_name ) ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please enter a collection name.', 'societypress' ) . '</p></div>';
        } elseif ( empty( $_FILES['csv_file']['tmp_name'] ) ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a CSV file.', 'societypress' ) . '</p></div>';
        } else {
            // Save the upload to a temp file
            $upload_dir = wp_upload_dir();
            $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
            if ( ! is_dir( $temp_dir ) ) {
                wp_mkdir_p( $temp_dir );
                file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
            }
            $temp_file = $temp_dir . '/record-import-' . wp_generate_password( 12, false ) . '.csv';
            move_uploaded_file( $_FILES['csv_file']['tmp_name'], $temp_file );

            // Read headers
            $handle  = fopen( $temp_file, 'r' );
            $headers = fgetcsv( $handle );
            fclose( $handle );

            if ( ! $headers || count( $headers ) < 1 ) {
                echo '<div class="notice notice-error"><p>' . esc_html__( 'CSV file is empty or has no headers.', 'societypress' ) . '</p></div>';
                wp_delete_file( $temp_file );
            } else {
                // Strip BOM and whitespace
                $headers = array_map( function( $h ) {
                    return trim( $h, "\xEF\xBB\xBF \t\n\r\"" );
                }, $headers );

                // Create the collection
                $slug = sp_unique_collection_slug( sanitize_title( $col_name ) );
                $wpdb->insert( $prefix . 'record_collections', [
                    'name'         => $col_name,
                    'slug'         => $slug,
                    'description'  => $description,
                    'record_type'  => $record_type,
                    'source_info'  => '',
                    'date_range'   => '',
                    'location'     => '',
                    'access_level' => $access_level,
                    'status'       => 'active',
                    'record_count' => 0,
                ] );
                $new_collection_id = (int) $wpdb->insert_id;

                if ( ! $new_collection_id ) {
                    echo '<div class="notice notice-error"><p>' . esc_html__( 'Failed to create collection.', 'societypress' ) . ' ' . esc_html( $wpdb->last_error ) . '</p></div>';
                    wp_delete_file( $temp_file );
                } else {
                    // Create a field for each CSV column header
                    // WHY: Each column in Annie's spreadsheet becomes a searchable,
                    //      public field. She can change visibility or searchability
                    //      later in the collection editor if needed.
                    $import_map = []; // col_index => field_id
                    foreach ( $headers as $idx => $header ) {
                        if ( empty( $header ) ) continue;
                        $field_slug = sanitize_title( $header );
                        $wpdb->insert( $prefix . 'record_collection_fields', [
                            'collection_id' => $new_collection_id,
                            'field_name'    => $header,
                            'field_slug'    => $field_slug,
                            'field_type'    => 'text',
                            'sort_order'    => $idx,
                            'required'      => 0,
                            'searchable'    => 1,
                            'is_public'     => 1,
                        ] );
                        $field_id = (int) $wpdb->insert_id;
                        if ( $field_id ) {
                            $import_map[ $idx ] = $field_id;
                        }
                    }

                    // Import the records using the existing processor
                    $results = sp_process_record_import( $temp_file, $new_collection_id, $import_map );

                    // Show results
                    echo '<div class="notice notice-success"><p>';
                    printf(
                        /* translators: 1: collection name, 2: field count, 3: record count */
                        esc_html__( 'Created collection "%1$s" with %2$d fields. Imported %3$d records.', 'societypress' ),
                        esc_html( $col_name ),
                        count( $import_map ),
                        $results['imported']
                    );
                    echo '</p></div>';

                    if ( $results['skipped'] > 0 ) {
                        echo '<div class="notice notice-warning"><p>';
                        printf( esc_html__( '%d rows skipped.', 'societypress' ), $results['skipped'] );
                        echo '</p></div>';
                    }

                    if ( $results['errors'] ) {
                        echo '<div class="notice notice-warning"><p><strong>' . esc_html__( 'Errors:', 'societypress' ) . '</strong><br>';
                        foreach ( array_slice( $results['errors'], 0, 10 ) as $err ) {
                            echo esc_html( $err ) . '<br>';
                        }
                        if ( count( $results['errors'] ) > 10 ) {
                            printf( '<br>' . esc_html__( '...and %d more.', 'societypress' ), count( $results['errors'] ) - 10 );
                        }
                        echo '</p></div>';
                    }

                    wp_delete_file( $temp_file );
                }
            }
        }
    }

    // STEP 2: Process the import
    if ( isset( $_POST['sp_process_record_import'] ) && check_admin_referer( 'sp_record_import' ) ) {
        $collection_id = absint( $_POST['collection_id'] );
        $field_map     = $_POST['field_map'] ?? [];

        // Reconstruct full path from basename token — never trust full paths from HTML
        $token      = sanitize_file_name( $_POST['temp_file'] ?? '' );
        $upload_dir = wp_upload_dir();
        $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp/';
        $temp_file  = realpath( $temp_dir . $token );
        if ( ! $temp_file || strpos( $temp_file, realpath( $temp_dir ) ) !== 0 ) {
            $temp_file = '';
        }

        if ( ! $collection_id || ! $temp_file || ! file_exists( $temp_file ) ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Missing data. Please try again.', 'societypress' ) . '</p></div>';
        } else {
            // Build column-index → field_id map
            $import_map = [];
            foreach ( $field_map as $col_idx => $field_id ) {
                $field_id = absint( $field_id );
                if ( $field_id > 0 ) {
                    $import_map[ (int) $col_idx ] = $field_id;
                }
            }

            $results = sp_process_record_import( $temp_file, $collection_id, $import_map );

            echo '<div class="notice notice-success"><p>';
            printf(
                esc_html__( 'Import complete: %d records imported, %d skipped, %d duplicates, %d errors.', 'societypress' ),
                $results['imported'],
                $results['skipped'],
                $results['duplicates'] ?? 0,
                count( $results['errors'] )
            );
            echo '</p></div>';

            if ( $results['errors'] ) {
                echo '<div class="notice notice-warning"><p><strong>' . esc_html__( 'Errors:', 'societypress' ) . '</strong><br>';
                foreach ( $results['errors'] as $err ) {
                    echo esc_html( $err ) . '<br>';
                }
                echo '</p></div>';
            }

            wp_delete_file( $temp_file );
        }
    }

    // STEP 1: Upload + preview with field mapping
    if ( isset( $_POST['sp_upload_record_csv'] ) && check_admin_referer( 'sp_record_import' ) ) {
        $collection_id = absint( $_POST['collection_id'] );

        if ( ! $collection_id ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a collection.', 'societypress' ) . '</p></div>';
        } elseif ( empty( $_FILES['csv_file']['tmp_name'] ) ) {
            echo '<div class="notice notice-error"><p>' . esc_html__( 'Please select a CSV file.', 'societypress' ) . '</p></div>';
        } else {
            $collection = $wpdb->get_row( $wpdb->prepare(
                "SELECT * FROM {$prefix}record_collections WHERE id = %d", $collection_id
            ) );
            $fields = $wpdb->get_results( $wpdb->prepare(
                "SELECT * FROM {$prefix}record_collection_fields WHERE collection_id = %d ORDER BY sort_order ASC",
                $collection_id
            ) );

            // Move uploaded file to temp location inside sp-import-temp
            // WHY: Using the same temp directory as other imports for consistency,
            //      and so the basename-only path reconstruction works the same way.
            $upload_dir = wp_upload_dir();
            $temp_dir   = $upload_dir['basedir'] . '/sp-import-temp';
            if ( ! is_dir( $temp_dir ) ) {
                wp_mkdir_p( $temp_dir );
                file_put_contents( $temp_dir . '/.htaccess', 'Deny from all' );
            }
            $temp_file = $temp_dir . '/record-import-' . wp_generate_password( 12, false ) . '.csv';
            move_uploaded_file( $_FILES['csv_file']['tmp_name'], $temp_file );

            // Read headers + sample rows
            $handle  = fopen( $temp_file, 'r' );
            $headers = fgetcsv( $handle );
            if ( $headers ) {
                $headers = array_map( function( $h ) {
                    return trim( $h, "\xEF\xBB\xBF \t\n\r\"" );
                }, $headers );
            }
            $sample_rows = [];
            for ( $i = 0; $i < 3 && ( $row = fgetcsv( $handle ) ) !== false; $i++ ) {
                $sample_rows[] = $row;
            }
            fclose( $handle );

            // Auto-mapping: try to match CSV headers to field names
            $auto_map = [];
            foreach ( $headers as $col_idx => $header ) {
                $header_lower = strtolower( trim( $header ) );
                foreach ( $fields as $f ) {
                    if ( strtolower( $f->field_name ) === $header_lower || strtolower( $f->field_slug ) === $header_lower ) {
                        $auto_map[ $col_idx ] = $f->id;
                        break;
                    }
                }
            }
            ?>
            <div class="wrap">
                <h1><?php esc_html_e( 'Import Records — Map Fields', 'societypress' ); ?></h1>
                <p><?php printf( esc_html__( 'Importing into: %s', 'societypress' ), '<strong>' . esc_html( $collection->name ) . '</strong>' ); ?></p>

                <form method="post" style="max-width:1000px;">
                    <?php wp_nonce_field( 'sp_record_import' ); ?>
                    <input type="hidden" name="collection_id" value="<?php echo esc_attr( $collection_id ); ?>">
                    <input type="hidden" name="temp_file" value="<?php echo esc_attr( basename( $temp_file ) ); ?>">

                    <table class="wp-list-table widefat sp-my-16">
                        <thead>
                            <tr>
                                <th><?php esc_html_e( 'CSV Column', 'societypress' ); ?></th>
                                <th><?php esc_html_e( 'Sample Data', 'societypress' ); ?></th>
                                <th><?php esc_html_e( 'Map To Field', 'societypress' ); ?></th>
