            'FUNERAL' => __( 'FUNERAL — Funeral home record', 'societypress' ),
        ],
    ];
}


/**
 * Parse a .genrecord file into header metadata and CSV rows.
 *
 * WHY: A .genrecord file is two sections separated by "---": a header block
 *      of #key: value lines (starting with ##GENRECORD 1.0) and a CSV data
 *      block. This parser splits them cleanly so import code can handle the
 *      metadata and data independently.
 *
 * @param  string $file_path  Path to the uploaded .genrecord file.
 * @return array{header: array, columns: string[], rows: array[]}|WP_Error
 */
function sp_parse_genrecord_file( string $file_path ) {
    $handle = fopen( $file_path, 'r' );
    if ( ! $handle ) {
        return new WP_Error( 'file_error', __( 'Could not open file.', 'societypress' ) );
    }

    // Read the first line — must be ##GENRECORD
    $first_line = trim( fgets( $handle ) );
    // Strip BOM if present
    $first_line = ltrim( $first_line, "\xEF\xBB\xBF" );
    if ( strpos( $first_line, '##GENRECORD' ) !== 0 ) {
        fclose( $handle );
        return new WP_Error( 'not_genrecord', __( 'File does not start with ##GENRECORD — not a valid GENRECORD file.', 'societypress' ) );
    }

    // Parse header block: all lines starting with # until we hit ---
    $header = [];
    $header['genrecord_version'] = trim( str_replace( '##GENRECORD', '', $first_line ) );

    while ( ( $line = fgets( $handle ) ) !== false ) {
        $line = trim( $line );

        // Separator line — end of header
        if ( $line === '---' ) {
            break;
        }

        // Header lines start with #
        if ( $line !== '' && $line[0] === '#' ) {
            // Strip leading # and split on first colon
            $line = ltrim( $line, '#' );
            $colon_pos = strpos( $line, ':' );
            if ( $colon_pos !== false ) {
                $key   = trim( substr( $line, 0, $colon_pos ) );
                $value = trim( substr( $line, $colon_pos + 1 ) );
                $header[ $key ] = $value;
            }
        }
    }

    // Read column definition row (first line after ---)
    $columns_raw = fgetcsv( $handle );
    if ( ! $columns_raw ) {
        fclose( $handle );
        return new WP_Error( 'no_columns', __( 'No column headers found after --- separator.', 'societypress' ) );
    }
    // Clean column names
    $columns = array_map( function( $col ) {
        return trim( $col, "\xEF\xBB\xBF \t\n\r\"" );
    }, $columns_raw );

    // Read all data rows
    $rows = [];
    while ( ( $row = fgetcsv( $handle ) ) !== false ) {
        // Skip completely empty rows
        $has_data = false;
        foreach ( $row as $val ) {
            if ( trim( $val ) !== '' ) {
                $has_data = true;
                break;
            }
        }
        if ( $has_data ) {
            $rows[] = $row;
        }
    }

    fclose( $handle );

    return [
        'header'  => $header,
        'columns' => $columns,
        'rows'    => $rows,
    ];
}


/**
 * AJAX: Export collection as GENRECORD file
 *
 * WHY: This is the counterpart to import — it lets a society package a
 *      transcribed record collection as a portable .genrecord file that any
 *      other society, archive, or GENRECORD-compatible software can read.
 *      The file includes full metadata in the header block and all records
 *      as CSV in the data block.
 */
add_action( 'wp_ajax_sp_export_genrecord', 'sp_ajax_export_genrecord' );
function sp_ajax_export_genrecord(): void {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    check_ajax_referer( 'sp_export_genrecord' );

    $collection_id  = absint( $_GET['collection_id'] ?? 0 );
    $genrecord_type = sanitize_text_field( $_GET['genrecord_type'] ?? '' );

    // Validate genrecord_type against the known type list
    // WHY: The type code is written directly into the file header. Even though
    //      sanitize_text_field strips tags and extra whitespace, we should only
    //      allow the 35 defined GENRECORD type codes — not arbitrary strings.
    if ( $genrecord_type ) {
        $valid_types = [];
        foreach ( sp_genrecord_type_labels() as $group ) {
            $valid_types = array_merge( $valid_types, array_keys( $group ) );
        }
        if ( ! in_array( $genrecord_type, $valid_types, true ) ) {
            $genrecord_type = '';
        }
    }

    if ( ! $collection_id ) {
        wp_die( esc_html__( 'No collection specified.', 'societypress' ) );
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Load collection metadata
    $collection = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collections WHERE id = %d", $collection_id
    ) );
    if ( ! $collection ) {
        wp_die( esc_html__( 'Collection not found.', 'societypress' ) );
    }

    // Load field definitions in display order
    $fields = $wpdb->get_results( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collection_fields WHERE collection_id = %d ORDER BY sort_order ASC",
        $collection_id
    ) );
    if ( ! $fields ) {
        wp_die( esc_html__( 'Collection has no fields defined.', 'societypress' ) );
    }

    // Determine GENRECORD type code: use explicitly requested type, or map from SP type
    if ( ! $genrecord_type ) {
        $sp_defaults    = sp_sp_type_to_genrecord_default();
        $genrecord_type = $sp_defaults[ $collection->record_type ] ?? 'BIO';
    }

    // Build society info from SocietyPress settings
    $settings     = get_option( 'societypress_settings', [] );
    $society_name = $settings['organization_name'] ?? get_bloginfo( 'name' );
    $society_url  = home_url();
    $contact      = $settings['organization_email'] ?? get_bloginfo( 'admin_email' );

    // Build filename following GENRECORD convention:
    // society_type_scope_daterange.genrecord
    $slug_parts = [
        sanitize_title( $society_name ),
        strtolower( $genrecord_type ),
        sanitize_title( $collection->location ?: 'records' ),
    ];
    if ( $collection->date_range ) {
        $slug_parts[] = sanitize_title( $collection->date_range );
    }
    $filename = implode( '_', array_filter( $slug_parts ) ) . '.genrecord';

    // Load all records and their values in bulk (avoid N+1)
    $records = $wpdb->get_results( $wpdb->prepare(
        "SELECT id FROM {$prefix}records WHERE collection_id = %d ORDER BY id ASC",
        $collection_id
    ) );
    $record_ids = wp_list_pluck( $records, 'id' );

    // Pre-load all values keyed by record_id → field_id → value
    $all_values = [];
    if ( $record_ids ) {
        $id_placeholders = implode( ',', array_fill( 0, count( $record_ids ), '%d' ) );
        $value_rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT record_id, field_id, field_value FROM {$prefix}record_values WHERE record_id IN ($id_placeholders)",
            ...$record_ids
        ) );
        foreach ( $value_rows as $vr ) {
            $all_values[ (int) $vr->record_id ][ (int) $vr->field_id ] = $vr->field_value;
        }
    }

    // Build column slugs from field definitions for GENRECORD column names
    // WHY: GENRECORD uses snake_case field names like surname, given, birth_date.
    //      SP field slugs are already sanitized titles (e.g. "surname", "given-name").
    //      We convert hyphens to underscores for GENRECORD compatibility.
    $field_ids   = [];
    $col_headers = [ 'record_id' ]; // record_id is always first per GENRECORD spec
    foreach ( $fields as $f ) {
        $field_ids[]   = (int) $f->id;
        $col_headers[] = str_replace( '-', '_', $f->field_slug );
    }

    // Stream output
    header( 'Content-Type: text/plain; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $out = fopen( 'php://output', 'w' );

    // --- Header block ---
    // WHY: All header values are collapsed to single lines. A newline inside a
    //      value would inject a fake header line — any downstream parser that
    //      trusts the header would be poisoned. We strip newlines from every
    //      value, not just description/notes.
    $clean = function( string $v ): string {
        return str_replace( [ "\r\n", "\r", "\n" ], ' ', $v );
    };

    fwrite( $out, "##GENRECORD 1.0\n" );
    fwrite( $out, "#version: 1.0\n" );
    fwrite( $out, "#type: " . $genrecord_type . "\n" );
    fwrite( $out, "#title: " . $clean( $collection->name ) . "\n" );
    if ( $society_name ) {
        fwrite( $out, "#society: " . $clean( $society_name ) . "\n" );
    }
    if ( $society_url ) {
        fwrite( $out, "#society_url: " . $clean( $society_url ) . "\n" );
    }
    fwrite( $out, "#created: " . gmdate( 'Y-m-d' ) . "\n" );
    fwrite( $out, "#license: CC0\n" );
    if ( $collection->location ) {
        fwrite( $out, "#coverage.place: " . $clean( $collection->location ) . "\n" );
    }
    if ( $collection->date_range ) {
        fwrite( $out, "#coverage.dates: " . $clean( $collection->date_range ) . "\n" );
    }
    if ( $contact ) {
        fwrite( $out, "#contact: " . $clean( $contact ) . "\n" );
    }
    fwrite( $out, "#record_count: " . count( $record_ids ) . "\n" );
    if ( $collection->description ) {
        fwrite( $out, "#notes: " . $clean( $collection->description ) . "\n" );
    }

    // --- Separator ---
    fwrite( $out, "---\n" );

    // --- Data block (CSV) ---
    fputcsv( $out, $col_headers );

    $row_num = 1;
    foreach ( $record_ids as $rid ) {
        $csv_row = [ $row_num ]; // record_id: sequential per GENRECORD spec
        foreach ( $field_ids as $fid ) {
            $csv_row[] = $all_values[ $rid ][ $fid ] ?? '';
        }
        fputcsv( $out, $csv_row );
        $row_num++;
    }

    fclose( $out );
    exit;
}


// ---- Records CSV Export — per-collection standard CSV ----
// WHY: GENRECORD is great for inter-society exchange, but Harold also needs
//      plain CSV exports he can open in Excel. Dynamic columns come from the
//      collection's field definitions — same EAV resolution as GENRECORD export
//      but without the header metadata block.
add_action( 'wp_ajax_sp_export_records_csv', function () {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_export_records_csv' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    global $wpdb;
    $prefix        = $wpdb->prefix . 'sp_';
    $collection_id = absint( $_GET['collection_id'] ?? 0 );

    $collection = $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$prefix}record_collections WHERE id = %d", $collection_id
    ) );
    if ( ! $collection ) {
        wp_die( esc_html__( 'Collection not found.', 'societypress' ) );
    }

    // Load field definitions (column headers)
    $fields = $wpdb->get_results( $wpdb->prepare(
        "SELECT id, field_name FROM {$prefix}record_collection_fields WHERE collection_id = %d ORDER BY sort_order ASC",
        $collection_id
    ) );
    $field_ids   = wp_list_pluck( $fields, 'id' );
    $field_names = wp_list_pluck( $fields, 'field_name' );

    // Load all records
    $record_ids = $wpdb->get_col( $wpdb->prepare(
        "SELECT id FROM {$prefix}records WHERE collection_id = %d ORDER BY id ASC",
        $collection_id
    ) );

    // Pre-load all values in one query (EAV pattern)
    $all_values = [];
    if ( $record_ids ) {
        $id_placeholders = implode( ',', array_fill( 0, count( $record_ids ), '%d' ) );
        $value_rows = $wpdb->get_results( $wpdb->prepare(
            "SELECT record_id, field_id, field_value FROM {$prefix}record_values WHERE record_id IN ($id_placeholders)",
            ...$record_ids
        ) );
        foreach ( $value_rows as $vr ) {
            $all_values[ (int) $vr->record_id ][ (int) $vr->field_id ] = $vr->field_value;
        }
    }

    // Stream CSV
    $slug     = sanitize_file_name( $collection->slug ?: 'records' );
    $filename = $slug . '-' . wp_date( 'Y-m-d' ) . '.csv';
    header( 'Content-Type: text/csv; charset=utf-8' );
    header( 'Content-Disposition: attachment; filename="' . $filename . '"' );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    $out = fopen( 'php://output', 'w' );
    fwrite( $out, "\xEF\xBB\xBF" ); // UTF-8 BOM for Excel
    fputcsv( $out, array_merge( [ 'Record ID' ], $field_names ) );

    foreach ( $record_ids as $rid ) {
        $row = [ $rid ];
        foreach ( $field_ids as $fid ) {
            $row[] = $all_values[ $rid ][ $fid ] ?? '';
        }
        fputcsv( $out, $row );
    }

    fclose( $out );
    exit;
} );


// ============================================================================
// GENEALOGICAL RECORDS — Frontend Search
//
// WHY: The whole point of transcribing records is making them searchable.
//      The frontend provides a public (or members-only) search interface
//      where visitors can search across all collections or filter by a
//      specific one. Results show the collection name and the first few
//      fields of each matching record, with a detail view.
// ============================================================================

/**
 * Page Builder Widget: records_search
 *
 * WHY: Allows embedding the records search on any page via the page builder,
 *      not just the dedicated sp-records template page.
 */
add_filter( 'sp_builder_widget_types', function( array $types ): array {
    $types['records_search'] = [
        'label'       => __( 'Genealogical Records Search', 'societypress' ),
        'description' => __( 'Searchable interface for transcribed genealogical records.', 'societypress' ),
        'fields'      => [
            'collection_id' => [
                'label'   => __( 'Collection (optional)', 'societypress' ),
                'type'    => 'number',
                'default' => 0,
            ],
            'login_required' => [
                'label'   => __( 'Require Login', 'societypress' ),
                'type'    => 'checkbox',
                'default' => false,
            ],
        ],
    ];
    return $types;
} );


/**
 * Render: Frontend Records Search
 *
 * WHY: The member-facing (or public-facing) records search. Lets users search
 *      across all collections or a specific one. Results are displayed in a
 *      responsive table with expandable detail rows (same UX pattern as the
 *      library catalog). Respects per-collection and per-field access levels.
 */
function sp_render_records_frontend( array $widget_settings = [] ): void {
    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    $login_required = $widget_settings['login_required'] ?? false;
    if ( $login_required && ! is_user_logged_in() ) {
        echo '<div class="sp-widget-login-required">';
        echo '<p>' . sprintf(
            __( 'Please <a href="%s">log in</a> to search genealogical records.', 'societypress' ),
            esc_url( wp_login_url( get_permalink() ) )
        ) . '</p>';
        echo '</div>';
        return;
    }

    $is_member     = is_user_logged_in();
    $fixed_coll_id = absint( $widget_settings['collection_id'] ?? 0 );

    // Read search params
    $search        = isset( $_GET['sp_rec_q'] ) ? sanitize_text_field( $_GET['sp_rec_q'] ) : '';
    $coll_filter   = $fixed_coll_id ?: ( isset( $_GET['sp_rec_coll'] ) ? absint( $_GET['sp_rec_coll'] ) : 0 );
    $per_page      = 25;
    $page_num      = max( 1, absint( $_GET['sp_rec_pg'] ?? 1 ) );
    $offset        = ( $page_num - 1 ) * $per_page;

    // Get active collections the user can see
    $access_where = $is_member ? "status = 'active'" : "status = 'active' AND access_level = 'public'";
    $available_collections = $wpdb->get_results(
        "SELECT id, name, record_type FROM {$prefix}record_collections WHERE {$access_where} ORDER BY name ASC"
    );
    $coll_ids = wp_list_pluck( $available_collections, 'id' );
    if ( empty( $coll_ids ) ) {
        echo '<p class="sp-text-secondary">' . esc_html__( 'No record collections are available at this time.', 'societypress' ) . '</p>';
        return;
    }

    // Build WHERE — defense-in-depth: use prepare() even though $coll_ids came from the DB
    $coll_ids          = array_map( 'absint', $coll_ids );
    $coll_placeholders = implode( ',', array_fill( 0, count( $coll_ids ), '%d' ) );
    $where = [ $wpdb->prepare( "r.collection_id IN ({$coll_placeholders})", ...$coll_ids ) ];
    if ( $coll_filter && in_array( $coll_filter, $coll_ids, true ) ) {
        $where = [ $wpdb->prepare( 'r.collection_id = %d', $coll_filter ) ];
    }
    if ( $search ) {
        $like    = '%' . $wpdb->esc_like( $search ) . '%';
        $where[] = $wpdb->prepare( 'r.search_text LIKE %s', $like );
    }
    $where_sql = implode( ' AND ', $where );

    // Count + fetch
    $total   = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$prefix}records r WHERE {$where_sql}" );
    $records = $wpdb->get_results( $wpdb->prepare(
        "SELECT r.*, c.name AS collection_name, c.record_type
         FROM {$prefix}records r
         INNER JOIN {$prefix}record_collections c ON r.collection_id = c.id
         WHERE {$where_sql}
         ORDER BY r.id DESC
         LIMIT %d OFFSET %d",
        $per_page,
        $offset
    ) );
    $total_pages = (int) ceil( $total / $per_page );

    // Load field definitions for display collections
    $active_coll_ids = array_unique( wp_list_pluck( $records, 'collection_id' ) );
    $fields_by_coll  = [];
    if ( $active_coll_ids ) {
        $active_coll_ids  = array_values( array_map( 'absint', $active_coll_ids ) );
        $cid_placeholders = implode( ',', array_fill( 0, count( $active_coll_ids ), '%d' ) );
        $all_fields = $wpdb->get_results( $wpdb->prepare(
            "SELECT * FROM {$prefix}record_collection_fields WHERE collection_id IN ({$cid_placeholders}) ORDER BY sort_order ASC",
            ...$active_coll_ids
        ) );
        foreach ( $all_fields as $f ) {
            // Respect per-field access: hide non-public fields from non-members
            if ( ! $is_member && ! $f->is_public ) continue;
            $fields_by_coll[ $f->collection_id ][] = $f;
        }
    }

    // Load values for displayed records
    $record_ids = array_map( 'absint', wp_list_pluck( $records, 'id' ) );
    $values_map = [];
    if ( $record_ids ) {
        $rid_placeholders = implode( ',', array_fill( 0, count( $record_ids ), '%d' ) );
        $all_vals = $wpdb->get_results( $wpdb->prepare(
            "SELECT record_id, field_id, field_value FROM {$prefix}record_values WHERE record_id IN ({$rid_placeholders})",
            ...$record_ids
        ) );
        foreach ( $all_vals as $v ) {
            $values_map[ $v->record_id ][ $v->field_id ] = $v->field_value;
        }
    }

    $uid = 'sp-records-' . wp_rand( 1000, 9999 );

    echo '<div class="sp-records-search" id="' . esc_attr( $uid ) . '">';

    // Inline styles
    ?>
    <style>
        .sp-records-search { font-family: var(--sp-font-body, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif); }
        .sp-records-filters { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 20px; align-items: flex-end; }
        .sp-records-filters input[type="text"] { flex: 1; min-width: 200px; padding: 10px 14px; border: 1px solid #d0d5dd; border-radius: 6px; font-size: 15px; }
        .sp-records-filters select { padding: 10px 12px; border: 1px solid #d0d5dd; border-radius: 6px; font-size: 14px; background: #fff; min-width: 180px; }
        .sp-records-status { margin-bottom: 14px; color: #555; font-size: 14px; }
        .sp-records-table { width: 100%; border-collapse: collapse; }
        .sp-records-table thead th { padding: 10px 14px; text-align: left; border-bottom: 2px solid #d0d5dd; background: #f8f9fa; font-size: 13px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.03em; color: #555; }
        .sp-records-table tbody td { padding: 10px 14px; border-bottom: 1px solid #eee; font-size: 14px; vertical-align: top; }
        .sp-records-table tbody tr:hover { background: #f8f9fa; cursor: pointer; }
        .sp-records-coll-badge { font-size: 11px; color: #666; background: #f0f0f0; padding: 2px 8px; border-radius: 10px; display: inline-block; }
        .sp-records-detail-row td { padding: 0 !important; border-bottom: 2px solid var(--sp-color-accent, #667eea) !important; }
        .sp-records-detail { padding: 20px 24px; background: #fafbfc; animation: spRecDetailSlide 0.25s ease-out; }
        @keyframes spRecDetailSlide { from { opacity: 0; } to { opacity: 1; } }
        .sp-records-detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px 32px; }
        .sp-records-detail-grid dt { font-size: 11px; text-transform: uppercase; letter-spacing: 0.05em; color: #888; margin-bottom: 2px; font-weight: 600; }
        .sp-records-detail-grid dd { margin: 0; font-size: 14px; color: #333; }
        .sp-records-pagination { display: flex; justify-content: center; gap: 4px; margin-top: 20px; flex-wrap: wrap; }
        .sp-records-pagination a, .sp-records-pagination span { display: inline-block; padding: 6px 12px; border: 1px solid #d0d5dd; border-radius: 4px; font-size: 14px; text-decoration: none; color: #333; }
        .sp-records-pagination a:hover { background: #f0f0f0; }
        .sp-records-pagination .current { background: var(--sp-color-primary, #2271b1); color: #fff; border-color: var(--sp-color-primary, #2271b1); }
        @media (max-width: 768px) {
            .sp-records-filters { flex-direction: column; }
            .sp-records-table thead { display: none; }
            .sp-records-table tbody tr { display: block; padding: 12px 0; border-bottom: 1px solid #eee; }
            .sp-records-table tbody td { display: block; padding: 3px 0 !important; border-bottom: none !important; }
            .sp-records-table tbody td:before { content: attr(data-label); font-weight: 600; font-size: 11px; text-transform: uppercase; color: #888; display: block; }
            .sp-records-detail-grid { grid-template-columns: 1fr; }
        }
    </style>
    <?php

    // Search + filter bar
    $base_params = [];
    foreach ( $_GET as $k => $v ) {
        if ( strpos( $k, 'sp_rec_' ) !== 0 ) {
            $base_params[ $k ] = $v;
        }
    }

    echo '<form method="get" class="sp-records-filters">';
    foreach ( $base_params as $k => $v ) {
        echo '<input type="hidden" name="' . esc_attr( $k ) . '" value="' . esc_attr( $v ) . '">';
    }
    // Visually-hidden label for the search input — screen readers need it, sighted users have the placeholder
    echo '<label for="sp-rec-q" class="screen-reader-text">' . esc_html__( 'Search records', 'societypress' ) . '</label>';
    echo '<input type="text" name="sp_rec_q" id="sp-rec-q" value="' . esc_attr( $search ) . '" placeholder="' . esc_attr__( 'Search names, places, dates...', 'societypress' ) . '">';

    if ( ! $fixed_coll_id && count( $available_collections ) > 1 ) {
        // Visually-hidden label for the collection filter dropdown
        echo '<label for="sp-rec-coll" class="screen-reader-text">' . esc_html__( 'Filter by collection', 'societypress' ) . '</label>';
        echo '<select name="sp_rec_coll" id="sp-rec-coll">';
        echo '<option value="">' . esc_html__( 'All Collections', 'societypress' ) . '</option>';
        foreach ( $available_collections as $ac ) {
            $sel = ( $coll_filter === (int) $ac->id ) ? ' selected' : '';
            echo '<option value="' . esc_attr( $ac->id ) . '"' . $sel . '>' . esc_html( $ac->name ) . '</option>';
        }
        echo '</select>';
    }

    echo '<button type="submit" class="sp-btn sp-btn-primary">' . esc_html__( 'Search', 'societypress' ) . '</button>';
    echo '</form>';

    // Results count
    echo '<div class="sp-records-status">' . number_format( $total ) . ' ' . esc_html__( 'records found', 'societypress' ) . '</div>';

    if ( empty( $records ) ) {
        echo '<p style="color:#666; font-style:italic; padding:20px 0;">' . esc_html__( 'No records match your search. Try broadening your query.', 'societypress' ) . '</p>';
    } else {
        // For multi-collection results, show Collection + first 3 fields
        // For single-collection, show first 4 fields
        $show_coll_column = ! $coll_filter || count( $active_coll_ids ) > 1;

        echo '<table class="sp-records-table">';
        echo '<thead><tr>';
        if ( $show_coll_column ) {
            echo '<th>' . esc_html__( 'Collection', 'societypress' ) . '</th>';
        }
        // Show generic column headers (we can't know field names across collections)
        // For single-collection, use actual field names
        if ( $coll_filter && isset( $fields_by_coll[ $coll_filter ] ) ) {
            $display_fields = array_slice( $fields_by_coll[ $coll_filter ], 0, $show_coll_column ? 3 : 4 );
            foreach ( $display_fields as $df ) {
                echo '<th>' . esc_html( $df->field_name ) . '</th>';
            }
        } else {
            echo '<th>' . esc_html__( 'Summary', 'societypress' ) . '</th>';
        }
        echo '</tr></thead><tbody>';

        foreach ( $records as $rec ) {
            $rec_fields = $fields_by_coll[ $rec->collection_id ] ?? [];
            $rec_values = $values_map[ $rec->id ] ?? [];

            // tabindex="0" makes the row focusable by keyboard; role="button" tells screen
            // readers it's clickable; aria-expanded tracks whether the detail panel is open
            echo '<tr class="sp-record-row" data-record-id="' . esc_attr( $rec->id ) . '" data-collection-id="' . esc_attr( $rec->collection_id ) . '" tabindex="0" role="button" aria-expanded="false">';

            if ( $show_coll_column ) {
                echo '<td data-label="' . esc_attr__( 'Collection', 'societypress' ) . '"><span class="sp-records-coll-badge">' . esc_html( $rec->collection_name ) . '</span></td>';
            }

            if ( $coll_filter && isset( $fields_by_coll[ $coll_filter ] ) ) {
                $display_fields = array_slice( $fields_by_coll[ $coll_filter ], 0, $show_coll_column ? 3 : 4 );
                foreach ( $display_fields as $df ) {
                    $val = $rec_values[ $df->id ] ?? '';
                    echo '<td data-label="' . esc_attr( $df->field_name ) . '">' . esc_html( wp_trim_words( $val, 8 ) ?: '—' ) . '</td>';
                }
            } else {
                // Multi-collection: show first few field values as a summary
                $summary_parts = [];
                $shown = 0;
                foreach ( $rec_fields as $rf ) {
                    if ( isset( $rec_values[ $rf->id ] ) && $rec_values[ $rf->id ] !== '' ) {
                        $summary_parts[] = wp_trim_words( $rec_values[ $rf->id ], 6 );
                        $shown++;
                        if ( $shown >= 4 ) break;
                    }
                }
                echo '<td data-label="' . esc_attr__( 'Summary', 'societypress' ) . '">' . esc_html( implode( ' · ', $summary_parts ) ?: '—' ) . '</td>';
            }

            echo '</tr>';
        }

        echo '</tbody></table>';

        // Pagination
        if ( $total_pages > 1 ) {
            echo '<div class="sp-records-pagination">';
            $base_url = remove_query_arg( 'sp_rec_pg' );
            if ( $page_num > 1 ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_rec_pg', $page_num - 1, $base_url ) ) . '">&laquo; ' . esc_html__( 'Prev', 'societypress' ) . '</a>';
            }
            $range = 2;
            for ( $i = 1; $i <= $total_pages; $i++ ) {
                if ( $i === 1 || $i === $total_pages || abs( $i - $page_num ) <= $range ) {
                    if ( $i === $page_num ) {
                        echo '<span class="current">' . $i . '</span>';
                    } else {
                        echo '<a href="' . esc_url( add_query_arg( 'sp_rec_pg', $i, $base_url ) ) . '">' . $i . '</a>';
                    }
                } elseif ( $i === 2 && $page_num > $range + 2 ) {
                    echo '<span>&hellip;</span>';
                } elseif ( $i === $total_pages - 1 && $page_num < $total_pages - $range - 1 ) {
                    echo '<span>&hellip;</span>';
                }
            }
            if ( $page_num < $total_pages ) {
                echo '<a href="' . esc_url( add_query_arg( 'sp_rec_pg', $page_num + 1, $base_url ) ) . '">' . esc_html__( 'Next', 'societypress' ) . ' &raquo;</a>';
            }
            echo '</div>';
        }
    }

    // Expand/collapse detail on row click
    ?>
    <script>
    (function() {
        var container = document.getElementById('<?php echo esc_js( $uid ); ?>');
        if (!container) return;
        var openRow = null;

        // Pre-load field data and values for displayed records (avoids AJAX)
        var recordData = <?php
            $js_data = [];
            foreach ( $records as $rec ) {
                $rec_fields = $fields_by_coll[ $rec->collection_id ] ?? [];
                $rec_values = $values_map[ $rec->id ] ?? [];
                $field_list = [];
                foreach ( $rec_fields as $rf ) {
                    $field_list[] = [
                        'name'  => $rf->field_name,
                        'value' => $rec_values[ $rf->id ] ?? '',
                    ];
                }
                $js_data[ $rec->id ] = [
                    'collection' => $rec->collection_name,
                    'fields'     => $field_list,
                ];
            }
            echo wp_json_encode( $js_data );
        ?>;

        // WHY extracted into a function: both click and keyboard (Enter/Space) handlers
        // need the same toggle logic. Also manages aria-expanded for screen readers.
        function toggleRecordRow(row) {
            var recId = row.getAttribute('data-record-id');

            // Toggle existing detail panel
            var existing = row.nextElementSibling;
            if (existing && existing.classList.contains('sp-records-detail-row')) {
                existing.remove();
                row.setAttribute('aria-expanded', 'false');
                openRow = null;
                return;
            }
            // Close any other open row first
            if (openRow) {
                var prevRow = openRow.previousElementSibling;
                if (prevRow) prevRow.setAttribute('aria-expanded', 'false');
                openRow.remove();
                openRow = null;
            }

            var data = recordData[recId];
            if (!data) return;

            var detailRow = document.createElement('tr');
            detailRow.className = 'sp-records-detail-row';
            var td = document.createElement('td');
            var colSpan = row.children.length;
            td.setAttribute('colspan', colSpan);

            var html = '<div class="sp-records-detail"><div class="sp-records-detail-grid">';
            data.fields.forEach(function(f) {
                if (f.value) {
                    html += '<dl><dt>' + escHtml(f.name) + '</dt><dd>' + escHtml(f.value) + '</dd></dl>';
                }
            });
            html += '</div></div>';
            td.innerHTML = html;
            detailRow.appendChild(td);
            row.after(detailRow);
            row.setAttribute('aria-expanded', 'true');
            openRow = detailRow;
        }

        container.addEventListener('click', function(e) {
            var row = e.target.closest('.sp-record-row');
            if (!row) return;
            toggleRecordRow(row);
        });

        // Keyboard support: Enter and Space toggle the record detail panel,
        // matching the behavior sighted users get with a click
        container.addEventListener('keydown', function(e) {
            if (e.key !== 'Enter' && e.key !== ' ') return;
            var row = e.target.closest('.sp-record-row');
            if (!row) return;
            e.preventDefault();
            toggleRecordRow(row);
        });

        function escHtml(s) {
            var d = document.createElement('div');
            d.appendChild(document.createTextNode(s));
            return d.innerHTML;
        }
    })();
    </script>
    <?php
    echo '</div>';
}


// ============================================================================
// STORE — Frontend Publication Sales
//
// WHY: Societies often have self-published books, pamphlets, or research
//      materials available for purchase. This store pulls directly from the
//      library catalog (filtered by a configurable acq_code, e.g., "the society
//      Publication", with a price > 0), so there's no separate product
//      management — the library catalog IS the product database. If no
//      acq_code is configured, all priced items show up.
//
//      The store acq_code and intro text are configurable via Settings →
//      Organization. No society-specific references in the code.
//
//      Add to Cart buttons are placeholder links (href="#") until payment
//      processing (Stripe/PayPal) is wired in.
// ============================================================================


/**
 * Render: Store Frontend
 *
 * WHY: A clean, public-facing storefront for society publications. Modeled
 *      after the EasyNetSites store layout with category sidebar filters,
 *      quantity selectors, and Add to Cart buttons. Uses the same design
 *      language as the rest of the site (CSS custom properties, responsive
 *      grid). Each book is a card with cover image (or placeholder), title,
 *      author, price, description, quantity picker, and Add to Cart.
 *
 *      Cart/payment is not yet wired — Add to Cart buttons are placeholders
 *      that will connect to Stripe/PayPal when payment processing is built.
 */
function sp_render_store_frontend(): void {
    global $wpdb;
    $prefix   = $wpdb->prefix . 'sp_';
    $settings = get_option( 'societypress_settings', [] );

    // Determine which library acq_code to filter by.
    // WHY: Originally hardcoded to 'Society Publication'. Now configurable via
    //      Settings so any society can designate which catalog items appear in
    //      their store. If no acq_code is configured, show ALL library items
    //      that have a price set — the store becomes a general catalog shop.
    $store_acq_code = trim( $settings['store_acq_code'] ?? '' );

    // Read active category filter from URL
    $active_cat = isset( $_GET['sp_store_cat'] ) ? sanitize_text_field( $_GET['sp_store_cat'] ) : '';

    // Build WHERE clause — always require a price
    $base_where = "item_value IS NOT NULL AND item_value > 0";
    if ( $store_acq_code !== '' ) {
        $base_where .= $wpdb->prepare( ' AND acq_code = %s', $store_acq_code );
    }

    $where = $base_where;
    if ( $active_cat ) {
        $where .= $wpdb->prepare( ' AND store_category = %s', $active_cat );
    }

    $items = $wpdb->get_results(
        "SELECT id, title, author, pub_year, description, store_description, item_value, cover_url, store_category
         FROM {$prefix}library_items
         WHERE {$where}
         ORDER BY title ASC"
    );

    // Get all categories with counts (unfiltered) for the sidebar
    $categories = $wpdb->get_results(
        "SELECT store_category, COUNT(*) as cnt
         FROM {$prefix}library_items
         WHERE {$base_where}
           AND store_category IS NOT NULL AND store_category != ''
         GROUP BY store_category
         ORDER BY store_category ASC"
    );
    $total_count = (int) $wpdb->get_var(
        "SELECT COUNT(*) FROM {$prefix}library_items WHERE {$base_where}"
    );

    ?>
    <style>
        .sp-store-intro { text-align: center; margin-bottom: 32px; }
        .sp-store-intro h1 { font-size: 32px; font-weight: 700; color: var(--sp-color-heading, #1a1a1a); margin-bottom: 8px; }
        .sp-store-intro p { font-size: 16px; color: var(--sp-color-text-secondary, #666); max-width: 600px; margin: 0 auto; line-height: 1.6; }

        .sp-store-layout { display: flex; gap: 32px; align-items: flex-start; }

        /* Category sidebar */
        .sp-store-sidebar { flex: 0 0 220px; }
        .sp-store-sidebar h3 { font-size: 14px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; color: #555; margin: 0 0 12px; }
        .sp-store-cat-list { list-style: none; margin: 0; padding: 0; }
        .sp-store-cat-list li { margin-bottom: 4px; }
        .sp-store-cat-list a {
            display: flex; justify-content: space-between; align-items: center;
            padding: 8px 12px; border-radius: 6px; text-decoration: none;
            font-size: 14px; color: #333; transition: background 0.15s ease;
        }
        .sp-store-cat-list a:hover { background: #f0f0f0; }
        .sp-store-cat-list a.active { background: var(--sp-color-primary, #2271b1); color: #fff; font-weight: 600; }
        .sp-store-cat-list a.active .sp-store-cat-count { background: rgba(255,255,255,0.25); color: #fff; }
        .sp-store-cat-count { font-size: 12px; background: #eee; padding: 1px 8px; border-radius: 10px; color: #666; }

        /* Main content */
        .sp-store-main { flex: 1; min-width: 0; }
        .sp-store-count { font-size: 14px; color: var(--sp-color-text-secondary, #888); margin-bottom: 20px; }

        .sp-store-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
            gap: 28px;
        }

        .sp-store-card {
            background: #fff;
            border: 1px solid var(--sp-color-border, #e5e7eb);
            border-radius: 10px;
            overflow: hidden;
            display: flex;
            flex-direction: column;
            transition: box-shadow 0.2s ease, transform 0.2s ease;
        }
        .sp-store-card:hover {
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
            transform: translateY(-2px);
        }

        .sp-store-cover {
            aspect-ratio: 3 / 4;
            background: #f0ebe3;
            display: flex;
            align-items: center;
            justify-content: center;
            overflow: hidden;
        }
        .sp-store-cover img {
            width: 100%;
            height: 100%;
            object-fit: cover;
        }
        .sp-store-cover-placeholder {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            color: #b8a88a;
            gap: 8px;
            padding: 20px;
            text-align: center;
        }
        .sp-store-cover-placeholder svg {
            width: 48px;
            height: 48px;
            opacity: 0.5;
        }
        .sp-store-cover-placeholder span {
            font-size: 13px;
            font-weight: 600;
            line-height: 1.3;
            max-width: 180px;
        }

        .sp-store-body {
            padding: 20px;
            flex: 1;
            display: flex;
            flex-direction: column;
        }
        .sp-store-cat-badge {
            font-size: 11px;
            color: var(--sp-color-accent, #c9973a);
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 0.04em;
            margin-bottom: 6px;
        }
        .sp-store-title {
            font-size: 16px;
            font-weight: 700;
            color: var(--sp-color-heading, #1a1a1a);
            margin: 0 0 4px;
            line-height: 1.3;
        }
        .sp-store-author {
            font-size: 13px;
            color: var(--sp-color-text-secondary, #888);
            margin-bottom: 10px;
        }
        .sp-store-desc {
            font-size: 13px;
            color: #555;
            line-height: 1.5;
            margin-bottom: 16px;
            flex: 1;
        }
        .sp-store-price {
            font-size: 22px;
            font-weight: 700;
            color: var(--sp-color-primary, #1a1a1a);
            margin-bottom: 12px;
        }

        .sp-store-actions {
            display: flex;
            align-items: center;
            gap: 10px;
        }
        .sp-store-qty {
            width: 60px;
            padding: 8px 6px;
            border: 1px solid #d0d5dd;
            border-radius: 6px;
            font-size: 14px;
            text-align: center;
        }
        .sp-store-add-to-cart {
            flex: 1;
            display: inline-block;
            padding: 10px 20px;
            background: var(--sp-color-accent, #c9973a);
            color: #fff;
            font-size: 14px;
            font-weight: 600;
            border-radius: 6px;
            text-decoration: none;
            text-align: center;
            transition: opacity 0.2s ease;
            cursor: pointer;
            border: none;
        }
        .sp-store-add-to-cart:hover {
            opacity: 0.85;
            color: #fff;
        }

        @media (max-width: 768px) {
            .sp-store-layout { flex-direction: column; }
            .sp-store-sidebar { flex: none; width: 100%; }
            .sp-store-cat-list { display: flex; flex-wrap: wrap; gap: 6px; }
            .sp-store-cat-list li { margin: 0; }
            .sp-store-cat-list a { padding: 6px 12px; font-size: 13px; background: #f0f0f0; border-radius: 20px; }
            .sp-store-cat-list a.active { background: var(--sp-color-primary, #2271b1); }
            .sp-store-grid {
                grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
                gap: 20px;
            }
            .sp-store-intro h1 { font-size: 26px; }
        }
        @media (max-width: 480px) {
            .sp-store-grid { grid-template-columns: 1fr; }
        }
    </style>

    <?php
    // Store intro — uses custom text if configured, otherwise a sensible default
    $store_intro = trim( $settings['store_intro_text'] ?? '' );
    $org_name    = trim( $settings['organization_name'] ?? get_bloginfo( 'name' ) );
    if ( $store_intro === '' ) {
        $store_intro = sprintf(
            /* translators: %s: organization name */
            __( 'Browse publications and materials available from %s.', 'societypress' ),
            $org_name
        );
    }
    ?>
    <div class="sp-store-intro">
        <h1><?php esc_html_e( 'Publications', 'societypress' ); ?></h1>
        <p><?php echo esc_html( $store_intro ); ?></p>
    </div>

    <div class="sp-store-layout">
        <!-- Category sidebar -->
        <aside class="sp-store-sidebar">
            <h3><?php esc_html_e( 'Categories', 'societypress' ); ?></h3>
            <ul class="sp-store-cat-list">
                <li>
                    <a href="<?php echo esc_url( remove_query_arg( 'sp_store_cat' ) ); ?>"<?php echo ! $active_cat ? ' class="active"' : ''; ?>>
                        <?php esc_html_e( 'All Publications', 'societypress' ); ?>
                        <span class="sp-store-cat-count"><?php echo $total_count; ?></span>
                    </a>
                </li>
                <?php foreach ( $categories as $cat ) : ?>
                    <li>
                        <a href="<?php echo esc_url( add_query_arg( 'sp_store_cat', urlencode( $cat->store_category ) ) ); ?>"<?php echo $active_cat === $cat->store_category ? ' class="active"' : ''; ?>>
                            <?php echo esc_html( $cat->store_category ); ?>
                            <span class="sp-store-cat-count"><?php echo $cat->cnt; ?></span>
                        </a>
                    </li>
                <?php endforeach; ?>
            </ul>
        </aside>

        <!-- Product grid -->
        <div class="sp-store-main">
            <?php if ( empty( $items ) ) : ?>
                <p class="sp-text-secondary sp-italic"><?php esc_html_e( 'No publications found in this category.', 'societypress' ); ?></p>
            <?php else : ?>
                <div class="sp-store-count">
                    <?php echo count( $items ); ?> <?php esc_html_e( 'publications', 'societypress' ); ?>
                    <?php if ( $active_cat ) : ?>
                        <?php esc_html_e( 'in', 'societypress' ); ?> <strong><?php echo esc_html( $active_cat ); ?></strong>
                    <?php endif; ?>
                </div>

                <div class="sp-store-grid">
                    <?php foreach ( $items as $item ) :
                        $author = rtrim( trim( $item->author ?? '' ), ',' );
                        // WHY: store_description is marketing copy written by
                        // Harold specifically for the store. If he hasn't written
                        // one yet, fall back to the physical description from the
                        // library catalog so the card isn't blank.
                        $desc   = $item->store_description ?: ( $item->description ?: '' );
                    ?>
                        <div class="sp-store-card" data-item-id="<?php echo (int) $item->id; ?>">
                            <div class="sp-store-cover">
                                <?php if ( ! empty( $item->cover_url ) ) : ?>
                                    <img src="<?php echo esc_url( $item->cover_url ); ?>" alt="<?php echo esc_attr( $item->title ); ?>" loading="lazy">
                                <?php else : ?>
                                    <div class="sp-store-cover-placeholder">
                                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
                                            <path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"></path>
                                            <path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"></path>
                                        </svg>
                                        <span><?php echo esc_html( wp_trim_words( $item->title, 6, '...' ) ); ?></span>
                                    </div>
                                <?php endif; ?>
                            </div>
                            <div class="sp-store-body">
                                <?php if ( $item->store_category ) : ?>
                                    <div class="sp-store-cat-badge"><?php echo esc_html( $item->store_category ); ?></div>
                                <?php endif; ?>
                                <h3 class="sp-store-title"><?php echo esc_html( $item->title ); ?></h3>
                                <?php if ( $author ) : ?>
                                    <div class="sp-store-author"><?php echo esc_html( $author ); ?><?php if ( $item->pub_year ) echo ' (' . esc_html( $item->pub_year ) . ')'; ?></div>
                                <?php endif; ?>
                                <?php if ( $desc ) : ?>
                                    <div class="sp-store-desc"><?php echo esc_html( $desc ); ?></div>
