        <!-- Update Status -->
        <div class="postbox sp-order-detail-box-mt">
            <h3 class="sp-order-detail-box-heading"><?php esc_html_e( 'Update Order', 'societypress' ); ?></h3>
            <form method="post">
                <?php wp_nonce_field( 'sp_update_order', 'sp_order_nonce' ); ?>
                <table class="form-table">
