                            <?php else : ?>
                                <span style="color:#2e7d32;">&#127760; <?php esc_html_e( 'Public', 'societypress' ); ?></span>
                            <?php endif; ?>
                        </td>
                        <td><?php echo $doc->status === 'published' ? esc_html__( 'Published', 'societypress' ) : esc_html__( 'Draft', 'societypress' ); ?></td>
                        <td>
                            <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-document-edit&id=' . $doc->id ) ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a>
                            |
                            <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-documents' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this document?', 'societypress' ) ); ?>">
                                <?php wp_nonce_field( 'sp_delete_document_' . $doc->id ); ?>
                                <input type="hidden" name="action" value="delete">
                                <input type="hidden" name="id" value="<?php echo (int) $doc->id; ?>">
                                <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                            </form>
                        </td>
                    </tr>
                    <?php endforeach; ?>
                <?php endif; ?>
            </tbody>
        </table>

        <p style="color:#666; margin-top:12px;">
            <?php printf( esc_html__( '%d document(s)', 'societypress' ), count( $docs ) ); ?>
        </p>
    </div>
    <?php
}


/**
 * Export all documents as a ZIP archive organized by category subfolders,
 * plus a metadata CSV.
 *
 * WHY: Documents are a society's institutional memory — bylaws, meeting minutes,
 *      forms, policies. An admin who needs an offline backup or is migrating to
 *      another platform should be able to download everything in one shot with
 *      the category structure preserved. The CSV provides the metadata (access
 *      levels, dates, categories) so reimporting into another system is possible.
 *
 * NOTE: Unlike newsletters (which use WP attachment IDs via file_id), documents
 *       store a direct file_url. We resolve that URL to a local filesystem path
 *       so we can copy the actual file into the ZIP without an HTTP round-trip.
 */
add_action( 'wp_ajax_sp_export_documents_zip', function () {
    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( esc_html__( 'Unauthorized.', 'societypress' ) );
    }
    if ( ! wp_verify_nonce( $_GET['nonce'] ?? '', 'sp_export_documents_zip' ) ) {
        wp_die( esc_html__( 'Security check failed.', 'societypress' ) );
    }

    if ( ! class_exists( 'ZipArchive' ) ) {
        wp_die( esc_html__( 'The ZipArchive PHP extension is required but not available on this server.', 'societypress' ) );
    }

    global $wpdb;
    $docs_table = $wpdb->prefix . 'sp_documents';
    $cats_table = $wpdb->prefix . 'sp_document_categories';

    $documents = $wpdb->get_results(
        "SELECT d.*, c.name AS category_name
         FROM {$docs_table} d
         LEFT JOIN {$cats_table} c ON d.category_id = c.id
         ORDER BY c.sort_order ASC, c.name ASC, d.title ASC"
    );

    if ( empty( $documents ) ) {
        wp_die( esc_html__( 'No documents to export.', 'societypress' ) );
    }

    // Build temp directory inside the WP uploads folder
    $upload_dir = wp_upload_dir();
    $temp_base  = trailingslashit( $upload_dir['basedir'] ) . 'sp-export-temp/';
    $temp_dir   = $temp_base . 'documents-' . wp_generate_password( 8, false ) . '/';

    if ( ! wp_mkdir_p( $temp_dir ) ) {
        wp_die( esc_html__( 'Could not create temporary directory for export.', 'societypress' ) );
    }

    // Clean up temp files when we are done no matter what
    $cleanup = function () use ( $temp_dir, $temp_base ) {
        if ( is_dir( $temp_dir ) ) {
            $files = new RecursiveIteratorIterator(
                new RecursiveDirectoryIterator( $temp_dir, RecursiveDirectoryIterator::SKIP_DOTS ),
                RecursiveIteratorIterator::CHILD_FIRST
            );
            foreach ( $files as $file_info ) {
                if ( $file_info->isDir() ) {
                    @rmdir( $file_info->getRealPath() );
                } else {
                    @unlink( $file_info->getRealPath() );
                }
            }
            @rmdir( $temp_dir );
        }
        foreach ( glob( $temp_base . 'documents-*.zip' ) as $stale_zip ) {
            @unlink( $stale_zip );
        }
    };
    register_shutdown_function( $cleanup );

    // ---- Build the metadata CSV ----
    $csv_path = $temp_dir . 'documents.csv';
    $csv_out  = fopen( $csv_path, 'w' );
    // UTF-8 BOM for Excel compatibility
    fwrite( $csv_out, "\xEF\xBB\xBF" );
    fputcsv( $csv_out, [
        'ID', 'Title', 'Category', 'Access Level', 'Status', 'Created At', 'Filename',
    ] );

    // Helper: convert a file_url stored in the database to a local filesystem
    // path. Documents are typically stored inside wp-content/uploads, so we
    // swap the uploads base URL for the uploads base directory.
    $uploads_url  = trailingslashit( $upload_dir['baseurl'] );
    $uploads_path = trailingslashit( $upload_dir['basedir'] );

    // Track filenames per category folder to avoid collisions
    $used_filenames = [];

    foreach ( $documents as $doc ) {
        // Determine category subfolder name (sanitized), or "Uncategorized"
        $category_folder = $doc->category_name
            ? sanitize_file_name( $doc->category_name )
            : sanitize_file_name( __( 'Uncategorized', 'societypress' ) );

        // Ensure the category subfolder exists
        $cat_dir = $temp_dir . $category_folder . '/';
        if ( ! is_dir( $cat_dir ) ) {
            wp_mkdir_p( $cat_dir );
        }

        $safe_filename = '';

        // Resolve the file_url to a local path so we can copy without HTTP
        if ( ! empty( $doc->file_url ) ) {
            $local_path = '';
            // If the URL is within the uploads directory, resolve directly
            if ( strpos( $doc->file_url, $uploads_url ) === 0 ) {
                $relative   = substr( $doc->file_url, strlen( $uploads_url ) );
                $local_path = $uploads_path . $relative;
            } elseif ( strpos( $doc->file_url, '/' ) === 0 && file_exists( ABSPATH . ltrim( $doc->file_url, '/' ) ) ) {
                // Absolute path relative to ABSPATH
                $local_path = ABSPATH . ltrim( $doc->file_url, '/' );
            }

            if ( $local_path && file_exists( $local_path ) ) {
                $ext = pathinfo( $local_path, PATHINFO_EXTENSION );
                if ( ! $ext && ! empty( $doc->file_name ) ) {
                    $ext = pathinfo( $doc->file_name, PATHINFO_EXTENSION );
                }
                if ( ! $ext ) {
                    $ext = 'pdf';
                }

                // Build a human-readable filename from the document title
                $base_name = sanitize_file_name( $doc->title );
                $base_name = preg_replace( '/\.' . preg_quote( $ext, '/' ) . '$/i', '', $base_name );
                $candidate = $base_name . '.' . $ext;

                // Initialize per-category dedup tracker
                $cat_key = strtolower( $category_folder );
                if ( ! isset( $used_filenames[ $cat_key ] ) ) {
                    $used_filenames[ $cat_key ] = [];
                }

                // Deduplicate within the category folder
                $counter = 1;
                while ( in_array( strtolower( $candidate ), $used_filenames[ $cat_key ], true ) ) {
                    $candidate = $base_name . '-' . $counter . '.' . $ext;
                    $counter++;
                }
                $used_filenames[ $cat_key ][] = strtolower( $candidate );
                $safe_filename = $candidate;

                copy( $local_path, $cat_dir . $safe_filename );
            }
        }

        fputcsv( $csv_out, [
            $doc->id,
            $doc->title,
            $doc->category_name ?? '',
            $doc->access_level,
            $doc->status,
            $doc->created_at,
            $safe_filename ? ( $category_folder . '/' . $safe_filename ) : '',
        ] );
    }

    fclose( $csv_out );

    // ---- Create the ZIP ----
    $zip_filename = 'documents-' . wp_date( 'Y-m-d' ) . '.zip';
    $zip_path     = $temp_base . $zip_filename;

    $zip = new ZipArchive();
    if ( $zip->open( $zip_path, ZipArchive::CREATE | ZipArchive::OVERWRITE ) !== true ) {
        wp_die( esc_html__( 'Could not create ZIP file.', 'societypress' ) );
    }

    // Walk the temp directory recursively; preserve category subfolder structure
    $base_len      = strlen( $temp_dir );
    $dir_iterator  = new RecursiveDirectoryIterator( $temp_dir, RecursiveDirectoryIterator::SKIP_DOTS );
    $file_iterator = new RecursiveIteratorIterator( $dir_iterator );
    foreach ( $file_iterator as $file_info ) {
        if ( $file_info->isFile() ) {
            // Relative path preserves category subfolders (e.g. "Bylaws/charter.pdf")
            $relative_path = substr( $file_info->getRealPath(), $base_len );
            $zip->addFile( $file_info->getRealPath(), $relative_path );
        }
    }

    $zip->close();

    // ---- Stream the ZIP to the browser ----
    $zip_size = filesize( $zip_path );
    header( 'Content-Type: application/zip' );
    header( 'Content-Disposition: attachment; filename="' . $zip_filename . '"' );
    header( 'Content-Length: ' . $zip_size );
    header( 'Pragma: no-cache' );
    header( 'Expires: 0' );

    readfile( $zip_path );

    // Clean up the ZIP file immediately (temp dir handled by shutdown function)
    @unlink( $zip_path );

    exit;
} );


// ---------------------------------------------------------------------------
// ADMIN: Document categories page
// ---------------------------------------------------------------------------

function sp_render_document_categories_page(): void {
    global $wpdb;
    $table = $wpdb->prefix . 'sp_document_categories';

    // Editing an existing category?
    $edit_id  = (int) ( $_GET['edit'] ?? 0 );
    $edit_cat = $edit_id ? $wpdb->get_row( $wpdb->prepare( "SELECT * FROM {$table} WHERE id = %d", $edit_id ) ) : null;

    $categories = $wpdb->get_results( "SELECT * FROM {$table} ORDER BY sort_order, name" );

    // Count documents per category
    $doc_counts = $wpdb->get_results(
        "SELECT category_id, COUNT(*) AS cnt FROM {$wpdb->prefix}sp_documents GROUP BY category_id",
        OBJECT_K
    );

    ?>
    <div class="wrap">
        <h1><?php esc_html_e( 'Document Categories', 'societypress' ); ?></h1>

        <?php if ( ! empty( $_GET['sp_updated'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Category saved.', 'societypress' ); ?></p></div>
        <?php endif; ?>
        <?php if ( ! empty( $_GET['sp_deleted'] ) ) : ?>
            <div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Category deleted.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <div style="display:flex; gap:40px; flex-wrap:wrap; margin-top:20px;">

            <!-- Add/Edit form -->
            <div style="flex:0 0 320px;">
                <h2><?php echo $edit_cat ? esc_html__( 'Edit Category', 'societypress' ) : esc_html__( 'Add Category', 'societypress' ); ?></h2>
                <form method="post">
                    <?php wp_nonce_field( 'sp_save_document_category', 'sp_doc_cat_nonce' ); ?>
                    <input type="hidden" name="sp_save_document_category" value="1">
                    <?php if ( $edit_cat ) : ?>
                        <input type="hidden" name="category_id" value="<?php echo (int) $edit_cat->id; ?>">
                    <?php endif; ?>

                    <table class="form-table">
                        <tr>
                            <th><label for="category_name"><?php esc_html_e( 'Name', 'societypress' ); ?></label></th>
                            <td><input type="text" id="category_name" name="category_name" value="<?php echo esc_attr( $edit_cat->name ?? '' ); ?>" class="regular-text" required></td>
                        </tr>
                        <tr>
                            <th><label for="category_description"><?php esc_html_e( 'Description', 'societypress' ); ?></label></th>
                            <td><textarea id="category_description" name="category_description" rows="3" class="large-text"><?php echo esc_textarea( $edit_cat->description ?? '' ); ?></textarea></td>
                        </tr>
                        <tr>
                            <th><label for="category_sort_order"><?php esc_html_e( 'Sort Order', 'societypress' ); ?></label></th>
                            <td><input type="number" id="category_sort_order" name="category_sort_order" value="<?php echo (int) ( $edit_cat->sort_order ?? 0 ); ?>" min="0" class="sp-w-80"></td>
                        </tr>
                    </table>

                    <?php submit_button( $edit_cat ? __( 'Update Category', 'societypress' ) : __( 'Add Category', 'societypress' ) ); ?>

                    <?php if ( $edit_cat ) : ?>
                        <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-document-categories' ) ); ?>"><?php esc_html_e( 'Cancel editing', 'societypress' ); ?></a>
                    <?php endif; ?>
                </form>
            </div>

            <!-- Categories table -->
            <div style="flex:1; min-width:400px;">
                <table class="widefat striped">
                    <thead>
                        <tr>
                            <th><?php esc_html_e( 'Name', 'societypress' ); ?></th>
                            <th><?php esc_html_e( 'Slug', 'societypress' ); ?></th>
                            <th><?php esc_html_e( 'Documents', 'societypress' ); ?></th>
                            <th><?php esc_html_e( 'Order', 'societypress' ); ?></th>
                            <th><?php esc_html_e( 'Actions', 'societypress' ); ?></th>
                        </tr>
                    </thead>
                    <tbody>
                        <?php if ( empty( $categories ) ) : ?>
                            <tr><td colspan="5" class="sp-empty-state"><?php esc_html_e( 'No categories yet.', 'societypress' ); ?></td></tr>
                        <?php else : ?>
                            <?php foreach ( $categories as $cat ) : ?>
                            <tr>
                                <td><strong><?php echo esc_html( $cat->name ); ?></strong></td>
                                <td><code><?php echo esc_html( $cat->slug ); ?></code></td>
                                <td><?php echo (int) ( $doc_counts[ $cat->id ]->cnt ?? 0 ); ?></td>
                                <td><?php echo (int) $cat->sort_order; ?></td>
                                <td>
                                    <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-document-categories&edit=' . $cat->id ) ); ?>"><?php esc_html_e( 'Edit', 'societypress' ); ?></a>
                                    |
                                    <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-document-categories' ) ); ?>" class="sp-inline" data-sp-confirm="<?php echo esc_attr( __( 'Delete this category? Documents in it will become uncategorized.', 'societypress' ) ); ?>">
                                        <?php wp_nonce_field( 'sp_delete_doc_cat_' . $cat->id ); ?>
                                        <input type="hidden" name="action" value="delete">
                                        <input type="hidden" name="id" value="<?php echo (int) $cat->id; ?>">
                                        <button type="submit" class="sp-link-btn"><?php esc_html_e( 'Delete', 'societypress' ); ?></button>
                                    </form>
                                </td>
                            </tr>
                            <?php endforeach; ?>
                        <?php endif; ?>
                    </tbody>
                </table>
            </div>

        </div>
    </div>
    <?php
}


// ---------------------------------------------------------------------------
// ADMIN: Document add/edit page
// ---------------------------------------------------------------------------

function sp_render_document_edit_page(): void {
    global $wpdb;

    $doc_id = (int) ( $_GET['id'] ?? 0 );
    $doc    = $doc_id ? $wpdb->get_row( $wpdb->prepare(
        "SELECT * FROM {$wpdb->prefix}sp_documents WHERE id = %d", $doc_id
    ) ) : null;

    $is_edit    = (bool) $doc;
    $categories = $wpdb->get_results(
        "SELECT * FROM {$wpdb->prefix}sp_document_categories ORDER BY sort_order, name"
    );

    // Enqueue media library for file picker
    wp_enqueue_media();

    ?>
    <div class="wrap">
        <h1><?php echo $is_edit ? esc_html__( 'Edit Document', 'societypress' ) : esc_html__( 'Add Document', 'societypress' ); ?></h1>

        <?php if ( ! empty( $_GET['sp_error'] ) && $_GET['sp_error'] === 'missing_fields' ) : ?>
            <div class="notice notice-error"><p><?php esc_html_e( 'Title and file are required.', 'societypress' ); ?></p></div>
        <?php endif; ?>

        <form method="post" action="<?php echo esc_url( admin_url( 'admin.php?page=sp-document-edit' ) ); ?>">
            <?php wp_nonce_field( 'sp_save_document', 'sp_document_nonce' ); ?>
            <input type="hidden" name="sp_save_document" value="1">
            <?php if ( $is_edit ) : ?>
                <input type="hidden" name="document_id" value="<?php echo (int) $doc->id; ?>">
            <?php endif; ?>

            <table class="form-table">
                <tr>
                    <th><label for="document_title"><?php esc_html_e( 'Title', 'societypress' ); ?></label></th>
                    <td><input type="text" id="document_title" name="document_title" value="<?php echo esc_attr( $doc->title ?? '' ); ?>" class="regular-text" style="width:100%; max-width:600px;" required></td>
                </tr>
                <tr>
                    <th><label for="document_description"><?php esc_html_e( 'Description', 'societypress' ); ?></label></th>
                    <td><textarea id="document_description" name="document_description" rows="3" class="large-text" style="max-width:600px;"><?php echo esc_textarea( $doc->description ?? '' ); ?></textarea></td>
                </tr>
                <tr>
                    <th><label for="document_category"><?php esc_html_e( 'Category', 'societypress' ); ?></label></th>
                    <td>
                        <select id="document_category" name="document_category">
                            <option value=""><?php esc_html_e( '— None —', 'societypress' ); ?></option>
                            <?php foreach ( $categories as $cat ) : ?>
                                <option value="<?php echo (int) $cat->id; ?>" <?php selected( $doc->category_id ?? 0, $cat->id ); ?>><?php echo esc_html( $cat->name ); ?></option>
                            <?php endforeach; ?>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="document_date"><?php esc_html_e( 'Document Date', 'societypress' ); ?></label></th>
                    <td><input type="date" id="document_date" name="document_date" value="<?php echo esc_attr( $doc->document_date ?? '' ); ?>"></td>
                </tr>
                <tr>
                    <th><?php esc_html_e( 'File', 'societypress' ); ?></th>
                    <td>
                        <input type="hidden" id="document_file_url" name="document_file_url" value="<?php echo esc_attr( $doc->file_url ?? '' ); ?>">
                        <input type="hidden" id="document_file_name" name="document_file_name" value="<?php echo esc_attr( $doc->file_name ?? '' ); ?>">
                        <input type="hidden" id="document_file_size" name="document_file_size" value="<?php echo (int) ( $doc->file_size ?? 0 ); ?>">
                        <input type="hidden" id="document_file_type" name="document_file_type" value="<?php echo esc_attr( $doc->file_type ?? '' ); ?>">

                        <div id="sp-doc-file-info" style="margin-bottom:8px; <?php echo empty( $doc->file_url ?? '' ) ? 'display:none;' : ''; ?>">
                            <span id="sp-doc-file-display"><?php echo esc_html( $doc->file_name ?? '' ); ?></span>
                            <?php if ( ! empty( $doc->file_size ) ) : ?>
                                <span class="sp-text-secondary"> (<?php echo esc_html( size_format( $doc->file_size ) ); ?>)</span>
                            <?php endif; ?>
                        </div>

                        <button type="button" id="sp-doc-upload-btn" class="button"><?php esc_html_e( 'Choose File', 'societypress' ); ?></button>
                        <button type="button" id="sp-doc-remove-btn" class="button" style="color:#b32d2e; <?php echo empty( $doc->file_url ?? '' ) ? 'display:none;' : ''; ?>"><?php esc_html_e( 'Remove', 'societypress' ); ?></button>
                    </td>
                </tr>
                <tr>
                    <th><label for="document_access"><?php esc_html_e( 'Access Level', 'societypress' ); ?></label></th>
                    <td>
                        <select id="document_access" name="document_access">
                            <option value="members_only" <?php selected( $doc->access_level ?? 'members_only', 'members_only' ); ?>><?php esc_html_e( 'Members Only', 'societypress' ); ?></option>
                            <option value="public" <?php selected( $doc->access_level ?? '', 'public' ); ?>><?php esc_html_e( 'Public', 'societypress' ); ?></option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="document_status"><?php esc_html_e( 'Status', 'societypress' ); ?></label></th>
                    <td>
                        <select id="document_status" name="document_status">
                            <option value="published" <?php selected( $doc->status ?? 'published', 'published' ); ?>><?php esc_html_e( 'Published', 'societypress' ); ?></option>
                            <option value="draft" <?php selected( $doc->status ?? '', 'draft' ); ?>><?php esc_html_e( 'Draft', 'societypress' ); ?></option>
                        </select>
                    </td>
                </tr>
                <tr>
                    <th><label for="document_sort_order"><?php esc_html_e( 'Sort Order', 'societypress' ); ?></label></th>
                    <td><input type="number" id="document_sort_order" name="document_sort_order" value="<?php echo (int) ( $doc->sort_order ?? 0 ); ?>" min="0" class="sp-w-80"></td>
                </tr>
            </table>

            <p class="submit">
                <input type="submit" class="button button-primary" value="<?php echo $is_edit ? esc_attr__( 'Update Document', 'societypress' ) : esc_attr__( 'Add Document', 'societypress' ); ?>">
                <a href="<?php echo esc_url( admin_url( 'admin.php?page=sp-documents' ) ); ?>" class="button" class="sp-ml-8"><?php esc_html_e( 'Cancel', 'societypress' ); ?></a>
            </p>
        </form>
    </div>

    <!-- WHY inline JS: The media library picker is a single-use interaction on
         this page. A separate .js file would add an HTTP request for ~30 lines
         of code that only runs on this one admin screen. -->
    <script>
    (function() {
        var frame;
        var uploadBtn  = document.getElementById('sp-doc-upload-btn');
        var removeBtn  = document.getElementById('sp-doc-remove-btn');
        var fileInfo   = document.getElementById('sp-doc-file-info');
        var fileDisplay = document.getElementById('sp-doc-file-display');

        if (!uploadBtn) return;

        uploadBtn.addEventListener('click', function(e) {
            e.preventDefault();

            if (frame) { frame.open(); return; }

            frame = wp.media({
                title: '<?php echo esc_js( __( 'Select Document', 'societypress' ) ); ?>',
                button: { text: '<?php echo esc_js( __( 'Use This File', 'societypress' ) ); ?>' },
                multiple: false
            });

            frame.on('select', function() {
                var attachment = frame.state().get('selection').first().toJSON();
                document.getElementById('document_file_url').value  = attachment.url;
                document.getElementById('document_file_name').value = attachment.filename;
                document.getElementById('document_file_size').value = attachment.filesizeInBytes || 0;
                document.getElementById('document_file_type').value = attachment.mime || '';

                fileDisplay.textContent = attachment.filename;
                fileInfo.style.display = '';
                removeBtn.style.display = '';
            });

            frame.open();
        });

        removeBtn.addEventListener('click', function(e) {
            e.preventDefault();
            document.getElementById('document_file_url').value  = '';
            document.getElementById('document_file_name').value = '';
            document.getElementById('document_file_size').value = '0';
            document.getElementById('document_file_type').value = '';
            fileInfo.style.display = 'none';
            removeBtn.style.display = 'none';
        });
    })();
    </script>
    <?php
}


// ---------------------------------------------------------------------------
// ADMIN: Document bulk upload handler
// ---------------------------------------------------------------------------

/**
 * Process bulk document uploads.
 *
 * WHY: Societies often have dozens or hundreds of documents (meeting minutes,
 *      newsletters, reports) to upload at once. Doing them one at a time through
 *      the single-document form is impractical. This handler processes an array
 *      of files selected via the multi-select WP media picker, creating one
 *      sp_documents row per file with shared category/access/status settings.
 */
add_action( 'admin_init', function () {
    if ( empty( $_POST['sp_bulk_upload_documents'] ) ) return;

    if ( ! wp_verify_nonce( $_POST['sp_bulk_doc_nonce'] ?? '', 'sp_bulk_upload_documents' ) ) {
        wp_die( __( 'Security check failed.', 'societypress' ) );
    }

    if ( ! current_user_can( 'manage_options' ) ) {
        wp_die( __( 'You do not have permission to manage documents.', 'societypress' ) );
    }

    global $wpdb;
    $table = $wpdb->prefix . 'sp_documents';

    // Shared settings for all files in this batch
    $category_id  = (int) ( $_POST['bulk_category'] ?? 0 ) ?: null;
    $access_level = in_array( $_POST['bulk_access'] ?? '', [ 'public', 'members_only' ], true )
                    ? $_POST['bulk_access'] : 'members_only';
    $status       = in_array( $_POST['bulk_status'] ?? '', [ 'published', 'draft' ], true )
                    ? $_POST['bulk_status'] : 'published';

    // Per-file data arrays
    $urls   = $_POST['bulk_file_url']  ?? [];
    $names  = $_POST['bulk_file_name'] ?? [];
    $sizes  = $_POST['bulk_file_size'] ?? [];
    $types  = $_POST['bulk_file_type'] ?? [];
    $titles = $_POST['bulk_title']     ?? [];
    $dates  = $_POST['bulk_date']      ?? [];

    $count = 0;
    $now   = current_time( 'mysql' );
    $uid   = get_current_user_id();

    for ( $i = 0, $len = count( $urls ); $i < $len; $i++ ) {
        $file_url  = esc_url_raw( $urls[ $i ] ?? '' );
        $file_name = sanitize_file_name( $names[ $i ] ?? '' );

        // Skip rows with no file
        if ( empty( $file_url ) || empty( $file_name ) ) continue;

        $title = sanitize_text_field( $titles[ $i ] ?? '' );
        if ( empty( $title ) ) {
            // Fallback: use filename without extension as title
            $title = pathinfo( $file_name, PATHINFO_FILENAME );
        }

        $doc_date = sanitize_text_field( $dates[ $i ] ?? '' );
        // Validate date format (YYYY-MM-DD)
        if ( $doc_date && ! preg_match( '/^\d{4}-\d{2}-\d{2}$/', $doc_date ) ) {
            $doc_date = null;
        }

        $wpdb->insert( $table, [
            'title'         => $title,
            'description'   => '',
            'category_id'   => $category_id,
            'file_url'      => $file_url,
            'file_name'     => $file_name,
            'file_size'     => (int) ( $sizes[ $i ] ?? 0 ),
            'file_type'     => sanitize_text_field( $types[ $i ] ?? '' ),
            'access_level'  => $access_level,
            'document_date' => $doc_date ?: null,
            'uploaded_by'   => $uid,
            'status'        => $status,
            'sort_order'    => 0,
            'created_at'    => $now,
            'updated_at'    => $now,
        ] );

        $count++;
    }

    wp_safe_redirect( admin_url( 'admin.php?page=sp-documents&sp_bulk_count=' . $count ) );
    exit;
});


