                </tr>
                <?php endif; ?>
            </table>

            <!-- Eligibility Section -->
            <h2><?php esc_html_e( 'Eligibility', 'societypress' ); ?></h2>
            <table class="form-table">
                <tr>
                    <th><?php esc_html_e( 'Who Can Vote', 'societypress' ); ?></th>
                    <td>
                        <label>
