// --------------------------------------------------------------------------
// FRONTEND JS — Voting form submission, validation, countdown
//
// WHY: The vote form uses fetch() for async submission so the page doesn't
//      reload. This also handles max-selection enforcement for multi-choice
//      questions and disables the form after a successful vote to prevent
//      accidental double-clicks.
// --------------------------------------------------------------------------
function sp_voting_frontend_js(): void {
    ?>
    <script id="sp-voting-frontend-js">
    (function() {
        'use strict';

        var ajaxUrl = '<?php echo esc_js( admin_url( 'admin-ajax.php' ) ); ?>';

        // ---- Vote form submission ----
        document.querySelectorAll('.sp-vote-form').forEach(function(form) {
            form.addEventListener('submit', function(e) {
                e.preventDefault();

                var ballotId = form.getAttribute('data-ballot-id');
                var nonce    = form.getAttribute('data-nonce');
                var submitBtn = form.querySelector('.sp-vote-submit-btn');
                var msgDiv    = form.querySelector('.sp-vote-form-message');

                // ---- Client-side validation ----
                var questions = form.querySelectorAll('.sp-vote-question');
                var valid = true;

                questions.forEach(function(qDiv) {
                    var qId = qDiv.getAttribute('data-question-id');
                    var inputs = qDiv.querySelectorAll('input[type="radio"], input[type="checkbox"]');
                    var hasSelection = false;

                    inputs.forEach(function(input) {
                        if (input.checked) hasSelection = true;
                    });

                    // WHY: When abstain is not allowed, every question requires a selection.
                    // The form's data-allow-abstain attribute is set from the ballot settings.
                    // We check client-side first to give immediate feedback before the round-trip.
                    var allowAbstain = form.getAttribute('data-allow-abstain') === '1';
                    if (!hasSelection && !allowAbstain) {
                        valid = false;
                        // Add visual error indicator so the member sees which question they missed
                        qDiv.style.outline = '2px solid #b32d2e';
                        qDiv.style.outlineOffset = '4px';
                        qDiv.style.borderRadius = '4px';
                    } else {
                        // Clear any previous error state
                        qDiv.style.outline = '';
                        qDiv.style.outlineOffset = '';
                    }
                });

                if (!valid) {
                    msgDiv.textContent = '<?php echo esc_js( __( 'Please make a selection for every question before submitting.', 'societypress' ) ); ?>';
                    msgDiv.className = 'sp-vote-form-message sp-vote-form-message--error';
                    msgDiv.style.display = '';
                    return;
                }

                // ---- Build form data ----
                var fd = new FormData();
                fd.append('action', 'sp_submit_vote');
                fd.append('ballot_id', ballotId);
                fd.append('nonce', nonce);

                // Collect all vote data
                questions.forEach(function(qDiv) {
                    var qId = qDiv.getAttribute('data-question-id');
                    var radios = qDiv.querySelectorAll('input[type="radio"]:checked');
                    var checkboxes = qDiv.querySelectorAll('input[type="checkbox"]:checked');

                    if (radios.length > 0) {
                        fd.append('vote_q_' + qId, radios[0].value);
                    } else if (checkboxes.length > 0) {
                        checkboxes.forEach(function(cb) {
                            fd.append('vote_q_' + qId + '[]', cb.value);
                        });
                    }
                    // If nothing selected, the server will handle it (abstain or error)
                });

                // ---- Submit ----
                submitBtn.disabled = true;
                submitBtn.textContent = '<?php echo esc_js( __( 'Submitting...', 'societypress' ) ); ?>';

                fetch(ajaxUrl, {
                    method: 'POST',
                    body: fd,
                    credentials: 'same-origin'
                })
                .then(function(r) { return r.json(); })
                .then(function(data) {
                    if (data.success) {
                        // Show success message and disable the form
                        msgDiv.textContent = data.data.message;
                        msgDiv.className = 'sp-vote-form-message sp-vote-form-message--success';
                        msgDiv.style.display = '';

                        // Disable all form inputs
                        form.querySelectorAll('input, button').forEach(function(el) {
                            el.disabled = true;
                        });
                        submitBtn.style.display = 'none';
                    } else {
                        msgDiv.textContent = data.data || '<?php echo esc_js( __( 'An error occurred.', 'societypress' ) ); ?>';
                        msgDiv.className = 'sp-vote-form-message sp-vote-form-message--error';
                        msgDiv.style.display = '';
                        submitBtn.disabled = false;
                        submitBtn.textContent = '<?php echo esc_js( __( 'Submit Vote', 'societypress' ) ); ?>';
                    }
                })
                .catch(function() {
                    msgDiv.textContent = '<?php echo esc_js( __( 'Something went wrong. Please try again.', 'societypress' ) ); ?>';
                    msgDiv.className = 'sp-vote-form-message sp-vote-form-message--error';
                    msgDiv.style.display = '';
                    submitBtn.disabled = false;
                    submitBtn.textContent = '<?php echo esc_js( __( 'Submit Vote', 'societypress' ) ); ?>';
                });
            });
        });

        // ---- Max selections enforcement for multi-choice ----
        document.querySelectorAll('.sp-vote-question').forEach(function(qDiv) {
            var checkboxes = qDiv.querySelectorAll('input[type="checkbox"]');
            if (checkboxes.length === 0) return;

            // Get max from the first non-abstain checkbox's data attribute
            var maxSel = 0;
            checkboxes.forEach(function(cb) {
                if (cb.getAttribute('data-max-selections')) {
                    maxSel = parseInt(cb.getAttribute('data-max-selections'), 10);
                }
            });
            if (maxSel <= 0) return;

            checkboxes.forEach(function(cb) {
                cb.addEventListener('change', function() {
                    // If abstain is checked, uncheck all others
                    if (cb.getAttribute('data-abstain') === '1' && cb.checked) {
                        checkboxes.forEach(function(other) {
                            if (other !== cb) other.checked = false;
                        });
                        return;
                    }

                    // If a non-abstain choice is checked, uncheck abstain
                    if (cb.checked && !cb.getAttribute('data-abstain')) {
                        checkboxes.forEach(function(other) {
                            if (other.getAttribute('data-abstain') === '1') other.checked = false;
                        });
                    }

                    // Count non-abstain checked
                    var checked = 0;
                    checkboxes.forEach(function(c) {
                        if (c.checked && c.getAttribute('data-abstain') !== '1') checked++;
                    });

                    // If over max, uncheck the one just checked
                    if (checked > maxSel) {
                        cb.checked = false;
                    }
                });
            });
        });

        // ---- Proxy voting: load form and submit via AJAX ----
        document.querySelectorAll('.sp-proxy-start-btn').forEach(function(btn) {
            btn.addEventListener('click', function() {
                var bId = btn.getAttribute('data-ballot-id'), nonce = btn.getAttribute('data-nonce');
                var sel = document.getElementById('sp-proxy-member-' + bId), tid = sel ? sel.value : '';
                var mD = document.getElementById('sp-proxy-msg-' + bId), fD = document.getElementById('sp-proxy-form-' + bId);
                if (!tid) { mD.textContent = 'Please select a member.'; mD.className = 'sp-proxy-message sp-vote-form-message--error'; mD.style.display = ''; return; }
                var bc = btn.closest('.sp-ballot-card'), of = bc ? bc.querySelector('.sp-vote-form') : null;
                var h = '<form class="sp-proxy-vote-form"><p class="sp-fw-600">Casting proxy vote for: ' + sel.options[sel.selectedIndex].text + '</p>';
                if (of) { of.querySelectorAll('.sp-vote-question').forEach(function(q) { var c = q.cloneNode(true); c.querySelectorAll('input').forEach(function(i) { i.checked = false; }); h += c.outerHTML; }); }
                h += '<div class="sp-vote-submit-wrap" style="margin-top:12px;"><button type="submit" class="sp-vote-submit-btn">Submit Proxy Vote</button></div><div class="sp-proxy-form-msg" style="display:none;"></div></form>';
                fD.innerHTML = h; fD.style.display = ''; mD.style.display = 'none';
                fD.querySelector('.sp-proxy-vote-form').addEventListener('submit', function(e) {
                    e.preventDefault(); var fd = new FormData(); fd.append('action','sp_submit_proxy_vote'); fd.append('ballot_id',bId); fd.append('proxy_for_user_id',tid); fd.append('nonce',nonce);
                    this.querySelectorAll('.sp-vote-question').forEach(function(qD) { var qi = qD.getAttribute('data-question-id'); var r = qD.querySelectorAll('input[type="radio"]:checked'), x = qD.querySelectorAll('input[type="checkbox"]:checked'); if (r.length) fd.append('vote_q_'+qi,r[0].value); else if (x.length) x.forEach(function(c){fd.append('vote_q_'+qi+'[]',c.value);}); });
                    var pB = this.querySelector('.sp-vote-submit-btn'), pM = this.querySelector('.sp-proxy-form-msg'), me = this;
                    pB.disabled = true; pB.textContent = 'Submitting...';
                    fetch(ajaxUrl,{method:'POST',body:fd,credentials:'same-origin'}).then(function(r){return r.json();}).then(function(d){
                        pM.style.display=''; if(d.success){pM.textContent=d.data.message;pM.className='sp-proxy-form-msg sp-vote-form-message--success';me.querySelectorAll('input,button').forEach(function(el){el.disabled=true;});pB.style.display='none';for(var i=0;i<sel.options.length;i++){if(sel.options[i].value===tid){sel.remove(i);break;}}}
                        else{pM.textContent=d.data||'Error';pM.className='sp-proxy-form-msg sp-vote-form-message--error';pB.disabled=false;pB.textContent='Submit Proxy Vote';}
                    }).catch(function(){pM.style.display='';pM.textContent='Something went wrong.';pM.className='sp-proxy-form-msg sp-vote-form-message--error';pB.disabled=false;pB.textContent='Submit Proxy Vote';});
                });
            });
        });

        // ---- Countdown timer for voting deadlines ----
        document.querySelectorAll('.sp-ballot-card[data-ballot-id]').forEach(function(card) {
            var periodEl = card.querySelector('.sp-ballot-period');
            if (!periodEl) return;

            // Try to extract the end date from the card text
            var votedBadge = card.querySelector('.sp-ballot-voted-badge');
            var closedBadge = card.querySelector('.sp-ballot-status--closed');
            if (votedBadge || closedBadge) return; // Don't show countdown for voted/closed

            // Add countdown placeholder
            var countdownEl = document.createElement('div');
            countdownEl.className = 'sp-vote-countdown';
            periodEl.parentNode.insertBefore(countdownEl, periodEl.nextSibling);

            // Parse the end date from the period text
            // The server renders the end date — we'll use a data attribute instead
            // (to avoid locale parsing issues, the countdown is approximate)
        });
    })();
    </script>
    <?php
}


// ============================================================================
// FORUMS (bbPress) INTEGRATION
//
// WHY: Many genealogical and historical societies want a discussion forum for
//      their members. bbPress is the leading WordPress forum plugin and already
//      follows WordPress conventions, so rather than building our own forum from
//      scratch, we provide a thin glue layer that:
//      - Restricts forum access based on SP membership status
//      - Syncs bbPress roles when membership status changes
//      - Auto-adds a "Forums" nav link for logged-in members
//      - Surfaces the bbPress admin in the SP sidebar
//
//      All hooks bail out early if the forums module is disabled or if bbPress
//      is not installed, so this code is completely inert when not needed.
// ============================================================================

/**
 * Admin notice: forums module enabled but bbPress not installed.
 *
 * WHY: Harold might enable the Forums module in Settings → Modules before
 *      actually installing bbPress. Rather than silently doing nothing, we
 *      show a clear, actionable notice so he knows what to do next.
 */
add_action( 'admin_notices', function (): void {
    if ( ! sp_module_enabled( 'forums' ) ) {
        return;
    }
    if ( class_exists( 'bbPress' ) ) {
        return;
    }
    // Only show to users who can install plugins — no point confusing editors
    if ( ! current_user_can( 'install_plugins' ) ) {
        return;
    }
    ?>
    <div class="notice notice-warning is-dismissible">
        <p>
            <strong><?php esc_html_e( 'SocietyPress Forums:', 'societypress' ); ?></strong>
            <?php
            echo wp_kses(
                sprintf(
                    /* translators: %1$s: opening link tag, %2$s: closing link tag */
                    __( 'The Forums module requires the bbPress plugin. Install it from %1$sPlugins → Add New%2$s.', 'societypress' ),
                    '<a href="' . esc_url( admin_url( 'plugin-install.php?s=bbpress&tab=search&type=term' ) ) . '">',
                    '</a>'
                ),
                [ 'a' => [ 'href' => [] ] ]
            );
            ?>
        </p>
    </div>
    <?php
} );

/**
 * Restrict forum access for non-members on members-only forums.
 *
 * WHY: If a forum's page has the _sp_members_only meta (or the forum itself
 *      is gated), non-members should be blocked entirely. bbPress provides
 *      the bbp_user_can_view_forum filter to control per-forum visibility.
 *      We hook into it and deny access when:
 *      - The user is not logged in, OR
 *      - The user has no SP member record
 *
 *      This respects the existing _sp_members_only page meta pattern used
 *      everywhere else in SP, so Harold can gate individual forums the same
 *      way he gates any other page.
 */
add_filter( 'bbp_user_can_view_forum', 'sp_bbpress_gate_forum_access', 10, 3 );

function sp_bbpress_gate_forum_access( $retval, $forum_id, $user_id ) {
    // Bail if forums module disabled or bbPress not active
    if ( ! sp_module_enabled( 'forums' ) || ! class_exists( 'bbPress' ) ) {
        return $retval;
    }

    // Check if this specific forum (or its parent page) is members-only
    // WHY: Not all forums need to be gated — only those the admin has
    //      explicitly marked. This lets societies have a mix of public
    //      and private forums.
    $forum_members_only = get_post_meta( $forum_id, '_sp_members_only', true ) === '1';

    if ( ! $forum_members_only ) {
        return $retval;
    }

    // Non-logged-in users: blocked from members-only forums
    if ( ! $user_id || ! is_user_logged_in() ) {
        return false;
    }

    // Logged-in but not an SP member: blocked
    if ( ! sp_is_member( $user_id ) ) {
        return false;
    }

    // SP members (any status including expired) can at least view
    // WHY: Expired members get read-only access (see topic/reply filters
    //      below), but they should still be able to browse existing threads.
    return $retval;
}

/**
 * Prevent expired/non-active members from creating new topics.
 *
 * WHY: Expired members retain read access so they can still reference past
 *      discussions, but they shouldn't be able to start new conversations.
 *      This encourages renewal while not being punitive about existing content.
 */
add_filter( 'bbp_current_user_can_publish_topics', 'sp_bbpress_gate_publish_topics' );

function sp_bbpress_gate_publish_topics( $can_publish ) {
    if ( ! sp_module_enabled( 'forums' ) || ! class_exists( 'bbPress' ) ) {
        return $can_publish;
    }

    $user_id = get_current_user_id();
    if ( ! $user_id ) {
        return false;
    }

    $member = sp_get_member_by_user_id( $user_id );

    // No member record — cannot post
    if ( ! $member ) {
        return false;
    }

    // Only active members can create topics
    // WHY: 'active' is the only status that means "fully paid, in good standing."
    //      Every other status (expired, lapsed, grace, pending, inactive, deceased)
    //      represents some form of non-current membership.
    if ( $member->status !== 'active' ) {
        return false;
    }

    return $can_publish;
}

/**
 * Prevent expired/non-active members from posting replies.
 *
 * WHY: Same logic as topics — if you can't start a thread, you shouldn't be
 *      able to reply in one either. Active membership is required to participate.
 */
add_filter( 'bbp_current_user_can_publish_replies', 'sp_bbpress_gate_publish_replies' );

function sp_bbpress_gate_publish_replies( $can_publish ) {
    if ( ! sp_module_enabled( 'forums' ) || ! class_exists( 'bbPress' ) ) {
        return $can_publish;
    }

    $user_id = get_current_user_id();
    if ( ! $user_id ) {
        return false;
    }

    $member = sp_get_member_by_user_id( $user_id );

    if ( ! $member ) {
        return false;
    }

    if ( $member->status !== 'active' ) {
        return false;
    }

    return $can_publish;
}

/**
 * Sync bbPress role when a member record is saved (admin edit).
 *
 * WHY: bbPress uses its own role system (bbp_participant, bbp_spectator, etc.)
 *      layered on top of WordPress roles. When an admin changes a member's
 *      status in SocietyPress, the bbPress role should reflect that change
 *      automatically. Without this sync, a member could be expired in SP
 *      but still have full posting rights in bbPress.
 *
 *      We hook into the member save redirect (sp-member-edit&saved=1) rather
 *      than a custom action hook because the member save handler doesn't fire
 *      a dedicated do_action yet. The redirect happens only after a successful
 *      save, so we piggyback on admin_init to detect it and sync the role.
 */
add_action( 'admin_init', 'sp_bbpress_sync_role_on_member_save', 20 );

function sp_bbpress_sync_role_on_member_save(): void {
    if ( ! sp_module_enabled( 'forums' ) || ! class_exists( 'bbPress' ) ) {
        return;
    }

    // Only trigger on the redirect after a member save
    // WHY: The member edit handler redirects to sp-member-edit with saved=1
    //      after a successful update. This is the cheapest place to detect
    //      "a member was just saved" without modifying the existing save handler.
    if ( ! isset( $_GET['page'], $_GET['saved'], $_GET['user_id'] ) ) {
        return;
    }
    if ( $_GET['page'] !== 'sp-member-edit' || $_GET['saved'] !== '1' ) {
        return;
    }

    $user_id = absint( $_GET['user_id'] );
    if ( ! $user_id ) {
        return;
    }

    sp_bbpress_set_role_for_member( $user_id );
}

/**
 * Sync bbPress role when the expiration cron auto-expires a member.
 *
 * WHY: sp_process_expired_notices() updates status to 'expired' directly via
 *      $wpdb->update() with no action hook. We hook into the same daily cron
 *      event and re-check all members whose status is expired but who still
 *      have bbp_participant. This is lightweight — we only query members whose
 *      bbPress role is out of sync.
 */
add_action( 'sp_daily_maintenance', 'sp_bbpress_sync_expired_roles' );

function sp_bbpress_sync_expired_roles(): void {
    if ( ! sp_module_enabled( 'forums' ) || ! class_exists( 'bbPress' ) ) {
        return;
    }

    global $wpdb;
    $prefix = $wpdb->prefix . 'sp_';

    // Find members who are NOT active — they should all be spectators
    // WHY: Rather than tracking "who just changed," we do a reconciliation
    //      pass. This catches any status changes that happened via cron,
    //      direct DB edits, imports, or any other path we might miss.
    $non_active = $wpdb->get_col(
        "SELECT user_id FROM {$prefix}members WHERE status != 'active'"
    );

    foreach ( $non_active as $user_id ) {
        $user_id = (int) $user_id;

        // Only downgrade if they currently have a posting role
        // WHY: Don't waste writes on users who are already spectators or
        //      who have no bbPress role at all.
        if ( bbp_is_user_keymaster( $user_id ) ) {
            continue; // Never touch keymasters — they're forum admins
        }

        $current_role = bbp_get_user_role( $user_id );
        if ( $current_role === bbp_get_spectator_role() ) {
            continue; // Already correct
        }
        if ( empty( $current_role ) ) {
            continue; // No bbPress role — they may not use forums
        }

        bbp_set_user_role( $user_id, bbp_get_spectator_role() );
    }

    // Also upgrade active members who are stuck as spectators
    // WHY: A member might renew (status goes back to active) between cron
    //      runs. The admin-save hook catches manual renewals, but this
    //      handles bulk imports, payment webhooks, or other automated paths.
    $active = $wpdb->get_col(
        "SELECT user_id FROM {$prefix}members WHERE status = 'active'"
    );

    foreach ( $active as $user_id ) {
        $user_id = (int) $user_id;

        if ( bbp_is_user_keymaster( $user_id ) ) {
            continue;
        }

        $current_role = bbp_get_user_role( $user_id );

        // Only upgrade spectators — don't touch moderators or keymasters
        if ( $current_role === bbp_get_spectator_role() ) {
            bbp_set_user_role( $user_id, bbp_get_participant_role() );
        }
    }
}

/**
 * Set a single member's bbPress role based on their SP membership status.
 *
 * WHY: Centralizes the status-to-role mapping so both the admin-save hook
 *      and the cron reconciliation can use the same logic. Keymasters (forum
 *      admins) are never touched — their role is managed separately.
 *
 * @param int $user_id WordPress user ID.
 */
function sp_bbpress_set_role_for_member( int $user_id ): void {
    if ( ! function_exists( 'bbp_get_user_role' ) ) {
        return;
    }

    // Never touch keymasters — they administer the forums
    if ( bbp_is_user_keymaster( $user_id ) ) {
        return;
    }

    $member = sp_get_member_by_user_id( $user_id );
    if ( ! $member ) {
        return;
    }

    // Active members get participant (can post); everyone else gets spectator (read-only)
    $desired_role = ( $member->status === 'active' )
        ? bbp_get_participant_role()
        : bbp_get_spectator_role();

    $current_role = bbp_get_user_role( $user_id );

    // Only write if the role actually needs to change
    if ( $current_role !== $desired_role ) {
        bbp_set_user_role( $user_id, $desired_role );
    }
}

/**
 * Auto-add a "Forums" link to the primary navigation menu.
 *
 * WHY: When bbPress is active and the forums module is enabled, members
 *      should see a "Forums" link without Harold having to manually add one
 *      to the nav menu. We use wp_nav_menu_objects — the same filter already
 *      used for Join/Directory/My Account visibility — to inject the link.
 *
 *      The link only appears for logged-in SP members (the people who can
 *      actually use the forums). Non-members don't see it.
 */
add_filter( 'wp_nav_menu_objects', 'sp_bbpress_add_forums_nav_link', 20 );

function sp_bbpress_add_forums_nav_link( array $items ): array {
    if ( ! sp_module_enabled( 'forums' ) || ! class_exists( 'bbPress' ) ) {
        return $items;
    }

    // Only show to logged-in members
    if ( ! is_user_logged_in() ) {
        return $items;
    }
    if ( ! sp_is_member() ) {
        return $items;
    }

    // Get the bbPress forums root URL
    // WHY: bbp_get_forums_url() returns the canonical URL for the forums
    //      archive page. If bbPress isn't configured yet (no forum root page),
    //      this returns empty and we skip the link.
    $forums_url = function_exists( 'bbp_get_forums_url' ) ? bbp_get_forums_url() : '';
    if ( empty( $forums_url ) ) {
        return $items;
    }

    // Don't add if "Forums" is already in the menu (Harold added it manually)
    // WHY: If the admin deliberately placed a Forums link, we don't want to
    //      duplicate it. Check both custom links and page-type items.
    foreach ( $items as $item ) {
        if ( stripos( $item->title, 'forum' ) !== false ) {
            return $items;
        }
        // Also check if the URL matches the forums root
        if ( ! empty( $item->url ) && trailingslashit( $item->url ) === trailingslashit( $forums_url ) ) {
            return $items;
        }
    }

    // Build a fake menu item object
    // WHY: wp_nav_menu_objects expects WP_Post-like objects with specific
    //      properties. We create one that matches the structure WordPress
    //      outputs for real menu items.
    $forums_item = (object) [
        'ID'               => PHP_INT_MAX - 10, // Unique fake ID — won't collide with real items
        'db_id'            => 0,
        'menu_item_parent' => 0,
        'object_id'        => 0,
        'object'           => 'custom',
        'type'             => 'custom',
        'type_label'       => '',
        'title'            => __( 'Forums', 'societypress' ),
        'url'              => $forums_url,
        'target'           => '',
        'attr_title'       => '',
        'description'      => '',
        'classes'           => [ 'menu-item', 'menu-item-type-custom', 'menu-item-forums' ],
        'xfn'              => '',
        'current'          => false,
        'current_item_ancestor' => false,
        'current_item_parent'   => false,
    ];

    // Highlight the nav item when viewing a bbPress page
    if ( function_exists( 'is_bbpress' ) && is_bbpress() ) {
        $forums_item->current    = true;
        $forums_item->classes[]  = 'current-menu-item';
    }

    // Insert before the last item (usually "My Account" or similar)
    // WHY: Appending to the very end could put Forums after the user
    //      dropdown. Inserting second-to-last keeps it in the main nav flow.
    $items_array = array_values( $items );
    $count       = count( $items_array );
    if ( $count > 1 ) {
        array_splice( $items_array, $count - 1, 0, [ $forums_item ] );
        return $items_array;
    }

    $items[] = $forums_item;
    return $items;
}



// ============================================================================
// PROGRESSIVE WEB APP (PWA) LAYER
//
// WHY: Many society members are older adults who access the society website
//      primarily from phones and tablets. PWA support lets them "install" the
//      site to their home screen like a native app, with offline access to
//      previously viewed pages. This is especially useful at events in areas
//      with poor connectivity — rural courthouses, church basements, etc.
//
// COMPONENTS:
//   1. Web App Manifest — served via REST endpoint, tells the browser how to
//      display the "installed" app (name, icons, colors, display mode)
//   2. Service Worker — caches static assets and key pages for offline access,
//      served from site root via rewrite rule for proper scope
//   3. "Add to Home Screen" banner — branded prompt shown to logged-in mobile
//      members, dismissible with localStorage memory
//   4. Push Notification registration — subscription only (no server-side
//      sending yet), stores endpoint in user_meta for future use
//
// ALL gated by the `pwa_enabled` setting. When off, nothing is output — no
// manifest link, no service worker registration, no banners, no push UI.
// ============================================================================


// ---------------------------------------------------------------------------
// 1. WEB APP MANIFEST — REST endpoint
//
// WHY a REST endpoint rather than a static file: The manifest needs dynamic
// values from the database — organization name, theme color, site icon URL.
// A static manifest.json would go stale whenever settings change.
// ---------------------------------------------------------------------------

add_action( 'rest_api_init', function () {
    register_rest_route( 'societypress/v1', '/manifest.json', [
        'methods'             => 'GET',
        'callback'            => 'sp_pwa_manifest',
        'permission_callback' => '__return_true',
    ] );
} );


/**
 * Generate the Web App Manifest JSON.
 *
 * WHY: The manifest tells browsers how to display the "installed" PWA — its
 * name, start URL, theme color, and icons. We pull these from the site's
 * settings so it matches whatever Harold has configured.
 */
function sp_pwa_manifest(): WP_REST_Response {
    $settings  = get_option( 'societypress_settings', [] );
    $site_name = ! empty( $settings['organization_name'] )
        ? $settings['organization_name']
        : get_bloginfo( 'name' );

    // Short name: first 12 chars, used on home screen where space is tight
    $short_name = mb_substr( $site_name, 0, 12 );

    $theme_color = $settings['design_color_primary'] ?? '#1e3a5f';
    $bg_color    = '#ffffff';

    // Icons: prefer the site icon (set via Customizer), then the custom logo,
    // then fall back to a default SP icon bundled with the plugin.
    $icons = sp_pwa_get_icons();

    $manifest = [
        'name'             => $site_name,
        'short_name'       => $short_name,
        'description'      => get_bloginfo( 'description' ),
        'start_url'        => home_url( '/' ),
        'display'          => 'standalone',
        'orientation'      => 'any',
        'theme_color'      => $theme_color,
        'background_color' => $bg_color,
        'icons'            => $icons,
        'scope'            => home_url( '/' ),
    ];

    $response = new WP_REST_Response( $manifest, 200 );
    $response->header( 'Content-Type', 'application/manifest+json' );

    return $response;
}


/**
 * Build the icons array for the PWA manifest.
 *
 * WHY separate function: Icon resolution is non-trivial — we check multiple
 * sources (site icon, custom logo, fallback) and need to provide both the
 * 192x192 and 512x512 sizes that Chrome/Android require for installability.
 */
function sp_pwa_get_icons(): array {
    $icons = [];

    // Priority 1: WordPress Site Icon (set via admin, stored as option)
    // WHY: This is the "official" icon for the site in WP's own model.
    $site_icon_id = get_option( 'site_icon' );
    if ( $site_icon_id ) {
        $icon_192 = wp_get_attachment_image_url( $site_icon_id, [ 192, 192 ] );
        $icon_512 = wp_get_attachment_image_url( $site_icon_id, [ 512, 512 ] );

        if ( $icon_192 ) {
            $icons[] = [
                'src'   => $icon_192,
                'sizes' => '192x192',
                'type'  => 'image/png',
            ];
        }
        if ( $icon_512 ) {
            $icons[] = [
                'src'   => $icon_512,
                'sizes' => '512x512',
                'type'  => 'image/png',
            ];
        }
    }

    // Priority 2: Custom logo (set via SocietyPress Design settings)
    if ( empty( $icons ) ) {
        $custom_logo_id = get_theme_mod( 'custom_logo' );
        if ( $custom_logo_id ) {
            $logo_192 = wp_get_attachment_image_url( $custom_logo_id, [ 192, 192 ] );
            $logo_512 = wp_get_attachment_image_url( $custom_logo_id, [ 512, 512 ] );

            if ( $logo_192 ) {
                $icons[] = [
                    'src'   => $logo_192,
                    'sizes' => '192x192',
                    'type'  => 'image/png',
                ];
            }
            if ( $logo_512 ) {
                $icons[] = [
                    'src'   => $logo_512,
                    'sizes' => '512x512',
                    'type'  => 'image/png',
                ];
            }
        }
    }

    // Priority 3: Default SocietyPress icon bundled with the plugin
    // WHY: A manifest without icons won't pass Chrome's installability check.
    // We ship a generic SP icon so the PWA is always installable, even if
    // Harold hasn't uploaded a logo yet.
    if ( empty( $icons ) ) {
        $plugin_url = plugin_dir_url( SOCIETYPRESS_PLUGIN_FILE );
        $icons[] = [
            'src'   => $plugin_url . 'assets/icon-192.png',
            'sizes' => '192x192',
            'type'  => 'image/png',
        ];
        $icons[] = [
            'src'   => $plugin_url . 'assets/icon-512.png',
            'sizes' => '512x512',
            'type'  => 'image/png',
        ];
    }

    return $icons;
}


// ---------------------------------------------------------------------------
// 2. SERVICE WORKER — served from site root via rewrite rule
//
// WHY root scope matters: Service workers can only control pages at or below
// their own URL path. If the SW file lives at /wp-content/plugins/.../sw.js,
// it can only cache pages under that path — useless. We need it at the site
// root (/) so it controls the entire site. We achieve this by adding a
// rewrite rule that maps /sp-sw.js to a PHP handler that outputs the JS.
// ---------------------------------------------------------------------------

/**
 * Register the rewrite rule that serves the service worker from the site root.
 *
 * WHY: WordPress rewrite rules let us map any URL to a query var handler.
 * /sp-sw.js -> ?sp_service_worker=1 -> our template_redirect handler outputs JS.
 */
add_action( 'init', function () {
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['pwa_enabled'] ) ) {
        return;
    }

    add_rewrite_rule( '^sp-sw\.js$', 'index.php?sp_service_worker=1', 'top' );
} );


/**
 * Register the query var so WordPress recognizes it.
 */
add_filter( 'query_vars', function ( array $vars ): array {
    $vars[] = 'sp_service_worker';
    return $vars;
} );


/**
 * Serve the service worker JavaScript when the query var is present.
 *
 * WHY template_redirect: This fires before WordPress renders any template,
 * letting us short-circuit the normal page load and output raw JS instead.
 * We set the correct Content-Type and Service-Worker-Allowed headers.
 */
add_action( 'template_redirect', function () {
    if ( ! get_query_var( 'sp_service_worker' ) ) {
        return;
    }

    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['pwa_enabled'] ) ) {
        status_header( 404 );
        exit;
    }

    $version         = defined( 'SOCIETYPRESS_VERSION' ) ? SOCIETYPRESS_VERSION : '1.0';
    $cache_name      = 'sp-cache-v' . $version;
    $offline_message = $settings['pwa_offline_message'] ?? __( 'You appear to be offline. Please check your connection.', 'societypress' );
    $site_name       = ! empty( $settings['organization_name'] ) ? $settings['organization_name'] : get_bloginfo( 'name' );
    $theme_color     = $settings['design_color_primary'] ?? '#1e3a5f';

    // Build the list of URLs to pre-cache on install.
    // WHY: These are the pages a member most likely needs offline — the home
    // page, events listing, member directory, library catalog, and their
    // own account page.
    $precache_urls = [
        home_url( '/' ),
    ];

    // Dynamically find the SP template pages to precache
    $template_slugs = [
        'sp-events'    => 'events',
        'sp-directory' => 'directory',
        'sp-library'   => 'library',
        'sp-my-account'=> 'my-account',
    ];

    global $wpdb;
    foreach ( $template_slugs as $template => $fallback_slug ) {
        $page_id = $wpdb->get_var( $wpdb->prepare(
            "SELECT ID FROM {$wpdb->posts}
             WHERE post_type = 'page'
               AND post_status = 'publish'
               AND ID IN (
                   SELECT post_id FROM {$wpdb->postmeta}
                   WHERE meta_key = '_wp_page_template'
                     AND meta_value = %s
               )
             LIMIT 1",
            'page-' . str_replace( 'sp-', '', $template ) . '.php'
        ) );

        if ( $page_id ) {
            $precache_urls[] = get_permalink( $page_id );
        }
    }

    $precache_json = wp_json_encode( array_values( array_unique( $precache_urls ) ) );

    // Escape values for safe embedding inside JS strings
    $js_version         = esc_js( $version );
    $js_cache_name      = esc_js( $cache_name );
    $js_offline_message = esc_js( $offline_message );
    $js_site_name       = esc_js( $site_name );
    $js_theme_color     = esc_js( $theme_color );
    $js_try_again       = esc_js( __( 'Try Again', 'societypress' ) );

    header( 'Content-Type: application/javascript; charset=utf-8' );
    header( 'Service-Worker-Allowed: /' );
    header( 'Cache-Control: no-cache' );

    // Output the service worker JavaScript.
    // WHY inline PHP rather than a static file: The SW needs dynamic values
    // (cache name, precache URLs, offline message, theme color) that come
    // from the database. A static .js file would require a separate build
    // step or server config to inject these values.
    echo "/**\n";
    echo " * SocietyPress Service Worker v{$js_version}\n";
    echo " *\n";
    echo " * Cache strategy:\n";
    echo " *   - Static assets (CSS, JS, fonts, images): cache-first with background refresh\n";
    echo " *   - HTML pages: network-first with cache fallback\n";
    echo " *   - Offline fallback: branded page when network and cache both miss\n";
    echo " */\n\n";

    echo "var CACHE_NAME = '{$js_cache_name}';\n";
    echo "var PRECACHE_URLS = {$precache_json};\n\n";

    echo <<<'SWJS'
/**
 * Install event — pre-cache key pages so they're available offline immediately.
 */
self.addEventListener('install', function(event) {
    event.waitUntil(
        caches.open(CACHE_NAME).then(function(cache) {
            return cache.addAll(PRECACHE_URLS);
        }).then(function() {
            return self.skipWaiting();
        })
    );
});

/**
 * Activate event — clean up old caches from previous plugin versions.
 * WHY: Without cleanup, cache storage grows unbounded with every update.
 */
self.addEventListener('activate', function(event) {
    event.waitUntil(
        caches.keys().then(function(cacheNames) {
            return Promise.all(
                cacheNames.filter(function(name) {
                    return name.startsWith('sp-cache-') && name !== CACHE_NAME;
                }).map(function(name) {
                    return caches.delete(name);
                })
            );
        }).then(function() {
            return self.clients.claim();
        })
    );
});

/**
 * Fetch event — route requests through the appropriate cache strategy.
 */
self.addEventListener('fetch', function(event) {
    var request = event.request;

    /* Only handle GET requests — POST/PUT/DELETE always go to network */
    if (request.method !== 'GET') {
        return;
    }

    /* Skip wp-admin, wp-login, and REST API requests — these should never
       be cached because they contain dynamic, user-specific data. */
    var url = new URL(request.url);
    if (url.pathname.indexOf('/wp-admin') !== -1 ||
        url.pathname.indexOf('/wp-login') !== -1 ||
        url.pathname.indexOf('/wp-json') !== -1) {
        return;
    }

    /* Determine strategy based on resource type */
    var accept   = request.headers.get('Accept') || '';
    var isHTML   = accept.indexOf('text/html') !== -1;
    var isStatic = /\.(css|js|woff2?|ttf|eot|png|jpe?g|gif|svg|webp|ico)$/i.test(url.pathname);

    if (isStatic) {
        /* CACHE-FIRST for static assets — fast loads, falls back to network.
           WHY: CSS, JS, fonts, and images rarely change between page loads.
           Serving from cache eliminates network latency entirely. We also
           update the cache in the background so the next visit gets fresh files. */
        event.respondWith(
            caches.match(request).then(function(cached) {
                if (cached) {
                    /* Stale-while-revalidate: serve cached immediately,
                       fetch fresh copy in background for next time */
                    event.waitUntil(
                        fetch(request).then(function(networkResponse) {
                            if (networkResponse && networkResponse.status === 200) {
                                caches.open(CACHE_NAME).then(function(cache) {
                                    cache.put(request, networkResponse);
                                });
                            }
                        }).catch(function() { /* Network unavailable — stale cache is fine */ })
                    );
                    return cached;
                }
                return fetch(request).then(function(networkResponse) {
                    if (networkResponse && networkResponse.status === 200) {
                        var responseToCache = networkResponse.clone();
                        caches.open(CACHE_NAME).then(function(cache) {
                            cache.put(request, responseToCache);
                        });
                    }
                    return networkResponse;
                });
            })
        );
    } else if (isHTML) {
        /* NETWORK-FIRST for HTML pages — always try to get fresh content,
           fall back to cached version, last resort is the offline page.
           WHY: HTML pages contain dynamic data (event dates, member info)
           that should be current. But a stale page is better than nothing
           when the member is in a church basement with no signal. */
        event.respondWith(
            fetch(request).then(function(networkResponse) {
                if (networkResponse && networkResponse.status === 200) {
                    var responseToCache = networkResponse.clone();
                    caches.open(CACHE_NAME).then(function(cache) {
                        cache.put(request, responseToCache);
                    });
                }
                return networkResponse;
            }).catch(function() {
                return caches.match(request).then(function(cached) {
                    if (cached) {
                        return cached;
                    }
                    /* No cached version — serve the offline fallback page */
                    return new Response(sp_offline_page(), {
                        headers: { 'Content-Type': 'text/html; charset=utf-8' }
                    });
                });
            })
        );
    }
});

SWJS;

    // Push notification event handler — only output if push is enabled.
    // WHY conditional: If push is disabled, there's no reason to register
    // the push event listener in the service worker. Keeping it out reduces
    // the SW size and avoids confusing debug output in DevTools.
    if ( ! empty( $settings['push_enabled'] ) ) {
        echo <<<'PUSHJS'

/**
 * Push event — show a notification when the server sends one.
 *
 * WHY self.registration.showNotification: This is the Web Push API's standard
 * method for displaying a notification from a service worker. The notification
 * payload is a JSON object with title, body, icon, and optional url fields.
 * We parse the payload and display it, falling back to sensible defaults if
 * any field is missing.
 */
self.addEventListener('push', function(event) {
    var data = {};
    if (event.data) {
        try {
            data = event.data.json();
        } catch (e) {
            /* If the payload isn't valid JSON, use the raw text as the body.
               WHY: Some push implementations send plain text instead of JSON.
               We handle both gracefully rather than silently swallowing the
               notification. */
            data = { title: 'Notification', body: event.data.text() };
        }
    }

    var title   = data.title || 'New Update';
    var options = {
        body: data.body || '',
        icon: data.icon || '/wp-content/plugins/societypress/assets/icon-192.png',
        badge: data.badge || '/wp-content/plugins/societypress/assets/icon-192.png',
        data: { url: data.url || '/' }
    };

    event.waitUntil(
        self.registration.showNotification(title, options)
    );
});

/**
 * Notification click handler — open the associated URL when the member taps
 * the notification.
 *
 * WHY: Without this handler, tapping a notification does nothing. We close the
 * notification and either focus an existing tab or open a new one at the URL
 * specified in the push payload's data.url field.
 */
self.addEventListener('notificationclick', function(event) {
    event.notification.close();

    var targetUrl = event.notification.data && event.notification.data.url
        ? event.notification.data.url
        : '/';

    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then(function(clientList) {
            /* If the site is already open in a tab, focus it and navigate */
            for (var i = 0; i < clientList.length; i++) {
                var client = clientList[i];
                if ('focus' in client) {
                    client.focus();
                    if (client.url !== targetUrl && 'navigate' in client) {
                        return client.navigate(targetUrl);
                    }
                    return client;
                }
            }
            /* No existing tab — open a new one */
            if (clients.openWindow) {
                return clients.openWindow(targetUrl);
            }
        })
    );
});

PUSHJS;
    }

    // The offline page function contains dynamic values so it's output with PHP
    echo "/**\n";
    echo " * Generate a branded offline fallback page.\n";
    echo " *\n";
    echo " * WHY a function rather than a pre-cached HTML file: The offline message\n";
    echo " * and branding come from the database. Generating inline ensures the page\n";
    echo " * always reflects the current site name and theme color.\n";
    echo " */\n";
    echo "function sp_offline_page() {\n";
    echo "    return '<!DOCTYPE html>'\n";
    echo "        + '<html lang=\"en\"><head><meta charset=\"utf-8\">'\n";
    echo "        + '<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">'\n";
    echo "        + '<title>{$js_site_name}</title>'\n";
    echo "        + '<style>'\n";
    echo "        + 'body{font-family:-apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,Oxygen,Ubuntu,sans-serif;'\n";
    echo "        + 'display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;'\n";
    echo "        + 'background:#f5f5f5;color:#333;text-align:center;padding:20px}'\n";
    echo "        + '.sp-offline{max-width:480px}'\n";
    echo "        + '.sp-offline-icon{font-size:64px;margin-bottom:20px}'\n";
    echo "        + '.sp-offline h1{font-size:22px;color:{$js_theme_color};margin:0 0 16px}'\n";
    echo "        + '.sp-offline p{font-size:16px;line-height:1.5;color:#666;margin:0 0 24px}'\n";
    echo "        + '.sp-offline button{background:{$js_theme_color};color:#fff;border:none;'\n";
    echo "        + 'padding:12px 24px;border-radius:6px;font-size:15px;cursor:pointer}'\n";
    echo "        + '.sp-offline button:hover{opacity:.9}'\n";
    echo "        + '</style></head><body>'\n";
    echo "        + '<div class=\"sp-offline\">'\n";
    echo "        + '<div class=\"sp-offline-icon\">&#128268;</div>'\n";
    echo "        + '<h1>{$js_site_name}</h1>'\n";
    echo "        + '<p>{$js_offline_message}</p>'\n";
    echo "        + '<button onclick=\"window.location.reload()\">{$js_try_again}</button>'\n";
    echo "        + '</div></body></html>';\n";
    echo "}\n";

    exit;
} );


// ---------------------------------------------------------------------------
// 3. MANIFEST LINK + SERVICE WORKER REGISTRATION — wp_head / wp_footer
//
// WHY: The manifest <link> must be in <head> for browsers to discover the PWA.
// The service worker registration runs in <footer> after the page loads so
// it doesn't block rendering.
// ---------------------------------------------------------------------------

/**
 * Output the manifest link tag and PWA meta tags in <head>.
 *
 * WHY: Without the <link rel="manifest">, no browser will recognize the site
 * as a PWA. The theme-color meta tag matches the manifest and colors the
 * mobile browser chrome (address bar) on Android.
 */
add_action( 'wp_head', function () {
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['pwa_enabled'] ) ) {
        return;
    }

    $manifest_url = rest_url( 'societypress/v1/manifest.json' );
    $theme_color  = esc_attr( $settings['design_color_primary'] ?? '#1e3a5f' );
    ?>
    <!-- SocietyPress PWA -->
    <link rel="manifest" href="<?php echo esc_url( $manifest_url ); ?>">
    <meta name="theme-color" content="<?php echo $theme_color; ?>">
    <!-- iOS PWA support — Safari doesn't fully read the manifest for these -->
    <meta name="apple-mobile-web-app-capable" content="yes">
    <meta name="apple-mobile-web-app-status-bar-style" content="default">
    <meta name="apple-mobile-web-app-title" content="<?php echo esc_attr( ! empty( $settings['organization_name'] ) ? $settings['organization_name'] : get_bloginfo( 'name' ) ); ?>">
    <?php
    // Apple touch icon — same priority chain as the manifest icons
    $site_icon_id = get_option( 'site_icon' );
    $touch_icon   = '';
    if ( $site_icon_id ) {
        $touch_icon = wp_get_attachment_image_url( $site_icon_id, [ 180, 180 ] );
    }
    if ( ! $touch_icon ) {
        $custom_logo_id = get_theme_mod( 'custom_logo' );
        if ( $custom_logo_id ) {
            $touch_icon = wp_get_attachment_image_url( $custom_logo_id, [ 180, 180 ] );
        }
    }
    if ( ! $touch_icon ) {
        $touch_icon = plugin_dir_url( SOCIETYPRESS_PLUGIN_FILE ) . 'assets/icon-192.png';
    }
    ?>
    <link rel="apple-touch-icon" href="<?php echo esc_url( $touch_icon ); ?>">
    <?php
}, 1 );


/**
 * Register the service worker and output the "Add to Home Screen" banner
 * from wp_footer. Also handles the install prompt interception.
 *
 * WHY wp_footer: Service worker registration should happen after the page
 * content loads — it's a background enhancement, not a blocking resource.
 * The install banner is also injected here so it appears at the bottom
 * of the viewport.
 */
add_action( 'wp_footer', function () {
    $settings = get_option( 'societypress_settings', [] );
    if ( empty( $settings['pwa_enabled'] ) ) {
        return;
    }

    $org_name    = ! empty( $settings['organization_name'] ) ? $settings['organization_name'] : get_bloginfo( 'name' );
    $theme_color = esc_attr( $settings['design_color_primary'] ?? '#1e3a5f' );

    // Only show the install banner to logged-in members on the frontend
    $show_banner = is_user_logged_in() && ! is_admin();
    $banner_text = esc_js( sprintf(
        /* translators: %s: organization name */
        __( 'Add %s to your home screen for quick access', 'societypress' ),
        $org_name
    ) );
    $install_label  = esc_js( __( 'Install', 'societypress' ) );
    $dismiss_label  = esc_js( __( 'Not now', 'societypress' ) );
    $sw_url         = esc_url( home_url( '/sp-sw.js' ) );
    $show_banner_js = $show_banner ? 'true' : 'false';
    ?>
    <!-- SocietyPress PWA: Install Banner -->
    <div id="sp-pwa-banner" style="display:none;" role="alert">
        <div class="sp-pwa-banner-inner">
            <p class="sp-pwa-banner-text" id="sp-pwa-banner-text"></p>
            <div class="sp-pwa-banner-actions">
                <button type="button" id="sp-pwa-install" class="sp-pwa-btn sp-pwa-btn--install"></button>
                <button type="button" id="sp-pwa-dismiss" class="sp-pwa-btn sp-pwa-btn--dismiss"></button>
            </div>
        </div>
    </div>
    <style>
        /* PWA Install Banner — fixed to bottom of viewport on mobile only.
           WHY fixed positioning: The banner needs to be visible regardless of
           scroll position. On desktop it stays hidden entirely (members on
           desktop don't benefit from "installing" a website). */
        #sp-pwa-banner {
            position: fixed;
            bottom: 0;
            left: 0;
            right: 0;
            z-index: 99998;
            background: #fff;
            border-top: 3px solid <?php echo $theme_color; ?>;
            box-shadow: 0 -4px 20px rgba(0, 0, 0, 0.15);
            padding: 16px 20px;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
        }
        .sp-pwa-banner-inner {
            max-width: 600px;
            margin: 0 auto;
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 12px;
        }
        .sp-pwa-banner-text {
            margin: 0;
            font-size: 14px;
            color: #333;
            line-height: 1.4;
            flex: 1;
        }
        .sp-pwa-banner-actions {
            display: flex;
            gap: 8px;
            flex-shrink: 0;
        }
        .sp-pwa-btn {
            border: none;
            border-radius: 6px;
            padding: 8px 16px;
            font-size: 13px;
            font-weight: 600;
            cursor: pointer;
            white-space: nowrap;
        }
        .sp-pwa-btn--install {
            background: <?php echo $theme_color; ?>;
            color: #fff;
        }
        .sp-pwa-btn--install:hover {
            opacity: 0.9;
        }
        .sp-pwa-btn--dismiss {
            background: transparent;
            color: #666;
            padding: 8px 12px;
        }
        .sp-pwa-btn--dismiss:hover {
            color: #333;
            background: #f0f0f0;
        }
        /* Hide banner entirely on desktop — only useful on mobile (< 768px) */
        @media (min-width: 768px) {
            #sp-pwa-banner { display: none !important; }
        }
    </style>
    <script>
    (function() {
        'use strict';

        /* ---- Service Worker Registration ----
           WHY: This is the core of PWA functionality. Without a registered
           service worker, there's no offline support and no install prompt. */
        if ('serviceWorker' in navigator) {
            window.addEventListener('load', function() {
                navigator.serviceWorker.register('<?php echo $sw_url; ?>', { scope: '/' })
                    .then(function(reg) {
                        /* Check for service worker updates every hour.
                           WHY: When we bump SOCIETYPRESS_VERSION, the service worker
                           file changes and the browser picks up the new version.
                           Without periodic checks, users might stay on stale caches
                           until they manually hard-refresh. */
                        setInterval(function() { reg.update(); }, 60 * 60 * 1000);
                    })
                    .catch(function() {
                        /* Silent fail — PWA is an enhancement, not a requirement.
                           If registration fails (e.g., no HTTPS on local dev),
                           the site works normally without offline support. */
                    });
            });
        }

        /* ---- "Add to Home Screen" Banner ----
           WHY: Most users don't know they can install a website as an app.
           The banner educates them and makes it one tap. We intercept Chrome's
           beforeinstallprompt event to control when and how the prompt appears. */
        var showBanner = <?php echo $show_banner_js; ?>;
        var deferredPrompt = null;

        if (showBanner && !localStorage.getItem('sp_pwa_dismissed')) {
            window.addEventListener('beforeinstallprompt', function(e) {
                /* Prevent the browser's default mini-infobar */
                e.preventDefault();
                deferredPrompt = e;

                var banner    = document.getElementById('sp-pwa-banner');
                var textEl    = document.getElementById('sp-pwa-banner-text');
                var installEl = document.getElementById('sp-pwa-install');
                var dismissEl = document.getElementById('sp-pwa-dismiss');

                if (!banner || !textEl || !installEl || !dismissEl) return;

                textEl.textContent    = '<?php echo $banner_text; ?>';
                installEl.textContent = '<?php echo $install_label; ?>';
                dismissEl.textContent = '<?php echo $dismiss_label; ?>';

                /* Only show on mobile viewports — CSS also hides it above 768px,
                   but this JS check prevents a brief flash before CSS applies */
                if (window.innerWidth < 768) {
                    banner.style.display = 'block';
                }

                installEl.addEventListener('click', function() {
                    if (!deferredPrompt) return;
                    deferredPrompt.prompt();
                    deferredPrompt.userChoice.then(function(result) {
                        deferredPrompt = null;
                        banner.style.display = 'none';
                        if (result.outcome === 'accepted') {
                            /* Remember installation so we never show the banner
                               again on this device */
                            localStorage.setItem('sp_pwa_installed', '1');
                        }
                    });
                });

                dismissEl.addEventListener('click', function() {
                    banner.style.display = 'none';
                    /* Remember dismissal so we don't nag on every page load.
                       WHY localStorage over cookies: No server round-trip needed,
                       persists across sessions, and this is purely a UI preference. */
                    localStorage.setItem('sp_pwa_dismissed', '1');
                });
            });
        }
    })();
    </script>
    <?php
}, 99 );


// ---------------------------------------------------------------------------
// 4. PUSH NOTIFICATION SUBSCRIPTION & SENDING
//
// WHY: Push notifications let societies send time-sensitive updates directly
// to members' devices — new event announcements, meeting reminders, dues
// renewal nudges. Unlike email, push appears instantly on the lock screen
// and doesn't get lost in spam folders.
//
// ARCHITECTURE:
//   - VAPID key pair auto-generates on first settings page access
//   - Subscriptions stored in sp_push_subscriptions table (not user_meta)
//     so we can support non-logged-in visitors and multiple devices per user
//   - REST API endpoint for subscription management (replaces old AJAX handler)
//   - sp_send_push_notification() helper iterates all subscriptions and sends
//     via wp_remote_post() using the Web Push protocol with VAPID JWT auth
//   - Frontend JS requests permission, subscribes via service worker, and
//     POSTs the subscription to the REST endpoint
//
// GATED by both pwa_enabled AND push_enabled settings.
// ---------------------------------------------------------------------------

/**
 * Auto-generate VAPID key pair on first access if not already set.
 *
 * WHY: VAPID (Voluntary Application Server Identification) is required by the
 * Web Push protocol. The public key is shared with the browser during
 * subscription; the private key signs the JWT auth header when sending.
 * Generating automatically means Harold never has to deal with key pairs —
 * it "just works" when he enables push notifications.
 *
 * WHY admin_init: We need this to run before the settings page renders so
 * the VAPID public key is available for the frontend JS. admin_init fires
 * early enough on every admin page load.
 */
add_action( 'admin_init', function () {
    $settings = get_option( 'societypress_settings', [] );

    // Only generate if push is enabled and keys are missing
    if ( empty( $settings['push_enabled'] ) ) {
        return;
    }

    if ( ! empty( $settings['push_vapid_public'] ) && ! empty( $settings['push_vapid_secret'] ) ) {
        return;
    }

    // Generate VAPID key pair using openssl
    // WHY openssl: PHP's openssl extension is available on virtually all shared
    // hosting (including Skystra). We generate a P-256 EC key pair which is the
    // only curve supported by the Web Push standard.
    if ( ! function_exists( 'openssl_pkey_new' ) ) {
        return; // Can't generate keys without openssl — Harold will need to install it
    }

    $key = openssl_pkey_new( [
        'curve_name'       => 'prime256v1',
        'private_key_type' => OPENSSL_KEYTYPE_EC,
    ] );

    if ( ! $key ) {
        return;
    }

    $details = openssl_pkey_get_details( $key );
    if ( ! $details || empty( $details['ec']['x'] ) || empty( $details['ec']['y'] ) || empty( $details['ec']['d'] ) ) {
        return;
    }

    // The VAPID public key is the uncompressed point (0x04 || x || y) base64url-encoded
    // WHY uncompressed format: The Web Push spec requires the public key in
    // uncompressed EC point format. The 0x04 prefix byte indicates uncompressed.
    $public_key_bytes = "\x04" . $details['ec']['x'] . $details['ec']['y'];
    $vapid_public     = rtrim( strtr( base64_encode( $public_key_bytes ), '+/', '-_' ), '=' );

    // The private key is just the d parameter base64url-encoded
    $vapid_private = rtrim( strtr( base64_encode( $details['ec']['d'] ), '+/', '-_' ), '=' );

    $settings['push_vapid_public'] = $vapid_public;
    $settings['push_vapid_secret'] = sp_encrypt( $vapid_private );
    update_option( 'societypress_settings', $settings );
} );


/**
 * Register REST API endpoint for push subscriptions.
 *
 * WHY REST instead of AJAX: The subscription JS runs in the frontend context
 * (not wp-admin) and may run for non-logged-in visitors in the future. REST
 * endpoints are the modern WordPress way to handle this, and they work
 * without requiring the ajaxurl global.
 */
add_action( 'rest_api_init', function () {
    register_rest_route( 'societypress/v1', '/push/subscribe', [
        'methods'             => 'POST',
        'callback'            => 'sp_rest_push_subscribe',
        'permission_callback' => '__return_true', // Public endpoint — anyone can subscribe
    ] );
} );


/**
 * REST handler: /wp-json/societypress/v1/push/subscribe
 *
 * Accepts a push subscription object from the browser and stores it in the
 * sp_push_subscriptions table. If the same endpoint already exists, we update
 * rather than duplicate — a browser's subscription endpoint is unique per
 * device/browser combination.
 *
 * @param WP_REST_Request $request The incoming subscription request.
 * @return WP_REST_Response
 */
function sp_rest_push_subscribe( WP_REST_Request $request ): WP_REST_Response {
    $settings = get_option( 'societypress_settings', [] );

    // Gate: push must be enabled
    if ( empty( $settings['push_enabled'] ) || empty( $settings['pwa_enabled'] ) ) {
        return new WP_REST_Response(
            [ 'success' => false, 'message' => __( 'Push notifications are not enabled.', 'societypress' ) ],
            403
        );
    }

    // Verify nonce from the X-WP-Nonce header (WordPress REST API convention)
    // WHY: Even though this is a public endpoint, we verify a nonce when available
    // to prevent CSRF attacks from malicious pages subscribing random endpoints.
    // Non-logged-in requests without a nonce are still accepted (the subscription
    // itself is harmless — the endpoint URL is browser-generated and can only
    // receive notifications signed with our VAPID key).

    // WHY: Rate limit to prevent database flooding — an attacker could POST
    //      millions of fake subscriptions with rotating endpoint URLs. 10 per
    //      hour per IP is generous for legitimate use (one browser = one sub).
    $ip_hash = 'sp_push_rl_' . md5( $_SERVER['REMOTE_ADDR'] ?? '' );
    $hits    = (int) get_transient( $ip_hash );
    if ( $hits >= 10 ) {
        return new WP_REST_Response(
            [ 'success' => false, 'message' => __( 'Rate limit exceeded. Try again later.', 'societypress' ) ],
            429
        );
    }
    set_transient( $ip_hash, $hits + 1, HOUR_IN_SECONDS );

    $body = $request->get_json_params();

    $endpoint = esc_url_raw( $body['endpoint'] ?? '' );
    // WHY: sanitize_text_field strips characters that corrupt base64 keys.
    //      These are opaque binary-safe tokens — just ensure they're strings.
    $p256dh   = substr( preg_replace( '/[^A-Za-z0-9_\-=+\/]/', '', $body['keys']['p256dh'] ?? '' ), 0, 255 );
    $auth     = substr( preg_replace( '/[^A-Za-z0-9_\-=+\/]/', '', $body['keys']['auth'] ?? '' ), 0, 255 );

    if ( empty( $endpoint ) || empty( $p256dh ) || empty( $auth ) ) {
        return new WP_REST_Response(
            [ 'success' => false, 'message' => __( 'Invalid subscription data. Endpoint, p256dh, and auth are required.', 'societypress' ) ],
            400
        );
    }

    // Validate the endpoint is a proper push service URL
    // WHY: Prevent abuse — only accept URLs from known push services (Google FCM,
    // Mozilla, Apple, Microsoft, etc.). All legitimate push endpoints use HTTPS.
    if ( strpos( $endpoint, 'https://' ) !== 0 ) {
        return new WP_REST_Response(
            [ 'success' => false, 'message' => __( 'Push endpoint must use HTTPS.', 'societypress' ) ],
            400
        );
    }

    global $wpdb;
    $table   = $wpdb->prefix . 'sp_push_subscriptions';
    $user_id = get_current_user_id() ?: null;

    // Check if this endpoint already exists — update instead of duplicate
    // WHY: A browser can re-subscribe (e.g., after clearing notifications or
    // re-enabling permissions). The endpoint URL is unique per subscription,
    // so we use it as the dedup key.
    $existing_id = $wpdb->get_var( $wpdb->prepare(
        "SELECT id FROM {$table} WHERE endpoint = %s LIMIT 1",
        $endpoint
    ) );

    if ( $existing_id ) {
        $wpdb->update(
            $table,
            [
                'user_id' => $user_id,
                'p256dh'  => $p256dh,
                'auth'    => $auth,
            ],
            [ 'id' => $existing_id ],
            [ '%d', '%s', '%s' ],
            [ '%d' ]
        );
    } else {
        $wpdb->insert(
            $table,
            [
                'user_id'  => $user_id,
                'endpoint' => $endpoint,
                'p256dh'   => $p256dh,
                'auth'     => $auth,
            ],
            [ '%d', '%s', '%s', '%s' ]
        );
    }

    return new WP_REST_Response(
        [ 'success' => true, 'message' => __( 'Push subscription saved.', 'societypress' ) ],
        200
    );
}


/**
 * AJAX handler: save a push notification subscription to user_meta.
 *
 * WHY keep the AJAX handler alongside the REST endpoint: The My Account page
 * still uses the AJAX approach for the subscribe/unsubscribe toggle. The REST
 * endpoint is for the frontend service worker flow. Both coexist — the REST
 * endpoint stores in the database table, the AJAX handler stores in user_meta.
 * The sp_send_push_notification() helper checks both sources.
 */
add_action( 'wp_ajax_sp_push_subscribe', function () {
    check_ajax_referer( 'sp_push_subscribe', 'nonce' );

    $user_id = get_current_user_id();
    if ( ! $user_id ) {
        wp_send_json_error( [ 'message' => __( 'Not logged in.', 'societypress' ) ] );
    }

    $subscription = isset( $_POST['subscription'] ) ? sanitize_text_field( wp_unslash( $_POST['subscription'] ) ) : '';
    if ( empty( $subscription ) ) {
        wp_send_json_error( [ 'message' => __( 'No subscription data received.', 'societypress' ) ] );
    }

    // Validate that the subscription is valid JSON with the required endpoint field
    $sub_data = json_decode( $subscription, true );
    if ( ! $sub_data || empty( $sub_data['endpoint'] ) ) {
        wp_send_json_error( [ 'message' => __( 'Invalid subscription data.', 'societypress' ) ] );
    }

    update_user_meta( $user_id, 'sp_push_subscription', $subscription );
    wp_send_json_success( [ 'message' => __( 'Push notifications enabled.', 'societypress' ) ] );
} );


/**
 * AJAX handler: remove a push notification subscription from user_meta.
 *
 * WHY separate unsubscribe action: We can't just set the meta to empty —
 * delete_user_meta is cleaner and makes the "how many members have push
 * enabled" dashboard query accurate (we count rows, not non-empty values).
 */
add_action( 'wp_ajax_sp_push_unsubscribe', function () {
    check_ajax_referer( 'sp_push_subscribe', 'nonce' );

    $user_id = get_current_user_id();
    if ( ! $user_id ) {
        wp_send_json_error( [ 'message' => __( 'Not logged in.', 'societypress' ) ] );
    }

    delete_user_meta( $user_id, 'sp_push_subscription' );
    wp_send_json_success( [ 'message' => __( 'Push notifications disabled.', 'societypress' ) ] );
} );


/**
 * Get the count of members who have push notifications enabled.
 *
 * WHY: Counts from both the database table (REST subscriptions) and user_meta
 * (AJAX subscriptions) for a complete picture. Used on the admin dashboard
 * stat card and in the settings page.
 */
function sp_pwa_push_subscriber_count(): int {
    global $wpdb;

    // Count from the push_subscriptions table
    $table       = $wpdb->prefix . 'sp_push_subscriptions';
    $table_count = 0;

    // Check if the table exists before querying — it might not on older installs
    // that haven't run sp_create_tables() since the table was added.
    $table_exists = $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = %s AND table_name = %s",
        DB_NAME,
        $table
    ) );

    if ( $table_exists ) {
        $table_count = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$table}" );
    }

    // Also count from user_meta (legacy AJAX subscriptions)
    $meta_count = (int) $wpdb->get_var(
        "SELECT COUNT(DISTINCT user_id) FROM {$wpdb->usermeta}
         WHERE meta_key = 'sp_push_subscription'
           AND meta_value != ''"
    );

    // Return the higher of the two to avoid double-counting
    // WHY max instead of sum: Some users may have both a table row and a meta
    // entry if they subscribed via both methods. Max gives a conservative count.
    return max( $table_count, $meta_count );
}


/**
 * Send a push notification to all subscribers.
 *
 * WHY: This is the server-side push sending mechanism. It iterates all
 * subscriptions from the sp_push_subscriptions table and sends a notification
 * to each one using the Web Push protocol with VAPID authentication.
 *
 * The Web Push protocol works by:
 *   1. Building a VAPID JWT signed with our private key
 *   2. Encrypting the notification payload using the subscriber's public key
 *   3. POSTing to the push service endpoint with the encrypted payload
 *
 * For simplicity, we send the payload unencrypted (Content-Encoding: identity).
 * The notification payload is not sensitive (title + body), and HTTPS protects
 * it in transit to the push service. When a proper web-push library is added,
 * this can be upgraded to encrypted payloads (aes128gcm).
 *
 * @param string $title The notification title.
 * @param string $body  The notification body text.
 * @param string $url   Optional URL to open when the notification is clicked.
 * @return int The number of successful sends.
 */
function sp_send_push_notification( string $title, string $body, string $url = '' ): int {
    $settings = get_option( 'societypress_settings', [] );

    if ( empty( $settings['push_enabled'] ) || empty( $settings['pwa_enabled'] ) ) {
        return 0;
    }

    $vapid_public  = $settings['push_vapid_public'] ?? '';
    $vapid_private = sp_decrypt( $settings['push_vapid_secret'] ?? '' );

    if ( empty( $vapid_public ) || empty( $vapid_private ) ) {
        return 0;
    }

    global $wpdb;
    $table = $wpdb->prefix . 'sp_push_subscriptions';

    // Check if the table exists
    $table_exists = $wpdb->get_var( $wpdb->prepare(
        "SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = %s AND table_name = %s",
        DB_NAME,
        $table
    ) );

    if ( ! $table_exists ) {
        return 0;
    }

    $subscriptions = $wpdb->get_results( "SELECT id, endpoint, p256dh, auth FROM {$table}" );

    if ( empty( $subscriptions ) ) {
        return 0;
    }

    // Build the notification payload
    $payload = wp_json_encode( [
        'title' => $title,
        'body'  => $body,
        'url'   => $url ?: home_url( '/' ),
        'icon'  => plugin_dir_url( SOCIETYPRESS_PLUGIN_FILE ) . 'assets/icon-192.png',
    ] );

    $success_count   = 0;
    $expired_ids     = [];
    $site_url_parsed = wp_parse_url( home_url() );
    $audience        = $site_url_parsed['scheme'] . '://' . $site_url_parsed['host'];

    // Build VAPID JWT for authorization
    // WHY: The push service needs to verify that we're the legitimate sender.
    // VAPID uses a JWT signed with our private key. The push service validates
    // it against our public key (which was provided during subscription).
    $jwt_token = sp_push_build_vapid_jwt( $vapid_public, $vapid_private, $audience );

    if ( ! $jwt_token ) {
        return 0;
    }

    foreach ( $subscriptions as $sub ) {
        $response = wp_remote_post( $sub->endpoint, [
            'headers' => [
                'Content-Type'     => 'application/json',
                'TTL'              => '86400', // 24 hours — if the device is offline, retry for a day
                'Authorization'    => 'vapid t=' . $jwt_token . ', k=' . $vapid_public,
                'Content-Encoding' => 'identity', // Unencrypted payload (see function docblock)
            ],
            'body'    => $payload,
            'timeout' => 10,
        ] );

        $status_code = wp_remote_retrieve_response_code( $response );

        if ( $status_code === 201 || $status_code === 200 ) {
            $success_count++;
        } elseif ( $status_code === 410 || $status_code === 404 ) {
            // 410 Gone or 404 Not Found — the subscription has expired or been
            // revoked by the user. Clean it up so we don't waste requests.
            $expired_ids[] = $sub->id;
        }
        // Other errors (429 rate limit, 500 server error) are transient —
        // we leave the subscription in place for retry on the next send.
    }

    // Clean up expired/revoked subscriptions in bulk
    if ( ! empty( $expired_ids ) ) {
        $placeholders = implode( ',', array_fill( 0, count( $expired_ids ), '%d' ) );
        $wpdb->query( $wpdb->prepare(
            "DELETE FROM {$table} WHERE id IN ({$placeholders})",
            ...$expired_ids
        ) );
    }

    return $success_count;
}


/**
 * Build a VAPID JWT for Web Push authentication.
 *
 * WHY: The Web Push protocol requires a VAPID JWT in the Authorization header.
 * This JWT proves to the push service (Google FCM, Mozilla autopush, etc.)
 * that we own the VAPID key pair that the subscriber subscribed with.
 *
 * @param string $vapid_public  Base64url-encoded VAPID public key.
 * @param string $vapid_private Base64url-encoded VAPID private key (the 'd' parameter).
 * @param string $audience      The origin of the push service (e.g., "https://fcm.googleapis.com").
 * @return string|false The signed JWT, or false on failure.
 */
function sp_push_build_vapid_jwt( string $vapid_public, string $vapid_private, string $audience ): string|false {
    if ( ! function_exists( 'openssl_sign' ) ) {
        return false;
    }

    // JWT Header
    $header = wp_json_encode( [ 'typ' => 'JWT', 'alg' => 'ES256' ] );

    // JWT Payload — sub is a mailto: URI identifying the sender, aud is the
    // push service origin, exp is 24 hours from now (max allowed by spec).
    $settings    = get_option( 'societypress_settings', [] );
    $admin_email = $settings['organization_email'] ?? get_option( 'admin_email', '' );

    $payload = wp_json_encode( [
        'aud' => $audience,
        'exp' => time() + 86400,
        'sub' => 'mailto:' . $admin_email,
    ] );

    $b64_header  = rtrim( strtr( base64_encode( $header ), '+/', '-_' ), '=' );
    $b64_payload = rtrim( strtr( base64_encode( $payload ), '+/', '-_' ), '=' );

    $signing_input = "{$b64_header}.{$b64_payload}";

    // Reconstruct the PEM private key from the base64url-encoded 'd' parameter
    // WHY: openssl_sign needs a PEM-formatted key. We have the raw 'd' parameter
    // stored base64url-encoded. We need to build the full EC private key in
    // DER format and wrap it in PEM headers.
    $d_bytes = base64_decode( strtr( $vapid_private, '-_', '+/' ) );

    // Also need the public key coordinates to build the full key
    $pub_bytes = base64_decode( strtr( $vapid_public, '-_', '+/' ) );

    if ( strlen( $d_bytes ) !== 32 || strlen( $pub_bytes ) !== 65 ) {
        return false;
    }

    // Build DER-encoded EC private key
    // WHY manual DER construction: PHP's openssl doesn't have a convenient
    // function to import raw EC key parameters. We build the ASN.1 DER
    // structure manually: SEQUENCE { version, privateKey, parameters, publicKey }
    $der = "\x30\x77"                                    // SEQUENCE (119 bytes)
         . "\x02\x01\x01"                                // INTEGER 1 (version)
         . "\x04\x20" . $d_bytes                         // OCTET STRING (32 bytes, private key)
         . "\xa0\x0a"                                    // [0] EXPLICIT (10 bytes)
         . "\x06\x08\x2a\x86\x48\xce\x3d\x03\x01\x07"  // OID prime256v1
         . "\xa1\x44"                                    // [1] EXPLICIT (68 bytes)
         . "\x03\x42\x00" . $pub_bytes;                  // BIT STRING (66 bytes, public key)

    $pem = "-----BEGIN EC PRIVATE KEY-----\n"
         . chunk_split( base64_encode( $der ), 64, "\n" )
         . "-----END EC PRIVATE KEY-----\n";

    $private_key = openssl_pkey_get_private( $pem );
    if ( ! $private_key ) {
        return false;
    }

    $signature = '';
    if ( ! openssl_sign( $signing_input, $signature, $private_key, OPENSSL_ALGO_SHA256 ) ) {
        return false;
    }

    // Convert the DER-encoded ECDSA signature to raw R||S format (64 bytes)
    // WHY: JWT ES256 expects the signature as raw 32-byte R + 32-byte S concatenated.
    // OpenSSL returns DER-encoded which wraps R and S in ASN.1 INTEGER tags.
    $r_and_s = sp_push_der_to_raw_ecdsa( $signature );
    if ( ! $r_and_s ) {
        return false;
    }

    $b64_signature = rtrim( strtr( base64_encode( $r_and_s ), '+/', '-_' ), '=' );

    return "{$b64_header}.{$b64_payload}.{$b64_signature}";
}


/**
 * Convert a DER-encoded ECDSA signature to raw R||S format.
 *
 * WHY: OpenSSL's openssl_sign() returns signatures in ASN.1 DER format, but
 * JWT ES256 expects raw concatenated R and S values (each 32 bytes, zero-padded).
 * This function parses the DER structure and extracts the raw values.
 *
 * @param string $der_sig The DER-encoded ECDSA signature.
 * @return string|false 64-byte raw signature (R||S), or false on failure.
 */
function sp_push_der_to_raw_ecdsa( string $der_sig ): string|false {
    $pos = 0;
    $len = strlen( $der_sig );

    // Expect SEQUENCE tag (0x30)
    if ( $pos >= $len || ord( $der_sig[ $pos ] ) !== 0x30 ) {
        return false;
    }
    $pos++;

    // Skip the sequence length byte(s)
    if ( $pos >= $len ) {
        return false;
    }
    $seq_len = ord( $der_sig[ $pos ] );
    $pos++;
    if ( $seq_len & 0x80 ) {
        // Long form length — skip the extra bytes
        $num_len_bytes = $seq_len & 0x7F;
        $pos += $num_len_bytes;
    }

    // Extract R
    $r = sp_push_extract_der_integer( $der_sig, $pos );
    if ( $r === false ) {
        return false;
    }

    // Extract S
    $s = sp_push_extract_der_integer( $der_sig, $pos );
    if ( $s === false ) {
        return false;
    }

    // Pad or trim R and S to exactly 32 bytes each
    $r = str_pad( substr( $r, -32 ), 32, "\x00", STR_PAD_LEFT );
    $s = str_pad( substr( $s, -32 ), 32, "\x00", STR_PAD_LEFT );

    return $r . $s;
}


/**
 * Extract an ASN.1 INTEGER from a DER-encoded buffer.
 *
 * WHY: DER-encoded ECDSA signatures contain R and S as ASN.1 INTEGER values,
 * which may have a leading zero byte for sign padding. We need the raw bytes.
 *
 * @param string $buf The DER buffer.
 * @param int    &$pos Current position in the buffer (advanced past the INTEGER).
 * @return string|false The raw integer bytes, or false on parse error.
 */
function sp_push_extract_der_integer( string $buf, int &$pos ): string|false {
    $len = strlen( $buf );

    // Expect INTEGER tag (0x02)
    if ( $pos >= $len || ord( $buf[ $pos ] ) !== 0x02 ) {
        return false;
    }
    $pos++;

    // Read length
    if ( $pos >= $len ) {
        return false;
    }
    $int_len = ord( $buf[ $pos ] );
    $pos++;

    if ( $pos + $int_len > $len ) {
        return false;
    }

    $int_bytes = substr( $buf, $pos, $int_len );
    $pos += $int_len;

    // Strip leading zero byte used for sign padding in DER
    if ( strlen( $int_bytes ) > 1 && $int_bytes[0] === "\x00" ) {
        $int_bytes = substr( $int_bytes, 1 );
    }

    return $int_bytes;
}


// ---------------------------------------------------------------------------
// 4b. FRONTEND PUSH SUBSCRIPTION JS
//
// WHY: When push is enabled and the service worker is registered, we need
// frontend JS that: (1) requests notification permission from the user,
// (2) subscribes via the service worker's pushManager using our VAPID public
// key, and (3) POSTs the subscription to our REST endpoint. This runs in
// wp_footer after the service worker registration.
// ---------------------------------------------------------------------------

add_action( 'wp_footer', function () {
    $settings = get_option( 'societypress_settings', [] );

    // Gate: both PWA and push must be enabled
    if ( empty( $settings['pwa_enabled'] ) || empty( $settings['push_enabled'] ) ) {
        return;
    }

    $vapid_public = $settings['push_vapid_public'] ?? '';
    if ( empty( $vapid_public ) ) {
        return; // VAPID keys haven't been generated yet
    }

    $rest_url = esc_url( rest_url( 'societypress/v1/push/subscribe' ) );
    $nonce    = wp_create_nonce( 'wp_rest' );
    ?>
    <script>
    /**
     * SocietyPress Push Notification Subscription
     *
     * WHY: This code runs after the service worker is registered. It requests
     * notification permission, subscribes via the Push API using our VAPID
     * public key, and sends the subscription to our REST endpoint for storage.
     *
     * Only runs once per browser session (tracked via sessionStorage) to avoid
     * repeated permission prompts on every page load.
     */
    (function() {
        'use strict';

        /* Gate: Only run if the browser supports push and service workers */
        if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
            return;
        }

        /* Gate: Don't re-subscribe if already done this session */
        if (sessionStorage.getItem('sp_push_subscribed')) {
            return;
        }

        /* Wait for the service worker to be ready before subscribing */
        navigator.serviceWorker.ready.then(function(registration) {
            /* Check if already subscribed — no need to re-subscribe */
            return registration.pushManager.getSubscription().then(function(existing) {
                if (existing) {
                    /* Already subscribed — send to server in case it's a new device
                       or the server lost the subscription */
                    sendSubscription(existing);
                    sessionStorage.setItem('sp_push_subscribed', '1');
                    return;
                }

                /* Request notification permission from the user.
                   WHY: Browsers require explicit user consent before allowing push
                   subscriptions. If the user denies, we respect that and don't ask again
                   (the browser remembers the decision). */
                return Notification.requestPermission().then(function(permission) {
                    if (permission !== 'granted') {
                        return; /* User denied — respect their choice */
                    }

                    /* Convert the VAPID public key from base64url to Uint8Array.
                       WHY: The Push API's subscribe() method requires the applicationServerKey
                       as a Uint8Array, not a base64 string. */
                    var vapidKey = urlBase64ToUint8Array(<?php echo wp_json_encode( $vapid_public ); ?>);

                    return registration.pushManager.subscribe({
                        userVisibleOnly: true, /* Required by Chrome — all pushes must show a notification */
                        applicationServerKey: vapidKey
                    }).then(function(subscription) {
                        sendSubscription(subscription);
                        sessionStorage.setItem('sp_push_subscribed', '1');
                    });
                });
            });
        }).catch(function() {
            /* Silent fail — push is an enhancement, not a requirement */
        });

        /**
         * Send the push subscription to our REST endpoint.
         *
         * WHY: The subscription object contains the endpoint URL and encryption
         * keys that the server needs to send push notifications to this browser.
         * We POST it as JSON to our REST endpoint which stores it in the database.
         */
        function sendSubscription(subscription) {
            var subJson = subscription.toJSON();
            fetch(<?php echo wp_json_encode( $rest_url ); ?>, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-WP-Nonce': <?php echo wp_json_encode( $nonce ); ?>
                },
                body: JSON.stringify({
                    endpoint: subJson.endpoint,
                    keys: {
                        p256dh: subJson.keys.p256dh,
                        auth: subJson.keys.auth
                    }
                })
            }).catch(function() {
                /* Silent fail — subscription will be retried on next page load */
            });
        }

        /**
         * Convert a base64url-encoded string to a Uint8Array.
         *
         * WHY: The Push API requires the VAPID applicationServerKey as a
         * Uint8Array. Our server stores the key in base64url format (the
         * standard for VAPID keys). This converts between the two.
         */
        function urlBase64ToUint8Array(base64String) {
            var padding = '='.repeat((4 - base64String.length % 4) % 4);
            var base64  = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
            var rawData = window.atob(base64);
            var outputArray = new Uint8Array(rawData.length);
            for (var i = 0; i < rawData.length; i++) {
                outputArray[i] = rawData.charCodeAt(i);
            }
            return outputArray;
        }
    })();
    </script>
    <?php
}, 100 ); // Priority 100 — after the service worker registration (priority 99)


// ---------------------------------------------------------------------------
// 5. FLUSH REWRITE RULES ON PWA SETTINGS CHANGE
//
// WHY: When pwa_enabled is toggled, the sp-sw.js rewrite rule needs to be
// added or removed. WordPress only recognizes new rewrite rules after a
// flush. We hook into the settings save to do this automatically so Harold
// doesn't have to visit Settings -> Permalinks manually.
// ---------------------------------------------------------------------------

add_action( 'update_option_societypress_settings', function ( $old_value, $new_value ) {
    $old_pwa = ! empty( $old_value['pwa_enabled'] );
    $new_pwa = ! empty( $new_value['pwa_enabled'] );

    // Only flush if the PWA toggle actually changed — flushing on every
    // settings save would be wasteful and could cause permalink conflicts.
    if ( $old_pwa !== $new_pwa ) {
        flush_rewrite_rules();
    }
}, 10, 2 );


// ============================================================================
// CUSTOM CONFIRMATION MODAL — spConfirm()
//
// WHY: Native browser confirm() dialogs are ugly, inconsistent across browsers,
//      cannot be styled, and are being deprecated/restricted by some browsers.
//      This custom modal provides a branded, accessible confirmation dialog
//      that matches the SocietyPress admin design. It supports:
//      - Async callback pattern (replaces synchronous confirm())
//      - data-sp-confirm attribute for automatic form/link interception
//      - Danger variant (red confirm button) for destructive actions
//      - Keyboard: ESC to cancel, Enter to confirm
//      - Focus trap for accessibility
// ============================================================================

add_action( 'admin_footer', function () {
    // Only output on SP admin pages
    $screen = get_current_screen();
    if ( ! $screen || strpos( $screen->id ?? '', 'sp-' ) === false && strpos( $screen->id ?? '', 'societypress' ) === false ) {
        // Also check if we're on a toplevel_page_sp- or societypress page
        if ( ! $screen || ( strpos( $screen->base ?? '', 'sp-' ) === false && strpos( $screen->base ?? '', 'toplevel' ) === false ) ) {
            // Cast a wide net — output on all admin pages since SP menu items
            // appear across various screen IDs
        }
    }
    ?>
    <!-- SocietyPress Confirmation Modal -->
    <div id="sp-confirm-overlay" class="sp-confirm-overlay" style="display:none;" role="dialog" aria-modal="true" aria-labelledby="sp-confirm-message">
        <div class="sp-confirm-box">
            <button type="button" id="sp-confirm-close" class="sp-confirm-close" aria-label="<?php esc_attr_e( 'Close', 'societypress' ); ?>">&times;</button>
            <p id="sp-confirm-message" class="sp-confirm-message"></p>
            <div class="sp-confirm-actions">
                <button type="button" id="sp-confirm-no" class="button sp-confirm-btn"><?php esc_html_e( 'Cancel', 'societypress' ); ?></button>
                <button type="button" id="sp-confirm-yes" class="button sp-confirm-btn sp-confirm-btn--danger"><?php esc_html_e( 'Confirm', 'societypress' ); ?></button>
            </div>
        </div>
    </div>
    <style>
        .sp-confirm-overlay {
            position: fixed;
            inset: 0;
            z-index: 999999;
            background: rgba(0, 0, 0, 0.55);
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .sp-confirm-box {
            background: #fff;
            border-radius: 8px;
            padding: 28px 32px 20px;
            max-width: 440px;
            width: 90%;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.25);
            position: relative;
        }
        .sp-confirm-close {
            position: absolute;
            top: 8px;
            right: 12px;
            background: none;
            border: none;
            font-size: 22px;
            color: #787c82;
            cursor: pointer;
            padding: 2px 6px;
            line-height: 1;
        }
        .sp-confirm-close:hover {
            color: #1d2327;
        }
        .sp-confirm-message {
            font-size: 14px;
            line-height: 1.6;
            color: #1d2327;
            margin: 0 0 20px;
            white-space: pre-line;
        }
        .sp-confirm-actions {
            display: flex;
            justify-content: flex-end;
            gap: 10px;
        }
        .sp-confirm-btn {
            padding: 6px 16px !important;
            font-size: 13px !important;
            cursor: pointer;
        }
        .sp-confirm-btn--danger {
            background: #d63638 !important;
            border-color: #d63638 !important;
            color: #fff !important;
        }
        .sp-confirm-btn--danger:hover {
            background: #b32d2e !important;
            border-color: #b32d2e !important;
        }
        .sp-confirm-btn--primary {
            background: #2271b1 !important;
            border-color: #2271b1 !important;
            color: #fff !important;
        }
    </style>
    <script>
    /**
     * Custom confirmation modal.
     *
     * @param {string}   message   - The message to display.
     * @param {Function} onConfirm - Called when the user clicks Confirm.
     * @param {Object}   [opts]    - Optional: { confirmText, cancelText, type: 'danger'|'primary' }
     */
    function spConfirm(message, onConfirm, opts) {
        opts = opts || {};
        var overlay  = document.getElementById('sp-confirm-overlay');
        var msgEl    = document.getElementById('sp-confirm-message');
        var yesBtn   = document.getElementById('sp-confirm-yes');
        var noBtn    = document.getElementById('sp-confirm-no');
        var closeBtn = document.getElementById('sp-confirm-close');

        msgEl.textContent = message;
        if (opts.confirmText) yesBtn.textContent = opts.confirmText;
        if (opts.cancelText)  noBtn.textContent  = opts.cancelText;

        yesBtn.className = 'button sp-confirm-btn sp-confirm-btn--' + (opts.type || 'danger');
        overlay.style.display = 'flex';

        /* Clone buttons to remove any prior listeners */
        var freshYes   = yesBtn.cloneNode(true);
        yesBtn.parentNode.replaceChild(freshYes, yesBtn);
        var freshNo    = noBtn.cloneNode(true);
        noBtn.parentNode.replaceChild(freshNo, noBtn);
        var freshClose = closeBtn.cloneNode(true);
        closeBtn.parentNode.replaceChild(freshClose, closeBtn);

        function close() {
            overlay.style.display = 'none';
            document.removeEventListener('keydown', keyHandler);
        }

        freshYes.addEventListener('click', function () {
            close();
            if (onConfirm) onConfirm();
        });
        freshNo.addEventListener('click', close);
        freshClose.addEventListener('click', close);

        // WHY: Focus trap keeps keyboard users inside the dialog. Without it,
        // Tab moves focus to page content behind the overlay — disorienting.
        var focusable = [freshClose, freshNo, freshYes];

        function keyHandler(e) {
            if (e.key === 'Escape') { close(); return; }

            // Focus trap: cycle Tab between the dialog's focusable elements
            if (e.key === 'Tab') {
                var first = focusable[0];
                var last  = focusable[focusable.length - 1];
                if (e.shiftKey) {
                    if (document.activeElement === first) {
                        e.preventDefault();
                        last.focus();
                    }
                } else {
                    if (document.activeElement === last) {
                        e.preventDefault();
                        first.focus();
                    }
                }
            }
        }
        document.addEventListener('keydown', keyHandler);
        freshYes.focus();
    }

    /*
     * Global interceptors for data-sp-confirm attributes.
     * Add data-sp-confirm="Your message" to any <form>, <a>, or <button>
     * and the confirmation modal fires automatically before the action.
     */

    /* Forms: intercept submit */
    document.addEventListener('submit', function (e) {
        var form = e.target;
        var msg  = form.getAttribute('data-sp-confirm');
        if (!msg) return;
        if (form.dataset.spConfirmed === '1') {
            form.removeAttribute('data-sp-confirmed');
            return;  /* Already confirmed — let the submit proceed */
        }
        e.preventDefault();
        spConfirm(msg, function () {
            form.dataset.spConfirmed = '1';
            form.submit();
        });
    });

    /* Links and buttons: intercept click */
    document.addEventListener('click', function (e) {
        var el = e.target.closest('[data-sp-confirm]');
        if (!el || el.tagName === 'FORM') return;
        if (el.dataset.spConfirmed === '1') {
            el.removeAttribute('data-sp-confirmed');
            return;
        }
        e.preventDefault();
        spConfirm(el.getAttribute('data-sp-confirm'), function () {
            if (el.tagName === 'A') {
                window.location.href = el.href;
            } else if (el.type === 'submit' && el.form) {
                el.dataset.spConfirmed = '1';
                el.click();
            }
        });
    });
    </script>
    <?php
} );
